def load_optional_module(module_name: str):
    try:
        return importlib.import_module(module_name)
    except ImportError:
        return None


def get_stripe_module():
    stripe_module = load_optional_module('stripe')
    if stripe_module is None:
        raise RuntimeError('stripe package not installed. Install with: pip install stripe')
    return stripe_module

# ==================== GLOBAL MT5 CONNECTION LOCK ====================
# Prevents multiple simultaneous MT5 connections which cause IPC conflicts
# Only ONE thread should connect to MT5 at a time
mt5_connection_lock = threading.Lock()
logger.info("✅ MT5 connection lock initialized - ensures sequential MT5 connections")

# Lightweight MT5 lock contention telemetry.
mt5_lock_metrics_lock = threading.Lock()
mt5_lock_metrics = {
    'pending_waiters': 0,
    'acquire_count': 0,
    'timeout_count': 0,
    'total_wait_seconds': 0.0,
    'max_wait_seconds': 0.0,
}

# ==================== MT5 ACCOUNT QUEUE (Multi-User Support) ====================
# When multiple users have different MT5 accounts, the single MT5 process must
# switch between accounts. This queue serializes access per-account to minimize
# unnecessary switches. Bots on the SAME account share the session; bots on
# DIFFERENT accounts wait for their turn.
mt5_current_account = None       # Account number currently logged in
mt5_account_lock = threading.Lock()  # Protects mt5_current_account reads/writes
mt5_priority_mode_switch = threading.Event()  # Blocks background bot reconnects during manual mode switches
logger.info("✅ MT5 account queue initialized - supports multi-user account switching")

# ==================== BOT CREATION LOCK ====================
# Prevents multiple simultaneous bot creations which compete for MT5 resources
# Only ONE bot should be created at a time to avoid MT5 lock contention
bot_creation_lock = threading.Lock()
logger.info("✅ Bot creation lock initialized - prevents concurrent bot creation")

# Session log throttling to prevent repeated identical 401 log spam.
_session_log_throttle = {}
_session_log_throttle_lock = threading.Lock()


def should_log_session_event(event_key: str, interval_seconds: int = 30) -> bool:
    """Return True when an auth event should be logged; suppress duplicates briefly."""
    now_ts = time.time()
    with _session_log_throttle_lock:
        last_ts = _session_log_throttle.get(event_key, 0)
        if now_ts - last_ts >= interval_seconds:
            _session_log_throttle[event_key] = now_ts
            return True
    return False

# ==================== BALANCE CACHE ====================
# CRITICAL FIX: Cache balances updated from successful MT5 connections
# When balance API calls get MT5 lock timeout, return cached balance instead of default $10,000
balance_cache = {}  # { f"{broker}:{account}": {'balance': X, 'equity': Y, 'timestamp': Z} }
balance_cache_lock = threading.Lock()
recent_balance_db_writes = {}
recent_balance_db_writes_lock = threading.Lock()
BALANCE_SNAPSHOT_DB_WRITE_MIN_INTERVAL = 15
BALANCE_CACHE_TTL_LIVE = 5 * 60     # 5 minutes max age for live account cache
BALANCE_CACHE_TTL_DEMO = 30 * 60    # 30 minutes max age for demo account cache
logger.info("✅ Balance cache initialized - stores real balances from successful MT5 connections")

# ==================== CREDENTIAL CACHE ====================
credential_cache = {}  # Cache for broker credentials to avoid repeated DB queries
logger.info("✅ Credential cache initialized - caches broker credentials")

# ==================== FAILED AUTH COOLDOWN ====================
# Track accounts that fail auth so we don't repeatedly block the MT5 lock trying bad credentials
# Format: { account_number: {'timestamp': time.time(), 'error': str} }
_failed_auth_accounts = {}
_failed_auth_lock = threading.Lock()
_FAILED_AUTH_COOLDOWN = 300  # 5 minutes before retrying a failed account
logger.info("✅ Failed auth cooldown initialized - prevents repeated bad credential retries")

# ==================== BALANCE FALLBACK COOLDOWN ====================
# Prevent the dashboard from stampeding MT5 with repeated live-balance probes.
_balance_fallback_attempts = {}
_balance_fallback_lock = threading.Lock()
_BALANCE_FALLBACK_COOLDOWN = 15
logger.info("✅ Balance fallback cooldown initialized - prevents repeated MT5 balance probes")


def should_skip_balance_fallback(broker_name: str, account_id) -> bool:
    cache_key = get_balance_cache_key(broker_name, account_id)
    now_ts = time.time()
    with _balance_fallback_lock:
        last_attempt = _balance_fallback_attempts.get(cache_key)
        if not last_attempt:
            return False
        if last_attempt.get('status') == 'failed' and now_ts - last_attempt.get('timestamp', 0) < _BALANCE_FALLBACK_COOLDOWN:
            return True
        if now_ts - last_attempt.get('timestamp', 0) >= _BALANCE_FALLBACK_COOLDOWN:
            _balance_fallback_attempts.pop(cache_key, None)
    return False


def record_balance_fallback_attempt(broker_name: str, account_id, status: str, reason: str = '') -> None:
    cache_key = get_balance_cache_key(broker_name, account_id)
    with _balance_fallback_lock:
        if status == 'success':
            _balance_fallback_attempts.pop(cache_key, None)
        else:
            _balance_fallback_attempts[cache_key] = {
                'status': status,
                'reason': reason,
                'timestamp': time.time(),
            }


def get_failed_auth_status(account_id):
    """Return active MT5 auth cooldown metadata for an account, if any."""
    if account_id in [None, '']:
        return None

    try:
        normalized_account = int(str(account_id).strip())
    except (TypeError, ValueError):
        normalized_account = str(account_id).strip()

    now_ts = time.time()
    with _failed_auth_lock:
        fail_info = _failed_auth_accounts.get(normalized_account)
        if not fail_info:
            return None

        elapsed = now_ts - fail_info.get('timestamp', 0)
        if elapsed >= _FAILED_AUTH_COOLDOWN:
            _failed_auth_accounts.pop(normalized_account, None)
            return None

        return {
            'elapsed': elapsed,
            'remaining': max(0, _FAILED_AUTH_COOLDOWN - elapsed),
            'error': fail_info.get('error', ''),
        }


def broker_uses_single_mode_slot(broker_name: str) -> bool:
    """Return True when a broker should have only one active credential per mode per user."""
    return canonicalize_broker_name(broker_name) == 'Exness'


def _broker_credential_completeness_score(row: Dict[str, Any]) -> int:
    broker_name = canonicalize_broker_name(row.get('broker_name'))
    account_number = str(row.get('account_number') or '').strip()
    password = str(row.get('password') or '').strip()
    server = str(row.get('server') or '').strip()
    api_key = str(row.get('api_key') or '').strip()
    username = str(row.get('username') or '').strip()

    score = 1 if account_number else 0
    if broker_name == 'FXCM':
        score += 10 if has_fxcm_connection_credentials({
            'api_key': api_key,
            'username': username,
            'password': password,
        }) else 0
    elif broker_name == 'Binance':
        score += 10 if api_key and password else 0
    elif broker_name == 'OANDA':
        score += 10 if api_key and account_number else 0
    else:
        score += 10 if account_number and password and server else 0

    if str(row.get('updated_at') or '').strip():
        score += 1
    return score


def _dedupe_key_for_active_credential(row: Dict[str, Any]) -> Tuple[Any, ...]:
    broker_name = canonicalize_broker_name(row.get('broker_name'))
    account_number = str(row.get('account_number') or '').strip()
    username = str(row.get('username') or '').strip()
    api_key = str(row.get('api_key') or '').strip()
    server = str(row.get('server') or '').strip().lower() or 'spot'
    normalized_is_live = int(normalize_mt5_is_live_flag(broker_name, row.get('is_live'), row.get('server')))

    if broker_uses_single_mode_slot(broker_name):
        return (broker_name, normalized_is_live)

    if broker_name == 'Binance' and api_key:
        return (broker_name, api_key, server, normalized_is_live)

    if broker_name == 'FXCM' and username:
        return (broker_name, username, normalized_is_live)

    return (broker_name, account_number, normalized_is_live)


def _is_probable_fxcm_trading_account_id(value: Any) -> bool:
    account_number = str(value or '').strip()
    return bool(account_number) and account_number.isdigit()


def _is_fxcm_placeholder_row(row: Dict[str, Any]) -> bool:
    broker_name = canonicalize_broker_name(row.get('broker_name'))
    if broker_name != 'FXCM':
        return False

    account_number = str(row.get('account_number') or '').strip()
    if not account_number:
        return True
    if _is_probable_fxcm_trading_account_id(account_number):
        return False

    username = str(row.get('username') or '').strip()
    api_key = str(row.get('api_key') or '').strip()
    password = str(row.get('password') or '').strip()
    return not bool(username or api_key or password)


def dedupe_active_broker_credentials(rows: List[Dict[str, Any]]) -> Tuple[List[Dict[str, Any]], List[str]]:
    # Decrypt sensitive fields up-front so all downstream callers (balance fetch,
    # broker connection setup, dedupe scoring) operate on plaintext values.
    rows = decrypt_credential_rows(rows)
    deduped_credentials: Dict[Tuple[Any, ...], Dict[str, Any]] = {}
    duplicate_credential_ids: List[str] = []

    for row in rows:
        dedupe_key = _dedupe_key_for_active_credential(row)

        existing = deduped_credentials.get(dedupe_key)
        if existing is None:
            deduped_credentials[dedupe_key] = row
            continue

        existing_score = _broker_credential_completeness_score(existing)
        new_score = _broker_credential_completeness_score(row)
        if new_score > existing_score:
            deduped_credentials[dedupe_key] = row
            discarded = existing
        else:
            discarded = row

        discarded_id = str(discarded.get('credential_id') or '').strip()
        if discarded_id:
            duplicate_credential_ids.append(discarded_id)

    fxcm_real_accounts_by_mode = {
        int(normalize_mt5_is_live_flag(canonicalize_broker_name(row.get('broker_name')), row.get('is_live'), row.get('server')))
        for row in deduped_credentials.values()
        if canonicalize_broker_name(row.get('broker_name')) == 'FXCM'
        and _is_probable_fxcm_trading_account_id(row.get('account_number'))
        and has_fxcm_connection_credentials(row)
    }

    if fxcm_real_accounts_by_mode:
        filtered_credentials: Dict[Tuple[Any, ...], Dict[str, Any]] = {}
        for dedupe_key, row in deduped_credentials.items():
            broker_name = canonicalize_broker_name(row.get('broker_name'))
            normalized_is_live = int(normalize_mt5_is_live_flag(broker_name, row.get('is_live'), row.get('server')))
            if (
                broker_name == 'FXCM'
                and normalized_is_live in fxcm_real_accounts_by_mode
                and _is_fxcm_placeholder_row(row)
            ):
                discarded_id = str(row.get('credential_id') or '').strip()
                if discarded_id:
                    duplicate_credential_ids.append(discarded_id)
                continue
            filtered_credentials[dedupe_key] = row
        deduped_credentials = filtered_credentials

    return list(deduped_credentials.values()), duplicate_credential_ids


def encrypt_credential_at_rest(cursor, credential_id: str) -> None:
    """Encrypt api_key + password columns for a given credential_id if they are
    still stored as plaintext. Idempotent: already-encrypted values are detected
    by the marker prefix and skipped. Call once after any INSERT/UPDATE that
    writes broker_credentials and before the surrounding conn.commit().
    """
    cred_id = str(credential_id or '').strip()
    if not cred_id:
        return
    try:
        cursor.execute(
            'SELECT api_key, password FROM broker_credentials WHERE credential_id = ?',
            (cred_id,),
        )
        row = cursor.fetchone()
        if not row:
            return
        api_key_v = row['api_key'] if hasattr(row, 'keys') else row[0]
        password_v = row['password'] if hasattr(row, 'keys') else row[1]
        new_api_key = encrypt_secret(api_key_v) if api_key_v else api_key_v
        new_password = encrypt_secret(password_v) if password_v else password_v
        if new_api_key != api_key_v or new_password != password_v:
            cursor.execute(
                'UPDATE broker_credentials SET api_key = ?, password = ? WHERE credential_id = ?',
                (new_api_key, new_password, cred_id),
            )
    except Exception as exc:
        logger.warning(
            f"[CREDENTIAL CRYPTO] Failed to encrypt-at-rest for credential {cred_id}: {exc}"
        )


def deactivate_duplicate_credential_ids(cursor, duplicate_credential_ids: List[str], user_id: str, reason: str) -> int:
    duplicate_credential_ids = [str(cid).strip() for cid in duplicate_credential_ids if str(cid or '').strip()]
    if not duplicate_credential_ids:
        return 0

    placeholders = ','.join('?' for _ in duplicate_credential_ids)
    cursor.execute(
        f'''
            UPDATE broker_credentials
            SET is_active = 0, updated_at = ?
            WHERE credential_id IN ({placeholders})
        ''',
        (datetime.now().isoformat(), *duplicate_credential_ids),
    )
    deactivated_count = cursor.rowcount or 0
    if deactivated_count:
        logger.warning(
            f"Deactivated {deactivated_count} duplicate/incomplete broker credential(s) for user {user_id} "
            f"while {reason}."
        )
    return deactivated_count


def deactivate_conflicting_broker_credentials(cursor, user_id: str, broker_name: str, is_live, keep_credential_id: str = None) -> int:
    """Deactivate duplicate credentials for brokers that only support one live/demo slot per user."""
    if not broker_uses_single_mode_slot(broker_name):
        return 0

    normalized_broker = canonicalize_broker_name(broker_name)
    normalized_is_live = int(normalize_mt5_is_live_flag(normalized_broker, is_live, None))
    params = [datetime.now().isoformat(), user_id, normalized_is_live, normalized_broker]
    query = '''
        UPDATE broker_credentials
        SET is_active = 0, updated_at = ?
        WHERE user_id = ?
          AND is_active = 1
          AND is_live = ?
          AND LOWER(TRIM(broker_name)) = LOWER(TRIM(?))
    '''
    if keep_credential_id:
        query += ' AND credential_id != ?'
        params.append(keep_credential_id)

    cursor.execute(query, tuple(params))
    return cursor.rowcount or 0


def _resolve_active_broker_credential_for_bot(
    user_id: str,
    broker_name: str,
    account_number: Any = None,
    mode_value: Any = None,
    current_credential_id: str = '',
) -> Optional[Dict[str, Any]]:
    normalized_broker = canonicalize_broker_name(broker_name)
    normalized_account = str(account_number or '').strip()
    normalized_credential_id = str(current_credential_id or '').strip()
    normalized_mode = str(mode_value or '').strip().lower()
    desired_is_live: Optional[int] = None
    if normalized_mode in {'live', 'demo'}:
        desired_is_live = 1 if normalized_mode == 'live' else 0

    conn = None
    try:
        conn = get_db_connection()
        cursor = conn.cursor()

        if normalized_credential_id:
            cursor.execute(
                '''
                  SELECT credential_id, broker_name, account_number, username, password, server,
                      is_live, api_key, account_currency, mt5_terminal_path, updated_at, created_at
                FROM broker_credentials
                WHERE credential_id = ? AND user_id = ? AND is_active = 1
                LIMIT 1
                ''',
                (normalized_credential_id, user_id),
            )
            current_row = cursor.fetchone()
            if current_row:
                current_row_dict = dict(current_row)
                current_is_live = int(
                    normalize_mt5_is_live_flag(
                        canonicalize_broker_name(current_row_dict.get('broker_name')),
                        current_row_dict.get('is_live'),
                        current_row_dict.get('server'),
                    )
                )
                if desired_is_live is None or current_is_live == desired_is_live:
                    return current_row_dict

        def _query_candidates(match_account: bool) -> List[Dict[str, Any]]:
            query = '''
                  SELECT credential_id, broker_name, account_number, username, password, server,
                      is_live, api_key, account_currency, mt5_terminal_path, updated_at, created_at
                FROM broker_credentials
                WHERE user_id = ?
                  AND is_active = 1
                  AND LOWER(TRIM(broker_name)) = LOWER(TRIM(?))
            '''
            params: List[Any] = [user_id, normalized_broker]
            if desired_is_live is not None:
                query += ' AND is_live = ?'
                params.append(desired_is_live)
            if match_account and normalized_account:
                query += ' AND TRIM(account_number) = ?'
                params.append(normalized_account)
            query += " ORDER BY COALESCE(updated_at, created_at, '') DESC, credential_id DESC"
            cursor.execute(query, tuple(params))
            return [dict(row) for row in cursor.fetchall()]

        candidate_rows = _query_candidates(match_account=True)
        if normalized_broker == 'FXCM' and not candidate_rows:
            candidate_rows = _query_candidates(match_account=False)

        candidate_rows, _ = dedupe_active_broker_credentials(candidate_rows)
        if candidate_rows:
            return candidate_rows[0]
        return None
    except Exception as exc:
        logger.warning(
            f"Could not resolve active broker credential for user {user_id}, broker {normalized_broker}, account {normalized_account}: {exc}"
        )
        return None
    finally:
        if conn:
            try:
                conn.close()
            except Exception:
                pass


def _sync_bot_credential_mapping(bot_id: str, user_id: str, credential_id: str) -> None:
    normalized_credential_id = str(credential_id or '').strip()
    if not bot_id or not user_id or not normalized_credential_id:
        return

    conn = None
    try:
        conn = get_db_connection()
        cursor = conn.cursor()
        cursor.execute('DELETE FROM bot_credentials WHERE bot_id = ? AND user_id = ?', (bot_id, user_id))
        cursor.execute(
            '''
            INSERT INTO bot_credentials (bot_id, credential_id, user_id, created_at)
            VALUES (?, ?, ?, ?)
            ''',
            (bot_id, normalized_credential_id, user_id, datetime.now().isoformat()),
        )
        conn.commit()
    except Exception as exc:
        logger.warning(f"Could not sync bot credential mapping for {bot_id}: {exc}")
    finally:
        if conn:
            try:
                conn.close()
            except Exception:
                pass

