def find_mt5_terminal_path(broker_name: str, configured_path: str = None, is_live: bool = None) -> Optional[str]:
    """Resolve a broker-specific terminal path even on VPS/local mixed setups.
    For Exness: uses separate DEMO/LIVE terminals when is_live is specified."""
    candidate_paths = []

    if configured_path:
        candidate_paths.append(configured_path)

    # For Exness: prefer the dedicated demo/live terminal path
    normalized = canonicalize_broker_name(broker_name)
    if normalized == 'Exness' and is_live is not None:
        if is_live and EXNESS_LIVE_PATH:
            candidate_paths.insert(0, EXNESS_LIVE_PATH)
        elif not is_live and EXNESS_DEMO_PATH:
            candidate_paths.insert(0, EXNESS_DEMO_PATH)

    env_path = os.getenv(f"{normalized.upper().replace(' ', '_')}_PATH", '').strip()
    if env_path:
        candidate_paths.append(env_path)

    candidate_paths.extend(get_known_mt5_paths(broker_name))

    for path in candidate_paths:
        resolved_path = resolve_mt5_terminal_executable_path(path)
        if resolved_path:
            return resolved_path

    return None


def normalize_mt5_server_name(broker_name: str, is_live: bool, server: str = None) -> str:
    normalized = canonicalize_broker_name(broker_name)
    # Allow explicit server override for MT5 brokers when provided by user.
    provided_server = (server or '').strip()
    invalid_mt5_aliases = {
        'rest-api',
        'rest_api',
        'metaapi',
        'meta-api',
        'socket',
        'socket-bridge',
        'socket_bridge',
    }
    if provided_server and provided_server.lower() not in invalid_mt5_aliases:
        return provided_server

    if normalized == 'Exness':
        return 'Exness-MT5Real27' if is_live else 'Exness-MT5Trial9'
    return 'MetaTrader 5'


def coerce_bool(value, default: bool = False) -> bool:
    """Convert common request truthy values into a real boolean."""
    if isinstance(value, bool):
        return value
    if value is None:
        return default
    if isinstance(value, (int, float)):
        return value != 0

    normalized = str(value).strip().lower()
    if normalized in {'1', 'true', 'yes', 'y', 'on', 'live'}:
        return True
    if normalized in {'0', 'false', 'no', 'n', 'off', 'demo', ''}:
        return False
    return default


def normalize_mt5_is_live_flag(broker_name: str, is_live, server: str = None) -> bool:
    """Resolve MT5 live/demo mode using both the posted flag and server naming."""
    resolved = coerce_bool(is_live, default=False)
    server_lower = str(server or '').strip().lower()

    if any(token in server_lower for token in ['trial', 'demo']):
        return False
    if any(token in server_lower for token in ['real', 'live']):
        return True

    return resolved


def is_mt5_process_running(terminal_path: str) -> bool:
    if not terminal_path or sys.platform != 'win32':
        return False

    resolved_path = resolve_mt5_terminal_executable_path(terminal_path)
    if not resolved_path:
        return False

    normalized_target = os.path.normcase(os.path.normpath(resolved_path))
    exe_name = os.path.basename(normalized_target).lower()
    if exe_name not in ['terminal64.exe', 'terminal.exe']:
        exe_name = 'terminal64.exe'

    try:
        command = (
            "Get-CimInstance Win32_Process "
            f"-Filter \"Name = '{exe_name}'\" | "
            "Select-Object -ExpandProperty ExecutablePath"
        )
        output = subprocess.check_output(
            ['powershell', '-NoProfile', '-Command', command],
            universal_newlines=True,
            stderr=subprocess.DEVNULL,
        )
        running_paths = [
            os.path.normcase(os.path.normpath(line.strip()))
            for line in output.splitlines()
            if line.strip()
        ]
        return normalized_target in running_paths
    except Exception as exc:
        logger.debug(f"[MT5 Terminal] Process check failed: {exc}")
        return False


def ensure_mt5_terminal_running(terminal_path: str, broker_name: str) -> bool:
    normalized_path = resolve_mt5_terminal_executable_path(terminal_path)
    if not normalized_path:
        raw_path = str(terminal_path or '').strip().strip('"').strip("'")
        logger.warning(f"[MT5 Terminal] Cannot launch {broker_name} terminal - path missing: {raw_path or 'unset'}")
        return False

    if not MT5_AUTO_LAUNCH:
        logger.info(f"[MT5 Terminal] Auto-launch disabled for {broker_name}; will not open terminal automatically")
        return is_mt5_process_running(normalized_path)

    if is_mt5_process_running(normalized_path):
        logger.info(f"[MT5 Terminal] MT5 process already running for {broker_name}; no launch needed")
        return True

    try:
        creationflags = 0
        if sys.platform == 'win32':
            creationflags = getattr(subprocess, 'DETACHED_PROCESS', 0) | getattr(subprocess, 'CREATE_NEW_PROCESS_GROUP', 0)

        subprocess.Popen(
            [normalized_path],
            cwd=os.path.dirname(normalized_path) or None,
            stdout=subprocess.DEVNULL,
            stderr=subprocess.DEVNULL,
            creationflags=creationflags,
        )
        logger.info(f"[MT5 Terminal] Started {broker_name} terminal: {normalized_path}")
        return True
    except Exception as exc:
        logger.error(f"[MT5 Terminal] Failed to launch {broker_name} terminal at {normalized_path}: {exc}")
        return False


def stop_mt5_terminal_process(terminal_path: str, broker_name: str) -> bool:
    resolved_path = resolve_mt5_terminal_executable_path(terminal_path)
    normalized_path = os.path.normcase(os.path.normpath(resolved_path)) if resolved_path else None
    if not normalized_path or sys.platform != 'win32':
        return False

    if not MT5_AUTO_RESTART:
        logger.info(f"[MT5 Terminal] Auto-restart disabled for {broker_name}; leaving running terminal untouched")
        return False

    exe_name = os.path.basename(normalized_path)
    command = (
        "Get-CimInstance Win32_Process "
        f"-Filter \"Name = '{exe_name}'\" | "
        "Where-Object { $_.ExecutablePath -and $_.ExecutablePath -ieq '" + normalized_path.replace("'", "''") + "' } | "
        "Select-Object -ExpandProperty ProcessId"
    )

    try:
        output = subprocess.check_output(
            ['powershell', '-NoProfile', '-Command', command],
            universal_newlines=True,
            stderr=subprocess.DEVNULL,
        )
        process_ids = [line.strip() for line in output.splitlines() if line.strip()]
        if not process_ids:
            return False

        for process_id in process_ids:
            subprocess.run(
                ['taskkill', '/PID', str(process_id), '/F', '/T'],
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
                check=False,
            )
        logger.warning(f"[MT5 Terminal] Restarting stale {broker_name} terminal: {normalized_path}")
        return True
    except Exception as exc:
        logger.warning(f"[MT5 Terminal] Could not stop stale {broker_name} terminal {normalized_path}: {exc}")
        return False


def warm_up_mt5_terminal(mt5_path: str, account: int, password: str, server: str, broker_name: str = 'Exness', timeout_seconds: int = 30) -> bool:
    """Launch and warm up the target MT5 terminal until its IPC channel is ready."""
    if not mt5_path or not account or not password:
        return False

    try:
        import MetaTrader5 as mt5
    except ImportError:
        logger.warning("[STARTUP] MetaTrader5 package not installed; skipping MT5 warm-up")
        return False

    if DEPLOYMENT_MODE == 'VPS':
        logger.info(f"[STARTUP] VPS mode - skipping local launch/restart for {broker_name} terminal; probing existing MT5 session only")
    elif not MT5_AUTO_LAUNCH:
        logger.info(f"[STARTUP] Auto-launch disabled for {broker_name}; probing existing MT5 session only")
    else:
        ensure_mt5_terminal_running(mt5_path, broker_name)

    deadline = time.time() + max(5, timeout_seconds)
    attempt = 0
    last_error = None
    restarted_terminal = False
    while time.time() < deadline:
        attempt += 1
        try:
            logger.info(f"[STARTUP] MT5 warm-up attempt {attempt}: path={mt5_path} account={account} server={server}")
            if mt5.initialize(path=mt5_path, login=int(account), password=str(password), server=str(server)):
                acct = mt5.account_info()
                if acct:
                    logger.info(f"[STARTUP] ✅ MT5 warm-up successful: Account {acct.login}, Balance {float(getattr(acct, 'balance', 0)):.2f}")
                    return True
                last_error = ('account_info', 'MT5 initialized but account_info returned None')
            else:
                last_error = mt5.last_error()
        except Exception as exc:
            last_error = str(exc)

        if DEPLOYMENT_MODE != 'VPS' and MT5_AUTO_RESTART and not restarted_terminal and isinstance(last_error, tuple) and last_error and last_error[0] in (-10004, -10005):
            restarted_terminal = True
            stop_mt5_terminal_process(mt5_path, broker_name)
            ensure_mt5_terminal_running(mt5_path, broker_name)
            logger.info(f"[STARTUP] Waiting 8s after restarting {broker_name} terminal for IPC to come up...")
            time.sleep(8)
            continue

        logger.info(f"[STARTUP] MT5 IPC not ready yet (attempt {attempt}): {last_error}")
        time.sleep(3)

    logger.warning(f"[STARTUP] ⚠️ MT5 warm-up failed after {attempt} attempts: {last_error}")
    return False

