def _resolve_signup_referrer_id(cursor, referral_code: Optional[str] = None) -> Optional[str]:
    if referral_code:
        cursor.execute('SELECT user_id FROM users WHERE referral_code = ?', (referral_code.upper(),))
        referrer = cursor.fetchone()
        if referrer:
            return referrer['user_id'] if isinstance(referrer, sqlite3.Row) else referrer[0]
    return _get_default_signup_referrer_id(cursor)

class PaymentGateway:
    """Unified payment gateway for Stripe, bank transfers, crypto, and internal payments"""
    
    @staticmethod
    def process_payout(user_id: str, amount: float, reason: str, method: str = 'stripe') -> Dict:
        """
        Process a payout to a user via specified method
        
        Methods supported:
        - 'stripe': Stripe Connect (fastest, recurring payouts)
        - 'bank': Bank transfer (slower, verified method)
        - 'crypto': Cryptocurrency transfer (Bitcoin, Ethereum, USDT)
        - 'internal': Internal account credit (instant, no fees)
        """
        try:
            conn = get_db_connection()
            cursor = conn.cursor()
            
            # Get user payment method preference
            cursor.execute('SELECT payment_method, stripe_account_id, bank_account_id, crypto_wallet FROM users WHERE user_id = ?', (user_id,))
            user = cursor.fetchone()
            
            if not user:
                return {'success': False, 'error': 'User not found'}
            
            # Create transaction record
            transaction_id = str(uuid.uuid4())
            
            if method == 'stripe' or (method == 'auto' and user[1]):  # Stripe Connect
                result = PaymentGateway._process_stripe_payout(user_id, amount, reason, transaction_id)
                
            elif method == 'bank' or (method == 'auto' and user[2]):  # Bank transfer
                result = PaymentGateway._process_bank_payout(user_id, amount, reason, transaction_id)
                
            elif method == 'crypto' or (method == 'auto' and user[3]):  # Crypto transfer
                result = PaymentGateway._process_crypto_payout(user_id, amount, reason, transaction_id)
                
            elif method == 'internal':
                result = PaymentGateway._process_internal_payout(user_id, amount, reason, transaction_id)
            else:
                return {'success': False, 'error': f'Payment method {method} not configured for user'}
            
            # Log transaction
            if result['success']:
                cursor.execute('''
                    INSERT INTO transactions (transaction_id, user_id, type, amount, method, status, reason, created_at)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                ''', (transaction_id, user_id, 'payout', amount, method, 'completed', reason, datetime.now()))
                conn.commit()
                logger.info(f"✅ [PAYOUT] {amount:.2f} USD to {user_id} via {method}: {result.get('reference', 'N/A')}")
            else:
                cursor.execute('''
                    INSERT INTO transactions (transaction_id, user_id, type, amount, method, status, reason, created_at)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                ''', (transaction_id, user_id, 'payout', amount, method, 'failed', reason, datetime.now()))
                conn.commit()
                logger.error(f"❌ [PAYOUT FAILED] {amount:.2f} USD to {user_id}: {result.get('error')}")
            
            conn.close()
            return result
            
        except Exception as e:
            logger.error(f"Error processing payout: {e}")
            return {'success': False, 'error': str(e)}
    
    @staticmethod
    def _process_stripe_payout(user_id: str, amount: float, reason: str, transaction_id: str) -> Dict:
        """Process payout via Stripe Connect"""
        try:
            stripe = get_stripe_module()
            stripe.api_key = os.getenv('STRIPE_SECRET_KEY')
            
            conn = get_db_connection()
            cursor = conn.cursor()
            cursor.execute('SELECT stripe_account_id FROM users WHERE user_id = ?', (user_id,))
            result = cursor.fetchone()
            conn.close()
            
            if not result or not result[0]:
                return {'success': False, 'error': 'Stripe account not connected'}
            
            stripe_account_id = result[0]
            
            # Create payout
            payout = stripe.Payout.create(
                amount=int(amount * 100),  # Convert to cents
                currency='usd',
                description=reason,
                statement_descriptor=f"Zwesta-{transaction_id[:8]}",
                stripe_account=stripe_account_id
            )
            
            return {
                'success': True,
                'reference': payout.id,
                'status': payout.status,
                'amount': amount,
                'method': 'stripe'
            }
        except Exception as e:
            logger.error(f"Stripe payout error: {e}")
            return {'success': False, 'error': str(e)}
    
    @staticmethod
    def _process_bank_payout(user_id: str, amount: float, reason: str, transaction_id: str) -> Dict:
        """Process bank transfer payout"""
        try:
            conn = get_db_connection()
            cursor = conn.cursor()
            
            # Get bank details
            cursor.execute('''
                SELECT bank_name, account_holder, account_number, routing_number, swift_code
                FROM users WHERE user_id = ?
            ''', (user_id,))
            
            bank_info = cursor.fetchone()
            conn.close()
            
            if not bank_info or not bank_info[2]:  # No account number
                return {'success': False, 'error': 'Bank account not configured'}
            
            # Create bank transfer (ACH in US, SEPA in EU, etc.)
            # This would integrate with your banking API (e.g., Wise, Stripe ACH, etc.)
            
            logger.info(f"📧 Bank transfer scheduled: {amount:.2f} to {bank_info[1]} ({bank_info[0]})")
            
            return {
                'success': True,
                'reference': transaction_id,
                'status': 'pending',
                'amount': amount,
                'method': 'bank',
                'estimatedDays': 1-3,
                'bankName': bank_info[0],
                'accountHolder': bank_info[1]
            }
        except Exception as e:
            logger.error(f"Bank payout error: {e}")
            return {'success': False, 'error': str(e)}
    
    @staticmethod
    def _process_crypto_payout(user_id: str, amount: float, reason: str, transaction_id: str) -> Dict:
        """Process cryptocurrency payout (Bitcoin, Ethereum, USDT)"""
        try:
            conn = get_db_connection()
            cursor = conn.cursor()
            
            # Get crypto wallet
            cursor.execute('SELECT crypto_wallet, crypto_type FROM users WHERE user_id = ?', (user_id,))
            result = cursor.fetchone()
            conn.close()
            
            if not result or not result[0]:
                return {'success': False, 'error': 'Crypto wallet not configured'}
            
            wallet = result[0]
            crypto_type = result[1] or 'USDT'  # Default to USDT stablecoin
            
            # This would integrate with your crypto API (Coinbase, Kraken API, etc.)
            # For now, log the transaction
            
            logger.info(f"🪙 Crypto transfer scheduled: {amount:.2f} USD worth of {crypto_type} to {wallet[:10]}...")
            
            return {
                'success': True,
                'reference': transaction_id,
                'status': 'pending',
                'amount': amount,
                'method': 'crypto',
                'cryptoType': crypto_type,
                'wallet': f"{wallet[:6]}...{wallet[-4:]}",
                'estimatedMinutes': 5  # Blockchain confirmation time
            }
        except Exception as e:
            logger.error(f"Crypto payout error: {e}")
            return {'success': False, 'error': str(e)}
    
    @staticmethod
    def _process_internal_payout(user_id: str, amount: float, reason: str, transaction_id: str) -> Dict:
        """Process internal account credit (instant)"""
        try:
            conn = get_db_connection()
            cursor = conn.cursor()
            
            # Add to user's internal balance
            cursor.execute('''
                UPDATE users SET internal_balance = internal_balance + ? WHERE user_id = ?
            ''', (amount, user_id))
            conn.commit()
            conn.close()
            
            logger.info(f"💳 Internal credit: +{amount:.2f} to {user_id}")
            
            return {
                'success': True,
                'reference': transaction_id,
                'status': 'completed',
                'amount': amount,
                'method': 'internal',
                'instant': True
            }
        except Exception as e:
            logger.error(f"Internal payout error: {e}")
            return {'success': False, 'error': str(e)}


def pay_user(user_id: str, amount: float, reason: str, method: str = 'auto') -> bool:
    """
    Pay a user via their preferred payment method
    
    Args:
        user_id: User to pay
        amount: Amount in USD
        reason: Reason for payment (commission, profit, etc.)
        method: Payment method ('auto' = user preference, 'stripe', 'bank', 'crypto', 'internal')
    
    Returns:
        True if payment initiated successfully, False otherwise
    """
    if amount <= 0:
        logger.warning(f"Invalid payout amount: {amount}")
        return False
    
    result = PaymentGateway.process_payout(user_id, amount, reason, method)
    return result.get('success', False)

def distribute_profit_split_and_commissions(user_id, profit, bot_id):
    """Settle a trader withdrawal internally after per-trade commissions are already booked."""
    if profit <= 0:
        return {'owner': 0.0, 'referrer': 0.0, 'trader': 0.0, 'settledInternally': False}

    trader_share = float(profit)
    payout_success = pay_user(
        user_id,
        trader_share,
        f"Trader profit withdrawal from bot {bot_id}",
        method='internal',
    )
    logger.info(
        f"[PROFIT WITHDRAWAL] Bot {bot_id}: credited {trader_share:.2f} internally to trader {user_id} "
        f"(platform commissions are booked separately per profitable trade)"
    )
    return {
        'owner': 0.0,
        'referrer': 0.0,
        'trader': trader_share,
        'settledInternally': payout_success,
    }


_public_crypto_market_data_cache: Dict[str, Dict[str, Any]] = {}
_PUBLIC_CRYPTO_MARKET_DATA_TTL_SECONDS = 15


def _fetch_public_crypto_market_data(symbol: str) -> Optional[Dict[str, Any]]:
    normalized_symbol = str(_resolve_analysis_symbol(symbol) or symbol or '').strip().upper()
    if normalized_symbol.endswith('M'):
        normalized_symbol = normalized_symbol[:-1]
    if not normalized_symbol.endswith('USDT'):
        return None

    now = time.monotonic()
    cached_entry = _public_crypto_market_data_cache.get(normalized_symbol)
    if cached_entry and (now - float(cached_entry.get('ts') or 0.0)) < _PUBLIC_CRYPTO_MARKET_DATA_TTL_SECONDS:
        cached_data = cached_entry.get('data')
        if isinstance(cached_data, dict):
            return dict(cached_data)

    try:
        import requests

        response = requests.get(
            'https://api.binance.com/api/v3/klines',
            params={'symbol': normalized_symbol, 'interval': '1m', 'limit': 50},
            timeout=5,
        )
        if response.status_code != 200:
            return None

        payload = response.json()
        if not isinstance(payload, list) or not payload:
            return None

        close_prices = []
        for candle in payload:
            if isinstance(candle, list) and len(candle) > 4:
                try:
                    close_prices.append(float(candle[4]))
                except (TypeError, ValueError):
                    continue

        if not close_prices:
            return None

        current_price = float(close_prices[-1])
        high_price = max(close_prices)
        low_price = min(close_prices)
        volatility_pct = abs(high_price - low_price) / current_price * 100 if current_price > 0 else 1.0
        market_data = {
            'current_price': current_price,
            'price': current_price,
            'volatility_pct': max(volatility_pct, 0.1),
            'price_history': close_prices[-50:],
            'analysis_symbol': normalized_symbol,
            'data_source': 'binance_public_klines',
        }
        _public_crypto_market_data_cache[normalized_symbol] = {'ts': now, 'data': market_data}
        return dict(market_data)
    except Exception as exc:
        logger.debug(f'Public crypto market data fetch failed for {normalized_symbol}: {exc}')

    return None


def _get_market_data_for_symbol(symbol: str) -> Dict[str, Any]:
    resolved_symbol = _resolve_analysis_symbol(symbol)
    candidate_symbols = []
    for candidate in (symbol, resolved_symbol):
        normalized_candidate = str(candidate or '').strip()
        if normalized_candidate and normalized_candidate not in candidate_symbols:
            candidate_symbols.append(normalized_candidate)
        if normalized_candidate.endswith('m') and normalized_candidate[:-1] not in candidate_symbols:
            candidate_symbols.append(normalized_candidate[:-1])

    for candidate in candidate_symbols:
        if candidate in commodity_market_data:
            return commodity_market_data[candidate]

    # Fetch public crypto data once per 30 seconds per symbol
    public_crypto_market_data = _fetch_public_crypto_market_data(symbol)
    if public_crypto_market_data:
        return public_crypto_market_data

    return {'current_price': 0, 'volatility_pct': 1.0, 'price_history': [0]}


def _enrich_market_data_with_bot_context(
    bot_config: Optional[Dict[str, Any]],
    symbol: str,
    market_data: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    base_market_data = dict(market_data or _get_market_data_for_symbol(symbol))
    if not bot_config:
        return base_market_data

    broker_name = canonicalize_broker_name(
        bot_config.get('brokerName') or bot_config.get('broker_type') or bot_config.get('broker') or ''
    )
    if broker_name == 'Binance':
        public_crypto_market_data = _fetch_public_crypto_market_data(symbol)
        if public_crypto_market_data:
            base_market_data.update(public_crypto_market_data)

    adaptive_offset = int(bot_config.get('adaptiveSignalThresholdOffset') or 0)
    adaptive_miss_count = int(bot_config.get('adaptiveSignalMissCount') or 0)
    adaptive_reduction = min(adaptive_offset, ADAPTIVE_STRATEGY_MIN_SIGNAL_REDUCTION_MAX)
    if bot_config.get('managementState') == 'recovery':
        adaptive_reduction = 0

    base_market_data['adaptive_signal_threshold_offset'] = adaptive_offset
    base_market_data['adaptive_signal_miss_count'] = adaptive_miss_count
    base_market_data['adaptive_min_signal_reduction'] = adaptive_reduction
    # When user has pinned a manual signalThreshold, propagate it so the per-symbol
    # strategy floor (min_signal_strength) clamps to the user's intent. Otherwise the
    # hardcoded SYMBOL_PARAMETERS floor of 50 silently overrides a manual threshold of e.g. 2.
    try:
        if str(bot_config.get('signalThresholdMode') or '').strip().lower() == 'manual':
            _manual_thr = int(bot_config.get('signalThreshold') or 0)
            if _manual_thr > 0:
                base_market_data['bot_signal_threshold_override'] = _manual_thr
    except (TypeError, ValueError):
        pass
    return base_market_data


def _strategy_cache_key(strategy_func, symbol: str) -> str:
    return f"{getattr(strategy_func, '__name__', 'strategy')}::{symbol}"


def _get_cached_strategy_params(strategy_cache: Dict[str, Optional[Dict[str, Any]]], strategy_func, symbol: str,
                                account_id: str, risk_per_trade: float,
                                market_data: Optional[Dict[str, Any]] = None) -> Optional[Dict[str, Any]]:
    cache_key = _strategy_cache_key(strategy_func, symbol)
    if cache_key in strategy_cache:
        return strategy_cache[cache_key]

    if market_data is None:
        market_data = _get_market_data_for_symbol(symbol)

    strategy_cache[cache_key] = strategy_func(symbol, account_id, risk_per_trade, market_data)
    return strategy_cache[cache_key]


def _get_effective_symbol_params(symbol: str, market_data: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    symbol_key = _normalize_symbol_base(symbol)
    params = dict(SYMBOL_PARAMETERS.get(symbol_key, DEFAULT_SYMBOL_PARAMS))
    adaptive_reduction = 0
    if isinstance(market_data, dict):
        try:
            adaptive_reduction = int(market_data.get('adaptive_min_signal_reduction') or 0)
        except (TypeError, ValueError):
            adaptive_reduction = 0

    if symbol_key in SMALL_LIVE_ACCOUNT_OPTIONAL_CRYPTO_BASE_SYMBOLS:
        adaptive_reduction = min(adaptive_reduction, 5)

    params['effective_min_signal_strength'] = max(5, int(params['min_signal_strength']) - max(0, adaptive_reduction))
    # Honor bot manual signalThreshold: clamp per-symbol floor down to user's threshold
    # (never raise it). This lets a manual threshold of e.g. 2 actually allow weak signals
    # to pass strategy gates instead of being silently filtered by the 50-floor in SYMBOL_PARAMETERS.
    if isinstance(market_data, dict):
        _bot_thr_override = market_data.get('bot_signal_threshold_override')
        if _bot_thr_override is not None:
            try:
                params['effective_min_signal_strength'] = max(
                    5,
                    min(int(params['effective_min_signal_strength']), int(_bot_thr_override)),
                )
            except (TypeError, ValueError):
                pass
    return params


def _build_adaptive_raw_trade_params(
    symbol: str,
    market_data: Dict[str, Any],
    raw_signal: Dict[str, Any],
    bot_config: Optional[Dict[str, Any]] = None,
) -> Optional[Dict[str, Any]]:
    """Build a conservative fallback trade when scanner finds a strong raw setup.

    Used only by adaptive scanner mode when strategy-specific filters reject a
    setup that still has unusually strong raw signal quality.
    """
    order_type = extract_signal_direction(raw_signal.get('signal'))
    trend = str(raw_signal.get('trend') or '').upper()
    broker_name = canonicalize_broker_name(
        (bot_config or {}).get('brokerName') or (bot_config or {}).get('broker_type') or (bot_config or {}).get('broker') or ''
    )
    mode_value = str((bot_config or {}).get('mode') or (bot_config or {}).get('botMode') or 'demo').strip().lower()
    is_demo_mode = mode_value != 'live' and not bool((bot_config or {}).get('is_live'))
    demo_validation_fallback_enabled = _coerce_bool(
        os.getenv('DEMO_BINANCE_VALIDATION_FALLBACK', 'false'),
        False,
    )
    is_binance_demo_validation = (
        isinstance(bot_config, dict)
        and broker_name == 'Binance'
        and is_demo_mode
        and demo_validation_fallback_enabled
    )
    if trend == 'RANGING' and not is_binance_demo_validation:
        return None

    signal_payload = dict(raw_signal)
    if order_type is None and isinstance(bot_config, dict):
        broker_name = canonicalize_broker_name(
            bot_config.get('brokerName') or bot_config.get('broker_type') or bot_config.get('broker') or ''
        )
        adaptive_floor = _adaptive_signal_threshold_floor(bot_config)
        strength = float(raw_signal.get('strength') or 0.0)
        volatility = str(raw_signal.get('volatility') or '').upper()
        if (
            broker_name == 'FXCM'
            and strength >= adaptive_floor
            and trend in {'UP', 'DOWN'}
            and volatility in {'LOW', 'MEDIUM'}
        ):
            order_type = 'BUY' if trend == 'UP' else 'SELL'
            signal_payload['signal'] = order_type
            signal_payload['entry_reason'] = (
                f"{signal_payload.get('entry_reason', 'Neutral raw setup')} + "
                f"FXCM trend-directed fallback at adaptive floor"
            )

    if order_type is None and is_binance_demo_validation:
        strength = float(raw_signal.get('strength') or 0.0)
        adaptive_floor = _adaptive_signal_threshold_floor(bot_config)
        if strength >= adaptive_floor:
            order_type = 'BUY'
            signal_payload['signal'] = 'BUY'
            signal_payload['entry_reason'] = (
                f"{signal_payload.get('entry_reason', 'Neutral raw setup')} + "
                f"Demo Binance validation fallback BUY"
            )

    if order_type is None:
        return None

    params = _get_effective_symbol_params(symbol, market_data)
    strength = float(raw_signal.get('strength') or 0.0)
    if broker_name == 'FXCM':
        volume = 0.01 if strength < 85 else 0.02
    else:
        volume = 0.6 if strength < 85 else 0.75
    raw_reason = signal_payload.get('entry_reason', 'High-conviction raw scanner setup')
    signal_payload['entry_reason'] = f"{raw_reason} + Adaptive scanner raw-signal fallback"

    return {
        'symbol': symbol,
        'type': order_type,
        'volume': volume,
        'stop_loss': params['stop_loss_pips'],
        'take_profit': params['take_profit_pips'] * 1.4,
        'signal': attach_execution_direction(signal_payload, order_type, 'Adaptive Scanner Fallback'),
        'duration_seconds': 900,
        'execution_source': 'adaptive_raw_fallback',
    }


def _get_binance_spot_inventory_snapshot(active_conn, symbol: str, market_price: float = 0.0) -> Dict[str, Any]:
    normalized_symbol = active_conn._normalize_symbol(symbol) if hasattr(active_conn, '_normalize_symbol') else str(symbol or '').upper()
    base_asset = str(normalized_symbol or symbol or '').upper()
    if base_asset.endswith('USDT'):
        base_asset = base_asset[:-4]

    free_balance = 0.0
    if hasattr(active_conn, '_get_spot_asset_free_balance'):
        free_balance = _safe_float(active_conn._get_spot_asset_free_balance(base_asset), 0.0)

    min_qty = 0.0
    min_notional = 0.0
    step_size = 0.0
    normalized_balance = free_balance

    if hasattr(active_conn, '_get_spot_symbol_filters'):
        spot_filters = active_conn._get_spot_symbol_filters(normalized_symbol)
        if isinstance(spot_filters, dict):
            lot_size_filter = spot_filters.get('LOT_SIZE', {})
            min_notional_filter = spot_filters.get('MIN_NOTIONAL', {})
            notional_filter = spot_filters.get('NOTIONAL', {})
            min_qty = _safe_float(lot_size_filter.get('minQty'), 0.0)
            step_size = _safe_float(lot_size_filter.get('stepSize'), 0.0)
            min_notional = max(
                _safe_float(min_notional_filter.get('minNotional'), 0.0),
                _safe_float(notional_filter.get('minNotional'), 0.0),
            )
            if hasattr(active_conn, '_normalize_spot_quantity'):
                normalized_balance = _safe_float(
                    active_conn._normalize_spot_quantity(free_balance, step_size, 0.0),
                    free_balance,
                )

    if market_price <= 0 and hasattr(active_conn, '_get_spot_symbol_price'):
        market_price = _safe_float(active_conn._get_spot_symbol_price(normalized_symbol), 0.0)

    has_min_qty = min_qty <= 0 or normalized_balance >= min_qty
    has_min_notional = min_notional <= 0 or market_price <= 0 or (normalized_balance * market_price) >= min_notional
    is_sellable = normalized_balance > 0 and has_min_qty and has_min_notional

    return {
        'symbol': normalized_symbol,
        'baseAsset': base_asset,
        'freeBalance': free_balance,
        'normalizedBalance': normalized_balance,
        'marketPrice': market_price,
        'minQty': min_qty,
        'minNotional': min_notional,
        'isSellable': is_sellable,
    }

def validate_api_key():
    """Validate API key from request headers"""
    api_key = request.headers.get('Authorization', '').replace('Bearer ', '')
    if not api_key:
        return False, "Missing API key in Authorization header"
    if api_key != API_KEY:
        return False, "Invalid API key"
    return True, "Valid"

def require_api_key(f):
    """Decorator to require API key authentication"""
    from functools import wraps
    @wraps(f)
    def decorated_function(*args, **kwargs):
        valid, message = validate_api_key()
        if not valid:
            return jsonify({'success': False, 'error': message}), 401
        return f(*args, **kwargs)
    return decorated_function

def require_session(f):
    """Decorator to require valid session token and extract user_id"""
    from functools import wraps
    @wraps(f)
    def decorated_function(*args, **kwargs):
        # Get session token from header - CRITICAL DEBUGGING FOR 401 ISSUES
        session_token = request.headers.get('X-Session-Token')

        def _mask_session_token(token: str) -> str:
            token_str = str(token or '').strip()
            if not token_str:
                return '<empty>'
            if len(token_str) <= 12:
                return token_str
            return f"{token_str[:6]}...{token_str[-4:]}"
        
        # Log all headers to diagnose missing token issue
        if not session_token:
            event_key = f"missing_token:{request.method}:{request.path}:{request.remote_addr}"
            if should_log_session_event(event_key, 30):
                logger.warning(f"🚨 [CRITICAL] MISSING X-Session-Token for {request.method} {request.path}")
                logger.warning(f"📋 Headers received: {dict(request.headers)}")
                logger.warning(f"🌐 Client IP: {request.remote_addr}")
        else:
            logger.debug(f"[SESSION CHECK] Endpoint: {request.endpoint}, Token received: {session_token[:20]}...")
        
        if not session_token:
            if should_log_session_event(f"missing_token_fail:{request.endpoint}:{request.remote_addr}", 30):
                logger.error(f"[SESSION FAIL] Missing X-Session-Token header for {request.endpoint}")
            return jsonify({'success': False, 'error': 'Missing session token in X-Session-Token header'}), 401

        cached_user_id, cache_source = get_recent_cached_session(session_token)
        if cached_user_id:
            request.user_id = cached_user_id
            logger.debug(f"[SESSION OK] {cache_source.title()} cache hit for user {cached_user_id} on {request.endpoint}")
            return f(*args, **kwargs)
        
        try:
            conn = get_db_connection()
            cursor = conn.cursor()
            
            # Query user_sessions table
            logger.debug(f"[SESSION QUERY] Looking for token: '{_mask_session_token(session_token)}'")
            cursor.execute('''
                SELECT user_id, expires_at, is_active 
                FROM user_sessions 
                WHERE token = ? AND is_active = 1
            ''', (session_token,))
            
            session = cursor.fetchone()
            logger.debug(f"[SESSION QUERY RESULT] token_found={bool(session)}")
            conn.close()
            
            if not session:
                # Try without the is_active filter to see if token exists at all
                conn2 = get_db_connection()
                cursor2 = conn2.cursor()
                cursor2.execute('SELECT token, is_active FROM user_sessions WHERE token = ?', (session_token,))
                all_sessions = cursor2.fetchall()
                if should_log_session_event(f"token_status:{request.endpoint}:{request.remote_addr}", 30):
                    logger.info(f"[🔍 TOKEN STATUS] Found {len(all_sessions)} matching token(s): {all_sessions}")
                conn2.close()
                if should_log_session_event(f"invalid_token:{request.endpoint}:{request.remote_addr}", 30):
                    logger.error(f"[SESSION FAIL] Token not found in DB or inactive: {session_token[:20]}...")
                return jsonify({'success': False, 'error': 'Invalid or inactive session token'}), 401
            
            # Check expiration
            expires_at = datetime.fromisoformat(session['expires_at'])
            if expires_at < datetime.now():
                if should_log_session_event(f"expired_token:{session['user_id']}:{request.endpoint}", 30):
                    logger.error(f"[SESSION FAIL] Token expired for user {session['user_id']}")
                return jsonify({'success': False, 'error': 'Session token expired'}), 401
            
            # Attach user_id to request for use in the route handler
            request.user_id = session['user_id']
            SESSION_VALIDATION_CACHE[session_token] = {
                'user_id': session['user_id'],
                'expires_at': session['expires_at'],
                'validated_at': time.time(),
            }
            logger.debug(f"[SESSION OK] User {session['user_id']} authenticated for {request.endpoint}")
            return f(*args, **kwargs)
        except sqlite3.OperationalError as e:
            if 'locked' in str(e).lower():
                cached_user_id, cache_source = get_recent_cached_session(session_token)
                if cached_user_id:
                    request.user_id = cached_user_id
                    if should_log_session_event(f"session_lock_cache_fallback:{request.endpoint}:{request.remote_addr}", 15):
                        logger.warning(
                            f"[SESSION WARN] SQLite locked during session validation for {request.endpoint}; "
                            f"using {cache_source} cache for user {cached_user_id}"
                        )
                    return f(*args, **kwargs)
            logger.error(f"Error validating session: {e}")
            return jsonify({'success': False, 'error': 'Session validation error'}), 500
        except Exception as e:
            logger.error(f"Error validating session: {e}")
            return jsonify({'success': False, 'error': 'Session validation error'}), 500
    
    return decorated_function


@app.before_request
def audit_bot_requests():
    if request.path not in ['/api/bot/create', '/api/bot/start', '/api/bot/quick-create']:
        return None

    try:
        token = request.headers.get('X-Session-Token', '')
        token_preview = f"{token[:12]}..." if token else 'missing'
        payload = request.get_json(silent=True) or {}
        logger.info(
            f"[BOT REQUEST] {request.method} {request.path} from {request.remote_addr} "
            f"token={token_preview} payload_keys={sorted(payload.keys())}"
        )

        if request.path == '/api/bot/create':
            logger.info(
                f"[BOT CREATE REQUEST] credentialId={payload.get('credentialId')} "
                f"symbols={payload.get('symbols') or payload.get('symbol')} strategy={payload.get('strategy')}"
            )
        elif request.path == '/api/bot/start':
            logger.info(
                f"[BOT START REQUEST] botId={payload.get('botId')} user_id={payload.get('user_id')}"
            )
        elif request.path == '/api/bot/quick-create':
            logger.info(
                f"[BOT QUICK REQUEST] credentialId={payload.get('credentialId')} preset={payload.get('preset')}"
            )
    except Exception as exc:
        logger.warning(f"[BOT REQUEST] Audit logging failed for {request.path}: {exc}")

    return None

def require_admin(f):
    """Decorator to require admin authorization"""
    from functools import wraps
    @wraps(f)
    def decorated_function(*args, **kwargs):
        # Get API key for admin verification
        valid, message = validate_api_key()
        if not valid:
            return jsonify({'success': False, 'error': 'Admin authentication required'}), 401
        
        # Optionally add additional admin role check from database if needed
        # For now, API key validation is sufficient for admin endpoints
        return f(*args, **kwargs)
    
    return decorated_function

