def get_db_connection():
    """Get database connection with WAL mode for concurrent writes"""
    return build_sqlite_connection(
        timeout=SQLITE_CONNECTION_TIMEOUT_SECONDS,
        row_factory=True,
        busy_timeout_ms=SQLITE_BUSY_TIMEOUT_MS,
    )

