class MT5Connection(BrokerConnection):
    """MetaTrader 5 Broker Connection"""
    
    # MT5 PAUSE/HALT RETCODES - Market status codes indicating trading halts
    RETCODE_PAUSED = 10009        # Trading paused/halted for symbol
    RETCODE_NO_MONEY = 10019      # Insufficient funds / margin
    RETCODE_MARKET_CLOSED = 10026 # Market closed (weekend/outside hours)
    RETCODE_NO_LIQUIDITY = 10018  # No liquidity - market paused
    RETCODE_INVALID_REQUEST = 10016  # Invalid request - often during news events
    RETCODE_TRADE_MODE_DISABLED = 10015  # Trading disabled for symbol
    
    # Map of retcodes to pause reasons
    PAUSE_RETCODES = {
        10009: ('SYMBOL_HALTED', 'Trading halted/suspended for this symbol'),
        10026: ('MARKET_CLOSED', 'Market is closed (weekend or outside trading hours)'),
        10018: ('NO_LIQUIDITY', 'No liquidity available - market may be paused'),
        10016: ('INVALID_REQUEST', 'Invalid request - often during news events or market halt'),
        10015: ('TRADE_MODE_DISABLED', 'Trading disabled for this symbol'),
        10040: ('POSITION_LIMIT', 'Broker position limit reached for this symbol - close existing positions first'),
    }
    
    def __init__(self, credentials: Dict = None):
        # Use MT5_CONFIG if no credentials provided
        if credentials is None:
            credentials = {
                'account': MT5_CONFIG['account'],
                'password': MT5_CONFIG['password'],
                'server': MT5_CONFIG['server'],
                'broker': 'MetaQuotes',
            }

        super().__init__(BrokerType.METATRADER5, credentials)
        self.last_error = None
        self.last_error_code = None
        # CRITICAL FIX: DO NOT launch terminal on every connection attempt!
        # Terminal should only be launched ONCE during backend startup
        # Reuse the existing terminal for all subsequent connections
        self.mt5_broker = canonicalize_broker_name(credentials.get('broker', 'Exness'))
        
        # Check if terminal is already running (avoid duplicate launches)
        try:
            import subprocess, sys, os
            # Simply skip terminal launch - assume it was launched at startup
            # If terminal crashes, MT5Connection.connect() will timeout and retry
            logger.info(f"[MT5 Terminal] Using {self.mt5_broker} MT5 terminal (launched on backend startup)")
        except Exception as e:
            logger.error(f"[MT5 Terminal Manager] Error checking terminal: {e}")
        
        try:
            import MetaTrader5 as mt5
            self.mt5 = mt5
            broker_cfg = get_mt5_config_for_broker(self.mt5_broker)
            resolved_server = credentials.get('server') or broker_cfg.get('server')
            # Prefer explicit credential path, then broker-specific config path.
            # Pass is_live to select the correct terminal for dual-terminal setups
            is_live = normalize_mt5_is_live_flag(self.mt5_broker, credentials.get('is_live', False), resolved_server)
            self.mt5_path = find_mt5_terminal_path(
                self.mt5_broker,
                credentials.get('path') or broker_cfg.get('path'),
                is_live=is_live
            )
            self.mt5_path = resolve_mt5_terminal_executable_path(self.mt5_path) or self.mt5_path
            self._ensure_mt5_terminal_started()
        except ImportError:
            logger.error("MetaTrader5 not installed")
            self.mt5 = None

    def _clear_last_error(self):
        self.last_error = None
        self.last_error_code = None

    def _set_last_error(self, message: str, code=None):
        self.last_error = message
        self.last_error_code = code

    def _format_mt5_error(self, err) -> str:
        if err is None:
            return 'Unknown MT5 error'
        if isinstance(err, tuple):
            code = err[0] if len(err) > 0 else None
            details = ', '.join(str(part) for part in err[1:] if part not in [None, ''])
            return f'{details} (code {code})' if details else f'MT5 error code {code}'
        return str(err)

    def _is_auth_error(self, err) -> bool:
        if isinstance(err, tuple) and len(err) > 0 and err[0] == -6:
            return True
        message = self._format_mt5_error(err).lower()
        auth_markers = [
            'authorization failed',
            'auth failed',
            'invalid account',
            'invalid login',
            'invalid password',
            'invalid server',
            'unauthorized',
        ]
        return any(marker in message for marker in auth_markers)

    def _ensure_mt5_terminal_started(self):
        """Ensure the MT5 terminal is started once per configured terminal path."""
        global mt5_terminal_paths_started

        if DEPLOYMENT_MODE == 'VPS':
            logger.info(f"[MT5 Terminal] VPS deployment mode — skipping local MT5 launch for {self.mt5_broker}")
            return

        if not MT5_AUTO_LAUNCH:
            logger.info(f"[MT5 Terminal] Auto-launch disabled for {self.mt5_broker}; connect() will only use an already running terminal")
            return

        if not self.mt5_path:
            logger.warning(f"[MT5 Terminal] No terminal path configured for {self.mt5_broker}; cannot auto-launch MT5")
            return

        normalized_path = resolve_mt5_terminal_executable_path(self.mt5_path)
        if not normalized_path:
            logger.warning(f"[MT5 Terminal] No valid executable path configured for {self.mt5_broker}: {self.mt5_path}")
            return

        with mt5_terminal_startup_lock:
            if normalized_path in mt5_terminal_paths_started:
                return

            if is_mt5_process_running(normalized_path):
                logger.info(f"[MT5 Terminal] Existing MT5 process detected for {self.mt5_broker}; using running terminal")
                mt5_terminal_paths_started.add(normalized_path)
                return

            if ensure_mt5_terminal_running(normalized_path, self.mt5_broker):
                mt5_terminal_paths_started.add(normalized_path)

    def connect(self) -> bool:
        """
        Connect to MT5 with retry logic and better error handling
        CRITICAL: Uses global lock to prevent simultaneous MT5 connections
        OPTIMIZED: Reduced lock timeout and added exponential backoff for racing bots
        """
        global mt5_connection_lock
        is_priority_mode_switch = bool(self.credentials.get('priority_mode_switch'))
        self._clear_last_error()

        if mt5_priority_mode_switch.is_set() and not is_priority_mode_switch:
            logger.info("⏸️ MT5 priority mode switch in progress - skipping background reconnect attempt")
            self._set_last_error('MT5 mode switch already in progress', 'PRIORITY_MODE_ACTIVE')
            return False

        if is_priority_mode_switch:
            mt5_priority_mode_switch.set()
            logger.info("🚦 MT5 priority mode switch activated - background bots will back off during this connect")
        
        # Acquire lock with timeout - INCREASED from 10s to 25s for trading loops
        # Balance checks use 0.1s timeout (non-blocking) to avoid stalling
        # Trading loops use 25s to give MT5 enough time to complete a full trade cycle
        lock_timeout = self.credentials.get('lock_timeout', 60)  # 60 seconds default for trades (increased from 25s to handle 10+ concurrent bots)
        
        # CRITICAL FIX: If this is a balance fetch (marked by 'is_balance_check'), use fast timeout
        if self.credentials.get('is_balance_check'):
            lock_timeout = 0.1  # 100ms - fail fast for balance reads when MT5 is busy
            logger.info(f"⏳ Balance check: Waiting for MT5 lock (max {lock_timeout}s, non-blocking)...")
        else:
            logger.info(f"⏳ Waiting for exclusive MT5 connection lock (max {lock_timeout} seconds, sequential mode)...")
        
        wait_start = time.monotonic()
        with mt5_lock_metrics_lock:
            mt5_lock_metrics['pending_waiters'] += 1
        lock_acquired = mt5_connection_lock.acquire(timeout=float(lock_timeout))
        wait_seconds = time.monotonic() - wait_start
        with mt5_lock_metrics_lock:
            mt5_lock_metrics['pending_waiters'] = max(0, mt5_lock_metrics['pending_waiters'] - 1)
            mt5_lock_metrics['acquire_count'] += 1
            mt5_lock_metrics['total_wait_seconds'] += wait_seconds
            if wait_seconds > mt5_lock_metrics['max_wait_seconds']:
                mt5_lock_metrics['max_wait_seconds'] = wait_seconds
        
        if not lock_acquired:
            with mt5_lock_metrics_lock:
                mt5_lock_metrics['timeout_count'] += 1
            logger.warning(f"⚠️ TIMEOUT: Could not acquire MT5 lock after {lock_timeout} seconds - system is busy")
            retry_delay = self.credentials.get('tradingInterval', 300) + random.uniform(1, 10)  # Add 1-10s random delay
            logger.warning(f"   Will retry in {retry_delay:.0f}s with staggered delay to reduce lock contention")
            logger.info(
                f"[MT5 LOCK METRICS] wait={wait_seconds:.2f}s pending={mt5_lock_metrics.get('pending_waiters', 0)} "
                f"timeouts={mt5_lock_metrics.get('timeout_count', 0)}"
            )
            self._set_last_error('MT5 is busy. Please try again in a few seconds.', 'LOCK_TIMEOUT')
            return False  # Return False to signal connection failed, bot will retry next cycle
        
        try:
            logger.info(
                f"✅ Acquired MT5 connection lock after {wait_seconds:.2f}s - proceeding with connection"
            )
            return self._connect_with_lock()
        finally:
            # CRITICAL: Always release the lock, even if connection fails
            mt5_connection_lock.release()
            if is_priority_mode_switch:
                mt5_priority_mode_switch.clear()
                logger.info("✅ MT5 priority mode switch completed - background bot reconnects may resume")
    
    def _connect_with_lock(self) -> bool:
        """Internal connection method - always called within mt5_connection_lock"""
        global balance_cache, balance_cache_lock, mt5_current_account  # Declare globals at function start (required by Python)
        
        try:
            if not self.mt5:
                logger.error("MetaTrader5 SDK not available")
                self._set_last_error('MetaTrader5 SDK not available on the backend', 'SDK_UNAVAILABLE')
                return False

            broker_name = canonicalize_broker_name(self.credentials.get('broker', self.mt5_broker))
            broker_cfg = get_mt5_config_for_broker(broker_name)

            account = self.credentials.get('account') or self.credentials.get('account_number') or broker_cfg.get('account')
            password = self.credentials.get('password') or broker_cfg.get('password')
            server = self.credentials.get('server') or broker_cfg.get('server')
            is_live = normalize_mt5_is_live_flag(broker_name, self.credentials.get('is_live', False), server)

            if account and not self.credentials.get('account'):
                self.credentials['account'] = account
            if account and not self.credentials.get('account_number'):
                self.credentials['account_number'] = account
            
            server = normalize_mt5_server_name(broker_name, is_live, server)
            self.credentials['server'] = server

            route_diagnostic = log_mt5_route_diagnostic(
                'MT5Connection.connect',
                {
                    'broker': broker_name,
                    'broker_name': broker_name,
                    'account': account,
                    'account_number': account,
                    'server': server,
                    'path': self.mt5_path,
                    'is_live': is_live,
                },
            )
            if route_diagnostic.get('selected_path'):
                self.mt5_path = route_diagnostic['selected_path']

            normalized_path = resolve_mt5_terminal_executable_path(self.mt5_path)
            if normalized_path:
                self.mt5_path = normalized_path
                route_diagnostic = log_mt5_route_diagnostic(
                    'MT5Connection.connect.resolved',
                    {
                        'broker': broker_name,
                        'broker_name': broker_name,
                        'account': account,
                        'account_number': account,
                        'server': server,
                        'path': normalized_path,
                        'is_live': is_live,
                    },
                )
            
            # Ensure account is integer for proper comparison with MT5 login field
            account = int(account)
            is_manual_test = bool(self.credentials.get('is_manual_test', False))
            
            # CRITICAL FIX: Check if already logged into this account on this terminal
            # If so, return True immediately without attempting re-init
            # This prevents loss of session on reconnection attempts
            try:
                existing_info = self.mt5.account_info()
                if existing_info and existing_info.login == account:
                    logger.info(f"✅ MT5 already logged in to account {account} - reusing existing connection")
                    self.connected = True
                    self.account_info = existing_info
                    # Track which account is active for multi-user awareness
                    with mt5_account_lock:
                        mt5_current_account = account
                    return True
            except Exception as e:
                logger.debug(f"  (Checking existing session: {e})")
            
            # Not logged in to correct account yet - proceed with login
            
            # Check failed-auth cooldown - skip accounts that recently failed authorization
            with _failed_auth_lock:
                if not is_manual_test and account in _failed_auth_accounts:
                    fail_info = _failed_auth_accounts[account]
                    elapsed = time.time() - fail_info['timestamp']
                    if elapsed < _FAILED_AUTH_COOLDOWN:
                        logger.warning(f"⏭️ Skipping account {account} - auth failed {elapsed:.0f}s ago (cooldown: {_FAILED_AUTH_COOLDOWN}s)")
                        self._set_last_error('Authentication for this account recently failed. Please wait before retrying.', 'AUTH_COOLDOWN')
                        return False
                    else:
                        # Cooldown expired, allow retry
                        del _failed_auth_accounts[account]
                        logger.info(f"🔄 Auth cooldown expired for account {account} - allowing retry")
            
            logger.info(f"Attempting login to account {account}...")
            
            # FAST PATH: If MT5 terminal is already running (initialized), switch accounts
            # using mt5.login() — this takes ~1-2s vs mt5.initialize() which can block for 30s+.
            # This is critical for single-terminal VPS mode where one terminal serves all accounts.
            force_initialize_on_selected_path = False
            try:
                _ver = self.mt5.version()  # Returns non-None when MT5 is already initialized
                version_ready = _ver not in [None, (0, 0, ''), (0, 0, '0')]
                if version_ready:
                    _term_info = None
                    try:
                        _term_info = self.mt5.terminal_info()
                    except Exception:
                        _term_info = None

                    _current_path = str(getattr(_term_info, 'path', '') or '').strip().strip('"').strip("'")
                    _path_mismatch = bool(
                        normalized_path and _current_path and
                        os.path.normcase(os.path.normpath(_current_path)) != os.path.normcase(os.path.normpath(normalized_path))
                    )

                    if _path_mismatch:
                        force_initialize_on_selected_path = True
                        logger.info(
                            f"  🔁 MT5 is attached to terminal '{_current_path}', but account {account} needs '{normalized_path}' — forcing initialize() on the correct terminal"
                        )
                    else:
                        logger.info(f"  🔑 MT5 already running (v{_ver}) — using fast mt5.login() to switch to account {account}")
                        login_ok = self.mt5.login(int(account), password=str(password), server=str(server))
                        if login_ok:
                            time.sleep(1)  # Brief stabilisation
                            acct_check = self.mt5.account_info()
                            if acct_check and acct_check.login == int(account):
                                self.connected = True
                                logger.info(f"✅ Fast-switched to MT5 account {account} ({getattr(acct_check, 'currency', 'USD')}) in single-terminal mode")
                                with mt5_account_lock:
                                    mt5_current_account = int(account)
                                self.get_account_info()
                                try:
                                    if self.account_info:
                                        with balance_cache_lock:
                                            ck = get_balance_cache_key(broker_name, account)
                                            bal = float(self.account_info.get('balance', 0))
                                            balance_cache[ck] = {
                                                'balance': bal,
                                                'equity': float(self.account_info.get('equity', 0)),
                                                'margin': float(self.account_info.get('margin', 0)),
                                                'marginFree': float(self.account_info.get('marginFree', 0)),
                                                'margin_level': float(self.account_info.get('margin_level', 0)),
                                                'currency': self.account_info.get('currency', 'USD'),
                                                'timestamp': time.time()
                                            }
                                            logger.info(f"  💾 [FAST-SWITCH CACHE] {ck} = {bal:.2f} {balance_cache[ck]['currency']}")
                                except Exception as ce:
                                    logger.warning(f"  ⚠️  Failed to cache balance after fast-switch: {ce}")
                                self._subscribe_symbols()
                                return True
                            else:
                                logger.warning(f"  ⚠️ Fast login succeeded but account verification failed — falling back to initialize()")
                        else:
                            err = self.mt5.last_error()
                            logger.warning(f"  ⚠️ Fast mt5.login() failed: {err} — falling back to initialize()")
                            if is_manual_test and self._is_auth_error(err):
                                self._set_last_error('Invalid Exness account number, password, or server.', 'AUTH_FAILED')
                                return False
                else:
                    logger.info(f"  ⏳ MT5 version probe returned {_ver}; IPC not ready for fast login, using initialize() path")
            except Exception as fe:
                logger.debug(f"  (Fast-path mt5.login() not attempted: {fe})")
            
            # Retry logic: balance checks get 1 attempt (fast fail), trading gets 3
            is_balance_check = self.credentials.get('is_balance_check', False)
            max_retries = 1 if (is_balance_check or is_manual_test) else 3
            for attempt in range(1, max_retries + 1):
                logger.info(f"MT5 connection attempt {attempt}/{max_retries}: Account={account}, Server={server}")
                
                try:
                    init_ok = False
                    if force_initialize_on_selected_path and attempt == 1:
                        logger.info("  ⏳ Waiting 10s for the selected MT5 terminal to expose its IPC channel before initialize()...")
                        time.sleep(10)
                    
                    # On retry attempts, just wait longer for IPC - DON'T kill MT5 terminal
                    # Killing the terminal causes loss of login session and requires manual re-login
                    # Instead, just give IPC connection more time to recover
                    if attempt > 1:
                        logger.info(f"  🔄 Allowing MT5 IPC more time to stabilize before retry...")
                        # CRITICAL FIX: Keep terminal running - just wait for recovery
                        retry_wait = 5 + (2 * attempt)
                        logger.info(f"     IPC recovery delay: {retry_wait} seconds (exponential backoff)")
                        time.sleep(retry_wait)
                    
                    # Always use broker-specific MT5 path (NO generic fallback)
                    if not self.mt5_path:
                        logger.error(f"❌ No {broker_name} MT5 path configured - cannot continue without broker-specific MT5")
                        self._set_last_error(f'No {broker_name} MT5 terminal path is configured on the backend.', 'PATH_NOT_CONFIGURED')
                        continue
                    
                    # Initialize with broker-specific path only
                    if normalized_path and os.path.isfile(normalized_path):
                        # Pass login credentials directly in initialize() to avoid MT5 auth races.
                        logger.info(f"  🔑 Calling mt5.initialize(path='{normalized_path}', login={account}, server='{server}')")
                        init_ok = self.mt5.initialize(
                            path=normalized_path,
                            login=int(account),
                            password=str(password),
                            server=str(server)
                        )
                        if init_ok:
                            self.mt5_path = normalized_path
                            logger.info(f"  ✓ MT5 initialize() returned True")
                        else:
                            logger.warning(f"  ✗ {broker_name} MT5 initialization failed: {self.mt5.last_error()}")
                    else:
                        logger.warning(f"  ✗ {broker_name} MT5 path not found: {normalized_path}")
                        init_ok = False

                    if init_ok:
                        # Successfully initialized AND authenticated (credentials passed to initialize)
                        logger.info(f"  ✓ MT5 initialized and authenticated (path: {self.mt5_path})")
                        
                        # Brief IPC stabilization wait
                        ipc_wait = 3
                        logger.info(f"  ⏳ Waiting {ipc_wait}s for MT5 IPC stabilization...")
                        time.sleep(ipc_wait)
                        
                        # Verify account is accessible
                        acct_info = self.mt5.account_info()
                        if acct_info and acct_info.login == int(account):
                            self.connected = True
                            logger.info(f"✅ Logged in to MT5 account {account} successfully")
                            # Track which account is active for multi-user awareness
                            with mt5_account_lock:
                                mt5_current_account = int(account)
                            self.get_account_info()
                            
                            # CRITICAL FIX: Populate balance cache IMMEDIATELY after login success
                            try:
                                if self.account_info:
                                    with balance_cache_lock:
                                        cache_key = get_balance_cache_key(broker_name, account)
                                        balance = float(self.account_info.get('balance', 0))
                                        # IMPORTANT: Store all distinct metrics (not just balance for all)
                                        balance_cache[cache_key] = {
                                            'balance': balance,
                                            'equity': float(self.account_info.get('equity', 0)),
                                            'margin': float(self.account_info.get('margin', 0)),
                                            'marginFree': float(self.account_info.get('marginFree', 0)),
                                            'margin_level': float(self.account_info.get('margin_level', 0)),
                                            'currency': self.account_info.get('currency', 'USD'),
                                            'timestamp': time.time()
                                        }
                                        cache_currency = str(balance_cache[cache_key].get('currency', 'USD') or 'USD').upper()
                                        logger.info(
                                            f"  💾 [BOT CACHE] Key='{cache_key}' Balance={balance:.2f} {cache_currency} "
                                            f"Equity={balance_cache[cache_key]['equity']:.2f} {cache_currency} "
                                            f"MarginFree={balance_cache[cache_key]['marginFree']:.2f} {cache_currency} "
                                            f"(Total cache entries: {len(balance_cache)})"
                                        )
                            except Exception as e:
                                logger.warning(f"  ⚠️  Failed to cache balance after login: {e}")
                            
                            # Subscribe to all symbols for trading
                            self._subscribe_symbols()
                            return True
                        else:
                            logger.warning(f"  ✗ Account verification failed after initialize - will retry")
                            if is_manual_test:
                                self._set_last_error('MT5 could not verify the requested account after login.', 'VERIFICATION_FAILED')
                                return False
                            continue
                    
                    else:
                        init_error = self.mt5.last_error()
                        logger.warning(f"  ✗ MT5 initialization failed: {init_error}")
                        self._set_last_error(
                            self._format_mt5_error(init_error),
                            init_error[0] if isinstance(init_error, tuple) and len(init_error) > 0 else 'INIT_FAILED'
                        )
                        if is_manual_test and self._is_auth_error(init_error):
                            self._set_last_error('Invalid Exness account number, password, or server.', 'AUTH_FAILED')
                            return False
                        # Check for IPC timeout during initialization
                        error_code = init_error[0] if isinstance(init_error, tuple) else -1
                        if error_code in [-10005, -10004]:  # IPC timeout or No IPC connection
                            logger.warning(f"  ⚠️  IPC CONNECTION ISSUE - will wait longer before retry")
                            ensure_mt5_terminal_running(self.mt5_path, broker_name)
                        logger.debug(f"    (Terminal process may still be starting...)")
                
                except Exception as e:
                    logger.warning(f"  ✗ Error during attempt {attempt}: {e}")
                
                # Wait before retry with exponential backoff
                if attempt < max_retries:
                    # Exponential backoff: 5s, 7s, (no 3rd wait as this completes loop)
                    wait_time = 5 + (2 * attempt)
                    logger.info(f"  ⏳ Retry in {wait_time}s (exponential backoff)...")
                    time.sleep(wait_time)
            
            # All retries exhausted
            logger.error(f"❌ Failed to connect to MT5 after {max_retries} attempts")
            
            # Track auth failures so we don't keep retrying bad credentials
            # Only track if the failure was auth-related (not IPC timeout from contention)
            try:
                last_err = self.mt5.last_error() if self.mt5 else None
                if self._is_auth_error(last_err):
                    self._set_last_error('Invalid Exness account number, password, or server.', 'AUTH_FAILED')
                elif last_err and not self.last_error:
                    self._set_last_error(
                        self._format_mt5_error(last_err),
                        last_err[0] if isinstance(last_err, tuple) and len(last_err) > 0 else 'CONNECT_FAILED'
                    )

                if not is_manual_test and last_err and isinstance(last_err, tuple) and last_err[0] == -6:  # Authorization failed
                    with _failed_auth_lock:
                        _failed_auth_accounts[account] = {
                            'timestamp': time.time(),
                            'error': str(last_err)
                        }
                        logger.warning(f"🚫 Account {account} added to auth cooldown ({_FAILED_AUTH_COOLDOWN}s) due to auth failure")
            except Exception:
                pass

            if not self.last_error:
                self._set_last_error('Failed to connect to MT5.', 'CONNECT_FAILED')
            
            return False
            
        except Exception as e:
            logger.error(f"MT5 connection error: {e}")
            self._set_last_error(str(e), 'EXCEPTION')
            return False

    def disconnect(self) -> bool:
        """Disconnect from MT5 - marks as disconnected but does NOT call mt5.shutdown()
        because the MT5 terminal is a shared singleton used by all bots.
        Calling shutdown() would kill connections for ALL bots and API endpoints."""
        try:
            # CRITICAL: Do NOT call self.mt5.shutdown() here!
            # The MT5 terminal is shared across all bots and API endpoints.
            # Just mark this connection object as disconnected.
            self.connected = False
            return True
        except Exception as e:
            logger.error(f"MT5 disconnect error: {e}")
            return False

    def _subscribe_symbols(self):
        """Subscribe all trading symbols so they're available for order placement"""
        if not self.connected or not self.mt5:
            return
        
        subscribed = 0
        failed = 0
        failed_symbols = []
        
        # Retry up to 3 times — MT5 terminal needs a few seconds after login
        # before symbol_select() becomes reliable
        MAX_SUB_RETRIES = 3
        ready_symbols = get_mt5_ready_symbols_for_broker(self.mt5_broker)
        for attempt in range(1, MAX_SUB_RETRIES + 1):
            subscribed = 0
            failed = 0
            failed_symbols = []
            for symbol in ready_symbols:
                try:
                    if self.mt5.symbol_select(symbol, True):
                        subscribed += 1
                    else:
                        failed += 1
                        failed_symbols.append(symbol)
                except Exception as e:
                    logger.warning(f"⚠️  Error subscribing to {symbol}: {e}")
                    failed += 1
                    failed_symbols.append(symbol)
            
            if subscribed > 0 or attempt == MAX_SUB_RETRIES:
                break
            # All failed — terminal still loading; wait and retry
            logger.warning(f"⚠️  Symbol subscription attempt {attempt}/{MAX_SUB_RETRIES}: 0/{len(ready_symbols)} symbols ready — terminal still loading, retrying in 5s...")
            time.sleep(5)
        
        logger.info(f"✅ Symbol subscription complete: {subscribed}/{len(ready_symbols)} symbols ready for trading")
        if failed > 0:
            logger.warning(f"⚠️  {failed} symbols unavailable: {failed_symbols}")
            logger.warning(f"   These symbols may not be available on this account/server")
            available = [s for s in ready_symbols if s not in failed_symbols]
            if available:
                logger.info(f"   Available symbols: {available}")

    def wait_for_mt5_ready(self, timeout_seconds: int = 60) -> bool:
        """
        Wait for MT5 terminal to be fully ready to execute orders.
        After MT5 restart, the terminal can connect but needs time to be operational.
        
        This method:
        1. Checks account info (basic connectivity)
        2. Checks symbol availability and market data (reading capability)
        3. Checks market hours and trading status (trading capability)
        4. Tests order execution path (full readiness test)
        5. Retries with increasing detail if any check fails
        """
        if not self.connected:
            logger.warning("MT5 not connected - cannot check readiness")
            return False
        
        logger.info(f"🔍 Comprehensive MT5 readiness check (timeout: {timeout_seconds}s)...")
        
        start_time = time.time()
        check_interval = 5  # Check every 5 seconds
        attempt = 0
        
        while time.time() - start_time < timeout_seconds:
            attempt += 1
            try:
                elapsed = time.time() - start_time
                
                # STEP 1: Check account info
                account_info = self.mt5.account_info()
                if account_info is None:
                    logger.debug(f"  Attempt {attempt} [{elapsed:.0f}s]: account_info = None")
                    time.sleep(check_interval)
                    continue
                
                account_currency = str(getattr(account_info, 'currency', 'USD') or 'USD').upper()
                logger.debug(
                    f"  Attempt {attempt} [{elapsed:.0f}s]: account_info OK "
                    f"(balance={float(account_info.balance):.2f} {account_currency})"
                )
                
                # STEP 2: Check symbol availability and data
                ready_symbols = get_mt5_ready_symbols_for_broker(self.mt5_broker)
                test_symbol = ready_symbols[0] if ready_symbols else normalize_symbol_for_broker('EURUSD', self.mt5_broker)
                if not self.mt5.symbol_select(test_symbol, True):
                    logger.debug(f"  Attempt {attempt} [{elapsed:.0f}s]: symbol_select({test_symbol}) failed")
                    time.sleep(check_interval)
                    continue
                
                tick = self.mt5.symbol_info_tick(test_symbol)
                if tick is None:
                    logger.debug(f"  Attempt {attempt} [{elapsed:.0f}s]: tick data not available")
                    time.sleep(check_interval)
                    continue
                
                logger.debug(f"  Attempt {attempt} [{elapsed:.0f}s]: {test_symbol} tick OK (bid={tick.bid}, ask={tick.ask})")
                
                # STEP 3: Check symbol info (trading rules, hours, etc)
                symbol_info = self.mt5.symbol_info(test_symbol)
                if symbol_info is None:
                    logger.debug(f"  Attempt {attempt} [{elapsed:.0f}s]: symbol_info({test_symbol}) = None")
                    time.sleep(check_interval)
                    continue
                
                is_tradable = symbol_info.trade_mode != self.mt5.SYMBOL_TRADE_MODE_DISABLED
                logger.debug(f"  Attempt {attempt} [{elapsed:.0f}s]: symbol_info OK (tradable={is_tradable})")
                
                # STEP 4: Diagnose why order_send might fail
                # Check if this is a permissions/state issue vs system issue
                logger.debug(f"  Attempt {attempt} [{elapsed:.0f}s]: Running order execution diagnostic...")
                
                # Try to get positions to verify trading API is responding
                positions = self.mt5.positions_get()
                logger.debug(f"  Attempt {attempt} [{elapsed:.0f}s]: positions_get() returned {len(positions) if positions else 'None'} positions")
                
                # Try to get account orders
                orders = self.mt5.orders_get()
                logger.debug(f"  Attempt {attempt} [{elapsed:.0f}s]: orders_get() returned {len(orders) if orders else 'None'} orders")
                
                # If we got here, terminal is reading data fine
                # Now test the order execution path with order_check (NOT order_send — that would place a real trade!)
                logger.debug(f"  Attempt {attempt} [{elapsed:.0f}s]: Testing order submission path with order_check()...")
                
                # Build a test order request — order_check validates without executing
                filling_type = self._get_filling_type(test_symbol)
                test_request = {
                    "action": self.mt5.TRADE_ACTION_DEAL,
                    "symbol": test_symbol,
                    "volume": 0.01,  # Micro volume for test
                    "type": self.mt5.ORDER_TYPE_BUY,
                    "price": tick.ask,
                    "comment": "ZTEST",  # Short comment within MT5's 31-char limit
                    "type_time": self.mt5.ORDER_TIME_GTC,
                    "type_filling": filling_type,
                }
                
                test_result = self.mt5.order_check(test_request)
                
                # ── order_check result interpretation ──────────────────────────────
                # order_check() returns None when the terminal IPC is broken.
                # It returns a result object (even with a non-zero retcode) when the
                # SDK is functional — e.g. retcode 10018 = "market closed" (weekend),
                # retcode 10019 = "no money", retcode 10030 = "invalid fill".
                # We only block on a true None (IPC issue); logical rejections mean
                # the terminal IS running — just the market or account has a constraint.
                if test_result is None:
                    # After 3 failed order_check attempts with valid account/tick/symbol,
                    # consider the terminal ready anyway (market may be closed / weekend).
                    # order_send() works fine even when order_check() returns None on weekends.
                    if attempt >= 3:
                        logger.warning(f"  ⚠️  order_check() persistently None after {attempt} attempts — terminal responds to all other calls.")
                        logger.warning(f"  🕐 Likely cause: market is closed (weekend/holiday) or demo account restriction.")
                        logger.info(f"✅ MT5 is READY (connectivity confirmed via account_info + tick + symbol_info)")
                        logger.info(f"   Account: {account_info.login}, Balance: ${account_info.balance}")
                        logger.info(f"   Symbol {test_symbol}: bid={tick.bid:.5f}, ask={tick.ask:.5f}")
                        return True
                    logger.warning(f"  Attempt {attempt} [{elapsed:.0f}s]: ⚠️  order_check() returned None (IPC not ready)")
                    time.sleep(check_interval)
                    continue
                
                # order_check returned a valid object — SDK is fully operational.
                if hasattr(test_result, 'retcode'):
                    retcode = test_result.retcode
                    # Codes that mean "terminal works but market/account prevented it"
                    LOGICAL_REJECTION_CODES = {10018, 10019, 10014, 10030, 10031, 10032, 10033}
                    if retcode == 0 or retcode in LOGICAL_REJECTION_CODES:
                        pass  # expected — terminal is healthy
                    else:
                        logger.debug(f"  Attempt {attempt} [{elapsed:.0f}s]: order_check retcode={retcode} (non-zero but terminal is live)")
                    logger.info(f"✅ MT5 is READY - order execution path is functional (order_check retcode={retcode})")
                    logger.info(f"   Account: {account_info.login}, Balance: ${account_info.balance}")
                    logger.info(f"   Symbol {test_symbol}: bid={tick.bid:.5f}, ask={tick.ask:.5f}")
                    
                    # CRITICAL FIX: Update global balance cache so balance API calls return real data
                    global balance_cache, balance_cache_lock
                    try:
                        with balance_cache_lock:
                            # Use consistent cache key format (also used by balance endpoint)
                            cache_key = get_balance_cache_key('Exness', account_info.login)
                            # IMPORTANT: Store all distinct metrics (not just balance for all)
                            balance_cache[cache_key] = {
                                'balance': float(account_info.balance),
                                'equity': float(account_info.equity),
                                'margin': float(account_info.margin) if hasattr(account_info, 'margin') else 0,
                                'marginFree': float(account_info.margin_free) if hasattr(account_info, 'margin_free') else float(account_info.balance),
                                'margin_level': float(account_info.margin_level) if hasattr(account_info, 'margin_level') else 0,
                                'currency': account_info.currency if hasattr(account_info, 'currency') else 'USD',
                                'timestamp': time.time()
                            }
                        logger.info(f"  💾 Cached balance for {cache_key}: ${account_info.balance} equity=${account_info.equity} margin=${account_info.margin_free} (cache size: {len(balance_cache)} entries)")
                    except Exception as e:
                        logger.error(f"  ❌ Failed to update balance cache: {e}")
                    return True
                else:
                    logger.debug(f"  Attempt {attempt} [{elapsed:.0f}s]: order_check() returned object without retcode")
                    logger.info(f"✅ MT5 is READY - SDK responding to order requests")
                    return True
                    
            except Exception as e:
                logger.debug(f"  Attempt {attempt} [{elapsed:.0f}s]: Exception: {e}")
                time.sleep(check_interval)
        
        # Timeout reached
        logger.error(f"❌ MT5 did not become fully ready within {timeout_seconds} seconds")
        logger.error("   Symptoms: order_send() returning None even though connection works")
        logger.error("   Likely causes:")
        logger.error("   1. MT5 terminal is still initializing (needs more time)")
        logger.error("   2. Terminal lost connection to server")
        logger.error("   3. Account restrictions on trading")
        return False

    def get_account_info(self) -> Dict:
        """Get COMPREHENSIVE account information from Exness MT5"""
        try:
            if not self.connected:
                return None

            info = self.mt5.account_info()
            if info is None:
                last_error = None
                try:
                    last_error = self.mt5.last_error()
                except Exception:
                    last_error = None
                logger.warning(f"MT5 account_info() returned None while fetching account details; last_error={last_error}")
                return None

            def _safe_float(value, default: float = 0.0) -> float:
                try:
                    if value is None:
                        return default
                    return float(value)
                except (TypeError, ValueError):
                    return default
            
            # Get positions for aggregate data
            positions = self.mt5.positions_get()
            total_positions = len(positions) if positions else 0
            total_volume = sum(pos.volume for pos in positions) if positions else 0
            total_pnl = sum(pos.profit for pos in positions) if positions else 0
            
            # Get orders (pending)
            orders = self.mt5.orders_get()
            total_pending = len(orders) if orders else 0
            
            # Calculate additional metrics
            balance = round(_safe_float(getattr(info, 'balance', None)), 2)
            equity = round(_safe_float(getattr(info, 'equity', None)), 2)
            floating_pl = round(_safe_float(getattr(info, 'profit', None)), 2)
            used_margin = round(_safe_float(getattr(info, 'margin', None)), 2)
            free_margin = round(_safe_float(getattr(info, 'margin_free', None)), 2)
            margin_level = round(_safe_float(getattr(info, 'margin_level', None)), 2)
            margin_percentage = (used_margin / (used_margin + free_margin) * 100) if (used_margin + free_margin) > 0 else 0
            account_currency = str(getattr(info, 'currency', 'USD') or 'USD').upper()
            
            # Comprehensive account data
            self.account_info = {
                # === BASIC INFO ===
                'accountNumber': info.login,
                'broker': info.server,
                'company': info.company if hasattr(info, 'company') else 'Exness',
                'currency': account_currency,
                'displayCurrency': account_currency,
                
                # === BALANCE & EQUITY ===
                'balance': balance,
                'equity': equity,
                'floatingPL': floating_pl,
                'realizedPL': round(balance - equity, 2),  # Closed P&L
                
                # === MARGIN METRICS ===
                'margin': used_margin,
                'marginFree': free_margin,
                'marginLevel': margin_level,
                'marginPercentage': round(margin_percentage, 2),
                'usedMarginPercentage': round((used_margin / (used_margin + free_margin) * 100), 2) if (used_margin + free_margin) > 0 else 0,
                
                # === LEVERAGE & LIMITS ===
                'leverage': info.leverage,
                'limitOrders': info.limits_orders if hasattr(info, 'limits_orders') else 0,
                'limitVolume': info.limit_volume if hasattr(info, 'limit_volume') else 0,
                'limitSymbols': info.limit_symbols if hasattr(info, 'limit_symbols') else 0,
                
                # === ACCOUNT TYPE ===
                'tradeMode': self._get_trade_mode(info),
                'accountType': self._get_account_type(info),
                'accountStopout': info.fifo_close if hasattr(info, 'fifo_close') else False,
                
                # === POSITION STATISTICS ===
                'openPositions': total_positions,
                'pendingOrders': total_pending,
                'totalVolume': total_volume,
                'totalPositionPL': round(total_pnl, 2),
                
                # === ACCOUNT RESTRICTIONS ===
                'tradeAllowed': info.trade_allowed if hasattr(info, 'trade_allowed') else True,
                'investMode': info.trade_mode if hasattr(info, 'trade_mode') else 0,
                'fifoClose': info.fifo_close if hasattr(info, 'fifo_close') else False,
                
                # === TIMESTAMP ===
                'lastUpdate': datetime.utcnow().isoformat(),
            }
            return self.account_info
        except Exception as e:
            logger.error(f"Error getting MT5 account info: {e}")
            return None
    
    def _get_trade_mode(self, info) -> str:
        """Determine trade mode from MT5 account"""
        try:
            if hasattr(info, 'trade_mode'):
                mode = info.trade_mode
                modes = {
                    0: 'DEMO',
                    1: 'REAL',
                    2: 'CONTEST'
                }
                return modes.get(mode, 'UNKNOWN')
            return 'UNKNOWN'
        except:
            return 'UNKNOWN'
    
    def _get_account_type(self, info) -> str:
        """Determine account type from MT5 account info"""
        try:
            if hasattr(info, 'account_type'):
                acc_type = info.account_type
                types = {
                    0: 'DEMO',
                    1: 'CONTEST',
                    2: 'REAL'
                }
                return types.get(acc_type, 'UNKNOWN')
            return 'UNKNOWN'
        except:
            return 'UNKNOWN'

    def get_positions(self) -> List[Dict]:
        """Get open positions with DETAILED metrics"""
        try:
            if not self.connected:
                return []

            positions = self.mt5.positions_get()
            result = []
            if not positions:
                return result
            for pos in positions:
                # Calculate additional metrics per position
                pnl_percentage = ((pos.price_current - pos.price_open) / pos.price_open * 100) if pos.price_open != 0 else 0
                swap = pos.swap if hasattr(pos, 'swap') else 0
                commission = pos.commission if hasattr(pos, 'commission') else 0
                comment = pos.comment if hasattr(pos, 'comment') else ''
                
                result.append({
                    'ticket': pos.ticket,
                    'symbol': pos.symbol,
                    'type': 'BUY' if pos.type == self.mt5.ORDER_TYPE_BUY else 'SELL',
                    'volume': pos.volume,
                    'openPrice': round(float(pos.price_open), 5),
                    'currentPrice': round(float(pos.price_current), 5),
                    'pnl': round(pos.profit, 2),
                    'pnlPercentage': round(pnl_percentage, 2),
                    'openTime': pos.time if hasattr(pos, 'time') else None,
                    'swap': round(swap, 2),
                    'commission': round(commission, 2),
                    'netProfit': round(pos.profit + swap + commission, 2),
                    'comment': comment,
                    'sl': pos.sl if hasattr(pos, 'sl') else 0,
                    'tp': pos.tp if hasattr(pos, 'tp') else 0,
                    'broker': 'MT5',
                })
            return result
        except Exception as e:
            logger.error(f"Error getting MT5 positions: {e}")
            return []
    
    def get_trade_history(self, days: int = 30) -> List[Dict]:
        """Get CLOSED TRADES (trade history) from the last N days"""
        try:
            if not self.connected:
                return []
            
            # Get closed deals from the last N days
            from_time = datetime.utcnow() - timedelta(days=days)
            deals = self.mt5.history_deals_get(from_time, datetime.utcnow())
            
            result = []
            win_count = 0
            loss_count = 0
            total_profit = 0

            trade_type_map = {
                getattr(self.mt5, 'DEAL_TYPE_BUY', 0): 'BUY',
                getattr(self.mt5, 'DEAL_TYPE_SELL', 1): 'SELL',
                getattr(self.mt5, 'DEAL_TYPE_BALANCE', -1): 'WITHDRAWAL',
                getattr(self.mt5, 'DEAL_TYPE_CREDIT', -2): 'DEPOSIT',
                getattr(self.mt5, 'DEAL_TYPE_CHARGE', -3): 'FEE',
                getattr(self.mt5, 'DEAL_TYPE_COMMISSION', -4): 'COMMISSION',
            }
            
            if deals:
                for deal in deals:
                    # Only include closed positions
                    if deal.profit != 0 or deal.entry == 1:  # dealing IN or OUT
                        deal_type = int(getattr(deal, 'type', -999))
                        mapped_type = trade_type_map.get(deal_type, 'OTHER')
                        if mapped_type not in {'BUY', 'SELL'}:
                            continue

                        profit = round(float(deal.profit), 2)
                        total_profit += profit
                        if profit > 0:
                            win_count += 1
                        elif profit < 0:
                            loss_count += 1
                        
                        result.append({
                            'ticket': deal.ticket,
                            'symbol': deal.symbol,
                            'type': mapped_type,
                            'volume': deal.volume,
                            'openPrice': round(float(deal.price), 5),
                            'profit': profit,
                            'closeTime': deal.time,
                            'commission': round(float(deal.commission), 2),
                            'swap': round(float(deal.swap), 2),
                        })
            
            return sorted(result, key=lambda x: x['closeTime'], reverse=True)
        except Exception as e:
            logger.error(f"Error getting MT5 trade history: {e}")
            return []
    
    def get_performance_metrics(self) -> Dict:
        """Get trading PERFORMANCE METRICS for the account"""
        try:
            if not self.connected:
                return None
            
            # Get trades from last 90 days
            trades = self.get_trade_history(days=90)
            
            if not trades:
                return {
                    'totalTrades': 0,
                    'winRate': 0,
                    'lossRate': 0,
                    'avgWin': 0,
                    'avgLoss': 0,
                    'profitFactor': 0,
                    'totalProfit': 0,
                    'maxDrawdown': 0,
                }
            
            wins = [t['profit'] for t in trades if t['profit'] > 0]
            losses = [abs(t['profit']) for t in trades if t['profit'] < 0]
            
            total_wins = sum(wins) if wins else 0
            total_losses = sum(losses) if losses else 0
            win_count = len(wins)
            loss_count = len(losses)
            total_trades = win_count + loss_count
            
            return {
                'totalTrades': total_trades,
                'winCount': win_count,
                'lossCount': loss_count,
                'winRate': round((win_count / total_trades * 100), 2) if total_trades > 0 else 0,
                'lossRate': round((loss_count / total_trades * 100), 2) if total_trades > 0 else 0,
                'avgWin': round(total_wins / win_count, 2) if wins else 0,
                'avgLoss': round(total_losses / loss_count, 2) if losses else 0,
                'profitFactor': round(total_wins / total_losses, 2) if total_losses > 0 else float('inf'),
                'totalProfit': round(total_wins - total_losses, 2),
                'maxWin': round(max(wins), 2) if wins else 0,
                'maxLoss': round(min(losses), 2) if losses else 0,
                'period': '90 days',
            }
        except Exception as e:
            logger.error(f"Error calculating performance metrics: {e}")
            return None

    def is_symbol_available(self, symbol: str) -> bool:
        """Check if a symbol is available for trading on this account"""
        try:
            if not self.connected or not self.mt5:
                return False
            # Try to select the symbol and get tick data
            if not self.mt5.symbol_select(symbol, True):
                return False
            tick = self.mt5.symbol_info_tick(symbol)
            return tick is not None
        except:
            return False
    
    def get_fallback_symbol(self) -> str:
        """Get the first available symbol from VALID_SYMBOLS for fallback"""
        for symbol in get_mt5_ready_symbols_for_broker(self.mt5_broker):
            if self.is_symbol_available(symbol):
                return symbol
        return normalize_symbol_for_broker('EURUSD', self.mt5_broker) or "EURUSD"

    def get_related_fallback_symbol(self, requested_symbol: str) -> Optional[str]:
        """Find a safe fallback in the same asset family as the requested symbol."""
        requested_base = _normalize_symbol_base(requested_symbol)
        if not requested_base:
            return None

        ready_symbols = get_mt5_ready_symbols_for_broker(self.mt5_broker)
        for candidate in ready_symbols:
            if _normalize_symbol_base(candidate) == requested_base and self.is_symbol_available(candidate):
                return candidate

        return None
    
    def wait_for_critical_symbols(self, symbols: list, timeout_seconds: int = 30) -> bool:
        """
        Wait for critical symbols (like ETHUSD, BTCUSD) to be loaded and available.
        Critical symbols require special handling because:
        - They fail fast if not available (no fallback)
        - They trade 24/7 but need different subscription patterns
        - Trading wrong symbol instead causes silent loss
        
        Returns True if all critical symbols are available, False on timeout
        """
        critical_symbols = {
            normalize_symbol_for_broker('BTCUSD', self.mt5_broker),
            normalize_symbol_for_broker('ETHUSD', self.mt5_broker),
        }
        symbols_to_wait = [normalize_symbol_for_broker(s, self.mt5_broker) for s in symbols]
        symbols_to_wait = [s for s in symbols_to_wait if s in critical_symbols]
        
        if not symbols_to_wait:
            return True  # No critical symbols, no need to wait
        
        logger.info(f"⏳ Checking critical symbols: {symbols_to_wait} (timeout: {timeout_seconds}s)")
        
        start_time = time.time()
        check_interval = 2  # Check every 2 seconds for symbols
        attempt = 0
        
        while time.time() - start_time < timeout_seconds:
            attempt += 1
            elapsed = time.time() - start_time
            unavailable = []
            
            for symbol in symbols_to_wait:
                try:
                    if not self.mt5.symbol_select(symbol, True):
                        unavailable.append(symbol)
                        continue
                    
                    tick = self.mt5.symbol_info_tick(symbol)
                    if tick is None:
                        unavailable.append(symbol)
                        continue
                    
                    # Symbol is available
                    logger.debug(f"  ✅ {symbol}: available (bid={tick.bid}, ask={tick.ask})")
                except Exception as e:
                    logger.debug(f"  ⚠️ {symbol}: check failed - {e}")
                    unavailable.append(symbol)
            
            if not unavailable:
                logger.info(f"✅ All critical symbols ready after {elapsed:.0f}s: {symbols_to_wait}")
                return True
            else:
                logger.debug(f"  Attempt {attempt} [{elapsed:.0f}s]: Waiting for symbols: {unavailable}")
                time.sleep(check_interval)
        
        # Timeout reached
        logger.error(f"❌ Critical symbols NOT ready after {timeout_seconds}s: {unavailable}")
        logger.error(f"   {unavailable} may take longer to load. Trading may fail if symbols don't become available.")
        return False

    def _get_filling_type(self, symbol: str):
        """Auto-detect the correct ORDER_FILLING type for the broker/symbol.
        Exness requires RETURN, other brokers may need IOC or FOK."""
        try:
            sym_info = self.mt5.symbol_info(symbol)
            if sym_info is not None:
                filling = sym_info.filling_mode
                # filling_mode is a bitmask: bit0=FOK, bit1=IOC, bit2=RETURN
                if filling & 2:  # IOC supported
                    return self.mt5.ORDER_FILLING_IOC
                elif filling & 1:  # FOK supported
                    return self.mt5.ORDER_FILLING_FOK
            # Default to RETURN (works on Exness and most brokers)
            return self.mt5.ORDER_FILLING_RETURN
        except Exception:
            return self.mt5.ORDER_FILLING_RETURN

    def place_order(self, symbol: str, order_type: str, volume: float, **kwargs) -> Dict:
        """
        Place order on MT5 with enhanced validation and fallback logic
        """
        try:
            if not self.connected:
                return {'success': False, 'error': 'Not connected'}

            # STEP 1: Validate requested symbol before attempting order
            original_symbol = symbol
            critical_symbols = {
                normalize_symbol_for_broker('BTCUSD', self.mt5_broker),
                normalize_symbol_for_broker('ETHUSD', self.mt5_broker),
            }
            if not self.is_symbol_available(symbol):
                logger.warning(f"⚠️  Symbol {symbol} is NOT available - checking if it's in VALID_SYMBOLS")
                if symbol in VALID_SYMBOLS:
                    logger.warning(f"   Symbol {symbol} IS in VALID_SYMBOLS but NOT available on this account")
                    logger.warning(f"   This may be due to: insufficient permissions, broker restrictions, or initialization delay")
                    
                    # ❌ CRITICAL FIX: Don't silently fall back for important symbols like BTC/ETH
                    # This was causing BTC trades to execute as EUR/USD instead
                    if symbol in critical_symbols:
                        logger.error(f"❌ CRITICAL: {symbol} requested but NOT available - refusing to fall back to another symbol")
                        logger.error(f"   User requested {symbol}, but system would execute on wrong symbol if we fell back")
                        logger.error(f"   This indicates MT5 initialization incomplete. Waiting for symbol to load...")
                        return {'success': False, 'error': f'{symbol} not yet available on MT5. Please ensure Exness MT5 terminal is connected and symbols are loaded. Retry in a few seconds.', 'retry_after_seconds': 5}
                else:
                    logger.warning(f"   Symbol {symbol} is NOT in VALID_SYMBOLS (list: {sorted(VALID_SYMBOLS)})")
                
                broker_normalized_symbol = normalize_symbol_for_broker(original_symbol, self.mt5_broker)
                if broker_normalized_symbol != original_symbol and self.is_symbol_available(broker_normalized_symbol):
                    logger.info(f"🔄 Normalized symbol for broker: {original_symbol} -> {broker_normalized_symbol}")
                    symbol = broker_normalized_symbol
                elif original_symbol not in critical_symbols:
                    related_fallback = self.get_related_fallback_symbol(original_symbol)
                    if related_fallback:
                        logger.info(f"🔄 Falling back from {original_symbol} to related symbol {related_fallback}")
                        symbol = related_fallback
                    else:
                        return {'success': False, 'error': f'Symbol {original_symbol} not available on this account and no safe related fallback exists'}

            # STEP 2: Select symbol so broker metadata and ticks are available.
            if not self.mt5.symbol_select(symbol, True):
                return {'success': False, 'error': f'Failed to select symbol {symbol}'}

            # STEP 3: Normalize requested volume to broker constraints.
            sym_info = self.mt5.symbol_info(symbol)
            fallback_min_volumes = {
                'OILK': 1.0,
                'XAUUSD': 0.01,
                'XAGUSD': 0.1,
                'XAUUSD': 0.01,
                'XAGUSD': 0.1,
            }
            min_volume = float(getattr(sym_info, 'volume_min', 0.0) or fallback_min_volumes.get(symbol, 0.01))
            max_volume = float(getattr(sym_info, 'volume_max', 0.0) or 0.0)
            volume_step = float(getattr(sym_info, 'volume_step', 0.0) or 0.01)
            requested_volume = float(volume)
            normalized_volume = requested_volume

            if normalized_volume < min_volume:
                normalized_volume = min_volume

            if volume_step > 0:
                import math
                step_precision = max(0, len(f"{volume_step:.10f}".rstrip('0').split('.')[-1]))
                step_count = math.ceil(((normalized_volume - min_volume) / volume_step) - 1e-9)
                step_count = max(0, step_count)
                normalized_volume = round(min_volume + (step_count * volume_step), step_precision)
            else:
                step_precision = 2

            if max_volume > 0 and normalized_volume > max_volume:
                return {
                    'success': False,
                    'error': f'Volume {normalized_volume} exceeds broker maximum {max_volume} for {symbol}'
                }

            if normalized_volume != requested_volume:
                logger.info(
                    f"Adjusting volume for {symbol}: requested={requested_volume}, "
                    f"normalized={normalized_volume}, min={min_volume}, step={volume_step}"
                )

            volume = normalized_volume

            # Get the tick data (bid/ask prices)
            tick = self.mt5.symbol_info_tick(symbol)
            if tick is None:
                return {'success': False, 'error': f'Cannot get tick data for {symbol}'}
            
            price = tick.ask if order_type == 'BUY' else tick.bid

            # Auto-detect correct filling type for broker
            filling_type = self._get_filling_type(symbol)

            request_dict = {
                "action": self.mt5.TRADE_ACTION_DEAL,
                "symbol": symbol,
                "volume": volume,
                "type": self.mt5.ORDER_TYPE_BUY if order_type == 'BUY' else self.mt5.ORDER_TYPE_SELL,
                "price": price,
                "comment": (kwargs.get('comment', 'ZTrade')[:31] if kwargs.get('comment') else 'ZTrade'),  # Enforce 31-char limit
                "type_time": self.mt5.ORDER_TIME_GTC,
                "type_filling": filling_type,
            }

            def _coerce_order_level(raw_value, field_name):
                import math

                if raw_value in (None, '', 0, 0.0):
                    return None

                try:
                    level = float(raw_value)
                except (TypeError, ValueError):
                    logger.warning(f"Ignoring invalid {field_name} for {symbol}: {raw_value}")
                    return None

                if not math.isfinite(level) or level <= 0:
                    logger.warning(f"Ignoring non-finite {field_name} for {symbol}: {raw_value}")
                    return None

                if order_type == 'BUY':
                    if field_name == 'sl' and level >= price:
                        logger.warning(f"Ignoring BUY stop loss above market for {symbol}: sl={level}, price={price}")
                        return None
                    if field_name == 'tp' and level <= price:
                        logger.warning(f"Ignoring BUY take profit below market for {symbol}: tp={level}, price={price}")
                        return None
                else:
                    if field_name == 'sl' and level <= price:
                        logger.warning(f"Ignoring SELL stop loss below market for {symbol}: sl={level}, price={price}")
                        return None
                    if field_name == 'tp' and level >= price:
                        logger.warning(f"Ignoring SELL take profit above market for {symbol}: tp={level}, price={price}")
                        return None

                return level

            stop_loss = _coerce_order_level(kwargs.get('stopLoss'), 'sl')
            take_profit = _coerce_order_level(kwargs.get('takeProfit'), 'tp')

            if stop_loss is not None:
                request_dict['sl'] = stop_loss
            if take_profit is not None:
                request_dict['tp'] = take_profit

            def _extract_retcode_and_comment(check_result):
                if check_result is None:
                    return None, ''
                return getattr(check_result, 'retcode', None), str(getattr(check_result, 'comment', '') or '')

            def _is_no_money_result(check_result):
                retcode, comment = _extract_retcode_and_comment(check_result)
                comment_lower = comment.lower()
                return retcode == self.RETCODE_NO_MONEY or 'no money' in comment_lower or 'insufficient' in comment_lower

            def _estimate_required_margin(volume_to_test):
                try:
                    margin = self.mt5.order_calc_margin(
                        request_dict['type'],
                        symbol,
                        float(volume_to_test),
                        price,
                    )
                    if margin is None:
                        return None
                    return float(margin)
                except Exception:
                    return None

            def _request_for_volume(volume_to_test):
                cloned = dict(request_dict)
                cloned['volume'] = round(float(volume_to_test), step_precision)
                return cloned

            def _find_affordable_volume(initial_volume):
                account_info = self.mt5.account_info()
                free_margin = 0.0
                if account_info is not None:
                    free_margin = float(
                        getattr(account_info, 'margin_free', 0.0)
                        or getattr(account_info, 'balance', 0.0)
                        or 0.0
                    )

                candidate = round(float(initial_volume), step_precision)
                minimum = round(float(min_volume), step_precision)
                epsilon = 10 ** (-(step_precision + 2)) if step_precision >= 0 else 1e-6
                last_margin = _estimate_required_margin(candidate)

                while candidate + epsilon >= minimum:
                    probe = self.mt5.order_check(_request_for_volume(candidate))
                    if probe is not None and not _is_no_money_result(probe):
                        return candidate, probe, free_margin, last_margin

                    last_margin = _estimate_required_margin(candidate) or last_margin

                    if candidate <= minimum + epsilon:
                        break

                    if volume_step > 0:
                        next_candidate = round(candidate - volume_step, step_precision)
                    else:
                        next_candidate = round(candidate * 0.5, step_precision)

                    if next_candidate < minimum:
                        next_candidate = minimum
                    if next_candidate >= candidate:
                        break

                    candidate = next_candidate

                return None, None, free_margin, last_margin

            affordable_volume, preflight_result, free_margin, required_margin = _find_affordable_volume(volume)
            if affordable_volume is None:
                min_required_margin = _estimate_required_margin(min_volume) or required_margin
                min_required_margin = round(min_required_margin, 2) if min_required_margin is not None else None
                return {
                    'success': False,
                    'error': f'Insufficient margin or balance to place even the minimum order on {symbol}',
                    'retcode': self.RETCODE_NO_MONEY,
                    'original_comment': 'No money',
                    'is_paused': False,
                    'requested_volume': requested_volume,
                    'normalized_volume': volume,
                    'min_volume': min_volume,
                    'free_margin': round(free_margin, 2),
                    'required_margin': min_required_margin,
                    'action_required': 'Reduce lot size, choose a lower-margin symbol, close other positions, or fund the account before retrying.'
                }

            if affordable_volume != volume:
                logger.warning(
                    f"💸 Auto-scaled {symbol} order volume for low-margin account: "
                    f"requested={volume}, affordable={affordable_volume}, free_margin={free_margin:.2f}, "
                    f"required_margin={required_margin if required_margin is not None else 'unknown'}"
                )
                volume = affordable_volume
                request_dict['volume'] = volume

            # TIMEOUT WRAPPER: order_send can hang for 10+ seconds if MT5 is busy/disconnected
            # Set a 5-second timeout to fail fast instead of freezing bot
            import threading
            result = None
            result_holder = []
            error_holder = []
            
            def mt5_order_with_timeout():
                try:
                    res = self.mt5.order_send(request_dict)
                    result_holder.append(res)
                except Exception as e:
                    error_holder.append(e)
            
            thread = threading.Thread(target=mt5_order_with_timeout, daemon=True)
            thread.start()
            thread.join(timeout=5.0)  # Wait max 5 seconds
            
            if error_holder:
                logger.error(f"MT5 order_send exception: {error_holder[0]}")
                result = None
            elif result_holder:
                result = result_holder[0]
            else:
                logger.error(f"MT5 order_send TIMEOUT after 5 seconds - terminal likely disconnected")
                result = None

            if result is None:
                logger.error(f"MT5 order_send returned None for {symbol} {order_type} vol={volume}")
                logger.error(f"  Request was: {request_dict}")
                logger.error(f"  This usually indicates the terminal is not ready or has lost connection")
                
                # TRY RECOVERY: Attempt to get MT5 last error for diagnostic info
                try:
                    last_error = self.mt5.last_error()
                    logger.error(f"  MT5 last_error: {last_error}")
                except:
                    pass
                
                # Return specific error so caller can distinguish between "symbol not found" vs "terminal issue"
                return {'success': False, 'error': 'MT5 order_send failed - terminal may have disconnected'}
            
            if result.retcode != self.mt5.TRADE_RETCODE_DONE:
                logger.warning(f"MT5 order failed: symbol={symbol}, type={order_type}, retcode={result.retcode}, comment={result.comment}")

                if result.retcode == self.RETCODE_NO_MONEY:
                    return {
                        'success': False,
                        'error': 'Insufficient margin or balance to place this order',
                        'retcode': result.retcode,
                        'original_comment': result.comment,
                        'is_paused': False,
                        'action_required': 'Reduce lot size, close other positions, or fund the account before retrying.'
                    }
                
                # CHECK FOR MARKET PAUSE/HALT CONDITIONS
                if result.retcode in self.PAUSE_RETCODES:
                    pause_type, pause_reason = self.PAUSE_RETCODES[result.retcode]
                    logger.warning(f"🔒 MARKET PAUSE DETECTED: {pause_type} - {pause_reason}")
                    return {
                        'success': False,
                        'error': f'Market paused: {pause_reason}',
                        'retcode': result.retcode,
                        'pause_type': pause_type,
                        'pause_reason': pause_reason,
                        'is_paused': True,
                        'original_comment': result.comment,
                        'action_required': f'Market is currently paused ({pause_type}). Trading will resume when market reopens.'
                    }
                
                # Retcode 10027 = AutoTrading disabled in MT5 terminal
                if result.retcode == 10027:
                    return {
                        'success': False,
                        'error': 'AutoTrading is disabled in MT5 terminal. Enable it by clicking the AutoTrading button in the MT5 toolbar, or run: mt5.terminal_info().trade_allowed',
                        'retcode': 10027,
                        'action_required': 'Enable AutoTrading in MT5 terminal'
                    }
                return {'success': False, 'error': f'MT5 error: {result.comment}', 'retcode': result.retcode}

            # Trade insert is handled by the calling bot trading loop (which has the correct bot_id/user_id)
            # Do not insert here to avoid duplicate records with bot_id='unknown'

            return {
                'success': True,
                'orderId': result.order,
                'symbol': symbol,
                'type': order_type,
                'price': price,
                'broker': 'MT5',
            }
        except Exception as e:
            logger.error(f"Error placing MT5 order: {e}")
            return {'success': False, 'error': str(e)}

    def close_position(self, position_id: str) -> Dict:
        """Close position"""
        try:
            if not self.connected:
                return {'success': False, 'error': 'Not connected'}

            position = self.mt5.positions_get(ticket=int(position_id))
            if not position:
                return {'success': False, 'error': 'Position not found'}

            pos = position[0]
            
            # Auto-detect correct filling type for broker
            filling_type = self._get_filling_type(pos.symbol)

            request_dict = {
                "action": self.mt5.TRADE_ACTION_DEAL,
                "symbol": pos.symbol,
                "volume": pos.volume,
                "type": self.mt5.ORDER_TYPE_SELL if pos.type == self.mt5.ORDER_TYPE_BUY else self.mt5.ORDER_TYPE_BUY,
                "position": int(position_id),
                "comment": "ZCLOSE",  # Short comment for close (31-char MT5 limit)
                "type_time": self.mt5.ORDER_TIME_GTC,
                "type_filling": filling_type,
            }

            result = self.mt5.order_send(request_dict)
            
            if result is None:
                logger.error(f"MT5 order_send returned None when closing position {position_id} - terminal disconnected")
                return {'success': False, 'error': 'MT5 order_send failed - terminal may have disconnected'}
            
            if result.retcode != self.mt5.TRADE_RETCODE_DONE:
                logger.warning(f"MT5 close failed: position={position_id}, retcode={result.retcode}, comment={result.comment}")
                return {'success': False, 'error': f'MT5 error: {result.comment}'}

            return {'success': True, 'broker': 'MT5'}
        except Exception as e:
            logger.error(f"Error closing MT5 position: {e}")
            return {'success': False, 'error': str(e)}

    def get_trades(self) -> List[Dict]:
        """Get trade history"""
        try:
            if not self.connected:
                return []

            deals = self.mt5.history_deals_get(position=0)
            result = []
            trade_type_map = {
                getattr(self.mt5, 'DEAL_TYPE_BUY', 0): ('BUY', 'trade'),
                getattr(self.mt5, 'DEAL_TYPE_SELL', 1): ('SELL', 'trade'),
                getattr(self.mt5, 'DEAL_TYPE_BALANCE', -1): ('WITHDRAWAL', 'cashflow'),
                getattr(self.mt5, 'DEAL_TYPE_CREDIT', -2): ('DEPOSIT', 'cashflow'),
                getattr(self.mt5, 'DEAL_TYPE_CHARGE', -3): ('FEE', 'cashflow'),
                getattr(self.mt5, 'DEAL_TYPE_COMMISSION', -4): ('COMMISSION', 'cashflow'),
            }
            for deal in deals[-50:]:
                deal_type = int(getattr(deal, 'type', -999))
                mapped = trade_type_map.get(deal_type, ('OTHER', 'cashflow'))
                direction = mapped[0]
                result.append({
                    'ticket': deal.ticket,
                    'deal_id': deal.ticket,
                    'position_id': getattr(deal, 'position_id', None),
                    'symbol': deal.symbol,
                    'type': direction,
                    'entryCategory': mapped[1],
                    'volume': deal.volume,
                    'price': deal.price,
                    'profit': deal.profit,
                    'time': datetime.fromtimestamp(deal.time).isoformat(),
                    'broker': 'MT5',
                })
            return result
        except Exception as e:
            logger.error(f"Error getting MT5 trades: {e}")
            return []


# Removed: IGConnection class (IG Markets integration removed)


class BinanceConnection(BrokerConnection):
    """Binance broker connection via REST API."""

    def __init__(self, credentials: Dict = None):
        # MULTI-USER SAFETY: never silently fall back to env vars. Each caller must
        # pass the user's broker_credentials row explicitly so per-user isolation is
        # guaranteed across all 5000+ users. Failing loudly prevents the "old env keys
        # leak through" bug class.
        if not credentials or not credentials.get('api_key') or not credentials.get('api_secret'):
            raise ValueError(
                'BinanceConnection requires explicit per-user credentials '
                '(api_key + api_secret). Load the broker_credentials row for the '
                'authenticated user_id and pass it in. Env-var fallback is disabled.'
            )

        super().__init__(BrokerType.BINANCE, credentials)
        self.market = (credentials.get('market') or credentials.get('server') or 'spot').lower()
        is_live = bool(credentials.get('is_live', False))
        # Demo mode supports two distinct sandboxes: Binance Demo Trading (demo-api.binance.com,
        # used by the "DEMO TRADING" toggle on binance.com) and the public spot/futures testnet
        # (testnet.binance.vision). Demo Trading matches what users see in the Binance UI when
        # they switch to demo mode, so it is the primary; testnet is kept as a fallback.
        self.base_url = 'https://api.binance.com/api' if is_live else 'https://demo-api.binance.com/api'
        self.fapi_url = 'https://fapi.binance.com/fapi' if is_live else 'https://demo-fapi.binance.com/fapi'
        self._demo_base_url_fallbacks = [] if is_live else [
            'https://demo-api.binance.com/api',
            'https://testnet.binance.vision/api',
        ]
        self._demo_fapi_url_fallbacks = [] if is_live else [
            'https://demo-fapi.binance.com/fapi',
            'https://testnet.binancefuture.com/fapi',
        ]
        self.effective_is_live = is_live
        self.last_error = None
        self.last_error_code = None
        self._auth_attempt_summaries = []
        self._time_offset_ms = 0
        self._time_offset_updated_at = 0.0
        self._spot_balances = {}

    def _set_last_error(self, message: str, code=None) -> None:
        self.last_error = message
        self.last_error_code = code

    def _clear_last_error(self) -> None:
        self.last_error = None
        self.last_error_code = None
        self._auth_attempt_summaries = []

    def _record_auth_attempt(self, label: str, url: str, response=None, exc: Optional[Exception] = None) -> None:
        target = str(url or '').replace('https://', '').replace('http://', '')
        if exc is not None:
            summary = f'{label} {target} -> EXCEPTION {exc}'
        else:
            status_code = getattr(response, 'status_code', None)
            code = None
            try:
                payload = response.json()
            except Exception:
                payload = None
            if isinstance(payload, dict):
                code = payload.get('code')
            code_suffix = f' code {code}' if code is not None else ''
            summary = f'{label} {target} -> HTTP {status_code}{code_suffix}'
        self._auth_attempt_summaries.append(summary)

    def _describe_auth_attempts(self) -> str:
        if not self._auth_attempt_summaries:
            return ''
        return '; '.join(self._auth_attempt_summaries)

    def _format_auth_error(self, response) -> Tuple[str, Optional[Any]]:
        status_code = getattr(response, 'status_code', None)
        try:
            payload = response.json()
        except Exception:
            payload = None

        if isinstance(payload, dict):
            code = payload.get('code')
            message = str(payload.get('msg') or '').strip() or f'Binance authentication failed with HTTP {status_code}'
            if code in {-2014, -2015}:
                message = f"{message}. Verify the API key/secret, Binance environment, IP whitelist, and API permissions."
            attempts = self._describe_auth_attempts()
            if attempts:
                message = f'{message} Attempted endpoints: {attempts}'
            return message, code

        raw_text = str(getattr(response, 'text', '') or '').strip()
        if raw_text:
            message = f'Binance authentication failed with HTTP {status_code}: {raw_text}'
        else:
            message = f'Binance authentication failed with HTTP {status_code}'
        attempts = self._describe_auth_attempts()
        if attempts:
            message = f'{message} Attempted endpoints: {attempts}'
        return message, None

    def _get_spot_asset_free_balance(self, asset: str) -> float:
        asset_key = str(asset or '').strip().upper()
        if not asset_key:
            return 0.0

        balance_entry = self._spot_balances.get(asset_key)
        if not balance_entry:
            self.get_account_info()
            balance_entry = self._spot_balances.get(asset_key)

        try:
            return float((balance_entry or {}).get('free', 0.0) or 0.0)
        except (TypeError, ValueError):
            return 0.0

    def _get_spot_asset_total_balance(self, asset: str) -> float:
        asset_key = str(asset or '').strip().upper()
        if not asset_key:
            return 0.0

        balance_entry = self._spot_balances.get(asset_key)
        if not balance_entry:
            self.get_account_info()
            balance_entry = self._spot_balances.get(asset_key)

        try:
            free_balance = float((balance_entry or {}).get('free', 0.0) or 0.0)
            locked_balance = float((balance_entry or {}).get('locked', 0.0) or 0.0)
            return free_balance + locked_balance
        except (TypeError, ValueError):
            return 0.0

    def _get_spot_symbol_price(self, instrument: str) -> float:
        normalized_instrument = self._normalize_symbol(instrument)
        if not normalized_instrument:
            return 0.0

        try:
            import requests

            response = requests.get(
                f"{self.base_url}/v3/ticker/price",
                params={'symbol': normalized_instrument},
                timeout=5,
            )
            if response.status_code != 200:
                return 0.0
            payload = response.json() if response.content else {}
            return float(payload.get('price', 0.0) or 0.0)
        except Exception as exc:
            logger.debug(f"Binance spot ticker lookup failed for {normalized_instrument}: {exc}")
            return 0.0

    def _get_spot_symbol_filters(self, instrument: str) -> Dict[str, Any]:
        normalized_instrument = self._normalize_symbol(instrument)
        if not normalized_instrument:
            return {}

        try:
            import requests

            response = requests.get(
                f"{self.base_url}/v3/exchangeInfo",
                params={'symbol': normalized_instrument},
                timeout=10,
            )
            if response.status_code != 200:
                return {}

            payload = response.json() if response.content else {}
            symbol_entries = payload.get('symbols') or []
            if not symbol_entries:
                return {}

            filters: Dict[str, Any] = {}
            for entry in symbol_entries[0].get('filters') or []:
                filter_type = str(entry.get('filterType') or '').upper()
                if filter_type:
                    filters[filter_type] = entry
            return filters
        except Exception as exc:
            logger.debug(f"Binance exchangeInfo lookup failed for {normalized_instrument}: {exc}")
            return {}

    def _normalize_spot_quantity(
        self,
        quantity: float,
        step_size: float,
        min_qty: float,
        *,
        round_up: bool = False,
    ) -> float:
        from decimal import Decimal, ROUND_CEILING, ROUND_FLOOR

        normalized_quantity = max(float(quantity or 0.0), 0.0)
        if step_size > 0:
            quantity_decimal = Decimal(str(normalized_quantity))
            step_decimal = Decimal(str(step_size))
            rounding_mode = ROUND_CEILING if round_up else ROUND_FLOOR
            normalized_quantity = float((quantity_decimal / step_decimal).to_integral_value(rounding=rounding_mode) * step_decimal)
        if min_qty > 0 and normalized_quantity < min_qty:
            normalized_quantity = min_qty
        return max(normalized_quantity, 0.0)

    def _headers(self) -> Dict:
        return {
            'X-MBX-APIKEY': self.credentials.get('api_key', ''),
            'Content-Type': 'application/json',
        }

    def _sign_params(self, params: Dict) -> Dict:
        import hmac
        from urllib.parse import urlencode

        signed_params = dict(params)
        signed_params.setdefault('recvWindow', 60000)
        signed_params['timestamp'] = int(time.time() * 1000) + int(self._time_offset_ms)
        query_string = urlencode(signed_params)
        signature = hmac.new(
            str(self.credentials.get('api_secret', '')).encode('utf-8'),
            query_string.encode('utf-8'),
            hashlib.sha256,
        ).hexdigest()
        signed_params['signature'] = signature
        return signed_params

    def _sync_server_time(self, force: bool = False) -> None:
        try:
            import requests

            now = time.monotonic()
            if not force and self._time_offset_updated_at and (now - self._time_offset_updated_at) < 60:
                return

            endpoint = f"{self.base_url}/v3/time"
            resp = requests.get(endpoint, timeout=10)
            if resp.status_code != 200:
                return

            payload = resp.json() if resp.content else {}
            server_time = int(payload.get('serverTime', 0) or 0)
            if server_time <= 0:
                return

            self._time_offset_ms = server_time - int(time.time() * 1000)
            self._time_offset_updated_at = now
        except Exception as e:
            logger.debug(f"Binance server time sync failed: {e}")

    def _request_with_time_retry(self, method: str, url: str, *, headers: Dict, params: Dict, timeout: int):
        import requests

        self._sync_server_time()
        response = requests.request(method, url, headers=headers, params=self._sign_params(params), timeout=timeout)
        if response.status_code != 400:
            return response

        try:
            payload = response.json()
        except Exception:
            return response

        if payload.get('code') != -1021:
            return response

        self._sync_server_time(force=True)
        return requests.request(method, url, headers=headers, params=self._sign_params(params), timeout=timeout)

    def _is_invalid_demo_auth_response(self, response) -> bool:
        if response is None:
            return False
        if response.status_code not in {400, 401}:
            return False
        try:
            payload = response.json()
        except Exception:
            return False
        return payload.get('code') in {-2014, -2015}

    def _try_demo_spot_endpoint_fallback(self, candidates: Optional[List[str]] = None) -> bool:
        fallback_candidates = candidates if candidates is not None else self._demo_base_url_fallbacks
        if not fallback_candidates:
            return False

        current_url = self.base_url
        for candidate in fallback_candidates:
            if candidate == current_url:
                continue

            previous_url = self.base_url
            previous_offset = self._time_offset_ms
            previous_updated_at = self._time_offset_updated_at
            self.base_url = candidate
            self._time_offset_ms = 0
            self._time_offset_updated_at = 0.0

            try:
                resp = self._request_with_time_retry(
                    'GET',
                    f"{self.base_url}/v3/account",
                    headers=self._headers(),
                    params={},
                    timeout=15,
                )
                self._record_auth_attempt('demo-fallback', f"{self.base_url}/v3/account", response=resp)
                if resp.status_code == 200:
                    logger.info(f"Binance demo endpoint fallback succeeded on {candidate}")
                    return True
                if not self._is_invalid_demo_auth_response(resp):
                    self.base_url = previous_url
                    self._time_offset_ms = previous_offset
                    self._time_offset_updated_at = previous_updated_at
                    return False
            except Exception as exc:
                self._record_auth_attempt('demo-fallback', f"{self.base_url}/v3/account", exc=exc)

            self.base_url = previous_url
            self._time_offset_ms = previous_offset
            self._time_offset_updated_at = previous_updated_at

        return False

    def _try_live_spot_endpoint_fallback(self, candidates: Optional[List[str]] = None) -> bool:
        fallback_candidates = candidates if candidates is not None else ['https://api.binance.com/api']
        if not fallback_candidates:
            return False

        current_url = self.base_url
        for candidate in fallback_candidates:
            if candidate == current_url:
                continue

            previous_url = self.base_url
            previous_offset = self._time_offset_ms
            previous_updated_at = self._time_offset_updated_at
            self.base_url = candidate
            self._time_offset_ms = 0
            self._time_offset_updated_at = 0.0

            try:
                resp = self._request_with_time_retry(
                    'GET',
                    f"{self.base_url}/v3/account",
                    headers=self._headers(),
                    params={},
                    timeout=15,
                )
                self._record_auth_attempt('live-fallback', f"{self.base_url}/v3/account", response=resp)
                if resp.status_code == 200:
                    logger.info(f"Binance live endpoint fallback succeeded on {candidate}")
                    return True
                if not self._is_invalid_demo_auth_response(resp):
                    self.base_url = previous_url
                    self._time_offset_ms = previous_offset
                    self._time_offset_updated_at = previous_updated_at
                    return False
            except Exception as exc:
                self._record_auth_attempt('live-fallback', f"{self.base_url}/v3/account", exc=exc)

            self.base_url = previous_url
            self._time_offset_ms = previous_offset
            self._time_offset_updated_at = previous_updated_at

        return False

    def _normalize_symbol(self, symbol: str) -> Optional[str]:
        if not symbol:
            return None

        symbol = symbol.upper().replace('/', '').replace('_', '')
        symbol_map = {
            'BTCUSD': 'BTCUSDT',
            'ETHUSD': 'ETHUSDT',
            'BNBUSD': 'BNBUSDT',
            'SOLUSD': 'SOLUSDT',
            'XRPUSD': 'XRPUSDT',
            'ADAUSD': 'ADAUSDT',
            'DOGEUSD': 'DOGEUSDT',
        }
        if symbol in symbol_map:
            return symbol_map[symbol]
        if _is_binance_supported_symbol(symbol):
            return symbol
        return None

    def connect(self) -> bool:
        try:
            self._clear_last_error()
            if not self.credentials.get('api_key') or not self.credentials.get('api_secret'):
                self._set_last_error('Binance: Missing API key or API secret', 'MISSING_CREDENTIALS')
                logger.error('Binance: Missing API key or API secret')
                return False

            configured_is_live = bool(self.credentials.get('is_live', False))
            logger.info(
                "[BINANCE AUTH] account=%s market=%s configured_mode=%s effective_mode=%s endpoint=%s/v3/account",
                str(self.credentials.get('account_number') or '').strip() or 'BINANCE',
                self.market,
                'live' if configured_is_live else 'demo',
                'live' if self.effective_is_live else 'demo',
                self.base_url,
            )

            resp = self._request_with_time_retry(
                'GET',
                f"{self.base_url}/v3/account",
                headers=self._headers(),
                params={},
                timeout=30,
            )
            self._record_auth_attempt('primary', f"{self.base_url}/v3/account", response=resp)
            if resp.status_code == 200:
                self.connected = True
                self.get_account_info()
                return True

            if not configured_is_live and self._try_demo_spot_endpoint_fallback():
                self.effective_is_live = False
                self.connected = True
                self._clear_last_error()
                logger.info("[BINANCE AUTH] fallback promoted effective_mode=demo endpoint=%s/v3/account", self.base_url)
                self.get_account_info()
                return True

            if not bool(self.credentials.get('is_live', False)) and self.market != 'futures' and self._is_invalid_demo_auth_response(resp):
                if self._try_live_spot_endpoint_fallback():
                    logger.warning('Binance demo auth failed, but live spot auth succeeded; treating this credential as live.')
                    self.credentials['is_live'] = True
                    self.effective_is_live = True
                    self.connected = True
                    self._clear_last_error()
                    logger.info("[BINANCE AUTH] compatibility fallback promoted effective_mode=live endpoint=%s/v3/account", self.base_url)
                    self.get_account_info()
                    return True

            if bool(self.credentials.get('is_live', False)) and self.market != 'futures' and self._is_invalid_demo_auth_response(resp):
                compatibility_candidates = [
                    'https://demo-api.binance.com/api',
                    'https://testnet.binance.vision/api',
                ]
                if self._try_demo_spot_endpoint_fallback(compatibility_candidates):
                    logger.error('Binance live auth failed, but demo/testnet spot auth succeeded. Refusing to downgrade a live-marked credential to demo.')
                    self.connected = False
                    self.base_url = 'https://api.binance.com/api'
                    self.fapi_url = 'https://fapi.binance.com/fapi'
                    self.effective_is_live = True
                    self._set_last_error(
                        'Binance credential mode mismatch: this credential authenticates on demo/testnet but is marked LIVE. Use a true live Binance key or relabel the credential as demo.',
                        'BINANCE_MODE_MISMATCH',
                    )
                    return False

            error_message, error_code = self._format_auth_error(resp)
            self._set_last_error(error_message, error_code)
            logger.error(f"Binance authentication failed: {resp.status_code} - {resp.text} | attempts={self._describe_auth_attempts()}")
            return False
        except Exception as e:
            self._set_last_error(f'Error connecting to Binance: {e}', 'EXCEPTION')
            logger.error(f"Error connecting to Binance: {e}")
            return False

    def disconnect(self) -> bool:
        self.connected = False
        return True

    def get_account_info(self) -> Dict:
        try:
            if not self.connected:
                return {}

            resp = self._request_with_time_retry(
                'GET',
                f"{self.base_url}/v3/account",
                headers=self._headers(),
                params={},
                timeout=30,
            )
            if resp.status_code == 200:
                acct = resp.json()
                balances = acct.get('balances', [])
                self._spot_balances = {
                    str(balance.get('asset', '')).upper(): {
                        'free': float(balance.get('free', 0) or 0),
                        'locked': float(balance.get('locked', 0) or 0),
                    }
                    for balance in balances
                    if str(balance.get('asset', '')).strip()
                }
                usdt = next((b for b in balances if b.get('asset') == 'USDT'), {'free': '0', 'locked': '0'})
                balance = float(usdt.get('free', 0)) + float(usdt.get('locked', 0))
                self.account_info = {
                    'account_id': self.credentials.get('account_id') or self.credentials.get('account_number') or 'BINANCE',
                    'balance': balance,
                    'equity': balance,
                    'margin_free': float(usdt.get('free', 0)),
                    'currency': 'USDT',
                    'broker': 'Binance',
                }
                return self.account_info
        except Exception as e:
            logger.error(f"Error getting Binance account info: {e}")

        return {}

    def get_positions(self) -> List[Dict]:
        try:
            if not self.connected:
                return []

            if self.market == 'futures':
                resp = self._request_with_time_retry(
                    'GET',
                    f"{self.fapi_url}/v2/positionRisk",
                    headers=self._headers(),
                    params={},
                    timeout=10,
                )
                if resp.status_code == 200:
                    result = []
                    for pos in resp.json():
                        amount = float(pos.get('positionAmt', 0))
                        if amount == 0:
                            continue
                        result.append({
                            'deal_id': pos.get('symbol', ''),
                            'symbol': pos.get('symbol', ''),
                            'type': 'BUY' if amount > 0 else 'SELL',
                            'size': abs(amount),
                            'level': float(pos.get('entryPrice', 0)),
                            'profit_loss': float(pos.get('unRealizedProfit', 0)),
                            'broker': 'Binance',
                        })
                    return result
            else:
                self.get_account_info()
                result = []
                for asset, balance_entry in list(self._spot_balances.items()):
                    if asset in {'USDT', 'BUSD', 'USDC', 'FDUSD'}:
                        continue

                    total_quantity = self._get_spot_asset_total_balance(asset)
                    if total_quantity <= 0:
                        continue

                    instrument = self._normalize_symbol(f'{asset}USDT')
                    if not instrument:
                        continue

                    current_price = self._get_spot_symbol_price(instrument)
                    result.append({
                        'ticket': f'SPOT-{asset}',
                        'deal_id': f'SPOT-{asset}',
                        'symbol': instrument,
                        'type': 'BUY',
                        'size': total_quantity,
                        'volume': total_quantity,
                        'level': current_price,
                        'openPrice': current_price,
                        'currentPrice': current_price,
                        'profit_loss': 0,
                        'profit': 0,
                        'openTime': datetime.now().isoformat(),
                        'broker': 'Binance',
                    })
                return result
        except Exception as e:
            logger.error(f"Error getting Binance positions: {e}")

        return []

    def place_order(self, symbol: str, order_type: str, volume: float, **kwargs) -> Dict:
        try:
            if not self.connected:
                return {'success': False, 'error': 'Not connected to Binance'}

            instrument = self._normalize_symbol(symbol)
            if not instrument:
                return {'success': False, 'error': f'Unsupported Binance symbol: {symbol}. Use crypto pairs like BTCUSDT.'}

            quantity = max(round(float(volume), 8), 0.0)
            quote_amount = _safe_float(kwargs.get('quote_amount'), 0.0)
            market_price = _safe_float(kwargs.get('market_price'), 0.0)
            min_qty = 0.001
            step_size = 0.001

            if self.market != 'futures':
                symbol_filters = self._get_spot_symbol_filters(instrument)
                lot_size_filter = symbol_filters.get('LOT_SIZE', {}) if isinstance(symbol_filters, dict) else {}
                min_notional_filter = symbol_filters.get('MIN_NOTIONAL', {}) if isinstance(symbol_filters, dict) else {}
                notional_filter = symbol_filters.get('NOTIONAL', {}) if isinstance(symbol_filters, dict) else {}

                min_qty = _safe_float(lot_size_filter.get('minQty'), 0.001)
                step_size = _safe_float(lot_size_filter.get('stepSize'), 0.001)
                min_notional = max(
                    _safe_float(min_notional_filter.get('minNotional'), 0.0),
                    _safe_float(notional_filter.get('minNotional'), 0.0),
                )

                if market_price <= 0:
                    market_price = self._get_spot_symbol_price(instrument)

                if order_type.upper() == 'BUY' and quote_amount > 0 and market_price > 0:
                    quantity = quote_amount / market_price

                quantity = self._normalize_spot_quantity(quantity, step_size, min_qty)

                if market_price > 0 and min_notional > 0 and (quantity * market_price) < min_notional:
                    quantity = self._normalize_spot_quantity(
                        min_notional / market_price,
                        step_size,
                        min_qty,
                        round_up=True,
                    )

                if quantity <= 0:
                    return {'success': False, 'error': f'Unable to derive a valid Binance spot quantity for {instrument}'}

            if self.market != 'futures' and order_type.upper() == 'SELL' and instrument.endswith('USDT'):
                base_asset = instrument[:-4]
                available_quantity = self._get_spot_asset_free_balance(base_asset)
                if available_quantity <= 0:
                    return {
                        'success': False,
                        'error': f'Binance spot account has no {base_asset} available to sell. Spot mode cannot open naked SELL positions.',
                    }
                quantity = min(quantity, available_quantity)
                quantity = self._normalize_spot_quantity(quantity, step_size, min_qty)
                if quantity < max(min_qty, 0.001):
                    return {
                        'success': False,
                        'error': f'Binance spot account only has {available_quantity:.6f} {base_asset} free, below the minimum sellable size.',
                    }

            params = {
                'symbol': instrument,
                'side': order_type.upper(),
                'type': 'MARKET',
                'quantity': format(quantity, '.8f').rstrip('0').rstrip('.'),
            }
            endpoint = f"{self.fapi_url}/v1/order" if self.market == 'futures' else f"{self.base_url}/v3/order"
            resp = self._request_with_time_retry('POST', endpoint, headers=self._headers(), params=params, timeout=15)
            if resp.status_code == 200:
                result = resp.json()
                return {
                    'success': True,
                    'orderId': result.get('orderId', ''),
                    'symbol': instrument,
                    'type': order_type.upper(),
                    'status': result.get('status', ''),
                    'executedQty': _safe_float(result.get('executedQty'), quantity),
                    'quoteQty': _safe_float(result.get('cummulativeQuoteQty'), 0.0),
                    'transactTime': result.get('transactTime'),
                    'broker': 'Binance',
                }
            return {'success': False, 'error': resp.text}
        except Exception as e:
            logger.error(f"Error placing Binance order: {e}")
            return {'success': False, 'error': str(e)}

    def close_position(self, position_id: str) -> Dict:
        try:
            if not self.connected:
                return {'success': False, 'error': 'Not connected to Binance'}
            if self.market == 'futures':
                positions = self.get_positions()
                pos = next((p for p in positions if str(p.get('deal_id')) == str(position_id)), None)
                if not pos:
                    return {'success': False, 'error': f'Futures position {position_id} not found'}
                close_side = 'SELL' if pos['type'] == 'BUY' else 'BUY'
                params = {
                    'symbol': pos['symbol'],
                    'side': close_side,
                    'type': 'MARKET',
                    'quantity': str(pos['size']),
                    'reduceOnly': 'true',
                }
                resp = self._request_with_time_retry('POST', f'{self.fapi_url}/v1/order', headers=self._headers(), params=params, timeout=15)
            else:
                open_orders = self.get_positions()
                order = next((entry for entry in open_orders if str(entry.get('deal_id')) == str(position_id)), None)
                if not order:
                    return {'success': False, 'error': f'Binance spot order {position_id} not found'}

                spot_symbol = str(order.get('symbol', '')).upper()
                if str(position_id).startswith('SPOT-'):
                    spot_size = max(_safe_float(order.get('size') or order.get('volume'), 0.0), 0.0)
                    if spot_size < 0.001:
                        return {'success': False, 'error': f'Binance spot holding {position_id} is below the minimum sellable size'}
                    resp = self._request_with_time_retry('POST', f'{self.base_url}/v3/order', headers=self._headers(), params={
                        'symbol': spot_symbol,
                        'side': 'SELL',
                        'type': 'MARKET',
                        'quantity': str(round(spot_size, 4)),
                    }, timeout=15)
                else:
                    resp = self._request_with_time_retry('DELETE', f'{self.base_url}/v3/order', headers=self._headers(), params={
                        'symbol': spot_symbol,
                        'orderId': position_id,
                    }, timeout=15)
            if resp.status_code in (200, 201):
                return {'success': True, 'position_id': position_id, 'broker': 'Binance'}
            return {'success': False, 'error': resp.text}
        except Exception as e:
            logger.error(f'Error closing Binance position: {e}')
            return {'success': False, 'error': str(e)}

    def get_trades(self) -> List[Dict]:
        try:
            if not self.connected:
                return []
            result = []
            endpoint = f'{self.fapi_url}/v1/userTrades' if self.market == 'futures' else f'{self.base_url}/v3/myTrades'
            watch_symbols = getattr(self, '_active_symbols', ['BTCUSDT', 'ETHUSDT', 'BNBUSDT'])
            for symbol in watch_symbols[:5]:  # limit to avoid rate limits
                try:
                    resp = self._request_with_time_retry('GET', endpoint, headers=self._headers(), params={'symbol': symbol, 'limit': 20}, timeout=10)
                    if resp.status_code == 200:
                        for trade in resp.json():
                            result.append({
                                'deal_id': str(trade.get('id', '')),
                                'symbol': trade.get('symbol', ''),
                                'type': 'BUY' if trade.get('isBuyer') else 'SELL',
                                'volume': float(trade.get('qty', 0)),
                                'price': float(trade.get('price', 0)),
                                'profit': float(trade.get('realizedPnl', 0)),
                                'time': trade.get('time'),
                                'broker': 'Binance',
                            })
                except Exception:
                    pass
            return result
        except Exception as e:
            logger.error(f'Error getting Binance trades: {e}')
            return []


class FXCMConnection(BrokerConnection):
    """FXCM broker connection via REST API."""

    def __init__(self, credentials: Dict = None):
        if credentials is None:
            credentials = {
                'api_key': os.getenv('FXCM_API_TOKEN', ''),
                'account_number': os.getenv('FXCM_ACCOUNT_ID', ''),
                'is_live': False,
            }

        super().__init__(BrokerType.FXM, credentials)
        self.base_url = self._candidate_base_urls()[0]
        self.last_error = ''
        self.forexconnect_client = None
        self.forexconnect_mode = False
        self.forexconnect_helper_mode = False
        self.forexconnect_helper_python = get_fxcm_forexconnect_python()

    def _fxcm_cache_key(self) -> str:
        return str(self.credentials.get('credential_id') or '').strip()

    def _helper_read_actions(self) -> Set[str]:
        return {'login_check', 'get_account_info', 'get_positions', 'get_trades', 'list_symbols'}

    def _get_helper_cache_entry(self) -> Optional[Dict[str, Any]]:
        cache_key = self._fxcm_cache_key()
        if not cache_key:
            return None
        return _fxcm_result_cache.setdefault(cache_key, {})

    def _mark_helper_read_failure(self, error_message: str) -> None:
        cache_entry = self._get_helper_cache_entry()
        if cache_entry is None:
            return
        now = time.monotonic()
        cache_entry['helper_read_error'] = str(error_message or '').strip()
        cache_entry['helper_read_failed_at'] = now
        cache_entry['helper_read_failed_until'] = now + _FXCM_HELPER_READ_FAILURE_COOLDOWN

    def _clear_helper_read_failure(self) -> None:
        cache_entry = self._get_helper_cache_entry()
        if cache_entry is None:
            return
        cache_entry.pop('helper_read_error', None)
        cache_entry.pop('helper_read_failed_at', None)
        cache_entry.pop('helper_read_failed_until', None)

    def _helper_read_failure_message(self) -> str:
        cache_entry = self._get_helper_cache_entry() or {}
        blocked_until = float(cache_entry.get('helper_read_failed_until', 0) or 0)
        remaining = blocked_until - time.monotonic()
        if remaining <= 0:
            return ''
        last_error = str(cache_entry.get('helper_read_error') or 'FXCM helper read path is temporarily unavailable').strip()
        return f"{last_error} (cooldown {int(max(1, round(remaining)))}s)"

    def _helper_read_fallback_account_info(self) -> Dict[str, Any]:
        cache_entry = self._get_helper_cache_entry() or {}
        cached_account_info = cache_entry.get('account_info')
        if not isinstance(cached_account_info, dict):
            return {}
        fallback = dict(cached_account_info)
        fallback['dataSource'] = fallback.get('dataSource') or 'helper-cache'
        return fallback

    def _helper_read_fallback_positions(self) -> List[Dict[str, Any]]:
        cache_entry = self._get_helper_cache_entry() or {}
        cached_positions = cache_entry.get('positions')
        return list(cached_positions) if isinstance(cached_positions, list) else []

    def _helper_read_fallback_trades(self) -> List[Dict[str, Any]]:
        cache_entry = self._get_helper_cache_entry() or {}
        cached_trades = cache_entry.get('trades')
        return list(cached_trades) if isinstance(cached_trades, list) else []

    def _invalidate_helper_cache(self, *, clear_account: bool = False) -> None:
        cache_key = self._fxcm_cache_key()
        if not cache_key:
            return

        cached = _fxcm_result_cache.get(cache_key)
        if not cached:
            return

        cached.pop('positions', None)
        cached.pop('ts', None)
        if clear_account:
            cached.pop('account_info', None)
            cached.pop('account_id', None)
            cached.pop('account_ts', None)
        cached.pop('trades', None)
        cached.pop('trades_ts', None)
        if not cached:
            _fxcm_result_cache.pop(cache_key, None)

    def _server_mode(self) -> str:
        server = str(self.credentials.get('server', '') or '').strip().lower()
        if bool(self.credentials.get('is_live', False)) or server in {'real', 'live', 'fxcm'}:
            return 'real'
        return 'demo'

    def _candidate_base_urls(self) -> List[str]:
        urls = []
        explicit_url = str(self.credentials.get('base_url') or os.getenv('FXCM_BASE_URL', '')).strip().rstrip('/')
        if explicit_url:
            urls.append(explicit_url)

        defaults = ['https://api.fxcm.com'] if self._server_mode() == 'real' else [
            'https://api-demo.fxcm.com',
            'https://api.fxcm.com',
        ]
        for url in defaults:
            if url not in urls:
                urls.append(url)
        return urls

    def _has_forexconnect_credentials(self) -> bool:
        return bool(self.credentials.get('username') and self.credentials.get('password'))

    def _forexconnect_url(self) -> str:
        configured = str(self.credentials.get('server') or '').strip()
        if configured.lower().startswith(('http://', 'https://')):
            return configured
        return 'https://www.fxcorporate.com/Hosts.jsp'

    def _forexconnect_connection_name(self) -> str:
        explicit = str(self.credentials.get('connection') or '').strip()
        if explicit:
            return explicit
        return 'Real' if bool(self.credentials.get('is_live', False)) else 'Demo'

    def _normalize_forexconnect_symbol(self, instrument: str) -> str:
        return (instrument or '').replace('/', '').upper()

    def _forexconnect_offer_subscription_status(self, offer) -> str:
        return str(getattr(offer, 'subscription_status', '') or '').upper()

    def _is_tradeable_forexconnect_offer(self, offer) -> bool:
        return self._forexconnect_offer_subscription_status(offer) == 'T' and bool(str(getattr(offer, 'offer_id', '') or '').strip())

    def _find_forexconnect_offer(self, symbol: str):
        if not self.forexconnect_client:
            return None
        try:
            from forexconnect import ForexConnect  # type: ignore

            requested = self._normalize_forexconnect_symbol(symbol)
            offers_table = self.forexconnect_client.get_table(ForexConnect.OFFERS)
            if offers_table is None:
                return None

            for offer in offers_table:
                instrument = str(getattr(offer, 'instrument', '') or '')
                if self._normalize_forexconnect_symbol(instrument) != requested:
                    continue
                if self._is_tradeable_forexconnect_offer(offer):
                    return offer
            return None
        except Exception as e:
            logger.error(f"Error reading ForexConnect offers table: {e}")
            return None

    def _find_forexconnect_trade(self, position_id: str):
        trade_id = str(position_id or '').strip()
        if not trade_id:
            return None
        for trade in self._get_forexconnect_trades_table():
            if str(getattr(trade, 'trade_id', '') or '') == trade_id:
                return trade
        return None

    def _resolve_fxcm_order_amount(self, volume: float, instrument: str, account=None) -> int:
        requested_volume = max(float(volume or 0), 0.0)
        if requested_volume <= 0:
            return 1

        normalized_instrument = self._normalize_forexconnect_symbol(instrument)
        asset_contract_baseline = 100000.0
        if normalized_instrument in {
            'XAU/USD', 'XAG/USD', 'USOIL', 'UKOIL', 'USOILSPOT', 'UKOILSPOT',
            'US30', 'GER30', 'NAS100', 'SPX500', 'UK100', '5USNOTE', '10USNOTE',
            '2USNOTE', 'BOBL', 'SCHATZ', 'FED30D', 'EURIBOR3M', 'SONIA3M',
        }:
            asset_contract_baseline = 1.0

        # Bot sizing is produced in MT5-style lots. FXCM expects trade amounts in instrument units.
        # Forex pairs use a 100k contract baseline, while metals, energy, indices, and rates use
        # a single-contract baseline so non-forex trades are not oversized.
        estimated_units = requested_volume * asset_contract_baseline
        base_unit_size = 0
        try:
            login_rules = self.forexconnect_client.login_rules if self.forexconnect_client else None
            trading_settings_provider = getattr(login_rules, 'trading_settings_provider', None)
            base_unit_size = int(trading_settings_provider.get_base_unit_size(instrument, account)) if trading_settings_provider else 0
        except Exception as e:
            logger.debug(f"FXCM base unit lookup failed for {instrument}: {e}")
            base_unit_size = 0

        if base_unit_size > 0:
            estimated_units = max(base_unit_size, round(estimated_units / base_unit_size) * base_unit_size)

        return max(int(round(estimated_units)), 1)

    def _send_forexconnect_request(self, request):
        if not self.forexconnect_client:
            self.last_error = 'ForexConnect client is not available'
            return None
        if request is None:
            self.last_error = 'ForexConnect could not create the request'
            return None
        try:
            response = self.forexconnect_client.send_request(request)
            self.last_error = ''
            return response
        except Exception as e:
            self.last_error = str(e)
            logger.error(f"Error sending ForexConnect request: {e}")
            return None

    def _can_use_forexconnect_helper(self) -> bool:
        helper_python = str(self.forexconnect_helper_python or '').strip().strip('"')
        helper_script = get_fxcm_forexconnect_helper_script()
        return bool(helper_python and os.path.exists(helper_python) and os.path.exists(helper_script))

    def _run_forexconnect_helper(self, action: str, *, extra: Dict = None, timeout: int = 45) -> Optional[Dict]:
        if not self._can_use_forexconnect_helper():
            self.last_error = (
                'FXCM ForexConnect helper is not configured. '
                'Set FXCM_FOREXCONNECT_PYTHON to a Python 3.7 interpreter with forexconnect installed.'
            )
            return None

        if action in self._helper_read_actions():
            failure_message = self._helper_read_failure_message()
            if failure_message:
                self.last_error = failure_message
                _log_fxcm_once(
                    'warning',
                    f'fxcm-helper-read-cooldown:{self._fxcm_cache_key()}:{action}:{failure_message}',
                    f"[FXCM] Skipping helper {action} during failure cooldown: {failure_message}",
                    cooldown_seconds=15,
                )
                return None

        helper_credentials = dict(self.credentials or {})
        payload = {
            'credentials': helper_credentials,
            'extra': extra or {},
        }
        helper_script = get_fxcm_forexconnect_helper_script()

        def _invoke_helper(current_payload: Dict) -> tuple[Optional[subprocess.CompletedProcess], Optional[str]]:
            try:
                completed = subprocess.run(
                    [self.forexconnect_helper_python, helper_script, action],
                    input=json.dumps(current_payload),
                    capture_output=True,
                    text=True,
                    timeout=timeout,
                )
                return completed, None
            except Exception as e:
                return None, str(e)

        try:
            completed, invoke_error = _invoke_helper(payload)
        except Exception as e:
            completed = None
            invoke_error = str(e)

        if invoke_error:
            self.last_error = invoke_error
            if action in self._helper_read_actions():
                self._mark_helper_read_failure(invoke_error)
            logger.error(f"Error running FXCM ForexConnect helper: {invoke_error}")
            return None

        if completed is None:
            self.last_error = 'FXCM helper did not return a result'
            return None

        stdout = (completed.stdout or '').strip()
        stderr = (completed.stderr or '').strip()
        if completed.returncode != 0:
            parsed_error = None
            try:
                helper_error_payload = json.loads(stdout) if stdout else {}
                if isinstance(helper_error_payload, dict):
                    parsed_error = helper_error_payload.get('error')
            except Exception:
                parsed_error = None

            if (
                action == 'login_check'
                and helper_credentials.get('account_number')
                and str(parsed_error or stderr or stdout or '').strip() == 'No FXCM account available for the supplied credentials'
            ):
                retry_credentials = dict(helper_credentials)
                requested_account = str(retry_credentials.get('account_number') or '').strip()
                retry_credentials['account_number'] = ''
                retry_payload = {
                    'credentials': retry_credentials,
                    'extra': extra or {},
                }
                retry_completed, retry_error = _invoke_helper(retry_payload)
                if retry_error:
                    self.last_error = retry_error
                    if action in self._helper_read_actions():
                        self._mark_helper_read_failure(retry_error)
                    _log_fxcm_once('error', f'fxcm-helper-retry:{action}:{retry_error}', f"Error retrying FXCM ForexConnect helper without account number: {retry_error}")
                    return None
                if retry_completed and retry_completed.returncode == 0:
                    retry_stdout = (retry_completed.stdout or '').strip()
                    try:
                        retry_result = json.loads(retry_stdout) if retry_stdout else {}
                    except Exception as e:
                        self.last_error = f'Invalid FXCM helper response: {e}'
                        logger.error(f"FXCM helper returned invalid JSON for {action} retry: {retry_stdout[:500]}")
                        return None
                    resolved_account = str((retry_result.get('account') or {}).get('account_id') or (retry_result.get('account') or {}).get('accountNumber') or '').strip()
                    if resolved_account and requested_account and resolved_account != requested_account:
                        logger.info(
                            f"[FXCM] Helper could not match requested account '{requested_account}'; using available account '{resolved_account}' instead"
                        )
                    self.last_error = ''
                    if action in self._helper_read_actions():
                        self._clear_helper_read_failure()
                    return retry_result

            self.last_error = str(parsed_error or stderr or stdout or f'FXCM helper exited with code {completed.returncode}')
            if action in self._helper_read_actions():
                self._mark_helper_read_failure(self.last_error)
            _log_fxcm_once('error', f'fxcm-helper:{action}:{self.last_error}', f"FXCM helper failed for {action}: {self.last_error}")
            return None

        try:
            result = json.loads(stdout) if stdout else {}
        except Exception as e:
            self.last_error = f'Invalid FXCM helper response: {e}'
            logger.error(f"FXCM helper returned invalid JSON for {action}: {stdout[:500]}")
            return None

        if result.get('success') is False:
            self.last_error = str(result.get('error') or 'FXCM helper request failed')
            if action in self._helper_read_actions():
                self._mark_helper_read_failure(self.last_error)
        else:
            self.last_error = ''
            if action in self._helper_read_actions():
                self._clear_helper_read_failure()
        return result

    def _login_forexconnect(self) -> bool:
        if self._can_use_forexconnect_helper():
            # Check if we have a recent cached login result — avoid redundant subprocess login
            cred_id = str(self.credentials.get('credential_id') or '').strip()
            now = time.monotonic()
            cached = _fxcm_result_cache.get(cred_id) if cred_id else None
            # Use account_ts (set by login_check) or ts (set by get_positions) as freshness indicator
            cache_age = now - max(cached.get('account_ts', 0), cached.get('ts', 0)) if cached else _FXCM_CACHE_TTL + 1
            if cached and cache_age < _FXCM_CACHE_TTL and cached.get('account_id'):
                # Cache is fresh — reuse without spawning a subprocess
                cached_account = cached.get('account_info') or {}
                cached_account_id = str(cached.get('account_id') or '').strip()
                if cached_account_id:
                    self.credentials['account_number'] = cached_account_id
                self.account_info = cached_account
                self.forexconnect_helper_mode = True
                self.forexconnect_mode = False
                self.connected = True
                self.last_error = ''
                return True

            result = self._run_forexconnect_helper('login_check', timeout=60)
            if result and result.get('success'):
                account = result.get('account') or {}
                account_id = str(account.get('account_id') or account.get('accountNumber') or '').strip()
                if account_id:
                    self.credentials['account_number'] = account_id
                self.account_info = account if isinstance(account, dict) else {}
                self.forexconnect_helper_mode = True
                self.forexconnect_mode = False
                self.connected = True
                self.last_error = ''
                # Seed account cache (positions will be fetched separately on first get_positions call)
                if cred_id:
                    entry = _fxcm_result_cache.setdefault(cred_id, {})
                    entry['account_info'] = self.account_info
                    entry['account_id'] = account_id
                    entry['account_ts'] = now
                    # Don't set 'ts' here — let get_positions set it after actually fetching
                return True

        try:
            ensure_forexconnect_sdk_available()
            from forexconnect import ForexConnect  # type: ignore

            username = self.credentials.get('username')
            password = self.credentials.get('password')
            if not username or not password:
                self.last_error = 'Missing FXCM username or password'
                return False

            fx = ForexConnect()
            fx.login(
                username,
                password,
                self._forexconnect_url(),
                self._forexconnect_connection_name(),
                self.credentials.get('session_id'),
                self.credentials.get('pin'),
                None,
            )

            table_manager = fx.table_manager
            accounts_table = table_manager.get_table(ForexConnect.ACCOUNTS)
            account_id = str(self.credentials.get('account_number', '') or '').strip()
            account_row = None
            fallback_account_row = None

            if accounts_table is not None:
                for row in accounts_table:
                    row_account_id = str(getattr(row, 'account_id', '') or '')
                    if fallback_account_row is None:
                        fallback_account_row = row
                    if row_account_id == account_id or not account_id:
                        account_row = row
                        break

            if account_row is None and fallback_account_row is not None:
                requested_account = account_id
                account_row = fallback_account_row
                resolved_account = str(getattr(account_row, 'account_id', '') or '')
                if requested_account and requested_account != resolved_account:
                    logger.info(
                        f"[FXCM] Requested account '{requested_account}' did not match ForexConnect accounts; using available account '{resolved_account}' instead"
                    )

            if account_row is None:
                self.last_error = 'No FXCM account available for the supplied credentials'
                try:
                    fx.logout()
                except Exception:
                    pass
                return False

            self.credentials['account_number'] = str(getattr(account_row, 'account_id', account_id) or account_id)
            self.forexconnect_client = fx
            self.forexconnect_mode = True
            self.connected = True
            self.last_error = ''
            return True
        except ImportError:
            self.last_error = (
                'ForexConnect Python bindings were not found in this backend environment. '
                'Install the official FXCM ForexConnect SDK, set FOREXCONNECT_HOME to the SDK path, '
                'or configure FXCM_FOREXCONNECT_PYTHON to a Python 3.7 interpreter with forexconnect installed.'
            )
            _log_fxcm_once('error', f'fxcm-forexconnect-import:{self.last_error}', self.last_error)
            return False
        except Exception as e:
            self.last_error = str(e)
            logger.error(f"Error connecting to FXCM via ForexConnect: {e}")
            return False

    def _get_forexconnect_account_row(self):
        if not self.forexconnect_client:
            return None
        try:
            from forexconnect import ForexConnect  # type: ignore

            accounts_table = self.forexconnect_client.table_manager.get_table(ForexConnect.ACCOUNTS)
            account_id = str(self.credentials.get('account_number', '') or '')
            if accounts_table is not None:
                for row in accounts_table:
                    if str(getattr(row, 'account_id', '') or '') == account_id or not account_id:
                        return row
        except Exception as e:
            logger.error(f"Error reading ForexConnect accounts table: {e}")
        return None

    def _get_forexconnect_trades_table(self):
        if not self.forexconnect_client:
            return []
        try:
            from forexconnect import ForexConnect  # type: ignore

            table = self.forexconnect_client.table_manager.get_table(ForexConnect.TRADES)
            return table or []
        except Exception as e:
            logger.error(f"Error reading ForexConnect trades table: {e}")
            return []

    def _get_forexconnect_closed_trades_table(self):
        if not self.forexconnect_client:
            return []
        try:
            from forexconnect import ForexConnect  # type: ignore

            table = self.forexconnect_client.table_manager.get_table(ForexConnect.CLOSED_TRADES)
            return table or []
        except Exception as e:
            logger.error(f"Error reading ForexConnect closed trades table: {e}")
            return []

    def _headers(self, content_type: bool = True) -> Dict:
        headers = {
            'Authorization': f"Bearer {self.credentials.get('api_key', '')}",
            'Accept': 'application/json',
        }
        if content_type:
            headers['Content-Type'] = 'application/json'
        return headers

    def _normalize_symbol(self, symbol: str) -> Optional[str]:
        if not symbol:
            return None

        canonical_symbol = normalize_symbol_for_broker(symbol, 'FXCM')
        if canonical_symbol in FXCM_CONFIGURABLE_SYMBOLS:
            compact_symbol = canonical_symbol.upper().replace('_', '').replace('/', '')
            if compact_symbol in {
                'EURUSD', 'GBPUSD', 'USDJPY', 'USDCHF', 'AUDUSD', 'NZDUSD', 'USDCAD', 'XAUUSD', 'XAGUSD'
            }:
                symbol = compact_symbol
            else:
                return canonical_symbol
        else:
            symbol = symbol.upper().replace('_', '').replace('/', '')

        symbol_map = {
            'EURUSD': 'EUR/USD',
            'GBPUSD': 'GBP/USD',
            'USDJPY': 'USD/JPY',
            'USDCHF': 'USD/CHF',
            'AUDUSD': 'AUD/USD',
            'NZDUSD': 'NZD/USD',
            'USDCAD': 'USD/CAD',
            'XAUUSD': 'XAU/USD',
            'XAGUSD': 'XAG/USD',
        }
        if symbol in symbol_map:
            return symbol_map[symbol]
        if len(symbol) == 6 and symbol.isalpha():
            return f"{symbol[:3]}/{symbol[3:]}"
        return None

    def _display_symbol(self, instrument: str) -> str:
        return (instrument or '').replace('/', '').upper()

    def _extract_payload_list(self, payload: Dict, *keys: str) -> List[Dict]:
        if not isinstance(payload, dict):
            return []

        response_payload = payload.get('response') if isinstance(payload.get('response'), dict) else {}
        candidates = [payload, response_payload]
        for candidate in candidates:
            for key in keys:
                value = candidate.get(key)
                if isinstance(value, list):
                    return value
        return []

    def _is_dns_resolution_error(self, raw_error) -> bool:
        message = str(raw_error or '').lower()
        return (
            'nameresolutionerror' in message or
            'failed to resolve' in message or
            'getaddrinfo failed' in message or
            'temporary failure in name resolution' in message
        )

    def _format_connectivity_error(self, prefix: str, errors: List[str]) -> str:
        if any(self._is_dns_resolution_error(err) for err in errors):
            return (
                'FXCM host DNS lookup failed on the backend. '
                'The server cannot resolve api.fxcm.com/api-demo.fxcm.com right now. '
                'This is a VPS/network DNS problem, not a bad FXCM login. '
                'Fix the server DNS or outbound access, then retry.'
            )
        return prefix + ' | '.join(errors)

    def _request(self, method: str, path: str, *, params: Dict = None, json: Dict = None, timeout: int = 15) -> Optional[Dict]:
        try:
            import requests
            errors = []
            for base_url in self._candidate_base_urls():
                try:
                    response = requests.request(
                        method,
                        f"{base_url}{path}",
                        headers=self._headers(content_type=json is not None),
                        params=params,
                        json=json,
                        timeout=timeout,
                    )
                    self.base_url = base_url
                    if response.status_code != 200:
                        self.last_error = f"HTTP {response.status_code}: {response.text[:300]}"
                        _log_fxcm_once('error', f'fxcm-request:{path}:{self.last_error}', f"FXCM request failed for {path}: {self.last_error}")
                        return None

                    payload = response.json()
                    if isinstance(payload, dict) and payload.get('error'):
                        self.last_error = str(payload.get('error'))
                        _log_fxcm_once('error', f'fxcm-api-error:{path}:{self.last_error}', f"FXCM API returned error for {path}: {self.last_error}")
                        return None

                    self.last_error = ''
                    return payload if isinstance(payload, dict) else {}
                except Exception as e:
                    errors.append(f"{base_url}: {e}")

            self.last_error = self._format_connectivity_error(
                'FXCM request failed for all configured hosts: ',
                errors,
            )
            _log_fxcm_once('error', f'fxcm-endpoint:{path}:{self.last_error}', f"Error calling FXCM endpoint {path}: {self.last_error}")
            return None
        except Exception as e:
            self.last_error = str(e)
            _log_fxcm_once('error', f'fxcm-endpoint-exception:{path}:{self.last_error}', f"Error calling FXCM endpoint {path}: {e}")
            return None

    def _connect_socketio_rest(self) -> bool:
        """Authenticate via FXCM Socket.IO REST handshake.
        
        Demo accounts can use the login password as the Socket.IO access_token.
        Token-based accounts can also pass an API token in api_key/password.
        The handshake returns a session ID used as the bearer token prefix.
        """
        import requests as _req

        password = self.credentials.get('password', '')
        token = self.credentials.get('api_key', '') or password
        if not token:
            return False

        errors = []
        for base_url in self._candidate_base_urls():
            try:
                handshake_url = f"{base_url}/socket.io/?EIO=3&transport=polling&access_token={token}"
                resp = _req.get(handshake_url, timeout=15)
                if resp.status_code == 200:
                    text = resp.text
                    json_start = text.find('{')
                    if json_start >= 0:
                        import json as _json
                        handshake_data = _json.loads(text[json_start:text.rfind('}') + 1])
                        sid = handshake_data.get('sid', '')
                        if sid:
                            self.base_url = base_url
                            self.credentials['api_key'] = f"{sid}{token}"
                            self.connected = True
                            self.last_error = ''
                            logger.info(f"[FXCM] ✅ Socket.IO REST auth succeeded ({self.base_url})")
                            self.get_account_info()
                            return True
                _log_fxcm_once('warning', f'fxcm-socketio-status:{base_url}:{resp.status_code}', f"[FXCM] Socket.IO handshake returned {resp.status_code} ({base_url})")
            except Exception as e:
                errors.append(f"{base_url}: {e}")
                _log_fxcm_once('warning', f'fxcm-socketio-exception:{base_url}:{e}', f"[FXCM] Socket.IO REST auth failed for {base_url}: {e}")

        if errors:
            self.last_error = self._format_connectivity_error(
                'FXCM Socket.IO handshake failed for all configured hosts: ',
                errors,
            )
        return False

    def connect(self) -> bool:
        try:
            # Strategy 1: ForexConnect SDK with Login ID + Password.
            # This is the documented FXCM Trading Station path and does not depend on api.fxcm.com DNS.
            if self._has_forexconnect_credentials():
                if self._login_forexconnect():
                    return True
                forexconnect_error = self.last_error
            else:
                forexconnect_error = ''

            # Strategy 2: Socket.IO REST handshake for token-based auth.
            # FXCM REST API REQUIRES a Socket.IO handshake first to obtain a session token.
            socketio_error = ''
            token = self.credentials.get('api_key') or self.credentials.get('token')
            demo_password_token = ''
            if not token and self._server_mode() == 'demo' and self._has_forexconnect_credentials():
                demo_password_token = self.credentials.get('password') or ''

            should_try_rest = bool(token or demo_password_token) and not (
                self._has_forexconnect_credentials()
                and forexconnect_error
                and 'not configured' not in forexconnect_error.lower()
                and 'bindings were not found' not in forexconnect_error.lower()
            )
            if should_try_rest:
                if self._connect_socketio_rest():
                    return True
                socketio_error = self.last_error

            self.last_error = socketio_error or forexconnect_error or (
                'FXCM authentication failed. '
                'Use Login ID + Password with ForexConnect, or use an API token for REST mode. '
                'If the backend does not have ForexConnect installed, install the official forexconnect package.'
            )
            _log_fxcm_once('error', f'fxcm-connect-final:{self.last_error}', f'[FXCM] {self.last_error}')
            return False
        except Exception as e:
            self.last_error = str(e)
            _log_fxcm_once('error', f'fxcm-connect-exception:{self.last_error}', f"Error connecting to FXCM: {e}")
            return False

    def disconnect(self) -> bool:
        self._invalidate_helper_cache(clear_account=False)
        if self.forexconnect_client:
            try:
                self.forexconnect_client.logout()
            except Exception as e:
                logger.debug(f"FXCM ForexConnect logout warning: {e}")
            finally:
                self.forexconnect_client = None
                self.forexconnect_mode = False
        self.forexconnect_helper_mode = False
        self.connected = False
        return True

    def get_account_info(self) -> Dict:
        try:
            if not self.connected:
                return {}

            if self.forexconnect_helper_mode:
                cred_id = str(self.credentials.get('credential_id') or '').strip()
                now = time.monotonic()
                cached = _fxcm_result_cache.get(cred_id) if cred_id else None
                cache_age = now - max(cached.get('account_ts', 0), cached.get('ts', 0)) if cached else _FXCM_CACHE_TTL + 1
                if cached and cache_age < _FXCM_CACHE_TTL and cached.get('account_info'):
                    return dict(cached['account_info'])

                result = self._run_forexconnect_helper('get_account_info')
                if not result or result.get('success') is False:
                    fallback_account_info = self._helper_read_fallback_account_info()
                    if fallback_account_info:
                        return fallback_account_info
                    return {}
                account = result.get('account') or {}
                if isinstance(account, dict):
                    self.account_info = account
                    if cred_id:
                        entry = _fxcm_result_cache.setdefault(cred_id, {})
                        entry['account_info'] = account
                        entry['account_id'] = str(account.get('account_id') or account.get('accountNumber') or '')
                        entry['account_ts'] = now
                return self.account_info

            if self.forexconnect_mode:
                account = self._get_forexconnect_account_row()
                if not account:
                    self.last_error = 'No FXCM account payload returned'
                    return {}

                self.account_info = {
                    'account_id': str(getattr(account, 'account_id', '')),
                    'accountNumber': str(getattr(account, 'account_id', '')),
                    'balance': float(getattr(account, 'balance', 0) or 0),
                    'equity': float(getattr(account, 'equity', getattr(account, 'balance', 0)) or 0),
                    'margin_free': float(getattr(account, 'usable_margin', 0) or 0),
                    'marginFree': float(getattr(account, 'usable_margin', 0) or 0),
                    'margin': float(getattr(account, 'usd_mr', getattr(account, 'mr', 0)) or 0),
                    'profit': float(getattr(account, 'gross_pl', 0) or 0),
                    'currency': 'USD',
                    'broker': 'FXCM',
                    'dataSource': 'forexconnect',
                }
                return self.account_info

            data = self._request('GET', '/trading/get_model', params={'models': 'Account'}, timeout=10)
            if not data:
                return {}

            accounts = self._extract_payload_list(data, 'accounts', 'Account')
            account_id = str(self.credentials.get('account_number', '') or '')
            account = {}
            if isinstance(accounts, list):
                for item in accounts:
                    if str(item.get('accountId', item.get('account_id', ''))) == account_id or not account_id:
                        account = item
                        break
                if not account and accounts:
                    account = accounts[0]

            if account and not self.credentials.get('account_number'):
                self.credentials['account_number'] = str(account.get('accountId', account.get('account_id', '')))

            if not account:
                self.last_error = 'No FXCM account payload returned'
                return {}

            self.account_info = {
                'account_id': account.get('accountId', account.get('account_id', '')),
                'accountNumber': str(account.get('accountId', account.get('account_id', ''))),
                'balance': float(account.get('balance', 0) or 0),
                'equity': float(account.get('equity', account.get('balance', 0)) or 0),
                'margin_free': float(account.get('usableMargin', account.get('usable_margin', 0)) or 0),
                'marginFree': float(account.get('usableMargin', account.get('usable_margin', 0)) or 0),
                'margin': float(account.get('usdMr', account.get('margin', 0)) or 0),
                'profit': float(account.get('grossPL', account.get('profit', 0)) or 0),
                'currency': str(account.get('mc', account.get('currency', 'USD')) or 'USD').upper(),
                'broker': 'FXCM',
                'dataSource': 'live',
            }
            return self.account_info
        except Exception as e:
            self.last_error = str(e)
            logger.error(f"Error getting FXCM account info: {e}")

        return {}

    def get_tradable_symbols(self) -> Optional[List[str]]:
        try:
            if self._can_use_forexconnect_helper():
                result = self._run_forexconnect_helper('list_symbols', timeout=60)
                if result and result.get('success'):
                    symbols = result.get('symbols') or []
                    return [str(symbol).strip() for symbol in symbols if str(symbol).strip()]

            if not self.forexconnect_mode or not self.forexconnect_client:
                return None

            from forexconnect import ForexConnect  # type: ignore

            offers_table = self.forexconnect_client.get_table(ForexConnect.OFFERS)
            if offers_table is None:
                return []

            symbols = []
            for offer in offers_table:
                if not self._is_tradeable_forexconnect_offer(offer):
                    continue
                instrument = str(getattr(offer, 'instrument', '') or '').strip()
                if instrument and instrument not in symbols:
                    symbols.append(instrument)
            return symbols
        except Exception as e:
            self.last_error = str(e)
            logger.error(f"Error getting FXCM tradable symbols: {e}")
            return None

    def get_positions(self) -> List[Dict]:
        try:
            if not self.connected:
                return []

            if self.forexconnect_helper_mode:
                result = self._run_forexconnect_helper('get_positions')
                if not result or result.get('success') is False:
                    return self._helper_read_fallback_positions()
                positions = result.get('positions')
                positions = positions if isinstance(positions, list) else []
                cred_id = str(self.credentials.get('credential_id') or '').strip()
                if cred_id:
                    entry = _fxcm_result_cache.setdefault(cred_id, {})
                    entry['positions'] = positions
                    entry['ts'] = time.monotonic()
                return positions

            if self.forexconnect_mode:
                account_id = str(self.credentials.get('account_number', '') or '')
                positions = []
                for pos in self._get_forexconnect_trades_table():
                    row_account_id = str(getattr(pos, 'account_id', '') or '')
                    if account_id and row_account_id != account_id:
                        continue
                    buy_sell = str(getattr(pos, 'buy_sell', '') or '').upper()
                    positions.append({
                        'deal_id': str(getattr(pos, 'trade_id', '') or ''),
                        'symbol': self._normalize_forexconnect_symbol(getattr(pos, 'instrument', '')),
                        'type': 'BUY' if buy_sell.startswith('B') else 'SELL',
                        'size': abs(float(getattr(pos, 'amount', 0) or 0)),
                        'level': float(getattr(pos, 'open_rate', 0) or 0),
                        'profit_loss': float(getattr(pos, 'gross_pl', 0) or 0),
                        'broker': 'FXCM',
                    })
                return positions

            data = self._request('GET', '/trading/get_model', params={'models': 'OpenPosition'}, timeout=10)
            if not data:
                return []

            raw = self._extract_payload_list(data, 'open_positions', 'openPositions', 'OpenPosition')
            return [{
                'deal_id': str(pos.get('tradeId', pos.get('trade_id', ''))),
                'symbol': self._display_symbol(pos.get('currency', pos.get('symbol', ''))),
                'type': 'BUY' if pos.get('isBuy', pos.get('is_buy', False)) else 'SELL',
                'size': abs(float(pos.get('amountK', pos.get('amount', 0)) or 0)),
                'level': float(pos.get('open', pos.get('open_price', 0)) or 0),
                'profit_loss': float(pos.get('grossPL', pos.get('gross_pl', 0)) or 0),
                'broker': 'FXCM',
            } for pos in (raw if isinstance(raw, list) else [])]
        except Exception as e:
            self.last_error = str(e)
            logger.error(f"Error getting FXCM positions: {e}")

        return []

    def place_order(self, symbol: str, order_type: str, volume: float, **kwargs) -> Dict:
        try:
            if self.forexconnect_helper_mode:
                result = self._run_forexconnect_helper(
                    'place_order',
                    extra={
                        'symbol': symbol,
                        'order_type': order_type,
                        'volume': volume,
                        'kwargs': kwargs,
                    },
                    timeout=60,
                )
                if result and result.get('success'):
                    self._invalidate_helper_cache(clear_account=False)
                return result or {'success': False, 'error': self.last_error or 'FXCM helper order failed'}

            if self.forexconnect_mode:
                from forexconnect import fxcorepy  # type: ignore

                if not self.connected or not self.forexconnect_client:
                    return {'success': False, 'error': 'Not connected to FXCM'}

                account = self._get_forexconnect_account_row()
                if not account:
                    self.last_error = 'No FXCM account available for trading'
                    return {'success': False, 'error': self.last_error}

                offer = self._find_forexconnect_offer(symbol)
                if not offer:
                    self.last_error = f'Unsupported FXCM instrument: {symbol}'
                    return {'success': False, 'error': self.last_error}

                buy_sell = fxcorepy.Constants.BUY if str(order_type or '').upper() == 'BUY' else fxcorepy.Constants.SELL
                amount = self._resolve_fxcm_order_amount(volume, str(getattr(offer, 'instrument', symbol) or symbol), account)
                logger.info(
                    f"[FXCM ORDER] ForexConnect submit | symbol={symbol} | instrument={getattr(offer, 'instrument', symbol)} "
                    f"| side={str(order_type or '').upper()} | requested_volume={float(volume or 0):.4f} | amount={amount}"
                )
                request = self.forexconnect_client.create_order_request(
                    order_type=fxcorepy.Constants.Orders.TRUE_MARKET_OPEN,
                    ACCOUNT_ID=str(getattr(account, 'account_id', '') or self.credentials.get('account_number', '')),
                    BUY_SELL=buy_sell,
                    AMOUNT=amount,
                    OFFER_ID=str(getattr(offer, 'offer_id', '') or ''),
                )
                response = self._send_forexconnect_request(request)
                if not response:
                    return {
                        'success': False,
                        'error': (
                            self.last_error
                            or f"FXCM ForexConnect order failed for {symbol} "
                               f"(instrument={getattr(offer, 'instrument', symbol)}, "
                               f"offer_id={getattr(offer, 'offer_id', '')}, amount={amount}, "
                               f"subscription={self._forexconnect_offer_subscription_status(offer)})"
                        ),
                    }

                order_id = str(getattr(response, 'order_id', '') or getattr(request, 'request_id', '') or '')
                return {
                    'success': True,
                    'orderId': order_id,
                    'deal_id': '',
                    'tradeId': '',
                    'symbol': self._normalize_forexconnect_symbol(getattr(offer, 'instrument', symbol)),
                    'type': str(order_type or '').upper(),
                    'amount': amount,
                    'broker': 'FXCM',
                    'dataSource': 'forexconnect',
                }

            import requests

            if not self.connected:
                return {'success': False, 'error': 'Not connected to FXCM'}

            instrument = self._normalize_symbol(symbol)
            if not instrument:
                return {'success': False, 'error': f'Unsupported FXCM instrument: {symbol}'}

            amount = self._resolve_fxcm_order_amount(volume, instrument)
            logger.info(
                f"[FXCM ORDER] REST submit | symbol={symbol} | instrument={instrument} "
                f"| side={order_type.upper()} | requested_volume={float(volume or 0):.4f} | amount={amount}"
            )

            payload = {
                'account_id': self.credentials.get('account_number', ''),
                'symbol': instrument,
                'is_buy': order_type.upper() == 'BUY',
                'amount': amount,
                'order_type': 'AtMarket',
                'time_in_force': 'GTC',
            }
            resp = requests.post(
                f"{self.base_url}/trading/open_trade",
                headers=self._headers(),
                json=payload,
                timeout=15,
            )
            if resp.status_code == 200:
                result = resp.json().get('data', {})
                return {
                    'success': True,
                    'orderId': result.get('orderId', ''),
                    'tradeId': result.get('tradeId', ''),
                    'symbol': self._display_symbol(instrument),
                    'type': order_type.upper(),
                    'amount': amount,
                    'broker': 'FXCM',
                }
            return {'success': False, 'error': resp.text}
        except Exception as e:
            logger.error(f"Error placing FXCM order: {e}")
            return {'success': False, 'error': str(e)}

    def close_position(self, position_id: str) -> Dict:
        try:
            if self.forexconnect_helper_mode:
                result = self._run_forexconnect_helper(
                    'close_position',
                    extra={'position_id': position_id},
                    timeout=60,
                )
                if result and result.get('success'):
                    self._invalidate_helper_cache(clear_account=False)
                return result or {'success': False, 'error': self.last_error or 'FXCM helper close failed'}

            if self.forexconnect_mode:
                from forexconnect import fxcorepy  # type: ignore

                if not self.connected or not self.forexconnect_client:
                    return {'success': False, 'error': 'Not connected to FXCM'}

                trade = self._find_forexconnect_trade(position_id)
                if not trade:
                    self.last_error = f'FXCM trade not found: {position_id}'
                    return {'success': False, 'error': self.last_error}

                instrument = str(getattr(trade, 'instrument', '') or '')
                offer = self._find_forexconnect_offer(instrument)
                if not offer:
                    self.last_error = f'FXCM offer not found for trade instrument: {instrument or position_id}'
                    return {'success': False, 'error': self.last_error}

                buy_sell = str(getattr(trade, 'buy_sell', '') or '').upper()
                close_side = fxcorepy.Constants.SELL if buy_sell == fxcorepy.Constants.BUY else fxcorepy.Constants.BUY
                request = self.forexconnect_client.create_order_request(
                    order_type=fxcorepy.Constants.Orders.TRUE_MARKET_CLOSE,
                    OFFER_ID=str(getattr(offer, 'offer_id', '') or ''),
                    ACCOUNT_ID=str(getattr(trade, 'account_id', '') or self.credentials.get('account_number', '')),
                    BUY_SELL=close_side,
                    AMOUNT=max(int(getattr(trade, 'amount', 0) or 0), 1),
                    TRADE_ID=str(getattr(trade, 'trade_id', '') or position_id),
                )
                response = self._send_forexconnect_request(request)
                if not response:
                    return {'success': False, 'error': self.last_error or 'FXCM ForexConnect close failed'}

                return {
                    'success': True,
                    'trade_id': str(getattr(trade, 'trade_id', '') or position_id),
                    'orderId': str(getattr(response, 'order_id', '') or getattr(request, 'request_id', '') or ''),
                    'broker': 'FXCM',
                    'dataSource': 'forexconnect',
                }

            import requests

            resp = requests.post(
                f"{self.base_url}/trading/close_trade",
                headers=self._headers(),
                json={'trade_id': str(position_id)},
                timeout=15,
            )
            if resp.status_code == 200:
                return {'success': True, 'trade_id': position_id, 'broker': 'FXCM'}
            return {'success': False, 'error': resp.text}
        except Exception as e:
            logger.error(f"Error closing FXCM position: {e}")
            return {'success': False, 'error': str(e)}

    def get_trades(self) -> List[Dict]:
        try:
            if not self.connected:
                return []

            if self.forexconnect_helper_mode:
                result = self._run_forexconnect_helper('get_trades')
                if not result or result.get('success') is False:
                    return self._helper_read_fallback_trades()
                trades = result.get('trades')
                trades = trades if isinstance(trades, list) else []
                cred_id = str(self.credentials.get('credential_id') or '').strip()
                if cred_id:
                    entry = _fxcm_result_cache.setdefault(cred_id, {})
                    entry['trades'] = trades
                    entry['trades_ts'] = time.monotonic()
                return trades

            if self.forexconnect_mode:
                account_id = str(self.credentials.get('account_number', '') or '')
                result = []
                for trade in self._get_forexconnect_closed_trades_table():
                    row_account_id = str(getattr(trade, 'account_id', '') or '')
                    if account_id and row_account_id != account_id:
                        continue
                    buy_sell = str(getattr(trade, 'buy_sell', '') or '').upper()
                    result.append({
                        'ticket': str(getattr(trade, 'trade_id', '') or ''),
                        'symbol': self._normalize_forexconnect_symbol(getattr(trade, 'instrument', '')),
                        'type': 'BUY' if buy_sell.startswith('B') else 'SELL',
                        'volume': abs(float(getattr(trade, 'amount', 0) or 0)),
                        'entryPrice': float(getattr(trade, 'open_rate', 0) or 0),
                        'exitPrice': float(getattr(trade, 'close_rate', 0) or 0),
                        'profit': float(getattr(trade, 'gross_pl', 0) or 0),
                        'time': str(getattr(trade, 'close_time', '') or getattr(trade, 'trade_close_time', '') or ''),
                        'time_open': str(getattr(trade, 'open_time', '') or ''),
                        'time_close': str(getattr(trade, 'close_time', '') or getattr(trade, 'trade_close_time', '') or ''),
                        'broker': 'FXCM',
                    })
                return result

            data = self._request('GET', '/trading/get_model', params={'models': 'ClosedPosition'}, timeout=10)
            if not data:
                return []

            raw = self._extract_payload_list(data, 'closed_positions', 'closedPositions', 'ClosedPosition')
            result = []
            for trade in raw if isinstance(raw, list) else []:
                is_buy = trade.get('isBuy', trade.get('is_buy', False))
                open_time = trade.get('openTime') or trade.get('open_time')
                close_time = trade.get('closeTime') or trade.get('close_time')
                result.append({
                    'ticket': str(trade.get('tradeId', trade.get('trade_id', ''))),
                    'symbol': self._display_symbol(trade.get('currency', trade.get('symbol', ''))),
                    'type': 'BUY' if is_buy else 'SELL',
                    'entryCategory': 'trade',
                    'volume': abs(float(trade.get('amountK', trade.get('amount', 0)) or 0)),
                    'openPrice': float(trade.get('open', trade.get('open_price', 0)) or 0),
                    'closePrice': float(trade.get('close', trade.get('close_price', 0)) or 0),
                    'profit': float(trade.get('grossPL', trade.get('gross_pl', 0)) or 0),
                    'commission': float(trade.get('commission', 0) or 0),
                    'time': close_time or open_time or datetime.now().isoformat(),
                    'openTime': open_time,
                    'closeTime': close_time,
                    'broker': 'FXCM',
                })
            return result
        except Exception as e:
            self.last_error = str(e)
            logger.error(f"Error getting FXCM trades: {e}")
            return []


class OANDAConnection(BrokerConnection):
    """OANDA broker connection via REST API."""

    def __init__(self, credentials: Dict = None):
        if credentials is None:
            credentials = {
                'api_key': os.getenv('OANDA_API_KEY', ''),
                'account_number': os.getenv('OANDA_ACCOUNT_ID', ''),
                'is_live': False,
            }

        super().__init__(BrokerType.OANDA, credentials)
        is_live = bool(credentials.get('is_live', False))
        self.base_url = 'https://api-fxtrade.oanda.com/v3' if is_live else 'https://api-fxpractice.oanda.com/v3'

    def _headers(self, content_type: bool = True) -> Dict:
        headers = {
            'Authorization': f"Bearer {self.credentials.get('api_key', '')}",
            'Accept': 'application/json',
        }
        if content_type:
            headers['Content-Type'] = 'application/json'
        return headers

    def _normalize_symbol(self, symbol: str) -> Optional[str]:
        if not symbol:
            return None

        symbol = symbol.upper().replace('/', '').replace('_', '')
        if len(symbol) == 6 and symbol.isalpha():
            return f"{symbol[:3]}_{symbol[3:]}"
        symbol_map = {
            'XAUUSD': 'XAU_USD',
            'XAGUSD': 'XAG_USD',
        }
        return symbol_map.get(symbol)

    def _display_symbol(self, instrument: str) -> str:
        return (instrument or '').replace('_', '').upper()

    def connect(self) -> bool:
        try:
            import requests

            if not self.credentials.get('api_key'):
                logger.error('OANDA: Missing API key')
                return False

            account_id = self.credentials.get('account_number', '')
            if account_id:
                resp = requests.get(
                    f"{self.base_url}/accounts/{account_id}/summary",
                    headers=self._headers(content_type=False),
                    timeout=10,
                )
            else:
                resp = requests.get(
                    f"{self.base_url}/accounts",
                    headers=self._headers(content_type=False),
                    timeout=10,
                )

            if resp.status_code == 200:
                if not account_id:
                    accounts = resp.json().get('accounts', [])
                    if accounts:
                        self.credentials['account_number'] = accounts[0].get('id', '')
                self.connected = True
                self.get_account_info()
                return True
            logger.error(f"OANDA authentication failed: {resp.status_code} - {resp.text}")
            return False
        except Exception as e:
            logger.error(f"Error connecting to OANDA: {e}")
            return False

    def disconnect(self) -> bool:
        self.connected = False
        return True

    def get_account_info(self) -> Dict:
        try:
            import requests

            if not self.connected:
                return {}

            account_id = self.credentials.get('account_number', '')
            if not account_id:
                return {}

            resp = requests.get(
                f"{self.base_url}/accounts/{account_id}/summary",
                headers=self._headers(content_type=False),
                timeout=10,
            )
            if resp.status_code == 200:
                account = resp.json().get('account', {})
                self.account_info = {
                    'account_id': account.get('id', account_id),
                    'balance': float(account.get('balance', 0)),
                    'equity': float(account.get('NAV', 0)),
                    'margin_free': float(account.get('marginAvailable', 0)),
                    'currency': account.get('currency', 'USD'),
                    'broker': 'OANDA',
                }
                return self.account_info
        except Exception as e:
            logger.error(f"Error getting OANDA account info: {e}")

        return {}

    def get_positions(self) -> List[Dict]:
        try:
            import requests

            if not self.connected:
                return []

            account_id = self.credentials.get('account_number', '')
            resp = requests.get(
                f"{self.base_url}/accounts/{account_id}/openTrades",
                headers=self._headers(content_type=False),
                timeout=10,
            )
            if resp.status_code == 200:
                return [{
                    'deal_id': trade.get('id', ''),
                    'symbol': self._display_symbol(trade.get('instrument', '')),
                    'type': 'BUY' if float(trade.get('currentUnits', 0)) > 0 else 'SELL',
                    'size': abs(float(trade.get('currentUnits', 0))),
                    'level': float(trade.get('price', 0)),
                    'profit_loss': float(trade.get('unrealizedPL', 0)),
                    'broker': 'OANDA',
                } for trade in resp.json().get('trades', [])]
        except Exception as e:
            logger.error(f"Error getting OANDA positions: {e}")

        return []

    def place_order(self, symbol: str, order_type: str, volume: float, **kwargs) -> Dict:
        try:
            import requests

            if not self.connected:
                return {'success': False, 'error': 'Not connected to OANDA'}

            instrument = self._normalize_symbol(symbol)
            if not instrument:
                return {'success': False, 'error': f'Unsupported OANDA instrument: {symbol}'}

            units = max(1, int(round(float(volume))))
            if order_type.upper() == 'SELL':
                units = -units

            payload = {
                'order': {
                    'instrument': instrument,
                    'units': str(units),
                    'type': 'MARKET',
                    'timeInForce': 'FOK',
                    'positionFill': 'DEFAULT',
                }
            }
            account_id = self.credentials.get('account_number', '')
            resp = requests.post(
                f"{self.base_url}/accounts/{account_id}/orders",
                headers=self._headers(),
                json=payload,
                timeout=15,
            )
            if resp.status_code == 201:
                result = resp.json().get('orderFillTransaction', {})
                return {
                    'success': True,
                    'orderId': result.get('id', ''),
                    'deal_id': result.get('tradeOpened', {}).get('tradeID', ''),
                    'symbol': self._display_symbol(instrument),
                    'type': order_type.upper(),
                    'broker': 'OANDA',
                }
            return {'success': False, 'error': resp.text}
        except Exception as e:
            logger.error(f"Error placing OANDA order: {e}")
            return {'success': False, 'error': str(e)}

    def close_position(self, position_id: str) -> Dict:
        try:
            import requests

            account_id = self.credentials.get('account_number', '')
            resp = requests.put(
                f"{self.base_url}/accounts/{account_id}/trades/{position_id}/close",
                headers=self._headers(),
                json={'units': 'ALL'},
                timeout=15,
            )
            if resp.status_code == 200:
                return {'success': True, 'trade_id': position_id, 'broker': 'OANDA'}
            return {'success': False, 'error': resp.text}
        except Exception as e:
            logger.error(f"Error closing OANDA position: {e}")
            return {'success': False, 'error': str(e)}

    def get_trades(self) -> List[Dict]:
        return []





class BrokerManager:
    """Manages multiple broker connections"""
    
    def __init__(self):
        self.connections: Dict[str, BrokerConnection] = {}
        self.accounts: Dict[str, Dict] = {}

    def add_connection(self, account_id: str, broker_type: BrokerType, credentials: Dict = None):
        """Add a new broker connection"""
        try:
            if broker_type == BrokerType.METATRADER5:
                connection = MT5Connection(credentials)
            elif broker_type == BrokerType.BINANCE:
                connection = BinanceConnection(credentials)
            elif broker_type == BrokerType.OANDA:
                connection = OANDAConnection(credentials)

            elif broker_type == BrokerType.FXM:
                connection = FXCMConnection(credentials)
            else:
                logger.error(f"Broker {broker_type} not yet implemented")
                return False

            self.connections[account_id] = connection
            logger.info(f"Connection added: {account_id} ({broker_type.value})")
            return True
        except Exception as e:
            logger.error(f"Error adding connection: {e}")
            return False

    def connect_all(self) -> Dict[str, bool]:
        """Connect all brokers"""
        results = {}
        for account_id, connection in self.connections.items():
            try:
                results[account_id] = connection.connect()
            except Exception as e:
                logger.error(f"Error connecting {account_id}: {e}")
                results[account_id] = False
        return results

    def disconnect_all(self) -> Dict[str, bool]:
        """Disconnect all brokers"""
        results = {}
        for account_id, connection in self.connections.items():
            try:
                results[account_id] = connection.disconnect()
            except Exception as e:
                logger.error(f"Error disconnecting {account_id}: {e}")
                results[account_id] = False
        return results

    def get_all_positions(self) -> Dict[str, List[Dict]]:
        """Get positions from all brokers"""
        results = {}
        for account_id, connection in self.connections.items():
            if connection.connected:
                try:
                    results[account_id] = connection.get_positions()
                except Exception as e:
                    logger.error(f"Error getting positions for {account_id}: {e}")
                    results[account_id] = []
        return results

    def get_all_trades(self) -> Dict[str, List[Dict]]:
        """Get trades from all brokers"""
        results = {}
        for account_id, connection in self.connections.items():
            if connection.connected:
                try:
                    results[account_id] = connection.get_trades()
                except Exception as e:
                    logger.error(f"Error getting trades for {account_id}: {e}")
                    results[account_id] = []
        return results

    def get_consolidated_summary(self) -> Dict:
        """Get summary across all accounts"""
        total_balance = 0
        total_equity = 0
        total_positions = 0
        total_profit = 0
        accounts_summary = {}

        for account_id, connection in self.connections.items():
            if connection.connected and connection.account_info:
                info = connection.account_info
                accounts_summary[account_id] = {
                    'balance': info['balance'],
                    'equity': info['equity'],
                    'margin': info['margin'],
                }
                total_balance += info['balance']
                total_equity += info['equity']

            positions = connection.get_positions()
            total_positions += len(positions)
            for pos in positions:
                total_profit += pos['pnl']

        return {
            'totalBalance': total_balance,
            'totalEquity': total_equity,
            'totalPositions': total_positions,
            'totalProfit': total_profit,
            'accounts': accounts_summary,
            'timestamp': datetime.now().isoformat(),
        }


# Initialize broker manager
broker_manager = BrokerManager()


def canonicalize_broker_name(broker_name: str) -> str:
    normalized = (broker_name or '').strip().lower()
    if 'exness' in normalized:
        return 'Exness'
    if normalized in {'fxcm', 'fxm'}:
        return 'FXCM'
    if normalized in {'xm', 'xm global'}:
        return 'XM Global' if normalized == 'xm global' else 'XM'

    broker_map = {
        'binance': 'Binance',
        'oanda': 'OANDA',
        'exness': 'Exness',
        'fxcm': 'FXCM',
        'fxm': 'FXCM',
    }
    return broker_map.get(normalized, broker_name)


def is_mt5_broker_name(broker_name: str) -> bool:
    return canonicalize_broker_name(broker_name) in ['Exness']


def get_mt5_config_for_broker(broker_name: str) -> Dict:
    normalized = canonicalize_broker_name(broker_name)
    if normalized == 'Exness':
        return get_exness_mt5_config()
    return get_exness_mt5_config()


def get_balance_cache_key(broker_name: str, account_id) -> str:
    """Generate consistent cache key for balance cache with auto-detection
    
    This function implements TWO-LAYER BROKER DETECTION:
    1. First, attempts to auto-detect the real broker based on account number
       (maps 'MetaTrader 5' → 'Exness' for known Exness accounts)
    2. Falls back to normalizing the provided broker_name if not in auto-detection map
    
    Used by BOTH bot connection AND balance endpoint to ensure key format matches.
    This prevents cache misses due to key format discrepancies.
    
    Args:
        broker_name: Raw broker name from database (e.g., 'Exness', 'MetaTrader 5', 'XM Global', 'Binance')
        account_id: Account number (int, or string convertible to int)
    
    Returns:
        Consistent cache key: "Exness:298997455" or "Binance:z9e8s9v7..."
        
    Example:
        # Bot code (sends raw account number):
        get_balance_cache_key('Exness', 298997455)  → 'Exness:298997455'
        
        # Endpoint code (gets broker_name from DB which might be 'MetaTrader 5'):
        get_balance_cache_key('MetaTrader 5', 298997455)  → 'Exness:298997455' ✅ Matches!
    """
    
    # ==================== LAYER 1: ACCOUNT-BASED AUTO-DETECTION ====================
    # Only apply auto-detection when broker_name is generic (e.g., 'MetaTrader 5', 'MT5')
    # Do NOT override when broker_name is already specific (Exness, XM, etc.)
    ACCOUNT_BROKER_MAPPING = {
        # Exness DEMO - known account that may be stored as 'MetaTrader 5' in DB
        '298997455': 'Exness',
        298997455: 'Exness',
        # Exness LIVE - known account that may be stored as 'MetaTrader 5' in DB
        '295677214': 'Exness',
        295677214: 'Exness',
        # Add more known accounts here as needed
    }
    
    # Normalize account for lookup
    try:
        account_str = str(int(account_id))
    except (ValueError, TypeError):
        account_str = str(account_id)
    
    # Only use auto-detection if the broker name is generic (MetaTrader 5, MT5, etc.)
    # If the broker name is already specific (Exness, XM, Binance), use it as-is
    normalized_broker = canonicalize_broker_name(broker_name)
    generic_broker_names = {'MetaTrader5', 'MetaTrader 5', 'MT5'}
    
    if normalized_broker in generic_broker_names or broker_name in generic_broker_names:
        # Check if this account number has a known broker mapping
        if account_str in ACCOUNT_BROKER_MAPPING:
            real_broker = ACCOUNT_BROKER_MAPPING[account_str]
            return f"{real_broker}:{account_str}"
        if account_id in ACCOUNT_BROKER_MAPPING:
            real_broker = ACCOUNT_BROKER_MAPPING[account_id]
            return f"{real_broker}:{account_str}"
    
    # ==================== LAYER 2: BROKER NAME NORMALIZATION ====================
    # Use the provided broker name (normalized) for the cache key
    cache_key = f"{normalized_broker}:{account_str}"
    return cache_key


def persist_account_snapshot(
    broker_name: str,
    account_number,
    account_info: Dict,
    credential_id: str = None,
    user_id: str = None,
) -> None:
    """Persist a live account snapshot to in-memory and SQLite caches."""
    if not account_info or account_number in [None, '']:
        return

    normalized_broker = canonicalize_broker_name(broker_name)
    resolved_account_number = str(account_info.get('accountNumber') or account_number)
    balance = float(account_info.get('balance', 0) or 0)
    equity = float(account_info.get('equity', balance) or balance)
    margin = float(account_info.get('margin', 0) or 0)
    margin_free = float(account_info.get('marginFree', account_info.get('margin_free', balance)) or balance)
    margin_level = float(account_info.get('margin_level', account_info.get('marginLevel', 0)) or 0)
    profit = float(account_info.get('total_pl', account_info.get('profit', account_info.get('floatingPL', 0))) or 0)
    currency = str(account_info.get('currency', account_info.get('displayCurrency', 'USD')) or 'USD').upper()
    snapshot_time = datetime.now().isoformat()

    try:
        with balance_cache_lock:
            cache_key = get_balance_cache_key(normalized_broker, resolved_account_number)
            balance_cache[cache_key] = {
                'balance': balance,
                'equity': equity,
                'margin': margin,
                'marginFree': margin_free,
                'margin_level': margin_level,
                'total_pl': profit,
                'currency': currency,
                'timestamp': time.time(),
            }
        logger.info(f"💾 Persisted balance cache for {cache_key}: {balance:.2f} {currency}")
    except Exception as exc:
        logger.warning(f"Could not persist in-memory balance cache for {normalized_broker} {resolved_account_number}: {exc}")

    persist_target = credential_id or f"{user_id or 'unknown'}:{normalized_broker}:{resolved_account_number}"
    snapshot_signature = (
        round(balance, 2),
        round(equity, 2),
        round(margin_free, 2),
        round(margin, 2),
        round(margin_level, 2),
        round(profit, 2),
        currency,
    )
    now_ts = time.time()
    with recent_balance_db_writes_lock:
        last_write = recent_balance_db_writes.get(persist_target)
        if last_write:
            last_signature = last_write.get('signature')
            last_ts = float(last_write.get('timestamp', 0))
            if last_signature == snapshot_signature and (now_ts - last_ts) < BALANCE_SNAPSHOT_DB_WRITE_MIN_INTERVAL:
                return

    try:
        conn = get_db_connection()
        cursor = conn.cursor()
        params = [
            balance,
            equity,
            margin_free,
            margin,
            margin_level,
            profit,
            currency,
            snapshot_time,
            snapshot_time,
        ]
        query = '''
            UPDATE broker_credentials
            SET cached_balance = ?, cached_equity = ?, cached_margin_free = ?,
                cached_margin = ?, cached_margin_level = ?, cached_profit = ?,
                account_currency = ?, last_update = ?, updated_at = ?
        '''

        if credential_id:
            query += ' WHERE credential_id = ?'
            params.append(credential_id)
        elif user_id:
            query += ' WHERE user_id = ? AND broker_name = ? AND account_number = ?'
            params.extend([user_id, normalized_broker, resolved_account_number])
        else:
            conn.close()
            return

        cursor.execute(query, tuple(params))
        conn.commit()
        conn.close()
        with recent_balance_db_writes_lock:
            recent_balance_db_writes[persist_target] = {
                'signature': snapshot_signature,
                'timestamp': now_ts,
            }
    except Exception as exc:
        logger.warning(f"Could not persist SQLite balance cache for {normalized_broker} {resolved_account_number}: {exc}")


def read_active_mt5_account_snapshot(
    broker_name: str,
    account_number,
    credential_id: str = None,
    user_id: str = None,
) -> Optional[Dict[str, Any]]:
    """Return a snapshot only when the current MT5 session is already on the requested account."""
    normalized_account = str(account_number or '').strip()
    if not normalized_account:
        return None

    try:
        import MetaTrader5 as mt5

        active_info = mt5.account_info()
        if active_info is None or str(getattr(active_info, 'login', '')) != normalized_account:
            return None

        snapshot = {
            'accountNumber': normalized_account,
            'balance': float(getattr(active_info, 'balance', 0) or 0),
            'equity': float(getattr(active_info, 'equity', getattr(active_info, 'balance', 0)) or 0),
            'marginFree': float(getattr(active_info, 'margin_free', 0) or 0),
            'margin': float(getattr(active_info, 'margin', 0) or 0),
            'margin_level': float(getattr(active_info, 'margin_level', 0) or 0),
            'total_pl': float(getattr(active_info, 'profit', 0) or 0),
            'profit': float(getattr(active_info, 'profit', 0) or 0),
            'currency': str(getattr(active_info, 'currency', 'USD') or 'USD').upper(),
            'broker': canonicalize_broker_name(broker_name),
            'server': getattr(active_info, 'server', None),
            'leverage': getattr(active_info, 'leverage', None),
            'dataSource': 'active_mt5_session',
        }
        persist_account_snapshot(
            broker_name,
            normalized_account,
            snapshot,
            credential_id=credential_id,
            user_id=user_id,
        )
        return snapshot
    except Exception as exc:
        logger.warning(f"Could not read active MT5 session for {broker_name} {normalized_account}: {exc}")
        return None

