@app.route('/api/admin/users/create', methods=['POST'])
@require_api_key
def create_user():
    """Create a new user"""
    try:
        data = request.get_json()
        user_id = str(uuid.uuid4())
        referral_code = ''.join(random.choices(string.ascii_uppercase + string.digits, k=8))
        
        conn = get_db_connection()
        cursor = conn.cursor()
        referrer_id = _get_default_signup_referrer_id(cursor)
        
        cursor.execute('''
            INSERT INTO users 
            (user_id, email, name, referrer_id, referral_code, created_at)
            VALUES (?, ?, ?, ?, ?, ?)
        ''', (
            user_id,
            data.get('email'),
            data.get('name'),
            referrer_id,
            referral_code,
            datetime.now().isoformat()
        ))

        if referrer_id:
            cursor.execute('''
                INSERT INTO referrals (referral_id, referrer_id, referred_user_id, created_at)
                VALUES (?, ?, ?, ?)
            ''', (str(uuid.uuid4()), referrer_id, user_id, datetime.now().isoformat()))
        
        conn.commit()
        conn.close()
        
        logger.info(f"✅ User created: {data.get('email')}")
        
        return jsonify({
            'success': True,
            'user_id': user_id,
            'referral_code': referral_code,
            'message': f"User {data.get('name')} created successfully"
        }), 201
    
    except Exception as e:
        logger.error(f"Error creating user: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/users/<user_id>', methods=['GET'])
@require_api_key
def get_user(user_id):
    """Get user details"""
    try:
        conn = get_db_connection()
        cursor = conn.cursor()
        
        cursor.execute('SELECT * FROM users WHERE user_id = ?', (user_id,))
        user = dict(cursor.fetchone() or {})
        
        # Get user accounts
        cursor.execute('SELECT * FROM user_accounts WHERE user_id = ?', (user_id,))
        accounts = [dict(row) for row in cursor.fetchall()]
        
        # Get user trading settings
        cursor.execute('SELECT * FROM user_trading_settings WHERE user_id = ?', (user_id,))
        settings = dict(cursor.fetchone() or {})
        
        conn.close()
        
        return jsonify({
            'success': True,
            'user': user,
            'accounts': accounts,
            'settings': settings
        }), 200
    
    except Exception as e:
        logger.error(f"Error getting user: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


