# ==================== DEMO/LIVE MODE SWITCHING ====================

def ensure_user_preferences_table(cursor):
    cursor.execute('''
        CREATE TABLE IF NOT EXISTS user_preferences (
            user_id TEXT PRIMARY KEY,
            trading_mode TEXT DEFAULT 'DEMO',
            live_account TEXT,
            live_server TEXT,
            updated_at TEXT
        )
    ''')


def ensure_user_risk_settings_table(cursor):
    cursor.execute('''
        CREATE TABLE IF NOT EXISTS user_risk_settings (
            user_id TEXT PRIMARY KEY,
            risk_percent REAL DEFAULT 2.0,
            max_open_trades INTEGER DEFAULT 3,
            max_drawdown_percent REAL DEFAULT 20.0,
            updated_at TEXT
        )
    ''')


def get_user_risk_settings(cursor, user_id: str) -> Dict[str, Any]:
    ensure_user_risk_settings_table(cursor)
    cursor.execute(
        '''
        SELECT risk_percent, max_open_trades, max_drawdown_percent, updated_at
        FROM user_risk_settings
        WHERE user_id = ?
        ''',
        (user_id,),
    )
    row = cursor.fetchone()
    if row:
        return {
            'risk_percent': float(row['risk_percent'] or 2.0),
            'max_open_trades': int(row['max_open_trades'] or 3),
            'max_drawdown_percent': float(row['max_drawdown_percent'] or 20.0),
            'updated_at': row['updated_at'],
        }

    return {
        'risk_percent': 2.0,
        'max_open_trades': 3,
        'max_drawdown_percent': 20.0,
        'updated_at': None,
    }


def get_preferred_mode_credential(cursor, user_id: str, mode: str, preferred_broker: str = None, preferred_account: str = None):
    desired_live = 1 if mode == 'LIVE' else 0
    query = '''
        SELECT credential_id, broker_name, account_number, server, is_live, updated_at, created_at
        FROM broker_credentials
        WHERE user_id = ? AND is_active = 1
    '''
    params = [user_id]

    if preferred_broker:
        query += ' AND broker_name = ?'
        params.append(canonicalize_broker_name(preferred_broker))

    if preferred_account:
        query += ' AND account_number = ?'
        params.append(str(preferred_account))

    query += '''
        ORDER BY
            CASE
                WHEN broker_name = 'Exness' THEN 0
                WHEN broker_name IN ('XM', 'XM Global', 'MetaQuotes', 'MetaTrader 5', 'PXBT') THEN 1
                ELSE 2
            END,
            updated_at DESC,
            created_at DESC
    '''

    cursor.execute(query, tuple(params))
    rows = [dict(row) for row in cursor.fetchall()]

    filtered_rows = [
        row for row in rows
        if int(normalize_mt5_is_live_flag(row.get('broker_name'), row.get('is_live'), row.get('server'))) == desired_live
    ]

    if filtered_rows:
        return filtered_rows[0]
    return None


def warm_trading_mode_credential(user_id: str, credential_id: str, mode: str):
    broker_type, broker_conn = get_broker_connection(credential_id, user_id, bot_id=f'mode-switch:{mode.lower()}')
    if broker_conn is None or not hasattr(broker_conn, 'connected') or not broker_conn.connected:
        return {
            'connected': False,
            'broker_type': broker_type,
            'error': broker_conn if isinstance(broker_conn, str) else (broker_type or 'Connection failed'),
            'account_info': {},
        }

    account_info = {}
    try:
        fetched_account_info = broker_conn.get_account_info()
        if isinstance(fetched_account_info, dict):
            account_info = fetched_account_info
            persist_account_snapshot(
                broker_conn.credentials.get('broker') or broker_type,
                broker_conn.credentials.get('account') or broker_conn.credentials.get('account_number'),
                account_info,
                credential_id=credential_id,
                user_id=user_id,
            )
    except Exception as exc:
        logger.warning(f"Could not fetch account info while warming trading mode for credential {credential_id}: {exc}")

    return {
        'connected': True,
        'broker_type': broker_type,
        'account_info': account_info,
        'error': None,
    }


def apply_user_trading_mode_to_active_bots(user_id: str, mode: str) -> Dict[str, Any]:
    normalized_mode = str(mode or 'DEMO').upper()
    desired_is_live = normalized_mode == 'LIVE'
    updated_bot_ids: List[str] = []
    skipped_bot_ids: List[str] = []

    for bot_id, bot_config in list(active_bots.items()):
        if bot_config.get('user_id') != user_id:
            continue

        broker_name = canonicalize_broker_name(
            bot_config.get('broker_type') or bot_config.get('brokerName') or bot_config.get('broker') or ''
        )
        resolved_credential = _resolve_active_broker_credential_for_bot(
            user_id,
            broker_name,
            bot_config.get('accountNumber') or bot_config.get('account_number') or bot_config.get('account'),
            normalized_mode.lower(),
            bot_config.get('credentialId'),
        )
        if not resolved_credential:
            skipped_bot_ids.append(bot_id)
            continue

        previous_conn = bot_config.get('broker_conn')
        if previous_conn is not None and hasattr(previous_conn, 'disconnect'):
            try:
                previous_conn.disconnect()
            except Exception:
                pass

        resolved_credential_id = str(resolved_credential.get('credential_id') or '').strip()
        if resolved_credential_id:
            bot_config['credentialId'] = resolved_credential_id
            _sync_bot_credential_mapping(bot_id, user_id, resolved_credential_id)

        resolved_account_number = str(resolved_credential.get('account_number') or '').strip()
        if resolved_account_number:
            bot_config['accountNumber'] = resolved_account_number
            bot_config['account_number'] = resolved_account_number

        bot_config['mode'] = normalized_mode.lower()
        bot_config['is_live'] = desired_is_live
        bot_config['broker_conn'] = None
        updated_bot_ids.append(bot_id)

        try:
            persist_bot_runtime_state(bot_id, force=True)
        except Exception as exc:
            logger.warning(f"Could not persist mode-switch runtime state for bot {bot_id}: {exc}")

    conn = None
    try:
        conn = get_db_connection()
        cursor = conn.cursor()
        cursor.execute(
            'UPDATE user_bots SET is_live = ?, updated_at = ? WHERE user_id = ?',
            (1 if desired_is_live else 0, datetime.now().isoformat(), user_id),
        )
        conn.commit()
    except Exception as exc:
        logger.warning(f"Could not persist trading mode for user {user_id} bots: {exc}")
    finally:
        if conn:
            try:
                conn.close()
            except Exception:
                pass

    return {
        'updated_bot_ids': updated_bot_ids,
        'skipped_bot_ids': skipped_bot_ids,
    }


def get_user_trading_mode_value(user_id: str, fallback_mode: str = 'DEMO') -> str:
    """Return the persisted user trading mode, defaulting to the provided fallback."""
    try:
        conn = get_db_connection()
        cursor = conn.cursor()
        ensure_user_preferences_table(cursor)
        cursor.execute(
            '''
            SELECT trading_mode
            FROM user_preferences
            WHERE user_id = ?
            ''',
            (user_id,),
        )
        row = cursor.fetchone()
        conn.close()
        return (row['trading_mode'] if row and row['trading_mode'] else fallback_mode).upper()
    except Exception as exc:
        logger.warning(f"Could not read trading mode for user {user_id}: {exc}")
        return str(fallback_mode or 'DEMO').upper()

