def add_account():
    """Add a new trading account"""
    data = request.json

    account_id = data.get('accountId')
    broker_type = data.get('brokerType')
    credentials = data.get('credentials')

    if not all([account_id, broker_type]):
        return jsonify({'success': False, 'error': 'Missing parameters'}), 400

    try:
        broker = BrokerType(broker_type)
        # Use provided credentials or fall back to MT5_CONFIG
        creds = credentials if credentials else MT5_CONFIG
        success = broker_manager.add_connection(account_id, broker, creds)

        if success:
            return jsonify({'success': True, 'accountId': account_id})
        else:
            return jsonify({'success': False, 'error': 'Failed to add account'}), 400
    except ValueError:
        return jsonify({'success': False, 'error': f'Unknown broker type: {broker_type}'}), 400


@app.route('/api/accounts/connect/<account_id>', methods=['POST'])
def connect_account(account_id):
    """Connect to a specific account"""
    if account_id not in broker_manager.connections:
        return jsonify({'success': False, 'error': 'Account not found'}), 404

    connection = broker_manager.connections[account_id]
    
    try:
        success = connection.connect()
        
        if success:
            return jsonify({
                'success': True,
                'accountId': account_id,
                'broker': connection.broker_type.value,
            })
        else:
            return jsonify({'success': False, 'error': 'Connection failed'}), 500
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/accounts/list', methods=['GET'])
def list_accounts():
    """List all configured accounts"""
    accounts = []
    for account_id, connection in broker_manager.connections.items():
        accounts.append({
            'accountId': account_id,
            'broker': connection.broker_type.value,
            'connected': connection.connected,
            'info': connection.account_info,
        })


    return jsonify({'accounts': accounts})


@app.route('/api/accounts/balances', methods=['GET'])
@require_session
def get_account_balances():
    """Get account balances from all user's brokers (Exness, XM, Binance, etc.)
    
    Returns unified account summary with balances from all integrated brokers.
    This is what displays in the dashboard showing real broker balances.
    
    IMPORTANT: Uses a 5-second timeout per broker to prevent dashboard reload loops.
    If a broker connection times out, returns cached balance from last successful fetch.
    """
    import signal
    import threading
    global balance_cache, balance_cache_lock
    
    def timeout_handler():
        """Handler for connection timeout"""
        pass

    def _cache_snapshot_age_seconds(snapshot_value):
        """Return age in seconds for either epoch timestamps or ISO datetime strings."""
        if snapshot_value in [None, '']:
            return None
        try:
            if isinstance(snapshot_value, (int, float)):
                return max(0.0, time.time() - float(snapshot_value))
            parsed = datetime.fromisoformat(str(snapshot_value))
            return max(0.0, (datetime.now() - parsed).total_seconds())
        except Exception:
            return None

    try:
        user_id = request.user_id
        conn = get_db_connection()
        cursor = conn.cursor()
        requested_mode = str(request.args.get('mode') or 'ALL').strip().upper()
        if requested_mode not in ['LIVE', 'DEMO', 'ALL', '']:
            requested_mode = 'ALL'
        
        # Get active broker credentials for this user, optionally scoped to one mode.
        credentials_query = '''
            SELECT credential_id, broker_name, account_number, is_live, api_key, username, password, server, account_currency, mt5_terminal_path,
                   updated_at, created_at
            FROM broker_credentials 
            WHERE user_id = ? AND is_active = 1
        '''
        credentials_params = [user_id]
        if requested_mode in ['LIVE', 'DEMO']:
            credentials_query += ' AND is_live = ?'
            credentials_params.append(1 if requested_mode == 'LIVE' else 0)
        credentials_query += ' ORDER BY COALESCE(updated_at, created_at, \'\') DESC, credential_id DESC'
        cursor.execute(credentials_query, credentials_params)

        raw_credentials = [dict(row) for row in cursor.fetchall()]
        credentials, duplicate_credential_ids = dedupe_active_broker_credentials(raw_credentials)
        if duplicate_credential_ids:
            logger.info(
                f"Detected {len(duplicate_credential_ids)} duplicate/incomplete broker credential(s) for user {user_id} while loading account balances; leaving database unchanged during polling."
            )
        
        # CRITICAL FIX: Fetch cached balances for fallback on timeout
        cached_query = '''
            SELECT credential_id, cached_balance, cached_equity, cached_margin_free, 
                   cached_margin, cached_margin_level, cached_profit, last_update
            FROM broker_credentials 
            WHERE user_id = ? AND is_active = 1
        '''
        cached_params = [user_id]
        if requested_mode in ['LIVE', 'DEMO']:
            cached_query += ' AND is_live = ?'
            cached_params.append(1 if requested_mode == 'LIVE' else 0)
        cursor.execute(cached_query, cached_params)
        
        cached_data = {row['credential_id']: dict(row) for row in cursor.fetchall()}
        conn.close()
        
        accounts_summary = {
            'success': True,
            'accounts': [],
            'totalBalance': 0,
            'totalEquity': 0,
            'totalByCurrency': {},  # e.g. {'USD': 168199.26, 'ZAR': 180.00}
            'brokers': {},  # Grouped by broker: {Exness: {...}, XM: {...}, Binance: {...}}
        }
        
        # Fetch balance from each broker with timeout protection
        for cred in credentials:
            broker_name = canonicalize_broker_name(cred['broker_name'])
            account_num = str(cred['account_number'] or '').strip()
            is_live = int(normalize_mt5_is_live_flag(broker_name, cred['is_live'], cred.get('server')))
            mode = 'Live' if is_live else 'Demo'

            try:
                bot_conn = get_db_connection()
                bot_cursor = bot_conn.cursor()
                bot_cursor.execute('''
                    SELECT COUNT(*) as count FROM user_bots
                    WHERE user_id = ? AND broker_account_id = ? AND status = 'active' AND enabled = 1
                ''', (user_id, account_num))
                active_bot_count = bot_cursor.fetchone()['count']
                bot_conn.close()
            except Exception:
                active_bot_count = 0

            # XM has been retired from the product UI; skip it from balance payloads.
            if broker_name in ['XM', 'XM Global']:
                logger.info(f"ℹ️ Skipping retired broker in balances endpoint: {broker_name} {account_num}")
                continue

            # GET ACTUAL ACCOUNT CURRENCY from database (demo USD vs live ZAR)
            account_currency = cred.get('account_currency', 'USD').upper()
            display_currency = _resolve_display_currency_for_mode(mode, account_currency)
            
            account_info = None
            error_msg = None
            timed_out = False
            allow_cached_balance_fallback = True
            failed_auth_status = get_failed_auth_status(account_num) if broker_name in ['Exness', 'XM', 'XM Global', 'PXBT'] else None
            
            try:
                if broker_name in ['Exness', 'XM', 'XM Global', 'PXBT']:
                    account_info = read_active_mt5_account_snapshot(
                        broker_name,
                        account_num,
                        credential_id=cred['credential_id'],
                        user_id=user_id,
                    )
                    if account_info:
                        error_msg = None
                        logger.info(
                            f"✅ Balance: using active MT5 session for {broker_name} {account_num} -> "
                            f"{float(account_info.get('balance', 0) or 0):.2f} {account_info.get('currency', 'USD')}"
                        )
                    else:
                        refresh_result = [None]

                        def try_fast_mt5_refresh():
                            mt5_conn = None
                            try:
                                mt5_conn = MT5Connection({
                                    'broker': broker_name,
                                    'account': int(account_num),
                                    'account_number': account_num,
                                    'password': cred.get('password'),
                                    'server': cred.get('server'),
                                    'is_live': bool(cred.get('is_live')),
                                    'path': cred.get('mt5_terminal_path') or None,
                                    'is_balance_check': True,
                                    'lock_timeout': 1.5,
                                })
                                if mt5_conn.connect():
                                    refresh_result[0] = mt5_conn.get_account_info()
                            except Exception as refresh_exc:
                                logger.debug(f"Fast MT5 balance refresh failed for {broker_name} {account_num}: {refresh_exc}")
                            finally:
                                if mt5_conn and hasattr(mt5_conn, 'disconnect'):
                                    try:
                                        mt5_conn.disconnect()
                                    except Exception:
                                        pass

                        refresh_thread = threading.Thread(target=try_fast_mt5_refresh, daemon=True)
                        refresh_thread.start()
                        refresh_thread.join(timeout=6)

                        if not refresh_thread.is_alive() and refresh_result[0]:
                            account_info = refresh_result[0]
                            account_info['accountNumber'] = account_info.get('accountNumber') or account_num
                            account_info['marginFree'] = account_info.get('marginFree', account_info.get('margin_free', 0))
                            account_info['total_pl'] = account_info.get('total_pl', account_info.get('profit', 0))
                            account_info['displayCurrency'] = account_info.get('currency', display_currency)
                            error_msg = None
                            logger.info(
                                f"✅ Balance: refreshed MT5 snapshot for {broker_name} {account_num} -> "
                                f"{float(account_info.get('balance', 0) or 0):.2f} {account_info.get('currency', 'USD')}"
                            )
                        else:
                    # DISCONNECTED MODE: Do NOT call MT5 from the balance endpoint unless cache is empty and no bots are running.
                            logger.info(f"ℹ️ Balance: {broker_name} {account_num} ({account_currency}) — using cache only (MT5 disconnected in balance endpoint)")
                            error_msg = f"Using cached balance ({account_currency}) — MT5 reads handled by trading loop"
                            cache_key = get_balance_cache_key(broker_name, account_num)
                            cache_empty = True
                            with balance_cache_lock:
                                if cache_key in balance_cache and balance_cache[cache_key].get('balance', 0) > 0:
                                    cache_empty = False

                            # Diagnostics: Log cache status
                            # Suppress repeated ZAR diagnostic warnings during polling - only show once per hour
                            cache_diag_key = f"zar_cache_warning_{broker_name}_{account_num}"
                            last_zar_warning = getattr(get_account_balances, '_last_warnings', {}).get(cache_diag_key, 0)
                            now_unix = time.time()

                            if cache_empty:
                                # Log as info only; SQLite fallback may still provide a valid cached balance.
                                if now_unix - last_zar_warning > 3600:
                                    logger.info(
                                        f"[DIAGNOSTIC] In-memory cache empty for {broker_name} {account_num}; will evaluate SQLite cache fallback."
                                    )
                                    if not hasattr(get_account_balances, '_last_warnings'):
                                        get_account_balances._last_warnings = {}
                                    get_account_balances._last_warnings[cache_diag_key] = now_unix
                            else:
                                # Show positive cache hit once per hour only
                                if now_unix - last_zar_warning > 3600:
                                    logger.info(f"[DIAGNOSTIC] Cached balance present for {broker_name} {account_num}.")
                                    if not hasattr(get_account_balances, '_last_warnings'):
                                        get_account_balances._last_warnings = {}
                                    get_account_balances._last_warnings[cache_diag_key] = now_unix
                
                elif broker_name == 'Binance':
                    # Connect to Binance API with timeout
                    try:
                        binance_conn = BinanceConnection({
                            'api_key': cred['api_key'],
                            'api_secret': cred['password'],
                            'account_number': account_num,
                            'server': cred.get('server') or 'spot',
                            'is_live': is_live,
                        })
                        result = [None]
                        def connect_binance():
                            if binance_conn.connect():
                                balance_info = binance_conn.account_info or binance_conn.get_account_info() or {}
                                result[0] = {
                                    'accountNumber': account_num,
                                    'balance': balance_info.get('balance', 0),
                                    'equity': balance_info.get('equity', balance_info.get('balance', 0)),
                                    'marginFree': balance_info.get('marginFree', balance_info.get('margin_free', 0)),
                                    'currency': balance_info.get('currency', 'USDT'),
                                    'displayCurrency': balance_info.get('currency', 'USDT'),
                                    'broker': 'Binance',
                                    'leverage': 1,
                                }
                                persist_account_snapshot(
                                    'Binance',
                                    account_num,
                                    result[0],
                                    credential_id=cred.get('credential_id'),
                                    user_id=user_id,
                                )
                            binance_conn.disconnect()
                        
                        thread = threading.Thread(target=connect_binance, daemon=True)
                        thread.start()
                        # Binance connect() performs a signed account request and may retry on demo/testnet hosts.
                        # Give it enough time to complete before declaring the balance path timed out.
                        thread.join(timeout=35)
                        
                        if thread.is_alive():
                            logger.warning(f"Binance balance fetch timed out for {account_num}")
                            timed_out = True
                            error_msg = "Connection timeout"
                        else:
                            account_info = result[0]
                            if not account_info:
                                error_msg = "Failed to connect to Binance API"
                    except Exception as e:
                        logger.warning(f"Binance balance error: {e}")
                        error_msg = str(e)

                elif broker_name == 'FXCM':
                    try:
                        cached_fxcm_snapshot = _get_cached_fxcm_endpoint_snapshot(cred['credential_id'])
                        snapshot_account_info = cached_fxcm_snapshot.get('accountInfo') if cached_fxcm_snapshot else None
                        snapshot_account_number = str(
                            (snapshot_account_info or {}).get('accountNumber')
                            or (snapshot_account_info or {}).get('account_id')
                            or ''
                        ).strip()
                        if (
                            cached_fxcm_snapshot
                            and isinstance(snapshot_account_info, dict)
                            and snapshot_account_info
                            and (not snapshot_account_number or snapshot_account_number == account_num)
                        ):
                            account_info = dict(cached_fxcm_snapshot['accountInfo'])
                            account_info['accountNumber'] = account_info.get('accountNumber') or account_num
                            account_info['marginFree'] = account_info.get('marginFree', account_info.get('margin_free', 0))
                            account_info['total_pl'] = account_info.get('profit', account_info.get('total_pl', 0))
                            account_info['displayCurrency'] = account_info.get('currency', display_currency)
                            error_msg = None
                        elif cached_fxcm_snapshot and snapshot_account_number and snapshot_account_number != account_num:
                            logger.warning(
                                f"Ignoring mismatched FXCM snapshot for credential {cred['credential_id']}: requested {account_num}, snapshot has {snapshot_account_number}"
                            )
                        else:
                            fxcm_conn = FXCMConnection({
                                'api_key': cred.get('api_key'),
                                'username': cred.get('username'),
                                'password': cred.get('password'),
                                'account_number': account_num,
                                'server': cred.get('server'),
                                'connection': 'Real' if bool(cred['is_live']) else 'Demo',
                                'is_live': bool(cred['is_live']),
                                'credential_id': cred['credential_id'],
                            })
                            if fxcm_conn.connect():
                                account_info = fxcm_conn.get_account_info()
                                if account_info:
                                    _store_fxcm_endpoint_snapshot(
                                        cred['credential_id'],
                                        account_info=account_info,
                                        data_source=account_info.get('dataSource', 'live') if isinstance(account_info, dict) else 'live',
                                    )
                                fxcm_conn.disconnect()
                            if account_info:
                                account_info['accountNumber'] = account_info.get('accountNumber') or account_num
                                account_info['marginFree'] = account_info.get('marginFree', account_info.get('margin_free', 0))
                                account_info['total_pl'] = account_info.get('profit', account_info.get('total_pl', 0))
                                account_info['displayCurrency'] = account_info.get('currency', display_currency)
                            if not account_info:
                                error_msg = fxcm_conn.last_error or 'Failed to connect to FXCM API'
                                allow_cached_balance_fallback = False
                    except Exception as e:
                        logger.warning(f"FXCM balance error: {e}")
                        error_msg = str(e)
                        allow_cached_balance_fallback = False

                elif broker_name == 'OANDA':
                    try:
                        oanda_conn = OANDAConnection({
                            'api_key': cred.get('api_key'),
                            'account_number': account_num,
                            'is_live': bool(cred['is_live']),
                        })
                        if oanda_conn.connect():
                            account_info = oanda_conn.get_account_info()
                            if account_info:
                                account_info['accountNumber'] = account_info.get('accountNumber') or account_num
                                account_info['marginFree'] = account_info.get('marginFree', account_info.get('margin_free', 0))
                                account_info['total_pl'] = account_info.get('profit', account_info.get('total_pl', 0))
                                account_info['displayCurrency'] = account_info.get('currency', display_currency)
                            oanda_conn.disconnect()
                        if not account_info:
                            error_msg = 'Failed to connect to OANDA API'
                    except Exception as e:
                        logger.warning(f"OANDA balance error: {e}")
                        error_msg = str(e)
                
                else:
                    # Generic MT5 fallback — also disconnected, use cache only
                    logger.info(f"ℹ️ Balance: {broker_name} {account_num} — using cache only (MT5 disconnected in balance endpoint)")
                    error_msg = "Using cached balance — MT5 reads handled by trading loop"
                
            except Exception as e:
                logger.warning(f"Error fetching balance from {broker_name} account {account_num}: {e}")
                error_msg = str(e)
            
            # Build account entry
            account_entry = {
                'credentialId': cred['credential_id'],
                'broker': broker_name,
                'accountNumber': account_num,
                'mode': mode,
                'is_live': is_live,  # Include is_live flag for frontend mode filtering
                'active_bots': active_bot_count,
                'last_update': datetime.now().isoformat() if account_info else cached_data.get(cred['credential_id'], {}).get('last_update'),
                'error': error_msg,
                'currency': display_currency,
                'displayCurrency': display_currency,
            }
            
            if account_info:
                # Fresh data from broker connection
                account_entry.update({
                    'balance': account_info.get('balance', 0),
                    'equity': account_info.get('equity', account_info.get('balance', 0)),
                    'marginFree': account_info.get('marginFree', 0),
                    'margin': account_info.get('margin', 0),
                    'margin_level': account_info.get('margin_level', 0),
                    'total_pl': account_info.get('total_pl', 0),
                    'currency': display_currency,
                    'displayCurrency': display_currency,
                    'connected': True,
                    'dataSource': 'live',
                })
                # Add to broker group
                if broker_name not in accounts_summary['brokers']:
                    accounts_summary['brokers'][broker_name] = []
                accounts_summary['brokers'][broker_name].append(account_entry)
                
                # Accumulate totals per currency (do NOT mix ZAR into USD total)
                _cur = account_entry.get('displayCurrency', account_entry.get('currency', 'USD')).upper()
                accounts_summary['totalByCurrency'].setdefault(_cur, 0.0)
                accounts_summary['totalByCurrency'][_cur] += account_entry['balance']
                accounts_summary['totalBalance'] += account_entry['balance']
                accounts_summary['totalEquity'] += account_entry['equity']
            else:
                # No live broker connection — use cached balance from
                # balance_cache (populated by bot trading loops) or DB cache.
                cache_key = get_balance_cache_key(broker_name, account_num)
                cached_balance = 0
                cached_equity = 0
                cached_margin = 0
                cached_margin_free = 0
                cached_margin_level = 0
                cached_profit = 0
                # USE database account_currency, NOT 'USD' default
                cached_currency = display_currency
                cache_source = 'not_connected'
                cache_snapshot_age = None
                sqlite_cache_used = False
                suppress_cached_balance = bool(is_live and failed_auth_status)
                if broker_name == 'FXCM' and not allow_cached_balance_fallback:
                    suppress_cached_balance = True
                    logger.warning(
                        f"🚫 Suppressing cached FXCM balance for {cache_key}: live read unavailable and no fresh FXCM snapshot was returned"
                    )

                if suppress_cached_balance:
                    logger.warning(
                        f"🚫 Suppressing cached balance for {cache_key}: account is in auth cooldown "
                        f"({failed_auth_status['remaining']:.0f}s remaining)"
                    )
                
                # Check in-memory cache (populated by bot trading loops)
                if not suppress_cached_balance:
                    with balance_cache_lock:
                        if cache_key in balance_cache:
                            cached_info = balance_cache[cache_key]
                            cache_snapshot_age = _cache_snapshot_age_seconds(cached_info.get('timestamp'))
                            # Enforce TTL: skip stale in-memory cache entries
                            ttl = BALANCE_CACHE_TTL_LIVE if is_live else BALANCE_CACHE_TTL_DEMO
                            if cache_snapshot_age is not None and cache_snapshot_age > ttl:
                                logger.info(f"⏳ Balance cache EXPIRED for {cache_key}: {cache_snapshot_age:.0f}s old (TTL={ttl}s)")
                            else:
                                cached_balance = cached_info.get('balance', 0)
                                cached_equity = cached_info.get('equity', cached_balance)
                                cached_margin = cached_info.get('margin', 0)
                                cached_margin_free = cached_info.get('marginFree', 0)
                                cached_margin_level = cached_info.get('margin_level', 0)
                                cached_profit = cached_info.get('total_pl', 0)
                                # Use cache currency if available, otherwise use database account_currency
                                if (not is_live) and 'currency' in cached_info:
                                    cached_currency = cached_info['currency']
                                cache_source = 'memory_cache'
                                logger.info(f"✅ Balance cache hit for {cache_key}: {cached_balance:.2f} {cached_currency} (age={cache_snapshot_age:.0f}s)")
                
                # Fallback: try SQLite cached_balance column
                if (not suppress_cached_balance) and cached_balance == 0 and cred['credential_id'] in cached_data:
                    cache = dict(cached_data[cred['credential_id']])
                    sqlite_age = _cache_snapshot_age_seconds(cache.get('last_update'))
                    sqlite_ttl = BALANCE_CACHE_TTL_LIVE if is_live else BALANCE_CACHE_TTL_DEMO
                    if sqlite_age is not None and sqlite_age > sqlite_ttl:
                        logger.info(f"⏳ SQLite cache EXPIRED for {cache_key}: {sqlite_age:.0f}s old (TTL={sqlite_ttl}s)")
                        cache_snapshot_age = sqlite_age
                    else:
                        cached_balance = cache.get('cached_balance', 0) or 0
                        cached_equity = cache.get('cached_equity', cached_balance) or 0
                        cached_margin = cache.get('cached_margin', 0) or 0
                        cached_margin_free = cache.get('cached_margin_free', 0) or 0
                        cached_margin_level = cache.get('cached_margin_level', 0) or 0
                        cached_profit = cache.get('cached_profit', 0) or 0
                        cache_source = 'sqlite_cache'
                        sqlite_cache_used = cached_balance > 0
                        cache_snapshot_age = sqlite_age
                        if cached_balance > 0:
                            logger.info(f"✅ SQLite cache hit for {cache_key}: {cached_balance:.2f} {cached_currency} (age={sqlite_age:.0f}s)")
                
                # If still $0 — account genuinely not connected / not funded
                if cached_balance == 0:
                    logger.info(f"ℹ️  {cache_key}: No cached balance — showing $0")
                
                # Staleness applies to ALL account types (live and demo)
                cache_is_stale = bool(
                    sqlite_cache_used and (
                        cache_snapshot_age is None or cache_snapshot_age > (BALANCE_CACHE_TTL_LIVE if is_live else BALANCE_CACHE_TTL_DEMO)
                    )
                )
                has_cached_data = cached_balance > 0 and not cache_is_stale
                account_entry.update({
                    'balance': float(cached_balance if has_cached_data else 0),
                    'equity': float(cached_equity if has_cached_data else 0),
                    'marginFree': float(cached_margin_free if has_cached_data else 0),
                    'margin': float(cached_margin if has_cached_data else 0),
                    'margin_level': float(cached_margin_level if has_cached_data else 0),
                    'total_pl': float(cached_profit if has_cached_data else 0),
                    'currency': cached_currency,
                    'displayCurrency': cached_currency,
                    'connected': bool(cache_source in ('memory_cache', 'sqlite_cache') and has_cached_data),
                    'dataSource': cache_source if has_cached_data else ('stale_cache' if cache_is_stale else 'not_connected'),
                    'cacheAgeSeconds': cache_snapshot_age,
                })
                if cache_is_stale:
                    account_entry['warning'] = 'Account balance snapshot is stale. Start a bot or reconnect to refresh.'
                    account_entry['lastKnownBalance'] = float(cached_balance)
                    account_entry['lastKnownEquity'] = float(cached_equity)
                    account_entry['lastKnownCurrency'] = cached_currency
                    logger.warning(
                        f"⚠️ {cache_key}: Hiding stale live SQLite snapshot ({cache_snapshot_age:.0f}s old) from connected balances"
                    )
                elif has_cached_data:
                    account_entry.pop('error', None)
                    if cache_source == 'sqlite_cache':
                        account_entry['warning'] = 'Showing cached snapshot only. Open this mode or run a bot to refresh the balance.'
                else:
                    if failed_auth_status and is_live:
                        account_entry['warning'] = (
                            f"Account authentication failed recently — cached balance hidden for "
                            f"{int(failed_auth_status['remaining'])}s"
                        )
                        account_entry['error'] = 'Authentication failed for this account. Check account number, password, and server.'
                    else:
                        account_entry['warning'] = 'Account not connected — balance will update when bot runs'
                
                # Add to broker group
                if broker_name not in accounts_summary['brokers']:
                    accounts_summary['brokers'][broker_name] = []
                accounts_summary['brokers'][broker_name].append(account_entry)
                
                # Accumulate totals from cache per currency (do NOT mix ZAR into USD total)
                _cur = account_entry.get('displayCurrency', account_entry.get('currency', 'USD')).upper()
                accounts_summary['totalByCurrency'].setdefault(_cur, 0.0)
                accounts_summary['totalByCurrency'][_cur] += account_entry['balance']
                accounts_summary['totalBalance'] += account_entry['balance']
                accounts_summary['totalEquity'] += account_entry['equity']
            
            accounts_summary['accounts'].append(account_entry)
        
        _by_cur_str = ', '.join(f"{c}: {v:.2f}" for c, v in accounts_summary['totalByCurrency'].items())
        logger.info(
            f"✅ Fetched account balances for user {user_id}: {len(accounts_summary['accounts'])} accounts "
            f"from {len(credentials)} unique credentials | {_by_cur_str}"
        )
        
        return jsonify(accounts_summary)
    
    except Exception as e:
        logger.error(f"Error getting account balance: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/accounts/<credential_id>/details', methods=['GET'])
@require_session
def get_account_details(credential_id):
    """Get detailed financial information for a specific broker account.
    
    Returns:
    - Account info (broker, account number, balance, equity)
    - Trade history with profits/losses
    - Withdrawal history
    - Commission/fee summary
    - Net profit calculation
    """
    try:
        user_id = request.user_id
        conn = get_db_connection()
        cursor = conn.cursor()
        
        # Verify credential belongs to this user
        cursor.execute('''
            SELECT credential_id, broker_name, account_number, is_live, server,
                   cached_balance, cached_equity, cached_margin_free, last_update
            FROM broker_credentials
            WHERE credential_id = ? AND user_id = ? AND is_active = 1
        ''', (credential_id, user_id))
        
        cred = cursor.fetchone()
        if not cred:
            conn.close()
            return jsonify({'success': False, 'error': 'Account not found'}), 404
        
        cred = dict(cred)
        broker_name = cred['broker_name']
        account_number = cred['account_number']
        
        # Get live balance/positions from the connected broker when available.
        balance = float(cred.get('cached_balance') or 0)
        equity = float(cred.get('cached_equity') or 0)
        margin_free = float(cred.get('cached_margin_free') or 0)
        live_account_info = None
        current_positions = []
        broker_recent_trades = []

        try:
            cached_fxcm_snapshot = _get_cached_fxcm_endpoint_snapshot(credential_id) if canonicalize_broker_name(broker_name) == 'FXCM' else None
            if cached_fxcm_snapshot:
                live_account_info = dict(cached_fxcm_snapshot.get('accountInfo') or {})
                current_positions = list(cached_fxcm_snapshot.get('positions') or [])
                broker_recent_trades = list(cached_fxcm_snapshot.get('recentTrades') or [])
            else:
                _, broker_conn = get_broker_connection(credential_id, user_id, bot_id=f'account-details:{credential_id}')
                if _is_live_broker_connection(broker_conn):
                    live_account_info = broker_conn.get_account_info() or {}
                    current_positions = broker_conn.get_positions() or []
                    broker_recent_trades = broker_conn.get_trades() or []
                    if canonicalize_broker_name(broker_name) == 'FXCM':
                        _store_fxcm_endpoint_snapshot(
                            credential_id,
                            account_info=live_account_info,
                            positions=current_positions,
                            trades=broker_recent_trades,
                            data_source=live_account_info.get('dataSource', 'live') if isinstance(live_account_info, dict) else 'live',
                        )
                    if hasattr(broker_conn, 'disconnect'):
                        broker_conn.disconnect()
                elif broker_conn:
                    logger.warning(f"Skipping invalid broker connection object for account details {credential_id}: {broker_conn}")

            if live_account_info:
                balance = float(live_account_info.get('balance', balance) or balance)
                equity = float(live_account_info.get('equity', equity) or equity)
                margin_free = float(
                    live_account_info.get('marginFree', live_account_info.get('margin_free', margin_free)) or margin_free
                )
        except Exception as e:
            logger.warning(f"Could not read live account details for {broker_name} {account_number}: {e}")

        # Get all trades for bots linked to this account
        cursor.execute('''
            SELECT t.trade_id, t.bot_id, t.symbol, t.order_type, t.volume,
                   t.price, t.profit, t.commission, t.swap, t.ticket,
                   t.time_open, t.time_close, t.status, t.created_at,
                   b.name as bot_name
            FROM trades t
            LEFT JOIN user_bots b ON t.bot_id = b.bot_id
            WHERE t.user_id = ? AND (
                b.broker_account_id = ? OR
                t.bot_id IN (
                    SELECT bc.bot_id FROM bot_credentials bc
                    WHERE bc.credential_id = ?
                )
            )
            ORDER BY t.created_at DESC
            LIMIT 200
        ''', (user_id, account_number, credential_id))
        
        trades = [dict(row) for row in cursor.fetchall()]
        
        # If no trades found via bot linkage, try broader match by user
        if not trades:
            cursor.execute('''
                SELECT t.trade_id, t.bot_id, t.symbol, t.order_type, t.volume,
                       t.price, t.profit, t.commission, t.swap, t.ticket,
                       t.time_open, t.time_close, t.status, t.created_at,
                       b.name as bot_name
                FROM trades t
                LEFT JOIN user_bots b ON t.bot_id = b.bot_id
                WHERE t.user_id = ?
                ORDER BY t.created_at DESC
                LIMIT 200
            ''', (user_id,))
            trades = [dict(row) for row in cursor.fetchall()]
        
        # Calculate trade stats
        total_profit = 0
        total_loss = 0
        total_commission = 0
        total_swap = 0
        open_trades = 0
        closed_trades = 0
        winning_trades = 0
        losing_trades = 0
        
        for trade in trades:
            profit = float(trade.get('profit') or 0)
            commission = float(trade.get('commission') or 0)
            swap = float(trade.get('swap') or 0)
            status = trade.get('status', 'open')
            
            total_commission += commission
            total_swap += swap
            
            if status == 'closed':
                closed_trades += 1
                if profit >= 0:
                    total_profit += profit
                    winning_trades += 1
                else:
                    total_loss += profit
                    losing_trades += 1
            else:
                open_trades += 1
                if profit >= 0:
                    total_profit += profit
                else:
                    total_loss += profit
        
        # Get withdrawal history for this account
        cursor.execute('''
            SELECT withdrawal_id, withdrawal_type, source_type,
                   profit_from_trades, commission_earned, total_amount,
                   fee, net_amount, status, withdrawal_method,
                   created_at, completed_at
            FROM exness_withdrawals
            WHERE user_id = ? AND broker_account_id = ?
            ORDER BY created_at DESC
            LIMIT 50
        ''', (user_id, account_number))
        
        withdrawals = [dict(row) for row in cursor.fetchall()]
        total_withdrawn = sum(float(w.get('net_amount') or w.get('total_amount') or 0) for w in withdrawals if w.get('status') == 'completed')
        
        # Get commission ledger entries
        cursor.execute('''
            SELECT entry_id, type, amount, payout_status, payout_date,
                   bot_id, trading_profit, created_at
            FROM commission_ledger
            WHERE user_id = ?
            ORDER BY created_at DESC
            LIMIT 50
        ''', (user_id,))
        
        commissions = [dict(row) for row in cursor.fetchall()]
        total_commission_earned = sum(float(c.get('amount') or 0) for c in commissions)
        
        # Get active bots count for this account
        cursor.execute('''
            SELECT COUNT(*) as count FROM user_bots
            WHERE user_id = ? AND broker_account_id = ? AND status = 'active' AND enabled = 1
        ''', (user_id, account_number))
        active_bots = cursor.fetchone()['count']
        
        # Get total bots count
        cursor.execute('''
            SELECT COUNT(*) as count FROM user_bots
            WHERE user_id = ? AND broker_account_id = ?
        ''', (user_id, account_number))
        total_bots = cursor.fetchone()['count']
        
        conn.close()
        
        # Calculate net profit
        gross_profit = total_profit + total_loss  # total_loss is negative
        net_profit = gross_profit + total_commission + total_swap  # commission and swap are usually negative
        win_rate = (winning_trades / max(winning_trades + losing_trades, 1)) * 100
        
        resolved_is_live = bool(normalize_mt5_is_live_flag(broker_name, cred.get('is_live'), cred.get('server')))

        detailed_account = {
            'credentialId': credential_id,
            'broker': broker_name,
            'accountNumber': account_number,
            'isLive': resolved_is_live,
            'mode': 'live' if resolved_is_live else 'demo',
            'server': cred.get('server'),
            'balance': balance,
            'equity': equity,
            'marginFree': margin_free,
            'activeBots': active_bots,
            'totalBots': total_bots,
        }

        if live_account_info:
            detailed_account['liveAccountInfo'] = {
                'tradeMode': live_account_info.get('tradeMode'),
                'accountType': live_account_info.get('accountType'),
                'openPositions': live_account_info.get('openPositions', len(current_positions)),
                'pendingOrders': live_account_info.get('pendingOrders'),
                'floatingPL': live_account_info.get('floatingPL'),
                'marginLevel': live_account_info.get('marginLevel'),
                'currency': live_account_info.get('currency'),
                'brokerServer': live_account_info.get('broker'),
            }
            detailed_account['currentPositions'] = current_positions
            if broker_recent_trades:
                detailed_account['brokerRecentTrades'] = broker_recent_trades[:20]
                detailed_account['brokerDataSource'] = live_account_info.get('dataSource', 'live')

        return jsonify({
            'success': True,
            'account': detailed_account,
            'tradeStats': {
                'totalTrades': len(trades),
                'openTrades': open_trades,
                'closedTrades': closed_trades,
                'winningTrades': winning_trades,
                'losingTrades': losing_trades,
                'winRate': round(win_rate, 1),
                'totalProfit': round(total_profit, 2),
                'totalLoss': round(total_loss, 2),
                'grossProfit': round(gross_profit, 2),
                'totalCommission': round(total_commission, 2),
                'totalSwap': round(total_swap, 2),
                'netProfit': round(net_profit, 2),
            },
            'recentTrades': trades[:20],
            'withdrawals': {
                'history': withdrawals[:10],
                'totalWithdrawn': round(total_withdrawn, 2),
                'count': len(withdrawals),
            },
            'commissions': {
                'history': commissions[:10],
                'totalEarned': round(total_commission_earned, 2),
                'count': len(commissions),
            },
        })
        
    except Exception as e:
        logger.error(f"Error getting account details: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


