# ==================== NEW: ENRICHED ACCOUNT DATA ENDPOINTS ====================

@app.route('/api/account/detailed', methods=['GET'])
@require_session
def get_account_detailed():
    """Get COMPREHENSIVE account data from ANY broker (Exness, Binance, FXCM, OANDA) with all metrics"""
    user_id = request.user_id
    
    try:
        conn = get_db_connection()
        cursor = conn.cursor()
        requested_mode = str(request.args.get('mode') or '').strip().upper()
        broker_filter = request.args.get('broker', default='', type=str).strip()
        preferred_mode = requested_mode if requested_mode in ['LIVE', 'DEMO'] else get_user_trading_mode_value(user_id)
        desired_live = 1 if preferred_mode == 'LIVE' else 0
        
        # Query all active credentials, optionally filtered by broker
        broker_clause = f"AND broker_name = '{broker_filter}'" if broker_filter else ""
        cursor.execute(f'''
            SELECT credential_id, broker_name, account_number, password, server, is_live, username,
                   cached_balance, cached_equity, cached_margin_free, cached_margin,
                   cached_margin_level, cached_profit, account_currency, last_update, updated_at, api_key
            FROM broker_credentials 
            WHERE user_id = ? AND is_active = 1 {broker_clause}
            ORDER BY broker_name, COALESCE(updated_at, last_update, '') DESC,
                     credential_id DESC
            LIMIT 10
        ''', (user_id,))
        
        creds = [dict(row) for row in cursor.fetchall()]
        creds, duplicate_credential_ids = dedupe_active_broker_credentials(creds)
        if duplicate_credential_ids:
            logger.info(
                f"Detected {len(duplicate_credential_ids)} duplicate/incomplete broker credential(s) for user {user_id} while loading account details; leaving database unchanged during polling."
            )
        conn.close()
        
        if not creds:
            return jsonify({
                'success': False,
                'error': f'No broker credentials found'
            }), 404

        accounts_data = []
        
        # Fetch account details from each broker
        for cred in creds:
            broker_name = canonicalize_broker_name(cred.get('broker_name'))
            account_num = cred['account_number']
            account_info = None
            skip_cached_snapshot = False
            
            try:
                # ==================== EXNESS / MT5 ====================
                if broker_name in ['Exness', 'MetaTrader5', 'PXBT']:
                    effective_is_live = int(normalize_mt5_is_live_flag(broker_name, cred.get('is_live'), cred.get('server')))
                    if effective_is_live == desired_live:
                        mt5_conn = MT5Connection({
                            'account': int(account_num),
                            'password': cred['password'],
                            'server': cred.get('server', 'Exness-MT5Trial9'),
                            'broker': broker_name,
                            'is_live': bool(cred['is_live']),
                        })
                        mt5_conn.connected = True
                        account_info = mt5_conn.get_account_info()
                        if account_info:
                            fetched_account = str(
                                account_info.get('accountNumber')
                                or account_info.get('account_id')
                                or account_info.get('login')
                                or ''
                            ).strip()
                            if fetched_account != str(account_num).strip():
                                logger.warning(
                                    f"⚠️ Skipping mismatched {broker_name} snapshot for credential {cred['credential_id']}: "
                                    f"requested {account_num}, active MT5 session returned {fetched_account or 'unknown'}"
                                )
                                account_info = None
                                skip_cached_snapshot = True
                            else:
                                account_info['broker'] = broker_name
                                account_info['credential_id'] = cred['credential_id']
                                logger.info(f"✅ Fetched account details from {broker_name} {account_num}")
                
                # ==================== BINANCE ====================
                elif broker_name == 'Binance':
                    binance_conn = BinanceConnection({
                        'api_key': cred.get('api_key'),
                        'api_secret': cred['password'],
                        'account_number': account_num,
                        'server': cred.get('server', 'spot'),
                        'is_live': bool(cred['is_live']),
                    })
                    if binance_conn.connect():
                        account_info = binance_conn.get_account_info()
                        if account_info:
                            account_info['broker'] = 'Binance'
                            account_info['credential_id'] = cred['credential_id']
                            logger.info(f"✅ Fetched account details from Binance {account_num}")
                        binance_conn.disconnect()
                
                # ==================== FXCM ====================
                elif broker_name == 'FXCM':
                    cached_fxcm_snapshot = _get_cached_fxcm_endpoint_snapshot(cred['credential_id'])
                    if cached_fxcm_snapshot and isinstance(cached_fxcm_snapshot.get('accountInfo'), dict) and cached_fxcm_snapshot['accountInfo']:
                        account_info = dict(cached_fxcm_snapshot['accountInfo'])
                        account_info['broker'] = 'FXCM'
                        account_info['credential_id'] = cred['credential_id']
                        account_info['dataSource'] = cached_fxcm_snapshot.get('dataSource', account_info.get('dataSource', 'cached-live'))
                    else:
                        fxcm_conn = FXCMConnection({
                            'api_key': cred.get('api_key'),
                            'username': cred.get('username'),
                            'password': cred.get('password'),
                            'account_number': account_num,
                            'server': cred.get('server'),
                            'connection': 'Real' if bool(cred['is_live']) else 'Demo',
                            'is_live': bool(cred['is_live']),
                        })
                        if fxcm_conn.connect():
                            account_info = fxcm_conn.get_account_info()
                            if account_info:
                                account_info['broker'] = 'FXCM'
                                account_info['credential_id'] = cred['credential_id']
                                _store_fxcm_endpoint_snapshot(
                                    cred['credential_id'],
                                    account_info=account_info,
                                    data_source=account_info.get('dataSource', 'live') if isinstance(account_info, dict) else 'live',
                                )
                                logger.info(f"✅ Fetched account details from FXCM {account_num}")
                            fxcm_conn.disconnect()
                        else:
                            logger.warning(
                                f"⚠️ FXCM account fetch failed for {account_num}: {fxcm_conn.last_error or 'Unknown FXCM error'}"
                            )
                
                # ==================== OANDA ====================
                elif broker_name == 'OANDA':
                    oanda_conn = OANDAConnection({
                        'api_key': cred.get('api_key'),
                        'account_number': account_num,
                        'is_live': bool(cred['is_live']),
                    })
                    if oanda_conn.connect():
                        account_info = oanda_conn.get_account_info()
                        if account_info:
                            account_info['broker'] = 'OANDA'
                            account_info['credential_id'] = cred['credential_id']
                            logger.info(f"✅ Fetched account details from OANDA {account_num}")
                        oanda_conn.disconnect()
                
                # Backup to cached data if live fetch failed
                if not account_info and not skip_cached_snapshot:
                    cached_balance = float(cred.get('cached_balance') or 0)
                    if cached_balance > 0 or cred.get('cached_equity'):
                        account_info = {
                            'account_id': account_num,
                            'accountNumber': account_num,
                            'balance': cached_balance,
                            'equity': float(cred.get('cached_equity') or cached_balance),
                            'marginFree': float(cred.get('cached_margin_free') or 0),
                            'margin': float(cred.get('cached_margin') or 0),
                            'margin_level': float(cred.get('cached_margin_level') or 0),
                            'profit': float(cred.get('cached_profit') or 0),
                            'currency': str(cred.get('account_currency') or 'USD').upper(),
                            'broker': broker_name,
                            'credential_id': cred['credential_id'],
                            'dataSource': 'cached',
                        }
                
                if account_info and account_info.get('dataSource') != 'cached':
                    persist_account_snapshot(
                        broker_name,
                        account_num,
                        account_info,
                        credential_id=cred.get('credential_id'),
                        user_id=user_id,
                    )
                if account_info:
                    accounts_data.append(account_info)
                    
            except Exception as e:
                logger.warning(f"⚠️ Could not fetch account details from {broker_name} {account_num}: {e}")
                continue

        if not accounts_data:
            # Return first cached option
            if creds:
                cred = creds[0]
                cached_balance = float(cred.get('cached_balance') or 0)
                return jsonify({
                    'success': True,
                    'accountNumber': cred['account_number'],
                    'balance': cached_balance,
                    'equity': float(cred.get('cached_equity') or cached_balance),
                    'marginFree': float(cred.get('cached_margin_free') or 0),
                    'margin': float(cred.get('cached_margin') or 0),
                    'margin_level': float(cred.get('cached_margin_level') or 0),
                    'profit': float(cred.get('cached_profit') or 0),
                    'currency': str(cred.get('account_currency') or 'USD').upper(),
                    'broker': cred['broker_name'],
                    'dataSource': 'cached',
                }), 200
            else:
                return jsonify({'success': False, 'error': 'No account data available'}), 404

        # Return all accounts or the first one depending on usage
        primary_account = accounts_data[0]
        return jsonify({
            'success': True,
            'accountNumber': primary_account.get('accountNumber', primary_account.get('account_id')),
            'balance': primary_account.get('balance', 0),
            'equity': primary_account.get('equity', 0),
            'marginFree': primary_account.get('marginFree', 0),
            'margin': primary_account.get('margin', 0),
            'margin_level': primary_account.get('margin_level', 0),
            'profit': primary_account.get('profit', 0),
            'currency': primary_account.get('currency', 'USD'),
            'broker': primary_account.get('broker'),
            'dataSource': primary_account.get('dataSource', 'live'),
            'allAccounts': accounts_data,  # Include all accounts for dashboard display
        }), 200
        
    except Exception as e:
        logger.error(f"Error getting account detailed: {e}")
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500


@app.route('/api/positions/detailed', methods=['GET'])
@require_session
def get_positions_detailed():
    """Get ALL open positions with DETAILED metrics"""
    user_id = request.user_id
    
    try:
        conn = get_db_connection()
        cursor = conn.cursor()
        requested_mode = str(request.args.get('mode') or '').strip().upper()
        preferred_mode = requested_mode if requested_mode in ['LIVE', 'DEMO'] else get_user_trading_mode_value(user_id)
        desired_live = 1 if preferred_mode == 'LIVE' else 0
        
        broker_filter = canonicalize_broker_name(request.args.get('broker', default='', type=str).strip())
        query = '''
            SELECT credential_id, broker_name, account_number, password, server, is_live, api_key, username
            FROM broker_credentials 
            WHERE user_id = ? AND is_active = 1
        '''
        params = [user_id]
        if broker_filter:
            query += ' AND UPPER(broker_name) = ?'
            params.append(broker_filter)
        query += '''
            ORDER BY broker_name, credential_id DESC
        '''
        cursor.execute(query, params)

        rows = [dict(row) for row in cursor.fetchall()]
        rows, duplicate_credential_ids = dedupe_active_broker_credentials(rows)
        if duplicate_credential_ids:
            logger.info(
                f"Detected {len(duplicate_credential_ids)} duplicate/incomplete broker credential(s) for user {user_id} while loading detailed positions; leaving database unchanged during polling."
            )
        conn.close()

        if not rows:
            return jsonify({
                'success': False,
                'positions': [],
                'totalCount': 0,
            })

        positions = []
        warnings_list = []

        for cred in rows:
            broker_name = canonicalize_broker_name(cred.get('broker_name'))
            effective_is_live = int(normalize_mt5_is_live_flag(broker_name, cred.get('is_live'), cred.get('server')))
            if effective_is_live != desired_live:
                continue

            conn_label, broker_conn = get_broker_connection(
                cred['credential_id'],
                user_id,
                bot_id=f'positions-detailed:{cred["credential_id"]}',
            )
            if not broker_conn:
                warnings_list.append(f"{broker_name} {cred['account_number']}: {conn_label}")
                continue

            try:
                broker_positions = broker_conn.get_positions() or []
                for position in broker_positions:
                    pnl = position.get('pnl', position.get('profit_loss', position.get('unrealizedPL', 0)))
                    positions.append({
                        'credentialId': cred['credential_id'],
                        'broker': broker_name,
                        'accountNumber': cred['account_number'],
                        'positionId': str(position.get('deal_id') or position.get('trade_id') or position.get('ticket') or ''),
                        'instrument': position.get('symbol') or position.get('instrument') or '',
                        'direction': position.get('type') or position.get('direction') or '',
                        'size': float(position.get('size', position.get('volume', 0)) or 0),
                        'level': float(position.get('level', position.get('openPrice', 0)) or 0),
                        'unrealizedPL': float(pnl or 0),
                        'raw': position,
                    })
            except Exception as e:
                warnings_list.append(f"{broker_name} {cred['account_number']}: {e}")
            finally:
                if hasattr(broker_conn, 'disconnect'):
                    try:
                        broker_conn.disconnect()
                    except Exception:
                        pass

        total_pl = sum(float(p.get('unrealizedPL', 0) or 0) for p in positions)

        return jsonify({
            'success': True,
            'positions': positions,
            'totalCount': len(positions),
            'totalPL': total_pl,
            'dataSource': 'multi-broker',
            'warnings': warnings_list,
        })
            
    except Exception as e:
        logger.error(f"Error getting detailed positions: {e}")
        return jsonify({
            'success': False,
            'error': str(e),
            'positions': []
        }), 500


@app.route('/api/unified/portfolio', methods=['GET'])
@require_session
def get_unified_portfolio():
    """Return unified portfolio totals and per-broker cards for the authenticated user."""
    user_id = request.user_id

    try:
        requested_mode = str(request.args.get('mode') or '').strip().upper()
        preferred_mode = requested_mode if requested_mode in ['LIVE', 'DEMO'] else get_user_trading_mode_value(user_id)
        desired_live = 1 if preferred_mode == 'LIVE' else 0

        conn = get_db_connection()
        cursor = conn.cursor()
        cursor.execute('''
            SELECT credential_id, broker_name, account_number, is_live, server,
                   cached_balance, cached_equity, cached_margin_free, cached_profit
            FROM broker_credentials
            WHERE user_id = ? AND is_active = 1
            ORDER BY broker_name, credential_id DESC
        ''', (user_id,))
        credentials = [dict(row) for row in cursor.fetchall()]
        conn.close()

        portfolio = {
            'total_balance': 0.0,
            'total_available': 0.0,
            'total_pnl': 0.0,
            'total_positions': 0,
            'connected_brokers': 0,
            'total_brokers': 0,
            'mode': preferred_mode,
        }
        brokers = {}

        for cred in credentials:
            broker_name = canonicalize_broker_name(cred.get('broker_name'))
            effective_is_live = int(normalize_mt5_is_live_flag(broker_name, cred.get('is_live'), cred.get('server')))
            if effective_is_live != desired_live:
                continue

            portfolio['total_brokers'] += 1
            broker_card = {
                'connected': False,
                'balance': float(cred.get('cached_balance') or 0),
                'available': float(cred.get('cached_margin_free') or 0),
                'pnl': float(cred.get('cached_profit') or 0),
                'positions': 0,
                'accountNumber': cred.get('account_number'),
                'mode': 'Live' if effective_is_live else 'Demo',
            }

            conn_label, broker_conn = get_broker_connection(
                cred['credential_id'],
                user_id,
                bot_id=f'unified-portfolio:{cred["credential_id"]}',
            )
            if broker_conn:
                try:
                    account_info = broker_conn.get_account_info() or {}
                    positions = broker_conn.get_positions() or []
                    broker_card.update({
                        'connected': True,
                        'balance': float(account_info.get('balance', broker_card['balance']) or broker_card['balance']),
                        'available': float(account_info.get('marginFree', account_info.get('margin_free', broker_card['available'])) or broker_card['available']),
                        'pnl': float(account_info.get('profit', account_info.get('total_pl', broker_card['pnl'])) or broker_card['pnl']),
                        'positions': len(positions),
                    })
                except Exception as e:
                    broker_card['error'] = str(e)
                finally:
                    if hasattr(broker_conn, 'disconnect'):
                        try:
                            broker_conn.disconnect()
                        except Exception:
                            pass
            else:
                broker_card['error'] = conn_label or 'Connection unavailable'

            brokers[broker_name] = broker_card
            if broker_card['connected']:
                portfolio['connected_brokers'] += 1
            portfolio['total_balance'] += float(broker_card['balance'] or 0)
            portfolio['total_available'] += float(broker_card['available'] or 0)
            portfolio['total_pnl'] += float(broker_card['pnl'] or 0)
            portfolio['total_positions'] += int(broker_card['positions'] or 0)

        return jsonify({'success': True, 'portfolio': portfolio, 'brokers': brokers}), 200
    except Exception as e:
        logger.error(f"Error building unified portfolio: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/unified/positions', methods=['GET'])
@require_session
def get_unified_positions():
    """Return all open positions across supported brokers for the authenticated user."""
    user_id = request.user_id

    try:
        requested_mode = str(request.args.get('mode') or '').strip().upper()
        preferred_mode = requested_mode if requested_mode in ['LIVE', 'DEMO'] else get_user_trading_mode_value(user_id)
        desired_live = 1 if preferred_mode == 'LIVE' else 0

        conn = get_db_connection()
        cursor = conn.cursor()
        cursor.execute('''
            SELECT credential_id, broker_name, account_number, is_live, server
            FROM broker_credentials
            WHERE user_id = ? AND is_active = 1
            ORDER BY broker_name, credential_id DESC
        ''', (user_id,))
        credentials = [dict(row) for row in cursor.fetchall()]
        conn.close()

        positions = []
        for cred in credentials:
            broker_name = canonicalize_broker_name(cred.get('broker_name'))
            effective_is_live = int(normalize_mt5_is_live_flag(broker_name, cred.get('is_live'), cred.get('server')))
            if effective_is_live != desired_live:
                continue

            _, broker_conn = get_broker_connection(
                cred['credential_id'],
                user_id,
                bot_id=f'unified-positions:{cred["credential_id"]}',
            )
            if not broker_conn:
                continue

            try:
                broker_positions = broker_conn.get_positions() or []
                for position in broker_positions:
                    pnl = position.get('pnl', position.get('profit_loss', position.get('unrealizedPL', 0)))
                    positions.append({
                        'broker': broker_name,
                        'accountNumber': cred['account_number'],
                        'positionId': str(position.get('deal_id') or position.get('trade_id') or position.get('ticket') or ''),
                        'instrument': position.get('symbol') or position.get('instrument') or '',
                        'direction': position.get('type') or position.get('direction') or '',
                        'size': float(position.get('size', position.get('volume', 0)) or 0),
                        'level': float(position.get('level', position.get('openPrice', 0)) or 0),
                        'unrealizedPL': float(pnl or 0),
                    })
            finally:
                if hasattr(broker_conn, 'disconnect'):
                    try:
                        broker_conn.disconnect()
                    except Exception:
                        pass

        return jsonify({'success': True, 'positions': positions, 'totalCount': len(positions)}), 200
    except Exception as e:
        logger.error(f"Error getting unified positions: {e}")
        return jsonify({'success': False, 'error': str(e), 'positions': []}), 500


@app.route('/api/unified/close-all', methods=['POST'])
@require_session
def close_all_unified_positions():
    """Close all open positions across supported brokers for the authenticated user."""
    user_id = request.user_id

    try:
        requested_mode = str((request.json or {}).get('mode') or '').strip().upper()
        preferred_mode = requested_mode if requested_mode in ['LIVE', 'DEMO'] else get_user_trading_mode_value(user_id)
        desired_live = 1 if preferred_mode == 'LIVE' else 0

        conn = get_db_connection()
        cursor = conn.cursor()
        cursor.execute('''
            SELECT credential_id, broker_name, account_number, is_live, server
            FROM broker_credentials
            WHERE user_id = ? AND is_active = 1
            ORDER BY broker_name, credential_id DESC
        ''', (user_id,))
        credentials = [dict(row) for row in cursor.fetchall()]
        conn.close()

        total_closed = 0
        results = []

        for cred in credentials:
            broker_name = canonicalize_broker_name(cred.get('broker_name'))
            effective_is_live = int(normalize_mt5_is_live_flag(broker_name, cred.get('is_live'), cred.get('server')))
            if effective_is_live != desired_live:
                continue

            conn_label, broker_conn = get_broker_connection(
                cred['credential_id'],
                user_id,
                bot_id=f'unified-close-all:{cred["credential_id"]}',
            )
            if not broker_conn:
                results.append({
                    'broker': broker_name,
                    'accountNumber': cred['account_number'],
                    'success': False,
                    'error': conn_label or 'Connection unavailable',
                })
                continue

            try:
                broker_positions = broker_conn.get_positions() or []
                for position in broker_positions:
                    position_id = position.get('deal_id') or position.get('trade_id') or position.get('ticket')
                    if position_id in [None, '']:
                        continue
                    close_result = broker_conn.close_position(str(position_id))
                    success = bool(close_result.get('success'))
                    if success:
                        total_closed += 1
                    results.append({
                        'broker': broker_name,
                        'accountNumber': cred['account_number'],
                        'positionId': str(position_id),
                        'success': success,
                        'error': close_result.get('error'),
                    })
            finally:
                if hasattr(broker_conn, 'disconnect'):
                    try:
                        broker_conn.disconnect()
                    except Exception:
                        pass

        return jsonify({'success': True, 'total_closed': total_closed, 'results': results}), 200
    except Exception as e:
        logger.error(f"Error closing unified positions: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/trades/history', methods=['GET'])
@require_session
def get_trades_history():
    """Get TRADE HISTORY (closed trades) from the last N days - supports all brokers"""
    user_id = request.user_id
    days = request.args.get('days', default=30, type=int)
    broker_filter = request.args.get('broker', default='', type=str).strip()  # Optional: filter by broker
    
    try:
        conn = get_db_connection()
        cursor = conn.cursor()
        preferred_mode = get_user_trading_mode_value(user_id)
        desired_live = 1 if preferred_mode == 'LIVE' else 0
        
        # Query all active credentials for user, optionally filtered by broker
        broker_clause = f"AND broker_name = '{broker_filter}'" if broker_filter else ""
        cursor.execute(f'''
            SELECT credential_id, broker_name, account_number, password, server, is_live, api_key, username
            FROM broker_credentials 
            WHERE user_id = ? AND is_active = 1 {broker_clause}
            ORDER BY broker_name, credential_id DESC
        ''', (user_id,))
        
        creds = [dict(row) for row in cursor.fetchall()]
        creds, duplicate_credential_ids = dedupe_active_broker_credentials(creds)
        if duplicate_credential_ids:
            logger.info(
                f"Detected {len(duplicate_credential_ids)} duplicate/incomplete broker credential(s) for user {user_id} while loading trade history; leaving database unchanged during polling."
            )
        conn.close()

        if not creds:
            return jsonify({
                'success': False,
                'trades': [],
                'totalCount': 0,
                'message': f'No broker credentials found for user'
            }), 200

        all_trades = []
        
        # Fetch trades from each broker
        for cred in creds:
            broker_name = canonicalize_broker_name(cred.get('broker_name'))
            account_num = cred['account_number']
            
            try:
                # ==================== EXNESS ====================
                if broker_name in ['Exness', 'MetaTrader5']:
                    effective_is_live = int(normalize_mt5_is_live_flag(broker_name, cred.get('is_live'), cred.get('server')))
                    if effective_is_live == desired_live:
                        mt5_conn = MT5Connection({
                            'account': int(account_num),
                            'password': cred['password'],
                            'server': cred.get('server', 'Exness-MT5Trial9'),
                            'broker': broker_name,
                            'is_live': bool(cred['is_live']),
                        })
                        mt5_conn.connected = True
                        broker_trades = mt5_conn.get_trade_history(days=days)
                        all_trades.extend(broker_trades or [])
                        logger.info(f"✅ Fetched {len(broker_trades or [])} trades from {broker_name} {account_num}")
                
                # ==================== BINANCE ====================
                elif broker_name == 'Binance':
                    binance_conn = BinanceConnection({
                        'api_key': cred.get('api_key'),
                        'api_secret': cred['password'],
                        'account_number': account_num,
                        'server': cred.get('server', 'spot'),
                        'is_live': bool(cred['is_live']),
                    })
                    if binance_conn.connect():
                        # Pull DB-tracked closed trades for this user (real P&L context)
                        db_hist_trades = []
                        try:
                            hist_conn = build_sqlite_connection(timeout=10.0, row_factory=True)
                            hist_cursor = hist_conn.cursor()
                            since_ts = (datetime.now() - timedelta(days=days)).isoformat()
                            hist_cursor.execute(
                                '''SELECT trade_id, bot_id, user_id, symbol, order_type, volume, price, profit,
                                          ticket, time_open, time_close, status, created_at
                                   FROM trades WHERE user_id = ? AND status = 'closed' AND created_at >= ?
                                   ORDER BY time_close DESC LIMIT 500''',
                                (user_id, since_ts)
                            )
                            db_hist_cols = [d[0] for d in hist_cursor.description]
                            for db_row in hist_cursor.fetchall():
                                db_trade = dict(zip(db_hist_cols, db_row))
                                db_trade['broker'] = 'Binance'
                                db_trade['account_number'] = account_num
                                db_trade['source'] = 'db'
                                db_trade['type'] = db_trade.pop('order_type', 'BUY')
                                entry_p = db_trade.pop('price', 0) or 0
                                db_trade['entryPrice'] = entry_p
                                db_trade['openPrice'] = entry_p
                                db_trade['openTime'] = db_trade.pop('time_open', None)
                                db_trade['closeTime'] = db_trade.pop('time_close', None)
                                db_hist_trades.append(db_trade)
                            hist_conn.close()
                        except Exception as hist_err:
                            logger.warning(f"Could not load DB history for Binance {user_id}: {hist_err}")
                        # For raw broker fills, only include those with meaningful P&L
                        raw_fills = binance_conn.get_trades() or []
                        db_tickets = {str(t.get('ticket', '')) for t in db_hist_trades}
                        meaningful_fills = [
                            t for t in raw_fills
                            if (
                                _safe_float(t.get('profit'), 0.0) != 0.0
                                or _safe_float(t.get('exitPrice'), 0.0) != 0.0
                            ) and str(t.get('ticket', '')) not in db_tickets
                        ]
                        for trade in meaningful_fills:
                            trade['broker'] = 'Binance'
                            trade['account_number'] = account_num
                        combined_binance = db_hist_trades + meaningful_fills
                        all_trades.extend(combined_binance)
                        logger.info(
                            f"✅ Fetched {len(combined_binance)} trades from Binance {account_num} "
                            f"({len(db_hist_trades)} DB closed, {len(meaningful_fills)} meaningful fills "
                            f"from {len(raw_fills)} raw)"
                        )
                        binance_conn.disconnect()
                
                # ==================== FXCM ====================
                elif broker_name == 'FXCM':
                    fxcm_conn = FXCMConnection({
                        'api_key': cred.get('api_key'),
                        'username': cred.get('username'),
                        'password': cred.get('password'),
                        'account_number': account_num,
                        'server': cred.get('server'),
                        'connection': 'Real' if bool(cred['is_live']) else 'Demo',
                        'is_live': bool(cred['is_live']),
                    })
                    if fxcm_conn.connect():
                        broker_trades = fxcm_conn.get_trades() or []
                        # Add broker info to each trade
                        for trade in broker_trades:
                            trade['broker'] = 'FXCM'
                            trade['account_number'] = account_num
                        all_trades.extend(broker_trades)
                        logger.info(f"✅ Fetched {len(broker_trades)} trades from FXCM {account_num}")
                        fxcm_conn.disconnect()
                    else:
                        logger.warning(
                            f"⚠️ FXCM trade fetch failed for {account_num}: {fxcm_conn.last_error or 'Unknown FXCM error'}"
                        )
                
                # ==================== OANDA ====================
                elif broker_name == 'OANDA':
                    oanda_conn = OANDAConnection({
                        'api_key': cred.get('api_key'),
                        'account_number': account_num,
                        'is_live': bool(cred['is_live']),
                    })
                    if oanda_conn.connect():
                        broker_trades = oanda_conn.get_trades() or []
                        # Add broker info to each trade
                        for trade in broker_trades:
                            trade['broker'] = 'OANDA'
                            trade['account_number'] = account_num
                        all_trades.extend(broker_trades)
                        logger.info(f"✅ Fetched {len(broker_trades)} trades from OANDA {account_num}")
                        oanda_conn.disconnect()
                        
            except Exception as e:
                logger.warning(f"⚠️ Could not fetch trades from {broker_name} {account_num}: {e}")
                continue

        # Sort trades by timestamp (most recent first)
        all_trades.sort(key=lambda t: t.get('closeTime') or t.get('closedAt') or '0', reverse=True)

        return jsonify({
            'success': True,
            'trades': all_trades,
            'totalCount': len(all_trades),
            'period': f'Last {days} days',
            'dataSource': 'multi-broker',
            'brokers': list(set([t.get('broker', 'unknown') for t in all_trades]))
        }), 200
            
    except Exception as e:
        logger.error(f"Error getting trade history: {e}")
        return jsonify({
            'success': False,
            'error': str(e),
            'trades': []
        }), 500


@app.route('/api/account/performance', methods=['GET'])
@require_session
def get_account_performance():
    """Get account PERFORMANCE METRICS and statistics"""
    user_id = request.user_id
    
    try:
        conn = get_db_connection()
        cursor = conn.cursor()
        preferred_mode = get_user_trading_mode_value(user_id)
        desired_live = 1 if preferred_mode == 'LIVE' else 0
        
        cursor.execute('''
            SELECT credential_id, broker_name, account_number, password, server, is_live
            FROM broker_credentials 
            WHERE user_id = ? AND is_active = 1 AND broker_name = 'Exness' AND is_live = ?
            ORDER BY credential_id
            LIMIT 1
        ''', (user_id, desired_live))
        
        cred = cursor.fetchone()
        conn.close()
        
        if not cred:
            return jsonify({
                'success': False,
                'metrics': None
            })
        
        mt5_conn = MT5Connection({
            'account': int(cred[2]),
            'password': cred[3],
            'server': cred[4],
            'broker': 'Exness',
            'is_live': bool(cred[5]),
        })
        
        if mt5_conn.connect():
            metrics = mt5_conn.get_performance_metrics()
            mt5_conn.disconnect()
            
            return jsonify({
                'success': True,
                'metrics': metrics,
            })
        else:
            return jsonify({
                'success': False,
                'error': 'Connection failed'
            })
            
    except Exception as e:
        logger.error(f"Error getting performance metrics: {e}")
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500


