def normalize_symbol_for_broker(symbol: str, broker_name: str = None) -> str:
    broker_name = canonicalize_broker_name(broker_name or '')
    raw_symbol = str(symbol or '').strip()
    if not raw_symbol:
        return ''

    if broker_name == 'FXCM':
        direct_match = next((candidate for candidate in FXCM_CONFIGURABLE_SYMBOLS if candidate.lower() == raw_symbol.lower()), '')
        if direct_match:
            return direct_match

        alias = FXCM_SYMBOL_ALIASES.get(raw_symbol.upper())
        if alias:
            return alias

        compact = raw_symbol.upper().replace('/', '').replace('_', '').replace(' ', '')
        alias = FXCM_SYMBOL_ALIASES.get(compact)
        if alias:
            return alias
        if compact in FXCM_SAFE_SYMBOLS:
            return compact
        return ''

    base_symbol = raw_symbol.split('.')[0].strip()
    lookup_key = base_symbol.upper().replace('/', '').replace('_', '')
    mapped_symbol = SYMBOL_MAPPING.get(base_symbol, SYMBOL_MAPPING.get(lookup_key, lookup_key))

    if broker_name in ('Exness', 'XM', 'XM Global'):
        mapped_upper = str(mapped_symbol).upper()
        if mapped_upper.endswith('M') and mapped_upper[:-1] in VALID_SYMBOLS:
            return mapped_upper[:-1] + 'm'
        return f"{mapped_upper}m"

    return str(mapped_symbol).upper()


def get_mt5_ready_symbols_for_broker(broker_name: str) -> List[str]:
    normalized_broker = canonicalize_broker_name(broker_name or '')
    if normalized_broker in ('Exness', 'XM', 'XM Global'):
        return [normalize_symbol_for_broker(symbol, normalized_broker) for symbol in sorted(VALID_SYMBOLS)]
    if normalized_broker == 'FXCM':
        return list(FXCM_SAFE_SYMBOLS)
    return sorted(VALID_SYMBOLS)


def _resolve_user_id_from_session_token(session_token: str) -> Optional[str]:
    token = str(session_token or '').strip()
    if not token:
        return None

    cached_session = TEMP_SESSION_CACHE.get(token)
    if cached_session:
        try:
            expires_at = datetime.fromisoformat(cached_session['expires_at'])
            if expires_at >= datetime.now():
                return str(cached_session['user_id'])
        except Exception:
            pass
        TEMP_SESSION_CACHE.pop(token, None)

    conn = None
    try:
        conn = get_db_connection()
        cursor = conn.cursor()
        cursor.execute(
            '''
            SELECT user_id, expires_at
            FROM user_sessions
            WHERE token = ? AND is_active = 1
            ''',
            (token,),
        )
        session = cursor.fetchone()
        if not session:
            return None

        expires_at = str(session['expires_at'] or '').strip()
        if expires_at:
            try:
                if datetime.fromisoformat(expires_at) < datetime.now():
                    return None
            except Exception:
                pass
        return str(session['user_id'])
    except Exception as exc:
        logger.warning(f"Could not resolve user from session token for symbol catalog lookup: {exc}")
        return None
    finally:
        if conn is not None:
            conn.close()


def _normalize_fxcm_symbol_key(symbol: str) -> str:
    normalized = normalize_symbol_for_broker(symbol, 'FXCM') or str(symbol or '').strip()
    return normalized.upper().replace('/', '').replace('_', '').replace(' ', '')


def _get_fxcm_symbol_candidate_keys(symbol: str) -> Set[str]:
    raw_symbol = str(symbol or '').strip()
    if not raw_symbol:
        return set()

    raw_key = raw_symbol.upper().replace('/', '').replace('_', '').replace(' ', '')
    normalized_key = _normalize_fxcm_symbol_key(raw_symbol)
    candidate_keys: Set[str] = {key for key in {raw_key, normalized_key} if key}

    for items in FXCM_SYMBOL_CONFIG.values():
        for item in items:
            configured_symbol = str(item.get('symbol') or '').strip()
            configured_key = _normalize_fxcm_symbol_key(configured_symbol)
            if configured_symbol.lower() == raw_symbol.lower() or configured_key in candidate_keys:
                if configured_key:
                    candidate_keys.add(configured_key)
                analysis_symbol = str(item.get('analysis_symbol') or '').strip()
                if analysis_symbol:
                    candidate_keys.add(_normalize_fxcm_symbol_key(analysis_symbol))
    return candidate_keys


def _get_fxcm_safe_symbol_catalog() -> Dict[str, List[Dict[str, Any]]]:
    safe_keys = {_normalize_fxcm_symbol_key(symbol) for symbol in FXCM_SAFE_SYMBOLS}
    filtered_config: Dict[str, List[Dict[str, Any]]] = {}
    for category, items in FXCM_SYMBOL_CONFIG.items():
        filtered_items = []
        for item in items:
            configured_symbol = str(item.get('symbol') or '')
            candidate_keys = _get_fxcm_symbol_candidate_keys(configured_symbol)
            if candidate_keys & safe_keys:
                filtered_items.append(item)
        if filtered_items:
            filtered_config[category] = filtered_items
    return filtered_config


def _get_fxcm_tradable_symbol_keys(*, credential_row: Optional[Dict[str, Any]] = None, broker_conn=None) -> Optional[Set[str]]:
    tradable_symbols: Optional[List[str]] = None
    if broker_conn is not None and hasattr(broker_conn, 'get_tradable_symbols'):
        try:
            tradable_symbols = broker_conn.get_tradable_symbols()
        except Exception as exc:
            logger.warning(f"Could not read FXCM tradable symbols from active connection: {exc}")
            tradable_symbols = None
    elif credential_row is not None:
        fxcm_conn = FXCMConnection({
            'broker': 'FXCM',
            'account_number': credential_row.get('account_number'),
            'username': credential_row.get('username'),
            'password': credential_row.get('password'),
            'server': credential_row.get('server'),
            'is_live': bool(credential_row.get('is_live')),
            'api_key': credential_row.get('api_key'),
        })
        try:
            tradable_symbols = fxcm_conn.get_tradable_symbols()
            if tradable_symbols is None and fxcm_conn.connect():
                tradable_symbols = fxcm_conn.get_tradable_symbols()
        finally:
            fxcm_conn.disconnect()

    if tradable_symbols is None:
        return None

    tradable_keys: Set[str] = set()
    for symbol in tradable_symbols:
        tradable_keys.update(_get_fxcm_symbol_candidate_keys(symbol))
    return tradable_keys


def _filter_fxcm_symbols_for_tradability(symbols: List[str], tradable_symbol_keys: Optional[Set[str]]) -> List[str]:
    if tradable_symbol_keys is None:
        return list(symbols)

    filtered_symbols: List[str] = []
    for symbol in symbols:
        candidate_keys = _get_fxcm_symbol_candidate_keys(symbol)
        if candidate_keys & tradable_symbol_keys:
            if symbol not in filtered_symbols:
                filtered_symbols.append(symbol)
    return filtered_symbols


def _get_fxcm_credential_for_catalog(session_token: str, credential_id: str = '') -> Optional[Dict[str, Any]]:
    user_id = _resolve_user_id_from_session_token(session_token)
    if not user_id:
        return None

    conn = None
    try:
        conn = get_db_connection()
        cursor = conn.cursor()
        if credential_id:
            cursor.execute(
                '''
                  SELECT credential_id, broker_name, account_number, username, password, server,
                      is_live, api_key
                FROM broker_credentials
                WHERE user_id = ? AND credential_id = ? AND is_active = 1
                ''',
                (user_id, credential_id),
            )
            row = cursor.fetchone()
            if row and canonicalize_broker_name(row['broker_name']) == 'FXCM':
                return dict(row)

        cursor.execute(
            '''
                 SELECT credential_id, broker_name, account_number, username, password, server,
                     is_live, api_key
            FROM broker_credentials
            WHERE user_id = ? AND is_active = 1 AND broker_name = 'FXCM'
            ORDER BY updated_at DESC, created_at DESC, credential_id DESC
            LIMIT 1
            ''',
            (user_id,),
        )
        row = cursor.fetchone()
        return dict(row) if row else None
    except Exception as exc:
        logger.warning(f"Could not resolve FXCM credential for symbol catalog lookup: {exc}")
        return None
    finally:
        if conn is not None:
            conn.close()


def _filter_fxcm_symbol_catalog_for_credential(symbol_config: Dict[str, List[Dict[str, Any]]], credential_row: Dict[str, Any]) -> Dict[str, List[Dict[str, Any]]]:
    allowed_keys = _get_fxcm_tradable_symbol_keys(credential_row=credential_row)
    if allowed_keys is None:
        annotated_config: Dict[str, List[Dict[str, Any]]] = {}
        for category, items in symbol_config.items():
            annotated_items = []
            for item in items:
                annotated_item = dict(item)
                annotated_item.update({
                    'tradeable': None,
                    'tradeabilityStatus': 'visible_only',
                    'tradeabilityLabel': 'VISIBLE ONLY',
                    'tradeabilityReason': 'FXCM account tradability could not be confirmed right now.',
                })
                annotated_items.append(annotated_item)
            if annotated_items:
                annotated_config[category] = annotated_items

        logger.info("[FXCM] Tradability check unavailable — returning full symbol catalog as visible-only")
        return annotated_config

    filtered_config: Dict[str, List[Dict[str, Any]]] = {}
    tradeable_count = 0
    unavailable_count = 0
    for category, items in symbol_config.items():
        filtered_items = []
        for item in items:
            candidate_keys = _get_fxcm_symbol_candidate_keys(str(item.get('symbol') or ''))
            is_tradeable = bool(candidate_keys & allowed_keys)
            annotated_item = dict(item)
            annotated_item.update({
                'tradeable': is_tradeable,
                'tradeabilityStatus': 'tradeable' if is_tradeable else 'unavailable',
                'tradeabilityLabel': 'TRADEABLE' if is_tradeable else 'CLOSED/UNAVAILABLE',
                'tradeabilityReason': (
                    'Tradable on the active FXCM account.'
                    if is_tradeable else
                    'Visible in FXCM, but not currently tradeable/subscribed on the active account.'
                ),
            })
            filtered_items.append(annotated_item)
            if is_tradeable:
                tradeable_count += 1
            else:
                unavailable_count += 1
        if filtered_items:
            filtered_config[category] = filtered_items

    logger.info(
        f"[FXCM] Filtered symbol catalog for credential {credential_row.get('credential_id')}: "
        f"{tradeable_count} tradeable symbols, {unavailable_count} closed/unavailable symbols"
    )
    return filtered_config


def _get_symbol_catalog_for_request(broker_name: str) -> Dict[str, List[Dict[str, Any]]]:
    if canonicalize_broker_name(broker_name) != 'FXCM':
        return FXCM_SYMBOL_CONFIG

    skip_tradability = str(request.args.get('skip_tradability') or '').strip().lower() in {
        '1',
        'true',
        'yes',
        'on',
    }
    if skip_tradability:
        logger.info('[FXCM] Legacy skip_tradability flag received; backend will still try credential-aware filtering')

    session_token = str(request.headers.get('X-Session-Token') or '').strip()
    credential_id = str(request.args.get('credential_id') or '').strip()
    credential_row = _get_fxcm_credential_for_catalog(session_token, credential_id)
    if not credential_row:
        return _get_fxcm_safe_symbol_catalog()
    return _filter_fxcm_symbol_catalog_for_credential(FXCM_SYMBOL_CONFIG, credential_row)


def _get_fxcm_credential_for_user(user_id: str, credential_id: str = '') -> Optional[Dict[str, Any]]:
    if not user_id:
        return None

    conn = None
    try:
        conn = get_db_connection()
        cursor = conn.cursor()
        if credential_id:
            cursor.execute(
                '''
                SELECT credential_id, broker_name, account_number, username, password, server,
                       is_live, api_key, is_active, account_currency
                FROM broker_credentials
                WHERE user_id = ? AND credential_id = ? AND is_active = 1
                LIMIT 1
                ''',
                (user_id, credential_id),
            )
            row = cursor.fetchone()
            if row and canonicalize_broker_name(row['broker_name']) == 'FXCM':
                return dict(row)
            return None

        cursor.execute(
            '''
            SELECT credential_id, broker_name, account_number, username, password, server,
                   is_live, api_key, is_active, account_currency
            FROM broker_credentials
            WHERE user_id = ? AND broker_name = 'FXCM' AND is_active = 1
            ORDER BY updated_at DESC, created_at DESC, credential_id DESC
            LIMIT 1
            ''',
            (user_id,),
        )
        row = cursor.fetchone()
        return dict(row) if row else None
    except Exception as exc:
        logger.warning(f"Could not resolve FXCM credential for user {user_id}: {exc}")
        return None
    finally:
        if conn is not None:
            conn.close()


def _get_bot_debug_context_for_user(user_id: str, bot_id: str) -> Optional[Dict[str, Any]]:
    if not user_id or not bot_id:
        return None

    active_bot = active_bots.get(bot_id)
    if active_bot and active_bot.get('user_id') == user_id:
        return {
            'bot_id': bot_id,
            'bot_name': active_bot.get('name') or bot_id,
            'broker_name': canonicalize_broker_name(active_bot.get('brokerName') or active_bot.get('broker_type')),
            'credential_id': str(active_bot.get('credentialId') or '').strip(),
            'symbols': validate_and_correct_symbols(active_bot.get('symbols') or [], active_bot.get('brokerName') or active_bot.get('broker_type')),
            'source': 'memory',
        }

    conn = None
    try:
        conn = get_db_connection()
        cursor = conn.cursor()
        cursor.execute(
            '''
            SELECT
                ub.bot_id,
                ub.name,
                ub.symbols,
                ub.runtime_state,
                bc.credential_id,
                bcr.broker_name
            FROM user_bots ub
            LEFT JOIN bot_credentials bc ON bc.bot_id = ub.bot_id AND bc.user_id = ub.user_id
            LEFT JOIN broker_credentials bcr ON bcr.credential_id = bc.credential_id
            WHERE ub.user_id = ? AND ub.bot_id = ?
            LIMIT 1
            ''',
            (user_id, bot_id),
        )
        row = cursor.fetchone()
        if not row:
            return None

        row_dict = dict(row)
        broker_name = canonicalize_broker_name(row_dict.get('broker_name'))
        runtime_state = {}
        try:
            runtime_state = json.loads(row_dict.get('runtime_state') or '{}') if row_dict.get('runtime_state') else {}
        except Exception:
            runtime_state = {}

        raw_symbols = runtime_state.get('symbols')
        if not raw_symbols:
            raw_symbols = [symbol.strip() for symbol in str(row_dict.get('symbols') or '').split(',') if symbol.strip()]

        return {
            'bot_id': row_dict.get('bot_id'),
            'bot_name': row_dict.get('name') or row_dict.get('bot_id'),
            'broker_name': broker_name,
            'credential_id': str(row_dict.get('credential_id') or '').strip(),
            'symbols': validate_and_correct_symbols(raw_symbols or [], broker_name),
            'source': 'database',
        }
    except Exception as exc:
        logger.warning(f"Could not resolve bot debug context for {bot_id}: {exc}")
        return None
    finally:
        if conn is not None:
            conn.close()


def _parse_fxcm_debug_symbols(raw_symbols: Any) -> List[str]:
    if isinstance(raw_symbols, list):
        values = raw_symbols
    else:
        raw_text = str(raw_symbols or '').strip()
        if not raw_text:
            return []
        values = raw_text.replace('\n', ',').split(',')

    parsed_symbols: List[str] = []
    for value in values:
        symbol = str(value or '').strip()
        if symbol and symbol not in parsed_symbols:
            parsed_symbols.append(symbol)
    return parsed_symbols


def _build_fxcm_symbol_debug_snapshot(credential_row: Dict[str, Any], symbols: List[str]) -> Dict[str, Any]:
    fxcm_conn = FXCMConnection({
        'broker': 'FXCM',
        'account_number': credential_row.get('account_number'),
        'username': credential_row.get('username'),
        'password': credential_row.get('password'),
        'server': credential_row.get('server'),
        'is_live': bool(credential_row.get('is_live')),
        'api_key': credential_row.get('api_key'),
    })

    allowed_keys = _get_fxcm_tradable_symbol_keys(credential_row=credential_row)
    tradability_error = str(fxcm_conn.last_error or '').strip()
    symbol_entries: List[Dict[str, Any]] = []
    tradeable_count = 0
    blocked_count = 0
    unknown_count = 0

    helper_available = fxcm_conn._can_use_forexconnect_helper()
    for symbol in symbols:
        candidate_keys = sorted(_get_fxcm_symbol_candidate_keys(symbol))
        debug_payload: Dict[str, Any] = {}
        matching_offers: List[Dict[str, Any]] = []
        helper_error = ''

        if helper_available:
            helper_result = fxcm_conn._run_forexconnect_helper(
                'debug_symbol',
                extra={'symbol': symbol},
                timeout=45,
            )
            if helper_result and helper_result.get('success'):
                debug_payload = helper_result
                matching_offers = helper_result.get('matching_offers') or []
            else:
                helper_error = str(fxcm_conn.last_error or '').strip()

        has_tradeable_offer = any(bool(offer.get('tradeable')) for offer in matching_offers)
        matching_statuses = sorted({str(offer.get('subscription_status') or '').upper() for offer in matching_offers if str(offer.get('subscription_status') or '').strip()})
        is_tradeable = has_tradeable_offer or (allowed_keys is not None and bool(set(candidate_keys) & allowed_keys))

        if is_tradeable:
            status = 'tradeable'
            label = 'TRADEABLE'
            reason = 'Tradable on the active FXCM account.'
            tradeable_count += 1
        elif allowed_keys is None:
            status = 'unknown'
            label = 'UNKNOWN'
            reason = tradability_error or helper_error or 'FXCM tradability could not be confirmed right now.'
            unknown_count += 1
        elif matching_offers:
            status = 'visible_only'
            label = 'VISIBLE ONLY'
            reason = (
                f"Matching FXCM offers exist with subscription status {', '.join(matching_statuses) or 'unknown'}, "
                "but none are currently tradeable on this account."
            )
            blocked_count += 1
        else:
            status = 'unavailable'
            label = 'CLOSED/UNAVAILABLE'
            reason = 'The symbol is not in the active FXCM tradable offer list for this account.'
            blocked_count += 1

        symbol_entries.append({
            'symbol': symbol,
            'normalizedKeys': candidate_keys,
            'tradeable': is_tradeable,
            'tradeabilityStatus': status,
            'tradeabilityLabel': label,
            'tradeabilityReason': reason,
            'matchingOffers': matching_offers,
            'matchingOfferStatuses': matching_statuses,
            'helperAvailable': helper_available,
            'helperError': helper_error,
            'helperDebug': debug_payload,
        })

    return {
        'credentialId': credential_row.get('credential_id'),
        'accountNumber': credential_row.get('account_number'),
        'username': credential_row.get('username'),
        'mode': 'live' if bool(credential_row.get('is_live')) else 'demo',
        'tradabilityKnown': allowed_keys is not None,
        'tradableSymbolCount': len(allowed_keys or []),
        'tradabilityError': tradability_error,
        'helperAvailable': helper_available,
        'symbols': symbol_entries,
        'summary': {
            'total': len(symbol_entries),
            'tradeable': tradeable_count,
            'blocked': blocked_count,
            'unknown': unknown_count,
        },
    }

def validate_and_correct_symbols(symbols, broker_name=None):
    """Validate symbols based on broker type and correct old/unavailable ones when possible."""
    broker_name = canonicalize_broker_name(broker_name or '')

    if broker_name == 'Binance':
        if not symbols:
            return ['BTCUSDT']

        corrected = []
        binance_symbol_map = {
            # BTC / ETH / BNB
            'BTCUSD': 'BTCUSDT', 'BTC/USDT': 'BTCUSDT', 'BTC_USDT': 'BTCUSDT', 'BITCOIN': 'BTCUSDT',
            'ETHUSD': 'ETHUSDT', 'ETH/USDT': 'ETHUSDT', 'ETH_USDT': 'ETHUSDT', 'ETHEREUM': 'ETHUSDT',
            'BNBUSD': 'BNBUSDT', 'BNB/USDT': 'BNBUSDT',
            # SOL / XRP / ADA / DOGE
            'SOLUSD': 'SOLUSDT', 'SOL/USDT': 'SOLUSDT',
            'XRPUSD': 'XRPUSDT', 'XRP/USDT': 'XRPUSDT',
            'ADAUSD': 'ADAUSDT', 'ADA/USDT': 'ADAUSDT',
            'DOGEUSD': 'DOGEUSDT', 'DOGE/USDT': 'DOGEUSDT',
            # Tier 2
            'AVAXUSD': 'AVAXUSDT', 'MATICS': 'MATICUSDT', 'MATIC/USDT': 'MATICUSDT', 'POLUSD': 'MATICUSDT',
            'LINKUSD': 'LINKUSDT', 'LTCUSD': 'LTCUSDT', 'TRXUSD': 'TRXUSDT',
            'DOTUSD': 'DOTUSDT', 'ATOMUSD': 'ATOMUSDT',
            # Tier 3
            'SHIBUSD': 'SHIBUSDT', 'SHIB/USDT': 'SHIBUSDT',
            'UNIUSD': 'UNIUSDT',  'UNI/USDT': 'UNIUSDT',
            'NEARUSD': 'NEARUSDT', 'ARBUSD': 'ARBUSDT', 'OPUSD': 'OPUSDT',
            'APTUSD': 'APTUSDT',  'INJUSD': 'INJUSDT', 'SUIUSD': 'SUIUSDT',
            'FTMUSD': 'FTMUSDT',  'AAVEUSD': 'AAVEUSDT',
            # Tier 4
            'SANDUSD': 'SANDUSDT', 'MANAUSD': 'MANAUSDT',
            'RUNEUSD': 'RUNEUSDT', 'ALGOUSD': 'ALGOUSDT',
        }

        for symbol in symbols:
            normalized = str(symbol).upper().replace('/', '').replace('_', '')
            normalized = binance_symbol_map.get(str(symbol).upper(), normalized)
            normalized = binance_symbol_map.get(normalized, normalized)

            if _is_binance_supported_symbol(normalized) and normalized not in corrected:
                corrected.append(normalized)
            else:
                logger.warning(f"⚠️ Unsupported Binance symbol {symbol} - skipping")

        return corrected or ['BTCUSDT']

    if broker_name == 'PXBT':
        if not symbols:
            return ['EURUSD']

        corrected = []
        pxbt_symbol_map = {
            'EURUSDM': 'EURUSD', 'EURUSD': 'EURUSD',
            'GBPUSDM': 'GBPUSD', 'GBPUSD': 'GBPUSD',
            'USDJPYM': 'USDJPY', 'USDJPY': 'USDJPY',
            'USDCHFM': 'USDCHF', 'USDCHF': 'USDCHF',
            'XAUUSDM': 'XAUUSD', 'XAUUSD': 'XAUUSD', 'GOLD': 'XAUUSD',
            'XAGUSDM': 'XAGUSD', 'XAGUSD': 'XAGUSD', 'SILVER': 'XAGUSD',
            'US30M': 'US30', 'US30': 'US30', 'DJ30': 'US30',
            'EUR50M': 'EUR50', 'EUR50': 'EUR50',
            'BRENTUSD': 'BRENT', 'BRENTM': 'BRENT', 'BRENT': 'BRENT',
            'BTCUSDM': 'BTCUSDT', 'BTCUSD': 'BTCUSDT', 'BTCUSDT': 'BTCUSDT', 'BITCOIN': 'BTCUSDT',
            'ETHUSDM': 'ETHUSDT', 'ETHUSD': 'ETHUSDT', 'ETHUSDT': 'ETHUSDT', 'ETHEREUM': 'ETHUSDT',
        }

        for symbol in symbols:
            normalized = str(symbol).upper().replace('/', '').replace('_', '')
            normalized = pxbt_symbol_map.get(normalized, normalized)

            if normalized in PXBT_VALID_SYMBOLS and normalized not in corrected:
                corrected.append(normalized)
            else:
                logger.warning(f"⚠️ Unknown PXBT symbol {symbol} -> defaulting to EURUSD")
                if 'EURUSD' not in corrected:
                    corrected.append('EURUSD')

        return corrected[:5] or ['EURUSD']

    if broker_name == 'FXCM':
        if not symbols:
            return ['EUR/USD']

        corrected = []
        for symbol in symbols:
            mapped = normalize_symbol_for_broker(symbol, broker_name)
            is_supported = bool(mapped and (mapped in FXCM_SAFE_SYMBOLS or mapped in FXCM_CONFIGURABLE_SYMBOLS))
            if is_supported:
                if mapped not in corrected:
                    corrected.append(mapped)
                continue

            logger.warning(f'⚠️ Unsupported FXCM symbol {symbol} -> defaulting to EUR/USD')
            if 'EUR/USD' not in corrected:
                corrected.append('EUR/USD')

        return corrected[:10] or ['EUR/USD']

    if broker_name in ('Exness', 'XM', 'XM Global'):
        if not symbols:
            return ['EURUSDm']
        corrected = []
        for symbol in symbols:
            mapped = normalize_symbol_for_broker(symbol, broker_name)
            if mapped and mapped not in corrected:
                corrected.append(mapped)
            else:
                logger.warning(f'⚠️ Unknown {broker_name} symbol {symbol} -> defaulting to EURUSDm')
                if 'EURUSDm' not in corrected:
                    corrected.append('EURUSDm')
        return corrected[:10] or ['EURUSDm']

    if not symbols:
        return ['EURUSDm']  # Default fallback to Exness EURUSDm
    
    corrected = []
    for symbol in symbols:
        raw_symbol = str(symbol or '').strip()
        normalized_symbol = raw_symbol.upper().replace('/', '').replace('_', '')

        if normalized_symbol in VALID_SYMBOLS:
            # Symbol is valid - keep it
            corrected.append(normalized_symbol)
        elif normalized_symbol.endswith('M') and normalized_symbol[:-1] in VALID_SYMBOLS:
            suffixed_symbol = normalized_symbol[:-1] + 'm'
            logger.info(f"Preserving MT5 suffix for symbol {raw_symbol} -> {suffixed_symbol}")
            if suffixed_symbol not in corrected:
                corrected.append(suffixed_symbol)
        elif raw_symbol in SYMBOL_MAPPING or normalized_symbol in SYMBOL_MAPPING:
            # Symbol is old - map to new one
            new_symbol = SYMBOL_MAPPING.get(raw_symbol, SYMBOL_MAPPING.get(normalized_symbol))
            if raw_symbol.lower().endswith('m') and str(new_symbol).upper() in VALID_SYMBOLS:
                new_symbol = f"{str(new_symbol).upper()}m"
            logger.warning(f"🔄 Auto-correcting symbol {raw_symbol} -> {new_symbol} based on configured Exness symbol mappings")
            if new_symbol not in corrected:
                corrected.append(new_symbol)
        else:
            # Unknown symbol - use fallback to valid Exness symbol
            logger.warning(f"⚠️  Unknown symbol {raw_symbol} - using EURUSDm fallback based on current Exness defaults")
            if 'EURUSDm' not in corrected:
                corrected.append('EURUSDm')
    
    # Ensure we have at least one symbol
    if not corrected:
        corrected = ['EURUSDm']
    
    # Remove duplicates while preserving order
    seen = set()
    final = []
    for s in corrected:
        if s not in seen:
            final.append(s)
            seen.add(s)
    
    return final[:10]  # Limit to 10 symbols max

