# ==================== REAL TECHNICAL INDICATOR CALCULATIONS ====================

def calculate_rsi(prices, period=14):
    """Calculate Relative Strength Index (RSI) from price list
    
    RSI > 70 = Overbought (SELL signal)
    RSI < 30 = Oversold (BUY signal)
    RSI 30-70 = Neutral
    """
    if len(prices) < period + 1:
        return 50  # Neutral if insufficient data
    
    # Calculate price changes
    deltas = [prices[i] - prices[i-1] for i in range(1, len(prices))]
    
    # Separate gains and losses
    gains = [d if d > 0 else 0 for d in deltas]
    losses = [-d if d < 0 else 0 for d in deltas]
    
    # Calculate average gain and loss
    avg_gain = sum(gains[-period:]) / period
    avg_loss = sum(losses[-period:]) / period
    
    if avg_loss == 0:
        return 100 if avg_gain > 0 else 50
    
    rs = avg_gain / avg_loss
    rsi = 100 - (100 / (1 + rs))
    
    return min(100, max(0, rsi))


def calculate_macd(prices, fast=12, slow=26, signal=9):
    """Calculate MACD (Moving Average Convergence Divergence) using proper EMA.

    Returns: (macd_line, signal_line, histogram)
    - MACD > Signal = BUY signal
    - MACD < Signal = SELL signal
    """
    def _ema(data, period):
        """True EMA: seed with SMA of first `period` values, then smooth."""
        if len(data) < period:
            return data[-1] if data else 0.0
        alpha = 2.0 / (period + 1)
        ema_val = sum(data[:period]) / period  # SMA seed
        for price in data[period:]:
            ema_val = alpha * price + (1.0 - alpha) * ema_val
        return ema_val

    min_len = slow + signal
    if len(prices) < min_len:
        return 0.0, 0.0, 0.0

    # Build a series of MACD values over the last `signal` windows so we can
    # compute a proper EMA signal line instead of a single-sample approximation.
    macd_series = []
    for offset in range(signal, 0, -1):
        sub = prices[:-offset]
        if len(sub) >= slow:
            macd_series.append(_ema(sub, fast) - _ema(sub, slow))

    # Current MACD value
    macd_line = _ema(prices, fast) - _ema(prices, slow)
    macd_series.append(macd_line)

    # Signal line = EMA(9) of the MACD series
    signal_line = _ema(macd_series, min(signal, len(macd_series)))
    histogram = macd_line - signal_line

    return macd_line, signal_line, histogram


def calculate_moving_averages(prices, short=10, long=20):
    """Calculate short and long moving averages
    
    Returns: (sma_short, sma_long)
    - Price > MA20 = Uptrend
    - Price < MA20 = Downtrend
    - MA10 > MA20 = Strong uptrend
    """
    if len(prices) < long:
        return prices[-1] if prices else 0, prices[-1] if prices else 0
    
    sma_short = sum(prices[-short:]) / short
    sma_long = sum(prices[-long:]) / long
    
    return sma_short, sma_long


def calculate_atr(highs, lows, closes, period=14):
    """Calculate Average True Range (ATR) for volatility measurement
    
    Higher ATR = More volatile
    Lower ATR = Less volatile
    
    Used for position sizing: wider stops on high ATR, tighter on low ATR
    """
    if len(closes) < period:
        return 0.5  # Default minimum ATR
    
    true_ranges = []
    for i in range(1, len(closes)):
        high_low = highs[i] - lows[i]
        high_close = abs(highs[i] - closes[i-1])
        low_close = abs(lows[i] - closes[i-1])
        tr = max(high_low, high_close, low_close)
        true_ranges.append(tr)
    
    atr = sum(true_ranges[-period:]) / period if true_ranges else 0.5
    return max(atr, 0.1)  # Ensure minimum of 0.1


# ==================== HIGH VOLATILITY UPSWING DETECTION (5-10 SECOND MICRO-TRADING) ====================

def calculate_fast_stochastic_rsi(prices, period=5, smooth_k=3, smooth_d=3):
    """Fast Stochastic RSI for 5-second candle detection
    
    Detects quick momentum shifts in micro timeframes
    Returns: (stoch_k, stoch_d)
    - Stoch K > 80 = Overbought micro-spike (SELL)
    - Stoch K < 20 = Oversold micro-dip (BUY)
    - K crossing D upward = Quick bullish momentum
    """
    # First calculate RSI on short period
    if len(prices) < period + 1:
        return 50, 50
    
    rsi = calculate_rsi(prices, period=period)
    
    # Apply Stochastic to RSI (not price) - this is the fast oscillator
    if len(prices) < period + smooth_d:
        return rsi, rsi
    
    # For true multi-candle stochastic, we need RSI history
    # Simple approximation: use RSI momentum
    rsi_momentum = rsi - calculate_rsi(prices[:-1], period=period) if len(prices) > period + 1 else 0
    stoch_k = 50 + (rsi_momentum * 10)  # Convert momentum to stochastic-like value
    stoch_k = min(100, max(0, stoch_k))
    stoch_d = rsi  # Use current RSI as signal line approximation
    
    return stoch_k, stoch_d


def detect_volatility_spike(market_data: Dict, baseline_volatility: float = 1.0, spike_threshold: float = 2.0) -> bool:
    """Detect sudden volatility spike opportunity
    
    When volatility > 2x baseline, quick upswings and reversals become likely
    Returns: True if major spike detected
    """
    current_vol = market_data.get('volatility_pct', 1.0)
    
    # Detect if current volatility is significantly above baseline
    if current_vol > baseline_volatility * spike_threshold:
        return True
    
    # Also check if volatility is rising rapidly (volatility of volatility)
    vol_history = market_data.get('volatility_history', [baseline_volatility] * 10)[-10:]
    if len(vol_history) >= 3:
        recent_avg = sum(vol_history[-3:]) / 3
        older_avg = sum(vol_history[:-3]) / max(len(vol_history) - 3, 1)
        if recent_avg > older_avg * 1.5:  # Volatility expanding 50% in last 3 periods
            return True
    
    return False


def detect_upswing_peak_or_bottom(prices: List[float], window: int = 5) -> Dict:
    """Detect if price just hit a peak or bottom (potential reversal)
    
    For catching 5-10 second upswings - identifies the exact reversal point
    Returns: {
        'is_peak': bool (price likely to reverse down),
        'is_bottom': bool (price likely to bounce up),
        'momentum': float (-1 to +1, positive = upward momentum),
        'strength': float (0-100, how strong the peak/bottom signal is)
    }
    """
    if len(prices) < window + 2:
        return {'is_peak': False, 'is_bottom': False, 'momentum': 0, 'strength': 0}
    
    current_price = prices[-1]
    recent = prices[-window:]
    older = prices[-(window*2):-window]
    
    # Check if current is near peak of recent window
    recent_max = max(recent)
    recent_min = min(recent)
    older_max = max(older)
    older_min = min(older)
    
    recent_range = recent_max - recent_min
    older_range = older_max - older_min
    
    # Peak detection: recent high + price pulled back slightly
    is_peak = (
        (recent_max - current_price) / recent_max < 0.002 and  # Within 0.2% of recent high
        current_price > older_max  # But still above older window
    )
    
    # Bottom detection: recent low + price bounced slightly
    is_bottom = (
        (current_price - recent_min) / recent_min < 0.002 and  # Within 0.2% of recent low
        current_price < older_min  # And below older window
    )
    
    # Calculate momentum
    momentum = (prices[-1] - prices[-2]) / prices[-2] if prices[-2] != 0 else 0
    
    # Strength based on how extreme the peak/bottom is
    strength = 0
    if is_peak:
        strength = min(100, (recent_range / current_price) * 10000)  # Larger range = stronger peak
    elif is_bottom:
        strength = min(100, (recent_range / current_price) * 10000)
    
    return {
        'is_peak': is_peak,
        'is_bottom': is_bottom,
        'momentum': momentum,
        'strength': strength,
    }


def detect_support_bounce_entry(prices: List[float], rsis: List[float], window: int = 10) -> Dict:
    """Detect when price bounces off support with RSI divergence
    
    Classic quick-reversal setup: price hits support + RSI starts rising
    Good for catching 5-8 second upswings after downswings
    Returns: {
        'is_bounce': bool (price bouncing from support),
        'bounce_strength': float (0-100),
        'rsi_divergence': float (how much RSI improving vs price),
    }
    """
    if len(prices) < window or len(rsis) < window:
        return {'is_bounce': False, 'bounce_strength': 0, 'rsi_divergence': 0}
    
    recent_prices = prices[-window:]
    recent_rsis = rsis[-window:]
    
    # Find recent low
    low_price_idx = recent_prices.index(min(recent_prices))
    low_rsi_idx = recent_rsis.index(min(recent_rsis))
    
    current_price = prices[-1]
    current_rsi = rsis[-1]
    low_price = recent_prices[low_price_idx]
    low_rsi = recent_rsis[low_rsi_idx]
    
    # Bounce detected when:
    # 1. Price is rising from recent low
    # 2. RSI is rising from oversold
    # 3. There's a divergence (RSI improving faster than price)
    
    price_pct_from_low = (current_price - low_price) / low_price if low_price > 0 else 0
    is_bounce = (
        price_pct_from_low > 0.0005 and  # Price is at least 0.05% above recent low
        current_rsi > low_rsi and  # RSI is rising
        low_rsi < 35  # Low RSI was in oversold zone
    )
    
    # Calculate how strong the bounce is
    bounce_strength = 0
    if is_bounce:
        price_recovery = (price_pct_from_low / 0.005) * 100  # Normalize to 100 for 0.5% move
        rsi_recovery = ((current_rsi - low_rsi) / 70) * 100  # Normalize RSI move to 100
        bounce_strength = min(100, (price_recovery + rsi_recovery) / 2)
    
    # RSI divergence: how much RSI improved vs price
    rsi_divergence = ((current_rsi - low_rsi) - (price_pct_from_low * 1000)) / 100
    
    return {
        'is_bounce': is_bounce,
        'bounce_strength': bounce_strength,
        'rsi_divergence': min(100, max(0, rsi_divergence)),
    }


def evaluate_micro_volatility_signal(symbol: str, market_data: Dict) -> Dict:
    """Evaluate micro-trading signals for 5-10 second upswings in high volatility
    
    This supplements the main signal evaluation with micro-timeframe opportunities
    Returns: {
        'micro_signal': 'QUICK_BUY' | 'QUICK_SELL' | 'HOLD',
        'entry_window_seconds': int (how long to allow entry after signal),
        'strength': 0-100,
        'micro_reason': string explanation,
        'volatility_spike': bool (major volatility detected),
    }
    """
    try:
        # Get baseline volatility for this symbol
        symbol_key = symbol[:-1] if symbol.endswith('m') else symbol
        symbol_key = symbol_key.upper()
        params = SYMBOL_PARAMETERS.get(symbol_key, DEFAULT_SYMBOL_PARAMS)
        baseline_vol = (params['volatility_low'] + params['volatility_high']) / 2
        
        current_vol = market_data.get('volatility_pct', baseline_vol)
        price_history = market_data.get('price_history', [])
        
        if len(price_history) < 10:
            return {
                'micro_signal': 'HOLD',
                'entry_window_seconds': 0,
                'strength': 0,
                'micro_reason': 'Insufficient price history for micro analysis',
                'volatility_spike': False,
            }
        
        # Check if volatility spike detected
        vol_spike = detect_volatility_spike(market_data, baseline_vol, spike_threshold=1.8)
        
        if not vol_spike:
            return {
                'micro_signal': 'HOLD',
                'entry_window_seconds': 0,
                'strength': 0,
                'micro_reason': 'No volatility spike detected',
                'volatility_spike': False,
            }
        
        # During volatility spike, check for micro entry signals
        peak_bottom = detect_upswing_peak_or_bottom(price_history, window=5)
        
        # Calculate RSI for bounce detection
        rsi_values = [calculate_rsi(price_history[max(0, i-14):i], period=14) for i in range(14, len(price_history))]
        bounce = detect_support_bounce_entry(price_history[-10:], rsi_values[-10:] if len(rsi_values) >= 10 else [50]*10, window=10)
        
        micro_signal = 'HOLD'
        strength = 0
        micro_reason = []
        entry_window = 0
        
        # QUICK_BUY opportunities during volatility spike
        if vol_spike and bounce['is_bounce']:
            micro_signal = 'QUICK_BUY'
            strength = int(bounce['bounce_strength'])
            entry_window = 8  # Allow 8 second entry window
            micro_reason.append(f'Support bounce detected during volatility spike (strength: {bounce["bounce_strength"]:.0f}%)')
            
            if peak_bottom['is_bottom']:
                strength += 15
                entry_window = 10  # Extend window if we hit a peak/bottom
                micro_reason.append('Price at micro-bottom - strong reversal setup')
        
        elif vol_spike and peak_bottom['is_bottom'] and peak_bottom['momentum'] > 0.0001:
            micro_signal = 'QUICK_BUY'
            strength = int(peak_bottom['strength']) + 20
            entry_window = 8
            micro_reason.append(f'Upswing detected from recent bottom (momentum: {peak_bottom["momentum"]:.6f})')
        
        # QUICK_SELL opportunities during volatility spike
        elif vol_spike and peak_bottom['is_peak'] and peak_bottom['momentum'] < -0.0001:
            micro_signal = 'QUICK_SELL'
            strength = int(peak_bottom['strength']) + 20
            entry_window = 8
            micro_reason.append(f'Downswing detected from recent peak (momentum: {peak_bottom["momentum"]:.6f})')
        
        # Secondary: check fast stochastic on volatility spike alone
        if micro_signal == 'HOLD' and vol_spike:
            fast_stoch_k, fast_stoch_d = calculate_fast_stochastic_rsi(price_history[-10:] if len(price_history) >= 10 else price_history, period=5)
            
            if fast_stoch_k < 25 and fast_stoch_d < fast_stoch_k:
                micro_signal = 'QUICK_BUY'
                strength = 45
                entry_window = 6
                micro_reason.append(f'Fast Stochastic RSI oversold during spike (K:{fast_stoch_k:.0f})')
            
            elif fast_stoch_k > 75 and fast_stoch_d < fast_stoch_k:
                micro_signal = 'QUICK_SELL'
                strength = 45
                entry_window = 6
                micro_reason.append(f'Fast Stochastic RSI overbought during spike (K:{fast_stoch_k:.0f})')
        
        return {
            'micro_signal': micro_signal,
            'entry_window_seconds': entry_window,
            'strength': min(100, strength),
            'micro_reason': ' + '.join(micro_reason) if micro_reason else 'Checking micro conditions...',
            'volatility_spike': vol_spike,
        }
    
    except Exception as e:
        logger.warning(f"Error in micro volatility signal for {symbol}: {e}")
        return {
            'micro_signal': 'HOLD',
            'entry_window_seconds': 0,
            'strength': 0,
            'micro_reason': f'Micro analysis error: {str(e)}',
            'volatility_spike': False,
        }


def evaluate_real_trade_signal(symbol: str, market_data: Dict) -> Dict:
    """Evaluate a REAL trading signal based on technical indicators - OPTIMIZED FOR HIGH WIN RATE
    
    Returns: {
        'signal': 'STRONG_BUY' | 'BUY' | 'SELL' | 'STRONG_SELL' | 'NEUTRAL',
        'strength': 0-100,  # Signal confidence
        'rsi': RSI value,
        'trend': 'UP' | 'DOWN' | 'RANGING',
        'volatility': 'HIGH' | 'MEDIUM' | 'LOW',
        'entry_reason': string explanation,
    }
    
    KEY CHANGES FOR BETTER WIN RATE:
    1. Only BUY when RSI < 35 (not 45) and MACD confirms
    2. Only SELL when RSI > 65 (not 55) and MACD confirms  
    3. Require MACD crossover + RSI extreme + Trend alignment
    4. Skip RANGING markets entirely (no low-probability trades)
    5. Higher signal threshold reduces false entries
    """
    try:
        # Get price data from market_data
        current_price = market_data.get('current_price', 0) or market_data.get('price', 0)
        if current_price <= 0:
            return {
                'signal': 'NEUTRAL',
                'strength': 0,
                'rsi': 50,
                'trend': 'RANGING',
                'volatility': 'MEDIUM',
                'entry_reason': 'Invalid price data',
            }
        
        # Get price history
        price_history = market_data.get('price_history', [current_price] * 50)[-50:]
        if len(price_history) < 5:
            price_history = [current_price] * 50
        
        # Calculate technical indicators
        rsi = calculate_rsi(price_history, period=14)
        ma_short, ma_long = calculate_moving_averages(price_history, short=10, long=20)
        macd_line, signal_line, histogram = calculate_macd(price_history)
        
        # Normalize broker display symbols to the underlying analysis symbol for param lookup.
        symbol_key = _resolve_analysis_symbol(str(market_data.get('analysis_symbol') or symbol))
        if not symbol_key:
            symbol_key = _normalize_symbol_base(symbol)

        # Determine trend — use dead zone around ma_long to avoid flip-flopping
        ma_diff_pct = (current_price - ma_long) / ma_long * 100 if ma_long > 0 else 0
        if ma_diff_pct > 0.15:  # clearly above MA → uptrend
            trend = 'UP' if ma_short > ma_long else 'RANGING'
        elif ma_diff_pct < -0.15:  # clearly below MA → downtrend
            trend = 'DOWN'
        else:  # price near ma_long → consolidating
            if ma_short > ma_long:
                trend = 'UP'
            elif ma_short < ma_long:
                trend = 'DOWN'
            else:
                trend = 'RANGING'
        
        # Determine volatility from market data
        volatility_pct = market_data.get('volatility_pct', 1.0)
        params = SYMBOL_PARAMETERS.get(symbol_key, DEFAULT_SYMBOL_PARAMS)
        
        if volatility_pct > params['volatility_high']:
            volatility = 'HIGH'
        elif volatility_pct > params['volatility_low']:
            volatility = 'MEDIUM'
        else:
            volatility = 'LOW'
        
        # OPTIMIZED SIGNAL GENERATION - HIGH WIN RATE FILTERS
        strength = 0
        signal = 'NEUTRAL'
        entry_reason = []
        
        # ✅ AGGRESSIVE: Allow trades in ALL market conditions including RANGING
        # (previously rejected RANGING markets as low probability)
        
        # Determine MACD confirmation and fresh crossover
        macd_prev_histogram = 0
        if len(price_history) >= 36:
            _, _, macd_prev_histogram = calculate_macd(price_history[:-1])
        macd_just_crossed_bullish = histogram > 0 and macd_prev_histogram <= 0
        macd_just_crossed_bearish = histogram < 0 and macd_prev_histogram >= 0
        macd_signal = 'NEUTRAL'
        if histogram > 0 and macd_line > signal_line:
            macd_signal = 'BUY'
        elif histogram < 0 and macd_line < signal_line:
            macd_signal = 'SELL'
        macd_strength = abs(histogram)
        trend_gap_pct = abs(ma_short - ma_long) / ma_long * 100 if ma_long > 0 else 0
        strong_trend = trend_gap_pct >= 0.18
        
        # RSI-based signals - STRICTER THRESHOLDS for high win rate
        rsi_signal = 'NEUTRAL'
        rsi_strength = 0
        
        if rsi < 33:  # Strong oversold
            rsi_signal = 'BUY'
            rsi_strength = 35
            entry_reason.append(f'RSI deeply oversold ({rsi:.0f})')
        elif rsi < 42:  # Moderate oversold
            rsi_signal = 'BUY'
            rsi_strength = 25
            entry_reason.append(f'RSI oversold ({rsi:.0f})')
        elif rsi < 52 and macd_signal == 'BUY' and (trend == 'UP' or macd_just_crossed_bullish):
            rsi_signal = 'BUY'
            rsi_strength = 20
            entry_reason.append(f'RSI neutral ({rsi:.0f}) + uptrend/MACD crossover')
        elif rsi > 67:  # Strong overbought
            rsi_signal = 'SELL'
            rsi_strength = 35
            entry_reason.append(f'RSI deeply overbought ({rsi:.0f})')
        elif rsi > 60:  # Moderate overbought
            rsi_signal = 'SELL'
            rsi_strength = 25
            entry_reason.append(f'RSI overbought ({rsi:.0f})')
        elif rsi > 50 and macd_signal == 'SELL' and (trend == 'DOWN' or macd_just_crossed_bearish):
            rsi_signal = 'SELL'
            rsi_strength = 20
            entry_reason.append(f'RSI neutral ({rsi:.0f}) + downtrend/MACD crossover')
        else:
            # Neutral RSI zone — trade on MACD or trend confirmation.
            if macd_signal == 'BUY' and (trend == 'UP' or macd_just_crossed_bullish):
                rsi_signal = 'BUY'
                rsi_strength = 15
                entry_reason.append(f'RSI neutral ({rsi:.0f}) + trend/MACD confirmation')
            elif macd_signal == 'SELL' and (trend == 'DOWN' or macd_just_crossed_bearish):
                rsi_signal = 'SELL'
                rsi_strength = 15
                entry_reason.append(f'RSI neutral ({rsi:.0f}) + trend/MACD confirmation')
            else:
                fallback_buy = (
                    macd_signal == 'BUY'
                    and macd_just_crossed_bullish
                    and 35 <= rsi <= 62
                )
                fallback_sell = (
                    macd_signal == 'SELL'
                    and macd_just_crossed_bearish
                    and 38 <= rsi <= 65
                )
                if fallback_buy or fallback_sell:
                    rsi_signal = 'BUY' if fallback_buy else 'SELL'
                    rsi_strength = 8
                    entry_reason.append(
                        f'RSI neutral ({rsi:.0f}) + fresh MACD crossover'
                    )
                else:
                    rsi_strength = 0
                    entry_reason.append(f'RSI neutral ({rsi:.0f})')
        
        strength += rsi_strength
        signal = rsi_signal

        extreme_reversal_setup = (
            signal != 'NEUTRAL'
            and rsi_strength >= 35
            and volatility in {'LOW', 'MEDIUM'}
        )
        
        # Only add MACD strength if it CONFIRMS RSI signal
        if signal != 'NEUTRAL':
            if macd_signal == signal:
                strength += 25  # Good confirmation
                entry_reason.append(f'MACD confirms {signal}')
                
                # Extra bonus if crossover is fresh
                if (signal == 'BUY' and macd_just_crossed_bullish) or (signal == 'SELL' and macd_just_crossed_bearish):
                    strength += 15
                    entry_reason.append('MACD crossover detected')
            else:
                conflict_penalty = 5 if extreme_reversal_setup else 15
                strength -= conflict_penalty
                if extreme_reversal_setup:
                    entry_reason.append('MACD conflicts with RSI signal but extreme reversal setup is still tradable')
                else:
                    entry_reason.append(f'MACD conflicts with RSI signal')
                if strength < 0:
                    signal = 'NEUTRAL'
                    entry_reason.append('Dropped due to conflicting momentum')
        
        # Trend confirmation bonus
        if signal != 'NEUTRAL':
            if (signal == 'BUY' and trend == 'UP') or (signal == 'SELL' and trend == 'DOWN'):
                strength += 15
                entry_reason.append(f'Trend {trend} confirms signal')
            elif trend == 'RANGING':
                strength -= 20  # Penalize if no clear trend
                if strength < 35:  # Strength too low if ranging
                    signal = 'NEUTRAL'
        
        # Volatility adjustment - SKIP high volatility trades
        if volatility == 'HIGH':
            strength -= 15  # Significant penalty
            entry_reason.append(f'High volatility - reduced confidence')
            if strength < 40:  # Too risky, skip
                signal = 'NEUTRAL'
        elif volatility == 'LOW':
            strength += 10
            entry_reason.append('Low volatility - favorable conditions')

        # Confidence scaling: only amplify setups that already have stacked confirmation.
        # This lifts high-quality signals into a more useful visible range without broadly
        # weakening the underlying entry filters.
        if signal != 'NEUTRAL':
            confirmation_count = 0
            if rsi_strength >= 20:
                confirmation_count += 1
            if macd_signal == signal:
                confirmation_count += 1
            if (signal == 'BUY' and trend == 'UP') or (signal == 'SELL' and trend == 'DOWN'):
                confirmation_count += 1
            if strong_trend:
                confirmation_count += 1
            if volatility == 'LOW':
                confirmation_count += 1

            if strong_trend:
                trend_bonus = 8 if trend_gap_pct >= 0.35 else 4
                strength += trend_bonus
                entry_reason.append(f'Trend separation bonus (+{trend_bonus})')

            if abs(ma_diff_pct) >= 0.35:
                strength += 4
                entry_reason.append('Price extended away from trend base')

            if confirmation_count >= 4:
                strength = (strength * 1.18) + 6
                entry_reason.append('Stacked confirmations boosted confidence')
            elif confirmation_count == 3:
                strength = (strength * 1.10) + 4
                entry_reason.append('Multi-factor confirmation boosted confidence')
            elif confirmation_count == 2 and strength >= 35:
                strength += 3
                entry_reason.append('Dual confirmation support')
        
        # Final strength bounds
        strength = min(100, max(0, strength))
        
        # Debug logging for signal evaluation
        if symbol in ['ETHUSD', 'BTCUSD', 'XAUUSD']:
            logger.debug(f"[SIGNAL-OPTIMIZED] {symbol}: rsi={rsi:.1f} macd_h={histogram:.6f} trend={trend} vol={volatility} sig={signal} str={strength} reasons={entry_reason}")
        
        # Determine signal strength category
        if signal != 'NEUTRAL':
            if strength >= 70:
                signal = f'STRONG_{signal}'
            entry_reason.append(f'Confidence: {strength:.0f}%')
        
        # Check for micro-volatility upswing opportunities during high volatility
        micro_signal_eval = evaluate_micro_volatility_signal(symbol, market_data)
        micro_signal = micro_signal_eval.get('micro_signal', 'HOLD')
        micro_strength = micro_signal_eval.get('strength', 0)
        
        # If micro signal is active and macro signal is weak/neutral, prefer micro signal
        entry_window = 0
        if micro_signal != 'HOLD' and micro_strength >= 45:
            if signal == 'NEUTRAL' or strength < 50:
                # Use micro signal as primary during high volatility
                if micro_signal == 'QUICK_BUY':
                    signal = 'QUICK_BUY'
                    strength = micro_strength
                    entry_window = micro_signal_eval.get('entry_window_seconds', 8)
                    entry_reason.append(f'MICRO: {micro_signal_eval.get("micro_reason", "")} [{entry_window}s window]')
                elif micro_signal == 'QUICK_SELL':
                    signal = 'QUICK_SELL'
                    strength = micro_strength
                    entry_window = micro_signal_eval.get('entry_window_seconds', 8)
                    entry_reason.append(f'MICRO: {micro_signal_eval.get("micro_reason", "")} [{entry_window}s window]')
        
        return {
            'signal': signal,
            'strength': strength,
            'rsi': round(rsi, 1),
            'trend': trend,
            'volatility': volatility,
            'entry_reason': ' + '.join(entry_reason) if entry_reason else 'Neutral: No clear setup',
            'micro_signal': micro_signal if micro_signal != 'HOLD' else None,
            'entry_window_seconds': entry_window,  # NEW: For time-limited quick entries
        }
    
    except Exception as e:
        logger.warning(f"Error evaluating signal for {symbol}: {e}")
        return {
            'signal': 'NEUTRAL',
            'strength': 0,
            'rsi': 50,
            'trend': 'RANGING',
            'volatility': 'MEDIUM',
            'entry_reason': f'Error: {str(e)}',
        }


# ==================== BOT TRADING STRATEGY IMPLEMENTATIONS (REAL MARKET BASED) ====================

def scalping_strategy(symbol, account_id, risk_amount, market_data=None):
    """Scalping: Quick trades with small profits (2-3 pips). HIGH WIN RATE, LOW REWARD.
    
    Best for: Liquid pairs (EURUSD), low volatility
    Entry: Strong support/resistance, RSI extreme
    Exit: Quick profit or bounceback stop
    ENHANCED: Now includes micro-volatility upswings (5-10 second opportunities)
    """
    if market_data is None:
        market_data = commodity_market_data.get(symbol, {})

    if _normalize_symbol_base(symbol) in SMALL_LIVE_ACCOUNT_OPTIONAL_CRYPTO_BASE_SYMBOLS:
        return None
    
    signal_eval = evaluate_real_trade_signal(symbol, market_data)
    params = _get_effective_symbol_params(symbol, market_data)
    
    # Check for micro-volatility quick entry (lower threshold during spikes)
    min_signal_strength = params['effective_min_signal_strength']
    
    # For QUICK_BUY/QUICK_SELL micro signals, use lower threshold (45 instead of 50+)
    if signal_eval.get('signal') in ['QUICK_BUY', 'QUICK_SELL']:
        min_signal_strength = 40  # Aggressive on micro-volatility setups
    
    # Check if signal is strong enough
    if signal_eval['strength'] < min_signal_strength:
        return None  # Don't trade on weak signal
    
    # Determine direction from signal
    order_type = extract_signal_direction(signal_eval.get('signal'))
    if order_type is None:
        return None
    
    # Adjust parameters for micro-volatility quick trades
    entry_window = signal_eval.get('entry_window_seconds', 0)
    if entry_window > 0:
        # Very tight stops/targets for quick upswings
        stop_loss = params['stop_loss_pips'] * 0.2  # Aggressive 1/5 of normal
        take_profit = params['take_profit_pips'] * 0.15  # Very tight TP for fast exits
        duration = entry_window + 1  # Exit immediately after entry window
    else:
        # Normal scalping parameters - optimized for quicker trades
        stop_loss = params['stop_loss_pips'] * 0.4  # Tighter stop for faster exits
        take_profit = params['take_profit_pips'] * 0.25  # Reduced TP (3-5 pips) for quick wins
        duration = 180  # 3 minute scalp (was 5 min) - get in and out faster
    
    # Tight parameters for scalping
    return {
        'symbol': symbol,
        'type': order_type,
        'volume': 1.0 * (1.0 if signal_eval['strength'] > 70 else 0.7),  # Position size based on signal strength
        'stop_loss': stop_loss,
        'take_profit': take_profit,
        'signal': attach_execution_direction(signal_eval, order_type, 'Scalping'),
        'duration_seconds': duration,
        'is_micro_volatility_trade': entry_window > 0,  # Flag for quick upswing trades
        'entry_window_seconds': entry_window,  # Track time window
    }


def high_volatility_upswing_strategy(symbol, account_id, risk_amount, market_data=None):
    """HIGH VOLATILITY UPSWING STRATEGY: Specialized for 5-10 second micro-reversals
    
    Targets: Quick bounces, micro peaks/bottoms during volatility spikes
    Entry: Support bounce, fast stochastic extremes, volatility spike + momentum
    Exit: Very tight (1-2 pips), immediate on reversal signal
    Risk: Lower per-trade but higher frequency  
    Win Rate: HIGH (80%+) due to micro-timeframe mean reversion
    """
    if market_data is None:
        market_data = commodity_market_data.get(symbol, {})

    if _normalize_symbol_base(symbol) in SMALL_LIVE_ACCOUNT_OPTIONAL_CRYPTO_BASE_SYMBOLS:
        return None
    
    signal_eval = evaluate_micro_volatility_signal(symbol, market_data)
    micro_signal = signal_eval.get('micro_signal', 'HOLD')
    micro_strength = signal_eval.get('strength', 0)
    entry_window = signal_eval.get('entry_window_seconds', 0)
    
    # Only trade if micro signal is active and volatility spike confirmed
    if micro_signal == 'HOLD' or not signal_eval.get('volatility_spike', False):
        return None
    
    # Lower threshold for micro trades (volatility spike context makes reversal likely)
    if micro_strength < 42:
        return None
    
    # Determine direction
    if micro_signal == 'QUICK_BUY':
        order_type = 'BUY'
    elif micro_signal == 'QUICK_SELL':
        order_type = 'SELL'
    else:
        return None
    
    params = _get_effective_symbol_params(symbol, market_data)
    
    # ULTRA-TIGHT parameters for micro-upswing trades
    # The whole trade lasts seconds, not minutes
    return {
        'symbol': symbol,
        'type': order_type,
        'volume': 0.5,  # Smaller position (more frequent trades)
        'stop_loss': params['stop_loss_pips'] * 0.15,  # Micro stop (1-2 pips)
        'take_profit': params['take_profit_pips'] * 0.1,  # Micro profit (0.5-1 pip)
        'signal': f'[MICRO-UPSWING] {signal_eval.get("micro_reason", "")}',
        'duration_seconds': entry_window + 1,  # Close after entry window expires
        'is_micro_volatility_trade': True,
        'entry_window_seconds': entry_window,
        'volatility_spike_strength': signal_eval.get('volatility_spike', False),
    }


def momentum_strategy(symbol, account_id, risk_amount, market_data=None):
    """Momentum: Follow strong price movements. MODERATE WIN RATE, GOOD REWARDS.
    
    Best for: Trending markets, moving averages aligned
    Entry: Price breaks above/below key level with volume
    Exit: Profit target or MA crossover
    """
    if market_data is None:
        market_data = commodity_market_data.get(symbol, {})

    if _normalize_symbol_base(symbol) in SMALL_LIVE_ACCOUNT_OPTIONAL_CRYPTO_BASE_SYMBOLS:
        return None
    
    signal_eval = evaluate_real_trade_signal(symbol, market_data)
    params = _get_effective_symbol_params(symbol, market_data)
    min_signal_strength = params['effective_min_signal_strength']
    
    # Only trade strong signals in momentum mode
    if signal_eval['strength'] < min_signal_strength + 5:
        return None
    
    # Only trade if trend exists
    if signal_eval['trend'] == 'RANGING':
        return None
    
    order_type = 'BUY' if signal_eval['trend'] == 'UP' else 'SELL'
    signal_direction = extract_signal_direction(signal_eval.get('signal'))
    if signal_direction != order_type:
        return None
    
    return {
        'symbol': symbol,
        'type': order_type,
        'volume': 1.5 * (signal_eval['strength'] / 80),  # Scale with signal strength
        'stop_loss': params['stop_loss_pips'],
        'take_profit': params['take_profit_pips'] * 1.5,  # Bigger TP for momentum
        'signal': attach_execution_direction(signal_eval, order_type, 'Momentum Trading'),
        'duration_seconds': 900,  # 15 minutes
    }


def trend_following_strategy(symbol, account_id, risk_amount, market_data=None):
    """Trend Following: Hold trades longer (big trends). LOWER WIN RATE, HIGHER REWARDS.
    
    Best for: Long-term trending markets
    Entry: Breakout on trend confirmation
    Exit: Trend reversal or fixed profit target
    """
    if market_data is None:
        market_data = commodity_market_data.get(symbol, {})
    
    signal_eval = evaluate_real_trade_signal(symbol, market_data)
    params = _get_effective_symbol_params(symbol, market_data)
    min_signal_strength = params['effective_min_signal_strength']
    symbol_base = _normalize_symbol_base(symbol)
    
    # Trend following needs trend + signal (ranging allowed at normal threshold)
    if signal_eval['strength'] < min_signal_strength:
        return None
    
    # Use the actual signal direction from the evaluator
    order_type = extract_signal_direction(signal_eval.get('signal'))
    if order_type is None:
        return None

    counter_trend_signal = (
        (order_type == 'BUY' and signal_eval.get('trend') == 'DOWN')
        or (order_type == 'SELL' and signal_eval.get('trend') == 'UP')
    )
    allow_extreme_crypto_reversal = (
        symbol_base in SMALL_LIVE_ACCOUNT_OPTIONAL_CRYPTO_BASE_SYMBOLS
        and signal_eval['strength'] >= max(min_signal_strength, 75)
        and signal_eval.get('volatility') in {'LOW', 'MEDIUM'}
        and (
            (order_type == 'BUY' and _safe_float(signal_eval.get('rsi'), 50.0) <= 32.0)
            or (order_type == 'SELL' and _safe_float(signal_eval.get('rsi'), 50.0) >= 68.0)
        )
    )
    if counter_trend_signal and not allow_extreme_crypto_reversal:
        return None

    signal_payload = dict(signal_eval)
    strategy_label = 'Trend Following'
    if counter_trend_signal and allow_extreme_crypto_reversal:
        existing_reason = signal_payload.get('entry_reason', '')
        signal_payload['entry_reason'] = (
            f"{existing_reason} + Trend-following crypto reversal override"
            if existing_reason else 'Trend-following crypto reversal override'
        )
        strategy_label = 'Trend Following (Crypto Reversal)'
    
    return {
        'symbol': symbol,
        'type': order_type,
        'volume': 0.9,
        'stop_loss': params['stop_loss_pips'] * 1.3,  # Wider stop for trend
        'take_profit': params['take_profit_pips'] * 1.5,  # Realistic TP (was 2.0x causing under-execution)
        'signal': attach_execution_direction(signal_payload, order_type, strategy_label),
        'duration_seconds': 1800,  # 30 minutes (was 3600) - let trend develop but don't hold overnight
    }


def mean_reversion_strategy(symbol, account_id, risk_amount, market_data=None):
    """Mean Reversion: Trade when price extreme. HIGH WIN RATE, MEDIUM REWARDS.
    
    Best for: Ranging markets, overbought/oversold conditions
    Entry: RSI extreme (>70 or <30)
    Exit: Return to mean or fixed profit
    """
    if market_data is None:
        market_data = commodity_market_data.get(symbol, {})

    # Block Mean Reversion on strongly-trending symbols (e.g. ZAR pairs).
    # These pairs trend persistently; mean reversion trades against the move and incur large losses.
    params = _get_effective_symbol_params(symbol, market_data)
    if params.get('mean_reversion_incompatible'):
        logger.debug(f"[Mean Reversion] Skipping {symbol} — incompatible trending pair")
        return None

    signal_eval = evaluate_real_trade_signal(symbol, market_data)
    min_signal_strength = params['effective_min_signal_strength']
    
    # Mean reversion works best when price is extreme (RSI <30 or >70)
    if not (signal_eval['rsi'] < 30 or signal_eval['rsi'] > 70):
        return None  # Only trade at extremes
    
    if signal_eval['strength'] < min_signal_strength - 5:
        return None
    
    # Trade AGAINST the extreme — sell overbought, buy oversold (mean reversion)
    order_type = 'SELL' if signal_eval['rsi'] > 70 else 'BUY'
    
    return {
        'symbol': symbol,
        'type': order_type,
        'volume': 1.1,
        'stop_loss': params['stop_loss_pips'],
        'take_profit': params['take_profit_pips'],  # Standard TP
        'signal': attach_execution_direction(signal_eval, order_type, 'Mean Reversion'),
        'duration_seconds': 600,  # 10 minutes
    }


def range_trading_strategy(symbol, account_id, risk_amount, market_data=None):
    """Range Trading: Buy low, sell high within range. VERY HIGH WIN RATE, LOWER REWARDS.
    
    Best for: Consolidating markets with clear support/resistance
    Entry: Price near support (BUY) or resistance (SELL)
    Exit: Opposite level or reversal
    """
    if market_data is None:
        market_data = commodity_market_data.get(symbol, {})
    
    signal_eval = evaluate_real_trade_signal(symbol, market_data)
    params = _get_effective_symbol_params(symbol, market_data)
    min_signal_strength = params['effective_min_signal_strength']
    
    # Range trading only works in ranging market
    if signal_eval['trend'] != 'RANGING':
        return None
    
    if signal_eval['strength'] < min_signal_strength - 10:
        return None
    
    order_type = extract_signal_direction(signal_eval.get('signal'))
    if order_type is None:
        return None
    
    return {
        'symbol': symbol,
        'type': order_type,
        'volume': 1.3,
        'stop_loss': params['stop_loss_pips'] * 0.7,  # Tighter stop for range
        'take_profit': params['take_profit_pips'] * 0.7,  # Quick exit when range breaks
        'signal': attach_execution_direction(signal_eval, order_type, 'Range Trading'),
        'duration_seconds': 480,  # 8 minutes
    }


def breakout_strategy(symbol, account_id, risk_amount, market_data=None):
    """Breakout: Trade when price breaks support/resistance. MODERATE WIN RATE, HIGH REWARDS.
    
    Best for: Price nearing key levels
    Entry: Break above/below with momentum
    Exit: Continuation target or failed breakout
    """
    if market_data is None:
        market_data = commodity_market_data.get(symbol, {})
    
    signal_eval = evaluate_real_trade_signal(symbol, market_data)
    params = _get_effective_symbol_params(symbol, market_data)
    min_signal_strength = params['effective_min_signal_strength']
    
    # Breakout needs strong signal and trend presence
    if signal_eval['strength'] < min_signal_strength + 10:
        return None
    
    if signal_eval['trend'] == 'RANGING':
        return None
    
    order_type = 'BUY' if signal_eval['trend'] == 'UP' else 'SELL'
    signal_direction = extract_signal_direction(signal_eval.get('signal'))
    if signal_direction != order_type:
        return None
    
    return {
        'symbol': symbol,
        'type': order_type,
        'volume': 1.0,
        'stop_loss': params['stop_loss_pips'] * 1.2,  # Protective stop behind level
        'take_profit': params['take_profit_pips'] * 2.5,  # Large profit target for breakout continuation
        'signal': attach_execution_direction(signal_eval, order_type, 'Breakout Trading'),
        'duration_seconds': 1200,  # 20 minutes
    }

def swing_trend_dca_strategy(symbol, account_id, risk_amount, market_data=None):
    """Swing Trend + DCA: BEST FOR SMALL ACCOUNTS ($10-$1000).

    - Only trades WITH the prevailing trend (50/200 SMA golden/death cross logic
      is embedded in evaluate_real_trade_signal via the trend field).
    - Requires RSI confirmation: in uptrend RSI must be > 40 (pullback not
      overdone); in downtrend RSI must be < 60.
    - Uses wide stops (1.5× ATR) and 1:2+ reward-to-risk for swing holding.
    - Volume is intentionally tiny (0.01 lots base) to preserve small capital.
    - Only fires on HIGH-strength signals to avoid chop.
    """
    if market_data is None:
        market_data = commodity_market_data.get(symbol, {})

    signal_eval = evaluate_real_trade_signal(symbol, market_data)
    params = _get_effective_symbol_params(symbol, market_data)

    # Must have a clear trend — no RANGING markets
    if signal_eval['trend'] == 'RANGING':
        return None

    # Need a strong signal (higher bar than normal strategies)
    min_strength = max(params['effective_min_signal_strength'] + 10, 60)
    if signal_eval['strength'] < min_strength:
        return None

    # RSI confirmation: only enter pullbacks, not chasing extremes
    rsi = signal_eval['rsi']
    if signal_eval['trend'] == 'UP' and rsi < 40:
        return None  # Pullback too deep in uptrend
    if signal_eval['trend'] == 'DOWN' and rsi > 60:
        return None  # Pullback too deep in downtrend

    order_type = extract_signal_direction(signal_eval.get('signal'))
    if order_type is None:
        return None
    if (order_type == 'BUY' and signal_eval.get('trend') != 'UP') or (order_type == 'SELL' and signal_eval.get('trend') != 'DOWN'):
        return None

    return {
        'symbol': symbol,
        'type': order_type,
        'volume': 0.01,  # Minimum lot — position sizer will scale from here
        'stop_loss': params['stop_loss_pips'] * 1.5,   # Wide stop for swing
        'take_profit': params['take_profit_pips'] * 2.5,  # 1:2.5+ R:R target
        'signal': attach_execution_direction(signal_eval, order_type, 'Swing Trend DCA'),
        'duration_seconds': 14400,  # 4 hours — swing timeframe
    }


def extract_signal_direction(signal_value: Any) -> Optional[str]:
    normalized_signal = str(signal_value or '').upper()
    if 'BUY' in normalized_signal:
        return 'BUY'
    if 'SELL' in normalized_signal:
        return 'SELL'
    return None


def attach_execution_direction(signal_eval: Dict[str, Any], order_type: str, strategy_name: str) -> Dict[str, Any]:
    enriched_signal = dict(signal_eval or {})
    enriched_signal['executionDirection'] = order_type
    enriched_signal['strategyName'] = strategy_name
    return enriched_signal


def build_scanner_symbol_universe(
    bot_config: Dict[str, Any],
    fxcm_tradable_symbol_keys: Optional[Set[str]] = None,
) -> List[str]:
    configured_symbols = bot_config.get('symbols') or []
    allow_cross_market = bool(bot_config.get('allowCrossMarketReallocation', False))
    normalized_broker = canonicalize_broker_name(
        bot_config.get('brokerName') or bot_config.get('broker_type') or 'Exness'
    )
    normalized_configured = validate_and_correct_symbols(configured_symbols, normalized_broker) if configured_symbols else []
    profile = _normalize_management_profile(bot_config.get('managementProfile'))
    broker_symbol_universe = get_mt5_ready_symbols_for_broker(normalized_broker)
    if normalized_broker == 'FXCM':
        filtered_configured = _filter_fxcm_symbols_for_tradability(normalized_configured, fxcm_tradable_symbol_keys)
        filtered_broker_symbol_universe = _filter_fxcm_symbols_for_tradability(broker_symbol_universe, fxcm_tradable_symbol_keys)
        normalized_configured = filtered_configured or normalized_configured
        broker_symbol_universe = filtered_broker_symbol_universe or broker_symbol_universe
    idle_cycles = int(bot_config.get('adaptiveSignalMissCount') or 0)
    expand_small_account_universe = idle_cycles >= ADAPTIVE_SCANNER_TRIGGER_MISSES

    if profile == 'small_account':
        account_currency = str(bot_config.get('displayCurrency') or 'USD').strip().upper()
        balance_basis = max(
            _safe_float(bot_config.get('accountEquity'), 0.0),
            _safe_float(bot_config.get('accountBalance'), 0.0),
        )
        configured_base_symbols = {
            _normalize_symbol_base(symbol)
            for symbol in normalized_configured
            if _normalize_symbol_base(symbol)
        }
        crypto_min_balance = _get_small_live_crypto_min_balance(account_currency)
        configured_crypto_bases = {
            _normalize_symbol_base(symbol)
            for symbol in normalized_configured
            if _normalize_symbol_base(symbol) in SMALL_LIVE_ACCOUNT_OPTIONAL_CRYPTO_BASE_SYMBOLS
        }
        allow_requested_crypto = bool(configured_crypto_bases) and balance_basis >= crypto_min_balance
        configured_crypto_only = bool(configured_base_symbols) and configured_base_symbols.issubset(SMALL_LIVE_ACCOUNT_OPTIONAL_CRYPTO_BASE_SYMBOLS)

        if configured_crypto_only:
            crypto_only_symbols = [
                symbol for symbol in broker_symbol_universe
                if _normalize_symbol_base(symbol) in configured_crypto_bases
            ]
            if normalized_configured:
                return normalized_configured if normalized_configured else crypto_only_symbols
            return crypto_only_symbols or normalized_configured or broker_symbol_universe

        allowed_base_symbols = set(SMALL_LIVE_ACCOUNT_SAFE_BASE_SYMBOLS)
        if allow_requested_crypto:
            allowed_base_symbols.update(configured_crypto_bases)

        allowed_symbols = [
            symbol for symbol in broker_symbol_universe
            if _normalize_symbol_base(symbol) in allowed_base_symbols
        ]
        preferred_order = {base: idx for idx, base in enumerate(SMALL_LIVE_ACCOUNT_PREFERRED_BASE_SYMBOLS)}
        allowed_symbols = sorted(
            allowed_symbols,
            key=lambda sym: preferred_order.get(_normalize_symbol_base(sym), len(preferred_order)),
        )

        if normalized_configured:
            configured_safe = [
                symbol for symbol in normalized_configured
                if _normalize_symbol_base(symbol) in allowed_base_symbols
            ]
            configured_safe = sorted(
                configured_safe,
                key=lambda sym: preferred_order.get(_normalize_symbol_base(sym), len(preferred_order)),
            )
            if configured_safe:
                if not allow_cross_market and not expand_small_account_universe:
                    return configured_safe
                return configured_safe + [symbol for symbol in allowed_symbols if symbol not in configured_safe]
        return allowed_symbols or normalized_configured or broker_symbol_universe

    if normalized_configured:
        # Keep scanner anchored to configured symbols unless cross-market reallocation is explicitly enabled.
        if normalized_broker == 'FXCM' and fxcm_tradable_symbol_keys is not None:
            tradeable_configured = _filter_fxcm_symbols_for_tradability(normalized_configured, fxcm_tradable_symbol_keys)
            if tradeable_configured:
                normalized_configured = tradeable_configured
            elif broker_symbol_universe:
                logger.info(
                    "[FXCM Scanner] Configured symbols are not currently tradable; keeping configured symbols for direct broker validation"
                )
        if not allow_cross_market:
            return normalized_configured
        return normalized_configured + [symbol for symbol in broker_symbol_universe if symbol not in normalized_configured]
    return broker_symbol_universe


STRATEGY_MAP = {
    'Scalping': scalping_strategy,
    'Momentum Trading': momentum_strategy,
    'Trend Following': trend_following_strategy,
    'Mean Reversion': mean_reversion_strategy,
    'Range Trading': range_trading_strategy,
    'Breakout Trading': breakout_strategy,
    'Swing Trend DCA': swing_trend_dca_strategy,
}

# ==================== INTELLIGENT STRATEGY SWITCHING & POSITION SIZING ====================

class StrategyPerformanceTracker:
    """Tracks performance of each strategy to enable intelligent switching"""
    
    def __init__(self):
        self.strategy_stats = {}
        self.reset_stats()
    
    def reset_stats(self):
        """Initialize stats for all strategies"""
        self.strategy_stats = {
            'Scalping': {'trades': 0, 'wins': 0, 'losses': 0, 'profit': 0.0, 'wins_streak': 0, 'losses_streak': 0},
            'Momentum Trading': {'trades': 0, 'wins': 0, 'losses': 0, 'profit': 0.0, 'wins_streak': 0, 'losses_streak': 0},
            'Trend Following': {'trades': 0, 'wins': 0, 'losses': 0, 'profit': 0.0, 'wins_streak': 0, 'losses_streak': 0},
            'Mean Reversion': {'trades': 0, 'wins': 0, 'losses': 0, 'profit': 0.0, 'wins_streak': 0, 'losses_streak': 0},
            'Range Trading': {'trades': 0, 'wins': 0, 'losses': 0, 'profit': 0.0, 'wins_streak': 0, 'losses_streak': 0},
            'Breakout Trading': {'trades': 0, 'wins': 0, 'losses': 0, 'profit': 0.0, 'wins_streak': 0, 'losses_streak': 0},
        }
    
    def record_trade(self, strategy, profit, symbol=''):
        """Record a trade result for a strategy"""
        if strategy not in self.strategy_stats:
            self.strategy_stats[strategy] = {'trades': 0, 'wins': 0, 'losses': 0, 'profit': 0.0, 'wins_streak': 0, 'losses_streak': 0}
        
        stats = self.strategy_stats[strategy]
        stats['trades'] += 1
        stats['profit'] += profit
        
        if profit > 0:
            stats['wins'] += 1
            stats['wins_streak'] += 1
            stats['losses_streak'] = 0
        else:
            stats['losses'] += 1
            stats['losses_streak'] += 1
            stats['wins_streak'] = 0
        
        logger.debug(f"Recorded {strategy} trade on {symbol}: profit={profit}, total_stats={stats}")
    
    def get_win_rate(self, strategy):
        """Get win rate for strategy"""
        stats = self.strategy_stats.get(strategy, {})
        trades = stats.get('trades', 0)
        if trades == 0:
            return 0
        return (stats.get('wins', 0) / trades) * 100
    
    def get_profit_factor(self, strategy):
        """Calculate profit factor (total wins / abs(total losses))"""
        stats = self.strategy_stats.get(strategy, {})
        profit = stats.get('profit', 0)
        trades = stats.get('trades', 0)
        wins = stats.get('wins', 0)
        losses = stats.get('losses', 0)
        
        if losses == 0 or trades < 3:
            return 1.0  # Insufficient data
        
        avg_win = profit / wins if wins > 0 else 0
        avg_loss = -profit / losses if losses > 0 else 0
        
        if avg_loss == 0:
            return 99.99
        
        return avg_win / abs(avg_loss) if avg_loss != 0 else 1.0
    
    def get_best_strategy(self):
        """Get best performing strategy based on profit factor and win rate"""
        best_strategy = 'Trend Following'  # Default
        best_score = 0
        
        for strategy, stats in self.strategy_stats.items():
            if stats['trades'] < 3:  # Need at least 3 trades for evaluation
                continue
            
            win_rate = self.get_win_rate(strategy)
            profit_factor = self.get_profit_factor(strategy)
            total_profit = stats['profit']
            
            # Composite score: 40% profit_factor + 40% win_rate + 20% total_profit (normalized)
            score = (profit_factor * 0.4) + (win_rate / 100 * 0.4) + min(total_profit / 1000, 1.0) * 0.2
            
            if score > best_score:
                best_score = score
                best_strategy = strategy
        
        return best_strategy
    
    def get_all_stats(self):
        """Get all strategy statistics"""
        return {
            strategy: {
                **stats,
                'win_rate': self.get_win_rate(strategy),
                'profit_factor': round(self.get_profit_factor(strategy), 2),
            }
            for strategy, stats in self.strategy_stats.items()
        }


AUTO_STRATEGY_SWITCH_COOLDOWN_MINUTES = 20


def _get_recent_strategy_trade_stats(bot_config: Dict[str, Any], strategy_name: str, limit: int = 12) -> Dict[str, float]:
    closed_trades = [
        trade for trade in (bot_config.get('tradeHistory') or [])
        if isinstance(trade, dict)
        and str(trade.get('status') or '').lower() == 'closed'
        and str(trade.get('strategy') or '').strip() == strategy_name
    ]
    if limit > 0:
        closed_trades = closed_trades[-limit:]

    trade_count = len(closed_trades)
    wins = sum(1 for trade in closed_trades if _safe_float(trade.get('profit'), 0.0) > 0)
    total_profit = sum(_safe_float(trade.get('profit'), 0.0) for trade in closed_trades)
    return {
        'trades': trade_count,
        'wins': wins,
        'win_rate': (wins / trade_count * 100.0) if trade_count else 0.0,
        'profit': total_profit,
    }


def _choose_strategy_for_cycle(
    bot_id: str,
    bot_config: Dict[str, Any],
    configured_symbols: List[str],
    signal_threshold: int,
) -> str:
    current_strategy = str(bot_config.get('strategy') or 'Trend Following')
    configured_base_symbols = {
        _normalize_symbol_base(symbol)
        for symbol in (configured_symbols or [])
        if _normalize_symbol_base(symbol)
    }
    if configured_base_symbols and configured_base_symbols.issubset(SMALL_LIVE_ACCOUNT_OPTIONAL_CRYPTO_BASE_SYMBOLS):
        allowed_crypto_strategies = {'Swing Trend DCA', 'Trend Following'}
        return current_strategy if current_strategy in allowed_crypto_strategies else 'Swing Trend DCA'

    if not _coerce_bool(bot_config.get('autoSwitch', True), True):
        return current_strategy

    if bot_config.get('open_positions'):
        return current_strategy

    last_switch_raw = bot_config.get('lastStrategySwitch')
    if last_switch_raw:
        try:
            last_switch_at = datetime.fromisoformat(str(last_switch_raw))
            if (datetime.now() - last_switch_at).total_seconds() < (AUTO_STRATEGY_SWITCH_COOLDOWN_MINUTES * 60):
                return current_strategy
        except Exception:
            pass

    idle_cycles = int(bot_config.get('adaptiveSignalMissCount') or 0)
    should_expand_symbol_universe = _coerce_bool(bot_config.get('intelligentScanner', False), False) or idle_cycles >= ADAPTIVE_SCANNER_TRIGGER_MISSES
    candidate_symbols = build_scanner_symbol_universe(bot_config) if should_expand_symbol_universe else list(configured_symbols)
    candidate_symbols = list(dict.fromkeys([symbol for symbol in candidate_symbols if str(symbol).strip()]))
    if not candidate_symbols:
        return current_strategy

    account_id = bot_config.get('accountId', '')
    risk_per_trade = _safe_float(bot_config.get('riskPerTrade'), 10.0)
    scored_candidates = []

    for strategy_name, strategy_func in STRATEGY_MAP.items():
        strategy_cache: Dict[str, Optional[Dict[str, Any]]] = {}
        strengths: List[float] = []
        qualifying_hits = 0
        best_symbol = None
        best_signal_label = 'NEUTRAL'

        for symbol in candidate_symbols:
            market_data = _enrich_market_data_with_bot_context(bot_config, symbol)
            trade_params = _get_cached_strategy_params(
                strategy_cache,
                strategy_func,
                symbol,
                account_id,
                risk_per_trade,
                market_data,
            )
            if not trade_params:
                continue

            signal_info = trade_params.get('signal', {}) or {}
            strength = _safe_float(signal_info.get('strength'), 0.0)
            strengths.append(strength)
            if strength >= signal_threshold:
                qualifying_hits += 1
            if best_symbol is None or strength > max(strengths[:-1], default=-1.0):
                best_symbol = symbol
                best_signal_label = str(signal_info.get('signal') or 'NEUTRAL')

        if not strengths:
            continue

        top_strengths = sorted(strengths, reverse=True)[:3]
        average_top_strength = sum(top_strengths) / len(top_strengths)
        global_stats = strategy_tracker.strategy_stats.get(strategy_name, {})
        global_trade_count = int(global_stats.get('trades', 0) or 0)
        global_perf_bonus = 0.0
        if global_trade_count >= 3:
            global_perf_bonus += min(strategy_tracker.get_win_rate(strategy_name) / 10.0, 10.0)
            global_perf_bonus += min(strategy_tracker.get_profit_factor(strategy_name) * 2.0, 10.0)
            global_perf_bonus += max(-5.0, min(_safe_float(global_stats.get('profit'), 0.0) / 50.0, 5.0))

        recent_stats = _get_recent_strategy_trade_stats(bot_config, strategy_name)
        recent_perf_bonus = 0.0
        if recent_stats['trades'] > 0:
            recent_perf_bonus += min(recent_stats['win_rate'] / 12.5, 8.0)
            recent_perf_bonus += max(-6.0, min(recent_stats['profit'] / 40.0, 6.0))

        stickiness_bonus = 4.0 if strategy_name == current_strategy else 0.0
        score = (
            qualifying_hits * 100.0
            + average_top_strength * 1.2
            + max(top_strengths)
            + global_perf_bonus
            + recent_perf_bonus
            + stickiness_bonus
        )

        scored_candidates.append({
            'strategy': strategy_name,
            'score': score,
            'hits': qualifying_hits,
            'bestStrength': max(top_strengths),
            'bestSymbol': best_symbol,
            'bestSignal': best_signal_label,
            'globalTrades': global_trade_count,
            'recentTrades': int(recent_stats['trades']),
        })

    if not scored_candidates:
        return current_strategy

    scored_candidates.sort(key=lambda item: (item['score'], item['hits'], item['bestStrength']), reverse=True)
    chosen = scored_candidates[0]
    chosen_strategy = chosen['strategy']
    bot_config['lastStrategySelection'] = {
        'timestamp': datetime.now().isoformat(),
        'strategy': chosen_strategy,
        'score': round(chosen['score'], 2),
        'hits': chosen['hits'],
        'bestSymbol': chosen['bestSymbol'],
        'bestSignal': chosen['bestSignal'],
    }

    if chosen_strategy == current_strategy:
        return current_strategy

    switch_reason = (
        f"scanner selected {chosen_strategy} on {chosen['bestSymbol']} "
        f"({chosen['bestSignal']} {chosen['bestStrength']:.0f}/100, {chosen['hits']} qualifying setup(s))"
    )
    logger.info(f"🧠 Bot {bot_id}: Strategy switch {current_strategy} -> {chosen_strategy} | {switch_reason}")
    bot_config['strategy'] = chosen_strategy
    bot_config['lastStrategySwitch'] = datetime.now().isoformat()
    bot_config.setdefault('strategyHistory', []).append({
        'timestamp': bot_config['lastStrategySwitch'],
        'fromStrategy': current_strategy,
        'toStrategy': chosen_strategy,
        'reason': switch_reason,
    })
    bot_config['strategyHistory'] = bot_config['strategyHistory'][-50:]
    persist_bot_runtime_state(bot_id)
    return chosen_strategy


class DynamicPositionSizer:
    """Intelligently adjusts position sizes based on account performance"""
    
    def __init__(self, base_size=1.0, min_size=0.01, max_size=5.0):
        self.base_size = base_size
        self.min_size = min_size
        self.max_size = max_size
    
    def calculate_position_size(self, bot_config, volatility_level='Medium'):
        """
        Calculate optimal position size based on:
        - Account equity changes (scaling)
        - Win/loss streaks (confidence)
        - Volatility (risk adjustment)
        - Drawdown (protection)
        """
        import random
        
        size = max(_safe_float(bot_config.get('basePositionSize'), self.base_size), self.min_size)
        
        # Get account performance metrics
        total_trades = bot_config.get('totalTrades', 0)
        winning_trades = bot_config.get('winningTrades', 0)
        total_profit = bot_config.get('totalProfit', 0)
        max_drawdown = bot_config.get('maxDrawdown', 0)
        peak_profit = bot_config.get('peakProfit', 0)
        
        # 1. EQUITY SCALING - Scale by cumulative profit
        if total_trades > 0 and total_profit > 0:
            equity_multiplier = 1.0 + (total_profit / 1000)  # +10% size per $1000 profit
            size *= min(equity_multiplier, 1.5)  # Cap at 1.5x
        
        # 2. WIN STREAK SCALING - Increase after winning trades
        if total_trades > 0:
            recent_trades = bot_config.get('tradeHistory', [])[-5:] if bot_config.get('tradeHistory') else []
            win_streak = 0
            loss_streak = 0
            for trade in reversed(recent_trades):
                if trade.get('profit', 0) > 0:
                    win_streak += 1
                    break
                else:
                    loss_streak += 1
                    if win_streak > 0:
                        break
            
            if win_streak > 2:
                size *= (1.0 + (win_streak * 0.1))  # +10% per win in streak
            elif loss_streak >= 2:
                size *= max(0.45, 1.0 - (loss_streak * 0.15))

        performance_state = _build_performance_sizing_state(bot_config, volatility_level)
        performance_multiplier = _safe_float(performance_state.get('multiplier'), 1.0)
        size *= performance_multiplier
        bot_config['effectivePositionSizeMultiplier'] = round(performance_multiplier, 3)
        bot_config['effectiveScannerCapitalMultiplier'] = round(_safe_float(performance_state.get('scannerCapitalMultiplier'), 1.0), 3)
        bot_config['lastSizingAdjustment'] = performance_state
        
        # 3. VOLATILITY ADJUSTMENT
        volatility_multiplier = {
            'Very Low': 1.15,  # Slightly increase in very low volatility
            'Low': 1.1,      # Increase size in low volatility
            'Medium': 1.0,   # Normal size
            'High': 0.8,     # Reduce in high volatility
            'Very High': 0.6 # Significantly reduce in extreme volatility
        }
        size *= volatility_multiplier.get(volatility_level, 1.0)
        
        # 4. DRAWDOWN PROTECTION - Reduce size during drawdowns
        if peak_profit > 0 and max_drawdown > 0:
            drawdown_percent = (max_drawdown / peak_profit) * 100
            if drawdown_percent > 20:  # If drawdown > 20%
                size *= 0.5  # Reduce to 50%
            elif drawdown_percent > 10:  # If drawdown > 10%
                size *= 0.7  # Reduce to 70%

        account_balance = max(
            float(bot_config.get('accountEquity') or 0.0),
            float(bot_config.get('accountBalance') or 0.0),
        )
        if _normalize_management_profile(bot_config.get('managementProfile')) == 'small_account':
            if account_balance > 0:
                balance_scale = max(0.25, min(account_balance / 250.0, 0.75))
                size *= balance_scale
            self_max = min(self.max_size, 0.5)
        else:
            self_max = self.max_size
        
        # 5. APPLY MIN/MAX CONSTRAINTS
        final_size = max(self.min_size, min(size, self_max))
        
        return round(final_size, 2)


def infer_symbol_quote_currency(symbol: str) -> Optional[str]:
    normalized = ''.join(ch for ch in str(symbol or '').upper() if ch.isalpha())
    if not normalized:
        return None

    for suffix in ('USDT', 'USDC', 'USD', 'EUR', 'GBP', 'ZAR', 'JPY', 'CHF', 'CAD', 'AUD', 'NZD'):
        if normalized.endswith(suffix):
            return suffix

    if len(normalized) >= 6:
        return normalized[3:6]

    return None


def _get_mt5_mid_rate(mt5_api, broker_name: str, symbol_name: str) -> Optional[float]:
    candidates = []
    normalized_symbol = normalize_symbol_for_broker(symbol_name, broker_name)
    if normalized_symbol:
        candidates.append(normalized_symbol)
    if symbol_name not in candidates:
        candidates.append(symbol_name)

    for candidate in candidates:
        try:
            mt5_api.symbol_select(candidate, True)
            tick = mt5_api.symbol_info_tick(candidate)
            if tick is None:
                continue

            bid = float(getattr(tick, 'bid', 0.0) or 0.0)
            ask = float(getattr(tick, 'ask', 0.0) or 0.0)
            if bid > 0 and ask > 0:
                return (bid + ask) / 2.0
            if bid > 0:
                return bid
            if ask > 0:
                return ask
        except Exception:
            continue

    return None


def convert_amount_between_currencies(
    amount: float,
    from_currency: str,
    to_currency: str,
    broker_name: str,
    mt5_api=None,
) -> tuple[float, Optional[str]]:
    from_currency = str(from_currency or '').upper()
    to_currency = str(to_currency or '').upper()

    if amount <= 0 or not from_currency or not to_currency or from_currency == to_currency:
        return amount, None

    if mt5_api is None:
        return amount, None

    direct_symbol = f"{to_currency}{from_currency}"
    direct_rate = _get_mt5_mid_rate(mt5_api, broker_name, direct_symbol)
    if direct_rate and direct_rate > 0:
        converted = amount / direct_rate
        return converted, f"{amount:.2f} {from_currency} -> {converted:.2f} {to_currency} via {direct_symbol}"

    reverse_symbol = f"{from_currency}{to_currency}"
    reverse_rate = _get_mt5_mid_rate(mt5_api, broker_name, reverse_symbol)
    if reverse_rate and reverse_rate > 0:
        converted = amount * reverse_rate
        return converted, f"{amount:.2f} {from_currency} -> {converted:.2f} {to_currency} via {reverse_symbol}"

    return amount, None


def estimate_fixed_trade_volume(
    trade_amount: float,
    symbol: str,
    account_currency: str,
    broker_name: str,
    mt5_api=None,
    market_price: float = 0.0,
    market_name: str = 'spot',
    exchange_leverage: float = 1.0,
) -> tuple[float, Dict[str, Any]]:
    details: Dict[str, Any] = {
        'account_currency': str(account_currency or 'USD').upper(),
        'quote_currency': infer_symbol_quote_currency(symbol),
        'contract_size': None,
        'price': None,
        'method': 'fallback',
        'conversion_note': None,
    }

    if not trade_amount or trade_amount <= 0:
        return 0.0, details

    quote_amount = float(trade_amount)
    if details['quote_currency']:
        quote_amount, conversion_note = convert_amount_between_currencies(
            float(trade_amount),
            details['account_currency'],
            details['quote_currency'],
            broker_name,
            mt5_api=mt5_api,
        )
        details['conversion_note'] = conversion_note

    contract_size = 0.0
    current_price = float(market_price or 0.0)

    if mt5_api is not None:
        try:
            mt5_api.symbol_select(symbol, True)
            sym_info = mt5_api.symbol_info(symbol)
            tick = mt5_api.symbol_info_tick(symbol)
            if sym_info is not None:
                contract_size = float(getattr(sym_info, 'trade_contract_size', 0.0) or 0.0)
            if tick is not None:
                bid = float(getattr(tick, 'bid', 0.0) or 0.0)
                ask = float(getattr(tick, 'ask', 0.0) or 0.0)
                current_price = ask if ask > 0 else bid if bid > 0 else current_price
        except Exception:
            pass

    if contract_size > 0 and current_price > 0:
        details['contract_size'] = contract_size
        details['price'] = current_price
        details['method'] = 'symbol-metadata'
        estimated_volume = quote_amount / (current_price * contract_size)
        return max(estimated_volume, 0.0), details

    normalized_broker = canonicalize_broker_name(broker_name)
    normalized_market = str(market_name or 'spot').strip().lower()
    if normalized_broker == 'Binance' and current_price > 0:
        effective_notional = quote_amount
        if normalized_market == 'futures':
            leverage_multiplier = max(1.0, float(exchange_leverage or 1.0))
            effective_notional *= leverage_multiplier
            details['method'] = 'binance-futures-price-notional'
        else:
            details['method'] = 'binance-price-notional'
        details['contract_size'] = 1.0
        details['price'] = current_price
        estimated_volume = effective_notional / current_price
        return max(estimated_volume, 0.0), details

    estimated_volume = quote_amount / 100000.0
    details['method'] = 'fallback-100000'
    details['price'] = current_price if current_price > 0 else None
    return max(estimated_volume, 0.0), details


# Initialize trackers
strategy_tracker = StrategyPerformanceTracker()
position_sizer = DynamicPositionSizer(base_size=1.0, min_size=0.1, max_size=5.0)


# ==================== INTELLIGENT OPPORTUNITY SCANNER & REALLOCATION ====================

def scan_all_opportunities(strategy_func, account_id, risk_per_trade, signal_threshold, strategy_cache=None,
                          symbol_universe=None, fallback_slack=20, bot_config=None,
                          allow_raw_signal_fallback=False):
    """Scan ALL valid symbols across every asset class for the best trade opportunities.

    Returns a ranked list of (symbol, signal_strength, signal_eval, trade_params) sorted
    by signal strength descending.  The caller decides how many to act on.
    """
    opportunities = []
    near_misses = []
    strategy_cache = strategy_cache if strategy_cache is not None else {}
    symbols_to_scan = list(symbol_universe or sorted(VALID_SYMBOLS))
    total_symbols = len(symbols_to_scan)
    adaptive_floor = _adaptive_signal_threshold_floor(bot_config or {}) if bot_config else 20
    if total_symbols > 0:
        logger.info(
            f"[SCANNER] Starting opportunity scan across {total_symbols} symbol(s) "
            f"at threshold {signal_threshold}"
        )
    for symbol in symbols_to_scan:
        symbol_index = len(opportunities) + len(near_misses) + 1
        try:
            logger.debug(f"[SCANNER] Evaluating symbol {symbol_index}/{total_symbols}: {symbol}")
            market_data = _enrich_market_data_with_bot_context(bot_config, symbol)
            trade_params = _get_cached_strategy_params(
                strategy_cache,
                strategy_func,
                symbol,
                account_id,
                risk_per_trade,
                market_data,
            )
            raw_signal = evaluate_real_trade_signal(symbol, market_data)
            raw_strength = raw_signal.get('strength', 0)
            if trade_params is None:
                if raw_strength >= max(60, signal_threshold):
                    logger.info(
                        f"[SCANNER] {symbol}: raw signal {raw_strength:.0f}/100 "
                        f"({raw_signal.get('signal', 'NEUTRAL')}) met visibility threshold, "
                        f"but the active strategy rejected execution: "
                        f"{raw_signal.get('entry_reason', 'Rejected by strategy')}"
                    )
                raw_fallback_min_strength = max(adaptive_floor, min(signal_threshold, ADAPTIVE_FALLBACK_MIN_STRENGTH))
                fallback_trade_params = None
                if allow_raw_signal_fallback and raw_strength >= raw_fallback_min_strength:
                    fallback_trade_params = _build_adaptive_raw_trade_params(symbol, market_data, raw_signal, bot_config)
                if fallback_trade_params is not None:
                    strategy_cache[_strategy_cache_key(strategy_func, symbol)] = fallback_trade_params
                    opportunities.append({
                        'symbol': symbol,
                        'strength': raw_strength,
                        'signal': fallback_trade_params['signal']['signal'],
                        'trend': raw_signal.get('trend', 'UNKNOWN'),
                        'rsi': raw_signal.get('rsi', 50),
                        'trade_params': fallback_trade_params,
                        'source': 'adaptive_raw_fallback',
                    })
                    continue
                if raw_strength > 0:
                    near_misses.append({
                        'symbol': symbol,
                        'strength': raw_strength,
                        'signal': raw_signal.get('signal', 'NEUTRAL'),
                        'reason': raw_signal.get('entry_reason', 'Rejected by strategy'),
                    })
                continue
            strength = trade_params.get('signal', {}).get('strength', 0)
            if strength >= signal_threshold:
                opportunities.append({
                    'symbol': symbol,
                    'strength': strength,
                    'signal': trade_params['signal']['signal'],
                    'trend': trade_params['signal'].get('trend', 'UNKNOWN'),
                    'rsi': trade_params['signal'].get('rsi', 50),
                    'trade_params': trade_params,
                    'source': trade_params.get('execution_source', 'strategy'),
                })
            else:
                near_misses.append({
                    'symbol': symbol,
                    'strength': strength,
                    'signal': trade_params['signal'].get('signal', 'NEUTRAL'),
                    'reason': trade_params['signal'].get('entry_reason', 'Below threshold'),
                })
        except Exception as e:
            logger.debug(f"[SCANNER] Error scanning {symbol}: {e}")

        if total_symbols > 25 and symbol_index % 25 == 0:
            logger.info(
                f"[SCANNER] Progress: scanned {symbol_index}/{total_symbols} symbols | "
                f"qualifying={len(opportunities)} | near_misses={len(near_misses)}"
            )
    
    # Sort by signal strength descending
    opportunities.sort(key=lambda x: x['strength'], reverse=True)
    if not opportunities and signal_threshold > adaptive_floor and fallback_slack > 0:
        fallback_threshold = max(adaptive_floor, signal_threshold - fallback_slack)
        logger.debug(f"[SCANNER] No opportunities above {signal_threshold}. Falling back to {fallback_threshold}.")
        for symbol in symbols_to_scan:
            try:
                market_data = _enrich_market_data_with_bot_context(bot_config, symbol)
                trade_params = _get_cached_strategy_params(
                    strategy_cache,
                    strategy_func,
                    symbol,
                    account_id,
                    risk_per_trade,
                    market_data,
                )
                if trade_params is None:
                    continue
                strength = trade_params.get('signal', {}).get('strength', 0)
                if strength >= fallback_threshold:
                    opportunities.append({
                        'symbol': symbol,
                        'strength': strength,
                        'signal': trade_params['signal']['signal'],
                        'trend': trade_params['signal'].get('trend', 'UNKNOWN'),
                        'rsi': trade_params['signal'].get('rsi', 50),
                        'trade_params': trade_params,
                    })
            except Exception as e:
                logger.debug(f"[SCANNER] Fallback error scanning {symbol}: {e}")
        opportunities.sort(key=lambda x: x['strength'], reverse=True)

    if not opportunities and near_misses:
        near_misses.sort(key=lambda x: x['strength'], reverse=True)
        top_near_misses = ', '.join(
            [f"{item['symbol']}:{item['strength']:.0f} {item['signal']} ({item['reason']})" for item in near_misses[:3]]
        )
        logger.info(
            f"[SCANNER] No symbols met threshold {signal_threshold}. Closest setups: {top_near_misses}"
        )

    logger.info(
        f"[SCANNER] ✅ Scan complete: {len(opportunities)} opportunities found, "
        f"{len(near_misses)} near-misses"
    )
    return opportunities

def evaluate_open_positions_for_reallocation(bot_config, opportunities, active_conn, is_mt5, signal_threshold):
    """Evaluate open positions and decide which to close in favour of better opportunities.
    
    Logic:
    - A position is a "close candidate" if its current profit is negative AND
      its symbol's CURRENT signal has reversed or weakened below threshold.
    - We only close if there's a genuinely better opportunity waiting (higher strength).
    - Never close a position that is in profit (let winners run).
    - Respects maxOpenPositions: only close to free a slot if we're at the limit.
    
    Returns list of tickets to close and the replacement symbols.
    """
    tracked = bot_config.get('open_positions', {})
    if not tracked:
        return [], []
    
    max_positions = bot_config.get('effectiveMaxOpenPositions') or bot_config.get('maxOpenPositions', 2)
    open_count = len(tracked)
    
    # If we have room for more positions, no need to close anything
    if open_count < max_positions:
        return [], []
    
    # Build set of symbols we already have open
    open_symbols = set()
    close_candidates = []
    
    for ticket_str, pos in tracked.items():
        pos_symbol = pos.get('symbol', '')
        open_symbols.add(pos_symbol)
        profit = pos.get('profit', 0)
        
        # Never close a winning position
        if profit > 0:
            continue
        
        # Check if the CURRENT signal for this symbol has weakened
        market_data = commodity_market_data.get(pos_symbol, {})
        current_eval = evaluate_real_trade_signal(pos_symbol, market_data)
        current_strength = current_eval.get('strength', 0)
        current_signal = current_eval.get('signal', 'NEUTRAL')
        
        # Position direction
        pos_type = (pos.get('type', '') or '').upper()
        
        # Signal reversal: we're long but signal says sell, or vice versa
        signal_reversed = (
            (pos_type == 'BUY' and 'SELL' in current_signal) or
            (pos_type == 'SELL' and 'BUY' in current_signal)
        )
        
        # Signal weakened below threshold
        signal_weak = current_strength < signal_threshold * 0.6  # Below 60% of threshold
        
        eth_reversal = signal_reversed and pos_symbol.upper().startswith('ETHUSD')
        if signal_reversed or signal_weak or eth_reversal:
            if profit > 0 or signal_weak or eth_reversal:
                close_candidates.append({
                    'ticket': ticket_str,
                    'symbol': pos_symbol,
                    'profit': profit,
                    'strength': current_strength,
                    'reason': 'SIGNAL_REVERSED' if signal_reversed else 'SIGNAL_WEAKENED',
                })
    
    if not close_candidates:
        return [], []
    
    # Sort by worst profit first (close the biggest losers first)
    close_candidates.sort(key=lambda x: x['profit'])
    
    # Only close if there's a better opportunity not already open
    tickets_to_close = []
    replacement_symbols = []
    
    for candidate in close_candidates:
        # Find the best opportunity that isn't already open
        for opp in opportunities:
            if opp['symbol'] not in open_symbols and opp['symbol'] != candidate['symbol']:
                if opp['strength'] > candidate['strength'] + 15:  # Must be significantly better
                    tickets_to_close.append(candidate['ticket'])
                    replacement_symbols.append(opp['symbol'])
                    open_symbols.add(opp['symbol'])  # Mark as taken
                    break
        
        # Only close up to 1 position per cycle to avoid whipsaw
        if len(tickets_to_close) >= 1:
            break
    
    return tickets_to_close, replacement_symbols


def execute_intelligent_reallocation(bot_id, bot_config, active_conn, is_mt5, mt5_conn, 
                                       strategy_func, signal_threshold, broker_type, strategy_cache=None,
                                       force_scan=False):
    """Main intelligence loop: scan, evaluate, close weak, reallocate to strong.
    
    Called once per trading cycle when intelligentScanner is enabled.
    Returns the list of symbols to trade THIS cycle (may differ from bot's original list).
    """
    if not bot_config.get('intelligentScanner', False) and not force_scan:
        return bot_config.get('symbols', ['EURUSDm'])
    
    account_id = bot_config.get('accountId', '')
    risk_per_trade = bot_config.get('riskPerTrade', 10)
    max_positions = bot_config.get('effectiveMaxOpenPositions') or bot_config.get('maxOpenPositions', 2)
    try:
        cycle_symbol_cap = max(1, int(max_positions or 2))
    except Exception:
        cycle_symbol_cap = 2
    if bot_config.get('managementMode', 'assisted') != 'manual':
        cycle_symbol_cap = min(cycle_symbol_cap, MAX_ASSISTED_SYMBOLS_PER_CYCLE)
    symbol_universe = []
    profile = _normalize_management_profile(bot_config.get('managementProfile'))
    adaptive_offset = int(bot_config.get('adaptiveSignalThresholdOffset') or 0)
    idle_cycles = int(bot_config.get('adaptiveSignalMissCount') or 0)
    mode_value = str(bot_config.get('mode') or bot_config.get('botMode') or 'demo').strip().lower()
    is_live = mode_value == 'live' or bool(bot_config.get('is_live'))
    conservative_entry_mode = (
        profile == 'small_account'
        or bot_config.get('managementState') == 'recovery'
        or is_live
        or int(bot_config.get('consecutiveLosses') or 0) > 0
    )
    fallback_slack = 0 if conservative_entry_mode else min(8, max(5, adaptive_offset))
    normalized_broker_type = canonicalize_broker_name(broker_type)
    fxcm_tradable_symbol_keys: Optional[Set[str]] = None
    fxcm_tradable_lookup_attempted = False

    if normalized_broker_type == 'FXCM':
        fxcm_tradable_symbol_keys = _get_fxcm_tradable_symbol_keys(broker_conn=active_conn)
        fxcm_tradable_lookup_attempted = True

    symbol_universe = build_scanner_symbol_universe(bot_config, fxcm_tradable_symbol_keys)
    
    def _is_symbol_tradeable_now(symbol_to_test: str) -> bool:
        """Best-effort tradability check to avoid selecting closed/illiquid symbols."""
        nonlocal fxcm_tradable_symbol_keys, fxcm_tradable_lookup_attempted
        if normalized_broker_type == 'FXCM':
            if not fxcm_tradable_lookup_attempted:
                fxcm_tradable_symbol_keys = _get_fxcm_tradable_symbol_keys(broker_conn=active_conn)
                fxcm_tradable_lookup_attempted = True
            candidate_keys = _get_fxcm_symbol_candidate_keys(symbol_to_test)
            return fxcm_tradable_symbol_keys is None or bool(candidate_keys & fxcm_tradable_symbol_keys)
        if not (is_mt5 and mt5_conn and getattr(mt5_conn, 'mt5', None)):
            return True
        try:
            mt5_api = mt5_conn.mt5
            if not mt5_conn.is_symbol_available(symbol_to_test):
                return False
            mt5_api.symbol_select(symbol_to_test, True)
            info = mt5_api.symbol_info(symbol_to_test)
            if info is None:
                return False
            if int(getattr(info, 'trade_mode', 1) or 1) == 0:
                return False
            tick = mt5_api.symbol_info_tick(symbol_to_test)
            if tick is None:
                return False
            bid = float(getattr(tick, 'bid', 0.0) or 0.0)
            ask = float(getattr(tick, 'ask', 0.0) or 0.0)
            if bid <= 0 or ask <= 0 or ask <= bid:
                return False
            tick_ts = int(getattr(tick, 'time', 0) or 0)
            if tick_ts > 0 and (time.time() - tick_ts) > 180:
                return False
            return True
        except Exception:
            return True

    # 1. SCAN all symbols for opportunities
    allow_adaptive_raw_fallback = _coerce_bool(
        bot_config.get('allowAdaptiveRawFallback', bot_config.get('intelligentScanner', False)),
        bool(bot_config.get('intelligentScanner', False)),
    )
    # MANUAL MODE GUARD: do not auto-enable raw-signal fallback when threshold mode is manual
    _raw_fb_manual = str(bot_config.get('signalThresholdMode') or '').strip().lower() == 'manual'
    auto_enable_raw_fallback = (
        not bot_config.get('open_positions')
        and bot_config.get('managementMode', 'assisted') != 'manual'
        and not _raw_fb_manual
        and (
            force_scan
            or bot_config.get('intelligentScanner', False)
            or idle_cycles >= ADAPTIVE_SCANNER_TRIGGER_MISSES
        )
    )
    use_raw_signal_fallback = allow_adaptive_raw_fallback or auto_enable_raw_fallback
    if auto_enable_raw_fallback and not allow_adaptive_raw_fallback:
        logger.info(
            f"🧠 Bot {bot_id}: Auto-enabling conservative raw-signal fallback while idle "
            f"to avoid stale cycles without strategy-approved entries"
        )
    opportunities = scan_all_opportunities(
        strategy_func,
        account_id,
        risk_per_trade,
        signal_threshold,
        strategy_cache,
        symbol_universe=symbol_universe,
        fallback_slack=fallback_slack,
        bot_config=bot_config,
        allow_raw_signal_fallback=use_raw_signal_fallback,
    )

    tradeable_opportunities = [opp for opp in opportunities if _is_symbol_tradeable_now(opp.get('symbol', ''))]
    spot_inventory_symbols: Set[str] = set()
    if normalized_broker_type == 'Binance' and active_conn and getattr(active_conn, 'market', 'spot') != 'futures':
        try:
            configured_symbols = [str(sym).upper() for sym in (bot_config.get('symbols') or []) if sym]
            candidate_symbols = list(dict.fromkeys(
                configured_symbols + [str(opp.get('symbol') or '').upper() for opp in tradeable_opportunities if opp.get('symbol')]
            ))
            for position_symbol in candidate_symbols:
                inventory_snapshot = _get_binance_spot_inventory_snapshot(active_conn, position_symbol)
                if inventory_snapshot['isSellable']:
                    spot_inventory_symbols.add(inventory_snapshot['symbol'])
        except Exception as inventory_error:
            logger.debug(f"🧠 Bot {bot_id}: Could not inspect Binance spot inventory: {inventory_error}")

        if not spot_inventory_symbols:
            preferred_buy_opportunities = [
                opp for opp in tradeable_opportunities
                if 'BUY' in str(opp.get('signal', '')).upper()
            ]
            if not preferred_buy_opportunities:
                relaxed_buy_threshold = max(
                    _adaptive_signal_threshold_floor(bot_config),
                    min(signal_threshold - 10, ADAPTIVE_FALLBACK_MIN_STRENGTH),
                )
                if relaxed_buy_threshold < signal_threshold:
                    relaxed_buy_scan = scan_all_opportunities(
                        strategy_func,
                        account_id,
                        risk_per_trade,
                        relaxed_buy_threshold,
                        strategy_cache,
                        symbol_universe=symbol_universe,
                        fallback_slack=0,
                        bot_config=bot_config,
                        allow_raw_signal_fallback=use_raw_signal_fallback,
                    )
                    preferred_buy_opportunities = [
                        opp for opp in relaxed_buy_scan
                        if 'BUY' in str(opp.get('signal', '')).upper() and _is_symbol_tradeable_now(opp.get('symbol', ''))
                    ]
                    if preferred_buy_opportunities:
                        logger.info(
                            f"🧠 Bot {bot_id}: Binance spot is flat - using relaxed BUY-only scan "
                            f"threshold {signal_threshold} -> {relaxed_buy_threshold}"
                        )
            tradeable_opportunities = preferred_buy_opportunities
        else:
            tradeable_opportunities = [
                opp for opp in tradeable_opportunities
                if 'BUY' in str(opp.get('signal', '')).upper() or str(opp.get('symbol') or '').upper() in spot_inventory_symbols
            ]
    
    if tradeable_opportunities:
        top_3 = ', '.join([f"{o['symbol']}:{o['strength']:.0f} [{o.get('source', 'strategy')}]" for o in tradeable_opportunities[:3]])
        scanner_mode = 'adaptive' if force_scan and not bot_config.get('intelligentScanner', False) else 'configured'
        logger.info(f"🧠 Bot {bot_id} SCANNER[{scanner_mode}]: Top tradeable opportunities: {top_3} (of {len(tradeable_opportunities)} qualifying)")
    else:
        scanner_mode = 'adaptive' if force_scan and not bot_config.get('intelligentScanner', False) else 'configured'
        if opportunities:
            logger.info(
                f"🧠 Bot {bot_id} SCANNER[{scanner_mode}]: {len(opportunities)} raw opportunities found, "
                f"but none currently tradeable"
            )
        else:
            logger.info(f"🧠 Bot {bot_id} SCANNER[{scanner_mode}]: No qualifying opportunities across {len(symbol_universe)} symbols")
        bot_config['lastScanResults'] = {
            'timestamp': datetime.now().isoformat(),
            'totalScanned': len(symbol_universe),
            'qualifyingOpportunities': 0,
            'scannerMode': 'adaptive' if force_scan and not bot_config.get('intelligentScanner', False) else ('always_on' if bot_config.get('intelligentScanner', False) else 'disabled'),
            'topOpportunities': [],
            'closedForReallocation': 0,
            'cycleSymbols': [],
        }
        return []
    
    # 2. EVALUATE open positions for potential reallocation
    tickets_to_close, replacement_symbols = evaluate_open_positions_for_reallocation(
        bot_config, tradeable_opportunities, active_conn, is_mt5, signal_threshold
    )
    
    # 3. CLOSE underperformers
    for ticket in tickets_to_close:
        tracked_pos = bot_config.get('open_positions', {}).get(ticket, {})
        symbol = tracked_pos.get('symbol', '?')
        profit = tracked_pos.get('profit', 0)
        
        display_currency = str(bot_config.get('displayCurrency') or 'USD').upper()
        logger.info(f"🧠 Bot {bot_id}: CLOSING underperformer {symbol} (ticket {ticket}, P&L: {profit:.2f} {display_currency}) — better opportunity found")
        
        try:
            if is_mt5 and mt5_conn:
                result = mt5_conn.close_position(ticket)
            elif active_conn:
                result = active_conn.close_position(ticket)
            else:
                result = {'success': False, 'error': 'No connection'}
            
            if result.get('success'):
                logger.info(f"🧠 Bot {bot_id}: ✅ Closed {symbol} (ticket {ticket}) for reallocation")
                # Update trade in database
                try:
                    realloc_conn = build_sqlite_connection(timeout=30.0)
                    realloc_cursor = realloc_conn.cursor()
                    realloc_cursor.execute('''
                        UPDATE trades SET profit = ?, status = 'closed', time_close = ?,
                        trade_data = json_set(COALESCE(trade_data, '{}'), '$.closeReason', 'INTELLIGENT_REALLOCATION'),
                        updated_at = ?
                        WHERE ticket = ? AND bot_id = ? AND status = 'open'
                    ''', (profit, datetime.now().isoformat(), datetime.now().isoformat(), str(ticket), bot_id))
                    realloc_conn.commit()
                    realloc_conn.close()
                except Exception as db_e:
                    logger.warning(f"Bot {bot_id}: DB update after realloc close: {db_e}")
                
                # Remove from tracked positions
                if ticket in bot_config.get('open_positions', {}):
                    del bot_config['open_positions'][ticket]
            else:
                logger.warning(f"🧠 Bot {bot_id}: Failed to close {symbol}: {result.get('error')}")
        except Exception as e:
            logger.error(f"🧠 Bot {bot_id}: Exception closing {symbol}: {e}")
    
    # 4. BUILD optimal symbol list for this cycle
    # Start with existing open positions (don't duplicate), then add best new opportunities.
    # NOTE: For Binance SPOT, "positions" are synthesized from token balances by
    # get_positions(). Counting these toward max_positions starves the scanner
    # of slots for new BUYs (every held coin permanently consumes a slot until
    # sold). We therefore DO NOT count spot_inventory_symbols toward the cap;
    # we still retain configured inventory symbols in cycle_symbols so the bot can manage/SELL them.
    current_open_symbols = set(p.get('symbol', '') for p in bot_config.get('open_positions', {}).values())
    configured_symbols = [str(s).upper() for s in (bot_config.get('symbols') or []) if s]
    configured_symbol_set = set(configured_symbols)
    managed_spot_inventory_symbols = [
        sym for sym in spot_inventory_symbols
        if sym in configured_symbol_set
    ]

    # Symbols already tracked (open_positions only) — used for de-duplication.
    # Spot-inventory symbols are NOT pre-seeded into dedup_symbols so that scanner
    # opportunities can fill new-trade slots first; inventory symbols are appended
    # afterward so they remain managed but don't starve the scanner.
    dedup_symbols = set(current_open_symbols)

    # STEP 1: Keep real tracked open positions first.
    cycle_symbols = list(current_open_symbols)

    # Compute remaining new-trade slots based on REAL tracked positions only,
    # so accumulated SPOT inventory cannot block new entries.
    new_trade_slots_used = len(current_open_symbols)

    # STEP 2: Add top scanner opportunities (highest priority, up to cap).
    for opp in tradeable_opportunities:
        if new_trade_slots_used >= cycle_symbol_cap:
            break
        if opp['symbol'] not in dedup_symbols and _is_symbol_tradeable_now(opp['symbol']):
            cycle_symbols.append(opp['symbol'])
            dedup_symbols.add(opp['symbol'])
            new_trade_slots_used += 1

    # STEP 3: Append managed spot-inventory symbols (cap-exempt for SELL management).
    # These come AFTER scanner picks so they don't push scanner results out when sliced.
    for sym in managed_spot_inventory_symbols:
        if sym and sym not in dedup_symbols:
            cycle_symbols.append(sym)
            dedup_symbols.add(sym)
    
    # If we still have slots, add fallback symbols from the active scanner universe.
    fallback_symbols = symbol_universe or bot_config.get('symbols', ['EURUSDm'])
    for s in fallback_symbols:
        if new_trade_slots_used >= cycle_symbol_cap:
            break
        fallback_eval = evaluate_real_trade_signal(s, _enrich_market_data_with_bot_context(bot_config, s))
        fallback_strength = _safe_float(fallback_eval.get('strength'), 0.0)
        adaptive_floor = _adaptive_signal_threshold_floor(bot_config)
        fallback_min_strength = max(adaptive_floor, min(signal_threshold, ADAPTIVE_FALLBACK_MIN_STRENGTH))
        if (
            s not in dedup_symbols
            and _is_symbol_tradeable_now(s)
            and fallback_strength >= fallback_min_strength
        ):
            cycle_symbols.append(s)
            dedup_symbols.add(s)
            new_trade_slots_used += 1

    if bot_config.get('managementMode', 'assisted') != 'manual' and len(cycle_symbols) > MAX_ASSISTED_SYMBOLS_PER_CYCLE:
        uncapped_count = len(cycle_symbols)
        cycle_symbols = list(cycle_symbols[:MAX_ASSISTED_SYMBOLS_PER_CYCLE])
        logger.info(
            f"🧭 Bot {bot_id}: Reallocation capped cycle symbols to top "
            f"{MAX_ASSISTED_SYMBOLS_PER_CYCLE} for risk control: {cycle_symbols} "
            f"(from {uncapped_count})"
        )

    if set(cycle_symbols) != set(bot_config.get('symbols', [])):
        logger.info(f"🧠 Bot {bot_id}: Cycle symbols REALLOCATED: {cycle_symbols} (was: {bot_config.get('symbols', [])})")

    # Store scanner state for the API / UI
    bot_config['lastScanResults'] = {
        'timestamp': datetime.now().isoformat(),
        'totalScanned': len(symbol_universe),
        'qualifyingOpportunities': len(tradeable_opportunities),
        'scannerMode': 'adaptive' if force_scan and not bot_config.get('intelligentScanner', False) else ('always_on' if bot_config.get('intelligentScanner', False) else 'disabled'),
        'topOpportunities': [
            {
                'symbol': o['symbol'],
                'strength': o['strength'],
                'signalStrength': round(_safe_float(o.get('strength'), 0.0), 1),
                'signalPercentage': round(_safe_float(o.get('strength'), 0.0), 1),
                'signal': o['signal'],
                'trend': o['trend'],
            }
            for o in tradeable_opportunities[:5]
        ],
        'closedForReallocation': len(tickets_to_close),
        'cycleSymbols': cycle_symbols,
    }
    
    return cycle_symbols

