def _normalize_bot_mode_value(mode_value: Any = None, is_live_value: Any = None) -> str:
    normalized_mode = str(mode_value or '').strip().lower()
    if normalized_mode in ['live', 'demo']:
        return normalized_mode
    if is_live_value is not None:
        return 'live' if bool(is_live_value) else 'demo'
    return 'demo'


def _resolve_bot_name_for_mode(
    requested_name: Any,
    existing_name: Any,
    strategy_name: Any,
    mode_value: Any,
) -> str:
    requested = str(requested_name or '').strip()
    if requested:
        return requested

    normalized_mode = _normalize_bot_mode_value(mode_value)
    normalized_existing = str(existing_name or '').strip()
    generic_mode_names = {
        'demo bot': 'demo',
        'live bot': 'live',
    }

    if normalized_existing:
        existing_mode = generic_mode_names.get(normalized_existing.lower())
        if existing_mode:
            return 'Live Bot' if normalized_mode == 'live' else 'Demo Bot'
        return normalized_existing

    strategy = str(strategy_name or '').strip()
    if strategy:
        return strategy
    return 'Live Bot' if normalized_mode == 'live' else 'Demo Bot'


def _get_demo_promotion_state(bot_config: Dict[str, Any], current_profit: float, total_trades: int) -> Dict[str, Any]:
    bot_mode = str(bot_config.get('mode') or 'demo').strip().lower()
    if bot_mode != 'demo':
        return {
            'status': 'not_applicable',
            'eligible': False,
            'readyAt': None,
            'expiredAt': None,
            'windowHours': DEMO_PROMOTION_EVALUATION_HOURS,
            'timeRemainingMinutes': None,
            'label': None,
        }

    created_at_text = bot_config.get('createdAt') or datetime.now().isoformat()
    try:
        created_at = datetime.fromisoformat(str(created_at_text))
    except Exception:
        created_at = datetime.now()

    now = datetime.now()
    ready_at = bot_config.get('promotionReadyAt')
    expired_at = bot_config.get('promotionExpiredAt')
    state_changed = False
    expires_at = created_at + timedelta(hours=DEMO_PROMOTION_EVALUATION_HOURS)
    eligible_now = int(total_trades or 0) >= DEMO_PROMOTION_MIN_TRADES and float(current_profit or 0.0) >= DEMO_PROMOTION_MIN_PROFIT

    status = 'evaluating'
    label = 'Live Test Running'
    if ready_at:
        status = 'ready'
        label = 'Ready For Live'
    elif expired_at:
        status = 'expired'
        label = 'Promotion Expired'
    elif eligible_now:
        ready_at = now.isoformat()
        bot_config['promotionReadyAt'] = ready_at
        state_changed = True
        status = 'ready'
        label = 'Ready For Live'
    elif now >= expires_at:
        expired_at = now.isoformat()
        bot_config['promotionExpiredAt'] = expired_at
        state_changed = True
        status = 'expired'
        label = 'Promotion Expired'

    time_remaining_minutes = None
    if status == 'evaluating':
        time_remaining_minutes = max(0, int((expires_at - now).total_seconds() // 60))

    return {
        'status': status,
        'eligible': status == 'ready',
        'readyAt': ready_at,
        'expiredAt': expired_at,
        'windowHours': DEMO_PROMOTION_EVALUATION_HOURS,
        'timeRemainingMinutes': time_remaining_minutes,
        'label': label,
        'stateChanged': state_changed,
    }


def _trade_history_timestamp_key(trade: Dict[str, Any]) -> float:
    raw_ts = trade.get('timestamp')
    if isinstance(raw_ts, (int, float)):
        return float(raw_ts)
    if raw_ts is not None:
        try:
            return float(raw_ts)
        except Exception:
            pass

    for field in ('exitTime', 'time_close', 'time', 'entryTime', 'time_open'):
        raw_value = trade.get(field)
        if not raw_value:
            continue
        try:
            return datetime.fromisoformat(str(raw_value)).timestamp() * 1000.0
        except Exception:
            continue

    return 0.0


def _rebuild_bot_profit_tracking(bot_state: Dict[str, Any]) -> None:
    trade_history = bot_state.get('tradeHistory') or []
    closed_trades = []
    for trade in trade_history:
        if not isinstance(trade, dict):
            continue
        status = str(trade.get('status') or '').lower()
        close_marker = trade.get('exitTime') or trade.get('time_close')
        if status == 'closed' or close_marker:
            closed_trades.append(trade)

    closed_trades.sort(key=_trade_history_timestamp_key)

    total_profit = 0.0
    winning_trades = 0
    total_losses = 0.0
    total_investment = 0.0
    peak_profit = 0.0
    max_drawdown = 0.0
    daily_profits: Dict[str, float] = {}
    profit_history = []

    for trade in closed_trades:
        profit = float(trade.get('profit') or 0.0)
        total_profit += profit
        if profit > 0:
            winning_trades += 1
        elif profit < 0:
            total_losses += abs(profit)

        try:
            total_investment += float(trade.get('volume') or 0.0) * float(trade.get('entryPrice') or 0.0)
        except Exception:
            pass

        peak_profit = max(peak_profit, total_profit)
        max_drawdown = max(max_drawdown, peak_profit - total_profit)

        close_time = trade.get('exitTime') or trade.get('time_close') or trade.get('time') or trade.get('entryTime')
        if close_time:
            try:
                close_dt = datetime.fromisoformat(str(close_time))
                day_key = close_dt.strftime('%Y-%m-%d')
                daily_profits[day_key] = round(daily_profits.get(day_key, 0.0) + profit, 2)
            except Exception:
                pass

        profit_history.append({
            'timestamp': int(_trade_history_timestamp_key(trade)),
            'profit': round(total_profit, 2),
            'trades': len(profit_history) + 1,
        })

    today_key = datetime.now().strftime('%Y-%m-%d')
    bot_state['totalTrades'] = max(int(bot_state.get('totalTrades', 0) or 0), len(trade_history), len(closed_trades))
    bot_state['winningTrades'] = winning_trades
    bot_state['totalProfit'] = round(total_profit, 2)
    bot_state['totalLosses'] = round(total_losses, 2)
    if total_investment > 0:
        bot_state['totalInvestment'] = round(total_investment, 2)
    bot_state['peakProfit'] = round(peak_profit, 2)
    bot_state['maxDrawdown'] = round(max_drawdown, 2)
    bot_state['profitHistory'] = profit_history[-500:]
    bot_state['dailyProfits'] = daily_profits
    bot_state['dailyProfit'] = float(daily_profits.get(today_key, 0.0) or 0.0)
    bot_state['profit'] = round(total_profit, 2)


def _merge_bot_trade_history_from_db(bot_state: Dict[str, Any], bot_id: str) -> None:
    existing_history = bot_state.get('tradeHistory') or []
    merged_by_ticket: Dict[str, Dict[str, Any]] = {}
    ordered_without_ticket = []

    for trade in existing_history:
        if not isinstance(trade, dict):
            continue
        ticket = str(trade.get('ticket') or '').strip()
        if ticket:
            merged_by_ticket[ticket] = trade
        else:
            ordered_without_ticket.append(trade)

    tconn = None
    try:
        tconn = build_sqlite_connection(timeout=10.0, row_factory=True)
        tcursor = tconn.cursor()
        tcursor.execute(
            '''
            SELECT ticket, symbol, order_type, volume, price, profit, time_open, time_close, status, trade_data, created_at, updated_at
            FROM trades
            WHERE bot_id = ?
            ORDER BY COALESCE(time_close, time_open, created_at, updated_at) ASC
            ''',
            (bot_id,)
        )
        restored_count = 0
        for trow in tcursor.fetchall():
            trade: Dict[str, Any] = {}
            if trow['trade_data']:
                try:
                    loaded = json.loads(trow['trade_data'])
                    if isinstance(loaded, dict):
                        trade = loaded
                except Exception:
                    trade = {}

            trade = {
                'ticket': trow['ticket'],
                'symbol': trow['symbol'],
                'type': trade.get('type') or trow['order_type'],
                'volume': trade.get('volume') if trade.get('volume') is not None else trow['volume'],
                'entryPrice': trade.get('entryPrice') if trade.get('entryPrice') is not None else trow['price'],
                'currentPrice': trade.get('currentPrice') if trade.get('currentPrice') is not None else trow['price'],
                'profit': trade.get('profit') if trade.get('profit') is not None else trow['profit'],
                'entryTime': trade.get('entryTime') or trow['time_open'],
                'exitTime': trade.get('exitTime') or trow['time_close'],
                'time': trade.get('time') or trow['time_close'] or trow['time_open'] or trow['created_at'],
                # Column status is authoritative when set to 'closed' to prevent stale
                # JSON state from resurrecting closed positions during rehydration.
                'status': (
                    'closed' if str(trow['status'] or '').lower() == 'closed'
                    else (trade.get('status') or trow['status'] or ('closed' if trow['time_close'] else 'open'))
                ),
                'timestamp': trade.get('timestamp') or int((_trade_history_timestamp_key(trade) or 0) or 0),
                'isWinning': trade.get('isWinning') if trade.get('isWinning') is not None else float(trow['profit'] or 0.0) > 0,
                'botId': trade.get('botId') or bot_id,
                'broker': trade.get('broker') or bot_state.get('broker_type') or bot_state.get('brokerName'),
                **trade,
            }

            # Final override: if the trades-table column says 'closed', force closed
            # regardless of what stale runtime JSON in trade_data may say. This keeps
            # the rehydrator from resurrecting a closed position.
            if str(trow['status'] or '').lower() == 'closed':
                trade['status'] = 'closed'
                if not trade.get('exitTime'):
                    trade['exitTime'] = trow['time_close'] or trade.get('time')

            ticket = str(trade.get('ticket') or '').strip()
            if ticket:
                existing = merged_by_ticket.get(ticket)
                merged_by_ticket[ticket] = {**(existing or {}), **trade}
                restored_count += 1
            else:
                ordered_without_ticket.append(trade)

        merged_history = list(merged_by_ticket.values()) + ordered_without_ticket
        merged_history.sort(key=_trade_history_timestamp_key)
        bot_state['tradeHistory'] = merged_history[-500:]
        if restored_count:
            logger.info(f"📊 Synced {restored_count} DB trade records into runtime history for bot {bot_id}")

        # Rehydrate open_positions from any OPEN rows so the tracker (e.g. Binance
        # spot auto-close) has something to iterate after a backend restart.
        # Without this the bot's open-position counter (driven by tradeHistory)
        # blocks new trades while the tracker silently skips an empty dict.
        existing_open_positions = bot_state.get('open_positions') or {}
        if not isinstance(existing_open_positions, dict):
            existing_open_positions = {}
        rehydrated_open = 0
        for trade in merged_history:
            try:
                if str(trade.get('status') or '').lower() != 'open':
                    continue
                ticket = str(trade.get('ticket') or '').strip()
                if not ticket or ticket in existing_open_positions:
                    continue
                existing_open_positions[ticket] = {
                    'ticket': trade.get('ticket'),
                    'symbol': trade.get('symbol'),
                    'type': trade.get('type') or 'BUY',
                    'volume': trade.get('volume'),
                    'entryPrice': trade.get('entryPrice'),
                    'currentPrice': trade.get('currentPrice') or trade.get('entryPrice'),
                    'profit': trade.get('profit') or 0.0,
                    'status': 'open',
                    'entryTime': trade.get('entryTime') or trade.get('time'),
                    'botId': trade.get('botId') or bot_id,
                    'broker': trade.get('broker') or bot_state.get('broker_type') or bot_state.get('brokerName'),
                    'stopLossPrice': trade.get('stopLossPrice') or 0.0,
                    'takeProfitPrice': trade.get('takeProfitPrice') or 0.0,
                    'slPips': trade.get('slPips') or 0.0,
                    'tpPips': trade.get('tpPips') or 0.0,
                    'pipDistance': trade.get('pipDistance') or 0.0,
                }
                rehydrated_open += 1
            except Exception:
                continue
        bot_state['open_positions'] = existing_open_positions
        if rehydrated_open:
            logger.info(f"♻️ Rehydrated {rehydrated_open} open position(s) from DB for bot {bot_id}: {list(existing_open_positions.keys())}")
    except Exception as e:
        logger.warning(f"Could not merge trades from DB for bot {bot_id}: {e}")
    finally:
        if tconn:
            try:
                tconn.close()
            except Exception:
                pass


def _restore_bot_runtime_state(row: sqlite3.Row) -> Dict[str, Any]:
    bot_state = _default_bot_runtime_state(row)
    runtime_state_raw = row['runtime_state']

    if runtime_state_raw:
        try:
            runtime_state = json.loads(runtime_state_raw)
            if isinstance(runtime_state, dict):
                for key, value in runtime_state.items():
                    if key in PERSISTED_BOT_STATE_FIELDS:
                        bot_state[key] = value
        except Exception as e:
            logger.warning(f"Could not restore runtime state for bot {row['bot_id']}: {e}")

    bot_state['botId'] = row['bot_id']
    bot_state['user_id'] = row['user_id']
    bot_state['name'] = row['name']
    bot_state['accountId'] = row['broker_account_id']
    bot_state['credentialId'] = row['credential_id']
    broker_name = canonicalize_broker_name(row['broker_name']) if row['broker_name'] else 'MT5'
    account_number = str(row['account_number'] or '').strip()
    bot_state['brokerName'] = broker_name
    bot_state['broker_type'] = bot_state.get('broker_type') or broker_name
    bot_state['accountNumber'] = bot_state.get('accountNumber') or account_number
    bot_state['account_number'] = bot_state.get('account_number') or bot_state['accountNumber']
    bot_state['mode'] = bot_state.get('mode') or ('live' if row['is_live'] else 'demo')
    resolved_credential = _resolve_active_broker_credential_for_bot(
        row['user_id'],
        broker_name,
        bot_state.get('accountNumber') or account_number,
        bot_state.get('mode'),
        row['credential_id'],
    )
    if resolved_credential:
        resolved_credential_id = str(resolved_credential.get('credential_id') or '').strip()
        previous_credential_id = str(row['credential_id'] or '').strip()
        if resolved_credential_id:
            bot_state['credentialId'] = resolved_credential_id
        resolved_account_number = str(resolved_credential.get('account_number') or '').strip()
        if resolved_account_number:
            bot_state['accountNumber'] = resolved_account_number
            bot_state['account_number'] = resolved_account_number
        resolved_is_live = bool(
            normalize_mt5_is_live_flag(
                canonicalize_broker_name(resolved_credential.get('broker_name')),
                resolved_credential.get('is_live'),
                resolved_credential.get('server'),
            )
        )
        bot_state['mode'] = 'live' if resolved_is_live else 'demo'
        if resolved_credential.get('account_currency'):
            bot_state['displayCurrency'] = str(resolved_credential.get('account_currency')).upper()
        if resolved_credential_id and resolved_credential_id != previous_credential_id:
            logger.warning(
                f"Bot {row['bot_id']}: remapped inactive credential {previous_credential_id or 'N/A'} to active credential {resolved_credential_id}"
            )
            _sync_bot_credential_mapping(row['bot_id'], row['user_id'], resolved_credential_id)
    if row['credential_id']:
        credential_conn = None
        try:
            credential_conn = get_db_connection()
            credential_cursor = credential_conn.cursor()
            credential_cursor.execute(
                '''
                SELECT broker_name, server, is_live, account_currency
                FROM broker_credentials
                WHERE credential_id = ? AND is_active = 1
                LIMIT 1
                ''',
                (bot_state.get('credentialId') or row['credential_id'],)
            )
            credential_row = credential_cursor.fetchone()
            if credential_row:
                normalized_mode_is_live = bool(
                    normalize_mt5_is_live_flag(
                        canonicalize_broker_name(credential_row['broker_name']) if credential_row['broker_name'] else broker_name,
                        credential_row['is_live'],
                        credential_row['server'],
                    )
                )
                bot_state['mode'] = 'live' if normalized_mode_is_live else 'demo'
                if credential_row['account_currency']:
                    bot_state['displayCurrency'] = str(credential_row['account_currency']).upper()
        except Exception as e:
            logger.warning(f"Could not restore credential metadata for bot {row['bot_id']}: {e}")
        finally:
            if credential_conn:
                try:
                    credential_conn.close()
                except Exception:
                    pass
    bot_state['strategy'] = row['strategy']
    bot_state['enabled'] = bool(row['enabled'])
    bot_state['createdAt'] = row['created_at'] or bot_state.get('createdAt') or datetime.now().isoformat()
    bot_state['maxOpenPositions'] = bot_state.get('maxOpenPositions') or 5
    bot_state['maxPositionsPerSymbol'] = bot_state.get('maxPositionsPerSymbol') or bot_state['maxOpenPositions']
    bot_state['managementProfile'] = _normalize_management_profile(bot_state.get('managementProfile'))
    bot_state['managementMode'] = 'manual' if str(bot_state.get('managementMode') or 'assisted').lower() == 'manual' else 'assisted'
    bot_state['managementState'] = bot_state.get('managementState') or 'normal'
    bot_state['autoAdaptationEnabled'] = _coerce_bool(bot_state.get('autoAdaptationEnabled', True), True)
    bot_state['allowAdaptiveRawFallback'] = _coerce_bool(
        bot_state.get('allowAdaptiveRawFallback', bot_state.get('intelligentScanner', False)),
        bool(bot_state.get('intelligentScanner', False)),
    )
    default_signal_threshold_mode = (
        'manual'
        if bot_state['managementMode'] == 'manual' and bot_state.get('signalThreshold') is not None
        else 'auto'
    )
    bot_state['signalThresholdMode'] = str(
        bot_state.get('signalThresholdMode') or default_signal_threshold_mode
    ).lower()
    # Allow explicit signalThresholdMode='manual' regardless of managementMode so that
    # users can pin a manual signalThreshold while still using assisted management.
    if bot_state['signalThresholdMode'] not in ('manual', 'auto'):
        bot_state['signalThresholdMode'] = 'auto'
    bot_state['signalThreshold'] = bot_state.get('signalThreshold') or _default_signal_threshold_for_broker_profile(
        bot_state['managementProfile'],
        broker_name,
    )
    fxcm_threshold_migrated = False
    if (
        broker_name == 'FXCM'
        and bot_state['managementMode'] != 'manual'
        and bot_state['signalThresholdMode'] == 'auto'
    ):
        current_threshold = int(_safe_float(bot_state.get('signalThreshold'), 0.0))
        if current_threshold <= 0 or current_threshold > 10:
            bot_state['signalThreshold'] = 10
            fxcm_threshold_migrated = True
    if broker_name == 'Binance' and bot_state['managementMode'] != 'manual':
        _binance_floor = 5
        _stored_eff = _safe_float(bot_state.get('effectiveSignalThreshold'), 0.0)
        if _stored_eff <= 0 or _stored_eff > 100:
            bot_state['effectiveSignalThreshold'] = _binance_floor
        _stored_sig = int(_safe_float(bot_state.get('signalThreshold'), 0.0))
        if _stored_sig <= 0:
            bot_state['signalThreshold'] = _binance_floor
    if isinstance(bot_state.get('lastNoTradeReason'), str) and 'threshold=' in bot_state.get('lastNoTradeReason', ''):
        bot_state['lastNoTradeReason'] = re.sub(
            r"threshold=\d+(?:\.\d+)?/100",
            f"threshold={_effective_signal_threshold_for_display(bot_state)}/100",
            bot_state['lastNoTradeReason'],
        )
    cadence_floor = _minimum_saved_bot_trade_cadence(
        bot_state.get('strategy', row['strategy']),
        bot_state['managementProfile'],
        bool(bot_state.get('intelligentScanner', False)),
    )
    cadence_migrated = False
    if str(bot_state.get('tradingMode') or '').strip().lower() != cadence_floor['tradingMode']:
        bot_state['tradingMode'] = cadence_floor['tradingMode']
        cadence_migrated = True
    current_trading_interval = int(bot_state.get('tradingInterval') or 0)
    if current_trading_interval <= 0 or current_trading_interval > cadence_floor['tradingInterval']:
        bot_state['tradingInterval'] = cadence_floor['tradingInterval']
        cadence_migrated = True
    current_poll_interval = int(bot_state.get('pollInterval') or 0)
    if current_poll_interval <= 0 or current_poll_interval > cadence_floor['pollInterval']:
        bot_state['pollInterval'] = cadence_floor['pollInterval']
        cadence_migrated = True
    if cadence_migrated:
        bot_state['_cadenceMigrationApplied'] = True
    restored_symbols = bot_state.get('symbols') or (row['symbols'].split(',') if row['symbols'] else ['EURUSDm'])
    original_restored_symbols = [str(symbol).strip() for symbol in restored_symbols if str(symbol).strip()]
    bot_state['symbols'] = validate_and_correct_symbols(restored_symbols, broker_name)
    bot_state['tradeHistory'] = bot_state.get('tradeHistory') or []
    _merge_bot_trade_history_from_db(bot_state, row['bot_id'])
    # ✅ Always resync totalTrades from DB count — covers both: tradeHistory loaded now
    # AND the case where tradeHistory was already in persisted runtime_state but totalTrades=0
    try:
        tsync_conn = build_sqlite_connection(timeout=10.0)
        tsync_cur = tsync_conn.cursor()
        tsync_cur.execute('SELECT COUNT(*) FROM trades WHERE bot_id = ?', (row['bot_id'],))
        db_trade_count = tsync_cur.fetchone()[0] or 0
        tsync_conn.close()
        if db_trade_count > bot_state.get('totalTrades', 0):
            bot_state['totalTrades'] = db_trade_count
            logger.info(f"📊 Resynced totalTrades={db_trade_count} from DB for bot {row['bot_id']}")
    except Exception as e:
        logger.warning(f"Could not resync totalTrades for bot {row['bot_id']}: {e}")
    bot_state['profitHistory'] = bot_state.get('profitHistory') or []
    bot_state['dailyProfits'] = bot_state.get('dailyProfits') or {}
    _rebuild_bot_profit_tracking(bot_state)
    bot_state['accountBalance'] = _safe_float(bot_state.get('accountBalance'), _safe_float(row['cached_balance'], 0.0))
    bot_state['accountEquity'] = _safe_float(bot_state.get('accountEquity'), _safe_float(row['cached_equity'], bot_state['accountBalance']))
    # Restore open_positions from DB if not already in runtime_state
    if not bot_state.get('open_positions'):
        bot_state['open_positions'] = {}
        try:
            tconn2 = build_sqlite_connection(timeout=10.0, row_factory=True)
            tcursor2 = tconn2.cursor()
            tcursor2.execute(
                "SELECT ticket, symbol, order_type, volume, price, time_open FROM trades WHERE bot_id = ? AND status = 'open'",
                (row['bot_id'],)
            )
            for trow in tcursor2.fetchall():
                ticket_str = str(trow['ticket'])
                restored_entry_price = _safe_float(trow['price'], 0.0)
                bot_state['open_positions'][ticket_str] = {
                    'ticket': trow['ticket'],
                    'symbol': trow['symbol'],
                    'type': trow['order_type'],
                    'volume': trow['volume'],
                    'entryPrice': restored_entry_price,
                    'currentPrice': restored_entry_price,
                    'profit': 0.0,
                    'status': 'open',
                    'entryTime': trow['time_open'],
                    'peakProfit': 0.0,
                    'profitProtectionArmed': False,
                    'lockedProfitFloor': 0.0,
                    'restoredFromDb': True,
                }
            tconn2.close()
            if bot_state['open_positions']:
                logger.info(f"📂 Restored {len(bot_state['open_positions'])} open positions from DB for bot {row['bot_id']}")
        except Exception as e:
            logger.warning(f"Could not restore open positions for bot {row['bot_id']}: {e}")
    for restored_ticket, restored_position in (bot_state.get('open_positions') or {}).items():
        if not isinstance(restored_position, dict):
            continue
        restored_entry_price = _safe_float(
            restored_position.get('entryPrice', restored_position.get('price', 0.0)),
            0.0,
        )
        if restored_position.get('entryPrice') is None:
            restored_position['entryPrice'] = restored_entry_price
        if restored_position.get('currentPrice') is None:
            restored_position['currentPrice'] = restored_entry_price
        restored_position['profit'] = _safe_float(restored_position.get('profit'), 0.0)
        restored_position['status'] = str(restored_position.get('status') or 'open').lower()
        restored_position['peakProfit'] = _safe_float(restored_position.get('peakProfit'), 0.0)
        restored_position['lockedProfitFloor'] = _safe_float(restored_position.get('lockedProfitFloor'), 0.0)
        restored_position['profitProtectionArmed'] = bool(restored_position.get('profitProtectionArmed', False))
        restored_position['ticket'] = restored_position.get('ticket') or restored_ticket
    bot_state['strategyHistory'] = bot_state.get('strategyHistory') or []
    bot_state['displayCurrency'] = str(bot_state.get('displayCurrency') or 'USD').upper()
    bot_state['profit'] = bot_state.get('totalProfit', 0.0) or 0.0

    restored_live_equity = max(
        _safe_float(bot_state.get('accountEquity'), 0.0),
        _safe_float(bot_state.get('accountBalance'), 0.0),
    )
    restored_equity_high = _safe_float(bot_state.get('accountEquityHighWatermark'), 0.0)
    restored_mode = str(bot_state.get('mode') or 'demo').strip().lower()
    if (
        restored_mode != 'live'
        and restored_live_equity > 0
        and restored_equity_high > restored_live_equity
        and not (bot_state.get('open_positions') or {})
        and not bot_state.get('drawdownPauseUntil')
    ):
        bot_state['accountEquityHighWatermark'] = round(restored_live_equity, 2)
        bot_state['_runtimeStateAdjusted'] = True
        logger.info(
            f"[RISK] Bot {row['bot_id']} rebased restored demo equity watermark "
            f"from {restored_equity_high:.2f} to {restored_live_equity:.2f} with no open positions."
        )

    if broker_name == 'FXCM' and bot_state['symbols'] != original_restored_symbols:
        logger.info(
            f"🔄 Restored FXCM symbols normalized for bot {row['bot_id']}: "
            f"{original_restored_symbols} -> {bot_state['symbols']}"
        )
        _persist_normalized_bot_symbols(row['bot_id'], bot_state, bot_state['symbols'])
    elif fxcm_threshold_migrated:
        logger.info(
            f"🔧 Migrated FXCM signal threshold to 10 for bot {row['bot_id']}"
        )
        _persist_normalized_bot_symbols(
            row['bot_id'],
            bot_state,
            bot_state['symbols'],
        )

    return bot_state


def _extract_persistable_bot_state(bot_config: Dict[str, Any]) -> Dict[str, Any]:
    return {
        key: bot_config.get(key)
        for key in PERSISTED_BOT_STATE_FIELDS
        if key in bot_config
    }


def _persist_normalized_bot_symbols(bot_id: str, bot_config: Dict[str, Any], normalized_symbols: list) -> None:
    bot_config['symbols'] = normalized_symbols
    runtime_state = _extract_persistable_bot_state(bot_config)
    updated_at = datetime.now().isoformat()

    conn = None
    try:
        conn = get_db_connection()
        cursor = conn.cursor()
        cursor.execute(
            '''
            UPDATE user_bots
            SET symbols = ?,
                runtime_state = ?,
                updated_at = ?
            WHERE bot_id = ?
            ''',
            (
                ','.join(normalized_symbols),
                json.dumps(runtime_state),
                updated_at,
                bot_id,
            ),
        )
        conn.commit()
    except Exception as e:
        logger.warning(f"Could not persist normalized symbols for bot {bot_id}: {e}")
    finally:
        if conn:
            try:
                conn.close()
            except Exception:
                pass


def _prune_fxcm_blocked_symbol(
    bot_id: str,
    bot_config: Dict[str, Any],
    blocked_symbol: Any,
    *,
    broker_conn=None,
) -> bool:
    normalized_symbols = validate_and_correct_symbols(
        bot_config.get('symbols') or ['EUR/USD'],
        'FXCM',
    )
    blocked_keys = _get_fxcm_symbol_candidate_keys(str(blocked_symbol or ''))
    if not blocked_keys:
        return False

    remaining_symbols = [
        symbol
        for symbol in normalized_symbols
        if not (_get_fxcm_symbol_candidate_keys(symbol) & blocked_keys)
    ]
    if broker_conn is not None and remaining_symbols:
        tradable_keys = _get_fxcm_tradable_symbol_keys(broker_conn=broker_conn)
        tradable_symbols = _filter_fxcm_symbols_for_tradability(remaining_symbols, tradable_keys)
        if tradable_symbols:
            remaining_symbols = tradable_symbols

    if not remaining_symbols or remaining_symbols == normalized_symbols:
        return False

    logger.info(
        f"🔄 Bot {bot_id}: Removed blocked FXCM symbol {blocked_symbol} from bot symbols: "
        f"{normalized_symbols} -> {remaining_symbols}"
    )
    _persist_normalized_bot_symbols(bot_id, bot_config, remaining_symbols)
    if bot_id in active_bots:
        active_bots[bot_id]['symbols'] = remaining_symbols
    return True


def _find_broker_closed_trade(active_conn, ticket_str: str) -> Optional[Dict[str, Any]]:
    if active_conn is None or not ticket_str or not hasattr(active_conn, 'get_trades'):
        return None

    try:
        broker_trades = active_conn.get_trades() or []
    except Exception:
        return None

    for broker_trade in broker_trades:
        candidate_ids = {
            str(broker_trade.get('ticket') or ''),
            str(broker_trade.get('deal_id') or ''),
            str(broker_trade.get('tradeId') or ''),
            str(broker_trade.get('trade_id') or ''),
            str(broker_trade.get('position_id') or ''),
            str(broker_trade.get('positionId') or ''),
        }
        candidate_ids.discard('')
        if ticket_str in candidate_ids:
            return broker_trade
    return None


def _purge_unconfirmed_restored_position(
    bot_id: str,
    bot_config: Dict[str, Any],
    ticket_str: str,
    tracked: Dict[str, Any],
) -> None:
    now_iso = datetime.now().isoformat()

    trade_history = bot_config.setdefault('tradeHistory', [])
    retained_history = []
    removed_trade = False
    for trade in trade_history:
        if str(trade.get('ticket')) == str(ticket_str):
            removed_trade = True
            continue
        retained_history.append(trade)
    if removed_trade:
        bot_config['tradeHistory'] = retained_history
        bot_config['totalTrades'] = max(0, int(bot_config.get('totalTrades', 0) or 0) - 1)

    try:
        trade_conn = build_sqlite_connection(timeout=30.0)
        trade_cursor = trade_conn.cursor()
        trade_cursor.execute(
            '''
            DELETE FROM trades
            WHERE ticket = ? AND bot_id = ? AND status = 'open'
            ''',
            (str(ticket_str), bot_id),
        )
        trade_conn.commit()
        trade_conn.close()
    except Exception as db_e:
        logger.warning(f"Bot {bot_id}: Could not purge stale restored trade {ticket_str} from DB: {db_e}")

    bot_config['lastNoTradeReason'] = 'stale restored open position removed after broker reconciliation'
    bot_config['lastNoTradeAt'] = now_iso
    logger.info(
        f"🧹 Bot {bot_id}: Purged unconfirmed restored position {tracked.get('symbol') or ticket_str} "
        f"(ticket {ticket_str}) after broker reconciliation"
    )


_persist_last_time: dict = {}

def persist_bot_runtime_state(bot_id: str, force: bool = False):
    """Persist bot runtime metrics so they can be restored after a VPS restart."""
    global _persist_last_time
    _now = time.time()
    if not force and _now - _persist_last_time.get(bot_id, 0) < 30:
        return  # Debounce: max 1 DB write per bot per 30 seconds
    _persist_last_time[bot_id] = _now

    bot_config = active_bots.get(bot_id)
    if not bot_config:
        return

    today = datetime.now().strftime('%Y-%m-%d')
    daily_profit = float(bot_config.get('dailyProfits', {}).get(today, bot_config.get('dailyProfit', 0.0)) or 0.0)
    total_profit = float(bot_config.get('totalProfit', 0.0) or 0.0)
    bot_config['dailyProfit'] = daily_profit
    bot_config['profit'] = total_profit

    runtime_state = _extract_persistable_bot_state(bot_config)
    updated_at = datetime.now().isoformat()

    conn = None
    for attempt in range(3):
        try:
            conn = get_db_connection()
            cursor = conn.cursor()
            cursor.execute(
                '''
                UPDATE user_bots
                SET enabled = ?,
                    daily_profit = ?,
                    total_profit = ?,
                    runtime_state = ?,
                    updated_at = ?
                WHERE bot_id = ?
                ''',
                (
                    1 if bot_config.get('enabled', False) else 0,
                    daily_profit,
                    total_profit,
                    json.dumps(runtime_state),
                    updated_at,
                    bot_id,
                ),
            )
            conn.commit()
            break
        except Exception as e:
            if attempt < 2:
                time.sleep(0.5 * (attempt + 1))
            else:
                logger.warning(f"Could not persist runtime state for bot {bot_id}: {e}")
        finally:
            if conn:
                try:
                    conn.close()
                except Exception:
                    pass
                conn = None


def log_pause_event(bot_id: str, user_id: str, symbol: str, pause_type: str, retcode: int, 
                    error_message: str, pause_reason: str):
    """Log a market pause/halt event to the database for monitoring and debugging"""
    try:
        pause_id = str(uuid.uuid4())
        detected_at = datetime.now().isoformat()
        
        conn = get_db_connection()
        cursor = conn.cursor()
        
        cursor.execute('''
            INSERT INTO pause_events 
            (pause_id, bot_id, user_id, symbol, pause_type, retcode, error_message, reason, detected_at, created_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        ''', (
            pause_id, bot_id, user_id, symbol, pause_type, retcode, 
            error_message, pause_reason, detected_at, detected_at
        ))
        
        conn.commit()
        conn.close()
        
        logger.info(f"📊 Pause event logged: bot={bot_id}, symbol={symbol}, type={pause_type}, retcode={retcode}")
        return pause_id
    except Exception as e:
        logger.error(f"Error logging pause event: {e}")
        return None


def _resolve_binance_market_for_context(
    *,
    credential_row: Optional[Dict[str, Any]] = None,
    bot_id: Optional[str] = None,
    bot_config: Optional[Dict[str, Any]] = None,
) -> str:
    normalized_market = str(
        (bot_config or {}).get('binanceMarket')
        or (bot_config or {}).get('market')
        or ''
    ).strip().lower()
    if normalized_market in {'spot', 'futures'}:
        return normalized_market

    runtime_bot = active_bots.get(str(bot_id)) if bot_id and isinstance(active_bots, dict) else None
    normalized_market = str(
        (runtime_bot or {}).get('binanceMarket')
        or (runtime_bot or {}).get('market')
        or ''
    ).strip().lower()
    if normalized_market in {'spot', 'futures'}:
        return normalized_market

    normalized_market = str(
        (credential_row or {}).get('market')
        or (credential_row or {}).get('server')
        or 'spot'
    ).strip().lower()
    if normalized_market not in {'spot', 'futures'}:
        normalized_market = 'spot'
    return normalized_market


def _get_bot_thread_credentials(bot_config: Dict[str, Any]) -> Optional[Dict[str, Any]]:
    credential_id = bot_config.get('credentialId')
    resolved_credential = _resolve_active_broker_credential_for_bot(
        bot_config.get('user_id'),
        bot_config.get('broker_type') or bot_config.get('brokerName') or bot_config.get('broker') or '',
        bot_config.get('accountNumber') or bot_config.get('account_number') or bot_config.get('account'),
        bot_config.get('mode'),
        credential_id,
    )
    if resolved_credential:
        resolved_credential_id = str(resolved_credential.get('credential_id') or '').strip()
        if resolved_credential_id and resolved_credential_id != str(credential_id or '').strip():
            bot_config['credentialId'] = resolved_credential_id
            if resolved_credential.get('account_number'):
                bot_config['accountNumber'] = str(resolved_credential.get('account_number'))
                bot_config['account_number'] = str(resolved_credential.get('account_number'))
            _sync_bot_credential_mapping(bot_config.get('botId'), bot_config.get('user_id'), resolved_credential_id)
        credential_id = resolved_credential_id

    if not credential_id:
        return None

    try:
        conn = get_db_connection()
        cursor = conn.cursor()
        cursor.execute(
            '''
            SELECT broker_name, account_number, username, password, server, is_live, api_key
            FROM broker_credentials
            WHERE credential_id = ? AND is_active = 1
            ''',
            (credential_id,),
        )
        credential_row = cursor.fetchone()
        conn.close()
        if not credential_row:
            return None

        broker_name = canonicalize_broker_name(credential_row['broker_name'])
        if broker_name == 'Binance':
            resolved_market = _resolve_binance_market_for_context(
                credential_row=credential_row,
                bot_id=bot_config.get('botId'),
                bot_config=bot_config,
            )
            return {
                'api_key': credential_row['api_key'],
                'api_secret': credential_row['password'],
                'account_number': credential_row['account_number'],
                'server': resolved_market,
                'market': resolved_market,
                'is_live': bool(credential_row['is_live']),
            }

        if broker_name == 'FXCM':
            _username = ''
            try:
                _username = credential_row['username'] or ''
            except (IndexError, KeyError):
                pass
            if not _username:
                try:
                    _username = credential_row['account_number'] or ''
                except (IndexError, KeyError):
                    pass
            return {
                'api_key': credential_row['api_key'] or '',
                'username': _username,
                'password': credential_row['password'] or '',
                'account_number': credential_row['account_number'],
                'server': credential_row['server'],
                'broker': broker_name,
                'is_live': bool(credential_row['is_live']),
            }

        return {
            'account': credential_row['account_number'],
            'password': credential_row['password'],
            'server': credential_row['server'],
            'broker': canonicalize_broker_name(credential_row['broker_name']),
            'is_live': bool(credential_row['is_live']),
        }
    except Exception as e:
        logger.warning(f"Could not load broker credentials for bot {bot_config.get('botId')}: {e}")
        return None


def normalize_mt5_bot_credentials(bot_credentials: Optional[Dict[str, Any]], bot_config: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    normalized = dict(bot_credentials or {})
    bot_config = bot_config or {}

    account_value = (
        normalized.get('account')
        or normalized.get('account_number')
        or bot_config.get('account')
        or bot_config.get('account_number')
    )
    if account_value:
        account_value = str(account_value)
        normalized['account'] = account_value
        normalized['account_number'] = account_value

    broker_name = canonicalize_broker_name(
        normalized.get('broker')
        or normalized.get('broker_name')
        or bot_config.get('broker_type')
        or bot_config.get('brokerName')
        or 'Exness'
    )
    normalized['broker'] = broker_name
    normalized['broker_name'] = broker_name

    if 'is_live' not in normalized:
        normalized['is_live'] = str(bot_config.get('mode', 'demo')).lower() == 'live'

    return normalized


def build_mt5_route_diagnostic(
    bot_credentials: Optional[Dict[str, Any]],
    bot_config: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    normalized = normalize_mt5_bot_credentials(bot_credentials, bot_config)
    broker_name = canonicalize_broker_name(normalized.get('broker') or normalized.get('broker_name') or '')
    account = normalized.get('account') or normalized.get('account_number')
    account_str = str(account) if account not in [None, ''] else None
    is_live = bool(normalized.get('is_live', False))
    configured_server = normalized.get('server')
    configured_path = normalized.get('path')
    is_mt5 = is_mt5_broker_name(broker_name)

    selected_server = normalize_mt5_server_name(broker_name, is_live, configured_server)

    selected_path = None
    if is_mt5:
        selected_path = find_mt5_terminal_path(
            broker_name,
            configured_path,
            is_live=is_live,
        )

    return {
        'broker': broker_name,
        'account': account_str,
        'account_number': account_str,
        'is_mt5': is_mt5,
        'is_live': is_live,
        'configured_server': configured_server,
        'selected_server': selected_server,
        'configured_path': configured_path,
        'selected_path': selected_path,
        'path_exists': bool(selected_path and os.path.exists(selected_path)),
        'cache_key': get_balance_cache_key(broker_name, account_str) if is_mt5 and account_str else None,
    }


def log_mt5_route_diagnostic(
    context: str,
    bot_credentials: Optional[Dict[str, Any]],
    bot_config: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    diagnostic = build_mt5_route_diagnostic(bot_credentials, bot_config)
    if diagnostic.get('is_mt5'):
        logger.info(
            "[MT5 ROUTE] %s | broker=%s | account=%s | is_live=%s | server=%s | path=%s | path_exists=%s | cache_key=%s",
            context,
            diagnostic.get('broker'),
            diagnostic.get('account'),
            diagnostic.get('is_live'),
            diagnostic.get('selected_server') or diagnostic.get('configured_server'),
            diagnostic.get('selected_path') or diagnostic.get('configured_path') or 'missing',
            diagnostic.get('path_exists'),
            diagnostic.get('cache_key') or '-',
        )
    return diagnostic


def start_enabled_bots_on_startup():
    """Restart previously enabled bots after a backend/VPS restart."""
    if not AUTO_RESTART_BOTS_ON_STARTUP:
        logger.warning("⏸️ Auto-restart of bots on backend startup is disabled (set AUTO_RESTART_BOTS_ON_STARTUP=true to enable)")
        return 0

    restarted_bots = 0

    for bot_id, bot_config in list(active_bots.items()):
        if not bot_config.get('enabled'):
            continue
        if bot_id in bot_threads and bot_threads[bot_id].is_alive():
            continue
        if BOT_STARTUP_RESTART_LIMIT and restarted_bots >= BOT_STARTUP_RESTART_LIMIT:
            logger.warning(
                f"⏸️ Reached BOT_STARTUP_RESTART_LIMIT={BOT_STARTUP_RESTART_LIMIT}; remaining enabled bots were not auto-restarted"
            )
            break

        bot_config['symbols'] = validate_and_correct_symbols(
            bot_config.get('symbols', ['EURUSDm']),
            bot_config.get('brokerName') or bot_config.get('broker_type'),
        )

        bot_mode = _normalize_bot_mode_value(bot_config.get('mode'), bot_config.get('is_live'))
        current_user_mode = _normalize_bot_mode_value(
            get_user_trading_mode_value(bot_config.get('user_id'), fallback_mode=bot_mode)
        )
        if bot_mode != current_user_mode:
            running_bots[bot_id] = False
            logger.info(
                f"⏸️ Skipping auto-restart for bot {bot_id}: bot mode is {bot_mode.upper()} "
                f"while user trading mode is {current_user_mode.upper()}"
            )
            continue

        bot_stop_flags[bot_id] = False
        running_bots[bot_id] = True
        bot_credentials = _get_bot_thread_credentials(bot_config)
        if _reset_persisted_daily_pause_on_restart(bot_config):
            persist_bot_runtime_state(bot_id)

        bot_thread = threading.Thread(
            target=continuous_bot_trading_loop,
            args=(bot_id, bot_config.get('user_id'), bot_credentials),
            daemon=True,
            name=f"BotThread-{bot_id}",
        )
        bot_threads[bot_id] = bot_thread
        bot_thread.start()
        restarted_bots += 1
        logger.info(f"♻️ Restarted bot {bot_id} from persisted runtime state")
        if BOT_STARTUP_RESTART_DELAY_SECONDS > 0:
            # Add small random jitter (0-5s) so bots don't all hit the MT5 lock in sync
            jitter = random.uniform(0, 5)
            time.sleep(BOT_STARTUP_RESTART_DELAY_SECONDS + jitter)

    return restarted_bots


def stop_bot_runtime(bot_id: str, bot_config: Dict[str, Any]) -> Dict[str, Any]:
    # If worker pool is active, send stop via worker queue
    if worker_pool_manager and worker_pool_manager.enabled:
        worker_pool_manager.stop_bot(bot_id)
        logger.info(f"🛑 Bot {bot_id}: Stop dispatched to worker pool")
    elif bot_id in bot_threads and bot_threads[bot_id].is_alive():
        logger.info(f"🛑 Bot {bot_id}: Stopping background trading thread...")
        bot_stop_flags[bot_id] = True
        bot_threads[bot_id].join(timeout=30)
        logger.info(f"✅ Bot {bot_id}: Background thread stopped")

    bot_config['enabled'] = False
    running_bots[bot_id] = False
    
    # OPTIMIZATION: Clean up cached connections for this bot to free memory
    user_id = bot_config.get('user_id', '')
    account = bot_config.get('account_number', bot_config.get('accountId', 'unknown'))
    broker_label = canonicalize_broker_name(bot_config.get('brokerName') or bot_config.get('broker_type') or 'Exness')
    if user_id and account:
        cache_key = f"{user_id}|{broker_label}|{account}"
        with broker_connection_cache_lock:
            if cache_key in broker_connection_cache:
                broker_connection_cache.pop(cache_key)
                logger.debug(f"♻️  Bot {bot_id}: Cached connection cleaned up ({len(broker_connection_cache)} remaining)")
    
    persist_bot_runtime_state(bot_id)

    logger.info(f"⏸️ Bot {bot_id} stopped (still in system, can be restarted)")
    logger.info(f"   Total Trades: {bot_config.get('totalTrades', 0)}")
    logger.info(f"   Total Profit: ${bot_config.get('totalProfit', 0):.2f}")

    return {
        'botId': bot_id,
        'totalTrades': bot_config.get('totalTrades', 0),
        'winningTrades': bot_config.get('winningTrades', 0),
        'totalProfit': round(float(bot_config.get('totalProfit', 0.0) or 0.0), 2),
        'mode': bot_config.get('mode', 'demo'),
        'symbols': bot_config.get('symbols', []),
    }


def load_user_bots_from_database(enabled_only: bool = False):
    """Load user-created bots from database into active_bots memory."""
    try:
        conn = get_db_connection()
        cursor = conn.cursor()

        query = '''
            SELECT
                ub.bot_id,
                ub.user_id,
                ub.name,
                ub.strategy,
                ub.broker_account_id,
                ub.symbols,
                ub.enabled,
                ub.created_at,
                ub.daily_profit,
                ub.total_profit,
                ub.runtime_state,
                bc.credential_id,
                bcr.broker_name,
                bcr.account_number,
                bcr.is_live,
                bcr.account_currency,
                bcr.cached_balance,
                bcr.cached_equity
            FROM user_bots ub
            LEFT JOIN bot_credentials bc ON bc.bot_id = ub.bot_id AND bc.user_id = ub.user_id
            LEFT JOIN broker_credentials bcr ON bcr.credential_id = bc.credential_id
            WHERE ub.status = 'active'
        '''
        if enabled_only:
            query += ' AND ub.enabled = 1'

        cursor.execute(query)
        
        bots_loaded = 0
        for row in cursor.fetchall():
            bot_id = row['bot_id']

            if bot_id in active_bots:
                continue

            restored_bot = _restore_bot_runtime_state(row)
            # OVERRIDE: Force use of profile default thresholds (disable persisted high thresholds)
            # MANUAL MODE GUARD: skip override when user has pinned signalThresholdMode='manual'
            if str(restored_bot.get('signalThresholdMode') or '').strip().lower() != 'manual':
                profile = _normalize_management_profile(restored_bot.get('managementProfile', 'beginner'))
                profile_defaults = BOT_MANAGEMENT_PROFILES.get(profile, BOT_MANAGEMENT_PROFILES['beginner'])
                restored_bot['signalThreshold'] = profile_defaults.get('signalThreshold', 5)
            active_bots[bot_id] = restored_bot
            if restored_bot.pop('_cadenceMigrationApplied', False) or restored_bot.pop('_runtimeStateAdjusted', False):
                persist_bot_runtime_state(bot_id, force=True)
            bots_loaded += 1
        
        conn.close()
        
        if bots_loaded > 0:
            logger.info(f"✅ Loaded {bots_loaded} user-created bots from database")
        
        return bots_loaded
    
    except Exception as e:
        logger.error(f"❌ Error loading user bots from database: {e}")
        return 0

