@app.route('/api/broker/credentials', methods=['GET'])
@require_session
def get_broker_credentials():
    """Get all broker credentials for authenticated user (deduped - latest only)"""
    try:
        user_id = request.user_id
        conn = get_db_connection()
        cursor = conn.cursor()
        
        cursor.execute('''
            SELECT credential_id, broker_name, account_number, server, is_live, is_active,
                   created_at, account_currency, COALESCE(cached_balance, 0), mt5_terminal_path
            FROM broker_credentials
            WHERE user_id = ? AND is_active = 1
            ORDER BY broker_name, account_number, created_at DESC
        ''', (user_id,))
        
        rows = cursor.fetchall()
        conn.close()
        
        # Deduplicate: keep only the latest credential for each broker+account+mode combo
        seen = {}  # key: (broker_name, account_number, is_live), value: credential_dict
        
        for row in rows:
            broker_name = canonicalize_broker_name(row[1])
            account_number = str(row[2] or '').strip()
            normalized_is_live = bool(normalize_mt5_is_live_flag(broker_name, row[4], row[3]))
            key = (broker_name, account_number, normalized_is_live)
            if key not in seen:  # Keep first (most recent due to ORDER BY DESC)
                seen[key] = {
                    'credential_id': row[0],
                    'broker': broker_name,
                    'account_number': account_number,
                    'server': row[3],
                    'is_live': normalized_is_live,
                    'is_active': bool(row[5]),
                    'created_at': row[6],
                    'account_currency': (row[7] or 'USD').upper(),
                    'cached_balance': float(row[8] or 0),
                    'has_cached_balance': float(row[8] or 0) > 0,
                    'mt5_terminal_path': row[9],
                }
        
        credentials = list(seen.values())
        demo_credentials = [c for c in credentials if not c['is_live']]
        live_credentials = [c for c in credentials if c['is_live']]
        
        logger.info(f"✅ Retrieved {len(credentials)} unique broker credentials for user {user_id}")
        return jsonify({
            'success': True,
            'credentials': credentials,
            'demoCredentials': demo_credentials,
            'liveCredentials': live_credentials,
            'count': len(credentials)
        }), 200
        
    except Exception as e:
        logger.error(f"❌ Error fetching credentials: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/broker/credentials', methods=['POST'])
@require_session
def save_broker_credentials():
    """Save new broker credentials for user
    
    Supports multiple brokers:
    - MetaQuotes/MT5: account_number, password, server, is_live
    - IG Markets: api_key, username, password, is_live
    - XM Global/XM: account_number, password, server, is_live
    - Binance: api_key, api_secret, optional market/server
    - FXCM: username/password or token/api_key, optional account_number
    - OANDA: api_key, account_number
    - Exness: account_number, password, server, is_live
    - PXBT: account_number, password, server, is_live
    """
    try:
        user_id = request.user_id
        data = request.json
        
        broker_name = canonicalize_broker_name(data.get('broker_name') or data.get('broker'))
        account_number = data.get('account_number')
        password = data.get('password')
        server = data.get('server')
        api_key = data.get('api_key')  # For IG Markets
        username = data.get('username')  # For IG Markets
        api_secret = data.get('api_secret')
        token = data.get('token')
        fxcm_login_mode = str(data.get('fxcm_login_mode') or '').strip().lower()
        mt5_terminal_path = data.get('mt5_terminal_path') or data.get('mt5_path')
        is_live = normalize_mt5_is_live_flag(broker_name, data.get('is_live', False), server)
        
        if not broker_name:
            return jsonify({'success': False, 'error': 'broker_name required'}), 400

        if str(broker_name).strip().lower() in {'ig', 'ig markets', 'ig.com'}:
            return jsonify({
                'success': False,
                'error': 'IG Markets is not integrated in the current backend setup. Supported direct brokers: Exness, Binance, FXCM, OANDA.'
            }), 400
        
        # Validate based on broker type
        # IG Markets integration removed
        if broker_name in ['Binance']:
            password = api_secret or password
            if not api_key or not password:
                return jsonify({
                    'success': False,
                    'error': 'Binance requires: api_key, api_secret'
                }), 400
            server = (server or data.get('market') or 'spot').lower()
            account_number = account_number or server.upper()
        elif broker_name in ['FXCM']:
            username = str(username or data.get('login_id') or '').strip()
            account_number = str(account_number or '').strip()
            password = str(password or '').strip()
            token = str(token or '').strip()
            api_key = str(api_key or '').strip()
            resolved_fxcm_info = None
            if not ((username and password) or token or api_key):
                return jsonify({
                    'success': False,
                    'error': 'FXCM requires either Login ID + Password or an API token'
                }), 400

            # Keep FXCM login ID separate from the trading account row ID returned by ForexConnect.
            # If the user leaves account_number blank, resolve and persist the actual account row when possible.
            if username and password and not account_number:
                server = server or ('real' if is_live else 'demo')
                fxcm_conn = FXCMConnection(credentials={
                    'username': username,
                    'password': password,
                    'api_key': token or api_key,
                    'account_number': account_number,
                    'server': server,
                    'connection': 'Real' if is_live else 'Demo',
                    'is_live': is_live,
                })
                if fxcm_conn.connect():
                    resolved_fxcm_info = fxcm_conn.get_account_info() or {}
                    resolved_account = str(resolved_fxcm_info.get('account_id') or resolved_fxcm_info.get('accountNumber') or '').strip()
                    if resolved_account:
                        account_number = resolved_account
                    fxcm_conn.disconnect()

            if not account_number:
                return jsonify({
                    'success': False,
                    'error': 'FXCM trading account ID could not be resolved. Test the connection first or enter the Trading Account ID before saving.'
                }), 400
            api_key = token or api_key
        elif broker_name in ['OANDA']:
            if not api_key or not account_number:
                return jsonify({
                    'success': False,
                    'error': 'OANDA requires: api_key, account_number'
                }), 400
            server = server or 'REST-API'
            password = ''
        elif broker_name in ['MetaQuotes', 'XM Global', 'XM', 'MetaTrader 5', 'PXBT']:
            if not account_number or not password:
                return jsonify({
                    'success': False,
                    'error': f'{broker_name} requires: account_number, password, server'
                }), 400
            if not server:
                if broker_name == 'MetaQuotes':
                    server = normalize_mt5_server_name('MetaQuotes', is_live, server)
                elif broker_name in ['XM', 'XM Global']:
                    server = normalize_mt5_server_name('XM Global', is_live, server)
                elif broker_name == 'PXBT':
                    server = normalize_mt5_server_name('PXBT', is_live, server)
                else:  # MetaTrader 5
                    server = normalize_mt5_server_name('MetaTrader 5', is_live, server)
        elif broker_name in ['Exness']:
            if not account_number or not password:
                return jsonify({
                    'success': False,
                    'error': 'Exness requires: account_number, password, server'
                }), 400
            if not server:
                server = 'Exness-MT5Real27' if is_live else 'Exness-MT5Trial9'
        else:
            return jsonify({
                'success': False,
                'error': f'Unknown broker: {broker_name}. Supported: MetaQuotes, Exness, Binance, FXCM, OANDA'
            }), 400

        created_at = datetime.now().isoformat()
        
        conn = get_db_connection()
        cursor = conn.cursor()
        
        # Use account_number as primary identifier
        account_id = account_number
        
        # Check if credential already exists for this user and broker
        # IG Markets integration removed
        cursor.execute('''
            SELECT credential_id FROM broker_credentials
            WHERE user_id = ? AND broker_name = ? AND account_number = ? AND is_live = ?
        ''', (user_id, broker_name, account_number, 1 if is_live else 0))
        
        existing = cursor.fetchone()
        
        if existing:
            # Update existing credential
            credential_id = existing[0]
            # IG Markets integration removed
            if broker_name in ['MetaQuotes', 'XM Global', 'XM', 'MetaTrader 5', 'Exness', 'PXBT']:
                cursor.execute('''
                    UPDATE broker_credentials
                    SET account_number = ?, password = ?, server = ?, is_live = ?, mt5_terminal_path = ?, updated_at = ?
                    WHERE credential_id = ?
                ''', (account_number, password, server, 1 if is_live else 0, mt5_terminal_path, created_at, credential_id))
            else:
                cursor.execute('''
                    UPDATE broker_credentials
                    SET account_number = ?, password = ?, server = ?, api_key = ?, username = ?, is_live = ?, updated_at = ?
                    WHERE credential_id = ?
                ''', (account_number, password, server, api_key or '', username or '', 1 if is_live else 0, created_at, credential_id))
            
            logger.info(f"✅ Updated broker credential for user {user_id}: {broker_name} | Account: {account_id}")
        else:
            # Create new credential
            credential_id = str(uuid.uuid4())
            cursor.execute('''
                INSERT INTO broker_credentials
                (credential_id, user_id, broker_name, account_number, password, server, 
                 api_key, username, is_live, is_active, created_at, updated_at, account_currency, mt5_terminal_path)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, 1, ?, ?, ?, ?)
            ''', (
                credential_id, user_id, broker_name, account_number or '', password, server or '',
                api_key or '', username or '', 1 if is_live else 0, created_at, created_at, 'USD', mt5_terminal_path
            ))
            logger.info(f"✅ Created new broker credential for user {user_id}: {broker_name} | Account: {account_id}")
        
        encrypt_credential_at_rest(cursor, credential_id)
        conn.commit()

        if broker_name == 'FXCM' and resolved_fxcm_info:
            persist_account_snapshot(
                broker_name,
                account_number,
                resolved_fxcm_info,
                credential_id=credential_id,
                user_id=user_id,
            )
        
        # CRITICAL: Fetch actual currency from broker account and update database
        try:
            # For Exness/MT5 brokers, get actual account currency
            if broker_name in ['Exness', 'MetaQuotes', 'XM', 'XM Global', 'PXBT', 'MetaTrader 5']:
                test_creds = {
                    'account_number': account_number,
                    'password': password,
                    'server': server,
                    'broker_name': broker_name,
                }
                mt5_conn = MT5Connection(test_creds)
                if mt5_conn.connect():
                    acct_info = mt5_conn.get_account_info()
                    if acct_info and acct_info.get('currency'):
                        account_currency = acct_info['currency'].upper()
                        cursor.execute('''
                            UPDATE broker_credentials 
                            SET account_currency = ? 
                            WHERE credential_id = ?
                        ''', (account_currency, credential_id))
                        conn2 = get_db_connection()
                        conn2.execute('UPDATE broker_credentials SET account_currency = ? WHERE credential_id = ?', (account_currency, credential_id))
                        conn2.commit()
                        conn2.close()
                        logger.info(f"✅ Captured account currency: {account_currency} for credential {credential_id}")
                    mt5_conn.disconnect()
            elif broker_name == 'Binance':
                # Binance always uses USDT
                cursor.execute('UPDATE broker_credentials SET account_currency = ? WHERE credential_id = ?', ('USDT', credential_id))
                conn2 = get_db_connection()
                conn2.execute('UPDATE broker_credentials SET account_currency = ? WHERE credential_id = ?', ('USDT', credential_id))
                conn2.commit()
                conn2.close()
            elif broker_name == 'FXCM':
                cursor.execute('UPDATE broker_credentials SET account_currency = ? WHERE credential_id = ?', ('USD', credential_id))
                conn2 = get_db_connection()
                conn2.execute('UPDATE broker_credentials SET account_currency = ? WHERE credential_id = ?', ('USD', credential_id))
                conn2.commit()
                conn2.close()
        except Exception as e:
            logger.warning(f"⚠️ Could not auto-capture currency from broker: {e}")
        
        conn.close()
        
        return jsonify({
            'success': True,
            'credential': {
                'credential_id': credential_id,
                'broker': broker_name,
                'broker_name': broker_name,
                'account_number': account_number or username,
                'server': server or '',
                'is_live': is_live,
                'mt5_terminal_path': mt5_terminal_path,
                'is_active': True,
                'created_at': created_at,
                'account_currency': (locals().get('account_currency') or 'USD').upper(),
            }
        }), 201
        
    except Exception as e:
        logger.error(f"❌ Error saving broker credentials: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/broker/credentials/<credential_id>', methods=['DELETE'])
@require_session
def delete_broker_credentials(credential_id):
    """Delete broker credential"""
    try:
        user_id = request.user_id
        conn = get_db_connection()
        cursor = conn.cursor()
        
        # Verify credential belongs to user
        cursor.execute('''
            SELECT user_id FROM broker_credentials WHERE credential_id = ?
        ''', (credential_id,))
        
        row = cursor.fetchone()
        if not row or row[0] != user_id:
            conn.close()
            return jsonify({'success': False, 'error': 'Credential not found or does not belong to user'}), 404
        
        # Delete credential
        cursor.execute('''
            DELETE FROM broker_credentials WHERE credential_id = ?
        ''', (credential_id,))
        
        conn.commit()
        conn.close()
        
        logger.info(f"✅ Deleted broker credential {credential_id} for user {user_id}")
        return jsonify({'success': True, 'message': 'Credential deleted'}), 200
        
    except Exception as e:
        logger.error(f"❌ Error deleting credential: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/broker/test-connection', methods=['POST'])
@require_session
def test_broker_connection():
    """Test broker connection and save credentials (supports MT5, Exness, Binance, etc.)"""
    try:
        user_id = request.user_id
        data = request.json
        broker = canonicalize_broker_name(data.get('broker', ''))
        is_live = normalize_mt5_is_live_flag(broker, data.get('is_live', False), data.get('server'))

        logger.info(f"🔌 Testing broker connection: {broker} | User: {user_id}")

        # IG MARKETS INTEGRATION REMOVED - only MT5 and other brokers supported
        if broker == 'IG Markets':
            return jsonify({
                'success': False,
                'error': 'IG Markets integration has been removed. Supported brokers: Exness, Binance, FXCM, OANDA'
            }), 400

        if broker in ['PXBT', 'XM', 'XM Global']:
            return jsonify({
                'success': False,
                'error': 'XM and PXBT are temporarily unsupported. Use Exness, Binance, FXCM, or OANDA instead.'
            }), 400

        # ==================== BINANCE ====================
        elif broker == 'Binance':
            api_key = data.get('api_key')
            api_secret = data.get('api_secret') or data.get('password')
            market = (data.get('market') or data.get('server') or 'spot').lower()
            account_id = data.get('account_number') or market.upper()

            if not all([api_key, api_secret]):
                return jsonify({'success': False, 'error': 'Missing Binance fields: api_key, api_secret'}), 400

            binance_conn = BinanceConnection(credentials={
                'api_key': api_key,
                'api_secret': api_secret,
                'account_number': account_id,
                'server': market,
                'is_live': is_live,
            })
            if not binance_conn.connect():
                backend_host = (request.host or '').strip()
                whitelist_host = backend_host.split(':', 1)[0] if backend_host else ''
                error_message = binance_conn.last_error or 'Failed to authenticate with Binance'
                auth_attempts = binance_conn._describe_auth_attempts() if hasattr(binance_conn, '_describe_auth_attempts') else ''
                if getattr(binance_conn, 'last_error_code', None) == -2015:
                    mode_label = 'LIVE' if is_live else 'DEMO'
                    error_message = (
                        f'Binance {mode_label} {market} key rejected (-2015). '
                        'Check API secret, Enable Reading, and Binance environment.'
                    )
                if getattr(binance_conn, 'last_error_code', None) == -2015 and whitelist_host:
                    error_message = (
                        f'{error_message} Whitelist {whitelist_host} in Binance API restrictions.'
                    )
                return jsonify({
                    'success': False,
                    'error': error_message,
                    'error_code': getattr(binance_conn, 'last_error_code', None),
                    'whitelist_host': whitelist_host or None,
                    'attempts': auth_attempts or None,
                }), 401

            effective_is_live = bool(getattr(binance_conn, 'effective_is_live', is_live))
            account_info = binance_conn.get_account_info()
            binance_conn.disconnect()

            conn = get_db_connection()
            cursor = conn.cursor()
            now_iso = datetime.now().isoformat()
            cursor.execute(
                '''
                SELECT credential_id
                FROM broker_credentials
                WHERE user_id = ?
                  AND broker_name = ?
                  AND is_active = 1
                  AND (
                        account_number = ?
                        OR (
                            is_live = ?
                            AND LOWER(COALESCE(server, 'spot')) = LOWER(?)
                            AND api_key = ?
                        )
                  )
                ORDER BY CASE WHEN account_number = ? THEN 0 ELSE 1 END,
                         CASE WHEN TRIM(COALESCE(credential_id, '')) = '' THEN 1 ELSE 0 END,
                         COALESCE(updated_at, created_at, '') DESC
                ''',
                (user_id, 'Binance', account_id, int(effective_is_live), market, api_key, account_id),
            )
            existing = cursor.fetchone()

            if existing:
                credential_id = existing['credential_id'] if hasattr(existing, 'keys') else existing[0]
                cursor.execute(
                    '''
                    UPDATE broker_credentials
                    SET account_number = ?, password = ?, server = ?, is_live = ?, is_active = 1, api_key = ?, updated_at = ?
                    WHERE credential_id = ?
                    ''',
                    (account_id, api_secret, market, int(effective_is_live), api_key, now_iso, credential_id),
                )
            else:
                credential_id = str(uuid.uuid4())
                cursor.execute('''
                    INSERT INTO broker_credentials 
                    (credential_id, user_id, broker_name, account_number, password, server, is_live, is_active, api_key, created_at, updated_at)
                    VALUES (?, ?, ?, ?, ?, ?, ?, 1, ?, ?, ?)
                ''', (credential_id, user_id, 'Binance', account_id, api_secret, market, int(effective_is_live), api_key, now_iso, now_iso))

            cursor.execute(
                '''
                UPDATE broker_credentials
                SET is_active = 0, updated_at = ?
                WHERE user_id = ?
                  AND broker_name = 'Binance'
                  AND is_active = 1
                                    AND (
                                                account_number = ?
                                                OR (
                                                        is_live = ?
                                                        AND LOWER(COALESCE(server, 'spot')) = LOWER(?)
                                                        AND api_key = ?
                                                )
                                    )
                  AND COALESCE(credential_id, '') != ?
                ''',
                                (now_iso, user_id, account_id, int(effective_is_live), market, api_key, credential_id),
            )
            encrypt_credential_at_rest(cursor, credential_id)
            conn.commit()
            # Invalidate credential cache to ensure fresh data on next access
            cache_key = f"cred_{credential_id}_{user_id}"
            credential_cache.pop(cache_key, None)
            conn.close()

            response_warning = None
            if effective_is_live != bool(is_live):
                response_warning = (
                    'Binance key authenticated against the live environment, so it was saved as a live credential.'
                    if effective_is_live
                    else 'Binance key authenticated against demo/testnet, so it was saved as a demo credential.'
                )

            return jsonify({
                'success': True,
                'message': f'Successfully connected to Binance account {account_id}',
                'credential_id': credential_id,
                'broker': 'Binance',
                'account_number': account_id,
                'balance': account_info.get('balance', 0),
                'currency': account_info.get('currency', 'USDT'),
                'is_live': effective_is_live,
                'status': 'CONNECTED',
                'warning': response_warning,
                'timestamp': datetime.now().isoformat()
            }), 200

        # ==================== FXCM ====================
        elif broker == 'FXCM':
            login_id = str(data.get('username') or data.get('login_id') or '').strip()
            password = str(data.get('password') or '').strip()
            token = str(data.get('token') or data.get('api_key') or data.get('api_token') or '').strip()
            requested_account_id = str(data.get('account_number') or '').strip()
            use_username_mode = bool(login_id and password)
            account_id = requested_account_id
            if not (token or use_username_mode):
                return jsonify({'success': False, 'error': 'Missing FXCM fields: provide Login ID + Password or an API token'}), 400

            fxcm_conn = FXCMConnection(credentials={
                'api_key': token,
                'username': login_id,
                'password': password,
                'fxcm_login_mode': 'forexconnect' if use_username_mode else 'rest',
                'account_number': account_id,
                'server': data.get('server') or ('real' if is_live else 'demo'),
                'connection': 'Real' if is_live else 'Demo',
                'is_live': is_live,
            })
            if not fxcm_conn.connect():
                return jsonify({'success': False, 'error': fxcm_conn.last_error or 'Failed to authenticate with FXCM'}), 401

            account_info = fxcm_conn.get_account_info()
            fxcm_conn.disconnect()
            account_id = str(account_info.get('account_id') or account_info.get('accountNumber') or account_id or login_id or 'FXCM').strip()

            conn = get_db_connection()
            cursor = conn.cursor()
            server_name = data.get('server') or ('real' if is_live else 'demo')
            timestamp = datetime.now().isoformat()
            cursor.execute('''
                SELECT credential_id FROM broker_credentials
                WHERE user_id = ? AND broker_name = ? AND account_number = ?
            ''', (user_id, 'FXCM', account_id))
            existing = cursor.fetchone()

            if existing:
                credential_id = existing[0]
                cursor.execute('''
                    UPDATE broker_credentials
                    SET password = ?, server = ?, is_live = ?, is_active = 1, api_key = ?, updated_at = ?, username = ?, account_currency = ?
                    WHERE credential_id = ?
                ''', (
                    (password or '') if use_username_mode else '',
                    server_name,
                    int(is_live),
                    token or '',
                    timestamp,
                    login_id if use_username_mode else None,
                    'USD',
                    credential_id,
                ))
            else:
                credential_id = str(uuid.uuid4())
                cursor.execute('''
                    INSERT INTO broker_credentials 
                    (credential_id, user_id, broker_name, account_number, password, server, is_live, is_active, api_key, created_at, updated_at, username, account_currency)
                    VALUES (?, ?, ?, ?, ?, ?, ?, 1, ?, ?, ?, ?, ?)
                ''', (
                    credential_id,
                    user_id,
                    'FXCM',
                    account_id,
                    (password or '') if use_username_mode else '',
                    server_name,
                    int(is_live),
                    token or '',
                    timestamp,
                    timestamp,
                    login_id if use_username_mode else None,
                    'USD',
                ))
            encrypt_credential_at_rest(cursor, credential_id)
            conn.commit()
            # Invalidate credential cache to ensure fresh data on next access
            cache_key = f"cred_{credential_id}_{user_id}"
            credential_cache.pop(cache_key, None)
            conn.close()

            if account_info:
                persist_account_snapshot(
                    'FXCM',
                    account_id,
                    account_info,
                    credential_id=credential_id,
                    user_id=user_id,
                )
                _store_fxcm_endpoint_snapshot(
                    credential_id,
                    account_info=account_info,
                    data_source=account_info.get('dataSource', 'live') if isinstance(account_info, dict) else 'live',
                )

            return jsonify({
                'success': True,
                'message': f'Successfully connected to FXCM account {account_id}',
                'credential_id': credential_id,
                'broker': 'FXCM',
                'account_number': account_id,
                'balance': float(account_info.get('balance', 0) or 0),
                'equity': float(account_info.get('equity', account_info.get('balance', 0)) or 0),
                'free_margin': float(account_info.get('marginFree', account_info.get('margin_free', 0)) or 0),
                'margin': float(account_info.get('margin', 0) or 0),
                'margin_level': float(account_info.get('margin_level', account_info.get('marginLevel', 0)) or 0),
                'profit': float(account_info.get('profit', account_info.get('total_pl', 0)) or 0),
                'currency': account_info.get('currency', 'USD'),
                'is_live': is_live,
                'status': 'CONNECTED',
                'timestamp': datetime.now().isoformat()
            }), 200

        # ==================== OANDA ====================
        elif broker == 'OANDA':
            api_key = data.get('api_key')
            account_id = data.get('account_number') or data.get('account_id')
            if not api_key or not account_id:
                return jsonify({'success': False, 'error': 'Missing OANDA fields: api_key, account_number'}), 400

            oanda_conn = OANDAConnection(credentials={
                'api_key': api_key,
                'account_number': account_id,
                'is_live': is_live,
            })
            if not oanda_conn.connect():
                return jsonify({'success': False, 'error': 'Failed to authenticate with OANDA'}), 401

            account_info = oanda_conn.get_account_info()
            oanda_conn.disconnect()

            conn = get_db_connection()
            cursor = conn.cursor()
            credential_id = str(uuid.uuid4())
            cursor.execute('''
                INSERT INTO broker_credentials 
                (credential_id, user_id, broker_name, account_number, password, server, is_live, is_active, api_key, created_at, updated_at)
                VALUES (?, ?, ?, ?, ?, ?, ?, 1, ?, ?, ?)
            ''', (credential_id, user_id, 'OANDA', account_id, '', 'REST-API', int(is_live), api_key, datetime.now().isoformat(), datetime.now().isoformat()))
            encrypt_credential_at_rest(cursor, credential_id)
            conn.commit()
            conn.close()

            return jsonify({
                'success': True,
                'message': f'Successfully connected to OANDA account {account_id}',
                'credential_id': credential_id,
                'broker': 'OANDA',
                'account_number': account_id,
                'currency': account_info.get('currency', 'USD'),
                'is_live': is_live,
                'status': 'CONNECTED',
                'timestamp': datetime.now().isoformat()
            }), 200

        # ==================== MT5 BROKERS ====================
        else:
            account = data.get('account_number', '')
            password = data.get('password', '')
            server = data.get('server', '')
            is_live = normalize_mt5_is_live_flag(broker, is_live, server)
            deferred_verification_warning = None
            skip_exness_warmup = False
            
            # Validate required fields
            if not all([broker, account, password, server]):
                return jsonify({
                    'success': False,
                    'error': 'Missing required fields for MT5: broker, account_number, password, server'
                }), 400

            # Exness guard: prevent accidental wrong account IDs (e.g. extra digit typos)
            # Current known Exness account IDs in this deployment are 9-digit numeric values.
            if broker.lower() == 'exness':
                account_str = str(account).strip()
                if not account_str.isdigit() or len(account_str) != 9:
                    return jsonify({
                        'success': False,
                        'error': 'Invalid Exness account number. Enter the exact 9-digit MT5 account ID.'
                    }), 400
                account = account_str

            defer_exness_verification = broker.lower() == 'exness'
            actual_balance = 10000.00  # Default fallback
            actual_equity = 10000.00
            actual_margin_free = 10000.00
            actual_margin_used = 0.00
            actual_margin_level = 0.00
            actual_profit = 0.00
            actual_currency = 'USD'  # Default; overwritten below from MT5 account_info().currency
            got_real_balance = False
            verified_connection = False
            
            # Fix server name for MT5 brokers — use per-account is_live, NOT global ENVIRONMENT
            broker_l = broker.lower()
            if broker_l in ['metaquotes', 'xm', 'xm global', 'metatrader5', 'mt5', 'exness', 'pxbt', 'prime xbt', 'primexbt']:
                if broker_l in ['xm', 'xm global']:
                    expected_server = normalize_mt5_server_name('XM Global', is_live, server)
                elif broker_l == 'exness':
                    expected_server = normalize_mt5_server_name('Exness', is_live, server)
                elif broker_l in ['pxbt', 'prime xbt', 'primexbt']:
                    expected_server = normalize_mt5_server_name('PXBT', is_live, server)
                else:
                    expected_server = normalize_mt5_server_name('MetaTrader 5', is_live, server)

                if not server or server != expected_server:
                    server = expected_server
                    logger.info(f"   Corrected server to: {server} (is_live={is_live})")

            if defer_exness_verification:
                quick_test_conn = MT5Connection({
                    'broker': broker,
                    'account': account,
                    'account_number': account,
                    'password': password,
                    'server': server,
                    'is_live': is_live,
                    'is_manual_test': True,
                    'lock_timeout': 35,
                })

                if quick_test_conn.connect():
                    quick_info = quick_test_conn.get_account_info() or {}
                    actual_balance = float(quick_info.get('balance', 0) or 0)
                    actual_equity = float(quick_info.get('equity', actual_balance) or actual_balance)
                    actual_margin_free = float(quick_info.get('margin_free', quick_info.get('marginFree', 0)) or 0)
                    actual_margin_used = float(quick_info.get('margin', 0) or 0)
                    actual_margin_level = float(quick_info.get('margin_level', quick_info.get('marginLevel', 0)) or 0)
                    actual_profit = float(quick_info.get('profit', 0) or 0)
                    actual_currency = str(quick_info.get('currency', 'USD') or 'USD').upper()
                    got_real_balance = True
                    verified_connection = True
                    skip_exness_warmup = True
                    quick_test_conn.disconnect()
                    logger.info(
                        f"✅ Fast Exness credential test succeeded for account {account}: {actual_balance:.2f} {actual_currency}"
                    )
                else:
                    quick_error_code = quick_test_conn.last_error_code
                    quick_error_message = quick_test_conn.last_error or 'Unable to verify Exness credentials right now.'

                    if quick_error_code == 'AUTH_FAILED':
                        return jsonify({
                            'success': False,
                            'error': quick_error_message,
                        }), 401

                    deferred_verification_warning = (
                        'Exness credential saved, but live verification was deferred: '
                        f'{quick_error_message}'
                    )
                    logger.warning(
                        f"⚠️ Fast Exness credential test could not verify account {account}: {quick_error_message}"
                    )
            
            # Try to get real balance - first from global cache, then from cached MT5 connection, then via quick MT5 login
            # FIRST: Check global balance_cache (populated on startup with hardcoded demo balances)
            try:
                global balance_cache, balance_cache_lock
                cache_key = f"{canonicalize_broker_name(broker)}:{account}"
                with balance_cache_lock:
                    if cache_key in balance_cache:
                        cached_info = balance_cache[cache_key]
                        actual_balance = cached_info.get('balance', actual_balance)
                        actual_currency = cached_info.get('currency', actual_currency)
                        got_real_balance = True
                        logger.info(f"💰 Got balance from global cache: {cache_key} = {actual_balance:.2f} {actual_currency}")
            except Exception as e:
                logger.warning(f"Could not fetch from global cache: {e}")

            if not got_real_balance and defer_exness_verification:
                try:
                    import MetaTrader5 as mt5_mod
                    active_info = mt5_mod.account_info()
                    if active_info is not None and str(active_info.login) == str(account):
                        actual_balance = active_info.balance
                        actual_equity = getattr(active_info, 'equity', actual_balance)
                        actual_margin_free = getattr(active_info, 'margin_free', 0)
                        actual_margin_used = getattr(active_info, 'margin', 0)
                        actual_margin_level = getattr(active_info, 'margin_level', 0)
                        actual_profit = getattr(active_info, 'profit', 0)
                        actual_currency = str(getattr(active_info, 'currency', actual_currency) or actual_currency).upper()
                        got_real_balance = True
                        verified_connection = True
                        logger.info(
                            f"💰 Captured Exness balance from active MT5 session during credential save: {actual_balance:.2f} {actual_currency}"
                        )
                except Exception as active_exc:
                    logger.warning(f"Could not read active Exness MT5 session during credential save: {active_exc}")
            
            # SECOND: Try cached connection
            if not got_real_balance and not defer_exness_verification:
                try:
                    cached_connection_id = None
                    normalized_broker = canonicalize_broker_name(broker)
                    if normalized_broker == 'Exness':
                        cached_connection_id = 'Exness MT5'
                    elif normalized_broker in ['XM', 'XM Global']:
                        cached_connection_id = 'XM Global MT5'
                    elif normalized_broker == 'PXBT':
                        cached_connection_id = 'PXBT MT5'
                    
                    if cached_connection_id:
                        cached_conn = broker_manager.connections.get(cached_connection_id)
                        if cached_conn and cached_conn.connected:
                            acct_info = cached_conn.account_info or cached_conn.get_account_info()
                            if acct_info and str(acct_info.get('accountNumber', '')) == str(account):
                                actual_balance = acct_info.get('balance', actual_balance)
                                actual_currency = acct_info.get('currency', actual_currency)
                                got_real_balance = True
                                verified_connection = True
                                logger.info(f"💰 Got real balance from cached {cached_connection_id}: {actual_balance:.2f} {actual_currency}")
                except Exception as e:
                    logger.warning(f"Could not fetch cached balance: {e}")
            
            # THIRD: If cached connection is for a different account, do a quick MT5 login to get real balance
            if not got_real_balance and not defer_exness_verification:
                try:
                    import MetaTrader5 as mt5_mod
                    # Before re-initializing MT5: check what account it is currently on.
                    # Calling mt5_mod.initialize() while MT5 is already connected to a DIFFERENT account
                    # blocks synchronously for 1-2+ minutes and disrupts the running bot session.
                    # Strategy:
                    #   1) Already on target account → read balance directly (no lock needed)
                    #   2) On a different account    → skip re-init; credential is saved; balance
                    #                                   will be refreshed by the bot trading loop
                    #   3) MT5 not connected         → proceed with guarded quick-login as before
                    try:
                        _current_info = mt5_mod.account_info()
                    except Exception:
                        _current_info = None

                    if _current_info is not None and str(_current_info.login) == str(account):
                        # MT5 is already on this exact account – read balance without re-init
                        actual_balance = _current_info.balance
                        actual_equity = getattr(_current_info, 'equity', actual_balance)
                        actual_margin_free = getattr(_current_info, 'margin_free', 0)
                        actual_margin_used = getattr(_current_info, 'margin', 0)
                        actual_margin_level = getattr(_current_info, 'margin_level', 0)
                        actual_profit = getattr(_current_info, 'profit', 0)
                        actual_currency = getattr(_current_info, 'currency', 'USD')
                        got_real_balance = True
                        verified_connection = True
                        logger.info(f"💰 Got real balance from active MT5 session (account {account}): {actual_balance:.2f} {actual_currency}")
                    elif _current_info is not None:
                        # MT5 is on a different account – do NOT call initialize(); it would block
                        logger.warning(
                            f"⚠️ MT5 already connected to account {_current_info.login} (target: {account}) "
                            f"- skipping quick login to avoid 1-2 min blocking hang. "
                            f"Credential saved; balance will refresh once a bot connects to this account."
                        )
                    else:
                        # MT5 not connected – safe to attempt quick login under lock
                        lock_acquired = mt5_connection_lock.acquire(timeout=2.0)  # Short timeout for balance check
                        if lock_acquired:
                            try:
                                terminal_path = find_mt5_terminal_path(broker, is_live=is_live)
                                init_ok = False
                                if terminal_path:
                                    init_ok = mt5_mod.initialize(
                                        path=terminal_path,
                                        login=int(account),
                                        password=str(password),
                                        server=str(server),
                                    )
                                else:
                                    init_ok = mt5_mod.initialize(login=int(account), password=str(password), server=str(server))

                                login_ok = init_ok
                                if login_ok:
                                    info = mt5_mod.account_info()
                                    if info:
                                        actual_balance = info.balance
                                        actual_equity = getattr(info, 'equity', actual_balance)
                                        actual_margin_free = getattr(info, 'margin_free', 0)
                                        actual_margin_used = getattr(info, 'margin', 0)
                                        actual_margin_level = getattr(info, 'margin_level', 0)
                                        actual_profit = getattr(info, 'profit', 0)
                                        actual_currency = getattr(info, 'currency', 'USD')
                                        got_real_balance = True
                                        verified_connection = True
                                        logger.info(f"💰 Got real balance via quick MT5 login: {actual_balance:.2f} {actual_currency} | Equity: {actual_equity:.2f} | Free Margin: {actual_margin_free:.2f} | P/L: {actual_profit:.2f}")
                                else:
                                    err = mt5_mod.last_error()
                                    logger.warning(f"⚠️ Quick MT5 login failed: {err} - using default balance")
                                mt5_mod.shutdown()
                            finally:
                                mt5_connection_lock.release()
                        else:
                            logger.warning(f"⚠️ Could not acquire MT5 lock for balance check - using default")
                except Exception as e:
                    logger.warning(f"Could not fetch balance via quick login: {e} - using default")
            
            # Save MT5 credentials
            conn = get_db_connection()
            cursor = conn.cursor()
            ensure_user_preferences_table(cursor)
            
            cursor.execute('''
                SELECT credential_id, account_currency FROM broker_credentials
                WHERE user_id = ? AND broker_name = ? AND account_number = ?
            ''', (user_id, broker, account))
            
            existing = cursor.fetchone()
            
            if existing:
                credential_id = existing['credential_id']
                if not got_real_balance and existing['account_currency']:
                    actual_currency = str(existing['account_currency']).upper()
                cursor.execute('''
                    UPDATE broker_credentials
                    SET password = ?, server = ?, is_live = ?, is_active = 1, updated_at = ?,
                        cached_balance = ?, cached_equity = ?, cached_margin_free = ?, 
                        cached_margin = ?, cached_margin_level = ?, cached_profit = ?,
                        account_currency = ?
                    WHERE credential_id = ?
                ''', (password, server, int(is_live), datetime.now().isoformat(),
                      actual_balance if got_real_balance else None,
                      actual_equity if got_real_balance else None,
                      actual_margin_free if got_real_balance else None,
                      actual_margin_used if got_real_balance else None,
                      actual_margin_level if got_real_balance else None,
                      actual_profit if got_real_balance else None,
                      actual_currency,
                      credential_id))
                logger.info(f"ℹ️  Updated broker credential: {broker} | Account: {account} | Currency: {actual_currency}")
            else:
                credential_id = str(uuid.uuid4())
                cursor.execute('''
                    INSERT INTO broker_credentials 
                    (credential_id, user_id, broker_name, account_number, password, server, is_live, is_active, created_at, updated_at,
                     cached_balance, cached_equity, cached_margin_free, cached_margin, cached_margin_level, cached_profit, account_currency)
                    VALUES (?, ?, ?, ?, ?, ?, ?, 1, ?, ?,
                            ?, ?, ?, ?, ?, ?, ?)
                ''', (credential_id, user_id, broker, account, password, server, int(is_live), 
                      datetime.now().isoformat(), datetime.now().isoformat(),
                      actual_balance if got_real_balance else None,
                      actual_equity if got_real_balance else None,
                      actual_margin_free if got_real_balance else None,
                      actual_margin_used if got_real_balance else None,
                      actual_margin_level if got_real_balance else None,
                      actual_profit if got_real_balance else None,
                      actual_currency))
                logger.info(f"✅ Created broker credential: {broker} | Account: {account} | Currency: {actual_currency}")
            
            encrypt_credential_at_rest(cursor, credential_id)
            conn.commit()
            # Invalidate credential cache to ensure fresh data on next access
            cache_key = f"cred_{credential_id}_{user_id}"
            credential_cache.pop(cache_key, None)

            auto_connected = False
            connection_status = 'saved'
            warning = None

            if defer_exness_verification and not verified_connection:
                warning = deferred_verification_warning or (
                    'Exness credential saved. Live MT5 verification is deferred to avoid request timeout '
                    'while the terminal is attached to another account.'
                )

            cursor.execute('''
                CREATE TABLE IF NOT EXISTS user_preferences (
                    user_id TEXT PRIMARY KEY,
                    trading_mode TEXT DEFAULT 'DEMO',
                    live_account TEXT,
                    live_server TEXT,
                    updated_at TEXT
                )
            ''')
            cursor.execute('SELECT trading_mode FROM user_preferences WHERE user_id = ?', (user_id,))
            preference_row = cursor.fetchone()
            current_mode = ((preference_row['trading_mode'] if preference_row else 'DEMO') or 'DEMO').upper()

            cursor.execute('''
                INSERT OR REPLACE INTO user_preferences
                (user_id, trading_mode, live_account, live_server, updated_at)
                VALUES (?, ?, ?, ?, ?)
            ''', (
                user_id,
                current_mode,
                account if is_live else None,
                server if is_live else None,
                datetime.now().isoformat(),
            ))
            conn.commit()

            if broker == 'Exness':
                target_mode = 'LIVE' if is_live else 'DEMO'
                if verified_connection:
                    auto_connected = True
                    connection_status = 'connected'
                    warning = None
                elif not skip_exness_warmup:
                    warm_result = warm_trading_mode_credential(user_id, credential_id, target_mode)
                    if warm_result['connected']:
                        auto_connected = True
                        connection_status = 'connected'
                        verified_connection = True
                        account_info = warm_result.get('account_info', {}) or {}
                        if account_info:
                            actual_balance = account_info.get('balance', actual_balance)
                            actual_equity = account_info.get('equity', actual_equity)
                            actual_margin_free = account_info.get('margin_free', account_info.get('marginFree', actual_margin_free))
                            actual_margin_used = account_info.get('margin', actual_margin_used)
                            actual_margin_level = account_info.get('margin_level', account_info.get('marginLevel', actual_margin_level))
                            actual_profit = account_info.get('profit', actual_profit)
                            actual_currency = str(account_info.get('currency', actual_currency)).upper()
                            got_real_balance = True
                            cursor.execute('''
                                UPDATE broker_credentials
                                SET cached_balance = ?, cached_equity = ?, cached_margin_free = ?,
                                    cached_margin = ?, cached_margin_level = ?, cached_profit = ?,
                                    account_currency = ?, updated_at = ?
                                WHERE credential_id = ?
                            ''', (
                                actual_balance,
                                actual_equity,
                                actual_margin_free,
                                actual_margin_used,
                                actual_margin_level,
                                actual_profit,
                                actual_currency,
                                datetime.now().isoformat(),
                                credential_id,
                            ))
                            conn.commit()
                            warning = None
                            logger.info(
                                f"✅ Warmed Exness credential {account}: {actual_balance:.2f} {actual_currency}"
                            )
                    else:
                        connection_status = 'connection-failed'
                        warning = warm_result.get('error')

            conn.close()
            
            logger.info(f"✅ Credentials saved for user {user_id}")
            
            return jsonify({
                'success': True,
                'message': (
                    f'Successfully connected to {broker} account {account}'
                    if connection_status == 'connected'
                    else f'Credentials saved for {broker} account {account}'
                ),
                'credential_id': credential_id,
                'broker': broker,
                'account_number': account,
                'balance': round(actual_balance, 2) if got_real_balance else 0,
                'equity': round(actual_equity, 2) if got_real_balance else 0,
                'free_margin': round(actual_margin_free, 2) if got_real_balance else 0,
                'margin': round(actual_margin_used, 2) if got_real_balance else 0,
                'margin_level': round(actual_margin_level, 2) if got_real_balance else 0,
                'total_pl': round(actual_profit, 2) if got_real_balance else 0,
                'currency': actual_currency,
                'is_live': is_live,
                'status': 'CONNECTED' if connection_status == 'connected' else 'SAVED',
                'connection_status': connection_status,
                'auto_connected': auto_connected,
                'warning': warning,
                'timestamp': datetime.now().isoformat()
            }), 200
        
    except Exception as e:
        logger.error(f"❌ Connection test failed: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


def _get_active_fxcm_credential_for_user(user_id: str):
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute('''
        SELECT credential_id, user_id, broker_name, account_number, server, is_live, is_active, api_key, username, password, updated_at, created_at
        FROM broker_credentials
        WHERE user_id = ? AND broker_name = 'FXCM' AND is_active = 1
        ORDER BY COALESCE(updated_at, created_at, '') DESC, credential_id DESC
        LIMIT 1
    ''', (user_id,))
    row = cursor.fetchone()
    conn.close()
    return dict(row) if row else None


@app.route('/api/fxcm/profit-check', methods=['POST'])
@require_session
def api_fxcm_profit_check_user():
    try:
        user_id = request.user_id
        data = request.json or {}
        target_profit = float(data.get('target_profit') or 0)
        auto_close = bool(data.get('auto_close', True))

        if target_profit <= 0:
            return jsonify({'success': False, 'error': 'target_profit must be greater than 0'}), 400

        credential = _get_active_fxcm_credential_for_user(user_id)
        if not credential or not (credential.get('api_key') or (credential.get('username') and credential.get('password'))):
            return jsonify({'success': False, 'error': 'No active FXCM credential found for this user'}), 404

        fxcm_conn = FXCMConnection({
            'api_key': credential.get('api_key'),
            'username': credential.get('username'),
            'password': credential.get('password'),
            'account_number': credential.get('account_number', ''),
            'server': credential.get('server'),
            'connection': 'Real' if bool(credential.get('is_live')) else 'Demo',
            'is_live': bool(credential.get('is_live')),
        })
        if not fxcm_conn.connect():
            return jsonify({'success': False, 'error': fxcm_conn.last_error or 'Failed to connect to FXCM'}), 401

        positions = fxcm_conn.get_positions() or []
        current_pnl = sum(float(pos.get('profit_loss', 0) or 0) for pos in positions)
        target_reached = current_pnl >= target_profit
        positions_closed = 0
        close_errors = []

        if target_reached and auto_close:
            for position in positions:
                position_id = position.get('deal_id') or position.get('trade_id') or position.get('ticket')
                if not position_id:
                    continue
                close_result = fxcm_conn.close_position(str(position_id))
                if close_result.get('success'):
                    positions_closed += 1
                else:
                    close_errors.append(close_result.get('error') or f'Failed to close position {position_id}')

        account_info = fxcm_conn.get_account_info() or {}
        fxcm_conn.disconnect()

        if target_reached and auto_close:
            message = f'FXCM profit target reached at {current_pnl:.2f}. Closed {positions_closed} position(s).'
        elif target_reached:
            message = f'FXCM profit target reached at {current_pnl:.2f}.'
        else:
            message = f'Current FXCM P/L is {current_pnl:.2f}. Target not reached.'

        response_payload = {
            'success': True,
            'target_profit': target_profit,
            'current_pnl': round(current_pnl, 2),
            'target_reached': target_reached,
            'auto_close': auto_close,
            'positions_checked': len(positions),
            'positions_closed': positions_closed,
            'balance_after': {
                'balance': float(account_info.get('balance', 0) or 0),
                'available': float(account_info.get('margin_free', account_info.get('marginFree', 0)) or 0),
                'equity': float(account_info.get('equity', 0) or 0),
                'currency': account_info.get('currency', 'USD'),
            },
            'message': message,
        }
        if close_errors:
            response_payload['close_errors'] = close_errors
        return jsonify(response_payload), 200
    except Exception as e:
        logger.error(f'❌ FXCM profit check error: {e}')
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/fxcm/withdrawal-notifications', methods=['GET'])
@require_session
def api_fxcm_get_withdrawal_notifications():
    try:
        user_id = request.user_id
        conn = get_db_connection()
        cursor = conn.cursor()
        cursor.execute('''
            SELECT notification_id, user_id, broker_name, amount, message, status, created_at, completed_at
            FROM broker_withdrawal_notifications
            WHERE user_id = ? AND broker_name = 'FXCM'
            ORDER BY COALESCE(created_at, '') DESC, notification_id DESC
        ''', (user_id,))
        notifications = []
        for row in cursor.fetchall():
            item = dict(row)
            amount = float(item.get('amount') or 0)
            message = item.get('message') or ''
            positions_closed = 0
            balance_available = amount
            realized_profit = amount
            if '|' in message:
                for part in message.split('|'):
                    key, _, value = part.partition('=')
                    key = key.strip().lower()
                    value = value.strip()
                    if key == 'positions_closed':
                        positions_closed = int(float(value or 0))
                    elif key == 'balance_available':
                        balance_available = float(value or 0)
                    elif key == 'realized_profit':
                        realized_profit = float(value or 0)
            item['positions_closed'] = positions_closed
            item['balance_available'] = balance_available
            item['realized_profit'] = realized_profit
            notifications.append(item)
        conn.close()
        return jsonify({'success': True, 'notifications': notifications}), 200
    except Exception as e:
        logger.error(f'❌ FXCM notification fetch error: {e}')
        return jsonify({'success': False, 'error': str(e)}), 500


