@app.route('/api/payments/ozow/notify', methods=['POST'])
def ozow_notify():
    try:
        payload = request.form.to_dict() if request.form else (request.get_json(silent=True) or {})
        if not payload:
            return 'Missing payload', 400
        if not verify_ozow_response_hash(payload):
            logger.warning(f"Invalid Ozow notify hash for reference {payload.get('TransactionReference')}")
            return 'Invalid hash', 400

        payment_reference = str(payload.get('TransactionReference') or '').strip()
        if not payment_reference:
            return 'Missing TransactionReference', 400

        normalized_status = str(payload.get('Status') or '').strip().lower()
        now_iso = datetime.now().isoformat()
        conn = get_db_connection()
        cursor = conn.cursor()
        cursor.execute('SELECT * FROM ozow_payments WHERE payment_reference = ?', (payment_reference,))
        payment_row = cursor.fetchone()
        if not payment_row:
            conn.close()
            return 'Payment not found', 404

        payment = dict(payment_row)
        verified_payload = payload
        try:
            verified_payload = fetch_ozow_transaction_status(
                payment_reference,
                transaction_id=str(payload.get('TransactionId') or '').strip(),
                is_test=bool(payment.get('is_test')),
            )
        except Exception as verify_error:
            logger.warning(f'Ozow notify verification API fallback used for {payment_reference}: {verify_error}')

        payment = _sync_ozow_payment_state(cursor, payment, verified_payload, 'notify')

        if payment.get('status') == 'complete' and payment.get('purpose') == 'wallet_topup' and not payment.get('credited_at'):
            _record_wallet_credit_from_ozow(cursor, payment, verified_payload)

        conn.commit()
        conn.close()
        return 'OK', 200
    except Exception as e:
        logger.error(f"Error processing Ozow notify: {e}")
        return 'Error', 500


# ==================== COMMISSION DISTRIBUTION HELPER ====================

def _get_commission_config(cursor):
    """Load commission rates from DB. Returns dict with all config fields."""
    cursor.execute('SELECT * FROM commission_config WHERE config_id = ?', ('default',))
    row = cursor.fetchone()
    if row:
        cfg = dict(row)
        direct_rate = float(cfg.get('developer_direct_rate', 0.25) or 0.25)
        cfg['developer_direct_rate'] = direct_rate
        cfg['developer_referral_rate'] = max(float(cfg.get('developer_referral_rate', direct_rate) or direct_rate), direct_rate)
        cfg['ig_developer_rate'] = max(float(cfg.get('ig_developer_rate', direct_rate) or direct_rate), direct_rate)
        cfg['recruiter_rate'] = float(cfg.get('recruiter_rate', 0.05) or 0.05)
        cfg['ig_recruiter_rate'] = float(cfg.get('ig_recruiter_rate', 0.05) or 0.05)
        cfg['fxcm_developer_rate'] = max(float(cfg.get('fxcm_developer_rate', direct_rate) or direct_rate), direct_rate)
        cfg['fxcm_recruiter_rate'] = float(cfg.get('fxcm_recruiter_rate', 0.05) or 0.05)
        cfg['binance_developer_rate'] = max(float(cfg.get('binance_developer_rate', direct_rate) or direct_rate), direct_rate)
        cfg['binance_recruiter_rate'] = float(cfg.get('binance_recruiter_rate', 0.05) or 0.05)
        cfg['tier2_rate'] = float(cfg.get('tier2_rate', 0.02) or 0.02)
        return cfg
    # Fallback defaults
    return {
        'developer_id': 'developer',
        'developer_direct_rate': 0.25,
        'developer_referral_rate': 0.25,
        'recruiter_rate': 0.05,
        'ig_commission_enabled': 1,
        'ig_developer_rate': 0.25,
        'ig_recruiter_rate': 0.05,
        'fxcm_commission_enabled': 1,
        'fxcm_developer_rate': 0.25,
        'fxcm_recruiter_rate': 0.05,
        'binance_commission_enabled': 1,
        'binance_developer_rate': 0.25,
        'binance_recruiter_rate': 0.05,
        'multi_tier_enabled': 0,
        'tier2_rate': 0.02,
    }


def _get_developer_account_id(cfg: Dict[str, Any]) -> str:
    developer_id = str(cfg.get('developer_id') or '').strip()
    return developer_id or OWNER_USER_ID


def _get_active_referrer(cursor, user_id: str) -> Optional[str]:
    cursor.execute('''
        SELECT referrer_id FROM referrals
        WHERE referred_user_id = ? AND status = 'active'
        ORDER BY created_at DESC
        LIMIT 1
    ''', (user_id,))
    row = cursor.fetchone()
    return row[0] if row else None


def _build_commission_distribution(cursor, user_id: str, profit_amount: float, source: str = 'MT5') -> Dict[str, Any]:
    cfg = _get_commission_config(cursor)
    developer_id = _get_developer_account_id(cfg)
    referrer_id = _get_active_referrer(cursor, user_id)
    entries: List[Dict[str, Any]] = []

    if profit_amount <= 0:
        return {
            'cfg': cfg,
            'developer_id': developer_id,
            'entries': [],
            'total_commission': 0.0,
            'trader_keeps': 0.0,
            'referrer_id': referrer_id,
            'source': source,
        }

    if source == 'IG' and not cfg.get('ig_commission_enabled', 1):
        return {
            'cfg': cfg,
            'developer_id': developer_id,
            'entries': [],
            'total_commission': 0.0,
            'trader_keeps': float(profit_amount),
            'referrer_id': referrer_id,
            'source': source,
        }

    if source == 'FXCM' and not cfg.get('fxcm_commission_enabled', 1):
        return {
            'cfg': cfg,
            'developer_id': developer_id,
            'entries': [],
            'total_commission': 0.0,
            'trader_keeps': float(profit_amount),
            'referrer_id': referrer_id,
            'source': source,
        }

    if source == 'BINANCE' and not cfg.get('binance_commission_enabled', 1):
        return {
            'cfg': cfg,
            'developer_id': developer_id,
            'entries': [],
            'total_commission': 0.0,
            'trader_keeps': float(profit_amount),
            'referrer_id': referrer_id,
            'source': source,
        }

    if source == 'IG':
        direct_rate = float(cfg.get('developer_direct_rate', 0.25) or 0.25)
        developer_rate = float(cfg.get('ig_developer_rate', 0.25) or 0.25)
        recruiter_rate = float(cfg.get('ig_recruiter_rate', 0.05) or 0.05)
    elif source == 'FXCM':
        direct_rate = float(cfg.get('fxcm_developer_rate', 0.25) or 0.25)
        developer_rate = float(cfg.get('fxcm_developer_rate', 0.25) or 0.25)
        recruiter_rate = float(cfg.get('fxcm_recruiter_rate', 0.05) or 0.05)
    elif source == 'BINANCE':
        direct_rate = float(cfg.get('binance_developer_rate', 0.25) or 0.25)
        developer_rate = float(cfg.get('binance_developer_rate', 0.25) or 0.25)
        recruiter_rate = float(cfg.get('binance_recruiter_rate', 0.05) or 0.05)
    else:
        direct_rate = float(cfg.get('developer_direct_rate', 0.25) or 0.25)
        developer_rate = float(cfg.get('developer_referral_rate', direct_rate) or direct_rate)
        recruiter_rate = float(cfg.get('recruiter_rate', 0.05) or 0.05)

    if referrer_id:
        entries.append({
            'recipient_id': developer_id,
            'rate': developer_rate,
            'amount': profit_amount * developer_rate,
            'entry_type': 'profit_share',
        })
        entries.append({
            'recipient_id': referrer_id,
            'rate': recruiter_rate,
            'amount': profit_amount * recruiter_rate,
            'entry_type': 'referral',
        })

        if bool(cfg.get('multi_tier_enabled', 0)):
            tier2_id = _get_active_referrer(cursor, referrer_id)
            tier2_rate = float(cfg.get('tier2_rate', 0.02) or 0.02)
            if tier2_id and tier2_rate > 0:
                entries.append({
                    'recipient_id': tier2_id,
                    'rate': tier2_rate,
                    'amount': profit_amount * tier2_rate,
                    'entry_type': 'affiliate',
                })
    else:
        entries.append({
            'recipient_id': developer_id,
            'rate': direct_rate,
            'amount': profit_amount * direct_rate,
            'entry_type': 'profit_share',
        })

    total_commission = sum(float(entry['amount'] or 0) for entry in entries)
    return {
        'cfg': cfg,
        'developer_id': developer_id,
        'entries': entries,
        'total_commission': total_commission,
        'trader_keeps': max(float(profit_amount) - total_commission, 0.0),
        'referrer_id': referrer_id,
        'source': source,
    }


def _insert_commission_record(cursor, earner_id: str, client_id: str, bot_id: str, profit_amount: float, commission_rate: float, commission_amount: float, now: str, entry_type: str, broker_source: str = 'MT5'):
    commission_id = str(uuid.uuid4())
    cursor.execute('''
        INSERT INTO commissions
        (commission_id, earner_id, client_id, bot_id, profit_amount, commission_rate, commission_amount, created_at)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?)
    ''', (commission_id, earner_id, client_id, bot_id, profit_amount, commission_rate, commission_amount, now))
    cursor.execute('''
        INSERT INTO commission_ledger
        (entry_id, commission_id, user_id, source_user_id, type, amount, payout_status, bot_id, trading_profit, broker_source, created_at)
        VALUES (?, ?, ?, ?, ?, ?, 'pending', ?, ?, ?, ?)
    ''', (str(uuid.uuid4()), commission_id, earner_id, client_id, entry_type, commission_amount, bot_id, profit_amount, broker_source, now))
    cursor.execute('''
        UPDATE users SET total_commission = COALESCE(total_commission, 0) + ? WHERE user_id = ?
    ''', (commission_amount, earner_id))
    return commission_id


def _commission_recipient_exists(cursor, user_id: str) -> bool:
    cursor.execute('SELECT 1 FROM users WHERE user_id = ? LIMIT 1', (user_id,))
    return cursor.fetchone() is not None


def _settle_commission_to_internal_balance(cursor, commission_id: str, earner_id: str, amount: float, reason: str, now: str):
    if amount <= 0:
        return False

    cursor.execute('''
        UPDATE users
        SET internal_balance = COALESCE(internal_balance, 0) + ?
        WHERE user_id = ?
    ''', (amount, earner_id))

    if cursor.rowcount <= 0:
        logger.warning(f"Commission settlement skipped for {earner_id}: user not found")
        return False

    cursor.execute('''
        INSERT INTO transactions (transaction_id, user_id, type, amount, method, status, reason, created_at, completed_at)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
    ''', (str(uuid.uuid4()), earner_id, 'commission', amount, 'internal', 'completed', reason, now, now))

    cursor.execute('''
        UPDATE commission_ledger
        SET payout_status = 'completed', payout_method = 'internal', payout_date = ?
        WHERE commission_id = ? AND user_id = ?
    ''', (now, commission_id, earner_id))
    return True


def _record_commission_distribution(cursor, user_id: str, bot_id: str, profit_amount: float,
                                    distribution: Dict[str, Any], auto_credit_platform: bool = False) -> List[Dict[str, Any]]:
    now = datetime.now().isoformat()
    recorded_entries: List[Dict[str, Any]] = []
    developer_id = distribution.get('developer_id')
    broker_source = distribution.get('source', 'MT5')

    for entry in distribution.get('entries', []):
        recipient_id = entry['recipient_id']
        amount = float(entry['amount'] or 0)
        if amount <= 0:
            continue

        if not _commission_recipient_exists(cursor, recipient_id):
            logger.warning(
                f"Commission entry skipped for {recipient_id}: recipient user not found "
                f"(bot={bot_id}, type={entry['entry_type']}, amount=${amount:.2f})"
            )
            continue

        commission_id = _insert_commission_record(
            cursor,
            recipient_id,
            user_id,
            bot_id,
            profit_amount,
            float(entry['rate'] or 0),
            amount,
            now,
            entry['entry_type'],
            broker_source,
        )

        auto_settled = False
        if auto_credit_platform and recipient_id == developer_id and entry['entry_type'] == 'profit_share':
            auto_settled = _settle_commission_to_internal_balance(
                cursor,
                commission_id,
                recipient_id,
                amount,
                f"Automated platform profit share from bot {bot_id}",
                now,
            )

        recorded_entries.append({
            'commission_id': commission_id,
            'recipient_id': recipient_id,
            'amount': amount,
            'rate': float(entry['rate'] or 0),
            'entry_type': entry['entry_type'],
            'auto_settled': auto_settled,
        })

    return recorded_entries


def distribute_trade_commissions(bot_id: str, user_id: str, profit_amount: float, source: str = 'MT5'):
    """
    Distribute commissions for profitable trades.
    SKIP COMMISSION if user is the system owner (your own bots = no commission).
    Reads rates from commission_config DB table (admin-editable).
    source: 'MT5' or 'IG' — uses matching rate set.
    """
    try:
        if profit_amount <= 0:
            return {'success': True, 'entries': [], 'trader_keeps': 0.0}

        # 🔑 OWNER EXCEPTION: System owner doesn't pay commission on own bots
        if user_id == OWNER_USER_ID:
            logger.info(f"✅ [{source}] Bot {bot_id}: Owner {user_id} keeps 100% of profit ${profit_amount:.2f} (no commission charged)")
            return {
                'success': True,
                'entries': [],
                'trader_keeps': profit_amount,
                'total_commission': 0.0,
                'reason': 'owner_exemption'
            }

        conn = get_db_connection()
        cursor = conn.cursor()

        distribution = _build_commission_distribution(cursor, user_id, profit_amount, source)
        if not distribution['entries']:
            conn.close()
            logger.info(f"[{source}] No commission entries generated for profit ${profit_amount:.2f}")
            return {'success': True, 'entries': [], 'trader_keeps': distribution['trader_keeps']}

        recorded_entries = _record_commission_distribution(
            cursor,
            user_id,
            bot_id,
            profit_amount,
            distribution,
            auto_credit_platform=True,
        )

        conn.commit()
        conn.close()

        actual_total_commission = round(sum(float(entry.get('amount') or 0.0) for entry in recorded_entries), 2)
        actual_trader_keeps = round(max(float(profit_amount) - actual_total_commission, 0.0), 2)

        if not recorded_entries:
            logger.info(f"[{source}] Commission entries skipped or unresolved for profit ${profit_amount:.2f}; trader keeps ${actual_trader_keeps:.2f}")
            return {
                'success': True,
                'entries': [],
                'trader_keeps': actual_trader_keeps,
                'total_commission': 0.0,
                'reason': 'no_valid_recipients',
            }

        summary = ', '.join(
            f"{entry['recipient_id']}=${entry['amount']:.2f}" for entry in recorded_entries
        )
        logger.info(f"💰 [{source}] Commission distribution for ${profit_amount:.2f} on {bot_id}: {summary} (User keeps: ${actual_trader_keeps:.2f})")
        return {
            'success': True,
            'entries': recorded_entries,
            'trader_keeps': actual_trader_keeps,
            'total_commission': actual_total_commission,
        }

    except Exception as e:
        logger.error(f"❌ Error in distribute_trade_commissions: {e}")
        # Don't raise - don't break trading if commission fails
        return {'success': False, 'error': str(e)}


# ==================== EMAIL NOTIFICATIONS ====================
def send_activation_pin_email(user_email: str, user_name: str, bot_id: str, pin: str):
    """Send activation PIN to user email"""
    try:
        smtp_server = os.environ.get('SMTP_SERVER', '')
        smtp_user = os.environ.get('SMTP_USER', '')
        smtp_pass = os.environ.get('SMTP_PASS', '')
        smtp_port = int(os.environ.get('SMTP_PORT', '587'))
        
        logger.info(f"🔐 BOT ACTIVATION PIN: User={user_name}, Bot={bot_id}, PIN={pin}")
        
        if not smtp_server or not smtp_user:
            logger.warning(f"⚠️ SMTP not configured — PIN for {user_email}: {pin}")
            return True
        
        msg = MIMEMultipart('alternative')
        msg['From'] = f'Zwesta Trading <{smtp_user}>'
        msg['To'] = user_email
        msg['Subject'] = f'Zwesta Trading - Bot Activation PIN'
        
        plain = f'Hi {user_name},\n\nYour bot activation PIN is: {pin}\nBot ID: {bot_id}\n\nThis PIN expires in 10 minutes.'
        
        html = f"""\
        <html><body style="font-family:Arial,sans-serif;background:#f4f4f4;padding:20px;">
        <div style="max-width:480px;margin:0 auto;background:#fff;border-radius:12px;padding:32px;box-shadow:0 2px 8px rgba(0,0,0,0.08);">
          <h2 style="color:#0A0E21;margin-top:0;">🤖 Bot Activation PIN</h2>
          <p style="color:#555;font-size:15px;">Hi <b>{user_name}</b>, use this PIN to activate your bot:</p>
          <div style="background:#0A0E21;color:#00E5FF;font-size:32px;font-weight:bold;letter-spacing:8px;text-align:center;padding:18px;border-radius:8px;margin:24px 0;">
            {pin}
          </div>
          <p style="color:#888;font-size:13px;">Bot ID: <code>{bot_id}</code></p>
          <p style="color:#888;font-size:13px;">This PIN expires in <b>10 minutes</b>.</p>
          <hr style="border:none;border-top:1px solid #eee;margin:24px 0;">
          <p style="color:#aaa;font-size:11px;text-align:center;">Zwesta Trading Platform</p>
        </div>
        </body></html>"""
        
        msg.attach(MIMEText(plain, 'plain'))
        msg.attach(MIMEText(html, 'html'))
        
        with smtplib.SMTP(smtp_server, smtp_port) as server:
            server.starttls()
            server.login(smtp_user, smtp_pass)
            server.send_message(msg)
        logger.info(f"✅ Activation PIN email sent to {user_email}")
        return True
    except Exception as e:
        logger.error(f"Error sending email: {e}")
        return False


# ==================== BOT ACTIVATION ENDPOINTS ====================
@app.route('/api/bot/<bot_id>/request-activation', methods=['POST'])
@require_session
def request_bot_activation(bot_id):
    """Request bot activation - sends PIN to user email for verification"""
    try:
        data = request.json or {}
        user_id = request.user_id  # From @require_session
        
        if not user_id:
            return jsonify({'success': False, 'error': 'Not authenticated'}), 401
        
        if bot_id not in active_bots:
            return jsonify({'success': False, 'error': f'Bot {bot_id} not found'}), 404
        
        bot = active_bots[bot_id]
        
        # Verify bot belongs to user
        if bot.get('user_id') != user_id:
            return jsonify({'success': False, 'error': 'Unauthorized: Bot does not belong to this user'}), 403
        
        # Generate 6-digit PIN
        activation_pin = str(random.randint(100000, 999999))
        pin_id = str(uuid.uuid4())
        expires_at = datetime.now() + timedelta(minutes=10)
        
        # Store PIN in database
        conn = get_db_connection()
        cursor = conn.cursor()
        
        # Get user email
        cursor.execute('SELECT email, name FROM users WHERE user_id = ?', (user_id,))
        user_row = cursor.fetchone()
        
        if not user_row:
            conn.close()
            return jsonify({'success': False, 'error': 'User not found'}), 404
        
        user_email = user_row['email']
        user_name = user_row['name']
        
        # Delete any existing unexpired PINs for this bot
        cursor.execute('''
            DELETE FROM bot_activation_pins 
            WHERE bot_id = ? AND user_id = ? AND expires_at > ?
        ''', (bot_id, user_id, datetime.now().isoformat()))
        
        # Insert new PIN
        cursor.execute('''
            INSERT INTO bot_activation_pins (pin_id, bot_id, user_id, pin, created_at, expires_at)
            VALUES (?, ?, ?, ?, ?, ?)
        ''', (pin_id, bot_id, user_id, activation_pin, datetime.now().isoformat(), expires_at.isoformat()))
        
        conn.commit()
        conn.close()
        
        # Send PIN to user (for demo, just logs it)
        send_activation_pin_email(user_email, user_name, bot_id, activation_pin)
        
        logger.info(f"Activation PIN requested for bot {bot_id} by user {user_id}")
        
        return jsonify({
            'success': True,
            'message': f'Activation PIN sent to {user_email}',
            'expires_in_seconds': 600,
            'bot_id': bot_id,
            'note': 'For testing: PIN will be printed in backend logs'
        }), 200
        
    except Exception as e:
        logger.error(f"Error requesting activation: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/bot/<bot_id>/request-deletion', methods=['POST'])
@require_session
def request_bot_deletion(bot_id):
    """Request bot deletion - creates confirmation token and captures bot stats"""
    try:
        data = request.json or {}
        user_id = request.user_id
        
        if not user_id:
            return jsonify({'success': False, 'error': 'Not authenticated'}), 401
        
        if bot_id not in active_bots:
            return jsonify({'success': False, 'error': f'Bot {bot_id} not found'}), 404
        
        bot_config = active_bots[bot_id]
        
        # Verify bot belongs to user
        if bot_config.get('user_id') != user_id:
            return jsonify({'success': False, 'error': 'Unauthorized: Bot does not belong to this user'}), 403
        
        # Generate deletion token
        deletion_token = str(uuid.uuid4().hex[:16])
        token_id = str(uuid.uuid4())
        expires_at = datetime.now() + timedelta(minutes=5)  # 5 minute confirmation window
        
        # Capture final bot stats
        bot_stats = {
            'totalTrades': bot_config.get('totalTrades', 0),
            'winningTrades': bot_config.get('winningTrades', 0),
            'totalProfit': bot_config.get('totalProfit', 0),
            'totalLosses': bot_config.get('totalLosses', 0),
        }
        
        # Store deletion token
        conn = get_db_connection()
        cursor = conn.cursor()
        
        # Delete any existing unexpired tokens
        cursor.execute('''
            DELETE FROM bot_deletion_tokens
            WHERE bot_id = ? AND user_id = ? AND expires_at > ? AND confirmed = 0
        ''', (bot_id, user_id, datetime.now().isoformat()))
        
        cursor.execute('''
            INSERT INTO bot_deletion_tokens 
            (token_id, bot_id, user_id, deletion_token, bot_stats, created_at, expires_at)
            VALUES (?, ?, ?, ?, ?, ?, ?)
        ''', (token_id, bot_id, user_id, deletion_token, json.dumps(bot_stats), 
              datetime.now().isoformat(), expires_at.isoformat()))
        
        conn.commit()
        conn.close()
        
        logger.warning(f"🗑️ BOT DELETION REQUESTED: {bot_id} by {user_id}")
        logger.warning(f"   Stats: {bot_stats}")
        logger.warning(f"   Confirmation Token: {deletion_token}")
        logger.warning(f"   Valid for 5 minutes")
        
        return jsonify({
            'success': True,
            'message': 'Deletion confirmation token generated',
            'confirmation_token': deletion_token,
            'expires_in_seconds': 300,
            'warning': 'This action cannot be undone. All bot data will be permanently deleted.',
            'bot_stats': bot_stats
        }), 200
        
    except Exception as e:
        logger.error(f"Error requesting deletion: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


