def _default_strategy_trading_cadence(strategy_name: str, management_profile: str, intelligent_scanner: bool = False) -> Dict[str, int]:
    normalized_strategy = str(strategy_name or 'Trend Following').strip().lower()
    normalized_profile = _normalize_management_profile(management_profile)

    if normalized_strategy == 'scalping':
        return {'tradingMode': 'signal-driven', 'tradingInterval': 30, 'pollInterval': 2}

    if normalized_strategy in {'momentum trading', 'breakout trading'}:
        return {'tradingMode': 'signal-driven', 'tradingInterval': 90, 'pollInterval': 8}

    if normalized_strategy == 'swing trend dca':
        return {'tradingMode': 'signal-driven', 'tradingInterval': 180, 'pollInterval': 15}

    if normalized_strategy == 'trend following':
        # Lowered from 600s -> 90s: 600s starved Binance bots (10 min between cycles)
        return {'tradingMode': 'signal-driven', 'tradingInterval': 90, 'pollInterval': 8}

    if intelligent_scanner:
        return {'tradingMode': 'signal-driven', 'tradingInterval': 90, 'pollInterval': 8}

    base_interval = 120 if normalized_profile == 'beginner' else 90 if normalized_profile == 'balanced' else 60
    base_poll = 12 if normalized_profile == 'beginner' else 10 if normalized_profile == 'balanced' else 5
    return {'tradingMode': 'signal-driven', 'tradingInterval': base_interval, 'pollInterval': base_poll}


def _minimum_saved_bot_trade_cadence(
    strategy_name: str,
    management_profile: str,
    intelligent_scanner: bool = False,
) -> Dict[str, int]:
    normalized_strategy = str(strategy_name or '').strip().lower()
    normalized_profile = _normalize_management_profile(management_profile)

    if normalized_strategy == 'scalping':
        return {'tradingMode': 'signal-driven', 'tradingInterval': 30, 'pollInterval': 2}

    if normalized_strategy in {'momentum trading', 'breakout trading'}:
        if normalized_profile in {'advanced', 'fast_growth'}:
            return {'tradingMode': 'signal-driven', 'tradingInterval': 60, 'pollInterval': 5}
        return {'tradingMode': 'signal-driven', 'tradingInterval': 90, 'pollInterval': 8}

    if normalized_strategy == 'swing trend dca':
        return {'tradingMode': 'signal-driven', 'tradingInterval': 300, 'pollInterval': 30}

    if intelligent_scanner:
        if normalized_profile in {'advanced', 'fast_growth'}:
            return {'tradingMode': 'signal-driven', 'tradingInterval': 60, 'pollInterval': 5}
        return {'tradingMode': 'signal-driven', 'tradingInterval': 120, 'pollInterval': 10}

    if normalized_profile in {'advanced', 'fast_growth'}:
        return {'tradingMode': 'signal-driven', 'tradingInterval': 60, 'pollInterval': 5}
    if normalized_profile == 'balanced':
        return {'tradingMode': 'signal-driven', 'tradingInterval': 90, 'pollInterval': 8}
    return {'tradingMode': 'signal-driven', 'tradingInterval': 120, 'pollInterval': 12}


def _adaptive_signal_threshold_floor(bot_config: Dict[str, Any]) -> int:
    broker_name = canonicalize_broker_name(
        bot_config.get('brokerName') or bot_config.get('broker_type') or bot_config.get('broker') or ''
    )
    if broker_name == 'FXCM':
        return 10
    if broker_name == 'Binance':
        return 1

    strategy_name = str(bot_config.get('strategy') or '').strip().lower()
    configured_symbols = bot_config.get('symbols') or []
    base_symbols = {
        _normalize_symbol_base(symbol)
        for symbol in configured_symbols
        if _normalize_symbol_base(symbol)
    }

    if base_symbols and base_symbols.issubset(SMALL_LIVE_ACCOUNT_OPTIONAL_CRYPTO_BASE_SYMBOLS):
        return 1
    if strategy_name in {'scalping', 'momentum trading'}:
        return 1   # AGGRESSIVE: Lower floor for faster trading
    if strategy_name in {'trend following', 'swing trend dca'}:
        return 1   # AGGRESSIVE: Lower floor for faster trading
    if _normalize_management_profile(bot_config.get('managementProfile')) == 'small_account':
        return 1   # AGGRESSIVE: Lower floor for faster trading
    return 1       # AGGRESSIVE: Global floor 1 for all strategies


def _effective_signal_threshold_for_display(bot_config: Dict[str, Any]) -> int:
    floor = _adaptive_signal_threshold_floor(bot_config or {})
    broker_name = canonicalize_broker_name(
        bot_config.get('brokerName') or bot_config.get('broker_type') or bot_config.get('broker') or ''
    )
    mode_value = str(bot_config.get('mode') or bot_config.get('botMode') or 'demo').strip().lower()
    is_demo = mode_value != 'live' and not bool(bot_config.get('is_live'))

    # Runtime trade loop hard-clamps Binance demo to floor; mirror that in every API payload.
    if broker_name == 'Binance' and is_demo:
        return floor

    raw_effective = int(
        _safe_float(
            bot_config.get('effectiveSignalThreshold', bot_config.get('signalThreshold', floor)),
            floor,
        )
    )
    if raw_effective <= 0 or raw_effective > 100:
        return floor
    return max(floor, raw_effective)


def _crypto_only_signal_threshold(symbols: List[Any]) -> Optional[int]:
    base_symbols = {
        _normalize_symbol_base(symbol)
        for symbol in (symbols or [])
        if _normalize_symbol_base(symbol)
    }
    if not base_symbols or not base_symbols.issubset(SMALL_LIVE_ACCOUNT_OPTIONAL_CRYPTO_BASE_SYMBOLS):
        return None
    return 5  # Lower threshold for crypto bots to enable more trading opportunities


def _resolve_runtime_trade_cadence(
    bot_config: Dict[str, Any],
    strategy_name: str,
    signal_symbol: Optional[str],
    signal_strength: float,
) -> Dict[str, int]:
    base_interval = int(bot_config.get('tradingInterval') or 300)
    base_poll = int(bot_config.get('pollInterval') or 15)
    strategy_label = str(strategy_name or '').strip().lower()
    base_symbol = _normalize_symbol_base(signal_symbol or '')
    market_data = _get_market_data_for_symbol(signal_symbol or '') if signal_symbol else {}
    volatility = str(market_data.get('volatility') or 'Medium').title()

    target_interval = base_interval
    target_poll = base_poll

    if base_symbol in {'BTCUSD', 'ETHUSD'}:
        if signal_strength >= 80:
            target_interval, target_poll = 120, 3
        elif signal_strength >= 70:
            target_interval, target_poll = 180, 5
        else:
            target_interval, target_poll = 240, 8
    elif strategy_label in {'trend following', 'swing trend dca'}:
        if signal_strength >= 75:
            target_interval, target_poll = 180, 10
        elif signal_strength >= 65:
            target_interval, target_poll = 240, 15
        else:
            target_interval, target_poll = 300, 20
    elif strategy_label == 'scalping':
        if signal_strength >= 75:
            target_interval, target_poll = 120, 3
        else:
            target_interval, target_poll = 180, 5
    else:
        if signal_strength >= 75:
            target_interval, target_poll = 180, 8
        elif signal_strength >= 65:
            target_interval, target_poll = 240, 12

    if volatility == 'Very High':
        target_interval = min(target_interval, 120 if base_symbol in {'BTCUSD', 'ETHUSD'} else 180)
        target_poll = min(target_poll, 4 if base_symbol in {'BTCUSD', 'ETHUSD'} else 8)
    elif volatility == 'High':
        target_interval = min(target_interval, 180 if base_symbol in {'BTCUSD', 'ETHUSD'} else 240)
        target_poll = min(target_poll, 6 if base_symbol in {'BTCUSD', 'ETHUSD'} else 10)

    # Treat the saved cadence as the maximum wait between scans so migrated
    # high-frequency bots are not slowed back down by adaptive runtime logic.
    target_interval = min(target_interval, base_interval)
    target_poll = min(target_poll, base_poll)

    target_interval = max(60, min(target_interval, 600))
    target_poll = max(2, min(target_poll, max(2, target_interval // 2)))
    return {
        'tradingInterval': target_interval,
        'pollInterval': target_poll,
    }


def _max_trades_per_30_minutes(bot_config: Dict[str, Any], strategy_name: str) -> int:
    profile = _normalize_management_profile(bot_config.get('managementProfile'))
    normalized_strategy = str(strategy_name or '').strip().lower()

    if normalized_strategy == 'scalping':
        return 10
    if profile in {'advanced', 'fast_growth'}:
        return 8
    if profile == 'balanced':
        return 7
    return 6


def _normalize_profit_protection_config(config: Optional[Dict[str, Any]]) -> Dict[str, Any]:
    raw = dict(config) if isinstance(config, dict) else {}
    normalized = dict(DEFAULT_PROFIT_PROTECTION_CONFIG)
    normalized['enabled'] = _coerce_bool(raw.get('enabled', normalized['enabled']), normalized['enabled'])
    normalized['activationPercent'] = max(0.5, min(50.0, _safe_float(raw.get('activationPercent', raw.get('activation_percent', normalized['activationPercent'])), normalized['activationPercent'])))
    normalized['activationMinProfit'] = max(0.0, _safe_float(raw.get('activationMinProfit', raw.get('activation_min_profit', normalized['activationMinProfit'])), normalized['activationMinProfit']))
    normalized['portfolioActivationMinProfit'] = max(0.0, _safe_float(raw.get('portfolioActivationMinProfit', raw.get('portfolio_activation_min_profit', normalized['portfolioActivationMinProfit'])), normalized['portfolioActivationMinProfit']))
    normalized['minLockedProfit'] = max(0.0, _safe_float(raw.get('minLockedProfit', raw.get('min_locked_profit', normalized['minLockedProfit'])), normalized['minLockedProfit']))
    normalized['marginTakeProfitPercent'] = max(0.0, min(200.0, _safe_float(raw.get('marginTakeProfitPercent', raw.get('margin_take_profit_percent', normalized['marginTakeProfitPercent'])), normalized['marginTakeProfitPercent'])))
    normalized['retraceClosePercent'] = max(5.0, min(95.0, _safe_float(raw.get('retraceClosePercent', raw.get('retrace_close_percent', normalized['retraceClosePercent'])), normalized['retraceClosePercent'])))
    normalized['switchOnReversal'] = _coerce_bool(raw.get('switchOnReversal', raw.get('switch_on_reversal', normalized['switchOnReversal'])), normalized['switchOnReversal'])
    normalized['adaptiveByVolatility'] = _coerce_bool(raw.get('adaptiveByVolatility', raw.get('adaptive_by_volatility', normalized['adaptiveByVolatility'])), normalized['adaptiveByVolatility'])
    normalized['breakEvenLockEnabled'] = _coerce_bool(raw.get('breakEvenLockEnabled', raw.get('break_even_lock_enabled', normalized['breakEvenLockEnabled'])), normalized['breakEvenLockEnabled'])
    normalized['breakEvenBufferProfit'] = max(0.0, _safe_float(raw.get('breakEvenBufferProfit', raw.get('break_even_buffer_profit', normalized['breakEvenBufferProfit'])), normalized['breakEvenBufferProfit']))
    normalized['breakEvenActivationShare'] = max(0.1, min(1.0, _safe_float(raw.get('breakEvenActivationShare', raw.get('break_even_activation_share', normalized['breakEvenActivationShare'])), normalized['breakEvenActivationShare'])))
    normalized['protectedSymbolCooldownMinutes'] = max(0.0, min(30.0, _safe_float(raw.get('protectedSymbolCooldownMinutes', raw.get('protected_symbol_cooldown_minutes', normalized['protectedSymbolCooldownMinutes'])), normalized['protectedSymbolCooldownMinutes'])))
    normalized['zeroLossLockEnabled'] = _coerce_bool(raw.get('zeroLossLockEnabled', raw.get('zero_loss_lock_enabled', normalized.get('zeroLossLockEnabled', True))), normalized.get('zeroLossLockEnabled', True))
    normalized['minimumHoldMinutes'] = max(0.0, min(60.0, _safe_float(raw.get('minimumHoldMinutes', raw.get('minimum_hold_minutes', normalized.get('minimumHoldMinutes', 1.0))), normalized.get('minimumHoldMinutes', 1.0))))
    return normalized


def _promote_profit_protection_bucket(bucket: str) -> str:
    order = ['very_low', 'low', 'medium', 'high', 'very_high']
    try:
        return order[min(order.index(bucket) + 1, len(order) - 1)]
    except ValueError:
        return bucket


def _demote_profit_protection_bucket(bucket: str) -> str:
    order = ['very_low', 'low', 'medium', 'high', 'very_high']
    try:
        return order[max(order.index(bucket) - 1, 0)]
    except ValueError:
        return bucket


def _classify_profit_protection_bucket(symbol: str, market_data: Optional[Dict[str, Any]] = None) -> str:
    base_symbol = _normalize_symbol_base(symbol)
    params = SYMBOL_PARAMETERS.get(base_symbol, DEFAULT_SYMBOL_PARAMS)
    volatility_high = max(_safe_float(params.get('volatility_high'), 1.0), 0.01)
    volatility_low = max(_safe_float(params.get('volatility_low'), 0.1), 0.0)
    atr_multiplier = _safe_float(params.get('atr_multiplier'), 1.5)
    live_volatility = max(_safe_float((market_data or {}).get('volatility_pct'), volatility_low), 0.0)

    if base_symbol in {'BTCUSD', 'ETHUSD', 'TSLA', 'NVDA', 'AMD'}:
        bucket = 'very_high'
    elif atr_multiplier >= 1.7 or volatility_high >= 2.0:
        bucket = 'high'
    elif atr_multiplier >= 1.45 or volatility_high >= 0.8:
        bucket = 'medium'
    elif atr_multiplier <= 1.15 and volatility_high <= 0.15:
        bucket = 'very_low'
    else:
        bucket = 'low'

    if live_volatility >= volatility_high * 1.1:
        bucket = _promote_profit_protection_bucket(bucket)
    elif live_volatility <= max(volatility_low * 1.05, 0.01):
        bucket = _demote_profit_protection_bucket(bucket)

    return bucket


def _resolve_profit_protection_for_symbol(
    bot_config: Dict[str, Any],
    symbol: str,
    market_data: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    normalized = _normalize_profit_protection_config(bot_config.get('profitProtection'))
    resolved = dict(normalized)
    resolved['volatilityBucket'] = None

    if not normalized.get('adaptiveByVolatility', True):
        return resolved

    bucket = _classify_profit_protection_bucket(symbol, market_data)
    profile = PROFIT_PROTECTION_VOLATILITY_PROFILES.get(bucket, PROFIT_PROTECTION_VOLATILITY_PROFILES['medium'])
    resolved['activationMinProfit'] = max(
        _safe_float(normalized.get('activationMinProfit'), 0.0),
        _safe_float(profile.get('activationMinProfit'), 0.0),
    )
    resolved['minLockedProfit'] = max(
        _safe_float(normalized.get('minLockedProfit'), 0.0),
        _safe_float(profile.get('minLockedProfit'), 0.0),
    )
    resolved['retraceClosePercent'] = min(
        _safe_float(normalized.get('retraceClosePercent'), 35.0),
        _safe_float(profile.get('retraceClosePercent'), 35.0),
    )
    resolved['breakEvenBufferProfit'] = max(
        _safe_float(normalized.get('breakEvenBufferProfit'), 0.0),
        _safe_float(profile.get('breakEvenBufferProfit'), 0.0),
    )
    resolved['breakEvenActivationShare'] = max(
        _safe_float(normalized.get('breakEvenActivationShare'), 0.5),
        _safe_float(profile.get('breakEvenActivationShare'), 0.5),
    )

    account_balance = max(
        _safe_float(bot_config.get('accountBalance'), 0.0),
        _safe_float(bot_config.get('accountEquity'), 0.0),
    )
    account_currency = str(bot_config.get('displayCurrency') or 'USD').upper()
    small_account_threshold = _get_small_live_account_threshold(account_currency)
    is_small_account = _normalize_management_profile(bot_config.get('managementProfile')) == 'small_account'
    base_symbol = _normalize_symbol_base(symbol)
    if is_small_account and account_balance > 0 and account_balance <= small_account_threshold * 1.5 and base_symbol in {'BTCUSD', 'ETHUSD'}:
        resolved['retraceClosePercent'] = min(_safe_float(resolved.get('retraceClosePercent'), 35.0), 20.0)
        resolved['breakEvenBufferProfit'] = max(_safe_float(resolved.get('breakEvenBufferProfit'), 0.0), 4.0 if base_symbol == 'BTCUSD' else 2.5)
        resolved['breakEvenActivationShare'] = min(_safe_float(resolved.get('breakEvenActivationShare'), 0.5), 0.4)
        resolved['protectedSymbolCooldownMinutes'] = max(_safe_float(resolved.get('protectedSymbolCooldownMinutes'), 5.0), 8.0)

    resolved['volatilityBucket'] = bucket
    return resolved


def _set_symbol_reentry_cooldown(
    bot_config: Dict[str, Any],
    symbol: str,
    minutes: float,
    reason: str,
) -> Optional[str]:
    if minutes <= 0:
        return None

    cooldown_until = (datetime.now() + timedelta(minutes=minutes)).isoformat()
    exact_symbol = str(symbol or '').strip()
    base_symbol = _normalize_symbol_base(symbol)
    cooldowns = bot_config.setdefault('symbolReentryCooldowns', {})
    if exact_symbol:
        cooldowns[exact_symbol] = {'until': cooldown_until, 'reason': reason, 'baseSymbol': base_symbol}
    if base_symbol:
        cooldowns[base_symbol] = {'until': cooldown_until, 'reason': reason, 'baseSymbol': base_symbol}
    return cooldown_until


def _normalize_milestone_withdrawal_plan(raw_plan: Any) -> List[Dict[str, float]]:
    if isinstance(raw_plan, str):
        try:
            raw_plan = json.loads(raw_plan)
        except Exception:
            raw_plan = None

    plan = raw_plan if isinstance(raw_plan, list) else DEFAULT_MILESTONE_WITHDRAWAL_PLAN
    normalized = []
    for item in plan:
        if not isinstance(item, dict):
            continue
        profit_percent = max(1.0, min(500.0, _safe_float(item.get('profitPercent', item.get('profit_percent', 0)), 0.0)))
        withdraw_ratio = max(0.0, min(1.0, _safe_float(item.get('withdrawRatio', item.get('withdraw_ratio', 0)), 0.0)))
        reinvest_ratio = item.get('reinvestRatio', item.get('reinvest_ratio'))
        if reinvest_ratio is None:
            reinvest_ratio = max(0.0, 1.0 - withdraw_ratio)
        reinvest_ratio = max(0.0, min(1.0, _safe_float(reinvest_ratio, max(0.0, 1.0 - withdraw_ratio))))
        if withdraw_ratio <= 0:
            continue
        normalized.append({
            'profitPercent': round(profit_percent, 2),
            'withdrawRatio': round(withdraw_ratio, 4),
            'reinvestRatio': round(reinvest_ratio, 4),
        })

    if not normalized:
        normalized = [dict(item) for item in DEFAULT_MILESTONE_WITHDRAWAL_PLAN]

    normalized.sort(key=lambda item: item['profitPercent'])
    return normalized


def _signal_reversed_for_position(position_type: str, current_signal: str) -> bool:
    normalized_type = str(position_type or '').upper()
    normalized_signal = str(current_signal or '').upper()
    return (
        (normalized_type == 'BUY' and 'SELL' in normalized_signal) or
        (normalized_type == 'SELL' and 'BUY' in normalized_signal)
    )


def _recent_close_request(position_state: Dict[str, Any], window_seconds: int = 45) -> bool:
    close_requested_at = position_state.get('closeRequestedAt')
    if not close_requested_at:
        return False
    try:
        return (datetime.now() - datetime.fromisoformat(close_requested_at)).total_seconds() < window_seconds
    except Exception:
        return False


def _position_age_minutes(entry_time: Optional[str]) -> float:
    if not entry_time:
        return 0.0
    try:
        if isinstance(entry_time, (int, float)):
            entry_dt = datetime.fromtimestamp(float(entry_time))
        else:
            entry_dt = datetime.fromisoformat(str(entry_time))
        return max(0.0, (datetime.now() - entry_dt).total_seconds() / 60.0)
    except Exception:
        return 0.0


def _evaluate_pyramid_addon(
    bot_config: Dict[str, Any],
    symbol: str,
    order_type: str,
    signal_strength: float,
    required_strength: float,
) -> Dict[str, Any]:
    decision = {
        'allowed': False,
        'parentTicket': None,
        'multiplier': PYRAMID_ADDON_VOLUME_MULTIPLIER,
        'reason': None,
    }

    if not symbol or not order_type:
        return decision
    if bot_config.get('managementState') == 'recovery':
        return decision
    if _normalize_management_profile(bot_config.get('managementProfile')) == 'small_account':
        return decision
    if _is_guarded_small_live_account(bot_config, 2.0):
        return decision

    tracked_positions = bot_config.get('open_positions') if isinstance(bot_config.get('open_positions'), dict) else {}
    if not tracked_positions:
        return decision

    same_symbol_positions = []
    addon_count = 0
    for ticket, tracked in tracked_positions.items():
        if str(tracked.get('symbol') or '') != str(symbol):
            continue
        if str(tracked.get('type') or '').upper() != str(order_type).upper():
            continue
        if tracked.get('status') not in {None, 'open'}:
            continue
        same_symbol_positions.append((ticket, tracked))
        if tracked.get('isPyramidAddon'):
            addon_count += 1

    if not same_symbol_positions or addon_count >= PYRAMID_ADDON_MAX_PER_SYMBOL:
        return decision

    parent_ticket = None
    parent_profit = 0.0
    parent_peak = 0.0
    for ticket, tracked in same_symbol_positions:
        if tracked.get('isPyramidAddon'):
            continue
        current_profit = _safe_float(tracked.get('profit'), 0.0)
        peak_profit = _safe_float(tracked.get('peakProfit'), current_profit)
        if current_profit > parent_profit:
            parent_ticket = ticket
            parent_profit = current_profit
            parent_peak = peak_profit

    if not parent_ticket:
        return decision
    if parent_profit < PYRAMID_ADDON_MIN_OPEN_PROFIT or parent_peak < PYRAMID_ADDON_MIN_PEAK_PROFIT:
        return decision
    if signal_strength < max(PYRAMID_ADDON_MIN_SIGNAL, required_strength + PYRAMID_ADDON_SIGNAL_BUFFER):
        return decision

    decision['allowed'] = True
    decision['parentTicket'] = parent_ticket
    decision['reason'] = (
        f"parent {symbol} position positive at {parent_profit:.2f} with signal {signal_strength:.0f}/{required_strength:.0f}"
    )
    return decision


def _profit_protection_activation_amount(bot_config: Dict[str, Any], protection_config: Dict[str, Any]) -> float:
    activation_basis = _profit_protection_margin_basis(bot_config, protection_config)
    activation_min_profit = float(protection_config.get('activationMinProfit') or 0.0)
    activation_percent = float(protection_config.get('activationPercent') or 0.0)
    return max(activation_min_profit, activation_basis * (activation_percent / 100.0))


def _profit_protection_margin_basis(bot_config: Dict[str, Any], protection_config: Dict[str, Any]) -> float:
    activation_min_profit = float(protection_config.get('activationMinProfit') or 0.0)
    fixed_trade_amount = _safe_float(bot_config.get('tradeAmount'), 0.0)
    balance_basis = max(
        _safe_float(bot_config.get('accountEquity'), 0.0),
        _safe_float(bot_config.get('accountBalance'), 0.0),
    )
    return fixed_trade_amount if fixed_trade_amount > 0 else max(balance_basis * 0.02, activation_min_profit)


def manage_protected_open_positions(bot_id, bot_config, current_positions, active_conn, is_mt5, mt5_conn):
    protection_config = _normalize_profit_protection_config(bot_config.get('profitProtection'))

    tracked_positions = bot_config.get('open_positions', {})
    if not tracked_positions or not current_positions:
        return []

    protection_events = []

    for current_position in current_positions:
        ticket = str(current_position.get('ticket') or current_position.get('deal_id') or '')
        if not ticket or ticket not in tracked_positions:
            continue

        tracked = tracked_positions[ticket]
        strategy_name = str(
            tracked.get('strategy')
            or bot_config.get('strategy')
            or ''
        ).strip().lower()
        allow_wider_trend_exits = strategy_name in {'trend following', 'swing trend dca'}
        symbol = tracked.get('symbol', current_position.get('symbol', ''))
        symbol_market_data = _get_market_data_for_symbol(symbol)
        effective_protection = _resolve_profit_protection_for_symbol(bot_config, symbol, symbol_market_data)
        margin_basis = _profit_protection_margin_basis(bot_config, effective_protection)
        activation_amount = _profit_protection_activation_amount(bot_config, effective_protection)
        margin_take_profit_amount = round(
            max(0.0, margin_basis * (_safe_float(effective_protection.get('marginTakeProfitPercent'), 30.0) / 100.0)),
            2,
        )
        break_even_activation_amount = max(
            _safe_float(effective_protection.get('breakEvenBufferProfit'), 0.0) * 2.0,
            activation_amount * _safe_float(effective_protection.get('breakEvenActivationShare'), 0.5),
        )
        current_profit = _resolve_open_position_profit({**tracked, **current_position})
        tracked['profit'] = current_profit
        tracked['currentPrice'] = current_position.get('currentPrice') or current_position.get('marketPrice') or current_position.get('price_current') or tracked.get('currentPrice', 0)
        tracked['peakProfit'] = round(max(_safe_float(tracked.get('peakProfit'), 0.0), current_profit), 2)
        tracked['profitProtectionBucket'] = effective_protection.get('volatilityBucket')

        if tracked['peakProfit'] >= activation_amount:
            tracked['profitProtectionArmed'] = True
            protected_floor = max(
                _safe_float(effective_protection.get('minLockedProfit'), 0.0),
                tracked['peakProfit'] * (1.0 - (_safe_float(effective_protection.get('retraceClosePercent'), 35.0) / 100.0)),
            )
            tracked['lockedProfitFloor'] = round(max(0.0, min(protected_floor, tracked['peakProfit'])), 2)

        if effective_protection.get('breakEvenLockEnabled') and tracked['peakProfit'] >= break_even_activation_amount:
            break_even_floor = round(max(0.0, _safe_float(effective_protection.get('breakEvenBufferProfit'), 0.0)), 2)
            tracked['breakEvenLocked'] = True
            tracked['breakEvenFloor'] = break_even_floor
            tracked['lockedProfitFloor'] = round(max(_safe_float(tracked.get('lockedProfitFloor'), 0.0), break_even_floor), 2)

        symbol_params = _get_effective_symbol_params(symbol, symbol_market_data)
        max_hold_minutes = _safe_float(symbol_params.get('max_hold_minutes'), 0.0)
        time_in_position = _position_age_minutes(tracked.get('entryTime'))
        protection_min_hold_minutes = _safe_float(effective_protection.get('minimumHoldMinutes'), 0.0)
        broker_name = canonicalize_broker_name(
            bot_config.get('brokerName') or bot_config.get('broker_type') or bot_config.get('broker') or ''
        )
        if broker_name == 'Exness':
            protection_min_hold_minutes = max(protection_min_hold_minutes, 1.0)
        protection_hold_satisfied = time_in_position >= protection_min_hold_minutes
        close_reason = None  # Initialize before any conditional assignments
        if max_hold_minutes > 0 and time_in_position >= max_hold_minutes:
            close_reason = 'MAX_HOLD_TIME_EXCEEDED'

        # ── HARD LOSS CAP: force-close if per-trade loss exceeds limit ──────────
        _hard_loss_limit, _stale_loss_threshold = _resolve_hard_loss_limits(bot_config)
        _currency_label = str(bot_config.get('displayCurrency') or 'USD').upper()
        peak_profit = _safe_float(tracked.get('peakProfit'), 0.0)
        if not close_reason and current_profit < -_hard_loss_limit and not _recent_close_request(tracked):
            close_reason = 'HARD_LOSS_LIMIT'
            logger.warning(
                f"[LOSS] Bot {bot_id}: position {ticket} hit hard loss limit "
                f"(loss {current_profit:.2f} {_currency_label} > {-_hard_loss_limit:.2f} {_currency_label}) — force closing"
            )

        stale_loss_min_age = STALE_LOSS_MINUTES
        stale_loss_threshold = _stale_loss_threshold
        if allow_wider_trend_exits:
            stale_loss_min_age = max(STALE_LOSS_MINUTES * 2.5, 30.0)
            stale_loss_threshold = _stale_loss_threshold * 1.6 if _stale_loss_threshold < 0 else _stale_loss_threshold

        # ── STALE LOSS EXIT: close slowly-bleeding positions that never turned profit ─
        if (
            not close_reason
            and peak_profit <= 0          # position never reached profit
            and current_profit <= stale_loss_threshold
            and time_in_position >= stale_loss_min_age
            and not _recent_close_request(tracked)
        ):
            close_reason = 'STALE_LOSS_EXIT'
            logger.warning(
                f"[LOSS] Bot {bot_id}: position {ticket} is stale-losing "
                f"({current_profit:.2f} {_currency_label} after {time_in_position:.0f}m, never in profit) — closing early"
            )

        signal_eval = evaluate_real_trade_signal(tracked.get('symbol', ''), _get_market_data_for_symbol(tracked.get('symbol', '')))
        current_signal = signal_eval.get('signal', 'NEUTRAL')
        locked_floor = _safe_float(tracked.get('lockedProfitFloor'), 0.0)
        upswing_retrace_floor = max(0.5, round(peak_profit * UPSWING_RETRACE_CLOSE_SHARE, 2))
        pyramid_locked_floor = max(0.25, round(peak_profit * PYRAMID_ADDON_LOCKED_PROFIT_SHARE, 2))

        if not close_reason:
            if (
                current_profit > 0
                and margin_take_profit_amount > 0
                and current_profit >= margin_take_profit_amount
                and not _recent_close_request(tracked)
            ):
                close_reason = 'MARGIN_TAKE_PROFIT'

        if not close_reason:
            # Zero-loss lock: close any trade that was ever in profit but has fallen back to 0 or negative.
            # This fires regardless of whether profitProtectionArmed is set, so even small winning
            # positions that reversed before hitting the activation threshold are protected.
            zero_loss_lock_active = effective_protection.get('zeroLossLockEnabled', True)
            if allow_wider_trend_exits and peak_profit < break_even_activation_amount:
                zero_loss_lock_active = False

            if zero_loss_lock_active and peak_profit > 0 and current_profit <= 0 and protection_hold_satisfied and not _recent_close_request(tracked):
                close_reason = 'ZERO_LOSS_LOCK'

        if not close_reason:
            if (
                not allow_wider_trend_exits
                and time_in_position >= UPSWING_RETRACE_MIN_AGE_MINUTES
                and peak_profit >= UPSWING_RETRACE_MIN_PEAK_PROFIT
                and current_profit > 0
                and current_profit <= upswing_retrace_floor
                and not _recent_close_request(tracked)
            ):
                close_reason = 'UPSWING_RETRACE_LOCK'

        if not close_reason:
            if (
                not allow_wider_trend_exits
                and time_in_position >= UPSWING_RETRACE_MIN_AGE_MINUTES
                and peak_profit >= UPSWING_RETRACE_MIN_PEAK_PROFIT
                and current_profit > 0
                and _signal_reversed_for_position(tracked.get('type', ''), current_signal)
                and not _recent_close_request(tracked)
            ):
                close_reason = 'UPSWING_SIGNAL_REVERSAL'

        if not close_reason and tracked.get('isPyramidAddon'):
            if (
                time_in_position >= PYRAMID_ADDON_MAX_HOLD_MINUTES
                and current_profit > 0
                and not _recent_close_request(tracked)
            ):
                close_reason = 'PYRAMID_TIME_EXIT'
            elif (
                peak_profit >= PYRAMID_ADDON_MIN_PEAK_PROFIT
                and current_profit > 0
                and current_profit <= pyramid_locked_floor
                and not _recent_close_request(tracked)
            ):
                close_reason = 'PYRAMID_RETRACE_LOCK'
            elif (
                current_profit > 0
                and _signal_reversed_for_position(tracked.get('type', ''), current_signal)
                and not _recent_close_request(tracked)
            ):
                close_reason = 'PYRAMID_SIGNAL_REVERSAL'
            elif (
                peak_profit > 0
                and current_profit <= 0
                and not _recent_close_request(tracked)
            ):
                close_reason = 'PYRAMID_BREAK_EVEN_FAILURE'

        if not close_reason:
            if not tracked.get('profitProtectionArmed') or _recent_close_request(tracked):
                continue

            if not protection_hold_satisfied:
                continue

            if current_profit <= locked_floor:
                close_reason = 'PROFIT_RETRACE'
            elif effective_protection.get('switchOnReversal') and _signal_reversed_for_position(tracked.get('type', ''), current_signal):
                if symbol.upper().startswith('ETHUSD'):
                    close_reason = 'SIGNAL_REVERSAL_ETH'
                elif current_profit > 0:
                    close_reason = 'LOCKED_PROFIT_SIGNAL_REVERSAL'
            elif tracked['peakProfit'] >= activation_amount and current_profit <= 0:
                close_reason = 'BREAK_EVEN_FAILURE'

        if not close_reason:
            continue

        try:
            if is_mt5 and mt5_conn:
                result = mt5_conn.close_position(ticket)
            elif active_conn:
                result = active_conn.close_position(ticket)
            else:
                result = {'success': False, 'error': 'No connection available'}

            if result.get('success'):
                tracked['closeRequestedAt'] = datetime.now().isoformat()
                tracked['closeReason'] = close_reason
                tracked['status'] = 'closing'
                cooldown_until = _set_symbol_reentry_cooldown(
                    bot_config,
                    tracked.get('symbol', ''),
                    _safe_float(effective_protection.get('protectedSymbolCooldownMinutes'), 5.0),
                    close_reason,
                )
                protection_events.append({
                    'ticket': ticket,
                    'symbol': tracked.get('symbol', ''),
                    'reason': close_reason,
                    'profit': current_profit,
                    'lockedProfitFloor': locked_floor,
                    'breakEvenFloor': _safe_float(tracked.get('breakEvenFloor'), 0.0),
                    'cooldownUntil': cooldown_until,
                })
                logger.info(
                    f"🛡️ Bot {bot_id}: Closed protected winner {tracked.get('symbol')} (ticket {ticket}) "
                    f"at {current_profit:.2f} due to {close_reason} with floor {locked_floor:.2f} "
                    f"[{effective_protection.get('volatilityBucket') or 'manual'}]"
                )
            else:
                logger.warning(f"🛡️ Bot {bot_id}: Failed to close protected position {tracked.get('symbol')}: {result.get('error')}")
        except Exception as close_error:
            logger.error(f"🛡️ Bot {bot_id}: Exception closing protected position {tracked.get('symbol')}: {close_error}")

    return protection_events

def upsert_auto_withdrawal_settings(cursor, bot_id: str, user_id: str, config: Dict[str, Any], bot_config: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    if not isinstance(config, dict):
        raise ValueError('auto-withdrawal config must be an object')

    if not _coerce_bool(config.get('enabled', True), True):
        raise ValueError('auto-withdrawal is disabled')

    withdrawal_mode = str(config.get('withdrawalMode') or config.get('withdrawal_mode') or 'fixed').strip().lower()
    if withdrawal_mode not in {'fixed', 'intelligent', 'milestone'}:
        raise ValueError("withdrawal_mode must be 'fixed', 'intelligent', or 'milestone'")

    target_profit = 0.0
    min_profit = 0.0
    max_profit = 0.0
    volatility_threshold = 0.02
    win_rate_min = 60.0
    trend_strength_min = 0.5
    time_between_withdrawals_hours = int(round(_safe_float(config.get('timeBetweenWithdrawalsHours', config.get('time_between_withdrawals_hours', 24)), 24)))
    milestone_config = None
    last_milestone_pct = 0.0

    if withdrawal_mode == 'fixed':
        target_profit = _safe_float(config.get('targetProfit', config.get('target_profit')), 0.0)
        if target_profit < 10:
            raise ValueError('Minimum profit target is 10')
    elif withdrawal_mode == 'intelligent':
        min_profit = _safe_float(config.get('minProfit', config.get('min_profit', 50)), 50.0)
        max_profit = _safe_float(config.get('maxProfit', config.get('max_profit', 1000)), 1000.0)
        volatility_threshold = _safe_float(config.get('volatilityThreshold', config.get('volatility_threshold', 0.02)), 0.02)
        win_rate_min = _safe_float(config.get('winRateMin', config.get('win_rate_min', 60)), 60.0)
        trend_strength_min = _safe_float(config.get('trendStrengthMin', config.get('trend_strength_min', 0.5)), 0.5)
        if min_profit < 10:
            raise ValueError('Minimum profit must be at least 10')
    else:
        milestones = _normalize_milestone_withdrawal_plan(config.get('milestones'))
        milestone_config = json.dumps(milestones)
        min_profit = _safe_float(config.get('minProfit', config.get('min_profit', 20)), milestones[0]['profitPercent'])

    baseline_equity = _safe_float(config.get('baselineEquity', config.get('baseline_equity', 0.0)), 0.0)
    if baseline_equity <= 0 and isinstance(bot_config, dict):
        baseline_equity = max(
            _safe_float(bot_config.get('accountBalance'), 0.0),
            _safe_float(bot_config.get('accountEquity'), 0.0),
        )
    if baseline_equity <= 0:
        baseline_equity = max(_safe_float(config.get('tradeAmount', 0.0), 0.0) * 5.0, 100.0)

    setting_id = str(uuid.uuid4())
    now_iso = datetime.now().isoformat()
    cursor.execute('''
        INSERT OR REPLACE INTO auto_withdrawal_settings
        (setting_id, bot_id, user_id, target_profit, is_active, withdrawal_method,
         withdrawal_mode, min_profit, max_profit, volatility_threshold, win_rate_min,
         trend_strength_min, time_between_withdrawals_hours, last_withdrawal_at,
         milestone_config, baseline_equity, last_milestone_pct, created_at, updated_at)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    ''', (
        setting_id,
        bot_id,
        user_id,
        target_profit,
        1,
        withdrawal_mode,
        withdrawal_mode,
        min_profit,
        max_profit,
        volatility_threshold,
        win_rate_min,
        trend_strength_min,
        time_between_withdrawals_hours,
        None,
        milestone_config,
        baseline_equity,
        last_milestone_pct,
        now_iso,
        now_iso,
    ))

    message = f'Auto-withdrawal configured for {bot_id} in {withdrawal_mode} mode'
    if withdrawal_mode == 'fixed':
        message = f'Fixed withdrawal set at profit target {target_profit:.2f}'
    elif withdrawal_mode == 'intelligent':
        message = f'Intelligent withdrawal set with min profit {min_profit:.2f} and max profit {max_profit:.2f}'
    elif withdrawal_mode == 'milestone':
        message = 'Milestone withdrawal plan configured'

    return {
        'setting_id': setting_id,
        'withdrawal_mode': withdrawal_mode,
        'baseline_equity': baseline_equity,
        'message': message,
    }


def _clamp_bot_config_value(field_name: str, raw_value, minimum: float, maximum: float, default_value: float, warnings: List[str]) -> float:
    """Clamp bot risk inputs into a safe range and track any overrides."""
    try:
        parsed_value = float(raw_value)
    except (TypeError, ValueError):
        warnings.append(f'{field_name} defaulted to {default_value}')
        return default_value

    if parsed_value < minimum:
        warnings.append(f'{field_name} raised to minimum {minimum}')
        return minimum
    if parsed_value > maximum:
        warnings.append(f'{field_name} reduced to maximum {maximum}')
        return maximum
    return parsed_value


def _clamp_int_value(field_name: str, raw_value, minimum: int, maximum: int, default_value: int, warnings: List[str]) -> int:
    try:
        parsed_value = int(round(float(raw_value)))
    except (TypeError, ValueError):
        warnings.append(f'{field_name} defaulted to {default_value}')
        return default_value

    if parsed_value < minimum:
        warnings.append(f'{field_name} raised to minimum {minimum}')
        return minimum
    if parsed_value > maximum:
        warnings.append(f'{field_name} reduced to maximum {maximum}')
        return maximum
    return parsed_value


def _coerce_bool(raw_value, default_value: bool = False) -> bool:
    if isinstance(raw_value, bool):
        return raw_value
    if isinstance(raw_value, str):
        return raw_value.strip().lower() in {'1', 'true', 'yes', 'on'}
    if raw_value is None:
        return default_value
    return bool(raw_value)


def _safe_float(raw_value, default_value: float = 0.0) -> float:
    try:
        return float(raw_value)
    except (TypeError, ValueError):
        return default_value


def _is_meaningful_broker_trade(trade: Dict[str, Any]) -> bool:
    symbol = str(trade.get('symbol') or trade.get('instrument') or '').strip()
    if not symbol:
        return False

    ticket = str(
        trade.get('ticket')
        or trade.get('deal_id')
        or trade.get('tradeId')
        or trade.get('trade_id')
        or ''
    ).strip()
    volume = abs(_safe_float(trade.get('volume', trade.get('size', trade.get('amount', 0.0))), 0.0))
    entry_price = _safe_float(trade.get('entryPrice', trade.get('openPrice', trade.get('price', 0.0))), 0.0)
    exit_price = _safe_float(trade.get('exitPrice', trade.get('closePrice', 0.0)), 0.0)
    profit = abs(_safe_float(trade.get('profit', trade.get('pnl', trade.get('profit_loss', 0.0))), 0.0))
    time_value = (
        trade.get('time')
        or trade.get('time_close')
        or trade.get('closeTime')
        or trade.get('time_open')
        or trade.get('openTime')
    )

    return bool(ticket or volume > 0 or entry_price > 0 or exit_price > 0 or profit > 0 or time_value)


def _resolve_display_currency_for_mode(mode_value: Any, fallback_currency: str = 'USD') -> str:
    """Normalize API display currency: use the account's actual currency, not hardcoded."""
    fb = str(fallback_currency or 'USD').strip().upper() or 'USD'
    if fb in SUPPORTED_DISPLAY_CURRENCIES:
        return fb
    return 'USD'


def _normalize_symbol_base(symbol: str) -> str:
    normalized = str(symbol or '').strip().upper().replace('/', '')
    if normalized.endswith('M'):
        normalized = normalized[:-1]
    return normalized


def _resolve_analysis_symbol(symbol: str) -> str:
    raw_symbol = str(symbol or '').strip()
    if not raw_symbol:
        return ''

    for items in FXCM_SYMBOL_CONFIG.values():
        for item in items:
            configured_symbol = str(item.get('symbol') or '').strip()
            if configured_symbol and configured_symbol.lower() == raw_symbol.lower():
                return str(item.get('analysis_symbol') or _normalize_symbol_base(configured_symbol))

    canonical_symbol = normalize_symbol_for_broker(raw_symbol, 'FXCM')
    if canonical_symbol and canonical_symbol != raw_symbol:
        for items in FXCM_SYMBOL_CONFIG.values():
            for item in items:
                configured_symbol = str(item.get('symbol') or '').strip()
                if configured_symbol and configured_symbol.lower() == canonical_symbol.lower():
                    return str(item.get('analysis_symbol') or _normalize_symbol_base(configured_symbol))

    normalized_symbol = _normalize_symbol_base(raw_symbol)
    mapped_symbol = SYMBOL_MAPPING.get(raw_symbol, SYMBOL_MAPPING.get(normalized_symbol, normalized_symbol))
    return _normalize_symbol_base(mapped_symbol)


def _get_small_live_account_threshold(currency: str) -> float:
    normalized_currency = str(currency or 'USD').strip().upper()
    return SMALL_LIVE_ACCOUNT_THRESHOLDS.get(normalized_currency, SMALL_LIVE_ACCOUNT_THRESHOLDS['USD'])


def _get_small_live_crypto_min_balance(currency: str) -> float:
    normalized_currency = str(currency or 'USD').strip().upper()
    return SMALL_LIVE_ACCOUNT_CRYPTO_MIN_BALANCES.get(normalized_currency, SMALL_LIVE_ACCOUNT_CRYPTO_MIN_BALANCES['USD'])


def _is_guarded_small_live_account(bot_config: Dict[str, Any], multiplier: float = 1.5) -> bool:
    if not isinstance(bot_config, dict):
        return False

    mode = str(bot_config.get('mode') or bot_config.get('botMode') or 'demo').strip().lower()
    is_live = mode == 'live' or bool(bot_config.get('is_live'))
    if not is_live:
        return False

    account_currency = str(bot_config.get('displayCurrency') or 'USD').strip().upper()
    threshold = _get_small_live_account_threshold(account_currency)
    balance_basis = max(
        _safe_float(bot_config.get('accountEquity'), 0.0),
        _safe_float(bot_config.get('accountBalance'), 0.0),
    )
    return balance_basis > 0 and balance_basis <= (threshold * multiplier)


