CURRENCY_TO_ZAR_RATE_ESTIMATES = {
    'ZAR': 1.0,
    'USD': 18.5,
    'USDT': 18.5,
    'USDC': 18.5,
    'EUR': 20.0,
    'GBP': 23.0,
    'AUD': 12.0,
    'CAD': 13.5,
    'CHF': 20.5,
    'JPY': 0.125,
}


def _estimate_balance_in_zar(balance: float, currency: Optional[str]) -> float:
    normalized_currency = str(currency or 'USD').strip().upper()
    rate = CURRENCY_TO_ZAR_RATE_ESTIMATES.get(normalized_currency, CURRENCY_TO_ZAR_RATE_ESTIMATES['USD'])
    return max(float(balance or 0.0), 0.0) * rate


def _get_live_capital_safety_band(balance_zar: float) -> Optional[Dict[str, Any]]:
    for band in LIVE_CAPITAL_SAFETY_BANDS:
        if balance_zar >= float(band['min_zar']):
            return band
    return None


def _get_fixed_trade_amount_cap_ratio(balance_zar: float, scanner_enabled: bool, is_live: bool) -> float:
    if not is_live or balance_zar < 20_000:
        return 0.08 if scanner_enabled else 0.12

    if balance_zar >= 1_000_000_000:
        return 0.0015 if scanner_enabled else 0.0025
    if balance_zar >= 100_000_000:
        return 0.0020 if scanner_enabled else 0.0030
    if balance_zar >= 10_000_000:
        return 0.0030 if scanner_enabled else 0.0045
    if balance_zar >= 1_000_000:
        return 0.0050 if scanner_enabled else 0.0075
    if balance_zar >= 500_000:
        return 0.0080 if scanner_enabled else 0.0120
    if balance_zar >= 200_000:
        return 0.0100 if scanner_enabled else 0.0150
    if balance_zar >= 100_000:
        return 0.0150 if scanner_enabled else 0.0220
    if balance_zar >= 50_000:
        return 0.0200 if scanner_enabled else 0.0300
    return 0.030 if scanner_enabled else 0.050


def enforce_runtime_capital_safety(bot_config: Dict[str, Any]) -> List[str]:
    """Continuously enforce live capital guardrails, including custom fixed trade amounts."""
    if not isinstance(bot_config, dict):
        return []

    mode = str(bot_config.get('mode') or bot_config.get('botMode') or 'demo').strip().lower()
    is_live = mode == 'live' or bool(bot_config.get('is_live'))
    if not is_live:
        return []

    balance = max(
        _safe_float(bot_config.get('accountEquity'), 0.0),
        _safe_float(bot_config.get('accountBalance'), 0.0),
    )
    if balance <= 0:
        return []

    account_currency = str(bot_config.get('displayCurrency') or 'USD').upper()
    guarded_data, _, band_name = enforce_live_capital_safety_net(
        bot_config,
        True,
        balance,
        account_currency,
    )

    changed_fields: List[str] = []
    for key in (
        'riskPerTrade',
        'maxDailyLoss',
        'maxOpenPositions',
        'maxOpenTrades',
        'maxPositionsPerSymbol',
        'signalThreshold',
        'allowedVolatility',
        'allowCrossMarketReallocation',
    ):
        if key in guarded_data and bot_config.get(key) != guarded_data.get(key):
            bot_config[key] = guarded_data.get(key)
            changed_fields.append(key)

    fixed_trade_amount = _safe_float(bot_config.get('tradeAmount'), 0.0)
    if fixed_trade_amount > 0:
        balance_zar = _estimate_balance_in_zar(balance, account_currency)
        cap_ratio = _get_fixed_trade_amount_cap_ratio(
            balance_zar,
            bool(bot_config.get('intelligentScanner', False)),
            True,
        )
        capped_trade_amount = round(max(1.0, balance * cap_ratio), 2)
        if fixed_trade_amount > capped_trade_amount:
            bot_config['tradeAmount'] = capped_trade_amount
            changed_fields.append('tradeAmount')

    if band_name and bot_config.get('capitalSafetyBand') != band_name:
        bot_config['capitalSafetyBand'] = band_name
        changed_fields.append('capitalSafetyBand')

    return changed_fields


def enforce_live_capital_safety_net(
    data: Dict[str, Any],
    is_live: bool,
    balance: float,
    account_currency: str,
) -> Tuple[Dict[str, Any], List[str], Optional[str]]:
    """Apply stricter capital-aware risk caps for live accounts with larger balances."""
    if not is_live:
        return data, [], None

    safe_balance = max(float(balance or 0.0), 0.0)
    if safe_balance <= 0:
        return data, [], None

    balance_zar = _estimate_balance_in_zar(safe_balance, account_currency)
    band = _get_live_capital_safety_band(balance_zar)
    if not band:
        return data, [], None

    guarded_data = dict(data)
    warnings: List[str] = [
        f"Capital safety net '{band['name']}' applied for approx balance {balance_zar:,.0f} ZAR"
    ]

    current_risk = _safe_float(guarded_data.get('riskPerTrade'), band['riskPerTradeCap'])
    if current_risk <= 0:
        current_risk = band['riskPerTradeCap']
    if current_risk > float(band['riskPerTradeCap']):
        warnings.append(f"riskPerTrade capped to {band['riskPerTradeCap'] / 10:.2f}%")
    guarded_data['riskPerTrade'] = min(current_risk, float(band['riskPerTradeCap']))

    capped_daily_loss = round(safe_balance * float(band['dailyLossPct']), 2)
    current_daily_loss = _safe_float(guarded_data.get('maxDailyLoss'), capped_daily_loss)
    if current_daily_loss <= 0 or current_daily_loss > capped_daily_loss:
        warnings.append(f"maxDailyLoss capped to {capped_daily_loss:.2f} {str(account_currency or 'USD').upper()}")
        guarded_data['maxDailyLoss'] = capped_daily_loss

    max_open_cap = int(band['maxOpenPositions'])
    current_max_open = int(max(1, round(_safe_float(guarded_data.get('maxOpenPositions', guarded_data.get('maxOpenTrades', max_open_cap)), max_open_cap))))
    if current_max_open > max_open_cap:
        warnings.append(f"maxOpenPositions capped to {max_open_cap}")
    guarded_data['maxOpenPositions'] = min(current_max_open, max_open_cap)
    guarded_data['maxOpenTrades'] = guarded_data['maxOpenPositions']

    max_per_symbol_cap = min(int(band['maxPositionsPerSymbol']), guarded_data['maxOpenPositions'])
    current_max_per_symbol = int(max(1, round(_safe_float(guarded_data.get('maxPositionsPerSymbol', max_per_symbol_cap), max_per_symbol_cap))))
    if current_max_per_symbol > max_per_symbol_cap:
        warnings.append(f"maxPositionsPerSymbol capped to {max_per_symbol_cap}")
    guarded_data['maxPositionsPerSymbol'] = min(current_max_per_symbol, max_per_symbol_cap)

    current_signal = int(max(20, round(_safe_float(guarded_data.get('signalThreshold', band['signalFloor']), band['signalFloor']))))
    if current_signal < int(band['signalFloor']):
        warnings.append(f"signalThreshold raised to {int(band['signalFloor'])} for safer entries")
    guarded_data['signalThreshold'] = max(current_signal, int(band['signalFloor']))

    requested_volatility = guarded_data.get('allowedVolatility')
    if not isinstance(requested_volatility, list):
        requested_volatility = list(band['allowedVolatility'])
    filtered_volatility = [
        str(level).title()
        for level in requested_volatility
        if str(level).title() in set(band['allowedVolatility'])
    ]
    if not filtered_volatility:
        filtered_volatility = list(band['allowedVolatility'])
    if len(filtered_volatility) != len(requested_volatility):
        warnings.append("allowedVolatility narrowed by capital safety net")
    guarded_data['allowedVolatility'] = filtered_volatility

    guarded_data['allowCrossMarketReallocation'] = False
    return guarded_data, warnings, str(band['name'])


def derive_small_account_trade_amount(balance: float, currency: Optional[str]) -> Optional[float]:
    normalized_currency = str(currency or 'USD').strip().upper()
    safe_balance = max(float(balance or 0.0), 0.0)
    if safe_balance <= 0:
        return None

    threshold = _get_small_live_account_threshold(normalized_currency)
    cap = SMALL_ACCOUNT_TRADE_AMOUNT_CAPS.get(normalized_currency, SMALL_ACCOUNT_TRADE_AMOUNT_CAPS['USD'])
    tiers = SMALL_LIVE_ACCOUNT_BALANCE_TIERS.get(normalized_currency, SMALL_LIVE_ACCOUNT_BALANCE_TIERS['USD'])
    selected_tier = tiers[0]
    for tier in tiers:
        if safe_balance >= _safe_float(tier.get('min_balance'), 0.0):
            selected_tier = tier

    ratio = max(0.01, _safe_float(selected_tier.get('ratio'), 0.025))
    tier_min_trade = max(0.0, _safe_float(selected_tier.get('min_trade'), safe_balance * 0.015))
    tier_max_trade = max(0.0, _safe_float(selected_tier.get('max_trade'), cap))
    dynamic_cap = max(cap, tier_max_trade)

    safety_soft_cap = safe_balance * 0.08 if safe_balance <= threshold else safe_balance * 0.06
    target_amount = min(safe_balance * ratio, safety_soft_cap, dynamic_cap)
    return round(max(target_amount, tier_min_trade), 2)


def derive_binance_default_trade_amount(
    balance: float,
    currency: Optional[str],
    market_name: Optional[str],
    max_open_positions: Optional[int],
    is_live: bool,
) -> Optional[float]:
    safe_balance = max(float(balance or 0.0), 0.0)
    if safe_balance <= 0:
        return None

    normalized_currency = str(currency or 'USD').strip().upper()
    normalized_market = str(market_name or 'spot').strip().lower()
    safe_positions = max(1, min(8, int(round(_safe_float(max_open_positions, 3) or 3))))

    quote_floor_map = {
        'USD': 40.0,
        'USDT': 40.0,
        'USDC': 40.0,
        'BUSD': 40.0,
        'ZAR': 700.0,
    }

    if normalized_market == 'futures':
        portfolio_ratio = 0.28 if is_live else 0.35
        per_position_cap_ratio = 0.12 if is_live else 0.15
        min_trade = max(25.0, quote_floor_map.get(normalized_currency, 40.0) * 0.6)
    else:
        portfolio_ratio = 0.72 if is_live else 0.80
        per_position_cap_ratio = 0.30 if is_live else 0.35
        min_trade = quote_floor_map.get(normalized_currency, 40.0)

    target_amount = safe_balance * portfolio_ratio / safe_positions
    capped_target = min(target_amount, safe_balance * per_position_cap_ratio)
    if capped_target <= 0:
        return None

    return round(min(safe_balance * 0.95, max(capped_target, min_trade)), 2)


def enforce_small_live_account_guard(
    data: Dict[str, Any],
    symbols: List[str],
    broker_name: str,
    is_live: bool,
    cached_balance,
    cached_margin_free,
    account_currency: str,
) -> Tuple[Dict[str, Any], List[str], List[str], bool]:
    if canonicalize_broker_name(broker_name) != 'Exness' or not is_live:
        return data, symbols, [], False

    balance = max(_safe_float(cached_balance), _safe_float(cached_margin_free))
    currency = str(account_currency or data.get('displayCurrency') or 'USD').strip().upper()
    threshold = _get_small_live_account_threshold(currency)
    guard_limit = threshold * SMALL_LIVE_ACCOUNT_GUARD_LIMIT_MULTIPLIER
    if balance <= 0 or balance > guard_limit:
        return data, symbols, [], False

    defaults = BOT_MANAGEMENT_PROFILES['small_account']
    tiers = SMALL_LIVE_ACCOUNT_BALANCE_TIERS.get(currency, SMALL_LIVE_ACCOUNT_BALANCE_TIERS['USD'])
    selected_tier = tiers[0]
    for tier in tiers:
        if balance >= _safe_float(tier.get('min_balance'), 0.0):
            selected_tier = tier

    tier_max_open_positions = int(max(1, min(2, round(_safe_float(selected_tier.get('max_open_positions'), 1)))))
    tier_risk_per_trade = max(4.0, min(7.5, _safe_float(selected_tier.get('risk_per_trade'), defaults['riskPerTrade'])))
    tier_max_daily_loss = max(defaults['maxDailyLoss'], _safe_float(selected_tier.get('max_daily_loss'), defaults['maxDailyLoss']))
    tier_profit_lock = max(defaults['profitLock'], _safe_float(selected_tier.get('profit_lock'), defaults['profitLock']))
    tier_signal_floor = int(max(65, min(70, round(_safe_float(selected_tier.get('signal_floor'), defaults['signalThreshold'])))))
    tier_allowed_volatility = list(selected_tier.get('allowed_volatility') or ['Very Low', 'Low', 'Medium'])

    guarded_data = dict(data)
    requested_crypto_bases = {
        _normalize_symbol_base(symbol)
        for symbol in symbols
        if _normalize_symbol_base(symbol) in SMALL_LIVE_ACCOUNT_OPTIONAL_CRYPTO_BASE_SYMBOLS
    }
    crypto_min_balance = _get_small_live_crypto_min_balance(currency)
    allow_requested_crypto = bool(requested_crypto_bases) and balance >= crypto_min_balance

    allowed_base_symbols = set(SMALL_LIVE_ACCOUNT_SAFE_BASE_SYMBOLS)
    if allow_requested_crypto:
        allowed_base_symbols.update(requested_crypto_bases)

    filtered_symbols = [symbol for symbol in symbols if _normalize_symbol_base(symbol) in allowed_base_symbols]
    preferred_order = {base: idx for idx, base in enumerate(SMALL_LIVE_ACCOUNT_PREFERRED_BASE_SYMBOLS)}
    filtered_symbols = sorted(
        filtered_symbols,
        key=lambda sym: preferred_order.get(_normalize_symbol_base(sym), len(preferred_order)),
    )
    warnings = [f"Small live account guard applied for {currency} balance {balance:.2f}"]
    if requested_crypto_bases and not allow_requested_crypto:
        warnings.append(f"BTC/ETH kept off until balance reaches {crypto_min_balance:.2f} {currency}")
    derived_trade_amount = derive_small_account_trade_amount(balance, currency)

    if filtered_symbols:
        if len(filtered_symbols) != len(symbols):
            warnings.append('Removed high-margin symbols that do not fit the small live account profile')
    else:
        fallback_symbols = SMALL_LIVE_ACCOUNT_DEFAULT_SYMBOLS
        filtered_symbols = validate_and_correct_symbols(fallback_symbols, broker_name)
        warnings.append('Replaced requested symbols with low-margin forex symbols for the small live account profile')

    intelligent_management = guarded_data.get('intelligentManagement')
    if not isinstance(intelligent_management, dict):
        intelligent_management = {}
    intelligent_management.update({
        'enabled': True,
        'profile': 'small_account',
        'experienceLevel': 'small_account',
        'autoSwitch': False,
        'dynamicSizing': True,
    })

    guarded_data.update({
        'intelligentManagement': intelligent_management,
        'intelligentScanner': False,
        'managementProfile': 'small_account',
        'riskProfile': 'small_account',
        'riskPerTrade': tier_risk_per_trade,
        'maxDailyLoss': tier_max_daily_loss,
        'profitLock': tier_profit_lock,
        'drawdownPausePercent': defaults['drawdownPausePercent'],
        'drawdownPauseHours': defaults['drawdownPauseHours'],
        'maxOpenPositions': tier_max_open_positions,
        'maxOpenTrades': tier_max_open_positions,
        'maxPositionsPerSymbol': 1,
        'signalThreshold': max(tier_signal_floor, min(max(int(_safe_float(guarded_data.get('signalThreshold'), defaults['signalThreshold'])), 20), 70)),
        'allowedVolatility': tier_allowed_volatility,
        'autoSwitch': False,
        'dynamicSizing': True,
        'displayCurrency': currency,
        'tradeAmount': derived_trade_amount,
    })

    if derived_trade_amount:
        warnings.append(
            f"Set stepped trade amount to {derived_trade_amount:.2f} {currency} "
            f"(tier starts at {int(_safe_float(selected_tier.get('min_balance'), 0.0))} {currency})"
        )

    return guarded_data, filtered_symbols, warnings, True


def _normalize_management_profile(raw_profile) -> str:
    profile = str(raw_profile or 'beginner').strip().lower()
    if profile in {'small_account', 'small', 'micro', 'tiny', 'dca', 'swing', 'swing_dca', 'small-account'}:
        return 'small_account'
    if profile in {'fast_growth', 'fast-growth', 'fast', 'growth', 'quick_growth', 'quick-profit', 'quick_profit', 'quick profit'}:
        return 'fast_growth'
    if profile in {'safe', 'conservative', 'starter', 'new', 'novice'}:
        return 'beginner'
    if profile in {'moderate', 'medium', 'assisted'}:
        return 'balanced'
    if profile in {'pro', 'expert', 'aggressive'}:
        return 'advanced'
    if profile not in BOT_MANAGEMENT_PROFILES:
        return 'beginner'
    return profile


def _extract_latest_trade_timestamp(trades: List[Dict[str, Any]]) -> Optional[datetime]:
    """Best-effort parse of latest trade timestamp from runtime trade history."""
    latest_dt = None
    candidate_keys = ('exitTime', 'closedAt', 'time', 'closeTime', 'entryTime')
    for trade in trades or []:
        if not isinstance(trade, dict):
            continue
        raw_value = None
        for key in candidate_keys:
            value = trade.get(key)
            if value:
                raw_value = value
                break
        if not raw_value:
            continue
        try:
            parsed = datetime.fromisoformat(str(raw_value).replace('Z', '+00:00'))
            if parsed.tzinfo is not None:
                parsed = parsed.replace(tzinfo=None)
            if latest_dt is None or parsed > latest_dt:
                latest_dt = parsed
        except Exception:
            continue
    return latest_dt


def _sync_demo_bot_with_best_peer(bot_id: str, bot_config: Dict[str, Any]) -> List[str]:
    """Align a demo bot with the user's best-performing peer bot to avoid idle, over-restricted behavior."""
    if not isinstance(bot_config, dict):
        return []

    mode = str(bot_config.get('mode') or 'demo').strip().lower()
    if mode != 'demo':
        return []

    user_id = bot_config.get('user_id')
    if not user_id:
        return []

    current_symbols = {
        _normalize_symbol_base(symbol)
        for symbol in (bot_config.get('symbols') or [])
        if _normalize_symbol_base(symbol)
    }
    current_strategy = str(bot_config.get('strategy') or '').strip().lower()
    current_broker = canonicalize_broker_name(
        bot_config.get('broker_type') or bot_config.get('brokerName') or bot_config.get('broker') or ''
    )

    best_peer = None
    best_score = None
    for peer_id, peer_bot in active_bots.items():
        if peer_id == bot_id or not isinstance(peer_bot, dict):
            continue
        if peer_bot.get('user_id') != user_id:
            continue

        peer_symbols = {
            _normalize_symbol_base(symbol)
            for symbol in (peer_bot.get('symbols') or [])
            if _normalize_symbol_base(symbol)
        }
        shared_symbols = len(current_symbols & peer_symbols)
        peer_strategy = str(peer_bot.get('strategy') or '').strip().lower()
        strategy_match = 1 if current_strategy and current_strategy == peer_strategy else 0
        peer_profit = _safe_float(peer_bot.get('totalProfit'), 0.0)
        peer_trades = int(peer_bot.get('totalTrades') or 0)
        peer_win_rate = 0.0
        if peer_trades > 0:
            peer_win_rate = (float(peer_bot.get('winningTrades') or 0) / max(peer_trades, 1)) * 100.0

        if shared_symbols == 0 and strategy_match == 0:
            continue
        if peer_trades <= 0:
            continue

        score = (shared_symbols, strategy_match, peer_profit, peer_win_rate, peer_trades)
        if best_score is None or score > best_score:
            best_score = score
            best_peer = peer_bot

    if not best_peer:
        return []

    synced_fields: List[str] = []
    sync_keys = (
        'managementMode',
        'managementProfile',
        'signalThresholdMode',
        'signalThreshold',
        'allowedVolatility',
        'intelligentScanner',
        'autoSwitch',
        'dynamicSizing',
        'tradingMode',
        'tradingInterval',
        'pollInterval',
        'maxOpenPositions',
        'maxOpenTrades',
        'maxPositionsPerSymbol',
    )
    if _normalize_management_profile(bot_config.get('managementProfile')) == 'fast_growth':
        sync_keys = tuple(
            key for key in sync_keys
            if key not in {
                'managementMode',
                'managementProfile',
                'signalThresholdMode',
                'signalThreshold',
                'allowedVolatility',
                'maxOpenPositions',
                'maxOpenTrades',
                'maxPositionsPerSymbol',
            }
        )
    peer_broker = canonicalize_broker_name(
        best_peer.get('broker_type') or best_peer.get('brokerName') or best_peer.get('broker') or ''
    )
    if peer_broker != current_broker:
        sync_keys = tuple(
            key for key in sync_keys
            if key not in {
                'managementProfile',
                'signalThresholdMode',
                'signalThreshold',
                'allowedVolatility',
                'tradingMode',
                'tradingInterval',
                'pollInterval',
            }
        )
    for key in sync_keys:
        peer_value = best_peer.get(key)
        if peer_value is None:
            continue
        if bot_config.get(key) != peer_value:
            if isinstance(peer_value, list):
                bot_config[key] = list(peer_value)
            elif isinstance(peer_value, dict):
                bot_config[key] = dict(peer_value)
            else:
                bot_config[key] = peer_value
            synced_fields.append(key)

    peer_protection = best_peer.get('profitProtection')
    if isinstance(peer_protection, dict):
        normalized_peer_protection = _normalize_profit_protection_config(peer_protection)
        if bot_config.get('profitProtection') != normalized_peer_protection:
            bot_config['profitProtection'] = normalized_peer_protection
            synced_fields.append('profitProtection')

    for transient_key, reset_value in (
        ('managementState', 'normal'),
        ('adaptiveSignalThresholdOffset', 0),
        ('adaptiveSignalMissCount', 0),
        ('adaptiveSignalThresholdReason', None),
        ('effectiveSignalThreshold', None),
        ('lossStreakPauseUntil', None),
        ('consecutiveLosses', 0),
        ('pauseReason', None),
    ):
        if bot_config.get(transient_key) != reset_value:
            bot_config[transient_key] = reset_value
            synced_fields.append(transient_key)

    if synced_fields:
        bot_config['behaviorProfileSourceBotId'] = best_peer.get('botId')
        bot_config['behaviorProfileSyncedAt'] = datetime.now().isoformat()

    return synced_fields


def _recent_closed_trades(bot_config: Dict[str, Any], limit: int = UNIVERSAL_ADAPTATION_RECENT_TRADE_WINDOW) -> List[Dict[str, Any]]:
    trade_history = bot_config.get('tradeHistory') or []
    closed_trades = []
    for trade in trade_history:
        if not isinstance(trade, dict):
            continue
        status = str(trade.get('status') or '').lower()
        close_marker = trade.get('exitTime') or trade.get('time_close')
        if status == 'closed' or close_marker:
            closed_trades.append(trade)

    closed_trades.sort(key=_trade_history_timestamp_key)
    if limit <= 0:
        return closed_trades
    return closed_trades[-limit:]


def _build_performance_sizing_state(bot_config: Dict[str, Any], volatility_level: str = 'Medium') -> Dict[str, Any]:
    recent_closed = _recent_closed_trades(bot_config, limit=PERFORMANCE_SIZING_WINDOW)
    recent_count = len(recent_closed)
    recent_profit = sum(_safe_float(trade.get('profit'), 0.0) for trade in recent_closed)
    recent_wins = sum(1 for trade in recent_closed if _safe_float(trade.get('profit'), 0.0) > 0)
    recent_win_rate = (recent_wins / recent_count * 100.0) if recent_count else 0.0

    consecutive_wins = 0
    consecutive_losses = 0
    for trade in reversed(recent_closed):
        profit = _safe_float(trade.get('profit'), 0.0)
        if profit > 0 and consecutive_losses == 0:
            consecutive_wins += 1
        elif profit < 0 and consecutive_wins == 0:
            consecutive_losses += 1
        else:
            break

    last_scan_results = bot_config.get('lastScanResults') if isinstance(bot_config.get('lastScanResults'), dict) else {}
    qualifying_opportunities = int(last_scan_results.get('qualifyingOpportunities') or 0)
    top_strength = 0.0
    top_opportunities = last_scan_results.get('topOpportunities') if isinstance(last_scan_results.get('topOpportunities'), list) else []
    if top_opportunities:
        top_strength = max(_safe_float(opportunity.get('strength'), 0.0) for opportunity in top_opportunities[:3])
    top_average_strength = 0.0
    if top_opportunities:
        sampled_strengths = [
            _safe_float(opportunity.get('strength'), 0.0)
            for opportunity in top_opportunities[: min(3, len(top_opportunities))]
        ]
        if sampled_strengths:
            top_average_strength = sum(sampled_strengths) / len(sampled_strengths)

    open_positions = bot_config.get('open_positions') if isinstance(bot_config.get('open_positions'), dict) else {}
    aggregate_open_profit = round(sum(_safe_float(position.get('profit'), 0.0) for position in open_positions.values()), 2)
    positive_open_positions = sum(1 for position in open_positions.values() if _safe_float(position.get('profit'), 0.0) > 0)
    best_open_peak = max((_safe_float(position.get('peakProfit'), 0.0) for position in open_positions.values()), default=0.0)

    multiplier = 1.0
    scanner_market_multiplier = 1.0
    reasons: List[str] = []
    state = 'normal'
    guarded_small_live = _is_guarded_small_live_account(bot_config, 2.0)
    is_live = str(bot_config.get('mode') or 'demo').strip().lower() == 'live' or bool(bot_config.get('is_live'))

    if recent_count >= PERFORMANCE_SIZING_MIN_SAMPLE:
        if recent_profit > 0 and recent_win_rate >= 65.0:
            hot_bonus = min(0.18, (recent_win_rate - 60.0) / 100.0)
            multiplier += hot_bonus
            state = 'hot'
            reasons.append(f"recent win rate {recent_win_rate:.0f}%")
            if recent_profit >= max(10.0, abs(_safe_float(bot_config.get('dailyProfit'), 0.0)) * 0.5):
                multiplier += 0.05
                reasons.append('recent profit momentum')
        elif recent_profit < 0 or recent_win_rate <= 45.0:
            multiplier -= 0.18
            state = 'defensive'
            reasons.append(f"recent win rate {recent_win_rate:.0f}%")

    if consecutive_wins >= 3:
        multiplier += 0.07
        state = 'hot'
        reasons.append(f'{consecutive_wins} trade win streak')
    elif consecutive_losses >= 2:
        multiplier -= 0.15
        state = 'defensive'
        reasons.append(f'{consecutive_losses} trade loss streak')

    if qualifying_opportunities >= 3 and top_strength >= 75.0 and state != 'defensive':
        multiplier += 0.08
        state = 'hot'
        reasons.append(f'{qualifying_opportunities} strong scanner setups')
    elif qualifying_opportunities == 0 and recent_count >= PERFORMANCE_SIZING_MIN_SAMPLE:
        multiplier -= 0.08
        state = 'defensive'
        reasons.append('scanner opportunity drought')

    # Scanner-driven capital allocation layer. This is the part that lets the bot
    # press harder in strong market periods and scale down when market quality fades.
    if qualifying_opportunities >= 4 and top_strength >= 85.0 and top_average_strength >= 78.0:
        scanner_market_multiplier = 1.55
        reasons.append(f'scanner regime very strong ({qualifying_opportunities} setups, avg {top_average_strength:.0f})')
    elif qualifying_opportunities >= 3 and top_strength >= 80.0 and top_average_strength >= 74.0:
        scanner_market_multiplier = 1.35
        reasons.append(f'scanner regime strong ({qualifying_opportunities} setups, avg {top_average_strength:.0f})')
    elif qualifying_opportunities >= 2 and top_strength >= 72.0:
        scanner_market_multiplier = 1.18
        reasons.append(f'scanner regime supportive ({qualifying_opportunities} setups)')
    elif qualifying_opportunities == 1 and top_strength >= 68.0:
        scanner_market_multiplier = 1.08
        reasons.append('single high-quality scanner setup')
    elif qualifying_opportunities == 0:
        scanner_market_multiplier = 0.82
        reasons.append('scanner found no qualified setups')

    if recent_profit > 0 and recent_win_rate >= 60.0 and scanner_market_multiplier > 1.0:
        scanner_market_multiplier += 0.10
        reasons.append('recent profits confirm scanner momentum')
    elif recent_profit < 0 and recent_win_rate <= 45.0:
        scanner_market_multiplier = min(scanner_market_multiplier, 0.78)
        reasons.append('recent losses override aggressive scanner sizing')

    if aggregate_open_profit > 0 and positive_open_positions > 0 and top_strength >= 78.0:
        scanner_market_multiplier += 0.08
        reasons.append('open positions support increasing capital deployment')
    elif aggregate_open_profit < 0:
        scanner_market_multiplier = min(scanner_market_multiplier, 0.85)
        reasons.append('open-position pressure reduces scanner capital')

    if consecutive_losses >= 2:
        scanner_market_multiplier = min(scanner_market_multiplier, 0.72)
        reasons.append('loss streak blocks capital expansion')

    if volatility_level == 'Very High' and scanner_market_multiplier > 1.0:
        scanner_market_multiplier = min(scanner_market_multiplier, 1.12)
        reasons.append('very high volatility tempers scanner boost')
    elif volatility_level == 'High' and scanner_market_multiplier > 1.0:
        scanner_market_multiplier = min(scanner_market_multiplier, 1.25)
        reasons.append('high volatility tempers scanner boost')

    multiplier *= scanner_market_multiplier

    if (
        open_positions
        and aggregate_open_profit >= UPSWING_SCALE_MIN_OPEN_PROFIT
        and positive_open_positions > 0
        and top_strength >= UPSWING_SCALE_MIN_SIGNAL_STRENGTH
        and bot_config.get('managementState') != 'recovery'
    ):
        multiplier += 0.12
        state = 'hot'
        reasons.append(
            f'open P/L {aggregate_open_profit:.2f} with live signal strength {top_strength:.0f}'
        )
    elif open_positions and aggregate_open_profit <= 0:
        multiplier = min(multiplier, 0.88)
        state = 'defensive'
        reasons.append(f'open P/L pressure {aggregate_open_profit:.2f}')

    if best_open_peak >= UPSWING_RETRACE_MIN_PEAK_PROFIT and aggregate_open_profit > 0 and state != 'defensive':
        multiplier += 0.05
        reasons.append(f'open trade peak reached {best_open_peak:.2f}')

    if bot_config.get('managementState') == 'recovery':
        multiplier = min(multiplier, 0.65)
        scanner_market_multiplier = min(scanner_market_multiplier, 0.75)
        state = 'defensive'
        reasons.append('recovery mode active')

    if volatility_level == 'High':
        multiplier = min(multiplier, 0.9)
        reasons.append('high volatility cap')
    elif volatility_level == 'Very High':
        multiplier = min(multiplier, 0.75)
        state = 'defensive'
        reasons.append('very high volatility cap')

    scanner_boost_cap = _resolve_scanner_capital_boost_cap(
        bot_config,
        is_live=is_live,
        guarded_small_live=guarded_small_live,
    )
    multiplier = min(multiplier, scanner_boost_cap)
    scanner_market_multiplier = min(scanner_market_multiplier, scanner_boost_cap)
    if guarded_small_live:
        reasons.append('small live account cap')

    multiplier = max(PERFORMANCE_SIZING_MAX_REDUCTION, min(multiplier, PERFORMANCE_SIZING_MAX_BOOST))
    if abs(multiplier - 1.0) < 0.03:
        multiplier = 1.0
        if state != 'defensive':
            state = 'normal'

    return {
        'timestamp': datetime.now().isoformat(),
        'state': state,
        'multiplier': round(multiplier, 3),
        'recentTradeCount': recent_count,
        'recentWinRate': round(recent_win_rate, 2),
        'recentProfit': round(recent_profit, 2),
        'consecutiveWins': consecutive_wins,
        'consecutiveLosses': consecutive_losses,
        'aggregateOpenProfit': aggregate_open_profit,
        'positiveOpenPositions': positive_open_positions,
        'bestOpenPeakProfit': round(best_open_peak, 2),
        'qualifyingOpportunities': qualifying_opportunities,
        'topOpportunityStrength': round(top_strength, 2),
        'topOpportunityAverageStrength': round(top_average_strength, 2),
        'scannerCapitalMultiplier': round(scanner_market_multiplier, 3),
        'reason': '; '.join(reasons) if reasons else 'baseline sizing',
    }


def apply_universal_performance_adaptation(bot_id: str, bot_config: Dict[str, Any]) -> List[str]:
    return []  # DISABLED: Adaptive boosting interferes with aggressive low-threshold trading

    now = datetime.now()
    last_adaptation_raw = bot_config.get('lastAdaptationAt')
    if last_adaptation_raw:
        try:
            last_adaptation_at = datetime.fromisoformat(str(last_adaptation_raw))
            if (now - last_adaptation_at).total_seconds() < (UNIVERSAL_ADAPTATION_COOLDOWN_MINUTES * 60):
                return []
        except Exception:
            pass

    profile = _normalize_management_profile(bot_config.get('managementProfile'))
    defaults = BOT_MANAGEMENT_PROFILES.get(profile, BOT_MANAGEMENT_PROFILES['beginner'])
    is_live = str(bot_config.get('mode') or 'demo').strip().lower() == 'live' or bool(bot_config.get('is_live'))
    guarded_small_live = _is_guarded_small_live_account(bot_config, 2.0)
    adaptive_floor = _adaptive_signal_threshold_floor(bot_config)
    changes: List[str] = []
    reasons: List[str] = []

    current_threshold = max(int(bot_config.get('signalThreshold') or defaults['signalThreshold']), adaptive_floor)
    current_allowed_volatility = list(bot_config.get('allowedVolatility') or defaults['allowedVolatility'])
    if not current_allowed_volatility:
        current_allowed_volatility = list(defaults['allowedVolatility'])

    current_drawdown_percent = float(bot_config.get('drawdownPausePercent') or defaults['drawdownPausePercent'])
    current_drawdown_hours = float(bot_config.get('drawdownPauseHours') or defaults['drawdownPauseHours'])
    drawdown_percent_min, drawdown_percent_max = BOT_RISK_LIMITS['drawdownPausePercent']
    drawdown_hours_min, drawdown_hours_max = BOT_RISK_LIMITS['drawdownPauseHours']

    open_positions = bot_config.get('open_positions') or {}
    idle_cycles = int(bot_config.get('adaptiveSignalMissCount') or 0)
    no_open_positions = not bool(open_positions)

    if not is_live and no_open_positions and idle_cycles >= max(2, ADAPTIVE_SCANNER_TRIGGER_MISSES + 2):
        if not bot_config.get('intelligentScanner', False):
            bot_config['intelligentScanner'] = True
            changes.append('intelligentScanner=enabled')
        lowered_threshold = max(adaptive_floor, current_threshold - 5)
        if lowered_threshold != current_threshold:
            bot_config['signalThreshold'] = lowered_threshold
            current_threshold = lowered_threshold
            changes.append(f'signalThreshold={lowered_threshold}')
        reasons.append(f'idle reallocation after {idle_cycles} missed cycles')

    recent_closed = _recent_closed_trades(bot_config)
    minimum_sample = UNIVERSAL_ADAPTATION_MIN_SAMPLE_TRADES
    if is_live:
        minimum_sample = max(12, UNIVERSAL_ADAPTATION_MIN_SAMPLE_TRADES * 2)
    if len(recent_closed) >= minimum_sample:
        recent_profit = sum(float(trade.get('profit') or 0.0) for trade in recent_closed)
        recent_wins = sum(1 for trade in recent_closed if float(trade.get('profit') or 0.0) > 0)
        recent_win_rate = (recent_wins / len(recent_closed)) * 100.0
        consecutive_losses = 0
        for trade in reversed(recent_closed):
            if float(trade.get('profit') or 0.0) < 0:
                consecutive_losses += 1
            else:
                break

        if (not is_live) and recent_profit > 0 and recent_win_rate >= UNIVERSAL_ADAPTATION_SUCCESS_WIN_RATE:
            target_threshold = max(adaptive_floor, current_threshold - 3)
            if target_threshold != current_threshold:
                bot_config['signalThreshold'] = target_threshold
                current_threshold = target_threshold
                changes.append(f'signalThreshold={target_threshold}')

            if not bot_config.get('dynamicSizing', True):
                bot_config['dynamicSizing'] = True
                changes.append('dynamicSizing=enabled')

            if profile != 'small_account' and 'High' not in current_allowed_volatility:
                next_allowed = list(current_allowed_volatility)
                next_allowed.append('High')
                bot_config['allowedVolatility'] = next_allowed
                current_allowed_volatility = next_allowed
                changes.append('allowedVolatility+=High')

            relaxed_drawdown_percent = min(drawdown_percent_max, current_drawdown_percent + 1.0)
            if relaxed_drawdown_percent != current_drawdown_percent:
                bot_config['drawdownPausePercent'] = relaxed_drawdown_percent
                current_drawdown_percent = relaxed_drawdown_percent
                changes.append(f'drawdownPausePercent={relaxed_drawdown_percent:.1f}')

            shorter_drawdown_hours = max(drawdown_hours_min, current_drawdown_hours - 1.0)
            if shorter_drawdown_hours != current_drawdown_hours:
                bot_config['drawdownPauseHours'] = shorter_drawdown_hours
                current_drawdown_hours = shorter_drawdown_hours
                changes.append(f'drawdownPauseHours={shorter_drawdown_hours:.1f}')

            reasons.append(
                f'strong recent form ({recent_win_rate:.0f}% win rate, {recent_profit:.2f} profit over {len(recent_closed)} trades)'
            )
        elif recent_profit < 0 or recent_win_rate <= UNIVERSAL_ADAPTATION_STRUGGLE_WIN_RATE or consecutive_losses >= 2:
            threshold_step = 8 if profile == 'fast_growth' else 5
            target_threshold = min(88 if profile == 'fast_growth' else 85, current_threshold + threshold_step)
            if is_live and guarded_small_live:
                target_threshold = max(target_threshold, 65)
            elif (not is_live) and no_open_positions:
                target_threshold = min(target_threshold, adaptive_floor + 10)
            if target_threshold != current_threshold:
                bot_config['signalThreshold'] = target_threshold
                current_threshold = target_threshold
                changes.append(f'signalThreshold={target_threshold}')

            safer_allowed = [
                level for level in current_allowed_volatility if level in ['Very Low', 'Low', 'Medium']
            ] or ['Very Low', 'Low', 'Medium']
            if profile == 'fast_growth':
                safer_allowed = [
                    level for level in safer_allowed if level in ['Very Low', 'Low']
                ] or ['Very Low', 'Low']
            if safer_allowed != current_allowed_volatility:
                bot_config['allowedVolatility'] = safer_allowed
                current_allowed_volatility = safer_allowed
                changes.append('allowedVolatility=tightened')

            tighter_drawdown_percent = max(drawdown_percent_min, current_drawdown_percent - 1.0)
            if tighter_drawdown_percent != current_drawdown_percent:
                bot_config['drawdownPausePercent'] = tighter_drawdown_percent
                current_drawdown_percent = tighter_drawdown_percent
                changes.append(f'drawdownPausePercent={tighter_drawdown_percent:.1f}')

            longer_drawdown_hours = min(drawdown_hours_max, current_drawdown_hours + 1.0)
            if longer_drawdown_hours != current_drawdown_hours:
                bot_config['drawdownPauseHours'] = longer_drawdown_hours
                current_drawdown_hours = longer_drawdown_hours
                changes.append(f'drawdownPauseHours={longer_drawdown_hours:.1f}')

            if is_live and bot_config.get('intelligentScanner', False):
                bot_config['intelligentScanner'] = False
                changes.append('intelligentScanner=disabled')
            elif (not is_live) and (not bot_config.get('intelligentScanner', False)) and no_open_positions:
                bot_config['intelligentScanner'] = True
                changes.append('intelligentScanner=enabled')

            reasons.append(
                f'weak recent form ({recent_win_rate:.0f}% win rate, {recent_profit:.2f} profit over {len(recent_closed)} trades)'
            )

    if changes:
        bot_config['lastAdaptationAt'] = now.isoformat()
        bot_config['lastAdaptationReason'] = '; '.join(reasons)
        logger.info(
            f"🧠 Bot {bot_id}: Universal adaptation applied -> {', '.join(changes)} | {bot_config['lastAdaptationReason']}"
        )

    return changes


def _reset_adaptive_signal_threshold(bot_config: Dict[str, Any]) -> bool:
    had_adaptive_state = any(
        [
            int(bot_config.get('adaptiveSignalThresholdOffset') or 0) > 0,
            int(bot_config.get('adaptiveSignalMissCount') or 0) > 0,
            bool(bot_config.get('adaptiveSignalThresholdReason')),
        ]
    )
    bot_config['adaptiveSignalThresholdOffset'] = 0
    bot_config['adaptiveSignalMissCount'] = 0
    bot_config['adaptiveSignalThresholdReason'] = None
    return had_adaptive_state


def update_adaptive_signal_threshold_state(
    bot_id: str,
    bot_config: Dict[str, Any],
    base_threshold: int,
    best_signal_strength: float,
    configured_signal_hits: int,
    scanner_signal_hits: int,
    trades_placed: int,
    open_positions: int,
) -> None:
    adaptive_floor = _adaptive_signal_threshold_floor(bot_config)
    best_signal_strength = float(best_signal_strength or 0.0)
    bot_config['lastBestSignalStrength'] = round(best_signal_strength, 1)
    if bot_config.get('managementState') == 'recovery':
        bot_config['autoSignalEnvironment'] = 'recovery'
        if _reset_adaptive_signal_threshold(bot_config):
            logger.info(
                f"🛡️ Bot {bot_id}: Adaptive threshold reset while recovery mode is active "
                f"(base threshold restored to {base_threshold})"
            )
        return

    has_qualifying_signal = configured_signal_hits > 0 or scanner_signal_hits > 0
    if trades_placed > 0 or has_qualifying_signal or open_positions > 0:
        total_signal_hits = int(configured_signal_hits or 0) + int(scanner_signal_hits or 0)
        if trades_placed > 0 or total_signal_hits >= 2 or best_signal_strength >= max(base_threshold + 15, 75):
            bot_config['autoSignalEnvironment'] = 'high'
        elif best_signal_strength >= max(adaptive_floor, base_threshold - 5):
            bot_config['autoSignalEnvironment'] = 'warming'
        else:
            bot_config['autoSignalEnvironment'] = 'balanced'
        if _reset_adaptive_signal_threshold(bot_config):
            logger.info(
                f"🎯 Bot {bot_id}: Adaptive threshold reset to base {base_threshold} "
                f"after {'trade execution' if trades_placed > 0 else 'signal recovery'}"
            )
        return

    miss_count = int(bot_config.get('adaptiveSignalMissCount') or 0) + 1
    current_offset = int(bot_config.get('adaptiveSignalThresholdOffset') or 0)
    signal_gap = max(0.0, float(base_threshold) - best_signal_strength)
    reduction_step = ADAPTIVE_SIGNAL_THRESHOLD_LOW_SIGNAL_STEP if signal_gap >= 10.0 else ADAPTIVE_SIGNAL_THRESHOLD_STEP
    new_offset = min(ADAPTIVE_SIGNAL_THRESHOLD_MAX_REDUCTION, current_offset + reduction_step)
    if best_signal_strength <= adaptive_floor + 5:
        bot_config['autoSignalEnvironment'] = 'low'
    else:
        bot_config['autoSignalEnvironment'] = 'warming'

    bot_config['adaptiveSignalMissCount'] = miss_count
    bot_config['adaptiveSignalThresholdOffset'] = new_offset
    bot_config['adaptiveSignalThresholdReason'] = 'no_qualifying_signal'

    if new_offset != current_offset:
        lowered_threshold = max(adaptive_floor, base_threshold - new_offset)
        logger.info(
            f"📉 Bot {bot_id}: No qualifying signals for {miss_count} cycle(s) - "
            f"best raw signal was {best_signal_strength:.0f}/100, reducing threshold by {reduction_step} "
            f"for next cycle ({base_threshold} -> {lowered_threshold})"
        )


def apply_assisted_management_overrides(bot_config: Dict[str, Any]) -> Dict[str, Any]:
    profile = _normalize_management_profile(bot_config.get('managementProfile'))
    is_assisted = bot_config.get('managementMode', 'assisted') != 'manual'
    mode_value = str(bot_config.get('mode') or bot_config.get('botMode') or 'demo').strip().lower()
    is_live = mode_value == 'live' or bool(bot_config.get('is_live'))
    guarded_small_live = _is_guarded_small_live_account(bot_config, 2.0)
    broker_name = canonicalize_broker_name(
        bot_config.get('brokerName')
        or bot_config.get('broker_type')
        or bot_config.get('broker')
        or ''
    )
    defaults = BOT_MANAGEMENT_PROFILES.get(profile, BOT_MANAGEMENT_PROFILES['beginner'])
    broker_default_signal_threshold = _default_signal_threshold_for_broker_profile(profile, broker_name)
    adaptive_floor = _adaptive_signal_threshold_floor(bot_config)
    crypto_only_threshold = _crypto_only_signal_threshold(bot_config.get('symbols') or [])
    signal_threshold_mode = str(bot_config.get('signalThresholdMode') or 'auto').lower()
    # MANUAL MODE GUARD: an explicit signalThresholdMode='manual' must survive even
    # under assisted management. Previously this was force-coerced to 'auto', which
    # silently clobbered user-pinned thresholds on every cycle.
    if signal_threshold_mode != 'manual':
        signal_threshold_mode = 'auto'
    bot_config['signalThresholdMode'] = signal_threshold_mode
    _user_manual_threshold = signal_threshold_mode == 'manual'
    effective = {
        'profile': profile,
        'mode': 'assisted' if is_assisted else 'manual',
        'maxOpenPositions': int(bot_config.get('maxOpenPositions') or defaults['maxOpenPositions']),
        'maxPositionsPerSymbol': int(bot_config.get('maxPositionsPerSymbol') or defaults['maxPositionsPerSymbol']),
        'signalThreshold': int(bot_config.get('signalThreshold') or broker_default_signal_threshold),
        'allowedVolatility': list(bot_config.get('allowedVolatility') or defaults['allowedVolatility']),
    }

    if is_assisted:
        effective['maxOpenPositions'] = min(effective['maxOpenPositions'], defaults['maxOpenPositions'])
        effective['maxPositionsPerSymbol'] = min(effective['maxPositionsPerSymbol'], defaults['maxPositionsPerSymbol'])
        if signal_threshold_mode == 'auto':
            target_threshold = crypto_only_threshold if crypto_only_threshold is not None else broker_default_signal_threshold
            effective['signalThreshold'] = max(adaptive_floor, int(target_threshold))
        effective['allowedVolatility'] = [
            level for level in effective['allowedVolatility'] if level in defaults['allowedVolatility']
        ] or list(defaults['allowedVolatility'])

        if profile == 'small_account':
            effective['maxOpenPositions'] = 1
            effective['maxPositionsPerSymbol'] = 1
            if signal_threshold_mode == 'auto':
                target_threshold = crypto_only_threshold if crypto_only_threshold is not None else broker_default_signal_threshold
                effective['signalThreshold'] = max(adaptive_floor, int(target_threshold))
            effective['allowedVolatility'] = [
                level for level in effective['allowedVolatility'] if level in ['Very Low', 'Low', 'Medium']
            ] or ['Very Low', 'Low', 'Medium']

        if profile == 'fast_growth':
            effective['maxOpenPositions'] = min(effective['maxOpenPositions'], 2)
            effective['maxPositionsPerSymbol'] = 1
            if signal_threshold_mode == 'auto':
                target_threshold = crypto_only_threshold if crypto_only_threshold is not None else broker_default_signal_threshold
                effective['signalThreshold'] = max(adaptive_floor, int(target_threshold))
            effective['allowedVolatility'] = [
                level for level in effective['allowedVolatility'] if level in ['Low', 'Medium']
            ] or ['Low', 'Medium']

        if guarded_small_live:
            effective['maxOpenPositions'] = 1
            effective['maxPositionsPerSymbol'] = 1
            effective['signalThreshold'] = max(effective['signalThreshold'], 66)
            effective['allowedVolatility'] = [
                level for level in effective['allowedVolatility'] if level in ['Very Low', 'Low', 'Medium']
            ] or ['Very Low', 'Low', 'Medium']
            bot_config['intelligentScanner'] = False

        recent_trades = bot_config.get('tradeHistory') or []
        recent_closed = recent_trades[-6:]
        consecutive_losses = 0
        for trade in reversed(recent_closed):
            if (trade.get('profit') or 0) < 0:
                consecutive_losses += 1
            else:
                break

        recent_count = len(recent_closed)
        recent_wins = sum(1 for trade in recent_closed if (trade.get('profit') or 0) > 0)
        recent_win_rate = (recent_wins / recent_count * 100) if recent_count else 100.0

        is_recovery_condition = consecutive_losses >= 2 or (recent_count >= 4 and recent_win_rate < 40)
        fast_growth_recovery = profile == 'fast_growth' and (consecutive_losses >= 1 or (recent_count >= 3 and recent_win_rate < 45))
        if is_recovery_condition or fast_growth_recovery:
            if (not is_live) and not bool(bot_config.get('open_positions')):
                recovery_floor = adaptive_floor + 5
                effective['signalThreshold'] = min(adaptive_floor + 10, max(recovery_floor, effective['signalThreshold']))
            else:
                recovery_floor = 68 if profile == 'small_account' else 66
                effective['signalThreshold'] = min(88, max(recovery_floor, effective['signalThreshold'] + 6))
            effective['maxOpenPositions'] = min(effective['maxOpenPositions'], 1 if profile == 'beginner' else 2)
            effective['maxPositionsPerSymbol'] = 1
            effective['allowedVolatility'] = ['Very Low', 'Low', 'Medium']  # Tighten but still allow trading
            if profile == 'fast_growth':
                effective['signalThreshold'] = min(88, max(effective['signalThreshold'], 72))
                effective['maxOpenPositions'] = 1
                effective['allowedVolatility'] = ['Very Low', 'Low']
            bot_config['managementState'] = 'recovery'
        else:
            bot_config['managementState'] = 'normal'

        # Recovery mode should protect, not stall indefinitely.
        if bot_config.get('managementState') == 'recovery':
            latest_trade_dt = _extract_latest_trade_timestamp(recent_trades)
            no_open_positions = not bool(bot_config.get('open_positions'))
            if latest_trade_dt and no_open_positions:
                idle_minutes = (datetime.now() - latest_trade_dt).total_seconds() / 60.0
                if idle_minutes >= 30:
                    bot_config['managementState'] = 'normal'
                    relaxed_threshold = crypto_only_threshold if crypto_only_threshold is not None else broker_default_signal_threshold
                    if guarded_small_live:
                        relaxed_threshold = max(relaxed_threshold, 65)
                    effective['signalThreshold'] = min(effective['signalThreshold'], relaxed_threshold)
                    if guarded_small_live:
                        effective['allowedVolatility'] = ['Very Low', 'Low', 'Medium']
                    else:
                        effective['allowedVolatility'] = list(defaults['allowedVolatility'])
                    logger.info(
                        f"🧠 Bot {bot_config.get('botId', 'unknown')}: Recovery relaxed after {idle_minutes:.0f}m "
                        f"without trades (threshold -> {effective['signalThreshold']})"
                    )
    else:
        bot_config['managementState'] = 'manual'

    signal_environment = str(bot_config.get('autoSignalEnvironment') or 'balanced').lower()
    if is_assisted and bot_config.get('managementState') != 'recovery':
        if signal_environment == 'low':
            effective['signalThreshold'] = max(adaptive_floor, effective['signalThreshold'] - 6)
            if 'Medium' not in effective['allowedVolatility'] and not guarded_small_live:
                effective['allowedVolatility'].append('Medium')
            bot_config['intelligentScanner'] = True
        elif signal_environment == 'warming':
            effective['signalThreshold'] = max(adaptive_floor, effective['signalThreshold'] - 3)
            if 'Medium' not in effective['allowedVolatility'] and not guarded_small_live:
                effective['allowedVolatility'].append('Medium')
        elif signal_environment == 'high':
            effective['signalThreshold'] = max(adaptive_floor, effective['signalThreshold'] - 2)
            if profile in {'balanced', 'advanced', 'fast_growth'} and not guarded_small_live:
                effective['maxOpenPositions'] = min(5, effective['maxOpenPositions'] + 1)
                effective['maxPositionsPerSymbol'] = min(effective['maxOpenPositions'], max(effective['maxPositionsPerSymbol'], 2 if profile in {'advanced', 'fast_growth'} else 1))
            if 'Medium' not in effective['allowedVolatility'] and not guarded_small_live:
                effective['allowedVolatility'].append('Medium')

    # In Binance demo mode keep the threshold at the runtime floor so
    # peer profile sync/adaptation cannot over-restrict entry gating.
    # MANUAL MODE GUARD: skip when user has pinned signalThresholdMode='manual'.
    if (not is_live) and broker_name == 'Binance' and not _user_manual_threshold:
        effective['signalThreshold'] = adaptive_floor

    adaptive_offset = int(bot_config.get('adaptiveSignalThresholdOffset') or 0)
    if adaptive_offset > 0 and bot_config.get('managementState') != 'recovery' and not _user_manual_threshold:
        effective['signalThreshold'] = max(adaptive_floor, effective['signalThreshold'] - adaptive_offset)

    # MANUAL MODE GUARD: when user has pinned a manual threshold and explicit maxOpenPositions,
    # restore them after all the assisted overrides above.
    if _user_manual_threshold:
        effective['signalThreshold'] = max(1, int(bot_config.get('signalThreshold') or 50))
        _user_max_open = int(bot_config.get('maxOpenPositions') or 0)
        if _user_max_open > 0:
            effective['maxOpenPositions'] = _user_max_open
        _user_max_per_sym = int(bot_config.get('maxPositionsPerSymbol') or 0)
        if _user_max_per_sym > 0:
            effective['maxPositionsPerSymbol'] = _user_max_per_sym

    bot_config['effectiveSignalThreshold'] = effective['signalThreshold']
    bot_config['effectiveMaxOpenPositions'] = effective['maxOpenPositions']
    bot_config['effectiveMaxPositionsPerSymbol'] = effective['maxPositionsPerSymbol']
    bot_config['effectiveAllowedVolatility'] = effective['allowedVolatility']
    return effective


def sanitize_bot_risk_config(
    data: Dict,
    account_currency: str = 'USD',
    broker_name: str = '',
) -> Dict[str, Any]:
    """Normalize bot risk configuration before persisting or trading.
    
    Args:
        data: Bot configuration dictionary
        account_currency: Account's actual currency (e.g., 'USD', 'ZAR') from broker credentials
    """
    warnings: List[str] = []

    intelligent_settings = data.get('intelligentManagement') or {}
    if not isinstance(intelligent_settings, dict):
        intelligent_settings = {}

    management_profile = _normalize_management_profile(
        intelligent_settings.get('profile')
        or intelligent_settings.get('experienceLevel')
        or data.get('managementProfile')
        or data.get('riskProfile')
        or 'beginner'
    )
    management_mode = 'manual' if not _coerce_bool(intelligent_settings.get('enabled', True), True) else 'assisted'
    profile_defaults = BOT_MANAGEMENT_PROFILES[management_profile]
    default_signal_threshold = _default_signal_threshold_for_broker_profile(
        management_profile,
        broker_name,
    )

    raw_risk_per_trade = data.get('riskPerTrade')
    if raw_risk_per_trade is None and data.get('riskPercent') is not None:
        try:
            raw_risk_per_trade = float(data.get('riskPercent', 2.0)) * 10.0
        except (TypeError, ValueError):
            raw_risk_per_trade = profile_defaults['riskPerTrade']
            warnings.append(f"riskPercent defaulted to {profile_defaults['riskPerTrade'] / 10:.1f}% profile value")

    risk_per_trade = _clamp_bot_config_value(
        'riskPerTrade',
        raw_risk_per_trade if raw_risk_per_trade is not None else profile_defaults['riskPerTrade'],
        BOT_RISK_LIMITS['riskPerTrade'][0],
        BOT_RISK_LIMITS['riskPerTrade'][1],
        profile_defaults['riskPerTrade'],
        warnings,
    )
    max_daily_loss = _clamp_bot_config_value(
        'maxDailyLoss',
        data.get('maxDailyLoss', profile_defaults['maxDailyLoss']),
        BOT_RISK_LIMITS['maxDailyLoss'][0],
        BOT_RISK_LIMITS['maxDailyLoss'][1],
        profile_defaults['maxDailyLoss'],
        warnings,
    )

    raw_profit_lock = data.get('profitLock', profile_defaults['profitLock'])
    try:
        parsed_profit_lock = float(raw_profit_lock)
    except (TypeError, ValueError):
        parsed_profit_lock = profile_defaults['profitLock']
        warnings.append(f"profitLock defaulted to {profile_defaults['profitLock']}")

    if parsed_profit_lock <= 0:
        profit_lock = 0.0
    else:
        profit_lock = _clamp_bot_config_value(
            'profitLock',
            parsed_profit_lock,
            20.0,
            BOT_RISK_LIMITS['profitLock'][1],
            profile_defaults['profitLock'],
            warnings,
        )

    drawdown_pause_percent = _clamp_bot_config_value(
        'drawdownPausePercent',
        data.get('drawdownPausePercent', data.get('maxDrawdownPercent', profile_defaults['drawdownPausePercent'])),
        BOT_RISK_LIMITS['drawdownPausePercent'][0],
        BOT_RISK_LIMITS['drawdownPausePercent'][1],
        profile_defaults['drawdownPausePercent'],
        warnings,
    )
    drawdown_pause_hours = _clamp_bot_config_value(
        'drawdownPauseHours',
        data.get('drawdownPauseHours', profile_defaults['drawdownPauseHours']),
        BOT_RISK_LIMITS['drawdownPauseHours'][0],
        BOT_RISK_LIMITS['drawdownPauseHours'][1],
        profile_defaults['drawdownPauseHours'],
        warnings,
    )

    max_open_positions = _clamp_int_value(
        'maxOpenPositions',
        data.get('maxOpenPositions', data.get('maxOpenTrades', profile_defaults['maxOpenPositions'])),
        1,
        8,
        profile_defaults['maxOpenPositions'],
        warnings,
    )
    max_positions_per_symbol = _clamp_int_value(
        'maxPositionsPerSymbol',
        data.get('maxPositionsPerSymbol', max_open_positions),
        1,
        max_open_positions,
        min(profile_defaults['maxPositionsPerSymbol'], max_open_positions),
        warnings,
    )
    default_signal_threshold_mode = (
        'manual'
        if management_mode == 'manual' and data.get('signalThreshold') is not None
        else 'auto'
    )
    signal_threshold_mode = str(
        data.get('signalThresholdMode') or default_signal_threshold_mode
    ).strip().lower()
    if signal_threshold_mode not in {'auto', 'manual'}:
        signal_threshold_mode = 'auto'
        warnings.append('signalThresholdMode defaulted to auto')
    if management_mode != 'manual' and signal_threshold_mode != 'auto':
        signal_threshold_mode = 'auto'
        warnings.append('signalThresholdMode forced to auto for assisted management')

    crypto_only_threshold = _crypto_only_signal_threshold(data.get('symbols') or [])

    if signal_threshold_mode == 'manual':
        signal_threshold = _clamp_int_value(
            'signalThreshold',
            data.get('signalThreshold', default_signal_threshold),
            ADAPTIVE_SIGNAL_THRESHOLD_MIN,
            90,
            default_signal_threshold,
            warnings,
        )
    else:
        signal_threshold = int(crypto_only_threshold if crypto_only_threshold is not None else default_signal_threshold)

    allowed_volatility = data.get('allowedVolatility') or profile_defaults['allowedVolatility']
    if not isinstance(allowed_volatility, list):
        allowed_volatility = profile_defaults['allowedVolatility']
        warnings.append('allowedVolatility defaulted to profile setting')
    allowed_volatility = [str(level).title() for level in allowed_volatility if str(level).strip()]
    if not allowed_volatility:
        allowed_volatility = list(profile_defaults['allowedVolatility'])

    auto_switch = _coerce_bool(
        data.get('autoSwitch', intelligent_settings.get('autoSwitch', profile_defaults['autoSwitch'])),
        profile_defaults['autoSwitch'],
    )
    dynamic_sizing = _coerce_bool(
        data.get('dynamicSizing', intelligent_settings.get('dynamicSizing', profile_defaults['dynamicSizing'])),
        profile_defaults['dynamicSizing'],
    )
    intelligent_scanner = _coerce_bool(data.get('intelligentScanner', False), False)
    cadence_defaults = _default_strategy_trading_cadence(
        data.get('strategy', 'Trend Following'),
        management_profile,
        intelligent_scanner,
    )

    trading_mode = str(data.get('tradingMode') or '').strip().lower()
    if trading_mode not in {'interval', 'signal-driven'}:
        trading_mode = cadence_defaults['tradingMode']

    trading_interval = _clamp_int_value(
        'tradingInterval',
        data.get('tradingInterval', cadence_defaults['tradingInterval']),
        30,
        900,
        cadence_defaults['tradingInterval'],
        warnings,
    )
    poll_interval = _clamp_int_value(
        'pollInterval',
        data.get('pollInterval', cadence_defaults['pollInterval']),
        5,
        120,
        cadence_defaults['pollInterval'],
        warnings,
    )

    cadence_floor = _minimum_saved_bot_trade_cadence(
        data.get('strategy', 'Trend Following'),
        management_profile,
        intelligent_scanner,
    )
    if trading_mode != cadence_floor['tradingMode']:
        trading_mode = cadence_floor['tradingMode']
        warnings.append('legacy trading mode migrated to signal-driven cadence')
    if trading_interval > cadence_floor['tradingInterval']:
        trading_interval = cadence_floor['tradingInterval']
        warnings.append(f"tradingInterval migrated to {trading_interval}s for active cadence")
    if poll_interval > cadence_floor['pollInterval']:
        poll_interval = cadence_floor['pollInterval']
        warnings.append(f"pollInterval migrated to {poll_interval}s for active cadence")

    if management_mode == 'assisted':
        max_open_positions = min(max_open_positions, profile_defaults['maxOpenPositions'])
        max_positions_per_symbol = min(max_positions_per_symbol, profile_defaults['maxPositionsPerSymbol'])
        if signal_threshold_mode == 'auto':
            target_threshold = crypto_only_threshold if crypto_only_threshold is not None else default_signal_threshold
            signal_threshold = max(signal_threshold, int(target_threshold))
        allowed_volatility = [level for level in allowed_volatility if level in profile_defaults['allowedVolatility']] or list(profile_defaults['allowedVolatility'])

    display_currency = str(account_currency).upper()  # Use actual account currency (USD, ZAR, etc.)
    scanner_cap_live = _clamp_bot_config_value(
        'scannerCapitalLiveMaxBoost',
        data.get('scannerCapitalLiveMaxBoost', SCANNER_CAPITAL_LIVE_MAX_BOOST),
        1.0,
        SCANNER_CAPITAL_ABSOLUTE_MAX_BOOST,
        SCANNER_CAPITAL_LIVE_MAX_BOOST,
        warnings,
    )
    
    return {
        'riskPerTrade': risk_per_trade,
        'maxDailyLoss': max_daily_loss,
        'profitLock': profit_lock,
        'drawdownPausePercent': drawdown_pause_percent,
        'drawdownPauseHours': drawdown_pause_hours,
        'maxOpenPositions': max_open_positions,
        'maxPositionsPerSymbol': max_positions_per_symbol,
        'signalThreshold': signal_threshold,
        'signalThresholdMode': signal_threshold_mode,
        'allowedVolatility': allowed_volatility,
        'autoSwitch': auto_switch,
        'dynamicSizing': dynamic_sizing,
        'tradingMode': trading_mode,
        'tradingInterval': trading_interval,
        'pollInterval': poll_interval,
        'managementMode': management_mode,
        'managementProfile': management_profile,
        'allowCrossMarketReallocation': _coerce_bool(
            data.get('allowCrossMarketReallocation', intelligent_settings.get('allowCrossMarketReallocation', True)),
            True,
        ),
        'scannerCapitalLiveMaxBoost': scanner_cap_live,
        'displayCurrency': display_currency,
        'warnings': warnings,
    }




def _generate_sample_trades_for_bot(symbols: List[str], trade_count: int = 10):
    """
    Generate sample trades for newly created bots so analytics display data immediately
    
    Returns: (trade_history, daily_profits, total_profit, winning_trades_count)
    """
    import random
    from datetime import timedelta
    
    try:
        trade_history = []
        daily_profits = {}
        now = datetime.now()
        total_profit = 0
        winning_trades = 0
        
        # Generate trades over the last 30 days (exclude today so daily P&L starts clean)
        for i in range(trade_count):
            # Random date within past 30 days (starting from 1 day ago, not today)
            days_ago = random.randint(1, 30)
            trade_time = now - timedelta(days=days_ago)
            date_key = trade_time.strftime('%Y-%m-%d')
            
            # Random profit/loss
            profit = random.uniform(-500, 2500)
            if profit > 0:
                winning_trades += 1
            
            trade = {
                'symbol': random.choice(symbols or ['EURUSDm']),
                'profit': round(profit, 2),
                'type': random.choice(['BUY', 'SELL']),
                'volume': round(random.uniform(0.1, 5.0), 2),
                'time': trade_time.isoformat(),
                'isWinning': profit > 0,
            }
            
            trade_history.append(trade)
            
            # Accumulate daily profits
            if date_key not in daily_profits:
                daily_profits[date_key] = 0.0
            daily_profits[date_key] += profit
            
            total_profit += profit
        
        # Do NOT generate fake profit for today - bot should start with clean daily P&L
        # so it doesn't immediately hit daily loss limits before placing any real trades
        
        return trade_history, daily_profits, round(total_profit, 2), winning_trades
        
    except Exception as e:
        logger.error(f"Error generating sample trades: {e}")
        return [], {}, 0, 0


@app.route('/api/bot/create', methods=['POST'])
@require_session
def create_bot():
    """Create and start a new trading bot for a user
    
    PROPER FLOW:
    1. User integrates broker account (broker_credentials table)
    2. User creates bot linked to that credential_id
    3. Bot trades using verified broker account
    
    Request body:
    {
        "botId": "optional_bot_name",
        "credentialId": "credential_uuid",  // ✅ REQUIRED - from broker integration
        "mode": "demo|live",                // ✅ REQUIRED - must match the credential's is_live mode
        "symbols": ["EURUSD", "XAUUSD"],
        "strategy": "Trend Following",
        "riskPerTrade": 20,
        "maxDailyLoss": 60
    }
    """
    logger.info("🚩 /api/bot/create endpoint called")
    # ==================== BOT CREATION LOCK ====================
    # Only allow ONE bot creation at a time to prevent MT5 lock contention
    # Multiple simultaneous creations cause competing MT5 connection attempts
    global bot_creation_lock
    logger.info("🔒 Waiting for exclusive bot creation lock...")
    
    with bot_creation_lock:
        conn = None
        try:
            data = request.get_json(silent=True)
            if not data:
                return jsonify({'success': False, 'error': 'No configuration provided'}), 400

            user_id = request.user_id  # From @require_session decorator
            if not user_id:
                return jsonify({'success': False, 'error': 'Not authenticated'}), 401

            # Get credential_id from request - REQUIRED
            credential_id = data.get('credentialId')
            if not credential_id:
                return jsonify({'success': False, 'error': 'credentialId required - must setup broker integration first'}), 400

            conn = get_db_connection()
            cursor = conn.cursor()
            cursor.execute('SELECT user_id FROM users WHERE user_id = ?', (user_id,))
            user_row = cursor.fetchone()
            if not user_row:
                return jsonify({'success': False, 'error': 'User not found'}), 404

            cursor.execute('''
                SELECT credential_id, broker_name, account_number, username, is_live, api_key, password, server, is_active,
                       account_currency, cached_balance, cached_margin_free
                FROM broker_credentials
                WHERE credential_id = ? AND user_id = ?
            ''', (credential_id, user_id))
            credential_row = cursor.fetchone()
            if not credential_row:
                return jsonify({'success': False, 'error': f'Broker credential {credential_id} not found or does not belong to this user'}), 404

            if not credential_row['is_active']:
                return jsonify({'success': False, 'error': 'This broker credential has been deactivated. Please use an active credential.'}), 400

            credential_data = dict(credential_row)
            broker_name = credential_data['broker_name']
            account_number = credential_data['account_number']
            is_live = credential_data['is_live']
            mode = 'live' if is_live else 'demo'
            cached_balance = _safe_float(credential_data.get('cached_balance'))
            cached_margin_free = _safe_float(credential_data.get('cached_margin_free'))

            # The request should explicitly state the intended mode to avoid demo/live credential mixups.
            requested_mode = data.get('mode') or data.get('botMode')
            if requested_mode is not None:
                requested_mode = str(requested_mode).strip().lower()
            elif 'is_live' in data:
                requested_mode = 'live' if bool(data.get('is_live')) else 'demo'

            if requested_mode and requested_mode not in ['demo', 'live']:
                return jsonify({'success': False, 'error': 'mode must be either "demo" or "live"'}), 400

            if requested_mode and requested_mode != mode:
                return jsonify({
                    'success': False,
                    'error': f'Credential mode mismatch: credential is {mode} but request mode is {requested_mode}. Use the correct credentialId for demo or live accounts.'
                }), 400

            if not requested_mode:
                requested_mode = mode
                logger.info(f"Bot create request did not specify mode; inferring mode={requested_mode} from credential {credential_id}")

            if canonicalize_broker_name(broker_name) == 'FXCM':
                username = str(credential_data.get('username') or '').strip()
                password = str(credential_data.get('password') or '').strip()
                if not username or not password:
                    return jsonify({
                        'success': False,
                        'error': 'FXCM credential is missing Login ID or password. Reconnect the FXCM account with Login ID + Password before creating a bot.'
                    }), 400

            # Fail fast for Binance credentials so users don't create bots that silently fail at runtime.
            if canonicalize_broker_name(broker_name) == 'Binance':
                try:
                    binance_conn = BinanceConnection(credentials={
                        'api_key': credential_data.get('api_key'),
                        'api_secret': credential_data.get('password'),
                        'account_number': account_number,
                        'server': credential_data.get('server') or 'spot',
                        'is_live': bool(is_live),
                    })
                    if not binance_conn.connect():
                        return jsonify({
                            'success': False,
                            'error': 'Binance credential validation failed. Please re-check API key/secret and account mode.'
                        }), 400
                    binance_conn.disconnect()
                except Exception as e:
                    logger.error(f"Binance credential validation exception: {e}")
                    return jsonify({
                        'success': False,
                        'error': f'Binance credential validation failed with error: {str(e)}. Please re-check API key/secret and account mode.'
                    }), 400

            print(f"✅ Using broker credential: {broker_name} | Account: {account_number} | Mode: {mode}")

            saved_risk_settings = get_user_risk_settings(cursor, user_id)
            merged_bot_data = dict(data)
            if merged_bot_data.get('riskPerTrade') is None and merged_bot_data.get('riskPercent') is None:
                merged_bot_data['riskPercent'] = saved_risk_settings['risk_percent']
            if merged_bot_data.get('maxOpenTrades') is None and merged_bot_data.get('maxOpenPositions') is None:
                merged_bot_data['maxOpenTrades'] = saved_risk_settings['max_open_trades']
            if merged_bot_data.get('maxDrawdownPercent') is None and merged_bot_data.get('drawdownPausePercent') is None:
                merged_bot_data['maxDrawdownPercent'] = saved_risk_settings['max_drawdown_percent']

            # Bot configuration
            import time
            bot_id = data.get('botId') or f"bot_{int(time.time() * 1000)}_{uuid.uuid4().hex[:8]}"
            auto_start = data.get('autoStart', True)  # ✅ ENABLED: Bots start automatically after creation
            if isinstance(auto_start, str):
                auto_start = auto_start.lower() in ['true', '1', 'yes', 'y']
            # Support both 'symbol' (singular) and 'symbols' (plural) in request
            raw_symbols = data.get('symbols') or data.get('symbol')
            if isinstance(raw_symbols, str):
                raw_symbols = [raw_symbols]  # Convert single symbol to list
            if not raw_symbols:
                raw_symbols = ['EURUSDm']  # Default fallback
            symbols = validate_and_correct_symbols(raw_symbols, broker_name)
            if broker_name == 'FXCM':
                # Skip live tradability check at creation time — ForexConnect login is not
                # always available at this point and false-rejects valid symbols.
                # Symbols are validated when the bot actually places trades.
                logger.info(f"[FXCM] Bot creation with {len(symbols)} symbol(s): {symbols}")
            strategy = data.get('strategy', 'Trend Following')
            
            # ✅ GET ACCOUNT CURRENCY from credentials (demo USD vs live ZAR)
            account_currency = credential_data.get('account_currency', 'USD').upper()
            live_balance_basis = max(cached_balance, cached_margin_free)
            effective_data, symbols, guard_warnings, small_account_guard = enforce_small_live_account_guard(
                merged_bot_data,
                symbols,
                broker_name,
                bool(is_live),
                cached_balance,
                cached_margin_free,
                account_currency,
            )
            effective_data, capital_safety_warnings, capital_safety_band = enforce_live_capital_safety_net(
                effective_data,
                bool(is_live),
                live_balance_basis,
                account_currency,
            )
            sanitized_risk_config = sanitize_bot_risk_config(
                effective_data,
                account_currency,
                broker_name,
            )
            if guard_warnings:
                sanitized_risk_config['warnings'] = guard_warnings + sanitized_risk_config.get('warnings', [])
            if capital_safety_warnings:
                sanitized_risk_config['warnings'] = capital_safety_warnings + sanitized_risk_config.get('warnings', [])
            risk_per_trade = sanitized_risk_config['riskPerTrade']
            max_daily_loss = sanitized_risk_config['maxDailyLoss']
            profit_lock = sanitized_risk_config['profitLock']
            drawdown_pause_percent = sanitized_risk_config['drawdownPausePercent']
            drawdown_pause_hours = sanitized_risk_config['drawdownPauseHours']
            max_open_positions = sanitized_risk_config['maxOpenPositions']
            max_positions_per_symbol = sanitized_risk_config['maxPositionsPerSymbol']
            signal_threshold = sanitized_risk_config['signalThreshold']
            allowed_volatility = sanitized_risk_config['allowedVolatility']
            auto_switch = sanitized_risk_config['autoSwitch']
            dynamic_sizing = sanitized_risk_config['dynamicSizing']
            management_mode = sanitized_risk_config['managementMode']
            management_profile = sanitized_risk_config['managementProfile']
            display_currency = sanitized_risk_config['displayCurrency']
            trading_mode = sanitized_risk_config['tradingMode']
            trading_interval = sanitized_risk_config['tradingInterval']
            poll_interval = sanitized_risk_config['pollInterval']
            trading_enabled = data.get('enabled', True)
            auto_adaptation_enabled = _coerce_bool(data.get('autoAdaptationEnabled', True), True)
            selected_preset = str(data.get('selectedPreset') or '').strip() or None
            preset_name = str(data.get('presetName') or '').strip() or None
            trade_amount = data.get('tradeAmount')  # Fixed amount in the broker account currency (overrides risk %)
            if trade_amount is not None:
                try:
                    trade_amount = float(trade_amount)
                    if trade_amount <= 0:
                        trade_amount = None
                except (ValueError, TypeError):
                    trade_amount = None

            binance_market_name = str(
                data.get('binanceMarket')
                or data.get('market')
                or credential_data.get('server')
                or 'spot'
            ).strip().lower()

            if trade_amount is None and canonicalize_broker_name(broker_name) == 'Binance':
                balance_basis = max(_safe_float(cached_balance), _safe_float(cached_margin_free))
                trade_amount = derive_binance_default_trade_amount(
                    balance_basis,
                    display_currency or credential_data.get('account_currency'),
                    binance_market_name,
                    max_open_positions,
                    bool(is_live),
                )
                if trade_amount is not None:
                    sanitized_risk_config.setdefault('warnings', []).append(
                        f"Binance default tradeAmount set to {trade_amount:.2f} {display_currency or credential_data.get('account_currency') or 'USD'} for stronger position sizing"
                    )

            # Guard custom fixed sizing against oversized entries on small balances.
            if trade_amount is not None:
                balance_basis = max(_safe_float(cached_balance), _safe_float(cached_margin_free))
                scanner_enabled = bool(effective_data.get('intelligentScanner', False))
                if balance_basis > 0:
                    balance_basis_zar = _estimate_balance_in_zar(balance_basis, account_currency)
                    cap_ratio = _get_fixed_trade_amount_cap_ratio(balance_basis_zar, scanner_enabled, bool(is_live))
                    capped_trade_amount = round(max(1.0, balance_basis * cap_ratio), 2)
                    if trade_amount > capped_trade_amount:
                        trade_amount = capped_trade_amount
                        sanitized_risk_config.setdefault('warnings', []).append(
                            f"tradeAmount capped to {capped_trade_amount:.2f} {account_currency} "
                            f"({cap_ratio * 100:.2f}% of live balance) for risk safety"
                        )

            account_id = f"{broker_name}_{account_number}"
            created_at = datetime.now().isoformat()

            # Set bot status
            status = 'active'

            try:
                cursor.execute('SELECT bot_id FROM user_bots WHERE bot_id = ?', (bot_id,))
                if cursor.fetchone():
                    logger.warning(f"Bot ID {bot_id} already exists, regenerating...")
                    bot_id = f"bot_{int(time.time() * 1000) + 1}_{uuid.uuid4().hex[:8]}"

                logger.info(f"🔧 [BOT INSERT] Inserting bot {bot_id} for user {user_id} into user_bots table...")
                cursor.execute('''
                    INSERT INTO user_bots (bot_id, user_id, name, strategy, status, enabled, broker_account_id, symbols, is_live, created_at, updated_at)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                ''', (bot_id, user_id, data.get('name', strategy), strategy, status, 1 if trading_enabled else 0, account_id, ','.join(symbols), 1 if is_live else 0, created_at, created_at))
                logger.info(f"✅ [BOT INSERT SUCCESS] user_bots row inserted")

                logger.info(f"🔧 [CREDENTIALS INSERT] Inserting bot credentials...")
                cursor.execute('''
                    INSERT INTO bot_credentials (bot_id, credential_id, user_id, created_at)
                    VALUES (?, ?, ?, ?)
                ''', (bot_id, credential_id, user_id, created_at))
                logger.info(f"✅ [CREDENTIALS INSERT SUCCESS] bot_credentials row inserted")

                logger.info(f"🔧 [DB COMMIT] Committing transaction...")
                conn.commit()
                logger.info(f"✅ [DB COMMIT SUCCESS] Transaction committed to database")
            except Exception as e:
                logger.error(f"❌ [DB ERROR] Exception during bot creation: {type(e).__name__}: {str(e)}")
                if 'UNIQUE constraint' in str(e):
                    logger.error("Bot creation failed - duplicate ID. Retrying with new ID...")
                    bot_id = f"bot_{int(time.time() * 1000000)}_{uuid.uuid4().hex[:6]}"
                    try:
                        cursor.execute('''
                            INSERT INTO user_bots (bot_id, user_id, name, strategy, status, enabled, broker_account_id, symbols, is_live, created_at, updated_at)
                            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                        ''', (bot_id, user_id, data.get('name', strategy), strategy, status, 1 if trading_enabled else 0, account_id, ','.join(symbols), 1 if is_live else 0, created_at, created_at))
                        cursor.execute('''
                            INSERT INTO bot_credentials (bot_id, credential_id, user_id, created_at)
                            VALUES (?, ?, ?, ?)
                        ''', (bot_id, credential_id, user_id, created_at))
                        conn.commit()
                        logger.info(f"✅ [RETRY SUCCESS] Bot retry successful with new ID: {bot_id}")
                    except Exception as retry_e:
                        logger.error(f"❌ [RETRY FAILED] Retry also failed: {type(retry_e).__name__}: {str(retry_e)}")
                        raise
                else:
                    raise

            now = datetime.now()
            # Start with clean stats — no fake sample trades that pollute analytics
            # Real trades will be recorded as the bot executes

            active_bots[bot_id] = {
                'botId': bot_id,
                'user_id': user_id,
                'accountId': account_id,
                'brokerName': broker_name,
                'broker_type': broker_name,
                'accountNumber': account_number,
                'account_number': account_number,
                'mode': mode,
                'credentialId': credential_id,
                'symbols': symbols,
                'strategy': strategy,
                'riskPerTrade': risk_per_trade,
                'maxDailyLoss': max_daily_loss,
                'profitLock': profit_lock,
                'drawdownPausePercent': drawdown_pause_percent,
                'drawdownPauseHours': drawdown_pause_hours,
                'signalThreshold': signal_threshold,
                'signalThresholdMode': sanitized_risk_config['signalThresholdMode'],
                'allowedVolatility': allowed_volatility,
                'autoSwitch': auto_switch,
                'dynamicSizing': dynamic_sizing,
                'managementMode': management_mode,
                'managementProfile': management_profile,
                'tradingMode': trading_mode,
                'tradingInterval': trading_interval,
                'pollInterval': poll_interval,
                'managementState': 'normal',
                'smallAccountGuard': small_account_guard,
                'capitalSafetyBand': capital_safety_band,
                'displayCurrency': display_currency,
                'enabled': trading_enabled,
                'selectedPreset': selected_preset,
                'presetName': preset_name,
                'autoAdaptationEnabled': auto_adaptation_enabled,
                'lastAdaptationAt': None,
                'lastAdaptationReason': None,
                'promotionReadyAt': None,
                'promotionExpiredAt': None,
                'tradeAmount': trade_amount,  # Fixed dollar amount per trade (None = use risk %)
                'binanceMarket': binance_market_name,
                'market': binance_market_name,
                'intelligentScanner': bool(effective_data.get('intelligentScanner', False)),  # Auto-scan all symbols & reallocate
                'profitProtection': _normalize_profit_protection_config(data.get('profitProtection')),
                'maxOpenPositions': max_open_positions,
                'maxPositionsPerSymbol': max_positions_per_symbol,
                'basePositionSize': data.get('basePositionSize', 1.0),
                'scannerCapitalLiveMaxBoost': sanitized_risk_config.get('scannerCapitalLiveMaxBoost', SCANNER_CAPITAL_LIVE_MAX_BOOST),
                'totalTrades': 0,
                'winningTrades': 0,
                'totalProfit': 0,
                'totalLosses': 0,
                'totalInvestment': 0,
                'createdAt': now.isoformat(),
                'startTime': now.isoformat(),
                'profitHistory': [],
                'tradeHistory': [],
                'dailyProfits': {},
                'dailyProfit': 0,
                'maxDrawdown': 0,
                'peakProfit': 0,
                'drawdownPauseUntil': None,
                'profit': 0,
                'open_positions': {},  # Track open positions for closure detection
            }
            # Force immediate persistence so bot settings survive restarts
            # even before the periodic runtime-state debounce cycle.
            persist_bot_runtime_state(bot_id, force=True)

            logger.info(f"✅ Created bot {bot_id} for user {user_id}")
            logger.info(f"   Broker: {broker_name} | Account: {account_number} | Mode: {mode}")

            if auto_start:
                running_bots[bot_id] = True
                bot_stop_flags[bot_id] = False

                # ==================== WORKER POOL DISPATCH ====================
                if worker_pool_manager and worker_pool_manager.enabled and is_mt5_broker_name(broker_name):
                    # Dispatch to a worker subprocess instead of local thread
                    _worker_creds = None
                    if credential_id:
                        try:
                            _wc_conn = get_db_connection()
                            _wc_cursor = _wc_conn.cursor()
                            _wc_cursor.execute('SELECT account_number, password, server FROM broker_credentials WHERE credential_id = ? AND user_id = ?', (credential_id, user_id))
                            _wc_row = _wc_cursor.fetchone()
                            _wc_conn.close()
                            if _wc_row:
                                _wc_row = decrypt_credential_row(_wc_row)
                                _worker_creds = normalize_mt5_bot_credentials({
                                    'account': _wc_row['account_number'] or account_number,
                                    'account_number': _wc_row['account_number'] or account_number,
                                    'password': _wc_row['password'],
                                    'server': _wc_row['server'],
                                    'is_live': bool(is_live),
                                    'broker': broker_name,
                                    'credential_id': credential_id,
                                })
                        except Exception as e:
                            logger.warning(f'Worker dispatch: could not fetch credentials: {e}')
                    worker_pool_manager.dispatch_bot(bot_id, user_id, active_bots[bot_id], _worker_creds)
                    logger.info(f"🚀 Bot {bot_id}: Dispatched to worker pool")
                else:
                    # Legacy single-process mode
                    def _async_start_bot():
                        """Start bot in background without blocking the API response"""
                        try:
                            time.sleep(0.5)

                            bot_credentials = None
                            if credential_id:
                                conn_local = None
                                try:
                                    conn_local = get_db_connection()
                                    cursor_local = conn_local.cursor()
                                    cursor_local.execute('''
                                        SELECT api_key, password, server, account_number
                                        FROM broker_credentials
                                        WHERE credential_id = ? AND user_id = ?
                                    ''', (credential_id, user_id))
                                    cred_row = cursor_local.fetchone()

                                    if cred_row:
                                        if canonicalize_broker_name(broker_name) == 'Binance':
                                            bot_credentials = {
                                                'api_key': cred_row['api_key'],
                                                'api_secret': cred_row['password'],
                                                'server': cred_row['server'] or 'spot',
                                                'is_live': bool(is_live),
                                            }
                                        else:
                                            bot_credentials = normalize_mt5_bot_credentials({
                                                'account': cred_row['account_number'] or account_number,
                                                'account_number': cred_row['account_number'] or account_number,
                                                'password': cred_row['password'],
                                                'server': cred_row['server'],
                                                'is_live': bool(is_live),
                                                'broker': broker_name,
                                                'credential_id': credential_id,
                                            })
                                except Exception as e:
                                    logger.warning(f'Could not fetch broker credentials for bot startup: {e}')
                                finally:
                                    if conn_local:
                                        conn_local.close()

                            if bot_id not in bot_threads or not bot_threads[bot_id].is_alive():
                                bot_thread = threading.Thread(
                                    target=continuous_bot_trading_loop,
                                    args=(bot_id, user_id, bot_credentials),
                                    daemon=True,
                                    name=f"BotThread-{bot_id}"
                                )
                                bot_threads[bot_id] = bot_thread
                                bot_thread.start()
                                logger.info(f"🚀 Bot {bot_id}: Background thread launched (async start)")
                        except Exception as e:
                            logger.error(f"Error in async bot start: {e}")

                    startup_thread = threading.Thread(target=_async_start_bot, daemon=True)
                    startup_thread.start()
            else:
                running_bots[bot_id] = False
                bot_stop_flags[bot_id] = False
                logger.info(f"⏸️ Bot {bot_id} created without starting - call /api/bot/start to begin trading")

            account_balance = cached_balance if cached_balance > 0 else 10000.0
            auto_withdrawal_status = None
            try:
                if canonicalize_broker_name(broker_name) == 'Binance':
                    binance_conn_balance = BinanceConnection(credentials={
                        'api_key': credential_data.get('api_key'),
                        'api_secret': credential_data.get('password'),
                        'account_number': account_number,
                        'server': credential_data.get('server') or 'spot',
                        'is_live': bool(is_live),
                    })
                    if binance_conn_balance.connect():
                        acct_info = binance_conn_balance.get_account_info()
                        if acct_info and 'balance' in acct_info:
                            account_balance = acct_info['balance']
                        binance_conn_balance.disconnect()
                elif is_mt5_broker_name(broker_name):
                    cached_connection_id = None
                    normalized_broker_name = canonicalize_broker_name(broker_name)

                    if normalized_broker_name == 'Exness':
                        cached_connection_id = 'Exness MT5'
                    elif normalized_broker_name in ['XM', 'XM Global']:
                        cached_connection_id = 'XM Global MT5'
                    elif normalized_broker_name == 'PXBT':
                        cached_connection_id = 'PXBT MT5'

                    cached_connection = broker_manager.connections.get(cached_connection_id) if cached_connection_id else None
                    if cached_connection and cached_connection.connected:
                        acct_info = cached_connection.account_info or cached_connection.get_account_info()
                        if acct_info and str(acct_info.get('accountNumber', '')) == str(account_number):
                            account_balance = acct_info.get('balance', account_balance)
                            logger.info(f"💰 Got cached balance for bot creation: ${account_balance}")
                        else:
                            logger.info(f"⚠️ Cached MT5 is for different account - balance will update after bot connects")
                    else:
                        logger.info(f"⚠️ No cached MT5 connection - balance will update after bot connects")

                active_bots[bot_id]['accountBalance'] = account_balance
                active_bots[bot_id]['accountEquity'] = account_balance

                auto_withdrawal_config = data.get('autoWithdrawal')
                if isinstance(auto_withdrawal_config, dict) and _coerce_bool(auto_withdrawal_config.get('enabled', False), False):
                    try:
                        auto_withdrawal_status = upsert_auto_withdrawal_settings(
                            cursor,
                            bot_id,
                            user_id,
                            auto_withdrawal_config,
                            bot_config=active_bots[bot_id],
                        )
                        conn.commit()
                    except Exception as auto_withdrawal_error:
                        logger.error(f"Auto-withdrawal setup failed for bot {bot_id}: {auto_withdrawal_error}")

                persist_bot_runtime_state(bot_id)
            except Exception as e:
                logger.info(f"⚠️  Could not fetch balance during bot creation: {e} - using default 10000.0")

            return jsonify({
                'success': True,
                'botId': bot_id,
                'user_id': user_id or '',
                'credentialId': credential_id or '',
                'accountId': account_id or '',
                'broker': broker_name or 'Unknown',
                'account_number': account_number or '',
                'balance': round(account_balance, 2),
                'mode': mode or 'demo',
                'displayCurrency': display_currency or 'USD',
                'smallAccountGuard': small_account_guard,
                'capitalSafetyBand': capital_safety_band,
                'tradeAmount': trade_amount,
                'autoWithdrawalConfigured': bool(auto_withdrawal_status),
                'appliedRiskConfig': {
                    'riskPerTrade': risk_per_trade or 20.0,
                    'maxDailyLoss': max_daily_loss or 60.0,
                    'profitLock': profit_lock or 80.0,
                    'drawdownPausePercent': drawdown_pause_percent or 0.0,
                    'drawdownPauseHours': drawdown_pause_hours or 6.0,
                },
                'appliedManagementConfig': {
                    'managementMode': management_mode,
                    'managementProfile': management_profile,
                    'maxOpenPositions': max_open_positions,
                    'maxPositionsPerSymbol': max_positions_per_symbol,
                    'signalThreshold': signal_threshold,
                    'signalThresholdMode': sanitized_risk_config['signalThresholdMode'],
                    'tradingMode': trading_mode,
                    'tradingInterval': trading_interval,
                    'pollInterval': poll_interval,
                    'allowedVolatility': allowed_volatility,
                    'autoSwitch': auto_switch,
                    'dynamicSizing': dynamic_sizing,
                },
                'warnings': (sanitized_risk_config or {}).get('warnings', []),
                'message': ('Bot ' + bot_id + ' created ' + ('and starting...' if auto_start else 'and waiting to be started')), 
                'status': 'STARTING' if auto_start else 'INACTIVE'
            }), 201
        except Exception as e:
            logger.error(f"Error creating bot: {e}")
            return jsonify({'success': False, 'error': str(e)}), 500
        finally:
            if conn:
                conn.close()


# ==================== CONTINUOUS BOT TRADING LOOP ====================

def evaluate_trade_signal_strength(symbol: str, strategy_params: Dict) -> float:
    """
    Evaluate how strong a profit signal is (0-100 scale)
    
    Returns: Signal strength score
    - 0-30: Weak signal, don't trade
    - 30-60: Medium signal, hold for better opportunity  
    - 60-85: Strong signal, good time to trade
    - 85-100: Very strong signal, excellent trade setup
    """
    try:
        # Get live price data
        if symbol not in commodity_market_data:
            return 0
        
        market_data = commodity_market_data[symbol]
        signal = market_data.get('signal', '')
        
        # Base score from signal type (from technical analysis)
        if 'STRONG BUY' in signal or 'STRONG SELL' in signal:
            base_score = 85
        elif 'BUY' in signal or 'SELL' in signal:
            base_score = 65
        elif 'CONSOLIDATING' in signal or 'WEAK BUY' in signal:
            base_score = 40
        else:
            base_score = 20
        
        # Adjust for volatility (high volatility = higher risk but higher reward)
        volatility = market_data.get('volatility_pct', 1.0)
        if volatility > 3:  # High volatility
            base_score *= 1.1
        elif volatility < 0.5:  # Very low volatility
            base_score *= 0.9
        
        # Cap at 100
        return min(100, max(0, base_score))
    except:
        return 0


def continuous_bot_trading_loop(bot_id: str, user_id: str, bot_credentials: Dict = None):
    """
    Continuously execute trading for a bot until stop is requested
    
    Supports TWO MODES:
    1. TIME-BASED (default): Execute trades every N seconds (5 min default)
    2. SIGNAL-DRIVEN (new): Execute trades IMMEDIATELY when profit signal detected
       - Checks signals frequently (every 10-30 seconds)
       - Executes when signal strength exceeds threshold
       - Much faster response to market opportunities
    
    This function runs in a background thread and:
    1. Executes trades based on mode (time or signal)
    2. Updates bot stats after each trade cycle
    3. Manages position sizing and risk
    4. Stops when bot_stop_flags[bot_id] is set to True
    """
    try:
        logger.info(f"🤖 Bot {bot_id}: CONTINUOUS TRADING LOOP STARTED (user {user_id})")
        
        bot_config = active_bots.get(bot_id)
        if not bot_config:
            logger.error(f"Bot {bot_id} not found in active_bots")
            return
        
        # ✅ DEFENSIVE FIX: Load bot_credentials from bot_config if not passed in
        if not bot_credentials:
            # Try to extract credentials from bot_config (set during start_bot)
            credential_id = bot_config.get('credentialId')
            if credential_id:
                try:
                    conn = get_db_connection()
                    cursor = conn.cursor()
                    cursor.execute('SELECT * FROM broker_credentials WHERE credential_id = ? AND user_id = ?', (credential_id, user_id))
                    cred_row = cursor.fetchone()
                    conn.close()
                    
                    if cred_row:
                        cred_dict = decrypt_credential_row(cred_row)
                        resolved_broker_name = canonicalize_broker_name(cred_dict.get('broker_name', 'Exness'))
                        if resolved_broker_name == 'Binance':
                            resolved_market = _resolve_binance_market_for_context(
                                credential_row=cred_dict,
                                bot_id=bot_id,
                                bot_config=bot_config,
                            )
                            bot_credentials = {
                                'api_key': cred_dict.get('api_key', ''),
                                'api_secret': cred_dict.get('password', ''),
                                'account_number': cred_dict.get('account_number', ''),
                                'server': resolved_market,
                                'market': resolved_market,
                                'broker': resolved_broker_name,
                                'is_live': bool(cred_dict.get('is_live', False)),
                            }
                        else:
                            bot_credentials = {
                                'account': cred_dict.get('account_number', ''),
                                'password': cred_dict.get('password', ''),
                                'server': cred_dict.get('server', 'Exness-MT5Real27'),
                                'broker': resolved_broker_name,
                                'is_live': bool(cred_dict.get('is_live', False))
                            }
                        logger.info(f"📌 Bot {bot_id}: Loaded credentials from database (credential_id={credential_id})")
                    else:
                        logger.warning(f"⚠️  Bot {bot_id}: Credential {credential_id} not found in database")
                        bot_credentials = {}
                except Exception as e:
                    logger.warning(f"⚠️  Bot {bot_id}: Could not load credentials: {e}")
                    bot_credentials = {}
            else:
                logger.warning(f"⚠️  Bot {bot_id}: No credentialId found in bot_config")
                bot_credentials = {}
        
        # Ensure bot_credentials is never None
        if not bot_credentials:
            bot_credentials = {
                'account': '',
                'password': '',
                'server': 'Exness-MT5Real27',
                'broker': 'Exness',
                'is_live': False
            }

        bot_credentials = normalize_mt5_bot_credentials(bot_credentials, bot_config)
        normalized_broker = canonicalize_broker_name(
            bot_config.get('broker_type')
            or bot_config.get('brokerName')
            or bot_credentials.get('broker')
            or 'Exness'
        )
        normalized_symbols = validate_and_correct_symbols(bot_config.get('symbols', ['EURUSDm']), normalized_broker)
        if normalized_symbols != bot_config.get('symbols', []):
            logger.info(f"🔄 Bot {bot_id}: Normalized symbols for {normalized_broker}: {bot_config.get('symbols')} -> {normalized_symbols}")
            _persist_normalized_bot_symbols(bot_id, bot_config, normalized_symbols)
        
        # Get trading mode configuration
        # Defaults aligned to fast cadence: signal-driven mode + 90s cycle (was 'interval'/300s)
        trading_mode = bot_config.get('tradingMode') or 'signal-driven'
        trading_interval = int(bot_config.get('tradingInterval') or 90)  # Default 90s (was 300s)
        runtime_signal_floor = _adaptive_signal_threshold_floor(bot_config)
        configured_signal_threshold = int(bot_config.get('signalThreshold', runtime_signal_floor) or runtime_signal_floor)
        crypto_only_threshold = _crypto_only_signal_threshold(bot_config.get('symbols') or [])
        # MANUAL MODE GUARD: when user pinned signalThresholdMode='manual', do NOT clamp
        # the configured threshold down via crypto-only floor or runtime floor.
        _threshold_mode_manual = str(bot_config.get('signalThresholdMode') or '').strip().lower() == 'manual'
        if normalized_broker == 'Binance' and crypto_only_threshold is not None and not _threshold_mode_manual:
            configured_signal_threshold = min(configured_signal_threshold, crypto_only_threshold)
        if _threshold_mode_manual:
            signal_threshold = max(1, int(bot_config.get('signalThreshold') or 50))
        else:
            signal_threshold = max(configured_signal_threshold, runtime_signal_floor)    # 0-100, minimum signal strength
        poll_interval = bot_config.get('pollInterval', 15)          # Check signals every N seconds in signal-driven mode
        
        if trading_mode == 'signal-driven':
            logger.info(f"Bot {bot_id}: ⚡ SIGNAL-DRIVEN MODE enabled")
            logger.info(f"   - Signal Threshold: {signal_threshold}/100 (trades execute when signal >= this)")
            logger.info(f"   - Poll Interval: {poll_interval} seconds (check signals this often)")
            logger.info(f"   - Will execute IMMEDIATELY when profit signal detected (no waiting!)")
        else:
            logger.debug(f"Bot {bot_id}: ⏱️ TIME-BASED MODE - trades every {trading_interval}s ({trading_interval/60:.1f} min)")
        
        # Initialize stop flag if not exists
        if bot_id not in bot_stop_flags:
            bot_stop_flags[bot_id] = False
        
        running_bots[bot_id] = True
        trade_cycle = 0
        mt5_ready_timeout = 30  # OPTIMIZED: Reduced from 120 to 30 seconds - MT5 usually ready in 5-15s
        consecutive_connection_failures = 0  # Auto-stop bot after repeated broker disconnects
        MAX_BROKER_DISCONNECT_FAILURES = 5   # Stop bot after 5 consecutive failed connections
        
        # ==================== MARKET HOURS CONFIG ====================
        # Define market hours for different symbol groups (UTC time)
        # ✅ FIXED: FOREX trades 24/5 (Sun evening to Fri evening) - allow all weekday+weekend trading in demo
        market_hours = {
            'FOREX': {'open': (0, 0), 'close': (24, 0), 'days': [0, 1, 2, 3, 4, 5, 6]},  # ✅ Open all days for demo - forex actually trades Sun 21:00 UTC to Fri 21:00 UTC
            'CRYPTO': {'open': (0, 0), 'close': (24, 0), 'days': [0, 1, 2, 3, 4, 5, 6]},  # 24/7
            'INDICES': {'open': (8, 0), 'close': (22, 0), 'days': [0, 1, 2, 3, 4]},  # Mon-Fri only
            'COMMODITIES': {'open': (1, 0), 'close': (23, 59), 'days': [0, 1, 2, 3, 4, 5, 6]},  # ✅ Open all days - gold/commodities trade extended hours
            'STOCKS': {'open': (13, 30), 'close': (20, 0), 'days': [0, 1, 2, 3, 4]},  # US stocks: 9:30 AM - 4:00 PM ET = Mon-Fri only
        }
        
        # Known US stock symbols on Exness (end with 'm' suffix)
        STOCK_SYMBOLS = {'AAPL', 'AMD', 'MSFT', 'NVDA', 'JPM', 'BAC', 'WFC', 'GOOGL', 'META', 'ORCL', 'TSM',
                         'AAPLM', 'AMDM', 'MSFTM', 'NVDAM', 'JPMM', 'BACM', 'WFCM', 'GOOGLM', 'METAM', 'ORCLM', 'TSMM'}
        
        def get_symbol_category(symbol):
            """Determine symbol category from its name"""
            symbol_upper = symbol.upper()
            # Check commodities FIRST (XAU/XAG contain USD but are commodities, not forex)
            if any(com in symbol_upper for com in ['XAU', 'XAG', 'OIL', 'GAS', 'WHEAT', 'GOLD', 'SILVER']):
                return 'COMMODITIES'
            elif any(crypto in symbol_upper for crypto in ['BTC', 'ETH', 'XRP', 'USDT']):
                return 'CRYPTO'
            elif any(idx in symbol_upper for idx in ['SPX', 'NDX', 'TECH', 'DOW', 'USTEC']):
                return 'INDICES'
            elif symbol_upper in STOCK_SYMBOLS:
                return 'STOCKS'
            elif any(pair in symbol_upper for pair in ['EUR', 'GBP', 'USD', 'JPY', 'CHF']):
                return 'FOREX'
            return 'STOCKS'  # Default to STOCKS (safer - has restricted hours)
        
        def is_market_open_for_symbol(symbol, mt5_conn=None):
            """Check if market is open for the given symbol"""
            try:
                # ==================== CRYPTO 24/7 OVERRIDE ====================
                # Crypto symbols (BTC, ETH, etc) trade 24/7 - bypass day-of-week check
                symbol_upper = symbol.upper()
                logger.info(f"[MARKET] Checking symbol: {symbol} -> {symbol_upper}")
                if any(crypto in symbol_upper for crypto in ['BTC', 'ETH', 'XRP', 'USDT']):
                    logger.info(f"✅ CRYPTO 24/7: {symbol} allowed to trade on weekends/weekdays")
                    return True, f"Market OPEN for {symbol} (crypto trades 24/7)"
                
                symbol_cat = get_symbol_category(symbol)
                category_hours = market_hours.get(symbol_cat, market_hours['FOREX'])
                
                now_utc = datetime.utcnow()
                current_day = now_utc.weekday()  # 0=Monday, 6=Sunday
                current_time = (now_utc.hour, now_utc.minute)
                
                # Check if today is a trading day
                if current_day not in category_hours['days']:
                    return False, f"Market closed (day {current_day} not in trading days)"
                
                open_time = category_hours['open']
                close_time = category_hours['close']
                
                # Convert times to minutes for easier comparison
                current_mins = current_time[0] * 60 + current_time[1]
                open_mins = open_time[0] * 60 + open_time[1]
                close_mins = close_time[0] * 60 + close_time[1]
                
                if open_mins <= current_mins < close_mins:
                    return True, f"Market OPEN for {symbol_cat}"
                else:
                    return False, f"Market closed - {symbol_cat} trading hours: {open_time[0]:02d}:{open_time[1]:02d}-{close_time[0]:02d}:{close_time[1]:02d} UTC"
            except Exception as e:
                logger.warning(f"Could not determine market hours: {e} - allowing trade")
                return True, "Unknown market status"
        
        while not bot_stop_flags.get(bot_id, False):
            try:
                trade_cycle += 1
                logger.info(f"🔄 Bot {bot_id}: Trade cycle #{trade_cycle} starting at {datetime.now().isoformat()}")
                
                # ==================== CHECK MARKET HOURS ====================
                # Only pause the entire bot if every configured symbol is closed.
                symbols_list = bot_config.get('symbols', ['EURUSDm'])
                logger.info(f"[BOT {bot_id}] symbols_list from config: {symbols_list}")
                market_status_by_symbol = {}
                open_symbols_for_cycle = []
                for configured_symbol in symbols_list or ['EURUSDm']:
                    is_open, market_status = is_market_open_for_symbol(configured_symbol)
                    market_status_by_symbol[configured_symbol] = (is_open, market_status)
                    if is_open:
                        open_symbols_for_cycle.append(configured_symbol)

                if not open_symbols_for_cycle:
                    first_symbol = (symbols_list or ['EURUSDm'])[0]
                    first_status = market_status_by_symbol.get(first_symbol, (False, 'Market closed'))[1]
                    logger.info(f"⏸️  Bot {bot_id}: {first_status} - all configured symbols are currently closed")
                    logger.info(f"   ⏰ Next check in {trading_interval} seconds")
                    time.sleep(trading_interval)
                    continue

                if trade_cycle == 1:
                    try:
                        previous_daily_profit = _safe_float(bot_config.get('dailyProfit'), 0.0)
                        previous_daily_profits = dict(bot_config.get('dailyProfits') or {}) if isinstance(bot_config.get('dailyProfits'), dict) else {}
                        _merge_bot_trade_history_from_db(bot_config, bot_id)
                        _rebuild_bot_profit_tracking(bot_config)
                        refreshed_daily_profit = _safe_float(bot_config.get('dailyProfit'), 0.0)
                        if previous_daily_profit != refreshed_daily_profit or previous_daily_profits != (bot_config.get('dailyProfits') or {}):
                            logger.info(
                                f"📊 Bot {bot_id}: Rebuilt daily PnL from persisted trade history on startup "
                                f"(${previous_daily_profit:.2f} -> ${refreshed_daily_profit:.2f})"
                            )
                    except Exception as startup_profit_sync_error:
                        logger.warning(f"Bot {bot_id}: Could not refresh startup daily PnL state: {startup_profit_sync_error}")

                bot_mode = str(bot_config.get('mode') or ('live' if bot_credentials.get('is_live') else 'demo')).lower()
                current_user_mode = get_user_trading_mode_value(user_id, fallback_mode=bot_mode).lower()
                if bot_mode != current_user_mode:
                    logger.info(
                        f"⏸️ Bot {bot_id}: Idle because bot mode is {bot_mode.upper()} while user trading mode is {current_user_mode.upper()}"
                    )
                    time.sleep(min(trading_interval, 60))
                    continue
                
                # Detect broker type
                broker_type = bot_config.get('broker_type', 'MT5')
                is_ig = broker_type == 'IG Markets'
                is_fxcm = broker_type in ['FXCM', 'fxcm', 'FXM']
                is_mt5 = broker_type in ['MetaTrader 5', 'MetaQuotes', 'XM Global', 'XM', 'Exness', 'PXBT', 'MT5']
                
                mt5_conn = None
                ig_conn = None
                fxcm_conn = None
                active_conn = None
                use_rest_trading = False  # True when MetaAPI REST is used instead of local MT5
                
                if is_fxcm:
                    # FXCM broker - use REST API via FXCMConnection
                    try:
                        fxcm_conn = bot_config.get('broker_conn')
                        if fxcm_conn is None or not getattr(fxcm_conn, 'connected', False):
                            credential_id = bot_config.get('credentialId')
                            if credential_id:
                                broker_type_new, new_conn = get_broker_connection(credential_id, user_id, bot_id)
                                if broker_type_new == 'FXCM' and hasattr(new_conn, 'connected') and new_conn.connected:
                                    fxcm_conn = new_conn
                                    bot_config['broker_conn'] = fxcm_conn
                                else:
                                    logger.error(f"Bot {bot_id}: FXCM reconnection failed")
                                    time.sleep(trading_interval)
                                    continue
                            else:
                                # Fallback: use global FXCM connection
                                fxcm_conn = FXCMConnection(credentials={
                                    'api_key': FXCM_CONFIG.get('token', ''),
                                    'username': FXCM_CONFIG['login'],
                                    'password': FXCM_CONFIG['password'],
                                    'account_number': FXCM_CONFIG['login'],
                                    'server': FXCM_CONFIG['server'],
                                    'is_live': FXCM_CONFIG['is_live'],
                                    'connection': 'Real' if FXCM_CONFIG['is_live'] else 'Demo',
                                })
                                if not fxcm_conn.connect():
                                    logger.error(f"Bot {bot_id}: FXCM fallback connection failed: {fxcm_conn.last_error}")
                                    time.sleep(trading_interval)
                                    continue
                                bot_config['broker_conn'] = fxcm_conn
                        logger.info(f"Bot {bot_id}: Connected to FXCM for trading")
                        active_conn = fxcm_conn
                    except Exception as e:
                        logger.error(f"Bot {bot_id}: FXCM connection exception: {e}")
                        time.sleep(trading_interval)
                        continue
                elif is_ig:
                    # IG Markets broker - use REST API via IGConnection
                    try:
                        ig_conn = bot_config.get('broker_conn')
                        if ig_conn is None or not ig_conn.connected:
                            # Re-establish IG connection
                            credential_id = bot_config.get('credentialId')
                            if credential_id:
                                broker_type_new, new_conn = get_broker_connection(credential_id, user_id, bot_id)
                                if False and broker_type_new == 'IG Markets' and hasattr(new_conn, 'connected'):  # IG Markets integration removed
                                    ig_conn = new_conn
                                    bot_config['broker_conn'] = ig_conn
                                else:
                                    logger.error(f"Bot {bot_id}: IG reconnection failed: {new_conn}")
                                    time.sleep(trading_interval)
                                    continue
                            else:
                                logger.error(f"Bot {bot_id}: No credentialId for IG reconnection")
                                time.sleep(trading_interval)
                                continue
                        logger.info(f"Bot {bot_id}: Connected to IG Markets for trading")
                        active_conn = ig_conn
                    except Exception as e:
                        logger.error(f"Bot {bot_id}: IG connection exception: {e}")
                        time.sleep(trading_interval)
                        continue
                elif is_mt5:
                    # MT5 broker - connect via terminal SDK or REST API (MetaAPI)
                    try:
                        # ==================== REST/SOCKET TRADING FAST PATH ====================
                        # Socket bridge or MetaAPI cloud for supported brokers → saves ~300MB RAM per account
                        if trade_router and not use_rest_trading:
                            # ✅ DEFENSIVE: Ensure bot_credentials is dict, never None
                            if not isinstance(bot_credentials, dict):
                                logger.warning(f"⚠️  Bot {bot_id}: bot_credentials is {type(bot_credentials).__name__}, expected dict - using empty dict")
                                bot_credentials = {}
                            
                            _broker_for_route = bot_config.get('broker_type', 'MT5')
                            _account_for_route = bot_credentials.get('account', '')
                            _exec_mode = trade_router.determine_mode(_broker_for_route, _account_for_route)
                            if _exec_mode in (ExecutionMode.SOCKET, ExecutionMode.METAAPI):
                                try:
                                    _acct_exec = trade_router.get_or_create_execution(
                                        broker=_broker_for_route,
                                        account_number=_account_for_route,
                                        password=bot_credentials.get('password', ''),
                                        server=bot_credentials.get('server', ''),
                                        is_live=bool(normalize_mt5_is_live_flag(_broker_for_route, bot_credentials.get('is_live'), bot_credentials.get('server', ''))),
                                        user_id=user_id,
                                    )
                                    if _acct_exec.connection and _acct_exec.mode in (ExecutionMode.SOCKET, ExecutionMode.METAAPI):
                                        mt5_conn = _acct_exec.connection
                                        active_conn = mt5_conn
                                        use_rest_trading = True
                                        _mode_label = 'Socket Bridge' if _acct_exec.mode == ExecutionMode.SOCKET else 'MetaAPI'
                                        logger.info(f"🔌 Bot {bot_id}: {_mode_label} trading ({_broker_for_route}) — no local MT5 needed")
                                except Exception as _re:
                                    logger.warning(f"Bot {bot_id}: REST/Socket setup failed ({_re}), falling back to local MT5")
                        
                        if not use_rest_trading:
                                    # LOCAL MT5 TERMINAL PATH (original code)
                                normalized_cache_broker = canonicalize_broker_name(bot_config.get('broker_type', 'MetaTrader 5'))
                                cache_key = f"{user_id}|{normalized_cache_broker}|{bot_credentials.get('account', 'unknown')}"
                                with broker_connection_cache_lock:
                                    if cache_key in broker_connection_cache:
                                        mt5_conn = broker_connection_cache[cache_key]
                                        logger.debug(f"♻️  Bot {bot_id}: Using cached MT5 connection (savings: 3-5s)")
                                
                                    else:
                                        # Create new connection and cache it
                                        if bot_credentials:
                                            # CRITICAL FIX: Use global MT5 singleton instead of creating new instances
                                            # BEFORE: Each bot created MT5Connection → 14 terminal windows
                                            # NOW: All bots reuse single global connection → 1 terminal window
                                            mt5_conn = get_global_mt5()
                                            if not mt5_conn:
                                                logger.info(f"Bot {bot_id}: Creating global MT5 singleton connection...")
                                                mt5_conn = MT5Connection(bot_credentials)
                                                set_global_mt5(mt5_conn)
                                            else:
                                                logger.debug(f"Bot {bot_id}: Reusing global MT5 connection")
                                        else:
                                            mt5_conn = get_global_mt5()
                                            if not mt5_conn:
                                                logger.info(f"Bot {bot_id}: Creating global MT5 singleton (no credentials)...")
                                                mt5_conn = MT5Connection()
                                                set_global_mt5(mt5_conn)
                                            else:
                                                logger.debug(f"Bot {bot_id}: Reusing global MT5 connection")
                                        broker_connection_cache[cache_key] = mt5_conn
                                        logger.debug(f"✨ Bot {bot_id}: MT5 connection cached")
                        
                                # CRITICAL FIX: Update singleton credentials with THIS bot's creds
                                # so _connect_with_lock uses correct is_live, server, and terminal path
                                if bot_credentials and mt5_conn:
                                    mt5_conn.credentials = bot_credentials
                                    _bot_is_live = bot_credentials.get('is_live', False)
                                    mt5_conn.mt5_path = find_mt5_terminal_path(
                                        mt5_conn.mt5_broker,
                                        bot_credentials.get('path'),
                                        is_live=_bot_is_live
                                    )
                                    logger.info(f"Bot {bot_id}: Updated MT5 credentials (is_live={_bot_is_live}, account={bot_credentials.get('account', '?')})")

                                if not mt5_conn.connect():
                                    consecutive_connection_failures += 1
                                    logger.error(f"Bot {bot_id}: MT5 connection failed (attempt {consecutive_connection_failures}/{MAX_BROKER_DISCONNECT_FAILURES}) - will retry next cycle")
                                    if consecutive_connection_failures >= MAX_BROKER_DISCONNECT_FAILURES:
                                        logger.error(f"🛑 Bot {bot_id}: Broker disconnected {MAX_BROKER_DISCONNECT_FAILURES} times in a row - AUTO-STOPPING bot")
                                        bot_config['status'] = 'STOPPED'
                                        bot_config['enabled'] = False
                                        bot_config['stopReason'] = f'Broker disconnected - auto-stopped after {MAX_BROKER_DISCONNECT_FAILURES} failed reconnection attempts'
                                        bot_stop_flags[bot_id] = True
                                        running_bots[bot_id] = False
                                        persist_bot_runtime_state(bot_id)
                                        try:
                                            _dc = get_db_connection()
                                            _dcc = _dc.cursor()
                                            _dcc.execute('UPDATE user_bots SET status=?, enabled=0 WHERE bot_id=?', ('STOPPED', bot_id))
                                            _dc.commit()
                                            _dc.close()
                                        except Exception as _dce:
                                            logger.warning(f"Bot {bot_id}: DB update on auto-stop failed: {_dce}")
                                        return
                                    # STAGGER: Add random delay (1-15s) so bots don't all retry simultaneously
                                    stagger_delay = random.uniform(1, 15)
                                    actual_wait = trading_interval + stagger_delay
                                    logger.info(f"   ⏰ Staggered retry in {actual_wait:.0f}s (base {trading_interval}s + jitter {stagger_delay:.0f}s)")
                                    time.sleep(actual_wait)
                                    continue
                                else:
                                    consecutive_connection_failures = 0  # Reset on successful connection
                        
                                # ==================== MULTI-USER ACCOUNT VERIFICATION ====================
                                # Verify MT5 is logged into THIS bot's account before trading.
                                # If another user's bot switched the account, we must re-login.
                                # Uses fast mt5_current_account check first to avoid expensive MT5 IPC call.
                                try:
                                    expected_account = int(bot_credentials.get('account', 0))
                                    needs_switch = False
                                    with mt5_account_lock:
                                        if mt5_current_account and expected_account and mt5_current_account != expected_account:
                                            needs_switch = True
                            
                                    if needs_switch:
                                        logger.warning(f"⚠️  Bot {bot_id}: MT5 on account {mt5_current_account} but bot needs {expected_account} - switching...")
                                        # Force re-login with this bot's credentials
                                        mt5_conn.connected = False
                                        if not mt5_conn.connect():
                                            logger.error(f"Bot {bot_id}: Account switch to {expected_account} failed - will retry")
                                            time.sleep(trading_interval)
                                            continue
                                        # Verify the switch actually stuck (another concurrent bot may have
                                        # switched the singleton back while we held the conn lock)
                                        try:
                                            import MetaTrader5 as _mt5_verify
                                            _verify_info = _mt5_verify.account_info()
                                            if _verify_info and _verify_info.login != expected_account:
                                                logger.warning(f"⚠️  Bot {bot_id}: Switch verification failed — MT5 is on {_verify_info.login}, not {expected_account}. Skipping cycle to avoid wrong-account trade.")
                                                time.sleep(trading_interval)
                                                continue
                                        except Exception:
                                            pass
                                        logger.info(f"✅ Bot {bot_id}: Switched MT5 to account {expected_account}")
                                    elif expected_account and not mt5_current_account:
                                        # First time — verify via MT5 IPC
                                        import MetaTrader5 as _mt5_check
                                        current_info = _mt5_check.account_info()
                                        if current_info and current_info.login != expected_account:
                                            mt5_conn.connected = False
                                            if not mt5_conn.connect():
                                                logger.error(f"Bot {bot_id}: Initial account login to {expected_account} failed")
                                                time.sleep(trading_interval)
                                                continue
                                except Exception as acct_err:
                                    logger.debug(f"Bot {bot_id}: Account verification check: {acct_err}")
                                # ==================== END MULTI-USER VERIFICATION ====================
                        
                                if trade_cycle == 1:
                                    logger.info(f"Bot {bot_id}: First trade cycle - waiting for MT5 readiness (up to {mt5_ready_timeout}s)...")
                                    timeout_for_this_cycle = mt5_ready_timeout
                                    # Log progress every 5 seconds to help diagnose hangs
                                    start_wait = datetime.now()
                                else:
                                    timeout_for_this_cycle = 10  # Reduced from 15s
                                    start_wait = None
                        
                                if not mt5_conn.wait_for_mt5_ready(timeout_seconds=timeout_for_this_cycle):
                                    if trade_cycle == 1:
                                        elapsed_wait = (datetime.now() - start_wait).total_seconds() if start_wait else timeout_for_this_cycle
                                        logger.warning(f"Bot {bot_id}: First cycle MT5 readiness timeout after {elapsed_wait:.0f}s (max {timeout_for_this_cycle}s)")
                                        logger.warning(f"  Will retry with extended wait... (another {timeout_for_this_cycle}s)")
                                        time.sleep(10)
                                        continue
                                    else:
                                        logger.warning(f"Bot {bot_id}: MT5 not ready after {timeout_for_this_cycle}s - will retry next cycle")
                                        # STAGGER: Add random delay to prevent thundering herd
                                        stagger_delay = random.uniform(2, 12)
                                        actual_wait = trading_interval + stagger_delay
                                        logger.info(f"   ⏰ Staggered retry in {actual_wait:.0f}s (base {trading_interval}s + jitter {stagger_delay:.0f}s)")
                                        time.sleep(actual_wait)
                                        continue

                                # ==================== AUTO-PAUSE CHECK: MT5 AutoTrading ====================
                                # If MT5 is ready but AutoTrading is disabled, warn and skip cycle
                                # (Do NOT permanently disable bot - AutoTrading may be re-enabled)
                                try:
                                    import MetaTrader5 as mt5_check
                                    term_info = mt5_check.terminal_info()
                                    if term_info and not term_info.trade_allowed:
                                        logger.warning(f"⚠️ Bot {bot_id}: MT5 AutoTrading is DISABLED - skipping cycle (will retry)")
                                        logger.warning(f"   Enable AutoTrading in MT5 toolbar to resume trading")
                                        if DEPLOYMENT_MODE != 'VPS':
                                            time.sleep(trading_interval)
                                            continue
                                        logger.warning(
                                            f"   Proceeding anyway in VPS mode because MT5 readiness already confirmed the order path; "
                                            f"the terminal AutoTrading flag can be stale during account switching"
                                        )
                                except Exception as auto_pause_e:
                                    logger.debug(f"Bot {bot_id}: AutoTrading check: {auto_pause_e}")

                                # ==================== WAIT FOR CRITICAL SYMBOLS ====================
                                # For bots trading ETHUSDm or BTCUSDm, ensure they're fully loaded
                                # These symbols require special initialization and fail fast if unavailable
                                symbols_list = bot_config.get('symbols', ['EURUSDm'])
                                if trade_cycle == 1:  # Only on first cycle to avoid repeated delays
                                    if not mt5_conn.wait_for_critical_symbols(symbols_list, timeout_seconds=15):
                                        logger.warning(f"Bot {bot_id}: Critical symbols not ready yet, will retry next cycle")
                                        # Rather than fail immediately, retry in next cycle
                                        # Critical symbols usually load within 30-60 seconds total after MT5 connects
                                        time.sleep(trading_interval)
                                        continue
                                # ==================== END CRITICAL SYMBOL CHECK ====================

                                active_conn = mt5_conn
                        
                    except Exception as e:
                        import traceback
                        logger.error(f"Bot {bot_id}: MT5 connection exception: {e}")
                        logger.error(f"  Traceback: {traceback.format_exc()}")
                        logger.error(f"  Exception type: {type(e).__name__}")
                        # STAGGER: Add random delay to prevent thundering herd
                        stagger_delay = random.uniform(2, 12)
                        actual_wait = trading_interval + stagger_delay
                        logger.info(f"   ⏰ Staggered retry in {actual_wait:.0f}s (base {trading_interval}s + jitter {stagger_delay:.0f}s)")
                        time.sleep(actual_wait)
                        continue
                else:
                    try:
                        active_conn = bot_config.get('broker_conn')
                        if active_conn is None or not active_conn.connected:
                            credential_id = bot_config.get('credentialId')
                            if credential_id:
                                broker_type_new, new_conn = get_broker_connection(credential_id, user_id, bot_id)
                                if hasattr(new_conn, 'connected'):
                                    active_conn = new_conn
                                    bot_config['broker_conn'] = active_conn
                                    bot_config['broker_type'] = broker_type_new
                                    broker_type = broker_type_new
                                else:
                                    logger.error(f"Bot {bot_id}: Broker reconnection failed: {new_conn}")
                                    # STAGGER: Add random delay to prevent thundering herd
                                    stagger_delay = random.uniform(2, 12)
                                    actual_wait = trading_interval + stagger_delay
                                    logger.info(f"   ⏰ Staggered retry in {actual_wait:.0f}s (base {trading_interval}s + jitter {stagger_delay:.0f}s)")
                                    time.sleep(actual_wait)
                                    continue
                            else:
                                logger.error(f"Bot {bot_id}: No credentialId for broker reconnection")
                                # STAGGER: Add random delay to prevent thundering herd
                                stagger_delay = random.uniform(2, 12)
                                actual_wait = trading_interval + stagger_delay
                                logger.info(f"   ⏰ Staggered retry in {actual_wait:.0f}s (base {trading_interval}s + jitter {stagger_delay:.0f}s)")
                                time.sleep(actual_wait)
                                continue
                        logger.info(f"Bot {bot_id}: Connected to {broker_type} for trading")
                    except Exception as e:
                        logger.error(f"Bot {bot_id}: Broker connection exception: {e}")
                        time.sleep(trading_interval)
                        continue
                
                trades_placed = 0
                symbols = bot_config.get('symbols', ['EURUSDm'])

                if canonicalize_broker_name(broker_type) == 'FXCM':
                    tradable_symbol_keys = _get_fxcm_tradable_symbol_keys(broker_conn=active_conn)
                    filtered_symbols = _filter_fxcm_symbols_for_tradability(list(symbols), tradable_symbol_keys)
                    if filtered_symbols and filtered_symbols != list(symbols):
                        logger.info(
                            f"🔄 Bot {bot_id}: Filtered FXCM configured symbols for active account tradability: "
                            f"{list(symbols)} -> {filtered_symbols}"
                        )
                        symbols = filtered_symbols
                        _persist_normalized_bot_symbols(bot_id, bot_config, filtered_symbols)
                    elif tradable_symbol_keys is not None and not filtered_symbols:
                        logger.info(
                            f"🧭 Bot {bot_id}: Configured FXCM symbols were not confirmed tradable by the helper; "
                            f"keeping the configured symbols for direct broker validation this cycle"
                        )

                if bot_config.get('managementMode', 'assisted') != 'manual' and len(symbols) > MAX_ASSISTED_SYMBOLS_PER_CYCLE:
                    symbols = list(symbols[:MAX_ASSISTED_SYMBOLS_PER_CYCLE])
                    logger.info(
                        f"🧭 Bot {bot_id}: Limiting cycle to top {MAX_ASSISTED_SYMBOLS_PER_CYCLE} symbols for risk control: {symbols}"
                    )

                runtime_safety_changes = enforce_runtime_capital_safety(bot_config)
                if runtime_safety_changes:
                    logger.info(
                        f"🛡️ Bot {bot_id}: Runtime capital safety adjusted "
                        f"{', '.join(runtime_safety_changes)}"
                    )
                
                # CHECK PROFIT LOCK AND DAILY LOSS LIMITS BEFORE TRADING
                profit_lock = bot_config.get('profitLock', 0.0) or 0.0
                max_daily_loss = bot_config.get('maxDailyLoss', 0.0) or 0.0
                today = datetime.now().strftime('%Y-%m-%d')
                # Safely handle dailyProfits - ensure it's a dict
                daily_profits_dict = bot_config.get('dailyProfits') or {}
                if not isinstance(daily_profits_dict, dict):
                    daily_profits_dict = {}
                    bot_config['dailyProfits'] = daily_profits_dict
                daily_profit = daily_profits_dict.get(today, 0.0)
                
                pause_reason = None
                if profit_lock > 0 and daily_profit >= profit_lock:
                    pause_reason = f"🔒 Daily profit lock reached: ${daily_profit:.2f} >= ${profit_lock:.2f}"
                elif max_daily_loss > 0 and daily_profit < -max_daily_loss:
                    pause_reason = f"⚠️ Daily loss limit hit: ${abs(daily_profit):.2f} >= ${max_daily_loss:.2f}"
                
                if pause_reason:
                    daily_loss_debug = _build_bot_daily_loss_diagnostics(bot_config)
                    logger.info(
                        f"[PAUSE] Bot {bot_id}: Daily loss debug | day={daily_loss_debug['today']} "
                        f"today_pnl=${daily_loss_debug['todayProfit']:.2f} realized_loss=${daily_loss_debug['realizedLoss']:.2f} "
                        f"max_daily_loss=${daily_loss_debug['maxDailyLoss']:.2f} open_pnl=${daily_loss_debug['openPositionPnl']:.2f} "
                        f"closed_trades_today={daily_loss_debug['closedTradesToday']} recent_daily={daily_loss_debug['recentDailyProfits']}"
                    )
                    logger.info(f"[PAUSE] Bot {bot_id}: {pause_reason} - PAUSING TRADES FOR TODAY")
                    bot_config['status'] = 'PAUSED'
                    bot_config['pauseReason'] = pause_reason
                    persist_bot_runtime_state(bot_id)
                    # Wait for trading interval before next cycle
                    time.sleep(trading_interval)
                    continue
                else:
                    # Trading is allowed
                    if bot_config.get('status') == 'PAUSED':
                        bot_config['status'] = 'ACTIVE'
                        bot_config['pauseReason'] = None
                
                demo_profile_sync = _sync_demo_bot_with_best_peer(bot_id, bot_config)
                if demo_profile_sync:
                    logger.info(
                        f"🧩 Bot {bot_id}: Synced demo behavior profile from "
                        f"{bot_config.get('behaviorProfileSourceBotId')} ({', '.join(demo_profile_sync)})"
                    )

                universal_adaptation_changes = apply_universal_performance_adaptation(bot_id, bot_config)
                if universal_adaptation_changes:
                    logger.info(
                        f"🧠 Bot {bot_id}: Universal performance adaptation updated "
                        f"{', '.join(universal_adaptation_changes)}"
                    )

                # ENHANCED LOGGING: Log signal evaluation for ALL symbols upfront
                management_state = apply_assisted_management_overrides(bot_config)
                adaptive_threshold_floor = _adaptive_signal_threshold_floor(bot_config)
                base_signal_threshold = max(
                    int(bot_config.get('signalThreshold', adaptive_threshold_floor) or adaptive_threshold_floor),
                    adaptive_threshold_floor,
                )
                signal_threshold = management_state['signalThreshold']
                runtime_mode_value = str(bot_config.get('mode') or bot_config.get('botMode') or 'demo').strip().lower()
                runtime_is_demo = runtime_mode_value != 'live' and not bool(bot_config.get('is_live'))
                # MANUAL MODE GUARD: respect user-configured signalThreshold; do not floor to adaptive=1
                _threshold_mode_manual = str(bot_config.get('signalThresholdMode') or '').strip().lower() == 'manual'
                if canonicalize_broker_name(broker_type) == 'Binance' and runtime_is_demo and not _threshold_mode_manual:
                    signal_threshold = adaptive_threshold_floor
                    base_signal_threshold = adaptive_threshold_floor
                    management_state['signalThreshold'] = signal_threshold
                    bot_config['effectiveSignalThreshold'] = signal_threshold
                elif _threshold_mode_manual:
                    manual_threshold_value = max(1, int(bot_config.get('signalThreshold') or 50))
                    signal_threshold = manual_threshold_value
                    base_signal_threshold = manual_threshold_value
                    management_state['signalThreshold'] = manual_threshold_value
                    bot_config['effectiveSignalThreshold'] = manual_threshold_value
                strategy_name = _choose_strategy_for_cycle(bot_id, bot_config, symbols, signal_threshold)
                strategy_func = STRATEGY_MAP.get(strategy_name, trend_following_strategy)
                strategy_cache: Dict[str, Optional[Dict[str, Any]]] = {}
                signal_summary = []
                best_signal_strength = 0.0
                best_signal_symbol = None
                configured_signal_hits = 0
                signal_strength_by_symbol: Dict[str, float] = {}
                for eval_symbol in symbols:
                    eval_market_data = _enrich_market_data_with_bot_context(bot_config, eval_symbol)
                    eval_signal = evaluate_real_trade_signal(eval_symbol, eval_market_data)
                    eval_params = _get_cached_strategy_params(
                        strategy_cache,
                        strategy_func,
                        eval_symbol,
                        bot_config['accountId'],
                        bot_config['riskPerTrade'],
                        eval_market_data,
                    )
                    signal_score = eval_signal.get('strength', 0)
                    signal_score_value = float(signal_score or 0.0)
                    signal_strength_by_symbol[eval_symbol] = signal_score_value
                    if signal_score_value >= best_signal_strength:
                        best_signal_strength = signal_score_value
                        best_signal_symbol = eval_symbol
                    signal_label = eval_signal.get('signal', 'NEUTRAL')
                    if eval_params and signal_score >= signal_threshold:
                        configured_signal_hits += 1
                    status = "✅" if eval_params and signal_score >= signal_threshold else "⏭️"
                    signal_summary.append(f"{status}{eval_symbol}:{signal_score:.0f} {signal_label}")

                runtime_cadence = _resolve_runtime_trade_cadence(
                    bot_config,
                    strategy_name,
                    best_signal_symbol,
                    best_signal_strength,
                )
                trading_interval = runtime_cadence['tradingInterval']
                poll_interval = runtime_cadence['pollInterval']
                logger.info(
                    f"⏱️ Bot {bot_id}: Adaptive cadence -> symbol={best_signal_symbol or 'n/a'} "
                    f"strength={best_signal_strength:.0f}/100 interval={trading_interval}s poll={poll_interval}s"
                )
                
                logger.info(f"📊 Bot {bot_id} Cycle #{trade_cycle}: Signal check: {' | '.join(signal_summary)} (threshold: {signal_threshold}/100)")
                
                # ==================== INTELLIGENT SCANNER & REALLOCATION ====================
                # If enabled, scan ALL symbols, close weak positions, and trade the best ones
                idle_cycles = int(bot_config.get('adaptiveSignalMissCount') or 0)
                forced_scanner_fallback = (
                    not bot_config.get('open_positions')
                    and configured_signal_hits == 0
                    and idle_cycles >= ADAPTIVE_FORCED_SCANNER_IDLE_CYCLES
                )

                adaptive_scanner_active = (
                    not bot_config.get('open_positions')
                    and (
                        bot_config.get('intelligentScanner', False)
                        or int(bot_config.get('adaptiveSignalMissCount') or 0) >= ADAPTIVE_SCANNER_TRIGGER_MISSES
                        or configured_signal_hits == 0
                    )
                )
                scanner_threshold = signal_threshold
                if forced_scanner_fallback:
                    scanner_threshold = max(
                        adaptive_threshold_floor,
                        signal_threshold - ADAPTIVE_FORCED_SCANNER_THRESHOLD_REDUCTION,
                    )
                    logger.info(
                        f"🧭 Bot {bot_id}: Forced scanner fallback after {idle_cycles} idle cycle(s) "
                        f"(temporary threshold {signal_threshold} -> {scanner_threshold})"
                    )

                if canonicalize_broker_name(broker_type) == 'Binance' and runtime_is_demo and not _threshold_mode_manual:
                    scanner_threshold = adaptive_threshold_floor
                if _threshold_mode_manual:
                    scanner_threshold = signal_threshold
                    adaptive_scanner_active = False

                if adaptive_scanner_active and not bot_config.get('intelligentScanner', False):
                    logger.info(f"🧠 Bot {bot_id}: Adaptive scanner engaged for this cycle because assigned symbols produced no qualifying setup")

                if adaptive_scanner_active:
                    symbols = execute_intelligent_reallocation(
                        bot_id, bot_config, active_conn, is_mt5, mt5_conn,
                        strategy_func, scanner_threshold, broker_type, strategy_cache,
                        force_scan=not bot_config.get('intelligentScanner', False),
                    )
                    if bot_config.get('managementMode', 'assisted') != 'manual' and len(symbols) > MAX_ASSISTED_SYMBOLS_PER_CYCLE:
                        symbols = list(symbols[:MAX_ASSISTED_SYMBOLS_PER_CYCLE])
                        logger.info(
                            f"🧭 Bot {bot_id}: Capped scanner cycle symbols to top "
                            f"{MAX_ASSISTED_SYMBOLS_PER_CYCLE} for risk control: {symbols}"
                        )
                scanner_signal_hits = 0
                if adaptive_scanner_active:
                    scanner_signal_hits = int((bot_config.get('lastScanResults') or {}).get('qualifyingOpportunities') or 0)
                
                trades_this_cycle = 0
                last_order_block_reason = None
                _block_reason_per_symbol: Dict[str, str] = {}
                for symbol in symbols:
                    if bot_stop_flags.get(bot_id, False):
                        break  # Stop requested, exit loop
                    
                    _iter_initial_block_reason = last_order_block_reason
                    try:
                        symbol_is_open, symbol_market_status = market_status_by_symbol.get(symbol, (None, None))
                        if symbol_is_open is None:
                            symbol_is_open, symbol_market_status = is_market_open_for_symbol(symbol)
                            market_status_by_symbol[symbol] = (symbol_is_open, symbol_market_status)
                        if not symbol_is_open:
                            last_order_block_reason = f"{symbol} market closed: {symbol_market_status}"
                            logger.info(f"⏭️ Bot {bot_id}: Skipping {symbol} - {symbol_market_status}")
                            continue

                        if not should_trade_symbol_based_on_risk_management(bot_config, symbol):
                            continue

                        # Adaptive symbol-performance gate: trade more on winners,
                        # demote / skip losers based on this bot's own closed trades.
                        try:
                            _perf = _evaluate_symbol_performance(bot_config, symbol)
                            _verdict = _perf.get('verdict', 'normal')
                            if _verdict == 'blacklisted':
                                if _is_symbol_blacklist_cooldown_active(bot_config, symbol):
                                    last_order_block_reason = (
                                        f"{symbol} blacklisted (winRate={_perf.get('winRate')}, pnl={_perf.get('pnl')})"
                                    )
                                    logger.info(
                                        f"❌ Bot {bot_id}: Skipping {symbol} - blacklisted by symbol performance "
                                        f"(samples={_perf.get('samples')}, wins={_perf.get('wins')}, losses={_perf.get('losses')}, pnl={_perf.get('pnl')})"
                                    )
                                    continue
                                else:
                                    logger.info(
                                        f"🔁 Bot {bot_id}: {symbol} blacklisted but cooldown elapsed - allowing 1 probe trade"
                                    )
                            elif _verdict == 'favored':
                                logger.info(
                                    f"⬆️ Bot {bot_id}: {symbol} favored "
                                    f"(winRate={_perf.get('winRate')}, pnl={_perf.get('pnl')}, mult={_perf.get('multiplier')})"
                                )
                            elif _verdict == 'demoted':
                                logger.info(
                                    f"⬇️ Bot {bot_id}: {symbol} demoted "
                                    f"(winRate={_perf.get('winRate')}, pnl={_perf.get('pnl')}, mult={_perf.get('multiplier')})"
                                )
                            _symbol_perf_multiplier = float(_perf.get('multiplier') or 1.0)
                        except Exception as _perf_err:
                            logger.debug(f"Bot {bot_id}: symbol-perf eval failed for {symbol}: {_perf_err}")
                            _symbol_perf_multiplier = 1.0

                        # Dynamic position sizing
                        binance_market_name = str(
                            bot_config.get('binanceMarket')
                            or bot_config.get('market')
                            or getattr(active_conn, 'market', 'spot')
                            or 'spot'
                        ).strip().lower()
                        configured_trade_amount = bot_config.get('tradeAmount')
                        fixed_trade_amount = configured_trade_amount
                        if not fixed_trade_amount and canonicalize_broker_name(broker_type) == 'Binance':
                            balance_basis = max(
                                float(bot_config.get('accountEquity') or 0.0),
                                float(bot_config.get('accountBalance') or 0.0),
                            )
                            fixed_trade_amount = derive_binance_default_trade_amount(
                                balance_basis,
                                bot_config.get('displayCurrency'),
                                binance_market_name,
                                bot_config.get('effectiveMaxOpenPositions') or bot_config.get('maxOpenPositions') or 3,
                                str(bot_config.get('mode') or 'demo').lower() == 'live',
                            )
                        if not fixed_trade_amount and _normalize_management_profile(bot_config.get('managementProfile')) == 'small_account':
                            balance_basis = max(
                                float(bot_config.get('accountEquity') or 0.0),
                                float(bot_config.get('accountBalance') or 0.0),
                            )
                            fixed_trade_amount = derive_small_account_trade_amount(
                                balance_basis,
                                bot_config.get('displayCurrency'),
                            )

                        # Apply per-symbol performance multiplier (favor winners / shrink losers)
                        if fixed_trade_amount and _symbol_perf_multiplier and _symbol_perf_multiplier != 1.0:
                            fixed_trade_amount = round(float(fixed_trade_amount) * _symbol_perf_multiplier, 2)

                        bot_currency = str(bot_config.get('displayCurrency') or 'USD').upper()
                        fixed_trade_volume = None
                        mt5_api = mt5_conn.mt5 if (is_mt5 and mt5_conn and hasattr(mt5_conn, 'mt5')) else None
                        futures_controls = {'enabled': False}
                        if canonicalize_broker_name(broker_type) == 'Binance' and binance_market_name == 'futures':
                            futures_controls = _resolve_binance_futures_order_controls(bot_config)
                        if fixed_trade_amount:
                            adaptive_trade_amount, sizing_snapshot = _resolve_adaptive_trade_amount(
                                bot_config,
                                float(fixed_trade_amount),
                                volatility_level=bot_config.get('volatilityLevel', 'Medium'),
                            )
                            fixed_trade_amount = adaptive_trade_amount
                            fixed_trade_volume, volume_details = estimate_fixed_trade_volume(
                                float(fixed_trade_amount),
                                symbol,
                                bot_currency,
                                broker_type,
                                mt5_api=mt5_api,
                                market_name=binance_market_name,
                                exchange_leverage=float(futures_controls.get('exchangeLeverage') or 1.0),
                            )
                            position_size = 1.0
                            conversion_note = volume_details.get('conversion_note')
                            if conversion_note:
                                logger.info(f"💱 Bot {bot_id}: Fixed trade amount conversion for {symbol}: {conversion_note}")
                            logger.info(
                                f"💵 Bot {bot_id}: Adaptive trade amount {float(fixed_trade_amount):.2f} {bot_currency} "
                                f"(base {float(_safe_float(configured_trade_amount, fixed_trade_amount)):.2f}, "
                                f"multiplier {_safe_float(sizing_snapshot.get('multiplier'), 1.0):.2f}) -> "
                                f"target volume {fixed_trade_volume:.4f} units ({volume_details.get('method')})"
                            )
                            if is_mt5 and mt5_api is not None and fixed_trade_volume is not None:
                                try:
                                    mt5_api.symbol_select(symbol, True)
                                    symbol_info = mt5_api.symbol_info(symbol)
                                    min_volume = float(getattr(symbol_info, 'volume_min', 0.0) or 0.0) if symbol_info else 0.0
                                    if min_volume > 0 and fixed_trade_volume < min_volume:
                                        if bot_config.get('dynamicSizing', True):
                                            logger.warning(
                                                f"↩️ Bot {bot_id}: Fixed trade amount for {symbol} would require "
                                                f"{fixed_trade_volume:.4f} lots, below broker minimum {min_volume:.4f}. "
                                                f"Falling back to risk-based sizing instead of auto-upsizing risk."
                                            )
                                            fixed_trade_amount = None
                                            fixed_trade_volume = None
                                            position_size = position_sizer.calculate_position_size(
                                                bot_config,
                                                volatility_level=bot_config.get('volatilityLevel', 'Medium')
                                            )
                                        else:
                                            logger.warning(
                                                f"⏭️ Bot {bot_id}: Skipping {symbol} - configured trade amount "
                                                f"would require {fixed_trade_volume:.4f} lots, below broker minimum {min_volume:.4f}. "
                                                f"Dynamic sizing is disabled, so the bot will not auto-upsize risk."
                                            )
                                            continue
                                except Exception as volume_guard_error:
                                    logger.warning(
                                        f"Bot {bot_id}: Could not validate broker minimum volume for {symbol}: {volume_guard_error}"
                                    )
                        elif bot_config.get('dynamicSizing', True):
                            position_size = position_sizer.calculate_position_size(
                                bot_config,
                                volatility_level=bot_config.get('volatilityLevel', 'Medium')
                            )
                        else:
                            position_size = bot_config.get('basePositionSize', 1.0)
                        
                        market_data = _enrich_market_data_with_bot_context(bot_config, symbol)

                        if fixed_trade_amount and mt5_api is None:
                            fixed_trade_volume, volume_details = estimate_fixed_trade_volume(
                                float(fixed_trade_amount),
                                symbol,
                                bot_currency,
                                broker_type,
                                market_price=float(market_data.get('current_price', 0.0) or 0.0),
                                market_name=binance_market_name,
                                exchange_leverage=float(futures_controls.get('exchangeLeverage') or 1.0),
                            )
                        
                        # Get trade direction from the cached signal evaluation for this cycle.
                        trade_params = _get_cached_strategy_params(
                            strategy_cache,
                            strategy_func,
                            symbol,
                            bot_config['accountId'],
                            bot_config['riskPerTrade'],
                            market_data,
                        )
                        
                        # Skip trade if signal strength is too low
                        if trade_params is None:
                            raw_signal = evaluate_real_trade_signal(symbol, market_data)
                            
                            # 🌱 MEAN REVERSION SEED-BUY: When no inventory exists and signal is bullish-but-weak
                            # Place a small starter BUY so future SELL signals can execute
                            seed_buy_enabled = bot_config.get('seedBuyEnabled', False)
                            if (seed_buy_enabled and broker_type == 'Binance' 
                                and getattr(active_conn, 'market', 'spot') == 'spot'
                                and raw_signal.get('trend') == 'UP' 
                                and raw_signal.get('strength', 0) >= bot_config.get('seedBuyStrengthMin', 20)
                                and raw_signal.get('strength', 0) < bot_config.get('seedBuyStrengthMax', 45)):
                                
                                # Check for no inventory
                                tracked_open = bot_config.get('open_positions', {})
                                has_position = any(p.get('symbol') == symbol for p in tracked_open.values() if isinstance(p, dict))
                                if not has_position:
                                    seed_size = bot_config.get('seedBuyVolume', 0.25)
                                    seed_tp_pct = bot_config.get('seedBuyProfitTarget', 0.05)  # 5%
                                    
                                    try:
                                        seed_qty = position_sizer.calculate_position_size(bot_config) * seed_size
                                        seed_tp_pips = int(100 * seed_tp_pct / 0.01)  # Approximate pips for TP
                                        seed_params = {
                                            'symbol': symbol,
                                            'type': 'BUY',
                                            'volume': seed_qty,
                                            'stop_loss': bot_config.get('seedBuySL', 50),
                                            'take_profit': seed_tp_pips,
                                            'signal': {'signal': 'SEED_BUY', 'strength': raw_signal.get('strength', 0)},
                                            'is_seed_buy': True,
                                        }
                                        trade_params = seed_params
                                        logger.info(f"🌱 Bot {bot_id}: Seed-BUY triggered on {symbol} (strength={raw_signal.get('strength'):.0f}/100, qty={seed_qty:.4f})")
                                    except Exception as seed_err:
                                        logger.debug(f"Bot {bot_id}: Seed-BUY calculation failed: {seed_err}")
                                        trade_params = None
                            
                            if trade_params is None:
                                last_order_block_reason = (
                                    f"{symbol} rejected by strategy: "
                                    f"signal={raw_signal.get('signal', 'NEUTRAL')} "
                                    f"strength={raw_signal.get('strength', 0):.0f}/100 "
                                    f"reason={raw_signal.get('entry_reason', 'Rejected by strategy')}"
                                )
                                logger.info(
                                    f"⏭️ Bot {bot_id}: Skipping {symbol} - "
                                    f"signal={raw_signal.get('signal', 'NEUTRAL')} "
                                    f"strength={raw_signal.get('strength', 0):.0f}/100 "
                                    f"trend={raw_signal.get('trend', 'UNKNOWN')} "
                                    f"reason={raw_signal.get('entry_reason', 'Rejected by strategy')}"
                                )
                                continue
                        
                        signal_info = trade_params.get('signal', {})
                        signal_strength = _safe_float(signal_info.get('strength'), 0.0)
                        required_strength = scanner_threshold if adaptive_scanner_active else signal_threshold
                        if signal_strength < required_strength:
                            last_order_block_reason = (
                                f"{symbol} below threshold: {signal_strength:.0f}/100 < {required_strength}/100"
                            )
                            logger.info(
                                f"⏭️ Bot {bot_id}: Skipping {symbol} - strength={signal_strength:.0f}/100 "
                                f"below required threshold={required_strength}/100"
                            )
                            continue

                        # Skip if trend following has already placed 3+ trades in last 30 minutes (over-trading filter)
                        recent_trade_history = bot_config.get('tradeHistory', [])
                        if recent_trade_history:
                            trade_cap_30min = _max_trades_per_30_minutes(bot_config, strategy_name)
                            now_timestamp = datetime.now().timestamp()
                            recent_trades_30min = []
                            for t in recent_trade_history:
                                if not isinstance(t, dict):
                                    continue
                                try:
                                    trade_ts = datetime.fromisoformat(str(t.get('time', '')).replace('Z', '+00:00')).timestamp()
                                    if (now_timestamp - trade_ts) < 1800:
                                        recent_trades_30min.append(t)
                                except:
                                    pass
                            if len(recent_trades_30min) >= trade_cap_30min and bot_config.get('open_positions'):
                                last_order_block_reason = (
                                    f"cooldown active on {symbol}: {len(recent_trades_30min)} trades in last 30min "
                                    f"(limit {trade_cap_30min})"
                                )
                                logger.info(
                                    f"⏭️ Bot {bot_id}: Already placed {len(recent_trades_30min)} trades in last 30min "
                                    f"(limit {trade_cap_30min}) - cooling down to avoid over-trading chop"
                                )
                                continue

                        sl_pips = max(_safe_float(trade_params.get('stop_loss'), 0.0), 0.0)
                        tp_pips = max(_safe_float(trade_params.get('take_profit'), 0.0), 0.0)
                        rr_ratio = (tp_pips / sl_pips) if sl_pips > 0 else 0.0
                        min_rr_ratio = get_min_risk_reward_ratio_for_broker(broker_type)
                        if rr_ratio < min_rr_ratio:
                            last_order_block_reason = (
                                f"{symbol} reward:risk too low: {rr_ratio:.2f} < {min_rr_ratio:.2f} "
                                f"(SL={sl_pips:.2f}, TP={tp_pips:.2f})"
                            )
                            logger.info(
                                f"⏭️ Bot {bot_id}: Skipping {symbol} - reward:risk {rr_ratio:.2f} below minimum {min_rr_ratio:.2f} | "
                                f"SL={sl_pips:.2f} TP={tp_pips:.2f}"
                            )
                            continue

                        order_type = trade_params['type']
                        pyramid_decision = _evaluate_pyramid_addon(
                            bot_config,
                            symbol,
                            order_type,
                            signal_strength,
                            required_strength,
                        )
                        if (
                            broker_type == 'Binance'
                            and active_conn
                            and getattr(active_conn, 'market', 'spot') != 'futures'
                        ):
                            normalized_spot_symbol = active_conn._normalize_symbol(symbol) if hasattr(active_conn, '_normalize_symbol') else symbol
                            tracked_open_positions = bot_config.get('open_positions', {}) if isinstance(bot_config.get('open_positions'), dict) else {}
                            tracked_symbol_position_exists = any(
                                (
                                    active_conn._normalize_symbol(str(position.get('symbol') or ''))
                                    if hasattr(active_conn, '_normalize_symbol')
                                    else str(position.get('symbol') or '')
                                ) == normalized_spot_symbol
                                for position in tracked_open_positions.values()
                                if isinstance(position, dict)
                            )
                            market_price = _safe_float(market_data.get('current_price', 0.0), 0.0)
                            inventory_snapshot = _get_binance_spot_inventory_snapshot(active_conn, normalized_spot_symbol, market_price)
                            base_asset = inventory_snapshot['baseAsset']
                            available_spot_balance = inventory_snapshot['freeBalance']
                            normalized_available_balance = inventory_snapshot['normalizedBalance']
                            min_qty = inventory_snapshot['minQty']
                            min_notional = inventory_snapshot['minNotional']
                            market_price = inventory_snapshot['marketPrice']
                            sellable_spot_inventory_exists = bool(inventory_snapshot['isSellable'])

                            if order_type.upper() == 'SELL' and not tracked_symbol_position_exists and sellable_spot_inventory_exists:
                                last_order_block_reason = (
                                    f"Binance spot found untracked inventory for {symbol} "
                                    f"({available_spot_balance:.8f} {base_asset}); skipping SELL - bot must place a BUY first to track the entry price"
                                )
                                logger.info(f"⏭️ Bot {bot_id}: {last_order_block_reason}")
                                continue

                            if order_type.upper() == 'SELL' and not tracked_symbol_position_exists and not sellable_spot_inventory_exists:
                                last_order_block_reason = (
                                    f"Binance spot cannot open a fresh SELL on {symbol}; waiting for a tracked BUY position to close"
                                )
                                if available_spot_balance > 0:
                                    last_order_block_reason = (
                                        f"Binance spot only has dust inventory on {symbol} ({available_spot_balance:.8f} {base_asset}); "
                                        f"waiting for a new BUY because the balance is not sellable"
                                    )
                                logger.info(f"⏭️ Bot {bot_id}: {last_order_block_reason}")
                                continue

                            if order_type.upper() == 'SELL' and not sellable_spot_inventory_exists:
                                last_order_block_reason = (
                                    f"Binance spot is flat on {symbol}; skipping SELL until the bot has {base_asset} inventory to exit"
                                )
                                if available_spot_balance > 0:
                                    last_order_block_reason = (
                                        f"Binance spot balance on {symbol} is dust ({available_spot_balance:.8f} {base_asset}) and cannot be sold yet"
                                    )
                                logger.info(f"⏭️ Bot {bot_id}: {last_order_block_reason}")
                                continue

                            if order_type.upper() == 'SELL' and min_qty > 0 and normalized_available_balance < min_qty:
                                last_order_block_reason = (
                                    f"Binance spot balance on {symbol} is below minQty ({normalized_available_balance:.8f} < {min_qty:.8f}); skipping SELL"
                                )
                                logger.info(f"⏭️ Bot {bot_id}: {last_order_block_reason}")
                                continue

                            if order_type.upper() == 'SELL' and min_notional > 0 and market_price > 0 and (normalized_available_balance * market_price) < min_notional:
                                last_order_block_reason = (
                                    f"Binance spot balance on {symbol} is below minNotional ({normalized_available_balance * market_price:.4f} < {min_notional:.4f}); skipping SELL"
                                )
                                logger.info(f"⏭️ Bot {bot_id}: {last_order_block_reason}")
                                continue

                            if order_type.upper() == 'SELL' and tracked_symbol_position_exists:
                                # Fee-aware anti-churn guard for spot: avoid exiting tiny/early moves
                                # that are unlikely to cover round-trip fees and slippage.
                                matched_tracked_position = None
                                for tracked_position in tracked_open_positions.values():
                                    if not isinstance(tracked_position, dict):
                                        continue
                                    tracked_symbol = str(tracked_position.get('symbol') or '').strip()
                                    normalized_tracked_symbol = (
                                        active_conn._normalize_symbol(tracked_symbol)
                                        if hasattr(active_conn, '_normalize_symbol')
                                        else tracked_symbol
                                    )
                                    if normalized_tracked_symbol == normalized_spot_symbol:
                                        matched_tracked_position = tracked_position
                                        break

                                if isinstance(matched_tracked_position, dict):
                                    entry_price = _safe_float(
                                        matched_tracked_position.get('entryPrice')
                                        or matched_tracked_position.get('openPrice')
                                        or matched_tracked_position.get('price'),
                                        0.0,
                                    )
                                    held_volume = _safe_float(
                                        matched_tracked_position.get('volume')
                                        or matched_tracked_position.get('size')
                                        or normalized_available_balance,
                                        normalized_available_balance,
                                    )
                                    held_volume = max(0.0, min(held_volume, normalized_available_balance))
                                    if entry_price > 0 and held_volume > 0 and market_price > 0:
                                        gross_pnl = (market_price - entry_price) * held_volume
                                        estimated_notional = held_volume * market_price
                                        try:
                                            estimated_fee_rate = float(os.getenv('BINANCE_SPOT_FEE_RATE', '0.001') or '0.001')
                                        except Exception:
                                            estimated_fee_rate = 0.001
                                        estimated_fee_rate = max(0.0, min(0.01, estimated_fee_rate))
                                        round_trip_fees = ((entry_price * held_volume) + estimated_notional) * estimated_fee_rate
                                        net_after_fees = gross_pnl - round_trip_fees

                                        try:
                                            min_net_exit_pct = float(os.getenv('BINANCE_SPOT_MIN_NET_EXIT_PCT', '0.20') or '0.20')
                                        except Exception:
                                            min_net_exit_pct = 0.20
                                        min_net_exit_pct = max(0.0, min(2.5, min_net_exit_pct))
                                        min_required_net = max(0.05, estimated_notional * (min_net_exit_pct / 100.0))

                                        open_time_raw = str(
                                            matched_tracked_position.get('openTime')
                                            or matched_tracked_position.get('time_open')
                                            or ''
                                        ).strip()
                                        held_minutes = 999.0
                                        if open_time_raw:
                                            try:
                                                held_minutes = max(
                                                    0.0,
                                                    (datetime.now() - datetime.fromisoformat(open_time_raw.replace('Z', '+00:00').replace(' UTC', ''))).total_seconds() / 60.0,
                                                )
                                            except Exception:
                                                held_minutes = 999.0

                                        sell_signal_urgency = signal_strength - required_strength
                                        min_hold_minutes = max(0.0, _safe_float(bot_config.get('binanceSpotMinHoldMinutes'), 1.0))
                                        allow_loss_exit = bool(bot_config.get('binanceSpotAllowLossExit', False))
                                        if not allow_loss_exit:
                                            try:
                                                allow_loss_exit = str(os.getenv('BINANCE_SPOT_ALLOW_LOSS_EXIT', 'false')).strip().lower() in ('1', 'true', 'yes', 'on')
                                            except Exception:
                                                allow_loss_exit = False
                                        if held_minutes < min_hold_minutes and sell_signal_urgency < 12:
                                            last_order_block_reason = (
                                                f"Binance spot hold guard on {symbol}: held {held_minutes:.1f}m < {min_hold_minutes:.1f}m"
                                            )
                                            logger.info(f"⏭️ Bot {bot_id}: {last_order_block_reason}")
                                            continue

                                        if net_after_fees < 0 and not allow_loss_exit:
                                            last_order_block_reason = (
                                                f"Binance spot loss guard on {symbol}: net_after_fees {net_after_fees:.4f} < 0"
                                            )
                                            logger.info(f"⏭️ Bot {bot_id}: {last_order_block_reason}")
                                            continue

                                        if net_after_fees < min_required_net and sell_signal_urgency < 12:
                                            last_order_block_reason = (
                                                f"Binance spot edge guard on {symbol}: net {net_after_fees:.4f} < required {min_required_net:.4f}"
                                            )
                                            logger.info(f"⏭️ Bot {bot_id}: {last_order_block_reason}")
                                            continue

                            if order_type.upper() == 'BUY' and sellable_spot_inventory_exists and not pyramid_decision['allowed']:
                                    if tracked_symbol_position_exists:
                                        logger.info(
                                            f"⏭️ Bot {bot_id}: Spot inventory already exists for {symbol} ({available_spot_balance:.6f} {base_asset}) - skipping duplicate BUY"
                                        )
                                        continue
                                    logger.info(
                                        f"ℹ️ Bot {bot_id}: Shared Binance spot inventory already exists for {symbol} "
                                        f"({available_spot_balance:.6f} {base_asset}) but is not tracked by this bot - allowing BUY"
                                    )

                        adjusted_volume = fixed_trade_volume if fixed_trade_volume is not None else trade_params['volume'] * position_size
                        if pyramid_decision['allowed']:
                            adjusted_volume = max(0.01, adjusted_volume * pyramid_decision['multiplier'])

                        # Log signal details - VERBOSE MODE
                        logger.info(f"🎯 Bot {bot_id}: {signal_info.get('signal', 'UNKNOWN')} setup on {symbol} -> executing {order_type}")
                        logger.info(f"   Signal Strength: {signal_info.get('strength', 0):.0f}/100 | Reason: {signal_info.get('entry_reason', 'N/A')}")
                        logger.info(f"   Risk/Reward Ratio: {rr_ratio:.2f} (minimum: {min_rr_ratio:.2f})")
                        logger.info(f"   Stop Loss: {sl_pips:.2f} pips | Take Profit: {tp_pips:.2f} pips")
                        if pyramid_decision['allowed']:
                            logger.info(
                                f"📈 Bot {bot_id}: Pyramiding add-on enabled for {symbol} at {adjusted_volume:.4f} lots | "
                                f"{pyramid_decision['reason']}"
                            )
                        
                        # Place order via broker with RETRY LOGIC
                        logger.info(f"📍 Bot {bot_id}: Placing {order_type} order on {symbol} via {broker_type} | Cycle: {trade_cycle}")
                        
                        order_result = None
                        
                        if is_ig:
                            # IG Markets - place order via REST API
                            try:
                                # Map MT5 symbol names to IG epics if needed
                                ig_epic = symbol
                                # Common MT5-to-IG epic mapping
                                ig_symbol_map = {
                                    'EURUSD': 'CS.D.EURUSD.CFD.IP',
                                    'GBPUSD': 'CS.D.GBPUSD.CFD.IP',
                                    'USDJPY': 'CS.D.USDJPY.CFD.IP',
                                    'USDCHF': 'CS.D.USDCHF.CFD.IP',
                                    'AUDUSD': 'CS.D.AUDUSD.CFD.IP',
                                    'NZDUSD': 'CS.D.NZDUSD.CFD.IP',
                                    'USDCAD': 'CS.D.USDCAD.CFD.IP',
                                    'XAUUSD': 'CS.D.USCGC.TODAY.IP',
                                    'XAGUSD': 'CS.D.USCSI.TODAY.IP',
                                }
                                if symbol in ig_symbol_map:
                                    ig_epic = ig_symbol_map[symbol]
                                
                                order_result = ig_conn.place_order(
                                    symbol=ig_epic,
                                    order_type=order_type,
                                    volume=round(adjusted_volume, 2),
                                    stop_loss=trade_params.get('stop_loss', 50),
                                    take_profit=trade_params.get('take_profit', 100),
                                )
                                
                                if order_result.get('success', False):
                                    logger.info(f"✅ Bot {bot_id}: IG order placed on {ig_epic}")
                                else:
                                    last_order_block_reason = f"IG rejected {ig_epic}: {order_result.get('error') or 'unknown error'}"
                                    logger.warning(f"Bot {bot_id}: IG order failed on {ig_epic}: {order_result.get('error')}")
                            except Exception as e:
                                logger.error(f"Bot {bot_id}: IG place_order exception: {e}")
                                last_order_block_reason = f"IG exception on {symbol}: {e}"
                                order_result = {'success': False, 'error': str(e)}
                        elif is_fxcm:
                            # FXCM - place order via REST API (FXCMConnection)
                            try:
                                explicit_fxcm_tradable_keys = _get_fxcm_tradable_symbol_keys(broker_conn=fxcm_conn)
                                if explicit_fxcm_tradable_keys is not None:
                                    symbol_keys = _get_fxcm_symbol_candidate_keys(symbol)
                                    if not (symbol_keys & explicit_fxcm_tradable_keys):
                                        last_order_block_reason = (
                                            f"FXCM rejected {symbol}: symbol is not tradeable/subscribed on the active account"
                                        )
                                        _prune_fxcm_blocked_symbol(
                                            bot_id,
                                            bot_config,
                                            symbol,
                                            broker_conn=fxcm_conn,
                                        )
                                        logger.info(
                                            f"⏭️ Bot {bot_id}: Skipping {symbol} before FXCM order placement - symbol is not tradeable/subscribed on this account"
                                        )
                                        continue

                                # Position limit check
                                max_open = bot_config.get('effectiveMaxOpenPositions') or bot_config.get('maxOpenPositions') or 5
                                tracked_fxcm_positions = bot_config.get('open_positions', {}) if isinstance(bot_config.get('open_positions'), dict) else {}
                                if len(tracked_fxcm_positions) >= int(max_open):
                                    logger.info(f"⏸️ Bot {bot_id}: FXCM position limit reached ({len(tracked_fxcm_positions)}/{max_open})")
                                    continue

                                order_result = fxcm_conn.place_order(
                                    symbol=symbol,
                                    order_type=order_type,
                                    volume=round(adjusted_volume, 2),
                                )

                                if order_result.get('success', False):
                                    logger.info(f"✅ Bot {bot_id}: FXCM order placed on {order_result.get('symbol', symbol)}")
                                else:
                                    err_msg = order_result.get('error') or 'unknown error'
                                    err_msg_lower = str(err_msg).lower()
                                    if (
                                        'maximum quantity violated' in err_msg_lower
                                        or 'ora-20134' in err_msg_lower
                                        or 'insufficient margin' in err_msg_lower
                                        or 'ora-20113' in err_msg_lower
                                    ):
                                        retry_volumes = []
                                        for reduction_factor in (0.5, 0.25, 0.1):
                                            retry_volume = max(0.01, round(float(adjusted_volume or 0.0) * reduction_factor, 2))
                                            if retry_volume < float(adjusted_volume or 0.0) and retry_volume not in retry_volumes:
                                                retry_volumes.append(retry_volume)

                                        for retry_volume in retry_volumes:
                                            logger.warning(
                                                f"↩️ Bot {bot_id}: FXCM order sizing rejected on {symbol}; retrying with smaller volume {retry_volume:.2f}"
                                            )
                                            retry_result = fxcm_conn.place_order(
                                                symbol=symbol,
                                                order_type=order_type,
                                                volume=retry_volume,
                                            )
                                            if retry_result.get('success', False):
                                                order_result = retry_result
                                                adjusted_volume = retry_volume
                                                err_msg = ''
                                                err_msg_lower = ''
                                                logger.info(
                                                    f"✅ Bot {bot_id}: FXCM order placed on {retry_result.get('symbol', symbol)} after downsizing to {retry_volume:.2f}"
                                                )
                                                break

                                            err_msg = retry_result.get('error') or err_msg
                                            err_msg_lower = str(err_msg).lower()

                                    if order_result.get('success', False):
                                        logger.info(f"✅ Bot {bot_id}: FXCM order placed on {order_result.get('symbol', symbol)}")
                                    else:
                                        err_msg = order_result.get('error') or err_msg or 'unknown error'
                                        last_order_block_reason = f"FXCM rejected {symbol}: {err_msg}"
                                        logger.warning(f"Bot {bot_id}: FXCM order failed on {symbol}: {err_msg}")
                                        # Skip symbols that are not subscribed on the account — retrying won't help
                                        is_fxcm_subscription_error = (
                                            ('not available for trading' in err_msg_lower or 'subscription' in err_msg_lower)
                                            and 'maximum quantity violated' not in err_msg_lower
                                            and 'ora-20134' not in err_msg_lower
                                            and 'insufficient margin' not in err_msg_lower
                                            and 'ora-20113' not in err_msg_lower
                                        )
                                        if is_fxcm_subscription_error:
                                            _prune_fxcm_blocked_symbol(
                                                bot_id,
                                                bot_config,
                                                symbol,
                                                broker_conn=fxcm_conn,
                                            )
                                            logger.info(f"⏭️ Bot {bot_id}: Skipping {symbol} — not subscribed on FXCM account (status D/V)")
                                            continue
                            except Exception as e:
                                logger.error(f"Bot {bot_id}: FXCM place_order exception: {e}")
                                last_order_block_reason = f"FXCM exception on {symbol}: {e}"
                                order_result = {'success': False, 'error': str(e)}
                        elif is_mt5:
                            # MT5 - place order with retry/fallback logic
                            # ❌ FIX: Only try fallback for non-critical symbols
                            critical_symbols = {'BTCUSDm', 'ETHUSDm'}
                            if symbol in critical_symbols:
                                symbols_to_try = [symbol]  # NO FALLBACK for BTC/ETH - fail instead
                            else:
                                symbols_to_try = [symbol, 'EURUSDm']  # Fallback only if primary fails
                            
                            # ⏰ POST-CLOSE COOLDOWN: skip re-entry on a symbol whose previous
                            # position was just closed (TP/SL hit OR user manually closed in MT5).
                            # Without this, MT5/Exness bots fire a fresh entry on the very next
                            # cycle and ignore the user's manual close ("keeps coming back").
                            try:
                                _cd_map = bot_config.get('symbol_cooldown_until') or {}
                                _cd_iso = _cd_map.get(symbol)
                                if _cd_iso:
                                    _cd_until = datetime.fromisoformat(str(_cd_iso))
                                    _now_dt = datetime.now()
                                    if _now_dt < _cd_until:
                                        _rem_min = max(0, int((_cd_until - _now_dt).total_seconds() / 60))
                                        last_order_block_reason = (
                                            f"{symbol} on post-close cooldown (~{_rem_min}m remaining)"
                                        )
                                        logger.info(
                                            f"⏸️ Bot {bot_id}: {symbol} on post-close cooldown "
                                            f"(~{_rem_min}m remaining) - skipping new entry"
                                        )
                                        continue
                                    else:
                                        # cooldown expired → clean up
                                        _cd_map.pop(symbol, None)
                                        bot_config['symbol_cooldown_until'] = _cd_map
                            except Exception as _cd_check_e:
                                logger.debug(f"Bot {bot_id}: cooldown check error for {symbol}: {_cd_check_e}")

                            # ✅ POSITION LIMIT CHECK: Enforce maxOpenPositions to prevent unlimited trades
                            max_open = bot_config.get('effectiveMaxOpenPositions') or bot_config.get('maxOpenPositions') or 5
                            max_per_symbol = bot_config.get('effectiveMaxPositionsPerSymbol') or bot_config.get('maxPositionsPerSymbol') or max_open
                            allowed_positions_on_symbol = max_per_symbol + (PYRAMID_ADDON_MAX_PER_SYMBOL if pyramid_decision['allowed'] else 0)
                            existing_positions = mt5_conn.get_positions()
                            bot_id_short = bot_id.split('_')[-1][:8]
                            comment_short = f'ZBot{bot_id_short}'
                            order_comment = f"{comment_short}-P1" if pyramid_decision['allowed'] else comment_short
                            
                            # Count positions belonging to THIS bot (by comment) and also by tracked open_positions
                            bot_position_count = 0
                            bot_positions_on_symbol = 0
                            tracked_open = bot_config.get('open_positions', {})
                            tracked_tickets = set(tracked_open.keys())
                            
                            for ep in existing_positions:
                                ep_comment = ep.get('comment', '') or ''
                                ep_ticket = str(ep.get('ticket', ''))
                                ep_symbol = ep.get('symbol', '')
                                # Match by comment OR by tracked ticket
                                is_this_bot = comment_short in ep_comment or ep_ticket in tracked_tickets
                                if is_this_bot:
                                    bot_position_count += 1
                                    if ep_symbol == symbol:
                                        bot_positions_on_symbol += 1
                            
                            # Respect the bot's configured per-symbol position cap.
                            if bot_positions_on_symbol >= allowed_positions_on_symbol:
                                logger.info(
                                    f"📌 Bot {bot_id}: Already has {bot_positions_on_symbol} open position(s) on {symbol} "
                                    f"(limit {allowed_positions_on_symbol}) - skipping"
                                )
                                continue
                            
                            # Skip if bot has reached max open positions overall
                            if bot_position_count >= max_open:
                                logger.info(f"📌 Bot {bot_id}: At max open positions ({bot_position_count}/{max_open}) - skipping new trade on {symbol}")
                                continue
                            
                            # ✅ Calculate SL/TP price levels for MT5
                            sl_price = None
                            tp_price = None
                            try:
                                if use_rest_trading:
                                    # REST path: get price via MetaAPI bridge (no local mt5 module)
                                    _price_data = mt5_conn.get_symbol_price(symbol)
                                    if _price_data and _price_data.get('bid', 0) > 0:
                                        _bid = _price_data['bid']
                                        _ask = _price_data['ask']
                                        _spread = _ask - _bid
                                        from rest_price_feed import get_pip_size
                                        _point = get_pip_size(symbol)
                                        _sl_pips = trade_params.get('stop_loss', 50)
                                        _tp_pips = trade_params.get('take_profit', 100)
                                        _sl_dist = _sl_pips * _point
                                        _tp_dist = _tp_pips * _point
                                        # Tightened: SL min 2x spread (was 3x) to reduce per-trade loss
                                        _spread_multiplier_sl = 2
                                        _spread_multiplier_tp = 2.5 if bot_config.get('profile') == 'small_account' else 3.5
                                        _sl_dist = max(_sl_dist, _spread * _spread_multiplier_sl)
                                        _tp_dist = max(_tp_dist, _spread * _spread_multiplier_tp)
                                        _digits = 5 if _point < 0.01 else 2  # forex=5, gold/indices=2
                                        if order_type == 'BUY':
                                            sl_price = round(_ask - _sl_dist, _digits)
                                            tp_price = round(_ask + _tp_dist, _digits)
                                        else:
                                            sl_price = round(_bid + _sl_dist, _digits)
                                            tp_price = round(_bid - _tp_dist, _digits)
                                        logger.info(f"📐 Bot {bot_id}: REST SL={sl_price}, TP={tp_price} (spread={_spread:.5f})")
                                else:
                                    _tick = mt5_conn.mt5.symbol_info_tick(symbol)
                                    _sym_info = mt5_conn.mt5.symbol_info(symbol)
                                    if _tick and _sym_info:
                                        _point = _sym_info.point
                                        _spread = _tick.ask - _tick.bid
                                        _sl_pips = trade_params.get('stop_loss', 50)
                                        _tp_pips = trade_params.get('take_profit', 100)
                                        _sl_dist = _sl_pips * _point
                                        _tp_dist = _tp_pips * _point
                                        # Tightened: SL min 2x spread (was 3x) to reduce per-trade loss
                                        _spread_multiplier_sl = 2
                                        _spread_multiplier_tp = 2.5 if bot_config.get('profile') == 'small_account' else 3.5
                                        # Ensure SL is at least 2x spread, TP at least (2.5-3.5)x spread
                                        _sl_dist = max(_sl_dist, _spread * _spread_multiplier_sl)
                                        _tp_dist = max(_tp_dist, _spread * _spread_multiplier_tp)
                                        if order_type == 'BUY':
                                            sl_price = round(_tick.ask - _sl_dist, _sym_info.digits)
                                            tp_price = round(_tick.ask + _tp_dist, _sym_info.digits)
                                        else:
                                            sl_price = round(_tick.bid + _sl_dist, _sym_info.digits)
                                            tp_price = round(_tick.bid - _tp_dist, _sym_info.digits)
                                        logger.info(f"📐 Bot {bot_id}: SL={sl_price}, TP={tp_price} (spread={_spread:.2f}, sl_dist={_sl_dist:.2f}, tp_dist={_tp_dist:.2f})")
                            except Exception as e:
                                logger.warning(f"Bot {bot_id}: Could not calculate SL/TP: {e}")
                            
                            # ✅ CRITICAL: Ensure SL/TP are ALWAYS set - positions without SL/TP never close
                            if sl_price is None or tp_price is None:
                                try:
                                    _tick_fb = mt5_conn.mt5.symbol_info_tick(symbol) if not use_rest_trading else None
                                    if _tick_fb:
                                        _price_fb = _tick_fb.ask if order_type == 'BUY' else _tick_fb.bid
                                        _sym_fb = mt5_conn.mt5.symbol_info(symbol)
                                        _point_fb = _sym_fb.point if _sym_fb else 0.00001
                                        _digits_fb = _sym_fb.digits if _sym_fb else 5
                                        # Default SL: 25 pips (was 50), TP: 75 pips — tighter to reduce max loss
                                        if order_type == 'BUY':
                                            sl_price = sl_price or round(_price_fb - 25 * _point_fb, _digits_fb)
                                            tp_price = tp_price or round(_price_fb + 75 * _point_fb, _digits_fb)
                                        else:
                                            sl_price = sl_price or round(_price_fb + 25 * _point_fb, _digits_fb)
                                            tp_price = tp_price or round(_price_fb - 75 * _point_fb, _digits_fb)
                                        logger.info(f"📐 Bot {bot_id}: Fallback SL={sl_price}, TP={tp_price} (default 25/75 pips)")
                                except Exception as fb_e:
                                    logger.warning(f"Bot {bot_id}: Fallback SL/TP calculation also failed: {fb_e}")
                            
                            for index, attempt_symbol in enumerate(symbols_to_try):
                                try:
                                    order_result = mt5_conn.place_order(
                                        symbol=attempt_symbol,
                                        order_type=order_type,
                                        volume=adjusted_volume,
                                        comment=order_comment,
                                        stopLoss=sl_price,
                                        takeProfit=tp_price
                                    )
                                    
                                    if order_result.get('success', False):
                                        # ✅ CRITICAL FIX: Log WARNING if traded symbol differs from requested
                                        actual_symbol = order_result.get('symbol', attempt_symbol)
                                        if actual_symbol != symbol:
                                            logger.warning(f"⚠️ SYMBOL MISMATCH - Bot {bot_id}: Requested {symbol} but EXECUTED on {actual_symbol}")
                                            logger.warning(f"   This may result in unexpected profits/losses if symbols trade differently")
                                        logger.info(f"✅ Bot {bot_id}: Order placed successfully on {actual_symbol}")
                                        symbol = actual_symbol  # Update to actual traded symbol
                                        break
                                    else:
                                        # ==================== CRITICAL SYMBOL RETRY LOGIC ====================
                                        # If critical symbol (ETHUSDm, BTCUSDm) is temporarily unavailable,
                                        # wait the suggested time and retry (don't give up immediately)
                                        retry_after = order_result.get('retry_after_seconds')
                                        is_critical = attempt_symbol in critical_symbols
                                        
                                        if is_critical and retry_after and retry_after > 0:
                                            logger.warning(f"⏳ Bot {bot_id}: {attempt_symbol} not yet available (retry in {retry_after}s)...")
                                            logger.warning(f"   Symbol is loading. MT5 terminal may still be initializing symbols.")
                                            # Wait for symbol to load, then retry immediately (max 3 retries)
                                            total_retries = 3
                                            for retry_num in range(total_retries):
                                                time.sleep(retry_after)
                                                logger.info(f"🔄 Bot {bot_id}: Retry {retry_num + 1}/{total_retries} for {attempt_symbol}...")
                                                retry_result = mt5_conn.place_order(
                                                    symbol=attempt_symbol,
                                                    order_type=order_type,
                                                    volume=adjusted_volume,
                                                    comment=order_comment,
                                                    stopLoss=sl_price,
                                                    takeProfit=tp_price
                                                )
                                                if retry_result.get('success', False):
                                                    logger.info(f"✅ Bot {bot_id}: {attempt_symbol} order placed successfully after retry {retry_num + 1}")
                                                    order_result = retry_result
                                                    symbol = attempt_symbol
                                                    break
                                                elif retry_num < total_retries - 1:
                                                    retry_wait = retry_result.get('retry_after_seconds', retry_after)
                                                    logger.warning(f"   Retry {retry_num + 1} failed, retrying again...")
                                                    continue
                                            
                                            # After retries, check if we finally succeeded
                                            if order_result.get('success', False):
                                                break
                                            else:
                                                # All retries failed - log but continue (don't trade this cycle)
                                                logger.error(f"❌ Bot {bot_id}: {attempt_symbol} unavailable after {total_retries} retries: {order_result.get('error')}")
                                                order_result = {'success': False, 'error': f'{attempt_symbol} still unavailable after retries'}
                                                break
                                        else:
                                            # Standard error handling (not a retry-able initialization delay)
                                            error_msg = order_result.get('error', '').lower()
                                            is_last_attempt = (index == len(symbols_to_try) - 1)
                                            
                                            if ('not found' in error_msg or 'disconnected' in error_msg or 'order_send failed' in error_msg) and not is_last_attempt:
                                                logger.warning(f"Bot {bot_id}: Order failed on {attempt_symbol} ({order_result.get('error')}) - trying {symbols_to_try[index+1]}...")
                                                continue
                                            else:
                                                # Don't log CRITICAL for pause conditions (position limit, market closed, etc.)
                                                if attempt_symbol in critical_symbols and not order_result.get('is_paused'):
                                                    logger.error(f"❌ CRITICAL SYMBOL FAILED: Bot {bot_id}: {attempt_symbol} failed and NO fallback allowed: {order_result.get('error')}")
                                                last_order_block_reason = f"{broker_type} rejected {attempt_symbol}: {order_result.get('error') or 'unknown error'}"
                                                logger.warning(f"Bot {bot_id}: Order failed on {attempt_symbol}: {order_result.get('error')}")
                                                break
                                except Exception as e:
                                    logger.error(f"Bot {bot_id}: Exception placing order on {attempt_symbol}: {e}")
                                    last_order_block_reason = f"{broker_type} exception on {attempt_symbol}: {e}"
                                    if index < len(symbols_to_try) - 1:
                                        continue
                                    break
                        else:
                            try:
                                order_kwargs = {
                                    'quote_amount': float(fixed_trade_amount or 0.0),
                                    'market_price': float(market_data.get('current_price', 0.0) or 0.0),
                                }
                                if canonicalize_broker_name(broker_type) == 'Binance' and binance_market_name == 'futures':
                                    if futures_controls.get('enabled'):
                                        order_kwargs['exchange_leverage'] = int(futures_controls.get('exchangeLeverage') or BINANCE_FUTURES_DEFAULT_BASE_LEVERAGE)
                                        order_kwargs['margin_type'] = str(futures_controls.get('marginType') or 'ISOLATED')
                                        bot_config['effectiveBinanceFuturesLeverage'] = int(order_kwargs['exchange_leverage'])
                                        bot_config['lastBinanceFuturesLeverageReason'] = futures_controls.get('reason')

                                order_result = active_conn.place_order(
                                    symbol=symbol,
                                    order_type=order_type,
                                    volume=round(adjusted_volume, 4),
                                    **order_kwargs,
                                )
                                if order_result.get('success', False):
                                    logger.info(f"✅ Bot {bot_id}: {broker_type} order placed on {order_result.get('symbol', symbol)}")
                                else:
                                    last_order_block_reason = f"{broker_type} rejected {symbol}: {order_result.get('error') or 'unknown error'}"
                                    logger.warning(f"Bot {bot_id}: {broker_type} order failed on {symbol}: {order_result.get('error')}")
                            except Exception as e:
                                logger.error(f"Bot {bot_id}: {broker_type} place_order exception: {e}")
                                last_order_block_reason = f"{broker_type} exception on {symbol}: {e}"
                                order_result = {'success': False, 'error': str(e)}
                        
                        # CHECK FOR MARKET PAUSE CONDITIONS - Log pause events
                        if order_result and order_result.get('is_paused', False):
                            pause_type = order_result.get('pause_type', 'UNKNOWN')
                            pause_reason = order_result.get('pause_reason', 'Market paused')
                            retcode = order_result.get('retcode', 0)
                            error_msg = order_result.get('original_comment', order_result.get('error', 'Unknown error'))
                            
                            # Log pause event to database
                            pause_id = log_pause_event(
                                bot_id=bot_id,
                                user_id=user_id,
                                symbol=symbol,
                                pause_type=pause_type,
                                retcode=retcode,
                                error_message=error_msg,
                                pause_reason=pause_reason
                            )
                            
                            logger.warning(f"🔒 Bot {bot_id}: Market pause event recorded (pause_id={pause_id})")
                            
                            # Update bot status to indicate pause
                            bot_config['lastPauseEvent'] = {
                                'symbol': symbol,
                                'pause_type': pause_type,
                                'pause_reason': pause_reason,
                                'detected_at': datetime.now().isoformat(),
                                'pause_id': pause_id
                            }
                            
                            # Skip this trade but continue to next symbol (don't stop bot)
                            continue
                        
                        if order_result and order_result.get('success', False):
                            # Get the order ticket/deal_id for precise matching
                            order_ticket = str(order_result.get('orderId') or order_result.get('deal_id') or '')

                            if (
                                broker_type == 'Binance'
                                and active_conn
                                and getattr(active_conn, 'market', 'spot') != 'futures'
                            ):
                                synthetic_ticket = str(order_result.get('orderId') or '')
                                synthetic_volume = _safe_float(
                                    order_result.get('executedQty'),
                                    adjusted_volume,
                                )
                                synthetic_price = _safe_float(
                                    market_data.get('current_price', 0.0),
                                    0.0,
                                )
                                inventory_snapshot = _get_binance_spot_inventory_snapshot(active_conn, order_result.get('symbol', symbol), synthetic_price)
                                base_asset = inventory_snapshot.get('baseAsset') or order_result.get('symbol', symbol)
                                synthetic_time = order_result.get('transactTime')
                                if synthetic_time:
                                    try:
                                        synthetic_time = datetime.fromtimestamp(
                                            float(synthetic_time) / 1000.0
                                        ).isoformat()
                                    except Exception:
                                        synthetic_time = datetime.now().isoformat()
                                else:
                                    synthetic_time = datetime.now().isoformat()

                                if order_type.upper() == 'BUY':
                                    pos_ticket = f"SPOT-{base_asset}-{str(bot_id)[-8:]}"
                                    if 'open_positions' not in bot_config:
                                        bot_config['open_positions'] = {}

                                    # Translate strategy SL/TP "pips" into absolute price levels
                                    # so the position tracker can auto-close Binance spot trades
                                    # when price hits TP/SL (Binance spot has no broker-side
                                    # SL/TP — we must enforce it ourselves).
                                    try:
                                        _spot_pip_distance = _compute_spot_pip_distance(
                                            order_result.get('symbol', symbol),
                                            synthetic_price,
                                        )
                                    except Exception:
                                        _spot_pip_distance = 0.0
                                    _sl_price_level = (
                                        round(synthetic_price - sl_pips * _spot_pip_distance, 8)
                                        if sl_pips > 0 and _spot_pip_distance > 0 and synthetic_price > 0
                                        else 0.0
                                    )
                                    _tp_price_level = (
                                        round(synthetic_price + tp_pips * _spot_pip_distance, 8)
                                        if tp_pips > 0 and _spot_pip_distance > 0 and synthetic_price > 0
                                        else 0.0
                                    )

                                    bot_config['open_positions'][str(pos_ticket)] = {
                                        'ticket': pos_ticket,
                                        'symbol': order_result.get('symbol', symbol),
                                        'type': order_type,
                                        'volume': synthetic_volume,
                                        'entryPrice': synthetic_price,
                                        'currentPrice': synthetic_price,
                                        'profit': 0.0,
                                        'status': 'open',
                                        'entryTime': synthetic_time,
                                        'botId': bot_id,
                                        'cycle': trade_cycle,
                                        'strategy': strategy_name,
                                        'broker': broker_type,
                                        'slPips': sl_pips,
                                        'tpPips': tp_pips,
                                        'stopLossPrice': _sl_price_level,
                                        'takeProfitPrice': _tp_price_level,
                                        'pipDistance': _spot_pip_distance,
                                        'isPyramidAddon': bool(pyramid_decision['allowed']),
                                        'pyramidParentTicket': pyramid_decision.get('parentTicket'),
                                        'pyramidReason': pyramid_decision.get('reason'),
                                        'peakProfit': 0.0,
                                        'profitProtectionArmed': False,
                                        'lockedProfitFloor': 0.0,
                                    }

                                    open_trade = {
                                        'ticket': pos_ticket,
                                        'symbol': order_result.get('symbol', symbol),
                                        'type': order_type,
                                        'volume': synthetic_volume,
                                        'entryPrice': synthetic_price,
                                        'currentPrice': synthetic_price,
                                        'profit': 0.0,
                                        'entryTime': synthetic_time,
                                        'time': synthetic_time,
                                        'timestamp': int(datetime.now().timestamp() * 1000),
                                        'botId': bot_id,
                                        'cycle': trade_cycle,
                                        'strategy': strategy_name,
                                        'isPyramidAddon': bool(pyramid_decision['allowed']),
                                        'pyramidParentTicket': pyramid_decision.get('parentTicket'),
                                        'isWinning': False,
                                        'status': 'open',
                                        'source': 'REAL_BINANCE_SPOT_OPEN',
                                        'broker': broker_type,
                                    }

                                    try:
                                        trade_conn = build_sqlite_connection(timeout=30.0)
                                        trade_cursor = trade_conn.cursor()
                                        trade_id = f"trade_{int(datetime.now().timestamp()*1000)}_{bot_id[-8:]}"
                                        trade_cursor.execute('''
                                            INSERT INTO trades (trade_id, bot_id, user_id, symbol, order_type, volume, price, profit, ticket, time_open, time_close, status, created_at, trade_data, timestamp)
                                            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                                        ''', (
                                            trade_id,
                                            bot_id,
                                            user_id,
                                            open_trade['symbol'],
                                            open_trade['type'],
                                            open_trade['volume'],
                                            open_trade['entryPrice'],
                                            0,
                                            str(open_trade['ticket']),
                                            open_trade['entryTime'],
                                            None,
                                            'open',
                                            datetime.now().isoformat(),
                                            json.dumps(open_trade),
                                            open_trade['timestamp'],
                                        ))
                                        trade_conn.commit()
                                        trade_conn.close()
                                    except Exception as e:
                                        logger.error(f"Bot {bot_id}: Error storing immediate Binance spot buy fill: {e}")

                                    trade_history = bot_config.setdefault('tradeHistory', [])
                                    existing_index = next(
                                        (index for index, existing in enumerate(trade_history) if str(existing.get('ticket')) == str(open_trade['ticket'])),
                                        None,
                                    )
                                    if existing_index is None:
                                        trade_history.append(open_trade)
                                        bot_config['totalTrades'] = bot_config.get('totalTrades', 0) + 1
                                    else:
                                        trade_history[existing_index] = {**trade_history[existing_index], **open_trade}

                                    logger.info(
                                        f"✅ Bot {bot_id}: Recorded Binance spot BUY as open position after broker confirmation | "
                                        f"{open_trade['symbol']} {open_trade['volume']:.6f} | Ticket: {open_trade['ticket']}"
                                    )

                                    # 🔒 Persist runtime state immediately so open_positions/tradeHistory survive a crash
                                    try:
                                        persist_bot_runtime_state(bot_id, force=True)
                                    except Exception as _persist_buy_err:
                                        logger.error(f"Bot {bot_id}: Failed to persist runtime state after BUY: {_persist_buy_err}")
                                else:
                                    # SELL — look up the matching open position to calculate real P&L
                                    sell_symbol = order_result.get('symbol', symbol)
                                    sell_base = base_asset  # e.g. 'BTC' for BTCUSDT
                                    open_ticket = f"SPOT-{sell_base}-{str(bot_id)[-8:]}"
                                    open_positions_map = bot_config.get('open_positions', {}) or {}
                                    open_pos = open_positions_map.get(open_ticket, {})
                                    # Legacy fallback: pre-namespacing positions stored as bare "SPOT-{base}"
                                    if not open_pos:
                                        legacy_ticket = f"SPOT-{sell_base}"
                                        open_pos = open_positions_map.get(legacy_ticket, {})
                                        if open_pos:
                                            open_ticket = legacy_ticket
                                    entry_price = _safe_float(
                                        open_pos.get('entryPrice', open_pos.get('price', 0.0)),
                                        0.0,
                                    )
                                    open_entry_time = open_pos.get('entryTime') or synthetic_time
                                    sell_volume = synthetic_volume
                                    # If runtime open_pos missing entry, fall back to DB
                                    if entry_price == 0:
                                        try:
                                            _ep_conn = build_sqlite_connection(timeout=10.0)
                                            _ep_cur = _ep_conn.cursor()
                                            _ep_cur.execute(
                                                "SELECT price, time_open FROM trades WHERE ticket = ? AND bot_id = ? AND status = 'open' ORDER BY created_at DESC LIMIT 1",
                                                (open_ticket, bot_id)
                                            )
                                            _ep_row = _ep_cur.fetchone()
                                            _ep_conn.close()
                                            if _ep_row and _ep_row[0]:
                                                entry_price = _safe_float(_ep_row[0], 0.0)
                                                open_entry_time = _ep_row[1] or open_entry_time
                                        except Exception:
                                            pass
                                    # Calculate P&L: (exitPrice - entryPrice) * volume (USDT-quoted)
                                    if entry_price > 0 and synthetic_price > 0:
                                        realized_profit = round((synthetic_price - entry_price) * sell_volume, 4)
                                    else:
                                        realized_profit = 0.0

                                    closed_trade = {
                                        'ticket': open_ticket,
                                        'symbol': sell_symbol,
                                        'type': order_type,
                                        'volume': sell_volume,
                                        'entryPrice': entry_price if entry_price > 0 else synthetic_price,
                                        'exitPrice': synthetic_price,
                                        'currentPrice': synthetic_price,
                                        'profit': realized_profit,
                                        'entryTime': open_entry_time,
                                        'exitTime': synthetic_time,
                                        'time': synthetic_time,
                                        'timestamp': int(datetime.now().timestamp() * 1000),
                                        'botId': bot_id,
                                        'cycle': trade_cycle,
                                        'strategy': strategy_name,
                                        'closeReason': f"BINANCE_SPOT_SELL_EXECUTED",
                                        'isWinning': realized_profit > 0,
                                        'status': 'closed',
                                        'source': 'REAL_BINANCE_SPOT_FILL',
                                        'broker': broker_type,
                                    }

                                    # Update the existing open DB row if found, else insert closed row
                                    try:
                                        trade_conn = build_sqlite_connection(timeout=30.0)
                                        trade_cursor = trade_conn.cursor()
                                        trade_cursor.execute(
                                            '''UPDATE trades SET profit = ?, status = 'closed', time_close = ?,
                                               updated_at = ?
                                               WHERE ticket = ? AND bot_id = ? AND status = 'open' ''',
                                            (realized_profit, synthetic_time, datetime.now().isoformat(),
                                             open_ticket, bot_id)
                                        )
                                        if trade_cursor.rowcount == 0:
                                            trade_id = f"trade_{int(datetime.now().timestamp()*1000)}_{bot_id[-8:]}"
                                            trade_cursor.execute('''
                                                INSERT INTO trades (trade_id, bot_id, user_id, symbol, order_type, volume, price, profit, ticket, time_open, time_close, status, created_at, trade_data, timestamp)
                                                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                                            ''', (
                                                trade_id, bot_id, user_id,
                                                closed_trade['symbol'], closed_trade['type'],
                                                closed_trade['volume'], closed_trade['entryPrice'],
                                                realized_profit, open_ticket,
                                                closed_trade['entryTime'], closed_trade['exitTime'],
                                                'closed', datetime.now().isoformat(),
                                                json.dumps(closed_trade),
                                                closed_trade['timestamp'],
                                            ))
                                        trade_conn.commit()
                                        trade_conn.close()
                                    except Exception as e:
                                        logger.error(f"Bot {bot_id}: Error storing immediate Binance spot SELL: {e}")

                                    # Remove from runtime open_positions
                                    if open_ticket in bot_config.get('open_positions', {}):
                                        del bot_config['open_positions'][open_ticket]

                                    trade_history = bot_config.setdefault('tradeHistory', [])
                                    existing_index = next(
                                        (index for index, existing in enumerate(trade_history) if str(existing.get('ticket')) == open_ticket),
                                        None,
                                    )
                                    if existing_index is None:
                                        trade_history.append(closed_trade)
                                        bot_config['totalTrades'] = bot_config.get('totalTrades', 0) + 1
                                    else:
                                        trade_history[existing_index] = {**trade_history[existing_index], **closed_trade}

                                    logger.info(
                                        f"✅ Bot {bot_id}: Recorded Binance spot SELL with P&L | "
                                        f"{sell_symbol} {sell_volume:.6f} | Entry: {entry_price:.4f} Exit: {synthetic_price:.4f} "
                                        f"Profit: {realized_profit:.4f} USDT | Ticket: {open_ticket}"
                                    )

                                    # 🔒 Persist runtime state immediately so closed trade history survives a crash
                                    try:
                                        persist_bot_runtime_state(bot_id, force=True)
                                    except Exception as _persist_sell_err:
                                        logger.error(f"Bot {bot_id}: Failed to persist runtime state after SELL: {_persist_sell_err}")
                                trades_placed += 1
                                continue
                            
                            # Get current position info (broker-aware)
                            positions = []
                            if is_ig and ig_conn:
                                positions = ig_conn.get_positions()
                            elif is_fxcm and fxcm_conn:
                                positions = fxcm_conn.get_positions()
                            elif is_mt5 and mt5_conn:
                                positions = mt5_conn.get_positions()
                            elif active_conn:
                                positions = active_conn.get_positions()

                            if (
                                not positions
                                and broker_type == 'Binance'
                                and active_conn
                                and getattr(active_conn, 'market', 'spot') != 'futures'
                            ):
                                synthetic_ticket = str(order_result.get('orderId') or '')
                                synthetic_volume = _safe_float(
                                    order_result.get('executedQty'),
                                    adjusted_volume,
                                )
                                synthetic_price = _safe_float(
                                    market_data.get('current_price', 0.0),
                                    0.0,
                                )
                                synthetic_time = order_result.get('transactTime')
                                if synthetic_time:
                                    try:
                                        synthetic_time = datetime.fromtimestamp(
                                            float(synthetic_time) / 1000.0
                                        ).isoformat()
                                    except Exception:
                                        synthetic_time = datetime.now().isoformat()
                                else:
                                    synthetic_time = datetime.now().isoformat()

                                closed_trade = {
                                    'ticket': synthetic_ticket or f"BINANCE-SPOT-{int(datetime.now().timestamp() * 1000)}",
                                    'symbol': order_result.get('symbol', symbol),
                                    'type': order_type,
                                    'volume': synthetic_volume,
                                    'entryPrice': synthetic_price,
                                    'exitPrice': synthetic_price,
                                    'currentPrice': synthetic_price,
                                    'profit': 0.0,
                                    'entryTime': synthetic_time,
                                    'exitTime': synthetic_time,
                                    'time': synthetic_time,
                                    'timestamp': int(datetime.now().timestamp() * 1000),
                                    'botId': bot_id,
                                    'cycle': trade_cycle,
                                    'strategy': strategy_name,
                                    'closeReason': f"BINANCE_SPOT_{order_type.upper()}_EXECUTED_NO_POSITION_SNAPSHOT",
                                    'isWinning': False,
                                    'status': 'closed',
                                    'source': 'REAL_BINANCE_SPOT_FILL',
                                    'broker': broker_type,
                                }

                                try:
                                    trade_conn = build_sqlite_connection(timeout=30.0)
                                    trade_cursor = trade_conn.cursor()
                                    trade_id = f"trade_{int(datetime.now().timestamp()*1000)}_{bot_id[-8:]}"
                                    trade_cursor.execute('''
                                        INSERT INTO trades (trade_id, bot_id, user_id, symbol, order_type, volume, price, profit, ticket, time_open, time_close, status, created_at, trade_data, timestamp)
                                        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                                    ''', (
                                        trade_id,
                                        bot_id,
                                        user_id,
                                        closed_trade['symbol'],
                                        closed_trade['type'],
                                        closed_trade['volume'],
                                        closed_trade['entryPrice'],
                                        0,
                                        str(closed_trade['ticket']),
                                        closed_trade['entryTime'],
                                        closed_trade['exitTime'],
                                        'closed',
                                        datetime.now().isoformat(),
                                        json.dumps(closed_trade),
                                        closed_trade['timestamp'],
                                    ))
                                    trade_conn.commit()
                                    trade_conn.close()
                                except Exception as e:
                                    logger.error(f"Bot {bot_id}: Error storing Binance spot fill without positions: {e}")

                                trade_history = bot_config.setdefault('tradeHistory', [])
                                existing_index = next(
                                    (index for index, existing in enumerate(trade_history) if str(existing.get('ticket')) == str(closed_trade['ticket'])),
                                    None,
                                )
                                if existing_index is None:
                                    trade_history.append(closed_trade)
                                    bot_config['totalTrades'] = bot_config.get('totalTrades', 0) + 1
                                else:
                                    trade_history[existing_index] = {**trade_history[existing_index], **closed_trade}

                                logger.info(
                                    f"✅ Bot {bot_id}: Recorded Binance spot {order_type.upper()} fill without broker position snapshot | "
                                    f"{closed_trade['symbol']} {closed_trade['volume']:.6f} | Ticket: {closed_trade['ticket']}"
                                )
                                trades_placed += 1
                                continue
                            
                            if positions:
                                matched_pos = None
                                matched_by_ticket = False
                                
                                # 1. Try exact ticket/deal_id match (precise)
                                if order_ticket:
                                    for pos in positions:
                                        pos_ticket = str(pos.get('ticket') or pos.get('deal_id', ''))
                                        if pos_ticket and pos_ticket == order_ticket:
                                            matched_pos = pos
                                            matched_by_ticket = True
                                            break
                                
                                # 2. Fallback: match by symbol+direction
                                if not matched_pos:
                                    for pos in positions:
                                        pos_symbol = pos.get('symbol') or pos.get('instrument') or pos.get('epic', '')
                                        pos_type = pos.get('type') or pos.get('direction', '')
                                        if (pos_symbol == symbol or symbol in pos_symbol) and pos_type.upper() == order_type.upper():
                                            matched_pos = pos
                                            break

                                if (
                                    not matched_pos
                                    and broker_type == 'Binance'
                                    and active_conn
                                    and getattr(active_conn, 'market', 'spot') != 'futures'
                                ):
                                    synthetic_ticket = str(order_result.get('orderId') or '')
                                    synthetic_volume = _safe_float(
                                        order_result.get('executedQty'),
                                        adjusted_volume,
                                    )
                                    synthetic_price = _safe_float(
                                        market_data.get('current_price', 0.0),
                                        0.0,
                                    )
                                    synthetic_time = order_result.get('transactTime')
                                    if synthetic_time:
                                        try:
                                            synthetic_time = datetime.fromtimestamp(
                                                float(synthetic_time) / 1000.0
                                            ).isoformat()
                                        except Exception:
                                            synthetic_time = datetime.now().isoformat()
                                    else:
                                        synthetic_time = datetime.now().isoformat()

                                    closed_trade = {
                                        'ticket': synthetic_ticket or f"BINANCE-SPOT-{int(datetime.now().timestamp() * 1000)}",
                                        'symbol': order_result.get('symbol', symbol),
                                        'type': order_type,
                                        'volume': synthetic_volume,
                                        'entryPrice': synthetic_price,
                                        'exitPrice': synthetic_price,
                                        'currentPrice': synthetic_price,
                                        'profit': 0.0,
                                        'entryTime': synthetic_time,
                                        'exitTime': synthetic_time,
                                        'time': synthetic_time,
                                        'timestamp': int(datetime.now().timestamp() * 1000),
                                        'botId': bot_id,
                                        'cycle': trade_cycle,
                                        'strategy': strategy_name,
                                        'closeReason': f"BINANCE_SPOT_{order_type.upper()}_EXECUTED_UNMATCHED",
                                        'isWinning': False,
                                        'status': 'closed',
                                        'source': 'REAL_BINANCE_SPOT_FILL',
                                        'broker': broker_type,
                                    }

                                    try:
                                        trade_conn = build_sqlite_connection(timeout=30.0)
                                        trade_cursor = trade_conn.cursor()
                                        trade_id = f"trade_{int(datetime.now().timestamp()*1000)}_{bot_id[-8:]}"
                                        trade_cursor.execute('''
                                            INSERT INTO trades (trade_id, bot_id, user_id, symbol, order_type, volume, price, profit, ticket, time_open, time_close, status, created_at, trade_data, timestamp)
                                            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                                        ''', (
                                            trade_id,
                                            bot_id,
                                            user_id,
                                            closed_trade['symbol'],
                                            closed_trade['type'],
                                            closed_trade['volume'],
                                            closed_trade['entryPrice'],
                                            0,
                                            str(closed_trade['ticket']),
                                            closed_trade['entryTime'],
                                            closed_trade['exitTime'],
                                            'closed',
                                            datetime.now().isoformat(),
                                            json.dumps(closed_trade),
                                            closed_trade['timestamp'],
                                        ))
                                        trade_conn.commit()
                                        trade_conn.close()
                                    except Exception as e:
                                        logger.error(f"Bot {bot_id}: Error storing Binance spot sell trade: {e}")

                                    trade_history = bot_config.setdefault('tradeHistory', [])
                                    existing_index = next(
                                        (index for index, existing in enumerate(trade_history) if str(existing.get('ticket')) == str(closed_trade['ticket'])),
                                        None,
                                    )
                                    if existing_index is None:
                                        trade_history.append(closed_trade)
                                        bot_config['totalTrades'] = bot_config.get('totalTrades', 0) + 1
                                    else:
                                        trade_history[existing_index] = {**trade_history[existing_index], **closed_trade}

                                    logger.info(
                                        f"✅ Bot {bot_id}: Recorded Binance spot {order_type.upper()} fill without runtime position match | "
                                        f"{closed_trade['symbol']} {closed_trade['volume']:.6f} | Ticket: {closed_trade['ticket']}"
                                    )
                                    trades_placed += 1
                                    continue
                                
                                if matched_pos:
                                    pos_symbol = matched_pos.get('symbol') or matched_pos.get('instrument') or symbol
                                    pos_type = matched_pos.get('type') or matched_pos.get('direction', order_type)
                                    pos_ticket = matched_pos.get('ticket') or matched_pos.get('deal_id', order_ticket)
                                    current_profit = matched_pos.get('profit') or matched_pos.get('pnl') or 0
                                    current_price = matched_pos.get('currentPrice') or matched_pos.get('marketPrice') or matched_pos.get('price_current') or 0
                                    
                                    # ============ TRACK AS OPEN POSITION — DO NOT RECORD P&L YET ============
                                    # The position was just opened, P&L is ~$0 (spread only).
                                    # Real P&L will be recorded when the position closes (via TP/SL or manual close).
                                    # Store in bot's open_positions tracker for monitoring.
                                    if 'open_positions' not in bot_config:
                                        bot_config['open_positions'] = {}
                                    
                                    bot_config['open_positions'][str(pos_ticket)] = {
                                        'ticket': pos_ticket,
                                        'symbol': pos_symbol,
                                        'type': pos_type,
                                        'volume': matched_pos.get('volume') or matched_pos.get('size', 0),
                                        'entryPrice': matched_pos.get('openPrice') or matched_pos.get('level', 0),
                                        'currentPrice': current_price,
                                        'profit': round(current_profit, 2),
                                        'status': 'open',
                                        'entryTime': matched_pos.get('openTime', datetime.now().isoformat()),
                                        'botId': bot_id,
                                        'cycle': trade_cycle,
                                        'strategy': strategy_name,
                                        'broker': broker_type,
                                        'isPyramidAddon': bool(pyramid_decision['allowed']),
                                        'pyramidParentTicket': pyramid_decision.get('parentTicket'),
                                        'pyramidReason': pyramid_decision.get('reason'),
                                        'peakProfit': round(current_profit, 2),
                                        'profitProtectionArmed': False,
                                        'lockedProfitFloor': 0.0,
                                    }
                                    
                                    # Store open trade in database
                                    try:
                                        trade_conn = build_sqlite_connection(timeout=30.0)
                                        trade_cursor = trade_conn.cursor()
                                        trade_id = f"trade_{int(datetime.now().timestamp()*1000)}_{bot_id[-8:]}"
                                        trade_cursor.execute('''
                                            INSERT INTO trades (trade_id, bot_id, user_id, symbol, order_type, volume, price, profit, ticket, time_open, time_close, status, created_at, trade_data, timestamp)
                                            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                                        ''', (
                                            trade_id,
                                            bot_id,
                                            user_id,
                                            pos_symbol,
                                            pos_type,
                                            matched_pos.get('volume', 0),
                                            matched_pos.get('openPrice', 0),
                                            0,  # Profit is 0 until position closes
                                            str(pos_ticket),
                                            matched_pos.get('openTime', datetime.now().isoformat()),
                                            None,  # No close time yet
                                            'open',  # Mark as OPEN, not closed
                                            datetime.now().isoformat(),
                                            json.dumps({'ticket': str(pos_ticket), 'symbol': pos_symbol, 'type': pos_type, 'entryPrice': matched_pos.get('openPrice', 0), 'source': f"REAL_{str(broker_type).upper().replace(' ', '_')}", 'isPyramidAddon': bool(pyramid_decision['allowed']), 'pyramidParentTicket': pyramid_decision.get('parentTicket')}),
                                            int(datetime.now().timestamp() * 1000)
                                        ))
                                        trade_conn.commit()
                                        trade_conn.close()
                                    except Exception as e:
                                        logger.error(f"Bot {bot_id}: Error storing open trade: {e}")

                                    open_trade = {
                                        'ticket': pos_ticket,
                                        'symbol': pos_symbol,
                                        'type': pos_type,
                                        'volume': matched_pos.get('volume') or matched_pos.get('size', 0),
                                        'entryPrice': matched_pos.get('openPrice', 0),
                                        'currentPrice': current_price,
                                        'profit': round(current_profit, 2),
                                        'entryTime': matched_pos.get('openTime', datetime.now().isoformat()),
                                        'time': matched_pos.get('openTime', datetime.now().isoformat()),
                                        'timestamp': int(datetime.now().timestamp() * 1000),
                                        'botId': bot_id,
                                        'cycle': trade_cycle,
                                        'strategy': strategy_name,
                                        'isPyramidAddon': bool(pyramid_decision['allowed']),
                                        'pyramidParentTicket': pyramid_decision.get('parentTicket'),
                                        'isWinning': current_profit > 0,
                                        'status': 'open',
                                        'source': f"REAL_{str(broker_type).upper().replace(' ', '_')}",
                                        'broker': broker_type,
                                    }

                                    trade_history = bot_config.setdefault('tradeHistory', [])
                                    existing_index = next(
                                        (index for index, existing in enumerate(trade_history) if str(existing.get('ticket')) == str(pos_ticket)),
                                        None,
                                    )
                                    if existing_index is None:
                                        trade_history.append(open_trade)
                                        bot_config['totalTrades'] = bot_config.get('totalTrades', 0) + 1
                                    else:
                                        trade_history[existing_index] = {**trade_history[existing_index], **open_trade}
                                    
                                    logger.info(f"✅ Bot {bot_id}: Position OPENED | {pos_symbol} {pos_type} @ {matched_pos.get('openPrice', 0)} | Ticket: {pos_ticket}")
                                    trades_placed += 1
                        else:
                            if order_result and order_result.get('error'):
                                last_order_block_reason = f"{broker_type} rejected {symbol}: {order_result.get('error')}"
                            logger.warning(f"Bot {bot_id}: Could not place order on {symbol} or EURUSD fallback")
                    
                    except Exception as e:
                        logger.error(f"Bot {bot_id}: Error in trade cycle for {symbol}: {e}")
                        continue
                    finally:
                        if last_order_block_reason and last_order_block_reason != _iter_initial_block_reason:
                            _block_reason_per_symbol[symbol] = last_order_block_reason
                
                # ==================== CHECK FOR CLOSED POSITIONS (TP/SL HIT) ====================
                # Compare tracked open_positions against current broker positions.
                # If a tracked position is no longer open, it was closed by TP/SL — record the real P&L.
                # NOTE: Binance SPOT has no "positions" concept (only balances), so calling
                # active_conn.get_positions() returns []. That would falsely flag every tracked
                # spot position as closed every cycle. Spot closure is handled explicitly in the
                # SELL execution path above, so skip this block for Binance spot.
                _is_binance_spot = (
                    broker_type == 'Binance'
                    and active_conn is not None
                    and getattr(active_conn, 'market', 'spot') != 'futures'
                )
                try:
                    tracked_positions = bot_config.get('open_positions', {})
                    if tracked_positions and active_conn and _is_binance_spot:
                        _run_binance_spot_tracker(bot_id, bot_config, active_conn, broker_type, user_id)

                    if tracked_positions and active_conn and not _is_binance_spot:
                        current_positions = []
                        if is_mt5 and mt5_conn:
                            current_positions = mt5_conn.get_positions()
                        elif active_conn:
                            current_positions = active_conn.get_positions()
                        
                        current_tickets = set()
                        for cp in current_positions:
                            current_ticket = str(cp.get('ticket') or cp.get('deal_id', ''))
                            current_tickets.add(current_ticket)
                            if current_ticket in tracked_positions:
                                tracked_positions[current_ticket]['currentPrice'] = cp.get('currentPrice') or cp.get('marketPrice') or cp.get('price_current') or tracked_positions[current_ticket].get('currentPrice', 0)
                                tracked_positions[current_ticket]['profit'] = _resolve_open_position_profit({
                                    **tracked_positions[current_ticket],
                                    **cp,
                                    'currentPrice': tracked_positions[current_ticket]['currentPrice'],
                                })
                                tracked_positions[current_ticket]['status'] = 'open'
                                for trade in bot_config.get('tradeHistory', []):
                                    if str(trade.get('ticket')) == current_ticket:
                                        trade['currentPrice'] = tracked_positions[current_ticket]['currentPrice']
                                        trade['profit'] = tracked_positions[current_ticket]['profit']
                                        trade['status'] = 'open'
                                        trade['isWinning'] = tracked_positions[current_ticket]['profit'] > 0
                                        break

                        manage_protected_open_positions(
                            bot_id,
                            bot_config,
                            current_positions,
                            active_conn,
                            is_mt5,
                            mt5_conn,
                        )
                        
                        closed_tickets = []
                        for ticket_str, tracked in list(tracked_positions.items()):
                            if ticket_str not in current_tickets:
                                broker_closed_trade = _find_broker_closed_trade(active_conn, ticket_str)
                                if tracked.get('restoredFromDb') and broker_closed_trade is None:
                                    closed_tickets.append(ticket_str)
                                    _purge_unconfirmed_restored_position(
                                        bot_id,
                                        bot_config,
                                        ticket_str,
                                        tracked,
                                    )
                                    continue

                                closed_tickets.append(ticket_str)

                                # ⏰ Set post-close cooldown on the symbol so the bot does NOT
                                # immediately reopen after a manual close in MT5 / TP-SL hit.
                                # Configurable via bot_config['postCloseCooldownMinutes'] (default 60).
                                # Only applied for MT5/Exness path; Binance spot has its own
                                # inventory-based serialization that already prevents re-entry storms.
                                if is_mt5:
                                    try:
                                        _close_sym = str(tracked.get('symbol') or '').strip()
                                        if _close_sym:
                                            _cd_minutes = int(bot_config.get('postCloseCooldownMinutes') or 60)
                                            if _cd_minutes > 0:
                                                _cd_until_iso = (datetime.now() + timedelta(minutes=_cd_minutes)).isoformat()
                                                bot_config.setdefault('symbol_cooldown_until', {})[_close_sym] = _cd_until_iso
                                                logger.info(
                                                    f"⏰ Bot {bot_id}: Post-close cooldown set on {_close_sym} "
                                                    f"for {_cd_minutes}m (until {_cd_until_iso}) - prevents auto-reopen after manual close"
                                                )
                                    except Exception as _cd_set_e:
                                        logger.warning(f"Bot {bot_id}: Could not set post-close cooldown: {_cd_set_e}")

                                # Position is gone — closed by TP/SL or manually
                                # Get the actual P&L from MT5 trade history
                                real_profit = 0
                                close_time_iso = datetime.now().isoformat()
                                try:
                                    if is_mt5 and mt5_conn and mt5_conn.mt5:
                                        from datetime import timedelta
                                        now_ts = datetime.now()
                                        deals = mt5_conn.mt5.history_deals_get(
                                            now_ts - timedelta(days=1), now_ts
                                        )
                                        if deals:
                                            for deal in deals:
                                                if deal.position_id == int(ticket_str):
                                                    # OUT deal = closing deal with actual profit
                                                    if deal.entry == 1:  # DEAL_ENTRY_OUT
                                                        real_profit = deal.profit + deal.swap + deal.commission
                                                        break
                                    elif broker_closed_trade is not None:
                                        real_profit = _safe_float(broker_closed_trade.get('profit'), 0.0)
                                        close_time_iso = str(
                                            broker_closed_trade.get('closeTime')
                                            or broker_closed_trade.get('time_close')
                                            or broker_closed_trade.get('time')
                                            or close_time_iso
                                        )
                                except Exception as hist_e:
                                    logger.warning(f"Bot {bot_id}: Could not get history for ticket {ticket_str}: {hist_e}")

                                # Fallback: when broker doesn't return realized P&L
                                # (e.g. Binance spot, partial fills, or stale closed-trade lookup)
                                # compute it from tracked entry/exit prices so trades don't
                                # persist with profit=0 despite a real price differential.
                                if abs(_safe_float(real_profit, 0.0)) < 1e-9:
                                    _entry_px = _safe_float(
                                        tracked.get('entryPrice')
                                        or tracked.get('openPrice')
                                        or tracked.get('price'),
                                        0.0,
                                    )
                                    _exit_px = _safe_float(
                                        tracked.get('exitPrice')
                                        or tracked.get('currentPrice')
                                        or tracked.get('marketPrice')
                                        or tracked.get('price_current'),
                                        0.0,
                                    )
                                    if _exit_px <= 0:
                                        try:
                                            _md = commodity_market_data.get(tracked.get('symbol', ''), {})
                                            _exit_px = _safe_float(_md.get('current_price'), 0.0)
                                        except Exception:
                                            pass
                                    _vol_px = abs(_safe_float(tracked.get('volume'), 0.0))
                                    _dir_px = str(tracked.get('type') or tracked.get('direction') or '').upper()
                                    if _entry_px > 0 and _exit_px > 0 and _vol_px > 0:
                                        if 'BUY' in _dir_px:
                                            real_profit = round((_exit_px - _entry_px) * _vol_px, 4)
                                        elif 'SELL' in _dir_px:
                                            real_profit = round((_entry_px - _exit_px) * _vol_px, 4)
                                        if abs(real_profit) > 1e-9:
                                            logger.info(
                                                f"Bot {bot_id}: Computed fallback close P&L for {tracked.get('symbol')} "
                                                f"({_dir_px}) entry={_entry_px} exit={_exit_px} vol={_vol_px} -> {real_profit}"
                                            )

                                trade = {
                                    'ticket': tracked.get('ticket', ticket_str),
                                    'symbol': tracked.get('symbol', ''),
                                    'type': tracked.get('type', ''),
                                    'volume': tracked.get('volume', 0),
                                    'entryPrice': tracked.get('entryPrice', 0),
                                    'currentPrice': tracked.get('currentPrice', 0),
                                    'entryTime': tracked.get('entryTime', ''),
                                    'exitTime': close_time_iso,
                                    'profit': round(real_profit, 2),
                                    'time': close_time_iso,
                                    'timestamp': int(datetime.now().timestamp() * 1000),
                                    'botId': bot_id,
                                    'cycle': tracked.get('cycle', 0),
                                    'strategy': tracked.get('strategy', ''),
                                    'closeReason': tracked.get('closeReason', 'TP_SL_OR_MANUAL'),
                                    'isWinning': real_profit > 0,
                                    'source': f"REAL_{str(broker_type).upper().replace(' ', '_')}",
                                    'broker': tracked.get('broker', broker_type),
                                }
                                
                                # Update trade in database from open to closed
                                try:
                                    trade_conn = build_sqlite_connection(timeout=30.0)
                                    trade_cursor = trade_conn.cursor()
                                    trade_cursor.execute('''
                                        UPDATE trades SET profit = ?, status = 'closed', time_close = ?, trade_data = ?, updated_at = ?
                                        WHERE ticket = ? AND bot_id = ? AND status = 'open'
                                    ''', (
                                        real_profit,
                                        close_time_iso,
                                        json.dumps(trade),
                                        datetime.now().isoformat(),
                                        str(ticket_str),
                                        bot_id
                                    ))
                                    trade_conn.commit()
                                    trade_conn.close()
                                except Exception as db_e:
                                    logger.error(f"Bot {bot_id}: Error updating closed trade: {db_e}")
                                
                                # Update bot analytics with REAL P&L
                                if 'tradeHistory' not in bot_config:
                                    bot_config['tradeHistory'] = []
                                existing_index = next(
                                    (index for index, existing in enumerate(bot_config['tradeHistory']) if str(existing.get('ticket')) == str(ticket_str)),
                                    None,
                                )
                                if existing_index is None:
                                    bot_config['tradeHistory'].append(trade)
                                    bot_config['totalTrades'] = bot_config.get('totalTrades', 0) + 1
                                    bot_config['totalInvestment'] = bot_config.get('totalInvestment', 0) + (trade['volume'] * trade['entryPrice'])
                                else:
                                    bot_config['tradeHistory'][existing_index] = {**bot_config['tradeHistory'][existing_index], **trade, 'status': 'closed'}
                                
                                if real_profit > 0:
                                    bot_config['winningTrades'] = bot_config.get('winningTrades', 0) + 1
                                else:
                                    bot_config['totalLosses'] = bot_config.get('totalLosses', 0) + abs(real_profit)
                                
                                bot_config['totalProfit'] = bot_config.get('totalProfit', 0) + real_profit
                                
                                # Update peak & drawdown
                                if bot_config['totalProfit'] > bot_config.get('peakProfit', 0):
                                    bot_config['peakProfit'] = bot_config['totalProfit']
                                drawdown = bot_config.get('peakProfit', 0) - bot_config['totalProfit']
                                if drawdown > bot_config.get('maxDrawdown', 0):
                                    bot_config['maxDrawdown'] = drawdown
                                
                                # Track profit history
                                bot_config.setdefault('profitHistory', []).append({
                                    'timestamp': trade['timestamp'],
                                    'profit': round(bot_config['totalProfit'], 2),
                                    'trades': bot_config['totalTrades'],
                                })
                                
                                # Track daily profit
                                today = datetime.now().strftime('%Y-%m-%d')
                                if today not in bot_config.get('dailyProfits', {}):
                                    bot_config.setdefault('dailyProfits', {})[today] = 0
                                bot_config['dailyProfits'][today] += real_profit
                                bot_config['dailyProfit'] = bot_config['dailyProfits'][today]
                                bot_config['profit'] = bot_config['totalProfit']
                                persist_bot_runtime_state(bot_id, force=True)
                                
                                # Commission distribution on real profit
                                if real_profit > 0:
                                    try:
                                        # Determine broker source from bot connection type
                                        _broker_src = str(bot_config.get('brokerType') or bot_config.get('broker_type') or 'MT5').upper()
                                        if _broker_src not in ('MT5', 'IG', 'FXCM', 'BINANCE', 'OANDA', 'EXNESS', 'XM'):
                                            _broker_src = 'MT5'
                                        distribute_trade_commissions(bot_id, user_id, real_profit, source=_broker_src)
                                    except Exception as comm_e:
                                        logger.error(f"Bot {bot_id}: Commission error: {comm_e}")

                                # Apply immediate post-close protection (pause/cooldown on loss streaks).
                                _apply_loss_streak_safety(bot_config, trade)
                                strategy_tracker.record_trade(
                                    str(trade.get('strategy') or tracked.get('strategy') or bot_config.get('strategy') or 'Trend Following'),
                                    real_profit,
                                    tracked.get('symbol', ''),
                                )
                                
                                display_currency = str(bot_config.get('displayCurrency') or 'USD').upper()
                                logger.info(f"💰 Bot {bot_id}: Position CLOSED by TP/SL | {tracked.get('symbol')} | Real P&L: {real_profit:.2f} {display_currency}")
                        
                        # Remove closed positions from tracker
                        for t in closed_tickets:
                            del tracked_positions[t]
                        if closed_tickets and len(tracked_positions) == 0:
                            logger.info(f"🔁 Bot {bot_id}: All tracked positions are closed. Continuing trading on next cycle.")
                
                except Exception as close_check_e:
                    logger.warning(f"Bot {bot_id}: Error checking closed positions: {close_check_e}")
                
                # ==================== DISCOVER UNTRACKED POSITIONS ====================
                # Sync ALL MT5 positions for this bot's symbols into open_positions/tradeHistory.
                # This catches positions that existed before tracking was enabled, or were placed
                # by MT5 directly (TP/SL spawned hedges, manual trades on same symbols, etc.)
                try:
                    if is_mt5 and mt5_conn and bot_config.get('symbols'):
                        discovery_positions = mt5_conn.get_positions()
                        tracked_positions = bot_config.get('open_positions', {})
                        tracked_tickets = set(tracked_positions.keys())
                        bot_symbols = set(bot_config.get('symbols', []))
                        bot_id_short = bot_id.split('_')[-1][:8]
                        comment_tag = f'ZBot{bot_id_short}'
                        
                        discovered_count = 0
                        for dp in discovery_positions:
                            dp_ticket = str(dp.get('ticket', ''))
                            dp_symbol = dp.get('symbol', '')
                            dp_comment = dp.get('comment', '') or ''
                            
                            # Skip if already tracked
                            if dp_ticket in tracked_tickets:
                                continue
                            
                            # Match: position is on one of the bot's symbols, OR has the bot's comment tag
                            is_bot_symbol = dp_symbol in bot_symbols
                            is_bot_comment = comment_tag in dp_comment
                            
                            if is_bot_symbol or is_bot_comment:
                                dp_type = dp.get('type', 'BUY')
                                dp_volume = dp.get('volume', 0)
                                dp_entry_price = dp.get('openPrice') or dp.get('price_open') or dp.get('level', 0)
                                dp_current_price = dp.get('currentPrice') or dp.get('marketPrice') or dp.get('price_current', 0)
                                dp_profit = round(dp.get('profit') or dp.get('pnl') or 0, 2)
                                dp_open_time = dp.get('openTime') or dp.get('time', datetime.now().isoformat())
                                
                                # Add to open_positions tracker
                                if 'open_positions' not in bot_config:
                                    bot_config['open_positions'] = {}
                                bot_config['open_positions'][dp_ticket] = {
                                    'ticket': dp.get('ticket', dp_ticket),
                                    'symbol': dp_symbol,
                                    'type': dp_type,
                                    'volume': dp_volume,
                                    'entryPrice': dp_entry_price,
                                    'currentPrice': dp_current_price,
                                    'profit': dp_profit,
                                    'status': 'open',
                                    'entryTime': dp_open_time,
                                    'botId': bot_id,
                                    'cycle': trade_cycle,
                                    'strategy': bot_config.get('strategy', 'trend_following'),
                                    'broker': broker_type,
                                    'discovered': True,
                                    'peakProfit': dp_profit,
                                    'profitProtectionArmed': False,
                                    'lockedProfitFloor': 0.0,
                                }
                                
                                # Add to tradeHistory if not already there
                                if 'tradeHistory' not in bot_config:
                                    bot_config['tradeHistory'] = []
                                existing_th = next(
                                    (i for i, t in enumerate(bot_config['tradeHistory']) if str(t.get('ticket')) == dp_ticket),
                                    None,
                                )
                                open_trade = {
                                    'ticket': dp.get('ticket', dp_ticket),
                                    'symbol': dp_symbol,
                                    'type': dp_type,
                                    'volume': dp_volume,
                                    'entryPrice': dp_entry_price,
                                    'currentPrice': dp_current_price,
                                    'profit': dp_profit,
                                    'time': dp_open_time,
                                    'timestamp': int(datetime.now().timestamp() * 1000),
                                    'botId': bot_id,
                                    'status': 'open',
                                    'isWinning': dp_profit > 0,
                                    'source': f"DISCOVERED_{str(broker_type).upper().replace(' ', '_')}",
                                    'broker': broker_type,
                                }
                                if existing_th is None:
                                    bot_config['tradeHistory'].append(open_trade)
                                    bot_config['totalTrades'] = bot_config.get('totalTrades', 0) + 1
                                    discovered_count += 1
                                else:
                                    # Update existing entry with live data
                                    bot_config['tradeHistory'][existing_th].update({
                                        'currentPrice': dp_current_price,
                                        'profit': dp_profit,
                                        'isWinning': dp_profit > 0,
                                        'status': 'open',
                                    })
                                
                                # Also insert into DB if not already there
                                if existing_th is None:
                                    try:
                                        disc_conn = build_sqlite_connection(timeout=30.0)
                                        disc_cursor = disc_conn.cursor()
                                        trade_id = f"disc_{int(datetime.now().timestamp()*1000)}_{dp_ticket}"
                                        disc_cursor.execute('''
                                            INSERT OR IGNORE INTO trades (trade_id, bot_id, user_id, symbol, order_type, volume, price, profit, ticket, time_open, status, created_at, trade_data, timestamp)
                                            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                                        ''', (
                                            trade_id, bot_id, user_id, dp_symbol, dp_type, dp_volume,
                                            dp_entry_price, dp_profit, dp_ticket, dp_open_time,
                                            'open', datetime.now().isoformat(),
                                            json.dumps({'ticket': dp_ticket, 'symbol': dp_symbol, 'type': dp_type, 'entryPrice': dp_entry_price, 'source': 'DISCOVERED'}),
                                            int(datetime.now().timestamp() * 1000)
                                        ))
                                        disc_conn.commit()
                                        disc_conn.close()
                                    except Exception as disc_db_e:
                                        logger.warning(f"Bot {bot_id}: Error saving discovered trade: {disc_db_e}")
                        
                        if discovered_count > 0:
                            logger.info(f"🔍 Bot {bot_id}: Discovered {discovered_count} untracked position(s) on {', '.join(bot_symbols)}")
                
                except Exception as disc_e:
                    logger.warning(f"Bot {bot_id}: Error discovering untracked positions: {disc_e}")
                
                # Update account balance (broker-aware)
                try:
                    if active_conn:
                        account_info = active_conn.get_account_info()
                        if account_info:
                            bot_config['accountBalance'] = account_info.get('balance', account_info.get('equity', 0))
                            bot_config['accountEquity'] = account_info.get('equity', account_info.get('balance', 0))
                except Exception as e:
                    logger.warning(f"Bot {bot_id}: Could not update account balance: {e}")

                open_pos_count = len(bot_config.get('open_positions', {}))
                update_adaptive_signal_threshold_state(
                    bot_id,
                    bot_config,
                    base_signal_threshold,
                    best_signal_strength,
                    configured_signal_hits,
                    scanner_signal_hits,
                    trades_placed,
                    open_pos_count,
                )
                persist_bot_runtime_state(bot_id)
                
                # Log cycle summary with position status for debugging
                display_currency = str(bot_config.get('displayCurrency') or 'USD').upper()
                adaptive_offset = int(bot_config.get('adaptiveSignalThresholdOffset') or 0)
                adaptive_note = ''
                if adaptive_offset > 0:
                    adaptive_note = f" | Next threshold: {max(adaptive_threshold_floor, base_signal_threshold - adaptive_offset)}/{base_signal_threshold}"
                no_trade_reason = None
                no_trade_note = ''
                if trades_placed == 0:
                    effective_max_open_positions = int(
                        bot_config.get('effectiveMaxOpenPositions')
                        or bot_config.get('maxOpenPositions')
                        or 0
                    )
                    if bot_config.get('status') == 'PAUSED' and bot_config.get('pauseReason'):
                        no_trade_reason = str(bot_config.get('pauseReason'))
                    elif effective_max_open_positions > 0 and open_pos_count >= effective_max_open_positions:
                        no_trade_reason = (
                            f"position limit reached ({open_pos_count}/{effective_max_open_positions})"
                        )
                    elif configured_signal_hits == 0 and scanner_signal_hits == 0:
                        no_trade_reason = (
                            f"no qualifying setups (best={best_signal_symbol or 'n/a'}:{best_signal_strength:.0f}/100, "
                            f"threshold={signal_threshold}/100)"
                        )
                    elif last_order_block_reason:
                        # Prefer the block reason from the strongest qualifying symbol so the cycle
                        # summary reflects what actually blocked a tradeable signal, not the last
                        # symbol iterated (which may have been a low-strength or closed market).
                        _qualifying_blocks = [
                            (sym, signal_strength_by_symbol.get(sym, 0.0), reason)
                            for sym, reason in _block_reason_per_symbol.items()
                            if signal_strength_by_symbol.get(sym, 0.0) >= signal_threshold
                        ]
                        if _qualifying_blocks:
                            _qualifying_blocks.sort(key=lambda x: x[1], reverse=True)
                            _qsym, _qstr, _qreason = _qualifying_blocks[0]
                            no_trade_reason = (
                                f"strongest qualifying signal {_qsym}:{_qstr:.0f}/100 blocked: {_qreason}"
                            )
                        else:
                            no_trade_reason = last_order_block_reason
                    else:
                        no_trade_reason = 'setup passed signal scan but was blocked by entry filters or broker checks'
                    if no_trade_reason:
                        bot_config['lastNoTradeReason'] = no_trade_reason
                        bot_config['lastNoTradeAt'] = datetime.now().isoformat()
                        no_trade_note = f" | No trade reason: {no_trade_reason}"
                else:
                    bot_config['lastNoTradeReason'] = None
                    bot_config['lastNoTradeAt'] = None
                logger.info(f"✅ Bot {bot_id}: Cycle #{trade_cycle} complete | Trades placed: {trades_placed} | Open positions: {open_pos_count} | Total P&L: {bot_config.get('totalProfit', 0):.2f} {display_currency}{adaptive_note}{no_trade_note}")
                
                # DUAL MODE: TIME-BASED vs SIGNAL-DRIVEN waiting
                if trading_mode == 'signal-driven':
                    # ⚡ SIGNAL-DRIVEN MODE: Check signals every poll_interval seconds
                    logger.info(f"⚡ Bot {bot_id}: Polling signals every {poll_interval}s (threshold: {signal_threshold}/100)...")
                    
                    poll_elapsed = 0
                    heartbeat_interval = min(trading_interval, max(30, poll_interval * 3))
                    next_heartbeat_at = heartbeat_interval
                    while not bot_stop_flags.get(bot_id, False) and poll_elapsed < trading_interval:
                        actual_poll_interval = min(poll_interval, 5) if bot_config.get('open_positions') else poll_interval
                        time.sleep(actual_poll_interval)
                        poll_elapsed += actual_poll_interval

                        if bot_config.get('open_positions'):
                            try:
                                # Binance spot has no broker-side positions concept; run the
                                # spot-specific tracker (floating P&L refresh + TP/SL trigger
                                # close) every poll tick so trades close even when the bot
                                # is otherwise idle (e.g. at position limit).
                                _poll_is_binance_spot = (
                                    broker_type == 'Binance'
                                    and active_conn is not None
                                    and getattr(active_conn, 'market', 'spot') != 'futures'
                                )
                                if _poll_is_binance_spot:
                                    try:
                                        _run_binance_spot_tracker(bot_id, bot_config, active_conn, broker_type, user_id)
                                    except Exception as spot_poll_err:
                                        logger.debug(f"Bot {bot_id}: spot poll tracker error: {spot_poll_err}")

                                if is_mt5 and mt5_conn:
                                    polled_positions = mt5_conn.get_positions()
                                elif active_conn and not _poll_is_binance_spot:
                                    polled_positions = active_conn.get_positions()
                                else:
                                    polled_positions = []

                                tracked_positions = bot_config.get('open_positions', {})
                                if tracked_positions and not _poll_is_binance_spot:
                                    current_tickets = {
                                        str((position or {}).get('ticket') or (position or {}).get('deal_id') or '')
                                        for position in (polled_positions or [])
                                    }
                                    closed_tickets = [
                                        tracked_ticket
                                        for tracked_ticket in list(tracked_positions.keys())
                                        if tracked_ticket not in current_tickets
                                    ]
                                    if closed_tickets:
                                        now_iso = datetime.now().isoformat()
                                        for closed_ticket in closed_tickets:
                                            tracked = tracked_positions.pop(closed_ticket, {})
                                            tracked_profit = round(_safe_float(tracked.get('profit'), 0.0), 2)

                                            for trade in bot_config.get('tradeHistory', []):
                                                if str(trade.get('ticket')) == str(closed_ticket):
                                                    trade['status'] = 'closed'
                                                    trade['closeReason'] = trade.get('closeReason', 'EXTERNAL_MANUAL_CLOSE')
                                                    trade['exitTime'] = now_iso
                                                    trade['time'] = now_iso
                                                    trade['timestamp'] = int(datetime.now().timestamp() * 1000)
                                                    trade['profit'] = tracked_profit
                                                    trade['isWinning'] = tracked_profit > 0
                                                    break

                                            try:
                                                trade_conn = build_sqlite_connection(timeout=30.0)
                                                trade_cursor = trade_conn.cursor()
                                                trade_cursor.execute('''
                                                    UPDATE trades
                                                    SET profit = ?, status = 'closed', time_close = ?, updated_at = ?
                                                    WHERE ticket = ? AND bot_id = ? AND status = 'open'
                                                ''', (
                                                    tracked_profit,
                                                    now_iso,
                                                    now_iso,
                                                    str(closed_ticket),
                                                    bot_id,
                                                ))
                                                trade_conn.commit()
                                                trade_conn.close()
                                            except Exception as poll_db_error:
                                                logger.debug(f"Bot {bot_id}: polling close-sync DB warning for ticket {closed_ticket}: {poll_db_error}")

                                        logger.info(f"🔁 Bot {bot_id}: Synced {len(closed_tickets)} externally closed position(s) during polling")

                                protection_events = manage_protected_open_positions(
                                    bot_id,
                                    bot_config,
                                    polled_positions or [],
                                    active_conn,
                                    is_mt5,
                                    mt5_conn,
                                )
                                if protection_events:
                                    persist_bot_runtime_state(bot_id)
                            except Exception as protection_poll_error:
                                logger.debug(f"🛡️ Bot {bot_id}: Profit protection poll failed: {protection_poll_error}")
                        
                        # Check if a strategy-approved signal exists for any symbol.
                        best_signal_strength = 0.0
                        best_signal_symbol = None
                        poll_visibility_signal_strength = 0.0
                        poll_visibility_symbol = None
                        poll_strategy_cache: Dict[str, Optional[Dict[str, Any]]] = {}

                        for symbol in bot_config.get('symbols', ['EURUSDm'])[:3]:
                            poll_market_data = _enrich_market_data_with_bot_context(bot_config, symbol)
                            raw_signal = evaluate_real_trade_signal(symbol, poll_market_data)
                            raw_strength = float(raw_signal.get('strength') or 0.0)
                            if raw_strength > poll_visibility_signal_strength:
                                poll_visibility_signal_strength = raw_strength
                                poll_visibility_symbol = symbol

                            trade_params = _get_cached_strategy_params(
                                poll_strategy_cache,
                                strategy_func,
                                symbol,
                                bot_config['accountId'],
                                bot_config['riskPerTrade'],
                                poll_market_data,
                            )
                            if not trade_params:
                                continue

                            strategy_signal = trade_params.get('signal', {})
                            strategy_strength = float(strategy_signal.get('strength') or 0.0)
                            if strategy_strength > best_signal_strength:
                                best_signal_strength = strategy_strength
                                best_signal_symbol = symbol

                        if best_signal_strength >= signal_threshold and best_signal_symbol:
                            logger.info(f"🔥 Bot {bot_id}: STRONG SIGNAL DETECTED on {best_signal_symbol}!")
                            logger.info(f"   Signal Strength: {best_signal_strength:.0f}/100 (threshold: {signal_threshold})")
                            logger.info(f"   Executing trade IMMEDIATELY (no waiting)...")
                            break  # Break inner loop, execute trade next cycle
                        elif poll_visibility_signal_strength > 0 and poll_visibility_symbol:
                            logger.debug(
                                f"📊 Bot {bot_id}: Raw signal on {poll_visibility_symbol}: "
                                f"{poll_visibility_signal_strength:.0f}/100, but no strategy-approved setup yet"
                            )

                        if poll_elapsed >= next_heartbeat_at and poll_elapsed < trading_interval:
                            logger.info(
                                f"💓 Bot {bot_id}: Waiting for next qualified setup | "
                                f"elapsed={poll_elapsed}s/{trading_interval}s | "
                                f"best={poll_visibility_symbol or 'n/a'}:{poll_visibility_signal_strength:.0f}/100 | "
                                f"threshold={signal_threshold}/100"
                            )
                            next_heartbeat_at += heartbeat_interval
                else:
                    # ⏱️ TIME-BASED MODE: Wait fixed interval
                    logger.debug(f"⏳ Bot {bot_id}: Waiting {trading_interval} seconds until next cycle...")
                    time.sleep(trading_interval)
            
            except Exception as e:
                logger.error(f"Bot {bot_id}: Error in trading loop: {e}")
                time.sleep(min(poll_interval if trading_mode == 'signal-driven' else trading_interval, 60))  # Wait at least 60 seconds before retry
        
        # Bot stopped
        logger.info(f"🛑 Bot {bot_id}: CONTINUOUS TRADING LOOP STOPPED")
        running_bots[bot_id] = False
    
    except Exception as e:
        logger.error(f"Bot {bot_id}: FATAL error in trading loop: {e}")
        running_bots[bot_id] = False


def get_broker_connection(credential_id: str, user_id: str, bot_id: str = None):
    """Dynamically load and return the correct broker connection based on credential type
    
    Supports:
    - Exness (MT5)
    - Binance (REST API)
    - FXCM (REST API)
    - OANDA (REST API)
    
    Returns: (broker_type, connection_object) or (None, error_message)
    """
    try:
        context_id = str(bot_id or 'runtime').strip() or 'runtime'
        if context_id.startswith('positions-detailed:'):
            context_label = f'Position inspection {context_id}'
        elif context_id.startswith('unified-portfolio:'):
            context_label = f'Portfolio inspection {context_id}'
        elif context_id.startswith('unified-positions:'):
            context_label = f'Positions aggregation {context_id}'
        elif context_id.startswith('account-details:'):
            context_label = f'Account details {context_id}'
        elif context_id.startswith('mode-switch:'):
            context_label = f'Mode switch {context_id}'
        elif context_id.startswith('unified-close-all:'):
            context_label = f'Close-all request {context_id}'
        elif context_id.startswith('manual-close:'):
            context_label = f'Manual close {context_id}'
        else:
            context_label = f'Bot {context_id}'

        conn = get_db_connection()
        cursor = conn.cursor()
        
        # Load credential from database
        cursor.execute('''
            SELECT credential_id, broker_name, api_key, username, password,
                   account_number, server, is_live, mt5_terminal_path
            FROM broker_credentials
            WHERE credential_id = ? AND user_id = ? AND is_active = 1
        ''', (credential_id, user_id))
        
        cred_row = cursor.fetchone()
        conn.close()
        
        if not cred_row:
            error_msg = f"Credential {credential_id} not found or inactive for user {user_id}"
            logger.error(error_msg)
            return None, error_msg
        
        cred = dict(cred_row)
        broker_name = canonicalize_broker_name(cred['broker_name'])
        
        logger.info(f"[Broker Detection] {context_label}: Detected broker type: {broker_name}")
        
        if broker_name == 'Binance':
            logger.info(f"[Broker Switch] {context_label}: Using Binance REST API")
            api_key = cred['api_key']
            api_secret = cred['password']
            account_number = cred['account_number']
            resolved_market = _resolve_binance_market_for_context(
                credential_row=cred,
                bot_id=bot_id,
                bot_config=active_bots.get(str(bot_id)) if bot_id and isinstance(active_bots, dict) else None,
            )
            is_live = cred['is_live']

            if not api_key or not api_secret:
                error_msg = 'Binance: Missing API key or API secret'
                logger.error(error_msg)
                return None, error_msg

            binance_conn = BinanceConnection(credentials={
                'api_key': api_key,
                'api_secret': api_secret,
                'account_number': account_number,
                'server': resolved_market,
                'market': resolved_market,
                'is_live': is_live,
            })
            if binance_conn.connect():
                logger.info(f"✅ {context_label}: Connected to Binance ({account_number or resolved_market}, market={resolved_market})")
                return 'Binance', binance_conn
            error_msg = 'Failed to connect to Binance'
            logger.error(error_msg)
            return None, error_msg

        elif broker_name == 'OANDA':
            logger.info(f"[Broker Switch] {context_label}: Using OANDA REST API")
            api_key = cred['api_key']
            account_number = cred['account_number']
            is_live = bool(cred['is_live'])

            if not api_key or not account_number:
                error_msg = 'OANDA: Missing API key or account number'
                logger.error(error_msg)
                return None, error_msg

            oanda_conn = OANDAConnection(credentials={
                'api_key': api_key,
                'account_number': account_number,
                'is_live': is_live,
            })
            if oanda_conn.connect():
                logger.info(f"✅ {context_label}: Connected to OANDA ({account_number})")
                return 'OANDA', oanda_conn
            error_msg = 'Failed to connect to OANDA'
            logger.error(error_msg)
            return None, error_msg

        elif broker_name == 'FXCM':
            logger.info(f"[Broker Switch] {context_label}: Using FXCM connection")
            api_key = str(cred['api_key'] or '').strip()
            username = str(cred.get('username') or '').strip()
            password = str(cred.get('password') or '').strip()
            account_number = cred['account_number']
            is_live = bool(cred['is_live'])
            # ForexConnect stores login ID in account_number — use as username fallback
            if not username and account_number:
                username = str(account_number).strip()

            if not has_fxcm_connection_credentials({
                'api_key': api_key,
                'username': username,
                'password': password,
            }):
                error_msg = 'FXCM: Credential incomplete - skipping connection attempt'
                logger.info(f"{context_label}: {error_msg}")
                return None, error_msg

            fxcm_conn = FXCMConnection(credentials={
                'api_key': api_key,
                'username': username,
                'password': password,
                'account_number': account_number,
                'server': cred.get('server'),
                'connection': 'Real' if is_live else 'Demo',
                'is_live': is_live,
                'credential_id': credential_id,
            })
            if fxcm_conn.connect():
                logger.info(f"✅ {context_label}: Connected to FXCM ({account_number or 'FXCM'})")
                return 'FXCM', fxcm_conn
            error_msg = fxcm_conn.last_error or 'Failed to connect to FXCM'
            logger.error(error_msg)
            return None, error_msg
        
        # ✅ METATRADER 5 - Exness
        elif broker_name == 'Exness':
            logger.info(f"[Broker Switch] {context_label}: Using MetaTrader 5 SDK")
            account_number = cred['account_number']
            password = cred['password']
            server = cred['server']
            is_live = cred['is_live']
            
            if not account_number or not password or not server:
                error_msg = f"MT5: Missing credentials (account={bool(account_number)}, password={bool(password)}, server={bool(server)})"
                logger.error(error_msg)
                return None, error_msg
            
            # Normalize server name for MT5
            server = normalize_mt5_server_name(broker_name, bool(is_live), server)
            
            logger.info(f"{context_label}: Connecting to MT5 - Account: {account_number}, Server: {server}")
            log_mt5_route_diagnostic(
                f'get_broker_connection:{bot_id or credential_id}',
                {
                    'broker': broker_name,
                    'broker_name': broker_name,
                    'account': account_number,
                    'account_number': account_number,
                    'server': server,
                    'is_live': bool(is_live),
                },
            )
            
            # Create MT5 connection
            # Determine broker name for MT5 connection initialization
            broker_for_mt5 = canonicalize_broker_name(broker_name)
            server = normalize_mt5_server_name(broker_name, is_live, server)
            
            mt5_conn = MT5Connection(credentials={
                'account': int(account_number),
                'password': password,
                'server': server,
                'broker': broker_for_mt5,
                'is_live': bool(is_live),
                'path': resolve_mt5_terminal_executable_path(cred.get('mt5_terminal_path')) or cred.get('mt5_terminal_path') or None,  # Per-account terminal path (prevents account-switching conflict)
                'priority_mode_switch': bool(bot_id and str(bot_id).startswith('mode-switch:')),
            })
            
            if mt5_conn.connect():
                logger.info(f"✅ Bot {bot_id}: Connected to MT5 ({account_number}@{server})")
                return 'MetaTrader 5', mt5_conn
            else:
                error_msg = f"Failed to connect to MT5 - Account: {account_number}, Server: {server}"
                logger.error(error_msg)
                return None, error_msg
        
        else:
            error_msg = f"Unknown broker type: {broker_name}. Supported: Exness, Binance, FXCM, OANDA"
            logger.error(error_msg)
            return None, error_msg
    
    except Exception as e:
        error_msg = f"Error loading broker connection: {str(e)}"
        logger.error(error_msg)
        return None, error_msg


# ==================== QUICK BOT CREATION (One-Click for Binance) ====================

@app.route('/api/bot/quick-create', methods=['POST'])
@require_session
def quick_create_bot():
    """One-click bot creation for Binance users with predefined high-performance pairs
    
    FEATURES:
    - No symbol selection needed (uses 6 best-performing pairs)
    - Optimized crypto risk settings
    - Instant creation and activation
    - Works only for Binance broker
    
    REQUEST:
    {
        "credentialId": "uuid",           // Required: Binance credential
        "preset": "top_edge" | "balanced" // Optional: pair selection strategy
    }
    
    RESPONSE: {bot_id, status, message, tradesPlaced, pairs}
    """
    # ==================== BOT CREATION LOCK ====================
    # Only allow ONE bot creation at a time
    global bot_creation_lock
    logger.info("🔒 Waiting for exclusive bot creation lock (quick-create)...")
    
    with bot_creation_lock:
        logger.info("✅ Acquired bot creation lock - proceeding with quick creation")
        conn = None
        try:
            data = request.json
            if not data:
                return jsonify({'success': False, 'error': 'No configuration provided'}), 400

            user_id = request.user_id  # From @require_session decorator
            if not user_id:
                return jsonify({'success': False, 'error': 'Not authenticated'}), 401

            credential_id = data.get('credentialId')
            if not credential_id:
                return jsonify({'success': False, 'error': 'credentialId required'}), 400

            preset = data.get('preset', 'top_edge')  # Default to top performers

            conn = get_db_connection()
            cursor = conn.cursor()

            # Verify credential exists and belongs to user AND is Binance
            cursor.execute('''
                SELECT credential_id, broker_name, account_number, is_live, api_key, password, server, account_currency
                FROM broker_credentials
                WHERE credential_id = ? AND user_id = ?
            ''', (credential_id, user_id))
            credential_row = cursor.fetchone()
            if not credential_row:
                return jsonify({'success': False, 'error': 'Broker credential not found'}), 404

            credential_data = dict(credential_row)
            broker_name = credential_data['broker_name']

            # Only allow Binance for quick create
            if canonicalize_broker_name(broker_name) != 'Binance':
                return jsonify({
                    'success': False,
                    'error': f'Quick bot creation only works for Binance. You are using {broker_name}'
                }), 400

            account_number = credential_data['account_number']
            is_live = credential_data['is_live']
            mode = 'live' if is_live else 'demo'

            # Validate Binance connection
            binance_conn = BinanceConnection(credentials={
                'api_key': credential_data.get('api_key'),
                'api_secret': credential_data.get('password'),
                'account_number': account_number,
                'server': credential_data.get('server') or 'spot',
                'is_live': bool(is_live),
            })
            if not binance_conn.connect():
                return jsonify({
                    'success': False,
                    'error': 'Binance connection failed. Check API key/secret.'
                }), 400
            binance_conn.disconnect()

            # Predefined high-performance Binance pairs
            BINANCE_PRESETS = {
                'top_edge': [
                    'BTCUSDT',   # Highest edge (6.8%)
                    'ETHUSDT',   # High edge (6.2%)
                    'SOLUSDT',   # Highest momentum (7.4%)
                    'XRPUSDT',   # Consistent (5.6%)
                    'BNBUSDT',   # Exchange beta (5.3%)
                    'LTCUSDT',   # Lower beta (4.8%)
                ],
                'balanced': [
                    'BTCUSDT', 'ETHUSDT', 'LINKUSDT', 'ADAUSDT', 'DOGEUSDT', 'MATICUSDT'
                ],
                'defi': [
                    'UNIUSDT', 'AAVEUSDT', 'APTUSDT', 'INJUSDT', 'SUIUSDT', 'FTMUSDT'
                ],
                'large_cap_only': [
                    'BTCUSDT', 'ETHUSDT', 'BNBUSDT', 'SOLUSDT', 'ADAUSDT', 'XRPUSDT'
                ]
            }

            symbols = BINANCE_PRESETS.get(preset, BINANCE_PRESETS['top_edge'])

            quick_profit_defaults = BOT_MANAGEMENT_PROFILES.get('fast_growth', {})
            management_profile = 'fast_growth'  # User-facing label: Quick Profit
            management_mode = 'assisted'
            signal_threshold = _crypto_only_signal_threshold(symbols) or 5   # AGGRESSIVE: 5 floor
            allowed_volatility = ['Low', 'Medium']
            max_open_positions = min(2, int(quick_profit_defaults.get('maxOpenPositions', 2) or 2))
            max_positions_per_symbol = 1
            intelligent_scanner = True
            profit_protection = {
                'enabled': True,
                'activationPercent': 3,
                'activationMinProfit': 2,
                'retraceClosePercent': 22,
                'switchOnReversal': True,
            }

            # Bot configuration (optimized for crypto)
            bot_id = f"quick_bot_{int(time.time() * 1000)}_{uuid.uuid4().hex[:6]}"
            strategy = 'Momentum Trading'  # Best for crypto
            risk_per_trade = 15  # Crypto-optimized
            max_daily_loss = 50
            profit_lock = 40
            drawdown_pause_percent = 5
            drawdown_pause_hours = 4
            # ✅ GET ACCOUNT CURRENCY from credentials (Binance is always USDT)
            account_currency = credential_data.get('account_currency', 'USDT').upper()
            trading_enabled = True

            account_id = f"{broker_name}_{account_number}"
            created_at = datetime.now().isoformat()

            # Store bot in database
            cursor.execute('''
                INSERT INTO user_bots (bot_id, user_id, name, strategy, status, enabled, broker_account_id, symbols, is_live, created_at, updated_at)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            ''', (bot_id, user_id, f'Quick {preset}', strategy, 'active', trading_enabled, account_id, ','.join(symbols), 1 if is_live else 0, created_at, created_at))

            # Link bot to credential
            cursor.execute('''
                INSERT INTO bot_credentials (bot_id, credential_id, user_id, created_at)
                VALUES (?, ?, ?, ?)
            ''', (bot_id, credential_id, user_id, created_at))
            
            conn.commit()

            now = datetime.now()
            # Start with clean stats — no fake sample trades

            active_bots[bot_id] = {
                'botId': bot_id,
                'user_id': user_id,
                'accountId': account_id,
                'brokerName': broker_name,
                'broker_type': broker_name,
                'accountNumber': account_number,
                'account_number': account_number,
                'mode': mode,
                'credentialId': credential_id,
                'symbols': symbols,
                'strategy': strategy,
                'riskPerTrade': risk_per_trade,
                'maxDailyLoss': max_daily_loss,
                'profitLock': profit_lock,
                'drawdownPausePercent': drawdown_pause_percent,
                'drawdownPauseHours': drawdown_pause_hours,
                'managementProfile': management_profile,
                'managementMode': management_mode,
                'signalThreshold': signal_threshold,
                'allowedVolatility': allowed_volatility,
                'maxOpenPositions': max_open_positions,
                'maxOpenTrades': max_open_positions,
                'maxPositionsPerSymbol': max_positions_per_symbol,
                'autoSwitch': True,
                'dynamicSizing': True,
                'intelligentScanner': intelligent_scanner,
                'selectedPreset': f'binance_{preset}',
                'presetName': f'Quick Profit ({preset})',
                'intelligentManagement': {
                    'enabled': True,
                    'profile': management_profile,
                    'experienceLevel': management_profile,
                    'autoSwitch': True,
                    'dynamicSizing': True,
                },
                'profitProtection': profit_protection,
                'displayCurrency': account_currency,  # Use actual account currency (USDT, USD, etc.)
                'enabled': trading_enabled,
                'totalTrades': 0,
                'winningTrades': 0,
                'totalProfit': 0,
                'totalLosses': 0,
                'totalInvestment': 0,
                'createdAt': now.isoformat(),
                'startTime': now.isoformat(),
                'profitHistory': [],
                'tradeHistory': [],
                'dailyProfits': {},
                'dailyProfit': 0,
                'maxDrawdown': 0,
                'peakProfit': 0,
                'profit': 0,
            }
            persist_bot_runtime_state(bot_id)

            running_bots[bot_id] = True
            bot_stop_flags[bot_id] = False

            # ==================== WORKER POOL DISPATCH (QUICK BOT) ====================
            if worker_pool_manager and worker_pool_manager.enabled and is_mt5_broker_name(broker_name):
                _qb_creds = None
                if credential_id:
                    try:
                        _qbc = get_db_connection()
                        _qbr = _qbc.cursor()
                        _qbr.execute('SELECT account_number, password, server, is_live FROM broker_credentials WHERE credential_id = ?', (credential_id,))
                        _qrow = _qbr.fetchone()
                        _qbc.close()
                        if _qrow:
                            _qrow = decrypt_credential_row(_qrow)
                            _qb_creds = {'account_number': _qrow['account_number'], 'password': _qrow['password'], 'server': _qrow.get('server', ''), 'is_live': bool(_qrow['is_live'])}
                    except Exception as e:
                        logger.warning(f'Quick bot worker dispatch: could not fetch credentials: {e}')
                worker_pool_manager.dispatch_bot(bot_id, user_id, active_bots[bot_id], _qb_creds)
                logger.info(f"🚀 Quick bot {bot_id}: Dispatched to worker pool")
            else:
                def _async_start_quick_bot():
                    try:
                        time.sleep(0.5)

                        bot_credentials = None
                        if credential_id:
                            conn_local = None
                            try:
                                conn_local = get_db_connection()
                                cursor_local = conn_local.cursor()
                                cursor_local.execute('SELECT api_key, password, server, is_live, account_number FROM broker_credentials WHERE credential_id = ?', (credential_id,))
                                cred_row = cursor_local.fetchone()

                                if cred_row:
                                    cred_dict = decrypt_credential_row(cred_row)
                                    bot_credentials = {
                                        'api_key': cred_dict['api_key'],
                                        'api_secret': cred_dict['password'],
                                        'account_number': cred_dict['account_number'],
                                        'server': cred_dict.get('server', 'spot'),
                                        'broker': broker_name,
                                        'is_live': bool(cred_dict['is_live'])
                                    }
                            except Exception as e:
                                logger.warning(f"Could not load credential details: {e}")
                            finally:
                                if conn_local:
                                    conn_local.close()

                        continuous_bot_trading_loop(bot_id, user_id, bot_credentials)
                    except Exception as e:
                        logger.error(f"Error auto-starting quick bot {bot_id}: {e}")
                        running_bots[bot_id] = False

                bot_thread = threading.Thread(target=_async_start_quick_bot, daemon=True)
                bot_threads[bot_id] = bot_thread
                bot_thread.start()

            logger.info(f"✅ Quick bot created: {bot_id} for user {user_id}")
            logger.info(f"   Preset: {preset} | Symbols: {symbols}")

            return jsonify({
                'success': True,
                'botId': bot_id,
                'status': 'active',
                'message': f'Quick bot created with preset: {preset}',
                'pairs': symbols,
                'strategy': strategy,
                'riskPerTrade': risk_per_trade,
                'managementProfile': management_profile,
                'signalThreshold': signal_threshold,
                'allowedVolatility': allowed_volatility,
                'tradingEnabled': trading_enabled,
            }), 201
            logger.error(f"Error in quick_create_bot: {e}")
            return jsonify({'success': False, 'error': str(e)}), 500
        finally:
            if conn:
                conn.close()


@app.route('/api/bot/start', methods=['POST'])
@require_session
def start_bot():
    """Start automatic trading for a bot with intelligent strategy switching
    
    SECURITY: Requires PIN verification (2FA) before activation
    
    REQUEST FLOW:
    1. User clicks "Start Bot"
    2. Frontend calls POST /api/bot/<bot_id>/request-activation
    3. Backend sends PIN to user email
    4. User enters PIN in app
    5. Frontend calls POST /api/bot/start with activation_pin
    6. Backend verifies PIN and activates bot
    
    Supports HYBRID MODE:
    - DEMO: Trades using shared demo MT5 account
    - LIVE: Trades using user's real MT5 account (if credentials stored)
    """
    try:
        data = request.get_json(silent=True) or {}
        bot_id = data.get('botId')
        user_id = data.get('user_id') or request.user_id  # Get from request or session
        activation_pin = data.get('activation_pin')  # NEW: Required for 2FA
        
        if not user_id:
            return jsonify({'success': False, 'error': 'user_id required'}), 400
        
        # ✅ FIX: Load bot from database if not in active_bots
        if bot_id not in active_bots:
            logger.info(f"[START BOT] Bot {bot_id} not in active_bots, loading from database...")
            conn_load = get_db_connection()
            cursor_load = conn_load.cursor()
            cursor_load.execute('SELECT * FROM user_bots WHERE bot_id = ? AND user_id = ?', (bot_id, user_id))
            db_bot = cursor_load.fetchone()
            conn_load.close()
            
            if not db_bot:
                return jsonify({'success': False, 'error': f'Bot {bot_id} not found or does not belong to this user'}), 404
            
            # Restore bot to active_bots from database
            logger.info(f"[START BOT] Restoring bot {bot_id} from database into active_bots...")
            active_bots[bot_id] = _restore_bot_runtime_state(db_bot)
            
            # Load credential_id from bot_credentials table
            conn_cred = get_db_connection()
            cursor_cred = conn_cred.cursor()
            cursor_cred.execute('SELECT credential_id FROM bot_credentials WHERE bot_id = ? AND user_id = ?', (bot_id, user_id))
            cred_row = cursor_cred.fetchone()
            conn_cred.close()
            
            if cred_row:
                active_bots[bot_id]['credentialId'] = cred_row['credential_id']
                logger.info(f"[START BOT] Loaded credential {cred_row['credential_id']} for bot {bot_id}")
            else:
                logger.warning(f"[START BOT] No credential found for bot {bot_id}")
        
        # Verify bot belongs to user
        bot = active_bots[bot_id]
        if bot.get('user_id') != user_id:
            return jsonify({'success': False, 'error': 'Unauthorized: Bot does not belong to this user'}), 403
        
        # ✅ OPTIONAL: Verify activation PIN (for enhanced security)
        # If PIN is provided, validate it; if not, allow start for backward compatibility
        conn = get_db_connection()
        cursor = conn.cursor()
        
        if activation_pin:
            # PIN PROVIDED: Verify PIN exists, belongs to user, and hasn't expired
            cursor.execute('''
                SELECT * FROM bot_activation_pins 
                WHERE bot_id = ? AND user_id = ? AND pin = ? AND expires_at > ?
            ''', (bot_id, user_id, activation_pin, datetime.now().isoformat()))
            
            pin_record = cursor.fetchone()
            
            if not pin_record:
                # Increment failed attempts
                cursor.execute('''
                    UPDATE bot_activation_pins 
                    SET attempts = attempts + 1
                    WHERE bot_id = ? AND user_id = ?
                ''', (bot_id, user_id))
                conn.commit()
                conn.close()
                
                return jsonify({
                    'success': False, 
                    'error': 'Invalid or expired PIN. Request a new one.',
                    'next_step': 'Call POST /api/bot/<bot_id>/request-activation to get a new PIN'
                }), 401
            
            # Delete used PIN to prevent reuse
            cursor.execute('DELETE FROM bot_activation_pins WHERE bot_id = ? AND user_id = ?', (bot_id, user_id))
            logger.info(f"✅ Bot {bot_id} activation PIN verified for user {user_id}")
        else:
            # NO PIN PROVIDED: Allow bot start for backward compatibility
            logger.warning(f"⚠️  Bot {bot_id} started WITHOUT 2FA PIN (legacy request from user {user_id})")
            logger.warning(f"   Recommendation: Update client to use /api/bot/<bot_id>/request-activation + PIN for security")
        
        cursor.execute('SELECT user_id FROM user_bots WHERE bot_id = ?', (bot_id,))
        db_bot = cursor.fetchone()
        
        if not db_bot or db_bot['user_id'] != user_id:
            conn.close()
            return jsonify({'success': False, 'error': 'Unauthorized: Bot does not belong to this user'}), 403
        
        conn.close()

        # ✅ PER-BOT MUTEX: Prevent duplicate thread spawning from concurrent /start requests
        # Without this, 3 simultaneous POST /api/bot/start calls would all pass the is_alive()
        # check before any thread is registered, spawning 3 trading loops for the same bot.
        bot_lock = get_bot_start_lock(bot_id)
        if not bot_lock.acquire(blocking=False):
            # Another request is already handling startup for this bot (e.g., user tapped Start 3x)
            logger.info(f"Bot {bot_id}: Another /start request is already in progress — returning early")
            bot_config = active_bots.get(bot_id, {})
            return jsonify({
                'success': True,
                'botId': bot_id,
                'status': 'STARTING',
                'message': f'Bot {bot_id} is already being started by another request',
            }), 200

        try:
            # ✅ FAST PATH: If bot thread is already alive (started by create_bot), return immediately
            # This avoids the expensive broker connection + 120s MT5 readiness wait on start_bot
            if bot_id in bot_threads and bot_threads[bot_id].is_alive():
                logger.info(f"Bot {bot_id}: Already running via background thread - returning success immediately")
                bot_config = active_bots[bot_id]
                return jsonify({
                    'success': True,
                    'botId': bot_id,
                    'strategy': bot_config.get('strategy', 'unknown'),
                    'status': 'RUNNING',
                    'message': f'Bot {bot_id} is already trading in background',
                    'tradingInterval': bot_config.get('tradingInterval', 300),
                    'botStats': {
                        'totalTrades': bot_config.get('totalTrades', 0),
                        'winningTrades': bot_config.get('winningTrades', 0),
                        'totalLosses': round(bot_config.get('totalLosses', 0), 2),
                        'totalProfit': round(bot_config.get('totalProfit', 0), 2),
                        'accountBalance': bot_config.get('accountBalance', 0),
                    }
                }), 200

            # Enforce VPS-safe global concurrency cap before expensive broker initialization.
            active_count = get_running_bot_count(exclude_bot_id=bot_id)
            if active_count >= MAX_CONCURRENT_ACTIVE_BOTS:
                logger.warning(
                    f"Bot {bot_id}: Start denied - active cap reached "
                    f"({active_count}/{MAX_CONCURRENT_ACTIVE_BOTS})"
                )
                return jsonify({
                    'success': False,
                    'error': (
                        f'Server is at active bot capacity '
                        f'({MAX_CONCURRENT_ACTIVE_BOTS}). Please stop another bot first.'
                    ),
                    'status': 'CAPACITY_LIMIT',
                    'activeBots': active_count,
                    'capacity': MAX_CONCURRENT_ACTIVE_BOTS,
                }), 429

            # Bot thread not running — connect to broker and start a new thread (INSIDE LOCK)
            # ✅ AUTOMATIC BROKER DETECTION
            credential_id = bot.get('credentialId')

            if not credential_id:
                return jsonify({
                    'success': False,
                    'error': 'Bot missing credentialId - must link to broker credential first'
                }), 400

            broker_type, broker_conn = get_broker_connection(credential_id, user_id, bot_id)

            if broker_conn is None or not hasattr(broker_conn, 'connected'):
                return jsonify({
                    'success': False,
                    'error': f'Failed to connect to broker: {broker_type or broker_conn}',
                    'botId': bot_id,
                    'status': 'FAILED'
                }), 503

            logger.info(f"✅ Bot {bot_id}: Broker connection established ({broker_type})")

            bot_config = active_bots[bot_id]
            bot_config['broker_type'] = broker_type
            bot_config['broker_conn'] = broker_conn
            
            import random
            
            # ✅ VALIDATE & CORRECT BOT SYMBOLS IMMEDIATELY (in case they're old/unavailable)
            # This prevents users from being shown old symbols and ensures trades use valid ones
            original_symbols = bot_config.get('symbols', ['EURUSDm'])
            corrected_symbols = validate_and_correct_symbols(original_symbols, broker_type)
            if broker_type == 'FXCM':
                tradable_keys = _get_fxcm_tradable_symbol_keys(broker_conn=broker_conn)
                tradable_symbols = _filter_fxcm_symbols_for_tradability(corrected_symbols, tradable_keys)
                if tradable_symbols and tradable_symbols != corrected_symbols:
                    logger.info(
                        f"🔄 Bot {bot_id}: Filtered FXCM symbols by tradability: "
                        f"{corrected_symbols} -> {tradable_symbols}"
                    )
                    corrected_symbols = tradable_symbols
            if corrected_symbols != original_symbols:
                logger.info(f"📝 Bot {bot_id} symbols corrected: {original_symbols} → {corrected_symbols}")
                bot_config['symbols'] = corrected_symbols
                active_bots[bot_id] = bot_config
                _persist_normalized_bot_symbols(bot_id, bot_config, corrected_symbols)

            logger.info(f"✅ Bot {bot_id}: All validation checks passed - ready to start trading")

            # Validate symbols are available
            validated_symbols = validate_and_correct_symbols(bot_config.get('symbols', ['EURUSDm']), broker_type)
            bot_config['symbols'] = validated_symbols
            logger.info(f"📍 Bot {bot_id}: Trading symbols validated: {validated_symbols}")
            
            logger.info(f"Bot {bot_id}: Starting CONTINUOUS trading in background thread")
            
            # Bot thread not running or stopped - create a new one
            logger.info(f"Bot {bot_id}: No active thread found - creating new background thread")
            
            # Reset stop flag and start new thread
            bot_stop_flags[bot_id] = False
            
            # ✅ REGISTER BOT AS RUNNING IMMEDIATELY (before thread starts)
            # This prevents dashboard from showing it as stopped during startup
            running_bots[bot_id] = True
            bot_config['enabled'] = True
            persist_bot_runtime_state(bot_id)
            
            bot_thread = threading.Thread(
                target=continuous_bot_trading_loop,
                args=(bot_id, user_id, None),
                daemon=True,
                name=f"BotThread-{bot_id}"
            )
            bot_threads[bot_id] = bot_thread
            bot_thread.start()
            
            logger.info(f"✅ Bot {bot_id}: Background thread launched successfully")
            
            # Return immediately - bot is running in background
            return jsonify({
                'success': True,
                'botId': bot_id,
                'strategy': bot_config['strategy'],
                'status': 'RUNNING',
                'message': f'Bot {bot_id} started - continuous trading in background',
                'tradingInterval': bot_config.get('tradingInterval', 300),
                'botStats': {
                    'totalTrades': bot_config['totalTrades'],
                    'winningTrades': bot_config['winningTrades'],
                    'totalLosses': round(bot_config['totalLosses'], 2),
                    'totalProfit': round(bot_config['totalProfit'], 2),
                    'accountBalance': bot_config.get('accountBalance', 0),
                }
            }), 200

        except Exception:
            raise
        finally:
            bot_lock.release()

    except Exception as e:
        logger.error(f"Error starting bot: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/market/commodities', methods=['GET'])
def get_commodity_market_data():
    """Get market sentiment and price data for all trading commodities (with live prices from MT5)"""
    try:
        # Thread-safe access to commodity_market_data
        with market_data_lock:
            # Count signals in response for debugging
            buy_count = sum(1 for s in commodity_market_data.values() if 'BUY' in s.get('signal', ''))
            sell_count = sum(1 for s in commodity_market_data.values() if 'SELL' in s.get('signal', ''))
            flat_count = sum(1 for s in commodity_market_data.values() if 'CONSOLIDAT' in s.get('signal', '') or 'VOLATILE' in s.get('signal', ''))
            hold_count = sum(1 for s in commodity_market_data.values() if s.get('signal', '') == '🟡 HOLD')
            
            # Log actual signal values for key symbols
            key_symbols = ['EURUSDm', 'XAUUSDm', 'BTCUSDm', 'ETHUSDm']
            for sym in key_symbols:
                if sym in commodity_market_data:
                    sig = commodity_market_data[sym].get('signal', 'UNKNOWN')
                    logger.debug(f"[API] {sym}: signal='{sig}'")
            
            logger.debug(f"[API] Returning commodities: {buy_count} BUY, {sell_count} SELL, {flat_count} FLAT, {hold_count} HOLD")
            
            return jsonify({
                'success': True,
                'commodities': commodity_market_data.copy(),
                'timestamp': datetime.now().isoformat(),
                'note': 'Prices updated live from MT5 every 3 seconds',
            }), 200
    except Exception as e:
        logger.error(f"Error getting market data: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/bot/status', methods=['GET'])
@require_session
def bot_status():
    """Get status of authenticated user's bots only.
    Optional query param: ?mode=LIVE or ?mode=DEMO to filter by trading mode.
    """
    try:
        user_id = request.user_id  # From session token
        mode_filter = request.args.get('mode', '').upper()  # LIVE, DEMO, or '' (all)
        bot_id_filter = (request.args.get('bot_id') or '').strip()
        include_history = _coerce_bool(request.args.get('include_history', 'false'))
        
        bots_list = []
        for bot in active_bots.values():
            # Only return bots for authenticated user
            if bot.get('user_id') != user_id:
                continue
            if bot_id_filter and bot.get('botId') != bot_id_filter:
                continue
            
            # Filter by trading mode if specified
            if mode_filter in ('LIVE', 'DEMO'):
                bot_mode = (bot.get('mode') or 'demo').upper()
                if bot_mode != mode_filter:
                    continue
            
            # Calculate runtime (safely access createdAt)
            created = datetime.fromisoformat(bot.get('createdAt', datetime.now().isoformat()))
            runtime_seconds = (datetime.now() - created).total_seconds()
            runtime_hours = runtime_seconds / 3600
            runtime_minutes = (runtime_seconds % 3600) / 60
            
            # Calculate daily profit (safely access dailyProfits)
            today = datetime.now().strftime('%Y-%m-%d')
            daily_profits = dict(bot.get('dailyProfits', {}))  # Copy so we don't mutate the original
            daily_profit = float(daily_profits.get(today, bot.get('dailyProfit', 0)) or 0)
            
            # Calculate ROI (safely access totalInvestment and totalProfit)
            total_profit = bot.get('totalProfit', 0)
            open_positions = list(bot.get('open_positions', {}).values())
            floating_profit = sum(float(position.get('profit') or 0) for position in open_positions)
            current_profit = total_profit + floating_profit
            
            # Also add historical profit entries from profitHistory if dailyProfits is sparse
            profit_history = bot.get('profitHistory', [])
            for ph in profit_history:
                ph_ts = ph.get('timestamp', 0)
                if ph_ts:
                    ph_date = datetime.fromtimestamp(ph_ts / 1000).strftime('%Y-%m-%d')
                    if ph_date not in daily_profits:
                        daily_profits[ph_date] = round(ph.get('profit', 0), 2)
            investment = float(bot.get('totalInvestment') or bot.get('initialBalance') or 0)
            roi = (total_profit / investment) * 100 if investment > 0 else 0
            current_roi = (current_profit / investment) * 100 if investment > 0 else 0
            
            # Calculate profitability (profit as % of total traded value)
            total_trades = bot.get('totalTrades', 0)
            closed_winning = bot.get('winningTrades', 0)
            effective_win_rate = round((closed_winning / max(total_trades, 1)) * 100, 1) if total_trades > 0 else 0
            if total_trades > 0:
                avg_trade_profit = total_profit / total_trades
                profitability = avg_trade_profit
            else:
                profitability = 0
            
            # Calculate profit factor - capped at 99.99 to avoid JSON infinity issues
            total_losses = bot.get('totalLosses', 0)
            if total_losses > 0:
                profit_factor = min(total_profit / total_losses, 99.99) if total_profit > 0 else 0
            else:
                profit_factor = 99.99 if total_profit > 0 else 0
            
            # Safely access symbols and other fields
            symbols = bot.get('symbols', [])
            if open_positions:
                symbol = open_positions[0].get('symbol', 'EURUSDm')
            elif len(symbols) == 1:
                symbol = symbols[0]
            elif len(symbols) > 1:
                symbol = 'MULTI'
            else:
                symbol = 'EURUSDm'
            trade_history = bot.get('tradeHistory', [])
            last_trade_time = trade_history[-1].get('time') if trade_history else bot.get('createdAt', datetime.now().isoformat())
            bot_mode_value = (bot.get('mode') or 'demo')
            bot_is_live = str(bot_mode_value).lower() == 'live'
            display_currency = _resolve_display_currency_for_mode(bot_mode_value, bot.get('displayCurrency', 'USD'))
            
            enhanced_bot = {
                'botId': bot.get('botId', 'unknown'),
                'symbol': symbol,
                'symbols': symbols,
                'strategy': bot.get('strategy', 'Unknown'),
                'commission': round(max(total_profit, 0) * 0.01, 2),
                'profit': round(current_profit, 2),
                'totalProfit': round(total_profit, 2),
                'floatingProfit': round(floating_profit, 2),
                'currentProfit': round(current_profit, 2),
                'totalTrades': bot.get('totalTrades', 0),
                'winningTrades': bot.get('winningTrades', 0),
                'winRate': effective_win_rate,
                'closedWinRate': effective_win_rate,
                'maxDrawdown': round(bot.get('maxDrawdown', 0), 2),
                'runtimeFormatted': f"{int(runtime_hours)}h {int(runtime_minutes)}m",
                'dailyProfit': round(daily_profit, 2),
                'roi': round(roi, 2),
                'realizedRoi': round(roi, 2),
                'currentRoi': round(current_roi, 2),
                'roiBasis': round(investment, 2),
                'roiBasisKnown': investment > 0,
                'profitability': round(profitability if total_trades > 0 else current_profit, 2),
                'profitFactor': round(profit_factor, 2),
                'avgProfitPerTrade': round(total_profit / max(bot.get('totalTrades', 1), 1), 2),
                'enabled': bot.get('enabled', True),
                'status': 'Active' if bot.get('enabled', True) else 'Inactive',
                'pauseReason': bot.get('pauseReason'),
                'stopReason': bot.get('stopReason'),  # Why bot was auto-stopped (e.g., external close)
                'lastPauseEvent': bot.get('lastPauseEvent'),  # Include last market pause event
                'displayCurrency': display_currency,
                'maxOpenPositions': bot.get('maxOpenPositions', 5),
                'maxPositionsPerSymbol': bot.get('maxPositionsPerSymbol', 1),
                'signalThreshold': _effective_signal_threshold_for_display(bot),
                'managementMode': bot.get('managementMode', 'assisted'),
                'managementProfile': bot.get('managementProfile', 'beginner'),
                'managementState': bot.get('managementState', 'normal'),
                'drawdownPauseUntil': bot.get('drawdownPauseUntil'),
                'lastTradeTime': last_trade_time,
                'broker_type': bot.get('broker_type', 'MT5'),
                'mode': str(bot_mode_value).upper(),
                'is_live': bot_is_live,
                'profitField': round(current_profit, 2),
                'openPositions': open_positions,  # Currently open positions
                'accountBalance': round(bot.get('accountBalance', 0), 2),  # Latest known balance
                'accountEquity': round(bot.get('accountEquity', 0), 2),  # Latest known equity
                'effectiveTradeAmount': round(_safe_float(bot.get('effectiveTradeAmount'), _safe_float(bot.get('tradeAmount'), 0.0)), 2),
                'tradeAmountAdaptation': bot.get('tradeAmountAdaptation'),
                'portfolioGuard': _evaluate_user_portfolio_profit_guard(bot),
            }
            if include_history:
                enhanced_bot['tradeHistory'] = trade_history  # Include full trade history for analytics
                enhanced_bot['dailyProfits'] = daily_profits  # Include daily profits map for charts
            bots_list.append(enhanced_bot)
        
        return jsonify({
            'success': True,
            'activeBots': len([b for b in bots_list if b.get('enabled', True) or b.get('status') == 'Active']),
            'bots': bots_list,
            'timestamp': datetime.now().isoformat(),
        }), 200
    
    except Exception as e:
        logger.error(f"Error getting bot status: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


def _compute_spot_pip_distance(symbol: str, reference_price: float) -> float:
    """Translate a 'pip' for a Binance spot symbol into an absolute price distance.

    Strategy SL/TP is expressed in pips. For forex/metals there is a fixed pip size,
    but for crypto USDT pairs price magnitudes vary wildly (BTC ~ $80k, SOL ~ $80,
    SHIB < $0.001) so a flat pip size makes 1 pip either trivial or useless.

    Rule:
      * If symbol ends in USDT (or USDC/BUSD/USD) and reference_price > 0,
        treat 1 pip as 1 basis point of price (price * 0.0001).
      * Otherwise fall back to the static get_pip_size() table.
    """
    try:
        from rest_price_feed import get_pip_size
    except Exception:
        get_pip_size = None  # type: ignore

    sym = (symbol or '').upper()
    ref = _safe_float(reference_price, 0.0)
    quote_is_stable = any(sym.endswith(stable) for stable in ('USDT', 'USDC', 'BUSD', 'FDUSD', 'TUSD', 'USD'))
    if quote_is_stable and ref > 0:
        # 1 pip = 1 bp of price -> 15 pips ≈ 0.15% move (sane across all magnitudes)
        return round(ref * 0.0001, 10)
    if get_pip_size is not None:
        try:
            return float(get_pip_size(sym))
        except Exception:
            return 0.0001
    return 0.0001


def _resolve_open_position_profit(position: Dict[str, Any]) -> float:
    explicit_profit = position.get('profit')
    if explicit_profit is None:
        explicit_profit = position.get('pnl', position.get('profit_loss', position.get('unrealizedPL', 0.0)))

    profit = _safe_float(explicit_profit, 0.0)
    if abs(profit) > 1e-9:
        return round(profit, 2)

    entry_price = _safe_float(
        position.get('entryPrice', position.get('openPrice', position.get('level', position.get('price', 0.0)))),
        0.0,
    )
    current_price = _safe_float(
        position.get('currentPrice', position.get('marketPrice', position.get('price_current', 0.0))),
        0.0,
    )
    volume = abs(_safe_float(position.get('volume', position.get('size', position.get('amount', 0.0))), 0.0))
    direction = str(position.get('type') or position.get('direction') or '').strip().upper()

    if entry_price <= 0 or current_price <= 0 or volume <= 0:
        return round(profit, 2)

    if 'BUY' in direction:
        estimated_profit = (current_price - entry_price) * volume
    elif 'SELL' in direction:
        estimated_profit = (entry_price - current_price) * volume
    else:
        estimated_profit = profit

    return round(estimated_profit, 2)


def _run_binance_spot_tracker(bot_id: str, bot_config: Dict[str, Any], active_conn: Any,
                              broker_type: str, user_id: str) -> bool:
    """Refresh floating P&L and fire TP/SL auto-close for Binance spot positions.

    Safe to call from any context (cycle loop or polling heartbeat). No-ops unless
    the bot is connected to Binance spot. Returns True if any position changed
    (price refresh or auto-close), so the caller can persist runtime state.
    """
    try:
        if not active_conn or broker_type != 'Binance':
            return False
        if getattr(active_conn, 'market', 'spot') == 'futures':
            return False
        tracked_positions = bot_config.get('open_positions', {})
        # Self-heal: if in-memory map is empty but DB has open rows for this bot,
        # rehydrate. Covers long-running bots that missed cycle==1 rehydration.
        if not tracked_positions:
            try:
                _heal_conn = build_sqlite_connection(timeout=10.0)
                _heal_cur = _heal_conn.cursor()
                _heal_cur.execute(
                    "SELECT COUNT(*) FROM trades WHERE bot_id = ? AND status = 'open'",
                    (bot_id,),
                )
                _heal_count = (_heal_cur.fetchone() or [0])[0] or 0
                _heal_conn.close()
            except Exception:
                _heal_count = 0
            if _heal_count > 0:
                try:
                    _merge_bot_trade_history_from_db(bot_config, bot_id)
                    tracked_positions = bot_config.get('open_positions', {}) or {}
                    if tracked_positions:
                        logger.info(
                            f"♻️ Bot {bot_id}: Spot tracker self-healed {len(tracked_positions)} "
                            f"open position(s) from DB: {list(tracked_positions.keys())}"
                        )
                except Exception as _heal_err:
                    logger.warning(f"Bot {bot_id}: Spot tracker self-heal failed: {_heal_err}")
            if not tracked_positions:
                return False
    except Exception:
        return False

    spot_persist_needed = False
    for spot_ticket, tracked in list(tracked_positions.items()):
        try:
            tracked_symbol = tracked.get('symbol', '')
            if not tracked_symbol:
                continue
            live_price = 0.0
            try:
                if hasattr(active_conn, '_get_spot_symbol_price'):
                    live_price = _safe_float(active_conn._get_spot_symbol_price(tracked_symbol), 0.0)
            except Exception:
                live_price = 0.0
            if live_price <= 0:
                try:
                    live_price = _safe_float(
                        commodity_market_data.get(tracked_symbol, {}).get('current_price'),
                        _safe_float(tracked.get('currentPrice'), 0.0),
                    )
                except Exception:
                    live_price = _safe_float(tracked.get('currentPrice'), 0.0)
            if live_price <= 0:
                continue

            tracked['currentPrice'] = live_price
            tracked['profit'] = _resolve_open_position_profit(tracked)
            tracked['isWinning'] = tracked['profit'] > 0

            for trade in bot_config.get('tradeHistory', []):
                if str(trade.get('ticket')) == str(spot_ticket) and trade.get('status') == 'open':
                    trade['currentPrice'] = live_price
                    trade['profit'] = tracked['profit']
                    trade['isWinning'] = tracked['profit'] > 0
                    break
            spot_persist_needed = True

            direction = str(tracked.get('type') or tracked.get('direction') or '').upper()
            if 'BUY' not in direction:
                continue
            sl_price = _safe_float(tracked.get('stopLossPrice'), 0.0)
            tp_price = _safe_float(tracked.get('takeProfitPrice'), 0.0)

            # Lazy backfill for legacy positions without absolute SL/TP levels
            if sl_price <= 0 or tp_price <= 0:
                _entry = _safe_float(tracked.get('entryPrice'), 0.0)
                _sl_pips = _safe_float(tracked.get('slPips'), 0.0)
                _tp_pips = _safe_float(tracked.get('tpPips'), 0.0)
                if _sl_pips <= 0:
                    _sl_pips = 30.0
                if _tp_pips <= 0:
                    _tp_pips = 100.0
                try:
                    _pip_dist = _safe_float(
                        tracked.get('pipDistance'),
                        _compute_spot_pip_distance(tracked_symbol, live_price),
                    )
                except Exception:
                    _pip_dist = live_price * 0.0001
                if _pip_dist <= 0:
                    _pip_dist = live_price * 0.0001
                if _entry > 0 and sl_price <= 0:
                    sl_price = round(_entry - _sl_pips * _pip_dist, 8)
                    tracked['stopLossPrice'] = sl_price
                if _entry > 0 and tp_price <= 0:
                    tp_price = round(_entry + _tp_pips * _pip_dist, 8)
                    tracked['takeProfitPrice'] = tp_price
                tracked['slPips'] = _sl_pips
                tracked['tpPips'] = _tp_pips
                tracked['pipDistance'] = _pip_dist
                logger.info(
                    f"🔧 Bot {bot_id}: Backfilled SL/TP for {tracked_symbol} "
                    f"entry={_entry} sl={sl_price} tp={tp_price} "
                    f"(slPips={_sl_pips}, tpPips={_tp_pips}, pipDist={_pip_dist})"
                )

            trigger_reason = None
            if tp_price > 0 and live_price >= tp_price:
                trigger_reason = 'TP_HIT'
            elif sl_price > 0 and live_price <= sl_price:
                trigger_reason = 'SL_HIT'

            # Position-age fallback: if BUY has been camping for longer than
            # `maxPositionAgeHours` and is at break-even or better, auto-SELL
            # so the bot can free spot inventory and trade again. Without this
            # a Binance spot bot can sit on a single BUY for hours when SL/TP
            # never trigger — the user reported this as "1 trade then stale".
            if not trigger_reason:
                try:
                    _max_age_h = _safe_float(bot_config.get('maxPositionAgeHours'), 4.0)
                    if _max_age_h > 0:
                        _entry_iso = str(tracked.get('entryTime') or tracked.get('time') or '').strip()
                        if _entry_iso:
                            try:
                                _entry_dt = datetime.fromisoformat(_entry_iso.replace('Z', ''))
                                _age_hours = (datetime.now() - _entry_dt).total_seconds() / 3600.0
                            except Exception:
                                _age_hours = 0.0
                            if _age_hours >= _max_age_h:
                                _cur_pnl = _safe_float(tracked.get('profit'), 0.0)
                                _be_floor = _safe_float(bot_config.get('agedClosePnlFloor'), -2.0)
                                if _cur_pnl >= _be_floor:
                                    trigger_reason = 'POSITION_AGE_TIMEOUT'
                                    logger.info(
                                        f"⏳ Bot {bot_id}: {tracked_symbol} BUY held for {_age_hours:.1f}h "
                                        f"(>= {_max_age_h}h) at PnL={_cur_pnl} — auto-SELL to free inventory"
                                    )
                                else:
                                    logger.debug(
                                        f"Bot {bot_id}: {tracked_symbol} BUY age {_age_hours:.1f}h but PnL {_cur_pnl} < floor {_be_floor} — holding"
                                    )
                except Exception as _age_err:
                    logger.debug(f"Bot {bot_id}: age-close eval failed: {_age_err}")

            if not trigger_reason:
                continue

            logger.info(
                f"🎯 Bot {bot_id}: {trigger_reason} for {tracked_symbol} @ {live_price:.6f} "
                f"(entry={tracked.get('entryPrice')} sl={sl_price} tp={tp_price}) — issuing SELL"
            )

            sell_volume = abs(_safe_float(tracked.get('volume'), 0.0))
            if sell_volume <= 0:
                logger.warning(f"Bot {bot_id}: Cannot auto-close {spot_ticket} — tracked volume is 0")
                continue

            # NOTIONAL PRE-CHECK: skip auto-close if (volume * price) is below Binance min-notional.
            # Otherwise Binance rejects with -1013 NOTIONAL and the position becomes a phantom.
            try:
                _spot_snapshot = _get_binance_spot_inventory_snapshot(active_conn, tracked_symbol, market_price=live_price)
                _min_notional = _safe_float(_spot_snapshot.get('minNotional'), 0.0)
                _proposed_notional = sell_volume * live_price
                if _min_notional > 0 and _proposed_notional > 0 and _proposed_notional < _min_notional:
                    logger.warning(
                        f"Bot {bot_id}: Skipping auto-close SELL on {tracked_symbol} — "
                        f"notional {_proposed_notional:.4f} < minNotional {_min_notional:.4f} "
                        f"(volume={sell_volume:.8f} price={live_price:.6f}). Position retained; will retry when price/volume qualify."
                    )
                    continue
            except Exception as _notional_err:
                logger.debug(f"Bot {bot_id}: NOTIONAL pre-check skipped on {tracked_symbol}: {_notional_err}")

            close_result = None
            try:
                close_result = active_conn.place_order(
                    symbol=tracked_symbol,
                    order_type='SELL',
                    volume=round(sell_volume, 6),
                    market_price=live_price,
                )
            except Exception as close_err:
                logger.error(f"Bot {bot_id}: Auto-close SELL exception on {tracked_symbol}: {close_err}")
                continue

            if not close_result or not close_result.get('success', False):
                logger.warning(
                    f"Bot {bot_id}: Auto-close SELL rejected on {tracked_symbol}: "
                    f"{(close_result or {}).get('error', 'unknown')}"
                )
                continue

            exec_price = _safe_float(
                close_result.get('avgPrice') or close_result.get('price'),
                live_price,
            )
            entry_price = _safe_float(tracked.get('entryPrice'), 0.0)
            executed_qty = _safe_float(close_result.get('executedQty'), sell_volume)
            realized_profit = (
                round((exec_price - entry_price) * executed_qty, 4)
                if entry_price > 0 and exec_price > 0
                else 0.0
            )

            close_time_iso = datetime.now().isoformat()
            closed_trade = {
                'ticket': spot_ticket,
                'symbol': tracked_symbol,
                'type': direction,
                'volume': executed_qty,
                'entryPrice': entry_price,
                'exitPrice': exec_price,
                'currentPrice': exec_price,
                'profit': realized_profit,
                'entryTime': tracked.get('entryTime', ''),
                'exitTime': close_time_iso,
                'time': close_time_iso,
                'timestamp': int(datetime.now().timestamp() * 1000),
                'botId': bot_id,
                'cycle': tracked.get('cycle', 0),
                'strategy': tracked.get('strategy', ''),
                'closeReason': trigger_reason,
                'isWinning': realized_profit > 0,
                'status': 'closed',
                'source': 'REAL_BINANCE_SPOT_AUTO_CLOSE',
                'broker': broker_type,
            }

            try:
                trade_conn = build_sqlite_connection(timeout=30.0)
                trade_cursor = trade_conn.cursor()
                trade_cursor.execute(
                    '''UPDATE trades SET profit = ?, status = 'closed', time_close = ?,
                       trade_data = ?, updated_at = ?
                       WHERE ticket = ? AND bot_id = ? AND status = 'open' ''',
                    (
                        realized_profit,
                        close_time_iso,
                        json.dumps(closed_trade),
                        datetime.now().isoformat(),
                        str(spot_ticket),
                        bot_id,
                    ),
                )
                if trade_cursor.rowcount == 0:
                    trade_id = f"trade_{int(datetime.now().timestamp()*1000)}_{bot_id[-8:]}"
                    trade_cursor.execute(
                        '''INSERT INTO trades (trade_id, bot_id, user_id, symbol, order_type, volume, price, profit, ticket, time_open, time_close, status, created_at, trade_data, timestamp)
                           VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)''',
                        (
                            trade_id, bot_id, user_id,
                            closed_trade['symbol'], closed_trade['type'],
                            closed_trade['volume'], closed_trade['entryPrice'],
                            realized_profit, str(spot_ticket),
                            closed_trade['entryTime'], closed_trade['exitTime'],
                            'closed', datetime.now().isoformat(),
                            json.dumps(closed_trade),
                            closed_trade['timestamp'],
                        ),
                    )
                trade_conn.commit()
                trade_conn.close()
            except Exception as db_e:
                logger.error(f"Bot {bot_id}: Auto-close DB update failed: {db_e}")

            trade_history = bot_config.setdefault('tradeHistory', [])
            existing_index = next(
                (idx for idx, existing in enumerate(trade_history)
                 if str(existing.get('ticket')) == str(spot_ticket)),
                None,
            )
            if existing_index is None:
                trade_history.append(closed_trade)
                bot_config['totalTrades'] = bot_config.get('totalTrades', 0) + 1
            else:
                trade_history[existing_index] = {
                    **trade_history[existing_index],
                    **closed_trade,
                }
            if realized_profit > 0:
                bot_config['winningTrades'] = bot_config.get('winningTrades', 0) + 1
            else:
                bot_config['totalLosses'] = bot_config.get('totalLosses', 0) + abs(realized_profit)
            bot_config['totalProfit'] = bot_config.get('totalProfit', 0) + realized_profit

            bot_config.get('open_positions', {}).pop(spot_ticket, None)
            spot_persist_needed = True

            logger.info(
                f"✅ Bot {bot_id}: Auto-closed {tracked_symbol} via {trigger_reason} | "
                f"entry={entry_price:.6f} exit={exec_price:.6f} vol={executed_qty:.6f} "
                f"profit={realized_profit:.4f} USDT"
            )
        except Exception as spot_close_err:
            logger.error(f"Bot {bot_id}: Spot tracker error on {spot_ticket}: {spot_close_err}")

    if spot_persist_needed:
        try:
            persist_bot_runtime_state(bot_id, force=False)
        except Exception:
            pass
    return spot_persist_needed


def _normalize_broker_position_preview(position: Dict[str, Any]) -> Dict[str, Any]:
    return {
        'ticket': position.get('ticket') or position.get('deal_id') or position.get('position') or position.get('positionId'),
        'symbol': position.get('symbol') or position.get('instrument') or '',
        'type': position.get('type') or position.get('direction') or '',
        'volume': _safe_float(position.get('volume', position.get('size', position.get('amount', 0.0))), 0.0),
        'entryPrice': _safe_float(position.get('entryPrice', position.get('openPrice', position.get('level', position.get('price', 0.0)))), 0.0),
        'currentPrice': _safe_float(position.get('currentPrice', position.get('marketPrice', position.get('price_current', 0.0))), 0.0),
        'profit': _resolve_open_position_profit(position),
        'broker': position.get('broker', 'FXCM'),
    }


def _normalize_broker_trade_preview(trade: Dict[str, Any]) -> Dict[str, Any]:
    time_value = trade.get('time') or trade.get('time_close') or trade.get('closeTime') or trade.get('time_open') or trade.get('openTime')
    return {
        'ticket': trade.get('ticket') or trade.get('deal_id') or trade.get('tradeId') or trade.get('trade_id'),
        'symbol': trade.get('symbol') or trade.get('instrument') or '',
        'type': trade.get('type') or trade.get('direction') or '',
        'volume': _safe_float(trade.get('volume', trade.get('size', trade.get('amount', 0.0))), 0.0),
        'entryPrice': _safe_float(trade.get('entryPrice', trade.get('openPrice', trade.get('price', 0.0))), 0.0),
        'exitPrice': _safe_float(trade.get('exitPrice', trade.get('closePrice', 0.0)), 0.0),
        'profit': round(_safe_float(trade.get('profit', trade.get('pnl', trade.get('profit_loss', 0.0))), 0.0), 2),
        'status': trade.get('status', 'closed'),
        'time': time_value,
        'time_open': trade.get('time_open') or trade.get('openTime'),
        'time_close': trade.get('time_close') or trade.get('closeTime') or time_value,
        'broker': trade.get('broker', 'FXCM'),
    }


def _build_fxcm_bot_broker_snapshot(
    user_id: str,
    bot: Dict[str, Any],
    snapshot_cache: Optional[Dict[str, Dict[str, Any]]] = None,
) -> Dict[str, Any]:
    credential_id = str(bot.get('credentialId') or '').strip()
    if not credential_id:
        return {'fetched': False, 'positions': [], 'recentTrades': [], 'accountInfo': {}, 'dataSource': 'missing-credential'}

    if snapshot_cache is not None and credential_id in snapshot_cache:
        cached_snapshot = snapshot_cache[credential_id]
    else:
        cached_snapshot = _get_cached_fxcm_endpoint_snapshot(credential_id)

    if cached_snapshot is None:
        account_info = {}
        positions = []
        trades = []
        data_source = 'unavailable'
        broker_conn = None
        try:
            broker_type, broker_conn = get_broker_connection(credential_id, user_id, bot_id=f"summary:{bot.get('botId', credential_id)}")
            if broker_type == 'FXCM' and _is_live_broker_connection(broker_conn):
                account_info = broker_conn.get_account_info() or {}
                positions = broker_conn.get_positions() or []
                trades = broker_conn.get_trades() or []
                data_source = account_info.get('dataSource', 'live') if isinstance(account_info, dict) else 'live'
            elif broker_conn:
                data_source = 'connection-error'
                logger.warning(
                    f"Could not build live FXCM snapshot for bot {bot.get('botId')}: invalid connection result {broker_conn}"
                )
        except Exception as exc:
            logger.warning(f"Could not build live FXCM snapshot for bot {bot.get('botId')}: {exc}")
            data_source = 'error'
        finally:
            if hasattr(broker_conn, 'disconnect'):
                broker_conn.disconnect()

        cached_snapshot = {
            'fetched': True,
            'positions': [_normalize_broker_position_preview(position) for position in positions],
            'recentTrades': [_normalize_broker_trade_preview(trade) for trade in trades],
            'accountInfo': account_info if isinstance(account_info, dict) else {},
            'dataSource': data_source,
        }
        _store_fxcm_endpoint_snapshot(
            credential_id,
            account_info=cached_snapshot['accountInfo'],
            positions=cached_snapshot['positions'],
            trades=cached_snapshot['recentTrades'],
            data_source=data_source,
        )
        if snapshot_cache is not None:
            snapshot_cache[credential_id] = cached_snapshot

    bot_symbols = bot.get('symbols', []) or []
    bot_symbol_keys: Set[str] = set()
    for symbol in bot_symbols:
        bot_symbol_keys.update(_get_fxcm_symbol_candidate_keys(str(symbol or '')))

    tracked_tickets = {
        str(ticket)
        for ticket in (bot.get('open_positions') or {}).keys()
        if str(ticket).strip()
    }
    for trade in bot.get('tradeHistory') or []:
        if str(trade.get('status') or '').lower() == 'open':
            trade_ticket = str(trade.get('ticket') or '').strip()
            if trade_ticket:
                tracked_tickets.add(trade_ticket)

    def _position_matches(position: Dict[str, Any]) -> bool:
        position_ticket = str(position.get('ticket') or '').strip()
        if position_ticket and position_ticket in tracked_tickets:
            return True
        position_symbol_keys = _get_fxcm_symbol_candidate_keys(str(position.get('symbol') or ''))
        return bool(position_symbol_keys and position_symbol_keys & bot_symbol_keys)

    def _trade_matches(trade: Dict[str, Any]) -> bool:
        trade_ticket = str(trade.get('ticket') or '').strip()
        if trade_ticket and trade_ticket in tracked_tickets:
            return True
        trade_symbol_keys = _get_fxcm_symbol_candidate_keys(str(trade.get('symbol') or ''))
        return bool(trade_symbol_keys and trade_symbol_keys & bot_symbol_keys)

    filtered_positions = [position for position in cached_snapshot.get('positions', []) if _position_matches(position)]
    filtered_trades = [trade for trade in cached_snapshot.get('recentTrades', []) if _trade_matches(trade)]

    return {
        'fetched': bool(cached_snapshot.get('fetched')),
        'positions': filtered_positions,
        'recentTrades': filtered_trades[:10],
        'accountInfo': cached_snapshot.get('accountInfo', {}),
        'dataSource': cached_snapshot.get('dataSource', 'live'),
    }


@app.route('/api/bot/summary', methods=['GET'])
@require_session
def bot_summary():
    """Return lightweight bot card data for dashboard polling."""
    try:
        user_id = request.user_id
        mode_filter = request.args.get('mode', '').upper()

        has_matching_runtime_bot = False
        for bot in active_bots.values():
            if bot.get('user_id') != user_id:
                continue
            if mode_filter in ('LIVE', 'DEMO'):
                bot_mode = str(bot.get('mode') or 'demo').upper()
                if bot_mode != mode_filter:
                    continue
            has_matching_runtime_bot = True
            break

        if not has_matching_runtime_bot:
            load_user_bots_from_database(enabled_only=False)

        bots_list = []
        fxcm_snapshot_cache: Dict[str, Dict[str, Any]] = {}
        for bot in active_bots.values():
            if bot.get('user_id') != user_id:
                continue

            if mode_filter in ('LIVE', 'DEMO'):
                bot_mode = (bot.get('mode') or 'demo').upper()
                if bot_mode != mode_filter:
                    continue

            if bot.get('tradeHistory'):
                _rebuild_bot_profit_tracking(bot)

            created_at = bot.get('createdAt', datetime.now().isoformat())
            created = datetime.fromisoformat(created_at)
            runtime_seconds = (datetime.now() - created).total_seconds()
            runtime_hours = runtime_seconds / 3600
            runtime_minutes = (runtime_seconds % 3600) / 60

            today = datetime.now().strftime('%Y-%m-%d')
            daily_profit = float((bot.get('dailyProfits') or {}).get(today, bot.get('dailyProfit', 0)) or 0)
            total_profit = float(bot.get('totalProfit', 0) or 0)
            runtime_open_positions = list(bot.get('open_positions', {}).values())
            open_positions = [
                {**position, 'profit': _resolve_open_position_profit(position)}
                for position in runtime_open_positions
            ]
            broker_confirmed_positions = []
            broker_recent_trades = []
            broker_snapshot_source = None
            floating_profit = sum(_resolve_open_position_profit(position) for position in open_positions)
            current_profit = total_profit + floating_profit
            total_trades = int(bot.get('totalTrades', 0) or 0)
            winning_trades = int(bot.get('winningTrades', 0) or 0)
            win_rate = round((winning_trades / total_trades) * 100, 1) if total_trades > 0 else 0
            investment = float(bot.get('totalInvestment') or bot.get('initialBalance') or 0)
            realized_roi = (total_profit / investment) * 100 if investment > 0 else 0

            symbols = bot.get('symbols', []) or []
            primary_symbol = open_positions[0].get('symbol', 'EURUSDm') if open_positions else (symbols[0] if len(symbols) == 1 else ('MULTI' if len(symbols) > 1 else 'EURUSDm'))
            trade_history = bot.get('tradeHistory', [])
            last_trade_time = trade_history[-1].get('time') if trade_history else created_at
            bot_mode_value = (bot.get('mode') or 'demo')
            bot_is_live = str(bot_mode_value).lower() == 'live'
            display_currency = _resolve_display_currency_for_mode(bot_mode_value, bot.get('displayCurrency', 'USD'))
            broker_name = canonicalize_broker_name(bot.get('brokerName') or bot.get('broker_type') or bot.get('broker') or 'MT5')
            if broker_name == 'FXCM':
                fxcm_snapshot = _build_fxcm_bot_broker_snapshot(user_id, bot, fxcm_snapshot_cache)
                if fxcm_snapshot.get('fetched'):
                    broker_confirmed_positions = list(fxcm_snapshot.get('positions') or [])
                    broker_recent_trades = list(fxcm_snapshot.get('recentTrades') or [])
                    broker_snapshot_source = fxcm_snapshot.get('dataSource')
                    open_positions = broker_confirmed_positions
                    floating_profit = sum(_resolve_open_position_profit(position) for position in open_positions)
                    current_profit = total_profit + floating_profit

            account_number = str(bot.get('accountNumber') or bot.get('account_number') or '').strip()
            if not account_number:
                account_id = str(bot.get('accountId') or '').strip()
                broker_prefix = f"{broker_name}_"
                if account_id.lower().startswith(broker_prefix.lower()):
                    account_number = account_id[len(broker_prefix):].strip()
                elif '_' in account_id:
                    account_number = account_id.split('_', 1)[1].strip()
            promotion_state = _get_demo_promotion_state(bot, current_profit, total_trades)
            last_strategy_selection = bot.get('lastStrategySelection') if isinstance(bot.get('lastStrategySelection'), dict) else None
            strategy_history = bot.get('strategyHistory') if isinstance(bot.get('strategyHistory'), list) else []
            last_strategy_event = strategy_history[-1] if strategy_history else None
            last_scan_results = bot.get('lastScanResults') if isinstance(bot.get('lastScanResults'), dict) else None
            last_sizing_adjustment = bot.get('lastSizingAdjustment') if isinstance(bot.get('lastSizingAdjustment'), dict) else None
            pyramid_open_count = sum(1 for position in open_positions if position.get('isPyramidAddon'))
            if promotion_state.get('stateChanged'):
                persist_bot_runtime_state(bot.get('botId', ''))

            open_positions_preview = []
            for pos in open_positions[:5]:
                open_positions_preview.append({
                    'ticket': pos.get('ticket') or pos.get('position') or pos.get('positionId'),
                    'symbol': pos.get('symbol'),
                    'type': pos.get('type'),
                    'volume': pos.get('volume'),
                    'entryPrice': pos.get('entryPrice') or pos.get('price'),
                    'currentPrice': pos.get('currentPrice'),
                    'profit': pos.get('profit'),
                    'lockedProfitFloor': round(_safe_float(pos.get('lockedProfitFloor'), 0.0), 2),
                    'breakEvenFloor': round(_safe_float(pos.get('breakEvenFloor'), 0.0), 2),
                    'profitProtectionArmed': bool(pos.get('profitProtectionArmed', False)),
                    'profitProtectionBucket': pos.get('profitProtectionBucket'),
                    'isPyramidAddon': bool(pos.get('isPyramidAddon', False)),
                    'pyramidParentTicket': pos.get('pyramidParentTicket'),
                })

            active_symbol_cooldowns = []
            cooldowns = bot.get('symbolReentryCooldowns') or {}
            seen_cooldowns = set()
            for cooldown_key, cooldown_entry in cooldowns.items():
                if not isinstance(cooldown_entry, dict):
                    continue
                until_raw = cooldown_entry.get('until')
                try:
                    until_dt = datetime.fromisoformat(str(until_raw))
                except Exception:
                    continue
                if until_dt <= datetime.now():
                    continue
                base_symbol = cooldown_entry.get('baseSymbol') or cooldown_key
                if base_symbol in seen_cooldowns:
                    continue
                seen_cooldowns.add(base_symbol)
                active_symbol_cooldowns.append({
                    'symbol': base_symbol,
                    'until': until_dt.isoformat(),
                    'reason': cooldown_entry.get('reason'),
                })

            # Calculate cumulative profit protection floor (30% max loss)
            cumulative_profit = float(total_profit or 0)
            cumulative_loss_allowance = (cumulative_profit * 0.30) if cumulative_profit > 0 else 0
            current_day_profit = (bot.get('dailyProfits') or {}).get(today, 0.0)
            open_position_pnl = sum([float(pos.get('profit', 0)) for pos in open_positions])
            current_session_pnl = current_day_profit + open_position_pnl
            current_session_loss = abs(current_session_pnl) if current_session_pnl < 0 else 0
            cumulative_protection_status = 'active' if cumulative_loss_allowance > 0 else 'inactive'
            if cumulative_loss_allowance > 0 and current_session_loss >= cumulative_loss_allowance:
                cumulative_protection_status = 'triggered'

            effective_signal_threshold = _effective_signal_threshold_for_display(bot)
            last_no_trade_reason = bot.get('lastNoTradeReason')
            if isinstance(last_no_trade_reason, str) and 'no qualifying setups' in last_no_trade_reason and 'threshold=' in last_no_trade_reason:
                last_no_trade_reason = re.sub(
                    r"threshold=\d+(?:\.\d+)?/100",
                    f"threshold={effective_signal_threshold}/100",
                    last_no_trade_reason,
                )

            bots_list.append({
                'botId': bot.get('botId', 'unknown'),
                'symbol': primary_symbol,
                'symbols': symbols,
                'strategy': bot.get('strategy', 'Unknown'),
                'profit': round(current_profit, 2),
                'totalProfit': round(total_profit, 2),
                'floatingProfit': round(floating_profit, 2),
                'currentProfit': round(current_profit, 2),
                'dailyProfit': round(daily_profit, 2),
                'totalTrades': total_trades,
                'winningTrades': winning_trades,
                'winRate': win_rate,
                'roi': round(realized_roi, 2),
                'realizedRoi': round(realized_roi, 2),
                'roiBasis': round(investment, 2),
                'roiBasisKnown': investment > 0,
                'avgProfitPerTrade': round(total_profit / total_trades, 2) if total_trades > 0 else 0,
                'maxDrawdown': round(bot.get('maxDrawdown', 0), 2),
                'runtimeFormatted': f"{int(runtime_hours)}h {int(runtime_minutes)}m",
                'enabled': bot.get('enabled', True),
                'status': 'Active' if bot.get('enabled', True) else 'Inactive',
                'pauseReason': bot.get('pauseReason'),
                'lastNoTradeReason': last_no_trade_reason,
                'lastNoTradeAt': bot.get('lastNoTradeAt'),
                'stopReason': bot.get('stopReason'),
                'lastPauseEvent': bot.get('lastPauseEvent'),
                'displayCurrency': display_currency,
                'maxOpenPositions': bot.get('maxOpenPositions', 5),
                'maxPositionsPerSymbol': bot.get('maxPositionsPerSymbol', 1),
                'signalThreshold': effective_signal_threshold,
                'managementMode': bot.get('managementMode', 'assisted'),
                'managementProfile': bot.get('managementProfile', 'beginner'),
                'autoAdaptationEnabled': _coerce_bool(bot.get('autoAdaptationEnabled', True), True),
                'lastAdaptationAt': bot.get('lastAdaptationAt'),
                'lastAdaptationReason': bot.get('lastAdaptationReason'),
                'effectivePositionSizeMultiplier': round(_safe_float(bot.get('effectivePositionSizeMultiplier'), 1.0), 3),
                'effectiveScannerCapitalMultiplier': round(_safe_float(bot.get('effectiveScannerCapitalMultiplier'), 1.0), 3),
                'lastSizingAdjustment': last_sizing_adjustment,
                'selectedPreset': bot.get('selectedPreset'),
                'presetName': bot.get('presetName'),
                'promotionStatus': promotion_state['status'],
                'promotionEligible': promotion_state['eligible'],
                'promotionReadyAt': promotion_state['readyAt'],
                'promotionExpiredAt': promotion_state['expiredAt'],
                'promotionWindowHours': promotion_state['windowHours'],
                'promotionTimeRemainingMinutes': promotion_state['timeRemainingMinutes'],
                'promotionLabel': promotion_state['label'],
                'managementState': bot.get('managementState', 'normal'),
                'drawdownPauseUntil': bot.get('drawdownPauseUntil'),
                'lastTradeTime': last_trade_time,
                'brokerName': broker_name,
                'broker_type': bot.get('broker_type', 'MT5'),
                'accountNumber': account_number,
                'account_number': account_number,
                'mode': str(bot_mode_value).upper(),
                'is_live': bot_is_live,
                'accountBalance': round(bot.get('accountBalance', 0), 2),
                'accountEquity': round(bot.get('accountEquity', 0), 2),
                'tradeAmount': bot.get('tradeAmount'),
                'openPositionsCount': len(open_positions),
                'pyramidOpenCount': pyramid_open_count,
                'openPositionsPreview': open_positions_preview,
                'brokerConfirmedOpenPositionsCount': len(broker_confirmed_positions),
                'brokerConfirmedOpenPositions': broker_confirmed_positions[:5],
                'brokerRecentTrades': broker_recent_trades[:5],
                'brokerSnapshotDataSource': broker_snapshot_source,
                'activeSymbolCooldowns': active_symbol_cooldowns,
                'scannerTopOpportunities': (last_scan_results or {}).get('topOpportunities', []),
                'cumulativeProfitFloor': round(cumulative_profit * 0.70, 2) if cumulative_profit > 0 else 0,
                'cumulativeProfitFloorRemaining': round(max(0, current_profit - (cumulative_profit * 0.70)), 2) if cumulative_profit > 0 else 0,
                'cumulativeProfitFloorBreach': current_profit <= (cumulative_profit * 0.70) if cumulative_profit > 0 else False,
                'cumulativeLossAllowance': round(cumulative_loss_allowance, 2),
                'cumulativeProtectionStatus': cumulative_protection_status,
                'effectiveTradeAmount': round(_safe_float(bot.get('effectiveTradeAmount'), _safe_float(bot.get('tradeAmount'), 0.0)), 2),
                'tradeAmountAdaptation': bot.get('tradeAmountAdaptation'),
                'portfolioGuard': _evaluate_user_portfolio_profit_guard(bot),
                'createdAt': created_at,
            })

        return jsonify({
            'success': True,
            'bots': bots_list,
            'activeBots': len([b for b in bots_list if b.get('enabled', True)]),
            'timestamp': datetime.now().isoformat(),
        }), 200

    except Exception as e:
        logger.error(f"Error getting bot summary: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/bot/<bot_id>/analytics-snapshot', methods=['GET'])
@require_session
def get_bot_analytics_snapshot(bot_id: str):
    """Return the full analytics payload for a single bot only."""
    try:
        user_id = request.user_id

        bot = active_bots.get(bot_id)
        if not bot:
            load_user_bots_from_database(enabled_only=False)
            bot = active_bots.get(bot_id)
        if not bot or bot.get('user_id') != user_id:
            return jsonify({'success': False, 'error': f'Bot {bot_id} not found'}), 404

        if bot.get('tradeHistory'):
            _rebuild_bot_profit_tracking(bot)

        created = datetime.fromisoformat(bot.get('createdAt', datetime.now().isoformat()))
        runtime_seconds = (datetime.now() - created).total_seconds()
        runtime_hours = runtime_seconds / 3600
        runtime_minutes = (runtime_seconds % 3600) / 60

        today = datetime.now().strftime('%Y-%m-%d')
        daily_profits = dict(bot.get('dailyProfits', {}))
        daily_profit = float(daily_profits.get(today, bot.get('dailyProfit', 0)) or 0)

        total_profit = float(bot.get('totalProfit', 0) or 0)
        runtime_open_positions = list(bot.get('open_positions', {}).values())
        open_positions = list(runtime_open_positions)
        broker_confirmed_positions = []
        broker_recent_trades = []
        broker_snapshot_source = None
        broker_name = canonicalize_broker_name(bot.get('brokerName') or bot.get('broker_type') or bot.get('broker') or 'MT5')
        if broker_name == 'FXCM':
            fxcm_snapshot = _build_fxcm_bot_broker_snapshot(user_id, bot)
            if fxcm_snapshot.get('fetched'):
                broker_confirmed_positions = list(fxcm_snapshot.get('positions') or [])
                broker_recent_trades = list(fxcm_snapshot.get('recentTrades') or [])
                broker_snapshot_source = fxcm_snapshot.get('dataSource')
                open_positions = broker_confirmed_positions
        floating_profit = sum(float(position.get('profit') or 0) for position in open_positions)
        current_profit = total_profit + floating_profit

        profit_history = bot.get('profitHistory', [])
        for ph in profit_history:
            ph_ts = ph.get('timestamp', 0)
            if ph_ts:
                ph_date = datetime.fromtimestamp(ph_ts / 1000).strftime('%Y-%m-%d')
                if ph_date not in daily_profits:
                    daily_profits[ph_date] = round(ph.get('profit', 0), 2)

        investment = float(bot.get('totalInvestment') or bot.get('initialBalance') or 0)
        realized_roi = (total_profit / investment) * 100 if investment > 0 else 0
        current_roi = (current_profit / investment) * 100 if investment > 0 else 0

        total_trades = int(bot.get('totalTrades', 0) or 0)
        winning_trades = int(bot.get('winningTrades', 0) or 0)
        win_rate = round((winning_trades / total_trades) * 100, 1) if total_trades > 0 else 0
        profitability = (total_profit / total_trades) if total_trades > 0 else 0

        total_losses = float(bot.get('totalLosses', 0) or 0)
        if total_losses > 0:
            profit_factor = min(total_profit / total_losses, 99.99) if total_profit > 0 else 0
        else:
            profit_factor = 99.99 if total_profit > 0 else 0

        symbols = bot.get('symbols', [])
        if open_positions:
            symbol = open_positions[0].get('symbol', 'EURUSDm')
        elif len(symbols) == 1:
            symbol = symbols[0]
        elif len(symbols) > 1:
            symbol = 'MULTI'
        else:
            symbol = 'EURUSDm'
        bot_mode_value = (bot.get('mode') or 'demo')
        bot_is_live = str(bot_mode_value).lower() == 'live'
        display_currency = _resolve_display_currency_for_mode(bot_mode_value, bot.get('displayCurrency', 'USD'))
        last_strategy_selection = bot.get('lastStrategySelection') if isinstance(bot.get('lastStrategySelection'), dict) else None
        strategy_history = bot.get('strategyHistory') if isinstance(bot.get('strategyHistory'), list) else []
        last_strategy_event = strategy_history[-1] if strategy_history else None
        last_scan_results = bot.get('lastScanResults') if isinstance(bot.get('lastScanResults'), dict) else None
        last_sizing_adjustment = bot.get('lastSizingAdjustment') if isinstance(bot.get('lastSizingAdjustment'), dict) else None
        pyramid_open_count = sum(1 for position in open_positions if position.get('isPyramidAddon'))

        trade_history = bot.get('tradeHistory', [])
        last_trade_time = trade_history[-1].get('time') if trade_history else bot.get('createdAt', datetime.now().isoformat())

        open_positions_payload = []
        for pos in open_positions:
            open_positions_payload.append({
                **pos,
                'profit': round(_safe_float(pos.get('profit'), 0.0), 2),
                'lockedProfitFloor': round(_safe_float(pos.get('lockedProfitFloor'), 0.0), 2),
                'breakEvenFloor': round(_safe_float(pos.get('breakEvenFloor'), 0.0), 2),
                'profitProtectionArmed': bool(pos.get('profitProtectionArmed', False)),
                'profitProtectionBucket': pos.get('profitProtectionBucket'),
                'isPyramidAddon': bool(pos.get('isPyramidAddon', False)),
                'pyramidParentTicket': pos.get('pyramidParentTicket'),
            })

        active_symbol_cooldowns = []
        cooldowns = bot.get('symbolReentryCooldowns') or {}
        seen_cooldowns = set()
        for cooldown_key, cooldown_entry in cooldowns.items():
            if not isinstance(cooldown_entry, dict):
                continue
            until_raw = cooldown_entry.get('until')
            try:
                until_dt = datetime.fromisoformat(str(until_raw))
            except Exception:
                continue
            if until_dt <= datetime.now():
                continue
            base_symbol = cooldown_entry.get('baseSymbol') or cooldown_key
            if base_symbol in seen_cooldowns:
                continue
            seen_cooldowns.add(base_symbol)
            active_symbol_cooldowns.append({
                'symbol': base_symbol,
                'until': until_dt.isoformat(),
                'reason': cooldown_entry.get('reason'),
            })

        # Calculate cumulative profit protection floor (30% max loss)
        cumulative_profit = float(total_profit or 0)
        cumulative_loss_allowance = (cumulative_profit * 0.30) if cumulative_profit > 0 else 0
        current_day_profit = bot.get('dailyProfits', {}).get(today, 0.0)
        open_position_pnl = sum([float(pos.get('profit', 0)) for pos in open_positions])
        current_session_pnl = current_day_profit + open_position_pnl
        current_session_loss = abs(current_session_pnl) if current_session_pnl < 0 else 0
        cumulative_protection_status = 'active' if cumulative_loss_allowance > 0 else 'inactive'
        if cumulative_loss_allowance > 0 and current_session_loss >= cumulative_loss_allowance:
            cumulative_protection_status = 'triggered'

        return jsonify({
            'success': True,
            'bot': {
                'botId': bot.get('botId', 'unknown'),
                'symbol': symbol,
                'symbols': symbols,
                'strategy': bot.get('strategy', 'Unknown'),
                'commission': round(max(total_profit, 0) * 0.01, 2),
                'profit': round(current_profit, 2),
                'totalProfit': round(total_profit, 2),
                'floatingProfit': round(floating_profit, 2),
                'currentProfit': round(current_profit, 2),
                'totalTrades': total_trades,
                'winningTrades': winning_trades,
                'winRate': win_rate,
                'closedWinRate': win_rate,
                'maxDrawdown': round(bot.get('maxDrawdown', 0), 2),
                'runtimeFormatted': f"{int(runtime_hours)}h {int(runtime_minutes)}m",
                'dailyProfit': round(daily_profit, 2),
                'roi': round(realized_roi, 2),
                'realizedRoi': round(realized_roi, 2),
                'currentRoi': round(current_roi, 2),
                'roiBasis': round(investment, 2),
                'roiBasisKnown': investment > 0,
                'profitability': round(profitability if total_trades > 0 else current_profit, 2),
                'profitFactor': round(profit_factor, 2),
                'avgProfitPerTrade': round(total_profit / max(total_trades, 1), 2),
                'enabled': bot.get('enabled', True),
                'status': 'Active' if bot.get('enabled', True) else 'Inactive',
                'pauseReason': bot.get('pauseReason'),
                'stopReason': bot.get('stopReason'),
                'lastPauseEvent': bot.get('lastPauseEvent'),
                'displayCurrency': display_currency,
                'maxOpenPositions': bot.get('maxOpenPositions', 5),
                'maxPositionsPerSymbol': bot.get('maxPositionsPerSymbol', 1),
                'signalThreshold': _effective_signal_threshold_for_display(bot),
                'managementMode': bot.get('managementMode', 'assisted'),
                'managementProfile': bot.get('managementProfile', 'beginner'),
                'managementState': bot.get('managementState', 'normal'),
                'drawdownPauseUntil': bot.get('drawdownPauseUntil'),
                'lastTradeTime': last_trade_time,
                'broker_type': bot.get('broker_type', 'MT5'),
                'intelligentScanner': bool(bot.get('intelligentScanner', False)),
                'lastStrategySwitch': bot.get('lastStrategySwitch'),
                'lastStrategySelection': last_strategy_selection,
                'lastStrategyEvent': last_strategy_event,
                'scannerMode': (last_scan_results or {}).get('scannerMode'),
                'lastScanTimestamp': (last_scan_results or {}).get('timestamp'),
                'scannerTopOpportunities': (last_scan_results or {}).get('topOpportunities', []),
                'effectivePositionSizeMultiplier': round(_safe_float(bot.get('effectivePositionSizeMultiplier'), 1.0), 3),
                'effectiveScannerCapitalMultiplier': round(_safe_float(bot.get('effectiveScannerCapitalMultiplier'), 1.0), 3),
                'lastSizingAdjustment': last_sizing_adjustment,
                'mode': str(bot_mode_value).upper(),
                'is_live': bot_is_live,
                'profitField': round(current_profit, 2),
                'tradeHistory': trade_history,
                'dailyProfits': daily_profits,
                'openPositions': open_positions_payload,
                'brokerConfirmedOpenPositions': broker_confirmed_positions,
                'brokerRecentTrades': broker_recent_trades,
                'brokerSnapshotDataSource': broker_snapshot_source,
                'pyramidOpenCount': pyramid_open_count,
                'accountBalance': round(bot.get('accountBalance', 0), 2),
                'accountEquity': round(bot.get('accountEquity', 0), 2),
                'activeSymbolCooldowns': active_symbol_cooldowns,
                'effectiveTradeAmount': round(_safe_float(bot.get('effectiveTradeAmount'), _safe_float(bot.get('tradeAmount'), 0.0)), 2),
                'tradeAmountAdaptation': bot.get('tradeAmountAdaptation'),
                'profitProtection': _normalize_profit_protection_config(bot.get('profitProtection')),
                'cumulativeProfitProtection': {
                    'enabled': cumulative_loss_allowance > 0,
                    'cumulativeProfit': round(cumulative_profit, 2),
                    'maxAllowedLoss30Percent': round(cumulative_loss_allowance, 2),
                    'currentSessionLoss': round(current_session_loss, 2),
                    'remainingLossBuffer': round(max(cumulative_loss_allowance - current_session_loss, 0), 2),
                    'status': cumulative_protection_status,
                },
            },
            'timestamp': datetime.now().isoformat(),
        }), 200

    except Exception as e:
        logger.error(f"Error getting bot analytics snapshot: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/bot/<bot_id>/performance', methods=['GET'])
@require_session
def get_bot_performance(bot_id):
    """Get detailed performance metrics for a specific bot
    
    Returns:
    - Account balance (from broker)
    - Total trades and breakdown
    - Profit/Loss
    - Commission distribution
    - Daily profits tracking
    """
    try:
        user_id = request.user_id
        
        if bot_id not in active_bots:
            return jsonify({'success': False, 'error': f'Bot {bot_id} not found'}), 404
        
        bot = active_bots[bot_id]
        
        # Get broker connection for live balance
        credential_id = bot.get('credentialId')
        broker_type = bot.get('broker_type', 'MT5')
        current_balance = 0
        
        try:
            if credential_id:
                _, broker_conn = get_broker_connection(credential_id, user_id, bot_id)
                account_info = broker_conn.get_account_info()
                if account_info:
                    current_balance = account_info.get('balance', account_info.get('equity', 0))
        except:
            current_balance = bot.get('accountBalance', 0)
        
        # Calculate metrics
        total_trades = bot.get('totalTrades', 0)
        winning_trades = bot.get('winningTrades', 0)
        total_profit = bot.get('totalProfit', 0)
        total_loss = bot.get('totalLosses', 0)
        
        win_rate = (winning_trades / max(total_trades, 1)) * 100 if total_trades > 0 else 0
        profit_factor = total_profit / max(total_loss, 0.01)
        investment_basis = float(bot.get('totalInvestment') or bot.get('initialBalance') or 0)
        realized_roi = (total_profit / investment_basis) * 100 if investment_basis > 0 else 0
        
        return jsonify({
            'success': True,
            'botId': bot_id,
            'botName': bot.get('name', bot_id),
            'brokerType': broker_type,
            'currentBalance': round(current_balance, 2),
            'initialBalance': bot.get('initialBalance', 0),
            'trades': {
                'total': total_trades,
                'winning': winning_trades,
                'losing': total_trades - winning_trades,
                'winRate': round(win_rate, 1)
            },
            'profitLoss': {
                'totalProfit': round(total_profit, 2),
                'totalLoss': round(total_loss, 2),
                'netProfit': round(total_profit - total_loss, 2),
                'roi': round(realized_roi, 2),
                'roiBasis': round(investment_basis, 2),
                'roiBasisKnown': investment_basis > 0,
                'profitFactor': round(profit_factor, 2)
            },
            'drawdown': {
                'maxDrawdown': round(bot.get('maxDrawdown', 0), 2),
                'peakProfit': round(bot.get('peakProfit', 0), 2),
                'currentDrawdown': round(bot.get('peakProfit', 0) - total_profit, 2)
            },
            'dailyProfits': bot.get('dailyProfits', {}),
            'created': bot.get('createdAt', 'Unknown'),
            'status': 'Running' if bot.get('enabled', False) else 'Stopped',
            'tradingMode': bot.get('tradingMode', 'interval'),
            'symbol': bot.get('symbols', ['EURUSD'])[0] if bot.get('symbols') else 'EURUSD'
        }), 200
    
    except Exception as e:
        logger.error(f"Error getting bot performance: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/bot/<bot_id>/trades-detailed', methods=['GET'])
@require_session
def get_bot_trades_detailed(bot_id):
    """Get detailed trade history for a specific bot with filters
    
    Query parameters:
    - limit: max trades to return (default 50)
    - offset: pagination offset (default 0)
    - symbol: filter by symbol
    - status: 'open', 'closed', 'all' (default all)
    """
    try:
        user_id = request.user_id
        limit = request.args.get('limit', 50, type=int)
        offset = request.args.get('offset', 0, type=int)
        symbol_filter = request.args.get('symbol', None)
        status_filter = request.args.get('status', 'all')
        
        if bot_id not in active_bots:
            return jsonify({'success': False, 'error': f'Bot {bot_id} not found'}), 404
        
        # Get trades from database
        conn = get_db_connection()
        cursor = conn.cursor()
        
        query = 'SELECT * FROM trades WHERE bot_id = ?'
        params = [bot_id]
        
        if symbol_filter:
            query += ' AND symbol = ?'
            params.append(symbol_filter)
        
        if status_filter and status_filter != 'all':
            query += ' AND status = ?'
            params.append(status_filter)
        
        # Get total count
        count_cursor = conn.cursor()
        count_cursor.execute(f'SELECT COUNT(*) FROM trades WHERE bot_id = ?', [bot_id])
        total_count = count_cursor.fetchone()[0]
        
        # Get paginated results
        query += ' ORDER BY created_at DESC LIMIT ? OFFSET ?'
        params.extend([limit, offset])
        
        cursor.execute(query, params)
        rows = cursor.fetchall()
        conn.close()
        
        trades = [dict(row) for row in rows]
        
        return jsonify({
            'success': True,
            'botId': bot_id,
            'trades': trades,
            'pagination': {
                'total': total_count,
                'offset': offset,
                'limit': limit,
                'hasMore': offset + limit < total_count
            }
        }), 200
    
    except Exception as e:
        logger.error(f"Error getting bot trades: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/bot/<bot_id>/commissions', methods=['GET'])
@require_session
def get_bot_commissions(bot_id):
    """Get commission earnings from a specific bot
    
    Returns:
    - Total commissions earned
    - Commission distribution by date
    - Pending withdrawals
    """
    try:
        user_id = request.user_id
        
        if bot_id not in active_bots:
            return jsonify({'success': False, 'error': f'Bot {bot_id} not found'}), 404
        
        # Get commission data from database
        conn = get_db_connection()
        cursor = conn.cursor()
        
        # Get total commissions from this bot
        cursor.execute('''
            SELECT COALESCE(SUM(commission_amount), 0) as total,
                   COUNT(*) as count
            FROM commission_ledger 
            WHERE bot_id = ? AND status = 'active'
        ''', [bot_id])
        
        comm_row = cursor.fetchone()
        total_commission = comm_row['total'] if comm_row else 0
        
        # Get commission history by date
        cursor.execute('''
            SELECT DATE(created_at) as date, 
                   SUM(commission_amount) as daily_commission,
                   COUNT(*) as trades
            FROM commission_ledger 
            WHERE bot_id = ?
            GROUP BY DATE(created_at)
            ORDER BY date DESC
        ''', [bot_id])
        
        commission_history = [dict(row) for row in cursor.fetchall()]
        
        # Get pending withdrawals
        cursor.execute('''
            SELECT * FROM withdrawal_requests
            WHERE bot_id = ?
            ORDER BY created_at DESC
        ''', [bot_id])
        
        withdrawals = [dict(row) for row in cursor.fetchall()]
        conn.close()
        
        return jsonify({
            'success': True,
            'botId': bot_id,
            'totalCommissions': round(total_commission, 2),
            'commissionHistory': commission_history,
            'withdrawals': withdrawals,
            'pendingWithdrawal': sum(w['amount'] for w in withdrawals if w['status'] == 'pending'),
            'completedWithdrawal': sum(w['amount'] for w in withdrawals if w['status'] == 'completed')
        }), 200
    
    except Exception as e:
        logger.error(f"Error getting bot commissions: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/dashboard/bots-summary', methods=['GET'])
@require_session
def get_dashboard_summary():
    """Get summary of all user bots for dashboard display
    
    Returns array of bot summaries with:
    - Bot name and ID
    - Current balance per broker
    - Performance metrics
    - Trading mode
    - Status
    """
    try:
        user_id = request.user_id
        
        # Get all bots for this user
        conn = get_db_connection()
        cursor = conn.cursor()
        cursor.execute('SELECT * FROM user_bots WHERE user_id = ?', [user_id])
        user_bots = [dict(row) for row in cursor.fetchall()]
        conn.close()
        
        summary = []
        total_balance_by_currency: Dict[str, float] = {}
        total_profit_by_currency: Dict[str, float] = {}
        
        for bot_row in user_bots:
            bot_id = bot_row['bot_id']
            
            if bot_id not in active_bots:
                continue
            
            bot = active_bots[bot_id]
            
            # Get live balance from broker
            credential_id = bot.get('credentialId')
            broker_type = bot.get('broker_type', 'MT5')
            current_balance = bot.get('accountBalance', 0)
            
            try:
                if credential_id:
                    _, broker_conn = get_broker_connection(credential_id, user_id, bot_id)
                    account_info = broker_conn.get_account_info()
                    if account_info:
                        current_balance = account_info.get('balance', account_info.get('equity', 0))
            except:
                pass
            
            total_profit = bot.get('totalProfit', 0)
            total_trades = bot.get('totalTrades', 0)
            display_currency = (bot.get('displayCurrency') or bot.get('accountCurrency') or 'USD').upper()

            total_balance_by_currency[display_currency] = total_balance_by_currency.get(display_currency, 0.0) + float(current_balance or 0)
            total_profit_by_currency[display_currency] = total_profit_by_currency.get(display_currency, 0.0) + float(total_profit or 0)
            
            summary.append({
                'botId': bot_id,
                'botName': bot.get('name', f'Bot-{bot_id[:8]}'),
                'broker': {
                    'type': broker_type,
                    'accountNumber': bot_row.get('broker_account_id', 'N/A')
                },
                'displayCurrency': display_currency,
                'balance': round(current_balance, 2),
                'profit': round(total_profit, 2),
                'trades': total_trades,
                'winRate': round((bot.get('winningTrades', 0) / max(total_trades, 1)) * 100, 1) if total_trades > 0 else 0,
                'status': 'Running' if bot.get('enabled', False) else 'Stopped',
                'tradingMode': bot.get('tradingMode', 'interval'),
                'createdAt': bot.get('createdAt', 'Unknown')
            })
        
        return jsonify({
            'success': True,
            'botsCount': len(summary),
            'botsRunning': sum(1 for b in summary if b['status'] == 'Running'),
            'totalBalance': round(sum(b['balance'] for b in summary), 2),
            'totalProfit': round(sum(b['profit'] for b in summary), 2),
            'totalBalanceByCurrency': {currency: round(value, 2) for currency, value in total_balance_by_currency.items()},
            'totalProfitByCurrency': {currency: round(value, 2) for currency, value in total_profit_by_currency.items()},
            'bots': summary,
            'timestamp': datetime.now().isoformat()
        }), 200
    
    except Exception as e:
        logger.error(f"Error getting dashboard summary: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/bot/status-public', methods=['GET'])
def bot_status_public():
    """Get status of RUNNING bots only (public - no authentication required)
    
    A bot is considered "running" if:
    1. It's in running_bots AND marked as running (True)
    2. OR it's in active_bots AND was just created (enabled=True and enabled field is explicitly set)
    """
    try:
        bots_list = []
        
        # Only include ENABLED (running) bots
        for bot_id, bot in active_bots.items():
            # Include bot if:
            # 1. It's explicitly marked as running in running_bots OR
            # 2. It's enabled in active_bots (just created, background thread starting)
            is_marked_running = running_bots.get(bot_id, False)
            is_enabled = bot.get('enabled', True)
            
            # Skip only if BOTH conditions fail
            if not is_marked_running and not is_enabled:
                logger.debug(f"Skipping bot {bot_id}: marked_running={is_marked_running}, enabled={is_enabled}")
                continue
            
            # Calculate runtime
            created = datetime.fromisoformat(bot.get('createdAt', datetime.now().isoformat()))
            runtime_seconds = (datetime.now() - created).total_seconds()
            runtime_hours = runtime_seconds / 3600
            runtime_minutes = (runtime_seconds % 3600) / 60
            
            # Calculate daily profit (safely access dailyProfits)
            today = datetime.now().strftime('%Y-%m-%d')
            daily_profit = bot.get('dailyProfits', {}).get(today, bot.get('dailyProfit', 0))
            
            # Calculate ROI (safely access totalInvestment)
            investment = bot.get('totalInvestment', 0)
            total_profit = bot.get('totalProfit', 0)
            roi = (total_profit / max(investment, 1)) * 100 if investment > 0 else 0
            
            # Calculate profit factor (safely access totalLosses)
            total_losses = bot.get('totalLosses', 0)
            if total_losses > 0:
                profit_factor = min(total_profit / total_losses, 99.99) if total_profit > 0 else 0
            else:
                profit_factor = 99.99 if total_profit > 0 else 0
            
            # Safely access symbols and strategy
            symbols = bot.get('symbols', [])
            symbol = symbols[0] if symbols else 'EURUSDm'
            
            # Determine status based on whether thread is actively running
            if is_marked_running:
                status = 'Running'
            elif is_enabled and not is_marked_running:
                status = 'Starting'  # Just created, background thread starting
            else:
                status = 'Stopped'
            
            enhanced_bot = {
                'botId': bot.get('botId', 'unknown'),
                'symbol': symbol,
                'symbols': symbols,  # ✅ Include full symbols list
                'strategy': bot.get('strategy', 'Unknown'),
                'commission': round(total_profit * 0.01, 2),
                'profit': round(total_profit, 2),
                'totalProfit': round(total_profit, 2),  # ✅ Include totalProfit field
                'totalTrades': bot.get('totalTrades', 0),  # ✅ Include totalTrades
                'winningTrades': bot.get('winningTrades', 0),  # ✅ Include winningTrades
                'runtimeFormatted': f"{int(runtime_hours)}h {int(runtime_minutes)}m",
                'dailyProfit': round(daily_profit, 2),
                'roi': round(roi, 2),
                'profitFactor': round(profit_factor, 2),
                'avgProfitPerTrade': round(total_profit / max(bot.get('totalTrades', 1), 1), 2),
                'status': status,
                'enabled': is_enabled,
                'pauseReason': bot.get('pauseReason'),  # Include bot-level pause reason
                'lastPauseEvent': bot.get('lastPauseEvent'),  # Include last market pause event
                'broker_type': bot.get('broker_type', 'MT5'),
                'createdAt': created.isoformat(),
                'lastTradeTime': bot.get('tradeHistory', [{}])[-1].get('time') if bot.get('tradeHistory') else bot.get('createdAt', datetime.now().isoformat()),
            }
            bots_list.append(enhanced_bot)
        
        # Sort by creation date (latest first)
        bots_list.sort(key=lambda x: x['createdAt'], reverse=True)
        
        return jsonify({
            'success': True,
            'activeBots': len(bots_list),
            'runningBots': len([b for b in bots_list if b['status'] == 'Running']),
            'startingBots': len([b for b in bots_list if b['status'] == 'Starting']),
            'bots': bots_list,
            'timestamp': datetime.now().isoformat(),
        }), 200
    
    except Exception as e:
        logger.error(f"Error getting public bot status: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


