@app.route('/api/bot/stop/<bot_id>', methods=['POST'])
@require_session
def stop_bot(bot_id):
    """Stop a trading bot (still keeps it in system for restart)"""
    try:
        data = request.get_json(silent=True) or {}
        user_id = data.get('user_id') or request.user_id
        
        if not user_id:
            return jsonify({'success': False, 'error': 'user_id required'}), 400
        
        if bot_id not in active_bots:
            return jsonify({'success': False, 'error': f'Bot {bot_id} not found'}), 404
        
        # Verify bot belongs to user
        bot_config = active_bots[bot_id]
        if bot_config.get('user_id') != user_id:
            return jsonify({'success': False, 'error': 'Unauthorized: Bot does not belong to this user'}), 403
        
        # Also verify in database
        conn = get_db_connection()
        cursor = conn.cursor()
        cursor.execute('SELECT user_id FROM user_bots WHERE bot_id = ?', (bot_id,))
        db_bot = cursor.fetchone()
        conn.close()
        
        if not db_bot or db_bot['user_id'] != user_id:
            return jsonify({'success': False, 'error': 'Unauthorized: Bot does not belong to this user'}), 403
        
        final_stats = stop_bot_runtime(bot_id, bot_config)
        
        return jsonify({
            'success': True,
            'message': f'Bot {bot_id} stopped',
            'finalStats': {
                'totalTrades': final_stats['totalTrades'],
                'winningTrades': final_stats['winningTrades'],
                'totalProfit': final_stats['totalProfit'],
                'note': 'Bot can be restarted later. Use /delete to permanently remove.'
            }
        }), 200
    
    except Exception as e:
        logger.error(f"Error stopping bot: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


def _record_bot_position_close(
    bot_id: str,
    bot_config: Dict[str, Any],
    ticket: Any,
    recorded_profit: float,
    close_reason: str,
    *,
    now_iso: Optional[str] = None,
) -> None:
    now_iso = now_iso or datetime.now().isoformat()
    ticket_str = str(ticket)

    tracked_positions = bot_config.setdefault('open_positions', {})
    tracked_trade = tracked_positions.pop(ticket_str, None)

    trade_history = bot_config.setdefault('tradeHistory', [])
    for existing in reversed(trade_history):
        if str(existing.get('ticket')) == ticket_str:
            existing['status'] = 'closed'
            existing['closeReason'] = close_reason
            existing['exitTime'] = now_iso
            existing['time'] = now_iso
            existing['timestamp'] = int(datetime.now().timestamp() * 1000)
            existing['profit'] = round(recorded_profit, 2)
            existing['isWinning'] = recorded_profit > 0
            break

    if tracked_trade:
        bot_config['totalProfit'] = _safe_float(bot_config.get('totalProfit'), 0.0) + recorded_profit
        bot_config['profit'] = bot_config['totalProfit']
        if recorded_profit > 0:
            bot_config['winningTrades'] = int(bot_config.get('winningTrades', 0) or 0) + 1
        else:
            bot_config['totalLosses'] = _safe_float(bot_config.get('totalLosses'), 0.0) + abs(recorded_profit)

        today = datetime.now().strftime('%Y-%m-%d')
        daily = bot_config.setdefault('dailyProfits', {})
        daily[today] = _safe_float(daily.get(today), 0.0) + recorded_profit
        bot_config['dailyProfit'] = daily[today]

    try:
        trade_conn = build_sqlite_connection(timeout=30.0)
        trade_cursor = trade_conn.cursor()
        trade_cursor.execute('''
            UPDATE trades
            SET profit = ?, status = 'closed', time_close = ?, trade_data = ?, updated_at = ?
            WHERE ticket = ? AND bot_id = ? AND status = 'open'
        ''', (
            recorded_profit,
            now_iso,
            json.dumps({
                'ticket': ticket_str,
                'botId': bot_id,
                'closeReason': close_reason,
                'profit': round(recorded_profit, 2),
                'time': now_iso,
            }),
            now_iso,
            ticket_str,
            bot_id,
        ))
        trade_conn.commit()
        trade_conn.close()
    except Exception as db_error:
        logger.warning(f"Bot {bot_id}: close-state DB sync warning for ticket {ticket_str}: {db_error}")


def _close_bot_positions_for_delete(bot_id: str, user_id: str, bot_config: Dict[str, Any]) -> Dict[str, Any]:
    tracked_positions = bot_config.get('open_positions', {}) if isinstance(bot_config.get('open_positions'), dict) else {}
    tickets_to_close = {str(ticket) for ticket in tracked_positions.keys() if str(ticket or '').strip()}

    trade_conn = None
    try:
        trade_conn = build_sqlite_connection(timeout=10.0, row_factory=True)
        trade_cursor = trade_conn.cursor()
        trade_cursor.execute(
            '''
            SELECT ticket
            FROM trades
            WHERE bot_id = ? AND status = 'open'
            ''',
            (bot_id,)
        )
        for row in trade_cursor.fetchall():
            ticket_str = str(row['ticket'] or '').strip()
            if ticket_str:
                tickets_to_close.add(ticket_str)
    except Exception as db_error:
        logger.warning(f"Bot {bot_id}: could not inspect open trades before delete: {db_error}")
    finally:
        if trade_conn:
            trade_conn.close()

    if not tickets_to_close:
        return {'closed': [], 'failed': []}

    credential_id = str(bot_config.get('credentialId') or '').strip()
    if not credential_id:
        raise RuntimeError(f'Bot {bot_id} has open positions but no credential linkage to close them')

    broker_type, connection = get_broker_connection(credential_id, user_id, bot_id=f'delete-close:{bot_id}')
    if not connection or not hasattr(connection, 'close_position'):
        raise RuntimeError(f'Could not connect broker for bot deletion close-out: {connection or broker_type}')

    closed_tickets = []
    failed_closes = []
    try:
        for ticket_str in sorted(tickets_to_close):
            close_result = connection.close_position(ticket_str)
            if not close_result or not close_result.get('success', False):
                failed_closes.append({
                    'ticket': ticket_str,
                    'error': (close_result or {}).get('error', 'Failed to close position'),
                })
                continue

            tracked_trade = tracked_positions.get(ticket_str, {})
            recorded_profit = _safe_float((close_result or {}).get('profit'), None)
            if recorded_profit is None and tracked_trade:
                recorded_profit = _safe_float(tracked_trade.get('profit'), 0.0)
            if recorded_profit is None:
                recorded_profit = 0.0

            _record_bot_position_close(
                bot_id,
                bot_config,
                ticket_str,
                recorded_profit,
                'BOT_DELETE',
            )
            closed_tickets.append(ticket_str)
    finally:
        if hasattr(connection, 'disconnect'):
            try:
                connection.disconnect()
            except Exception:
                pass

    if failed_closes:
        failed_summary = ', '.join(f"{item['ticket']}: {item['error']}" for item in failed_closes[:5])
        raise RuntimeError(f'Failed to close bot positions before deletion: {failed_summary}')

    if closed_tickets:
        persist_bot_runtime_state(bot_id, force=True)
        logger.info(
            f"🧹 Bot {bot_id}: closed {len(closed_tickets)} position(s) before deletion via {broker_type}"
        )

    return {'closed': closed_tickets, 'failed': failed_closes}


@app.route('/api/bot/<bot_id>/positions/<ticket>/close', methods=['POST'])
@require_session
def close_bot_position(bot_id, ticket):
    """Manually close a specific open position for a bot."""
    try:
        user_id = request.user_id

        if bot_id not in active_bots:
            return jsonify({'success': False, 'error': f'Bot {bot_id} not found'}), 404

        bot_config = active_bots[bot_id]
        if bot_config.get('user_id') != user_id:
            return jsonify({'success': False, 'error': 'Unauthorized: Bot does not belong to this user'}), 403

        try:
            int(ticket)
        except (TypeError, ValueError):
            return jsonify({'success': False, 'error': 'Invalid ticket'}), 400

        credential_id = bot_config.get('credentialId')
        if not credential_id:
            return jsonify({'success': False, 'error': 'Bot missing credential linkage'}), 400

        broker_type, connection = get_broker_connection(credential_id, user_id, bot_id=f'manual-close:{bot_id}')
        if not connection or not hasattr(connection, 'close_position'):
            return jsonify({'success': False, 'error': f'Could not connect broker for bot close: {connection}'}), 500

        close_result = connection.close_position(str(ticket))
        if not close_result or not close_result.get('success', False):
            return jsonify({'success': False, 'error': (close_result or {}).get('error', 'Failed to close position')}), 500

        tracked_positions = bot_config.setdefault('open_positions', {})
        tracked_trade = tracked_positions.get(str(ticket), None)

        recorded_profit = _safe_float((close_result or {}).get('profit'), None)
        if recorded_profit is None and tracked_trade:
            recorded_profit = _safe_float(tracked_trade.get('profit'), 0.0)
        if recorded_profit is None:
            recorded_profit = 0.0

        _record_bot_position_close(
            bot_id,
            bot_config,
            str(ticket),
            recorded_profit,
            'MANUAL_CLOSE',
        )

        persist_bot_runtime_state(bot_id)

        display_currency = _resolve_display_currency_for_mode(bot_config.get('mode'), bot_config.get('displayCurrency', 'USD'))
        logger.info(f"✅ Bot {bot_id}: manually closed ticket {ticket} via {broker_type}")
        return jsonify({
            'success': True,
            'botId': bot_id,
            'ticket': str(ticket),
            'message': 'Position closed',
            'recordedProfit': round(recorded_profit, 2),
            'displayCurrency': display_currency,
        }), 200

    except Exception as e:
        logger.error(f"Error closing bot position {bot_id}/{ticket}: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/bot/stop-all', methods=['POST'])
@require_session
def stop_all_bots():
    """Stop all matching bots for the authenticated user."""
    try:
        data = request.json or {}
        user_id = data.get('user_id') or request.user_id
        mode_filter = (data.get('mode') or 'all').lower()
        only_loss_making = bool(data.get('only_loss_making', False))

        if not user_id:
            return jsonify({'success': False, 'error': 'user_id required'}), 400
        if mode_filter not in {'all', 'demo', 'live'}:
            return jsonify({'success': False, 'error': 'mode must be one of: all, demo, live'}), 400

        stopped_bots = []
        skipped_bots = []

        for bot_id, bot_config in list(active_bots.items()):
            if bot_config.get('user_id') != user_id:
                continue
            if not bot_config.get('enabled'):
                skipped_bots.append({'botId': bot_id, 'reason': 'already_disabled'})
                continue

            bot_mode = (bot_config.get('mode') or 'demo').lower()
            if mode_filter != 'all' and bot_mode != mode_filter:
                skipped_bots.append({'botId': bot_id, 'reason': f'mode_{bot_mode}'})
                continue

            total_profit = float(bot_config.get('totalProfit', 0.0) or 0.0)
            daily_profit = float(bot_config.get('dailyProfit', 0.0) or 0.0)
            if only_loss_making and total_profit >= 0 and daily_profit >= 0:
                skipped_bots.append({'botId': bot_id, 'reason': 'not_loss_making'})
                continue

            stopped_bots.append(stop_bot_runtime(bot_id, bot_config))

        logger.info(
            f"🛑 Stopped {len(stopped_bots)} bots for user {user_id} "
            f"(mode={mode_filter}, only_loss_making={only_loss_making})"
        )

        return jsonify({
            'success': True,
            'message': f'Stopped {len(stopped_bots)} bots',
            'stoppedBots': stopped_bots,
            'skippedBots': skipped_bots,
        }), 200

    except Exception as e:
        logger.error(f"Error stopping all bots: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/bot/delete/<bot_id>', methods=['DELETE', 'POST'])
@require_session
def delete_bot(bot_id):
    """Delete a trading bot permanently (requires confirmation token)"""
    try:
        data = request.json or {}
        user_id = data.get('user_id') or request.user_id
        confirmation_token = data.get('confirmation_token')
        
        if not user_id:
            return jsonify({'success': False, 'error': 'user_id required'}), 400
        
        conn = get_db_connection()
        cursor = conn.cursor()

        resolved_bot_id = bot_id
        bot_config = active_bots.get(resolved_bot_id)

        # Resolve identifier by exact bot_id first, then by bot name for user convenience.
        if not bot_config:
            cursor.execute('''
                SELECT bot_id
                FROM user_bots
                WHERE user_id = ? AND (bot_id = ? OR LOWER(name) = LOWER(?))
                ORDER BY created_at DESC
            ''', (user_id, bot_id, bot_id))
            matches = cursor.fetchall()
            if not matches:
                conn.close()
                return jsonify({'success': False, 'error': f'Bot {bot_id} not found'}), 404
            if len(matches) > 1:
                conn.close()
                return jsonify({
                    'success': False,
                    'error': f"Multiple bots match '{bot_id}'. Please delete using bot_id."
                }), 400

            resolved_bot_id = matches[0]['bot_id'] if isinstance(matches[0], sqlite3.Row) else matches[0][0]
            bot_config = active_bots.get(resolved_bot_id)
        
        # Verify bot ownership in database
        cursor.execute('SELECT user_id FROM user_bots WHERE bot_id = ?', (resolved_bot_id,))
        db_bot = cursor.fetchone()
        if not db_bot or db_bot['user_id'] != user_id:
            conn.close()
            return jsonify({'success': False, 'error': 'Unauthorized: Bot does not belong to this user'}), 403
        
        if confirmation_token:
            # TOKEN PROVIDED: Look up and verify token
            cursor.execute('''
                SELECT * FROM bot_deletion_tokens
                WHERE bot_id = ? AND user_id = ? AND deletion_token = ? AND expires_at > ?
            ''', (resolved_bot_id, user_id, confirmation_token, datetime.now().isoformat()))
            
            token_record = cursor.fetchone()
            
            if not token_record:
                conn.close()
                return jsonify({
                    'success': False,
                    'error': 'Invalid or expired confirmation token',
                    'next_step': f'Call POST /api/bot/{resolved_bot_id}/request-deletion to get a new token'
                }), 401
            
            logger.info(f"✅ Bot {resolved_bot_id} deletion token verified for user {user_id}")
        else:
            # NO TOKEN PROVIDED: Allow deletion for backward compatibility
            logger.warning(f"⚠️  Bot {resolved_bot_id} deleted WITHOUT 2-step confirmation (legacy request from user {user_id})")
            logger.warning(f"   Recommendation: Update client to use /api/bot/{resolved_bot_id}/request-deletion + token for safety")
        conn.close()

        deletion_result = _delete_bot_internal(resolved_bot_id, user_id, reason='manual delete')
        
        return jsonify({
            'success': True,
            'message': f'Bot {resolved_bot_id} permanently deleted',
            'deleted_stats': deletion_result['deleted_stats'],
            'closedPositions': len(deletion_result.get('closed_positions', [])),
            'remainingBots': len(active_bots)
        }), 200
    
    except Exception as e:
        logger.error(f"Error deleting bot: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


def _delete_bot_internal(bot_id: str, user_id: str, reason: str = 'manual delete') -> Dict[str, Any]:
    conn = get_db_connection()
    cursor = conn.cursor()
    try:
        bot_config = active_bots.get(bot_id)
        has_live_bot_config = bot_config is not None

        cursor.execute('SELECT user_id FROM user_bots WHERE bot_id = ?', (bot_id,))
        db_bot = cursor.fetchone()
        if not db_bot:
            raise ValueError(f'Bot {bot_id} not found')
        if db_bot['user_id'] != user_id:
            raise PermissionError('Unauthorized: Bot does not belong to this user')

        if not bot_config:
            cursor.execute(
                'SELECT credential_id FROM bot_credentials WHERE bot_id = ? AND user_id = ?',
                (bot_id, user_id),
            )
            credential_row = cursor.fetchone()
            bot_config = {
                'credentialId': credential_row['credential_id'] if credential_row else None,
                'open_positions': {},
                'tradeHistory': [],
                'dailyProfits': {},
                'displayCurrency': 'USD',
            }

        final_stats = (bot_config or {}).copy()
        logger.critical(f"🗑️ BOT PERMANENTLY DELETED: {bot_id} by user {user_id} ({reason})")
        logger.critical(f"   Final Stats: {json.dumps({'totalTrades': final_stats.get('totalTrades'), 'totalProfit': final_stats.get('totalProfit')}, indent=2)}")

        if worker_pool_manager and worker_pool_manager.enabled:
            worker_pool_manager.stop_bot(bot_id)

        closed_positions = []
        if has_live_bot_config:
            stop_bot_runtime(bot_id, bot_config)

        close_summary = _close_bot_positions_for_delete(bot_id, user_id, bot_config)
        closed_positions = close_summary.get('closed', [])
        final_stats = (bot_config or {}).copy()

        bot_stop_flags[bot_id] = True
        running_bots.pop(bot_id, None)
        thread = bot_threads.get(bot_id)
        if thread and thread.is_alive():
            thread.join(timeout=30)
        bot_threads.pop(bot_id, None)
        bot_stop_flags.pop(bot_id, None)

        cursor.execute('DELETE FROM user_bots WHERE bot_id = ?', (bot_id,))
        cursor.execute('DELETE FROM bot_credentials WHERE bot_id = ?', (bot_id,))
        cursor.execute('DELETE FROM bot_deletion_tokens WHERE bot_id = ?', (bot_id,))
        cursor.execute('DELETE FROM bot_activation_pins WHERE bot_id = ?', (bot_id,))
        conn.commit()

        active_bots.pop(bot_id, None)

        return {
            'botId': bot_id,
            'deleted_stats': {
                'totalTrades': final_stats.get('totalTrades', 0),
                'winningTrades': final_stats.get('winningTrades', 0),
                'totalProfit': final_stats.get('totalProfit', 0),
            },
            'closed_positions': closed_positions,
        }
    finally:
        conn.close()


def cleanup_expired_demo_bots_worker():
    """Background task that permanently removes expired demo bots after the retention window."""
    while True:
        try:
            now = datetime.now()
            cutoff = now - timedelta(hours=DEMO_PROMOTION_CLEANUP_RETENTION_HOURS)
            cleaned_count = 0

            for bot_id, bot in list(active_bots.items()):
                if str(bot.get('mode') or 'demo').strip().lower() != 'demo':
                    continue

                # Skip cleanup for external real-broker bots (FXCM, Binance, etc.)
                # These use the broker's own demo accounts and are not subject to the
                # internal demo-promotion evaluation/expiry system.
                _broker_name_val = str(bot.get('brokerName') or bot.get('broker_type') or '').strip().upper()
                if _broker_name_val and _broker_name_val not in {'MT5'}:
                    continue

                total_profit = float(bot.get('totalProfit', 0) or 0)
                open_positions = list(bot.get('open_positions', {}).values())
                floating_profit = sum(float(position.get('profit') or 0) for position in open_positions)
                current_profit = total_profit + floating_profit
                total_trades = int(bot.get('totalTrades', 0) or 0)

                promotion_state = _get_demo_promotion_state(bot, current_profit, total_trades)
                if promotion_state.get('stateChanged'):
                    persist_bot_runtime_state(bot_id)

                expired_at_raw = promotion_state.get('expiredAt')
                if not expired_at_raw:
                    continue

                try:
                    expired_at = datetime.fromisoformat(str(expired_at_raw))
                except Exception:
                    continue

                if expired_at > cutoff:
                    continue

                user_id = bot.get('user_id')
                if not user_id:
                    continue

                logger.info(
                    f"🧹 Auto-cleaning expired demo bot {bot_id} after "
                    f"{DEMO_PROMOTION_CLEANUP_RETENTION_HOURS:.0f}h retention"
                )
                _delete_bot_internal(bot_id, user_id, reason='expired demo cleanup')
                cleaned_count += 1

            if cleaned_count > 0:
                logger.info(f"🧹 Expired demo bot cleanup removed {cleaned_count} bot(s)")
        except Exception as e:
            logger.error(f"Expired demo bot cleanup worker error: {e}")

        time.sleep(DEMO_PROMOTION_CLEANUP_INTERVAL_SECONDS)


