@app.route('/api/user/settings', methods=['POST'])
@require_session
def update_user_settings():
    """Update user settings (2FA, notifications, etc.)"""
    try:
        data = request.get_json()
        user_id = request.user_id
        
        conn = get_db_connection()
        cursor = conn.cursor()
        
        # Ensure settings columns exist
        for col in ['two_factor_enabled', 'notifications_enabled']:
            try:
                cursor.execute(f'ALTER TABLE users ADD COLUMN {col} INTEGER DEFAULT 0')
                conn.commit()
            except Exception:
                pass  # Column already exists
        
        updates = []
        values = []
        if 'two_factor_enabled' in data:
            updates.append('two_factor_enabled = ?')
            values.append(1 if data['two_factor_enabled'] else 0)
        if 'notifications_enabled' in data:
            updates.append('notifications_enabled = ?')
            values.append(1 if data['notifications_enabled'] else 0)
        
        if updates:
            values.append(user_id)
            cursor.execute(f"UPDATE users SET {', '.join(updates)} WHERE user_id = ?", values)
            conn.commit()
        
        conn.close()
        return jsonify({'success': True, 'message': 'Settings updated'}), 200
    except Exception as e:
        logger.error(f"Error updating user settings: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/user/change-password', methods=['POST'])
@require_session
def change_password():
    """Change user password (requires current password)"""
    try:
        data = request.get_json()
        user_id = request.user_id
        old_password = data.get('old_password', '')
        new_password = data.get('new_password', '')
        
        if not new_password or len(new_password) < 6:
            return jsonify({'success': False, 'error': 'New password must be at least 6 characters'}), 400
        
        conn = get_db_connection()
        cursor = conn.cursor()
        
        cursor.execute('SELECT password_hash FROM users WHERE user_id = ?', (user_id,))
        user = cursor.fetchone()
        
        if not user:
            conn.close()
            return jsonify({'success': False, 'error': 'User not found'}), 404
        
        stored_hash = user['password_hash']
        
        # If user has an existing password, verify old password
        if stored_hash:
            if not old_password or not check_password_hash(stored_hash, old_password):
                conn.close()
                return jsonify({'success': False, 'error': 'Current password is incorrect'}), 401
        
        # Set new password
        new_hash = generate_password_hash(new_password)
        cursor.execute('UPDATE users SET password_hash = ? WHERE user_id = ?', (new_hash, user_id))
        conn.commit()
        conn.close()
        
        logger.info(f"Password changed for user {user_id}")
        return jsonify({'success': True, 'message': 'Password changed successfully'}), 200
    
    except Exception as e:
        logger.error(f"Error changing password: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/user/update-profile', methods=['PUT'])
@require_session
def update_user_profile():
    """Update user profile (name, email)"""
    try:
        data = request.get_json()
        user_id = request.user_id
        
        name = data.get('name', '').strip()
        email = data.get('email', '').lower().strip()
        
        if not name and not email:
            return jsonify({'success': False, 'error': 'Name or email required'}), 400
        
        conn = get_db_connection()
        cursor = conn.cursor()
        
        # Check email uniqueness if changing email
        if email:
            cursor.execute('SELECT user_id FROM users WHERE email = ? AND user_id != ?', (email, user_id))
            if cursor.fetchone():
                conn.close()
                return jsonify({'success': False, 'error': 'Email already taken by another user'}), 409
        
        updates = []
        values = []
        if name:
            updates.append('name = ?')
            values.append(name)
        if email:
            updates.append('email = ?')
            values.append(email)
        
        values.append(user_id)
        cursor.execute(f"UPDATE users SET {', '.join(updates)} WHERE user_id = ?", values)
        
        # Fetch updated user
        cursor.execute('SELECT user_id, name, email, referral_code FROM users WHERE user_id = ?', (user_id,))
        updated = cursor.fetchone()
        updated_dict = dict(updated)
        
        conn.commit()
        conn.close()
        
        logger.info(f"Profile updated for user {user_id}")
        return jsonify({
            'success': True,
            'message': 'Profile updated successfully',
            'user': updated_dict
        }), 200
    
    except Exception as e:
        logger.error(f"Error updating profile: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/user/<user_id>/broker-credentials', methods=['POST'])
@require_session
def add_broker_credentials(user_id):
    """Add broker credentials for a user"""
    # Verify user is adding credentials for themselves
    if request.user_id != user_id:
        return jsonify({'success': False, 'error': 'Unauthorized: Cannot add credentials for other users'}), 403
    """Add broker credentials for a user"""
    try:
        data = request.get_json()
        broker_name = canonicalize_broker_name(data.get('broker_name'))
        account_number = data.get('account_number')
        password = data.get('password')
        server = data.get('server')
        is_live = data.get('is_live', False)
        mt5_terminal_path = data.get('mt5_terminal_path') or data.get('mt5_path')
        
        if not all([broker_name, account_number, password]):
            return jsonify({'success': False, 'error': 'Missing required fields'}), 400
        
        conn = get_db_connection()
        cursor = conn.cursor()
        
        # Verify user exists
        cursor.execute('SELECT user_id FROM users WHERE user_id = ?', (user_id,))
        if not cursor.fetchone():
            conn.close()
            return jsonify({'success': False, 'error': 'User not found'}), 404
        
        created_at = datetime.now().isoformat()
        normalized_is_live = int(normalize_mt5_is_live_flag(broker_name, is_live, server))

        if broker_uses_single_mode_slot(broker_name):
            cursor.execute('''
                SELECT credential_id FROM broker_credentials
                WHERE user_id = ?
                  AND is_live = ?
                  AND LOWER(TRIM(broker_name)) = LOWER(TRIM(?))
                ORDER BY COALESCE(updated_at, created_at, '') DESC, credential_id DESC
                LIMIT 1
            ''', (user_id, normalized_is_live, broker_name))
            existing = cursor.fetchone()
            if existing:
                credential_id = existing['credential_id'] if isinstance(existing, sqlite3.Row) else existing[0]
                deactivate_conflicting_broker_credentials(cursor, user_id, broker_name, normalized_is_live, keep_credential_id=credential_id)
                cursor.execute('''
                    UPDATE broker_credentials
                    SET broker_name = ?, account_number = ?, password = ?, server = ?,
                        is_live = ?, is_active = 1, mt5_terminal_path = ?, updated_at = ?
                    WHERE credential_id = ?
                ''', (broker_name, account_number, password, server, normalized_is_live, mt5_terminal_path, created_at, credential_id))
            else:
                credential_id = str(uuid.uuid4())
                cursor.execute('''
                    INSERT INTO broker_credentials 
                    (credential_id, user_id, broker_name, account_number, password, server, is_live, mt5_terminal_path, is_active, created_at, updated_at)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, 1, ?, ?)
                ''', (credential_id, user_id, broker_name, account_number, password, server, normalized_is_live, mt5_terminal_path, created_at, created_at))
        else:
            credential_id = str(uuid.uuid4())
            cursor.execute('''
                INSERT INTO broker_credentials 
                (credential_id, user_id, broker_name, account_number, password, server, is_live, mt5_terminal_path, created_at, updated_at)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            ''', (credential_id, user_id, broker_name, account_number, password, server, normalized_is_live, mt5_terminal_path, created_at, created_at))
        
        encrypt_credential_at_rest(cursor, credential_id)
        conn.commit()
        conn.close()
        
        logger.info(f"Broker credentials added for user {user_id}: {broker_name}")
        
        return jsonify({
            'success': True,
            'credential_id': credential_id,
            'mt5_terminal_path': mt5_terminal_path,
            'message': f'Broker credentials added for {broker_name}'
        }), 200
    
    except Exception as e:
        logger.error(f"Error adding broker credentials: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


