@app.route('/api/admin/commission-config', methods=['POST'])
@require_api_key
def update_commission_config():
    """Update commission rate configuration (admin only)"""
    try:
        data = request.get_json()

        # Validate rates are between 0 and 1
        rate_fields = [
            'developer_direct_rate', 'developer_referral_rate', 'recruiter_rate',
            'ig_developer_rate', 'ig_recruiter_rate',
            'fxcm_developer_rate', 'fxcm_recruiter_rate',
            'binance_developer_rate', 'binance_recruiter_rate',
            'tier2_rate'
        ]
        for field in rate_fields:
            if field in data:
                val = float(data[field])
                if val < 0 or val > 1:
                    return jsonify({'success': False, 'error': f'{field} must be between 0 and 1'}), 400

        # Validate total rates don't exceed 100%
        dev_direct = float(data.get('developer_direct_rate', 0.25))
        dev_referral = float(data.get('developer_referral_rate', dev_direct))
        recruiter = float(data.get('recruiter_rate', 0.05))
        tier2 = float(data.get('tier2_rate', 0.02))
        max_total = dev_referral + recruiter + tier2
        if max_total > 1.0:
            return jsonify({
                'success': False,
                'error': f'Total commission rates ({max_total*100:.0f}%) exceed 100%. '
                         f'Developer ({dev_referral*100:.0f}%) + Recruiter ({recruiter*100:.0f}%) + Tier2 ({tier2*100:.0f}%) must be ≤ 100%.'
            }), 400

        conn = get_db_connection()
        cursor = conn.cursor()

        # Build dynamic UPDATE
        updates = []
        values = []
        allowed = rate_fields + [
            'developer_id',
            'ig_commission_enabled',
            'fxcm_commission_enabled',
            'binance_commission_enabled',
            'multi_tier_enabled',
        ]
        for key in allowed:
            if key in data:
                updates.append(f'{key} = ?')
                values.append(data[key])

        if not updates:
            conn.close()
            return jsonify({'success': False, 'error': 'No valid fields to update'}), 400

        updates.append('updated_at = ?')
        values.append(datetime.now().isoformat())
        values.append('default')

        cursor.execute(
            f"UPDATE commission_config SET {', '.join(updates)} WHERE config_id = ?",
            values
        )
        conn.commit()

        # Return updated config
        cfg = _get_commission_config(cursor)
        conn.close()

        logger.info(f"✅ Commission config updated: {data}")

        return jsonify({'success': True, 'config': cfg, 'message': 'Commission rates updated successfully'}), 200
    except Exception as e:
        logger.error(f"Error updating commission config: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/commission-config/preview', methods=['POST'])
@require_api_key
def preview_commission_split():
    """Preview how a profit amount would be split with given rates"""
    try:
        data = request.get_json()
        profit = float(data.get('profit_amount', 100))
        has_referrer = data.get('has_referrer', True)
        source = data.get('source', 'MT5')

        conn = get_db_connection()
        cursor = conn.cursor()
        cfg = _get_commission_config(cursor)
        conn.close()

        if source == 'IG':
            dev_rate = float(cfg.get('ig_developer_rate', 0.25))
            rec_rate = float(cfg.get('ig_recruiter_rate', 0.05))
            direct_rate = float(cfg.get('developer_direct_rate', 0.25))
        elif source == 'FXCM':
            dev_rate = float(cfg.get('fxcm_developer_rate', 0.25))
            rec_rate = float(cfg.get('fxcm_recruiter_rate', 0.05))
            direct_rate = float(cfg.get('fxcm_developer_rate', 0.25))
        elif source == 'BINANCE':
            dev_rate = float(cfg.get('binance_developer_rate', 0.25))
            rec_rate = float(cfg.get('binance_recruiter_rate', 0.05))
            direct_rate = float(cfg.get('binance_developer_rate', 0.25))
        else:
            direct_rate = float(cfg.get('developer_direct_rate', 0.25))
            dev_rate = float(cfg.get('developer_referral_rate', 0.25))
            rec_rate = float(cfg.get('recruiter_rate', 0.05))

        tier2_rate = float(cfg.get('tier2_rate', 0.02))
        multi_tier = bool(cfg.get('multi_tier_enabled', 0))

        if has_referrer:
            dev_amount = profit * dev_rate
            rec_amount = profit * rec_rate
            tier2_amount = profit * tier2_rate if multi_tier else 0
            trader_keeps = profit - dev_amount - rec_amount - tier2_amount
            breakdown = {
                'developer': {'rate': dev_rate, 'amount': round(dev_amount, 2)},
                'recruiter': {'rate': rec_rate, 'amount': round(rec_amount, 2)},
            }
            if multi_tier:
                breakdown['tier2'] = {'rate': tier2_rate, 'amount': round(tier2_amount, 2)}
        else:
            dev_amount = profit * direct_rate
            trader_keeps = profit - dev_amount
            breakdown = {
                'developer': {'rate': direct_rate, 'amount': round(dev_amount, 2)},
            }

        return jsonify({
            'success': True,
            'profit_amount': profit,
            'source': source,
            'has_referrer': has_referrer,
            'breakdown': breakdown,
            'total_commission': round(profit - trader_keeps, 2),
            'trader_keeps': round(trader_keeps, 2),
        }), 200
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/dashboard', methods=['GET'])
@require_api_key
def admin_dashboard():
    """Admin dashboard with all users, bots, and earnings"""
    try:
        conn = get_db_connection()
        cursor = conn.cursor()
        cfg = _get_commission_config(cursor)
        developer_id = _get_developer_account_id(cfg)
        
        # Get total users
        cursor.execute('SELECT COUNT(*) as count FROM users')
        total_users = cursor.fetchone()['count'] or 0
        
        cursor.execute("SELECT COUNT(*) as count FROM user_bots WHERE status = 'active' AND enabled = 1")
        total_bots = cursor.fetchone()['count'] or 0

        cursor.execute('''
            SELECT
                COALESCE(SUM(amount), 0) AS total_earned,
                COALESCE(SUM(CASE WHEN payout_status = 'completed' THEN amount ELSE 0 END), 0) AS paid_earned,
                COALESCE(SUM(CASE WHEN payout_status != 'completed' THEN amount ELSE 0 END), 0) AS pending_earned
            FROM commission_ledger
            WHERE user_id = ? AND type = 'profit_share'
        ''', (developer_id,))
        platform_commission_row = dict(cursor.fetchone())

        cursor.execute('''
            SELECT COALESCE(SUM(amount), 0) AS total_referral
            FROM commission_ledger
            WHERE type IN ('referral', 'affiliate')
        ''')
        referral_earnings = cursor.fetchone()['total_referral'] or 0

        cursor.execute('SELECT COALESCE(internal_balance, 0) AS internal_balance FROM users WHERE user_id = ?', (developer_id,))
        balance_row = cursor.fetchone()
        platform_internal_balance = balance_row['internal_balance'] if balance_row else 0
        
        # Get all users with their bots
        cursor.execute('SELECT user_id, name, email FROM users ORDER BY created_at DESC LIMIT 100')
        users_list = [dict(row) for row in cursor.fetchall()]

        user_ids = [user['user_id'] for user in users_list]
        bots_by_user: Dict[str, List[Dict[str, Any]]] = {}
        earnings_by_user: Dict[str, Dict[str, float]] = {}

        if user_ids:
            placeholders = ','.join(['?'] * len(user_ids))
            cursor.execute(
                f'''
                    SELECT user_id, bot_id, name, strategy, total_profit, enabled
                    FROM user_bots
                    WHERE status = 'active' AND user_id IN ({placeholders})
                    ORDER BY updated_at DESC, created_at DESC
                ''',
                user_ids,
            )
            for row in cursor.fetchall():
                live_profit = active_bots.get(row['bot_id'], {}).get('totalProfit', row['total_profit'])
                bots_by_user.setdefault(row['user_id'], []).append({
                    'botId': row['bot_id'],
                    'name': row['name'],
                    'strategy': row['strategy'] or 'Unknown',
                    'profit': round(float(live_profit or 0), 2),
                    'enabled': bool(row['enabled']),
                })

            cursor.execute(
                f'''
                    SELECT
                        source_user_id,
                        COALESCE(SUM(CASE WHEN user_id = ? AND type = 'profit_share' THEN amount ELSE 0 END), 0) AS platform_commission,
                        COALESCE(SUM(CASE WHEN type IN ('referral', 'affiliate') THEN amount ELSE 0 END), 0) AS referral_earnings
                    FROM commission_ledger
                    WHERE source_user_id IN ({placeholders})
                    GROUP BY source_user_id
                ''',
                [developer_id, *user_ids],
            )
            for row in cursor.fetchall():
                earnings_by_user[row['source_user_id']] = {
                    'platform_commission': float(row['platform_commission'] or 0),
                    'referral_earnings': float(row['referral_earnings'] or 0),
                }
        
        users_with_bots = []
        total_profit = 0.0
        for user in users_list:
            user_bots = bots_by_user.get(user['user_id'], [])
            user_total_profit = round(sum(float(bot.get('profit', 0) or 0) for bot in user_bots), 2)
            total_profit += user_total_profit
            commission_data = earnings_by_user.get(user['user_id'], {})
            
            users_with_bots.append({
                'user_id': user['user_id'],
                'name': user['name'],
                'email': user['email'],
                'bot_count': len(user_bots),
                'bots': user_bots[:5],  # First 5 bots
                'total_profit': user_total_profit,
                'platform_commission': round(float(commission_data.get('platform_commission', 0) or 0), 2),
                'referral_earnings': round(float(commission_data.get('referral_earnings', 0) or 0), 2),
            })
        
        conn.close()
        
        return jsonify({
            'success': True,
            'total_users': total_users,
            'total_bots': total_bots,
            'total_profit': round(total_profit, 2),
            'platform_earnings': round(float(platform_commission_row.get('total_earned', 0) or 0), 2),
            'platform_paid_earnings': round(float(platform_commission_row.get('paid_earned', 0) or 0), 2),
            'platform_pending_earnings': round(float(platform_commission_row.get('pending_earned', 0) or 0), 2),
            'platform_internal_balance': round(float(platform_internal_balance or 0), 2),
            'referral_earnings': round(float(referral_earnings or 0), 2),
            'commission_rate_platform': float(cfg.get('developer_direct_rate', 0.25) or 0.25),
            'commission_rate_referrer': float(cfg.get('recruiter_rate', 0.05) or 0.05),
            'commission_rates': {
                'developer_direct_rate': float(cfg.get('developer_direct_rate', 0.25) or 0.25),
                'developer_referral_rate': float(cfg.get('developer_referral_rate', 0.25) or 0.25),
                'recruiter_rate': float(cfg.get('recruiter_rate', 0.05) or 0.05),
                'ig_developer_rate': float(cfg.get('ig_developer_rate', 0.25) or 0.25),
                'ig_recruiter_rate': float(cfg.get('ig_recruiter_rate', 0.05) or 0.05),
                'tier2_rate': float(cfg.get('tier2_rate', 0.02) or 0.02),
                'multi_tier_enabled': bool(cfg.get('multi_tier_enabled', 0)),
            },
            'developer_id': developer_id,
            'users': users_with_bots
        }), 200
    
    except Exception as e:
        logger.error(f"Error getting admin dashboard: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/ig-credentials/health', methods=['GET'])
@require_api_key
def admin_ig_credentials_health():
    """Admin view of IG credential readiness by user without returning secrets."""
    try:
        include_all = str(request.args.get('include_all', 'true')).lower() in ('1', 'true', 'yes')
        limit = int(request.args.get('limit', 200))
        if limit < 1:
            limit = 1
        if limit > 1000:
            limit = 1000

        conn = get_db_connection()
        cursor = conn.cursor()

        cursor.execute('''
            SELECT
                u.user_id,
                u.email,
                u.name,
                bc.credential_id,
                bc.username AS ig_username,
                bc.account_number AS ig_account_id,
                bc.is_live,
                bc.api_key,
                bc.password,
                bc.updated_at,
                bc.created_at
            FROM users u
            LEFT JOIN broker_credentials bc
              ON bc.credential_id = (
                  SELECT bc2.credential_id
                  FROM broker_credentials bc2
                  WHERE bc2.user_id = u.user_id
                    AND bc2.is_active = 1
                    AND bc2.broker_name IN ('IG Markets', 'IG.com', 'IG')
                  ORDER BY bc2.updated_at DESC, bc2.created_at DESC
                  LIMIT 1
              )
            ORDER BY u.created_at DESC
            LIMIT ?
        ''', (limit,))

        health_rows = []
        total_with_ig = 0
        total_ready = 0

        for row in cursor.fetchall():
            has_ig = bool(row['credential_id'])
            if has_ig:
                total_with_ig += 1

            missing_fields = []
            if has_ig:
                if not row['api_key']:
                    missing_fields.append('api_key')
                if not row['ig_username']:
                    missing_fields.append('username')
                if not row['password']:
                    missing_fields.append('password')
                if not row['ig_account_id']:
                    missing_fields.append('account_id')

            is_ready = has_ig and len(missing_fields) == 0
            if is_ready:
                total_ready += 1

            if include_all or has_ig:
                health_rows.append({
                    'user_id': row['user_id'],
                    'email': row['email'],
                    'name': row['name'],
                    'has_ig_credentials': has_ig,
                    'credential_id': row['credential_id'] if has_ig else None,
                    'ig_username': row['ig_username'] if has_ig else None,
                    'ig_account_id': row['ig_account_id'] if has_ig else None,
                    'environment': 'live' if bool(row['is_live']) else 'demo' if has_ig else None,
                    'is_ready': is_ready,
                    'missing_fields': missing_fields,
                    'updated_at': row['updated_at'] if has_ig else None,
                    'created_at': row['created_at'] if has_ig else None,
                })

        conn.close()

        return jsonify({
            'success': True,
            'summary': {
                'users_scanned': len(health_rows) if include_all else total_with_ig,
                'users_with_ig_credentials': total_with_ig,
                'users_ready': total_ready,
                'users_not_ready': max(total_with_ig - total_ready, 0),
                'include_all': include_all,
                'limit': limit,
            },
            'users': health_rows,
        }), 200
    except Exception as e:
        logger.error(f"Error getting IG credential health: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


# ==================== WITHDRAWAL SYSTEM ====================
@app.route('/api/withdrawal/request', methods=['POST'])
@require_api_key
def request_withdrawal():
    """Request a withdrawal of earned commissions"""
    try:
        data = request.get_json()
        user_id = data.get('user_id')
        amount = data.get('amount')
        method = data.get('method')
        account_details = data.get('account_details')
        
        # Validate amount
        if amount < WITHDRAWAL_CONFIG['min_amount']:
            return jsonify({'success': False, 'error': f"Minimum withdrawal is ${WITHDRAWAL_CONFIG['min_amount']}"}), 400
        
        if amount > WITHDRAWAL_CONFIG['max_amount']:
            return jsonify({'success': False, 'error': f"Maximum withdrawal is ${WITHDRAWAL_CONFIG['max_amount']}"}), 400
        
        # Test mode: limit to $50 for testing
        if ENVIRONMENT == 'DEMO':
            if amount > WITHDRAWAL_CONFIG['test_mode_max']:
                return jsonify({'success': False, 'error': f"Test mode: maximum ${WITHDRAWAL_CONFIG['test_mode_max']} per withdrawal"}), 400
        
        # Check available balance
        conn = get_db_connection()
        cursor = conn.cursor()
        
        cursor.execute('''
            SELECT SUM(commission_amount) as total_earned FROM commissions 
            WHERE earner_id = ?
        ''', (user_id,))
        
        earnings = cursor.fetchone()
        total_earned = earnings['total_earned'] or 0
        
        # Get withdrawn amount
        cursor.execute('''
            SELECT SUM(amount) as total_withdrawn FROM withdrawals 
            WHERE user_id = ? AND status IN ('approved', 'pending', 'processing')
        ''', (user_id,))
        
        withdrawn = cursor.fetchone()
        total_withdrawn = withdrawn['total_withdrawn'] or 0
        available_balance = total_earned - total_withdrawn
        
        if amount > available_balance:
            conn.close()
            return jsonify({'success': False, 'error': 'Amount exceeds available balance'}), 400
        
        # Create withdrawal request
        withdrawal_id = str(uuid.uuid4())
        fee = amount * (WITHDRAWAL_CONFIG['processing_fee_percent'] / 100)
        net_amount = amount - fee
        created_at = datetime.now().isoformat()
        
        cursor.execute('''
            INSERT INTO withdrawals (withdrawal_id, user_id, amount, method, account_details, status, created_at, fee, net_amount)
            VALUES (?, ?, ?, ?, ?, 'pending', ?, ?, ?)
        ''', (withdrawal_id, user_id, amount, method, account_details, created_at, fee, net_amount))
        
        conn.commit()
        conn.close()
        
        logger.info(f"Withdrawal request {withdrawal_id}: {user_id} - ${amount} ({method})")
        
        return jsonify({
            'success': True,
            'withdrawal_id': withdrawal_id,
            'amount': amount,
            'fee': round(fee, 2),
            'net_amount': round(net_amount, 2),
            'status': 'pending',
            'message': f'Withdrawal request submitted. Will receive ${round(net_amount, 2)} after {WITHDRAWAL_CONFIG["processing_fee_percent"]}% fee. Processing in {WITHDRAWAL_CONFIG["processing_days"]} business days.'
        }), 200
    
    except Exception as e:
        logger.error(f"Error requesting withdrawal: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


