@app.route('/api/withdrawals/recent', methods=['GET'])
@require_session
def get_recent_withdrawals():
    """Get recent withdrawals for the current user (last 10)"""
    try:
        conn = get_db_connection()
        cursor = conn.cursor()
        user_id = request.user_id
        
        # Get recent withdrawals from all withdrawal sources (exness_withdrawals, commission_withdrawals, withdrawals)
        # Combine Exness withdrawals
        cursor.execute('''
            SELECT 
                withdrawal_id, 
                user_id, 
                'Exness' as broker,
                broker_account_id as accountNumber,
                total_amount as amount,
                status,
                created_at as date,
                'exness' as type,
                'withdrawal' as eventCategory,
                'bank_withdrawal' as eventType
            FROM exness_withdrawals
            WHERE user_id = ?
            ORDER BY created_at DESC
            LIMIT 20
        ''', (user_id,))
        
        exness_withdrawals = [dict(row) for row in cursor.fetchall()]
        
        # Get recent commission withdrawals
        cursor.execute('''
            SELECT 
                cw.withdrawal_id,
                cw.user_id,
                'Commission' as broker,
                NULL as accountNumber,
                cw.amount,
                cw.status,
                cw.created_at as date,
                'commission' as type,
                'withdrawal' as eventCategory,
                'commission_withdrawal' as eventType
            FROM commission_withdrawals cw
            WHERE cw.user_id = ?
            ORDER BY cw.created_at DESC
            LIMIT 20
        ''', (user_id,))
        
        commission_withdrawals = [dict(row) for row in cursor.fetchall()]
        
        # Get recent general withdrawals
        cursor.execute('''
            SELECT 
                withdrawal_id,
                user_id,
                method as broker,
                account_details as accountNumber,
                amount,
                status,
                created_at as date,
                'general' as type,
                'withdrawal' as eventCategory,
                'generic_withdrawal' as eventType
            FROM withdrawals
            WHERE user_id = ?
            ORDER BY created_at DESC
            LIMIT 20
        ''', (user_id,))
        
        general_withdrawals = [dict(row) for row in cursor.fetchall()]

        # Include broker-native notifications (FXCM/Binance/OANDA etc.)
        cursor.execute('''
            SELECT
                notification_id as withdrawal_id,
                user_id,
                broker_name as broker,
                NULL as accountNumber,
                amount,
                status,
                created_at as date,
                'broker_notification' as type,
                'withdrawal' as eventCategory,
                'broker_withdrawal_notification' as eventType,
                message
            FROM broker_withdrawal_notifications
            WHERE user_id = ?
            ORDER BY created_at DESC
            LIMIT 20
        ''', (user_id,))

        broker_notifications = [dict(row) for row in cursor.fetchall()]
        
        conn.close()
        
        # Combine and sort by date
        all_withdrawals = exness_withdrawals + commission_withdrawals + general_withdrawals + broker_notifications
        all_withdrawals.sort(key=lambda x: x.get('date', ''), reverse=True)
        
        # Return only recent ones
        recent = all_withdrawals[:10]
        
        logger.info(f"✅ Retrieved {len(recent)} recent withdrawals for user {user_id}")
        
        return jsonify({
            'success': True,
            'withdrawals': recent,
            'total_count': len(all_withdrawals)
        }), 200
    
    except Exception as e:
        logger.error(f"Error getting recent withdrawals: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/withdrawals/analytics', methods=['GET'])
@require_session
def get_withdrawal_analytics():
    """Return aggregated withdrawal amounts + commission distributions for analytics screen."""
    try:
        conn = get_db_connection()
        cursor = conn.cursor()
        user_id = request.user_id

        # Total withdrawn from broker (Exness/PXBT style)
        cursor.execute('''
            SELECT COALESCE(SUM(total_amount), 0) as total,
                   COUNT(*) as count
            FROM exness_withdrawals
            WHERE user_id = ? AND status IN ('completed', 'approved', 'done')
        ''', (user_id,))
        ew = cursor.fetchone()
        broker_total = float(ew['total'] if ew else 0)
        broker_count = int(ew['count'] if ew else 0)

        # Total from general withdrawals table
        cursor.execute('''
            SELECT COALESCE(SUM(amount), 0) as total,
                   COUNT(*) as count
            FROM withdrawals
            WHERE user_id = ? AND status IN ('completed', 'approved', 'done')
        ''', (user_id,))
        gw = cursor.fetchone()
        general_total = float(gw['total'] if gw else 0)

        # Commission totals (what earner received)
        cursor.execute('''
            SELECT COALESCE(SUM(amount), 0) as earned,
                   COUNT(*) as count
            FROM commission_withdrawals
            WHERE user_id = ? AND status IN ('completed', 'approved', 'done')
        ''', (user_id,))
        cw = cursor.fetchone()
        commission_earned = float(cw['earned'] if cw else 0)

        # Commission generated FROM this user's bots (developer/platform cut)
        try:
            cursor.execute('''
                SELECT COALESCE(SUM(commission_amount), 0) as total_generated,
                       COALESCE(AVG(commission_rate), 0) as avg_rate
                FROM commission_records
                WHERE client_id = ?
            ''', (user_id,))
            cr = cursor.fetchone()
            commission_generated = float(cr['total_generated'] if cr else 0)
            avg_commission_rate = float(cr['avg_rate'] if cr else 0)
        except sqlite3.OperationalError as exc:
            if 'no such table' not in str(exc).lower():
                raise
            commission_generated = 0.0
            avg_commission_rate = 0.0

        # Monthly breakdown (last 6 months)
        cursor.execute('''
            SELECT strftime('%Y-%m', created_at) as month,
                   SUM(total_amount) as broker_amount
            FROM exness_withdrawals
            WHERE user_id = ?
            GROUP BY month
            ORDER BY month DESC
            LIMIT 6
        ''', (user_id,))
        monthly_broker = [{'month': r['month'], 'amount': float(r['broker_amount'] or 0)} for r in cursor.fetchall()]

        cursor.execute('''
            SELECT strftime('%Y-%m', created_at) as month,
                   SUM(amount) as commission_amount
            FROM commission_withdrawals
            WHERE user_id = ?
            GROUP BY month
            ORDER BY month DESC
            LIMIT 6
        ''', (user_id,))
        monthly_commission = [{'month': r['month'], 'amount': float(r['commission_amount'] or 0)} for r in cursor.fetchall()]

        # Get user commission config, tolerating older DBs that still use developer_id.
        cursor.execute("PRAGMA table_info(commission_config)")
        commission_config_columns = {str(row['name']) for row in cursor.fetchall()}
        cfg_row = None
        if commission_config_columns:
            config_fields = ['ig_developer_rate', 'recruiter_rate']
            if 'mt5_commission_enabled' in commission_config_columns:
                config_fields.append('mt5_commission_enabled')
            elif 'ig_commission_enabled' in commission_config_columns:
                config_fields.append('ig_commission_enabled AS mt5_commission_enabled')

            where_column = None
            if 'user_id' in commission_config_columns:
                where_column = 'user_id'
            elif 'developer_id' in commission_config_columns:
                where_column = 'developer_id'

            if where_column:
                cursor.execute(
                    f"SELECT {', '.join(config_fields)} FROM commission_config WHERE {where_column} = ? LIMIT 1",
                    (user_id,),
                )
                cfg_row = cursor.fetchone()

            if cfg_row is None:
                cursor.execute(
                    f"SELECT {', '.join(config_fields)} FROM commission_config ORDER BY updated_at DESC LIMIT 1"
                )
                cfg_row = cursor.fetchone()

        platform_rate = float((cfg_row['ig_developer_rate'] if cfg_row else None) or 0.25)
        recruiter_rate = float((cfg_row['recruiter_rate'] if cfg_row else None) or 0.05)
        comm_enabled = bool((cfg_row['mt5_commission_enabled'] if cfg_row else None) if cfg_row else True)

        conn.close()

        return jsonify({
            'success': True,
            'totalWithdrawn': round(broker_total + general_total, 2),
            'brokerWithdrawals': round(broker_total, 2),
            'brokerWithdrawalsCount': broker_count,
            'generalWithdrawals': round(general_total, 2),
            'commissionEarned': round(commission_earned, 2),
            'commissionGenerated': round(commission_generated, 2),
            'avgCommissionRate': round(avg_commission_rate * 100, 1),
            'platformRate': round(platform_rate * 100, 1),
            'recruiterRate': round(recruiter_rate * 100, 1),
            'commissionEnabled': comm_enabled,
            'monthlyBrokerWithdrawals': monthly_broker,
            'monthlyCommissions': monthly_commission,
        }), 200

    except Exception as e:
        logger.error(f"Error getting withdrawal analytics: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/withdrawals', methods=['GET'])
@require_api_key
def admin_withdrawals():
    """Admin endpoint to view all pending withdrawals"""
    try:
        conn = get_db_connection()
        cursor = conn.cursor()
        
        cursor.execute('''
            SELECT w.withdrawal_id, w.user_id, u.name, u.email, w.amount, w.method, 
                   w.account_details, w.status, w.created_at, w.fee, w.net_amount
            FROM withdrawals w
            JOIN users u ON w.user_id = u.user_id
            WHERE w.status = 'pending'
            ORDER BY w.created_at ASC
        ''')
        
        withdrawals = []
        for row in cursor.fetchall():
            item = dict(row)
            item['withdrawal_type'] = 'wallet'
            withdrawals.append(item)

        cursor.execute('''
            SELECT cw.withdrawal_id, cw.user_id, u.name, u.email, cw.amount,
                   cw.payout_method, cw.payout_details, cw.payment_reference,
                   cw.status, cw.created_at, cw.admin_notes, cw.external_reference,
                   cw.processed_by, cw.updated_at
            FROM commission_withdrawals cw
            JOIN users u ON cw.user_id = u.user_id
            WHERE cw.status IN ('pending', 'approved', 'processing')
            ORDER BY cw.created_at ASC
        ''')
        for row in cursor.fetchall():
            item = dict(row)
            item['withdrawal_type'] = 'commission'
            withdrawals.append(item)

        withdrawals.sort(key=lambda item: item.get('created_at') or '')
        conn.close()
        
        return jsonify({
            'success': True,
            'pending_withdrawals': withdrawals,
            'total_pending': len(withdrawals),
            'total_pending_amount': sum([float(w['amount']) for w in withdrawals])
        }), 200
    
    except Exception as e:
        logger.error(f"Error getting admin withdrawals: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


